import { useCallback } from 'react';
import { useDebugMenuDevSettings } from 'cb-wallet-data/stores/DebugMenuDevSettings/hooks/useDebugMenuDevSettings';
import { useUpdateDebugMenuDevSetting } from 'cb-wallet-data/stores/DebugMenuDevSettings/hooks/useUpdateDebugMenuDevSetting';
import { DevSettingsKey } from 'cb-wallet-data/stores/DebugMenuDevSettings/state';
import { useToggler } from '@cbhq/cds-web';
import { Switch } from '@cbhq/cds-web/controls';
import { Box, VStack } from '@cbhq/cds-web/layout';
import { Table, TableBody, TableCell, TableHeader, TableRow } from '@cbhq/cds-web/tables';
import { TextTitle2 } from '@cbhq/cds-web/typography';

type Props = {
  name: DevSettingsKey;
  description: string;
  subtitle?: string;
};
/**
 * Formatted as:
 * [KEY, DESCRIPTION, SUBTITLE]
 */
const availableDevSettings: [DevSettingsKey, string, string?][] = [
  [
    'enable_analytic_logging',
    'Log analytic events to the console',
    'Refresh extension to see changes.',
  ],
];

function DevSettingRow({ name, description, subtitle }: Props) {
  const devSettings = useDebugMenuDevSettings();
  const updateDevSetting = useUpdateDebugMenuDevSetting();

  const [isSettingChecked, { toggle }] = useToggler(devSettings.has(name));

  const handleChange = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (event: any) => {
      if (event.target.checked) {
        updateDevSetting(name, true);
      } else {
        updateDevSetting(name, false);
      }
      toggle();
    },
    [name, toggle, updateDevSetting],
  );

  return (
    <TableRow>
      <TableCell title={description} subtitle={subtitle} overflow="wrap" />
      <TableCell>
        <Switch checked={isSettingChecked} onChange={handleChange} />
      </TableCell>
    </TableRow>
  );
}

export function DebugDevSettings() {
  return (
    <VStack>
      <Box spacing={1}>
        <TextTitle2 as="p">Developer Settings</TextTitle2>
      </Box>
      <Table bordered variant="ruled" tableLayout="auto">
        <TableHeader>
          <TableRow>
            <TableCell title="Setting" width="70%" />
            <TableCell title="ON/OFF" width="20%" />
          </TableRow>
        </TableHeader>
        <TableBody>
          {availableDevSettings.map(([name, description, subtitle]) => (
            <DevSettingRow
              key={`row--${name}`}
              name={name}
              description={description}
              subtitle={subtitle}
            />
          ))}
        </TableBody>
      </Table>
    </VStack>
  );
}

