import { useCallback, useEffect, useState } from 'react';
import { styled } from '@linaria/react';
import { TxMetadataKey_txSource } from 'cb-wallet-data/chains/AccountBased/Ethereum/config';
import { TransferValue } from 'cb-wallet-data/models/TransferValue';
import { useActiveAccountId } from 'cb-wallet-data/stores/Accounts/hooks/useActiveAccountId';
import { SignedTx } from 'cb-wallet-data/stores/Transactions/interfaces/SignedTx';
import { generateUnsignedTransaction } from 'cb-wallet-data/stores/Transactions/methods/generateUnsignedTransaction';
import { signAndSubmitTransaction } from 'cb-wallet-data/stores/Transactions/methods/signAndSubmitTransaction';
import {
  TxMetadataKey,
  TxMetadataValue,
} from 'cb-wallet-data/stores/Transactions/models/TxMetadataKey';
import { UnsignedTxResult } from 'cb-wallet-data/stores/Transactions/models/UnsignedTxResult';
import { useSetWallets } from 'cb-wallet-data/stores/Wallets/hooks/useSetWallets';
import { Wallet } from 'cb-wallet-data/stores/Wallets/models/Wallet';
import { walletsArraySelector } from 'cb-wallet-data/stores/Wallets/state';
