const strings = {
  pageTitle: 'Create/Sign/Submit Eth Transaction',
  createSectionTitle: 'Create Unsigned Transaction',
  planUnsignedTx: 'Draft of Unsigned Transaction',
  unsignedTxResult: 'Unsigned Transaction JSON',
  signedTx: 'Unsigned Transaction JSON',
