export function SolanaDebugButtons() {
  const [address, setAddress] = useState<string | undefined>();
  const [balance, setBalance] = useState<bigint | undefined>();
  const [selectedWallet, setSelectedWallet] = useState<Wallet | undefined>();
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [unsignedTx, setUnsignedTx] = useState<UnsignedTxResult | undefined>();
  const [unsignedTxString, setUnsignedTxString] = useState<string | undefined>();
  const [result, setResult] = useState<string | undefined>();
  const [toAddress, setToAddress] = useState<string | undefined>();
  const activeAccountId = useActiveAccountId();
  const wallets = useRecoilValue(walletsArraySelector);
  useSetWallets();

  useEffect(() => {
    getAddresses(SolanaNetworkSetting.allNetworks[0].network, activeAccountId).then((addresses) => {
      setAddress(addresses[0].address);
      alert(`${addresses[0].address}:${addresses[0].balance}`);
      setBalance(addresses[0].balance);
    });
  }, [activeAccountId]);

  const requestAirDropDevnet = useCallback(() => {
    if (address) {
      const devurl = 'https://api.devnet.solana.com/';
      requestAirDrop(address, 1n, devurl).then((res: string) => {
        setResult(res);
      });
    }
  }, [address]);

  const requestAirDropTestnet = useCallback(() => {
    if (address) {
      const devurl = 'https://api.testnet.solana.com/';
      requestAirDrop(address, 1n, devurl).then((res: string) => {
        setResult(res);
      });
    }
  }, [address]);

  const sendSolana = useCallback(async () => {
    if (!selectedWallet) {
      alert('no selected wallet');
    } else if (!toAddress) {
      alert('No toAddress');
    } else {
      // TODO: Implement send for Solana
      alert('Not implemented');
    }
  }, [selectedWallet, toAddress]);

  const signAndsubmit = useCallback(async () => {
    if (!unsignedTx?.transaction) {
      alert('No unsignedTx available');
    } else if (!selectedWallet) {
      alert('No selectedWallet ');
    } else {
      try {
        await appLockRepository.submitPassword(
          'password123',
          activeAccountId,
          SecretAccessContext.DebugMenu,
          false,
        );
        try {
          const signedTx = await signAndSubmitTransaction({
            unsignedTx: unsignedTx.transaction,
            wallet: selectedWallet,
            txSubmissionType: 'original',
            onSubmit: () => {},
          });
          alert(
            JSON.stringify(
              signedTx,
              (_key, value) => (typeof value === 'bigint' ? `${value.toString()}n` : value),
              2,
            ),
          );
        } catch (e) {
          alert('TX signing failed');
        }
      } catch (e) {
        alert('Mnemonic decryption failed');
      }
    }
  }, [unsignedTx, selectedWallet, activeAccountId]);

  // eslint-disable-next-line wallet/require-named-effect
  useEffect(() => {
    const solWallet = (wallets ?? []).find((w) => w.currencyCode.code === 'SOL');
    setSelectedWallet(solWallet);
  }, [wallets]);

  useEffect(() => {
    setUnsignedTxString(
      unsignedTx
        ? JSON.stringify(
            unsignedTx,
            (_key, value) => (typeof value === 'bigint' ? `${value.toString()}n` : value),
            2,
          )
        : unsignedTx,
    );
  }, [unsignedTx]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleToAddressChange = useCallback(({ target }: any) => {
    setToAddress(target.value);
  }, []);

  return (
    <div>
      <div>
        Solana Wallet: {selectedWallet?.addresses[0] as unknown as string}, balance:{' '}
        {balance?.toString()}
      </div>
      <p />
      <div className={debugButton} onClick={requestAirDropDevnet}>
        Request 1 SOL airdrop devnet
      </div>
      <p />
      <div className={debugButton} onClick={requestAirDropTestnet}>
        Request 1 SOL airdrop testnet
      </div>
      <p />
      <form>
        <div>
          <div>
            <Label htmlFor="address">To address</Label>
            <Input
              type="string"
              id="toAddress"
              name="toAddress"
              placeholder="n/a"
              onChange={handleToAddressChange}
            />
          </div>
        </div>
      </form>
      <div className={debugButton} onClick={sendSolana}>
        Send 1 SOL to an address
      </div>
      <p />
      {!!unsignedTx && (
        <div>
          UnsignedTx<code>{unsignedTxString}</code>
          <div className={debugButton} onClick={signAndsubmit}>
            Sign and Submit
          </div>
        </div>
      )}
      <TextLabel1 as="div">{result && <div>Result: {result}</div>}</TextLabel1>
    </div>
  );
}

