import { screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { useAddAddressSelectAddressesPageViewed } from 'cb-wallet-analytics/ledger';
import { LedgerError } from 'cb-wallet-data/chains/AccountBased/Ethereum/Transactions/ledgerError';
import { cbReportError } from 'cb-wallet-data/errors/reportError';
import { renderWithAllProviders } from 'wallet-cds-web/test/testUtils';

import { SelectAddresses } from ':extension/components/HardwareWallet/SelectAddresses/SelectAddresses';

import { useSetAddLedgerAddressErrorAtom } from '../state/useAddLedgerAddressErrorAtom';
import { useAddLedgerAddressStepper } from '../steppers/AddLedgerAddress';

import { AddHWWalletAddressSelectAddresses } from './AddHWWalletAddressSelectAddresses';

jest.mock('cb-wallet-data/errors/reportError');
jest.mock('../steppers/AddLedgerAddress');
jest.mock('../state/useAddLedgerAddressErrorAtom');
jest.mock('cb-wallet-analytics/ledger');

const mockLedgerError = new LedgerError('test-error', 100, 'foo');

jest.mock(':extension/components/HardwareWallet/SelectAddresses/SelectAddresses', () => ({
  SelectAddresses: (props: React.ComponentProps<typeof SelectAddresses>) => {
    return (
      <>
        <button data-testid="onContinue-button" onClick={() => props.onContinue(1)} />
        <button
          data-testid="onGetLedgerAddressError-button"
          onClick={() => props.onGetAddressError(mockLedgerError)}
        />
        <div>HWTroubleConnecting_Component</div>
      </>
    );
  },
}));

describe('<AddHWWalletAddressSelectAddresses />', () => {
  let reportErrorMock: jest.Mock;
  let replaceStepMock: jest.Mock;
  let goToStepMock: jest.Mock;
  let setAddLedgerAddressErrorAtomMock: jest.Mock;
  beforeEach(() => {
    reportErrorMock = jest.fn();
    replaceStepMock = jest.fn();
    goToStepMock = jest.fn();
    setAddLedgerAddressErrorAtomMock = jest.fn();
    (useAddLedgerAddressStepper as jest.Mock).mockReturnValue({
      replaceStep: replaceStepMock,
      goToStep: goToStepMock,
    });
    (cbReportError as jest.Mock).mockReturnValue(reportErrorMock);
    (useSetAddLedgerAddressErrorAtom as jest.Mock).mockReturnValue(
      setAddLedgerAddressErrorAtomMock,
    );
  });

  it('should report error, set error atom, and replace step with hw-trouble-connecting when handleGetAddressError is called', async () => {
    renderWithAllProviders(<AddHWWalletAddressSelectAddresses />);
    await userEvent.click(screen.getByTestId('onGetLedgerAddressError-button'));
    expect(cbReportError).toHaveBeenCalledWith({
      error: mockLedgerError,
      context: 'ledger-error',
      severity: 'error',
      isHandled: false,
    });
    expect(replaceStepMock).toHaveBeenCalledWith('hw-trouble-connecting');
    expect(setAddLedgerAddressErrorAtomMock).toHaveBeenCalledWith({
      errorId: 'foo',
      statusCode: 100,
      errorMessage: '',
    });
    expect(useAddAddressSelectAddressesPageViewed).toHaveBeenCalled();
  });

  it('should go to the addresses-signing when onContinue is called', async () => {
    renderWithAllProviders(<AddHWWalletAddressSelectAddresses />);

    expect(useAddAddressSelectAddressesPageViewed).toHaveBeenCalled();

    await userEvent.click(screen.getByTestId('onContinue-button'));

    expect(goToStepMock).toHaveBeenCalledWith('addresses-signing');
  });
});

