import { RoutesEnum } from ':extension/screens/Routes/Routes';
import { RouteWithErrorBoundary } from ':extension/screens/Routes/RouteWithErrorBoundary';
import { lazyWithPreload } from ':extension/util/lazyWithPreload';

import { BannedLocation } from './BannedLocation';

const Secret = lazyWithPreload(async () =>
  import(':extension/screens/Secret/Secret').then((module) => ({
    default: module.Secret,
  })),
);
const ShowSecret = lazyWithPreload(async () =>
  import(':extension/screens/ShowSecret/ShowSecret').then((module) => ({
    default: module.ShowSecret,
  })),
);
const ChooseWallet = lazyWithPreload(async () =>
  import(':extension/screens/ChooseWallet/ChooseWallet').then((module) => ({
    default: module.ChooseWallet,
  })),
);

type BannedLocationGateProps = {
  children: ReactNode;
};

/** This is only exported for use in the in-app debug menu */
export function BannedLocationRouter() {
  return (
    <MemoryRouter>
      <Switch>
        <RouteWithErrorBoundary exact path={RoutesEnum.CHOOSE_WALLET} component={ChooseWallet} />
        <RouteWithErrorBoundary exact path={RoutesEnum.SHOW_SECRET} component={ShowSecret} />
