export const InvalidStep = memo(function InvalidStep() {
  const activeWalletGroupId = useActiveWalletGroupId();
  const {
    isLoading,
    subdomainSuffix,
    claim,
    declineClaim,
    username: currentUsername = '',
  } = useSubdomainReservation(activeWalletGroupId);
  const validateUsername = useValidateUsername();
  const validators = useUsernameValidators(DISALLOW_ANONYMOUS, IS_SUBDOMAIN);
  const [isTermsChecked, { toggle: handleTermsChange }] = useToggler();
  const [isUsernameAvailable, setIsUsernameAvailable] = useState(false);
  const [username, setUsername] = useState('');

  const [isValidating, setIsValidating] = useState(false);
  const [isClaiming, setIsClaiming] = useState(false);
  const [hasErrors, setHasErrors] = useState(false);
  const { push } = useHistory();
  const { formatMessage } = useIntl();
  const toast = useToast();

  const givenError = useMemo(() => {
    // only default to "Not Available" if all validators come back clean
    if (!hasErrors && !isUsernameAvailable) {
      return formatMessage(validationMessages.invalidValidationNotAvailable, { username });
    }
  }, [formatMessage, hasErrors, isUsernameAvailable, username]);

  const isDisabled = useMemo(
    () => !isTermsChecked || hasErrors || !username || isValidating || !isUsernameAvailable,
    [hasErrors, isValidating, isTermsChecked, username, isUsernameAvailable],
  );

  const handleClaim = useCallback(async () => {
    if (isDisabled) {
      return;
    }

    logSubdomainClaim();
    setIsClaiming(true);

    try {
      await claim(username);
      setIsClaiming(false);
      logSubdomainClaimSuccess();
      push(RoutesEnum.DEFAULT);
    } catch (err) {
      const error = coerceError(err, 'invalid step');
      logSubdomainClaimError();
      cbReportError({
        error,
        context: 'did_error',
        metadata: {
          screen: 'InvalidStep',
          method: 'InvalidStep.handleClaim',
        },
        severity: 'error',
        isHandled: false,
      });
      setIsClaiming(false);
      toast.show(formatMessage(messages.error));
    }
  }, [push, toast, formatMessage, isDisabled, claim, username]);

  const validateName = useCallback(
    async (name: string) => {
      try {
        const isValid = await validateUsername(name, IS_SUBDOMAIN);
        setIsUsernameAvailable(isValid);
      } finally {
        setIsValidating(false);
      }
    },
    [validateUsername],
  );

  const debouncedValidateUsername = useDebouncedCallback(validateName);

  const handleUsernameChange = useCallback(
    (name: string): void => {
      setIsValidating(true);
      setUsername(name);
      debouncedValidateUsername(name);
    },
    [debouncedValidateUsername],
  );

  useLogSubdomainChangeStepViewed();

  usePerfMarkOnMount(PERF_MARKS.subdomain, SUBDOMAIN_MARKS.load_subdomain_invalid, {
    type: 'end',
  });

  useEffect(
    function onUsernameLoad() {
      const validateCurrentUsername = async () => {
        if (!isLoading && currentUsername && !username) {
          // if currentUsername is invalid, don't prefill it as as a suggestion
          try {
            const isValid = await validateUsername(currentUsername, IS_SUBDOMAIN);
            setUsername(isValid ? currentUsername : '');
          } finally {
            setIsValidating(false);
          }
        }
      };
      validateCurrentUsername();
    },
    // eslint-disable-next-line wallet/exhaustive-deps
    [isLoading, currentUsername],
  );

  if (isLoading) {
    return (
      <StepWrapper testID="claim-subdomain-change-step">
        <VStack spacingHorizontal={3}>
          <TextTitle1 as="h1" spacingBottom={0.5}>
            {formatMessage(messages.title)}
