const mockGoToStep = jest.fn();
const mockSignOut = jest.fn();

describe('<ErrorFallback />', () => {
  beforeEach(() => {
    (useAuthenticationContext as jest.Mock).mockReturnValue({ signOut: mockSignOut });
    (useEscapeHatchStepper as jest.Mock).mockReturnValue({
      goToStep: mockGoToStep,
    });
    (getEncryptedSecrets as jest.Mock).mockReturnValue({ 1: 'secret' });
  });

  describe('when viewSecretsOrSignout is the active screen', () => {
    beforeEach(() => {
      (useEscapeHatchStepper as jest.Mock).mockReturnValue({
        goToStep: mockGoToStep,
        currentStep: 'viewSecretsOrSignout',
      });
    });

    it('should go to errorState when back is clicked', async () => {
      renderWithAllProviders(
        <stepper.Provider defaultStep="viewSecretsOrSignout">
          <ErrorFallbackContent />
        </stepper.Provider>,
      );

      expect(await screen.findByTestId('nav-title-back')).toBeInTheDocument();
      expect(mockGoToStep).not.toHaveBeenCalled();

      await userEvent.click(screen.getByTestId('nav-title-back'));

      expect(mockGoToStep).toHaveBeenCalledWith('errorState');
    });

    describe('when sign out is clicked', () => {
      it('should go to signoutConfirmation if the user has stored secrets', async () => {
        const mockSignOutAnalytics = jest.fn();
        renderWithAllProviders(
          <stepper.Provider defaultStep="viewSecretsOrSignout">
            <ErrorFallbackContent onSignOutClickAnalytics={mockSignOutAnalytics} />
          </stepper.Provider>,
        );

        expect(await screen.findByTestId('onPressSignOut-button')).toBeInTheDocument();
        expect(mockGoToStep).not.toHaveBeenCalled();

        await userEvent.click(screen.getByTestId('onPressSignOut-button'));

        expect(mockGoToStep).toHaveBeenCalledWith('signOutConfirmation');
        expect(mockSignOutAnalytics).toHaveBeenCalled();
      });

      it('should immediately sign out if the user does not have stored secrets', async () => {
        const mockSignOutAnalytics = jest.fn();
        (getEncryptedSecrets as jest.Mock).mockReturnValue({});
        renderWithAllProviders(
          <stepper.Provider defaultStep="viewSecretsOrSignout">
            <ErrorFallbackContent onSignOutClickAnalytics={mockSignOutAnalytics} />
          </stepper.Provider>,
        );

        expect(await screen.findByTestId('onPressSignOut-button')).toBeInTheDocument();
        expect(mockSignOut).not.toHaveBeenCalled();

        await userEvent.click(screen.getByTestId('onPressSignOut-button'));
        expect(mockSignOut).toHaveBeenCalled();
        expect(mockSignOutAnalytics).toHaveBeenCalled();
      });
    });

    describe('when view recovery phrase is clicked', () => {
      it('should go to passwordEntry if the user has one account', async () => {
        renderWithAllProviders(
          <stepper.Provider defaultStep="viewSecretsOrSignout">
            <ErrorFallbackContent />
          </stepper.Provider>,
        );

        expect(await screen.findByTestId('onPressViewRecoveryPhrase-button')).toBeInTheDocument();
        expect(mockGoToStep).not.toHaveBeenCalled();

        await userEvent.click(screen.getByTestId('onPressViewRecoveryPhrase-button'));
        expect(mockGoToStep).toHaveBeenCalledWith('passwordEntry');
      });

      it('should go to chooseWallet if the user has more than one account', async () => {
        (getEncryptedSecrets as jest.Mock).mockReturnValue({ 1: 'secret', 2: 'secret' });
        renderWithAllProviders(
          <stepper.Provider defaultStep="viewSecretsOrSignout">
            <ErrorFallbackContent />
          </stepper.Provider>,
        );

        expect(await screen.findByTestId('onPressViewRecoveryPhrase-button')).toBeInTheDocument();
        expect(mockGoToStep).not.toHaveBeenCalled();

        await userEvent.click(screen.getByTestId('onPressViewRecoveryPhrase-button'));
        expect(mockGoToStep).toHaveBeenCalledWith('chooseWallet');
      });
    });
  });

  describe('when chooseWallet is the active screen', () => {
    beforeEach(() => {
      (useEscapeHatchStepper as jest.Mock).mockReturnValue({
        goToStep: mockGoToStep,
        currentStep: 'chooseWallet',
