export type Props = {
  label: string;
  description?: string;
  isMouseHovering?: boolean;
  isPrevDisabled?: boolean;
  isNextDisabled?: boolean;
  scroll?: (shouldMoveForward: boolean) => void;
};

export function SectionHeader({
  label,
  description,
  isMouseHovering,
  scroll,
  isNextDisabled,
  isPrevDisabled,
}: Props) {
  const previousScroll = useCallback(() => {
    scroll?.(false);
  }, [scroll]);

  const nextScroll = useCallback(() => {
    scroll?.(true);
  }, [scroll]);

  return (
    <VStack testID="explore-section-header">
      <HStack height={45} alignItems="center" spacingTop={2} spacingStart={3} spacingEnd={1}>
        {label ? (
          <TextTitle3 testID="explore-section-header-title" as="h2" numberOfLines={1}>
            {label}
          </TextTitle3>
        ) : null}
        {description ? (
          <Tooltip content={description}>
            <Box className={navigationSectionScale} justifyContent="flex-start">
              <IconButton
                name="info"
                testID="explore-section-header-tooltip"
                variant="foregroundMuted"
                transparent
              />
            </Box>
          </Tooltip>
        ) : null}
        <Spacer />
        {isMouseHovering ? (
          <HStack gap={2} className={navigationSectionScale}>
            <IconButton
              testID="explore-section-header-prev-button"
              compact
              name="caretLeft"
              disabled={isPrevDisabled}
              onPress={previousScroll}
            />
            <IconButton
              testID="explore-section-header-next-button"
              compact
              name="caretRight"
              disabled={isNextDisabled}
              onPress={nextScroll}
            />
          </HStack>
        ) : null}
      </HStack>
    </VStack>
  );
}

