});

function isBrowserOutdatedNotification(
  notification: NotificationItem,
): notification is BrowserOutdatedNotification {
  return notification.notification_id === 'extension-is-browser-outdated';
}

type NotificationsHubItemsProps = {
  container: HTMLDivElement | null;
  notifications: NotificationItem[];
  fetchNextPage: InfiniteQueryObserverBaseResult['fetchNextPage'];
  hasNextPage?: boolean;
  isLoading?: boolean;
};

export const NotificationsHubItems = memo(function NotificationsHubItems({
  container,
  notifications,
  hasNextPage,
  isLoading,
  fetchNextPage,
}: NotificationsHubItemsProps) {
  const routeToLandingPage = useRouteToLandingPage();
  const updateNotificationsAction = useUpdateNotificationState();

  useNotificationHubViewed();

  const loadMore = useCallback(async () => {
    if (isLoading) {
      return;
    }

    if (!hasNextPage) {
      return;
    }

    await fetchNextPage();
  }, [isLoading, hasNextPage, fetchNextPage]);

  const rowCount = notifications.length + (hasNextPage ? 5 : 0);

  const handleOnNotificationPress = useCallback(
    (notification: ExternalNotificationItem) => {
      triggerNotificationPressed({
        communicationId: notification.communication_id,
        notificationTitle: notification.payload.Payload.InAppStatic.title,
        notificationBody: notification.payload.Payload.InAppStatic.body,
        template: notification.template_name,
      });
      updateNotificationsAction([notification]);

      const notificationUrl = notification?.payload?.Payload?.InAppStatic?.url;

      if (!notificationUrl) {
        return;
      }

      routeToLandingPage(notificationUrl);
    },
    [routeToLandingPage, updateNotificationsAction],
  );

  const renderRow = useCallback(
    ({ key, index, style }: ListRowProps) => {
      const item = notifications[index];

      if (!item) {
        return (
          <div key={key} style={style}>
            <ListCellFallback title subdetail />
          </div>
        );
      }

      return (
        <div key={key} style={style}>
          {isBrowserOutdatedNotification(item) ? (
            <BrowserOutdatedListCell testID={`promotion-list-cell-${index}`} notification={item} />
          ) : (
            <PromotionsListCell
              testID={`promotion-list-cell-${index}`}
              onPress={handleOnNotificationPress}
              notification={item}
            />
          )}
        </div>
      );
    },
    [handleOnNotificationPress, notifications],
  );

  const isRowLoaded = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ({ index }: any) => {
      return Boolean(notifications[index]);
    },
    [notifications],
  );

  // these are just estimates, since there is no monospacing, and word length could overflow the word to the next line.
  const calculateRowHeight = useCallback(
    (row: Index) => {
      // loading state notifications
      if (row.index >= notifications.length) {
        return 85;
      }
      const bodyLength = notifications[row.index].payload.Payload.InAppStatic.body?.length;
      // 3 lines
      if (bodyLength >= 85 && bodyLength < 115) {
        return 110;
      }
      // 4 lines
      if (bodyLength >= 115) {
        return 135;
      }

      // 2 lines
      return 85;
    },
    [notifications],
  );

  return (
    <WindowScroller scrollElement={container as HTMLDivElement}>
      {({ height, scrollTop }) => (
        <AutoSizer disableHeight>
          {({ width }) => (
            <InfiniteLoader
              threshold={10}
              isRowLoaded={isRowLoaded}
              loadMoreRows={loadMore}
              rowCount={rowCount}
            >
              {({ onRowsRendered, registerChild }) => (
                <List
                  rowCount={rowCount}
                  width={width ? width - 5 : 375}
                  height={height ? height - 100 : 135}
                  autoHeight
                  scrollTop={scrollTop}
                  rowHeight={calculateRowHeight}
                  overscanCount={10}
                  rowRenderer={renderRow}
                  ref={registerChild}
                  onRowsRendered={onRowsRendered}
                />
              )}
            </InfiniteLoader>
          )}
        </AutoSizer>
      )}
    </WindowScroller>
  );
});

const NotificationsHub = memo(function NotificationsHub() {
  const { data, hasNextPage, fetchNextPage, isLoading } = useNotificationsHub();
  const clearUnread = useClearUnreadNotifications();
  const { formatMessage } = useIntl();
  const { goBack, push } = useHistory();
  const { browserOutdatedNotification } = useBrowserOutdatedNotification();

  useNotificationHubViewed();

  const [container, setContainer] = useState<HTMLDivElement | null>(null);

  const navigateToNotificationSettings = useCallback(() => {
    push('/settings/notifications');
  }, [push]);

  const notifications = useMemo(() => {
    const externalNotifications = (data?.pages || []).map((page) => {
      if (page.response.items) {
        return page.response.items;
      }
      return [];
    });
    return [browserOutdatedNotification, ...externalNotifications]
      .flat()
      .filter(Boolean) as NotificationItem[];
  }, [data, browserOutdatedNotification]);

  const onUnmount = useCallback(() => {
    clearUnread();
  }, [clearUnread]);

  useOnUnmount(onUnmount);

  return (
    <Screen
      header={
        <NavBar
          variant="secondary"
          title={formatMessage(messages.title)}
          actions={<SettingsButton onPress={navigateToNotificationSettings} />}
          handleBack={goBack}
          titleOverflow="wrap"
        />
      }
      ref={setContainer}
    >
      {isLoading && <NotificationsHubLoadingState />}
      {notifications.length === 0 && <NotificationsHubEmptyState />}
      {!isLoading && notifications.length !== 0 && container && (
        <NotificationsHubItems
          hasNextPage={hasNextPage}
          fetchNextPage={fetchNextPage}
          isLoading={isLoading}
          notifications={notifications}
          container={container}
        />
      )}
    </Screen>
  );
});

const NotificationsHubWithSuspense = memo(function NotificationsHubWithSuspense() {
  return (
    <Suspense fallback={<NotificationsHubLoadingState />}>
      <NotificationsHubContent />
    </Suspense>
  );
});

const NotificationsHubContent = memo(function NotificationsHubContent() {
  const user = useUser();
  return !user ? <NotificationsHubAuthGate /> : <NotificationsHub />;
});

export { NotificationsHubWithSuspense as NotificationsHub };

