const ALLOW_ANONYMOUS = true;
const IS_SUBDOMAIN = true;

/**
 * "Pick your username" Screen
 */
export function Username() {
  const { update, isImported } = useOnboardingContext();
  const [isUsernameAvailable, setIsUsernameAvailable] = useState(false);
  const [username, setUsername] = useState('');
  const [hasErrors, setHasErrors] = useState(false);
  const [isValidating, setIsValidating] = useState(false);
  const [isTermsChecked, setIsTermsChecked] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { formatMessage } = useIntl();
  const toast = useToast();
  const { goToStep } = useOnboardingStepper();
  const validateUsername = useValidateUsername();
  const validators = useUsernameValidators(ALLOW_ANONYMOUS, IS_SUBDOMAIN);
  const [subdomainSuffix] = useSubdomainSuffixes();
  const claimSubdomain = useClaimSubdomain();
  const refreshUser = useRefreshUser();
  const invalidateProfileByAddressQuery = useInvalidateProfileByAddressQuery();
  const invalidateProfilesByAddressesQuery = useInvalidateProfilesByAddressesQuery();
  const activeWalletGroupId = useActiveWalletGroupId();
  const address = useProfileAddress(activeWalletGroupId);
  const allAddressesMap = useSubdomainAddressMapping();
  const { unlockSuccess } = useUnlockSuccess();
  const { start: markStartLoadBackupPerf } = useExtensionPerfMark(
    toExtensionName(PERF_MARKS.onboarding),
    ONBOARDING_MARKS.load_backup_wallet,
    {
      logMetric: true,
    },
  );

  const isDisabled = useMemo(
    () =>
      !isTermsChecked ||
      !address ||
      !subdomainSuffix ||
      hasErrors ||
      username.length === 0 ||
      isValidating ||
      !isUsernameAvailable,
    [
      hasErrors,
      isValidating,
      isTermsChecked,
      username.length,
      isUsernameAvailable,
      address,
      subdomainSuffix,
    ],
  );

  const givenError = useMemo(() => {
    // only default to "Not Available" if all validators come back clean
    if (!hasErrors && !isUsernameAvailable) {
      return formatMessage(validationMessages.validationNotAvailable);
    }
  }, [formatMessage, hasErrors, isUsernameAvailable]);

  const handleTermsCheckToggle = useCallback(() => {
    setIsTermsChecked((isChecked) => !isChecked);
  }, []);

  const validateName = useCallback(
    async (name: string) => {
      setIsUsernameAvailable(await validateUsername(name, IS_SUBDOMAIN));
      setIsValidating(false);
    },
    [validateUsername],
  );

  const debouncedValidateUsername = useDebouncedCallback(validateName);

  const handleUsernameChange = useCallback(
    (name: string): void => {
      setIsValidating(true);
      setUsername(name);
      debouncedValidateUsername(name);
    },
    [debouncedValidateUsername],
  );

  const handleSubmitUsername = useCallback(async () => {
    if (isDisabled) {
      return;
    }

    triggerOnboardingUsernameSubmit(isImported);
    markStartLoadBackupPerf();

    const subdomain = `${username}${subdomainSuffix}`;

    logSubdomainClaim();
    setIsSubmitting(true);

    try {
      await claimSubdomain({
        ethereumAddress: address!,
        coinAddresses: allAddressesMap,
        name: username,
        subdomainSuffix: subdomainSuffix || '',
      });
      await refreshUser();
      invalidateProfileByAddressQuery(address!);
      invalidateProfilesByAddressesQuery();
      setIsSubmitting(false);
      logSubdomainClaimSuccess();
    } catch (error) {
      const err = coerceError(error, 'username');
      logSubdomainClaimError();
      cbReportError({
        error: err,
        context: 'did_error',
        metadata: {
          screen: 'Username',
          method: 'Username.handleSubmitUsername',
        },
        severity: 'error',
        isHandled: false,
      });
      setIsSubmitting(false);
      toast.show((error as Error).message);
      return;
    }

    update(
      (prev): ContextUpdate => ({
        ...prev,
        ethereumAddress: address,
        isCoinbaseBackground: true,
        subdomain,
      }),
      () => {
        goToStep('subdomain-claim-success');
      },
    );
  }, [
    isDisabled,
    isImported,
    markStartLoadBackupPerf,
    username,
    subdomainSuffix,
    update,
    claimSubdomain,
    address,
    allAddressesMap,
    refreshUser,
    invalidateProfileByAddressQuery,
    invalidateProfilesByAddressesQuery,
    toast,
    goToStep,
  ]);

  useOnMount(() => {
    triggerOnboardingSubdomainUsernameViewed();
  });

  usePerfMarkOnMount(toExtensionName(PERF_MARKS.onboarding), ONBOARDING_MARKS.load_username, {
    type: 'end',
  });

  return (
    <StepWrapper
      flexDirection="column"
      justifyContent="space-between"
      onClose={unlockSuccess}
      hideStepper
    >
      <VStack>
        <TextTitle1 as="h3" spacingBottom={1}>
          {formatMessage(messages.pickUsername)}
        </TextTitle1>
        <TextBody as="div" color="foregroundMuted">
          {formatMessage(messages.subdomainInstructions)}
        </TextBody>
        <Box spacingTop={2}>
          <ValidatedTextInput
            placeholder="satoshi123"
            name="username"
            testID="username-input"
            isLoading={isValidating}
            defaultSubscript={formatMessage(messages.poweredBy)}
            loadingMessage={formatMessage(messages.checking)}
            successMessage={formatMessage(messages.validationAvailable)}
            label={formatMessage(messages.userNameMessage)}
            value={username}
            onError={setHasErrors}
            autoFocus
            givenError={givenError}
            onChange={handleUsernameChange}
            validators={validators}
            onEnter={handleSubmitUsername}
