import { ProfileFollowActionProps } from ':extension/screens/Profile/types';

type FollowProfileButtonProps = {
  address: string;
} & ProfileFollowActionProps;

export function FollowProfileButton({ address, onFollow }: FollowProfileButtonProps) {
  const [isProcessing, { toggleOn, toggleOff }] = useToggler();
  const activeWalletGroupId = useActiveWalletGroupId();
  const profileAddress = useProfileAddress(activeWalletGroupId);
  const createFollow = useCreateFollow(profileAddress);

  const handleOnClick = useCallback(() => {
    toggleOn();
    createFollow(address).then(onFollow).finally(toggleOff);
  }, [address, createFollow, onFollow, toggleOn, toggleOff]);

  return (
    <IconButton
      name="followInactive"
      variant="secondary"
      testID="profile-list-item-follow"
      onPress={handleOnClick}
      disabled={isProcessing}
    />
  );
}

