describe('The GenericReceiveByAddress component', () => {
  const ethWalletAddress = new WalletAddress(EthereumAddressType, 'someETHAddressString', 1n);
  const solWalletAddress = new WalletAddress(SolanaAddressType, 'someSOLAddressString', 2n);
  const btcWalletAddress = new WalletAddress(BitcoinSegwitAddressType, 'someBTCAddress string', 3n);
  const unsupportedWalletAddress = new WalletAddress(
    new AddressType('JohnCandy'),
    'someCADCAddressString',
    2n,
  );
  const expectedText = {
    copiedToast: 'Copied to clipboard',
  };

  const queryAllListItems = () => screen.queryAllByTestId('list-item');

  const getListItem = (address: WalletAddress) =>
    screen.getByText(`AddressType_${address.type.rawValue}`);

  const getListItemCopyButton = (address: WalletAddress) =>
    // eslint-disable-next-line testing-library/prefer-screen-queries
    getByTestId(getListItem(address), 'copy-button');

  const getListItemQRCodeButton = (address: WalletAddress) =>
    // eslint-disable-next-line testing-library/prefer-screen-queries
    getByTestId(getListItem(address), 'qr-code-button');

  const mockPush = jest.fn();
  beforeEach(() => {
    (useActiveAccount as jest.Mock).mockReturnValue(mockMnemonicAccount1);
    (useActiveWalletGroup as jest.Mock).mockReturnValue(mockWalletGroup1a);
    (useHasUTXOExtensionExperiment as jest.Mock).mockReturnValue(true);
    (useHistory as jest.Mock).mockReturnValue({
      push: mockPush,
    });
  });

  afterEach(() => {
    jest.clearAllMocks();
    mockAddressesMap = new Map();
  });

  describe('when there are primary receive addresses available', () => {
    beforeEach(() => {
      mockAddressesMap = new Map([
        [EthereumBlockchain.rawValue, ethWalletAddress],
        [SolanaBlockchain.rawValue, solWalletAddress],
        ['CADC', unsupportedWalletAddress],
      ]);
    });

    describe('UTXO extension experiment', () => {
      it('renders UTXO address types when experiment is enabled', () => {
        mockAddressesMap = new Map([
          [EthereumBlockchain.rawValue, ethWalletAddress],
          [SolanaBlockchain.rawValue, solWalletAddress],
          [BitcoinBlockchain.rawValue, btcWalletAddress],
          ['CADC', unsupportedWalletAddress],
        ]);

        const expectedNumListItems = mockAddressesMap.size - 1;
        renderWithAllProviders(<GenericReceiveByAddress />);
        const listItems = queryAllListItems();

        expect(listItems).toHaveLength(expectedNumListItems);
        expect(getListItem(ethWalletAddress)).toBeInTheDocument();
        expect(getListItem(solWalletAddress)).toBeInTheDocument();
        expect(getListItem(btcWalletAddress)).toBeInTheDocument();
        expect(() => getListItem(unsupportedWalletAddress)).toThrow();
      });

      it('does not render UTXO address types when experiment is disabled', () => {
        (useHasUTXOExtensionExperiment as jest.Mock).mockReturnValue(false);
        mockAddressesMap = new Map([
          [EthereumBlockchain.rawValue, ethWalletAddress],
          [SolanaBlockchain.rawValue, solWalletAddress],
          [BitcoinBlockchain.rawValue, btcWalletAddress],
          ['CADC', unsupportedWalletAddress],
        ]);

        const expectedNumListItems = mockAddressesMap.size - 2;
        renderWithAllProviders(<GenericReceiveByAddress />);
        const listItems = queryAllListItems();

        expect(listItems).toHaveLength(expectedNumListItems);
        expect(getListItem(ethWalletAddress)).toBeInTheDocument();
        expect(getListItem(solWalletAddress)).toBeInTheDocument();
        expect(() => getListItem(btcWalletAddress)).toThrow();
        expect(() => getListItem(unsupportedWalletAddress)).toThrow();
      });
    });

    it('renders only supported address types', () => {
      const expectedNumListItems = mockAddressesMap.size - 1;
      renderWithAllProviders(<GenericReceiveByAddress />);
      const listItems = queryAllListItems();

      expect(listItems).toHaveLength(expectedNumListItems);
      expect(getListItem(ethWalletAddress)).toBeInTheDocument();
      expect(getListItem(solWalletAddress)).toBeInTheDocument();
      expect(() => getListItem(unsupportedWalletAddress)).toThrow();
    });

    it('renders onramp when useIsReceiveOnrampCardEnabled is true', () => {
      (useIsReceiveOnrampCardEnabled as jest.Mock).mockReturnValueOnce(true);
      renderWithAllProviders(<GenericReceiveByAddress />);
      expect(screen.getByText('Receive from Coinbase')).toBeTruthy();
    });

    it('fires a screen view event', () => {
      renderWithAllProviders(<GenericReceiveByAddress />);
      expect(useReceiveByGenericAddressScreenViewed).toHaveBeenCalledTimes(1);
      expect(useReceiveByGenericAddressScreenViewed).toHaveBeenCalledWith({
        isQuickCopyUI: false,
        accountType: 'mnemonic',
        walletIndex: '0',
      });
    });
  });

  describe('when the user interacts with the list items controls', () => {
    beforeEach(() => {
      jest.useFakeTimers();

      mockAddressesMap = new Map([
        [EthereumBlockchain.rawValue, ethWalletAddress],
        [SolanaBlockchain.rawValue, solWalletAddress],
      ]);
    });

    afterEach(() => {
      jest.useRealTimers();
    });

    it(`will copy the list item address to the user's clipboard when they click on the copy button`, () => {
      renderWithAllProviders(<GenericReceiveByAddress />);

      expect(mockClearQueue).not.toHaveBeenCalled();
      expect(mockShowToast).not.toHaveBeenCalled();

      getListItemCopyButton(ethWalletAddress).click();

      expect(mockClearQueue).toHaveBeenCalledTimes(1);
      expect(mockShowToast).not.toHaveBeenCalled();

      jest.advanceTimersByTime(0);

      expect(mockShowToast).toHaveBeenCalledWith(expectedText.copiedToast);
      expect(mockShowToast).toHaveBeenCalledTimes(1);
    });

    it('will open the receive wallet address modal when they click on the QR code button for an Ethereum wallet address', () => {
      renderWithAllProviders(<GenericReceiveByAddress />);

      expect(mockOpenModal).not.toHaveBeenCalled();

      getListItemQRCodeButton(ethWalletAddress).click();

      expect(mockOpenModal).toHaveBeenCalledTimes(1);
    });

    it('will open the receive wallet address modal when they click on the QR code button for a Solana wallet address', () => {
      renderWithAllProviders(<GenericReceiveByAddress />);

      expect(mockOpenModal).not.toHaveBeenCalled();

      getListItemQRCodeButton(solWalletAddress).click();

      expect(mockOpenModal).toHaveBeenCalledTimes(1);
    });

    it('should show profile infos and search bar if search asset experiment is enabled', () => {
      (useSearchReceiveAssetEnabled as jest.Mock).mockReturnValue(true);
      renderWithAllProviders(<GenericReceiveByAddress />);

      const searchInput = screen.getByTestId('search-receive-asset-entry-input');
      expect(searchInput).toBeInTheDocument();

      fireEvent.click(searchInput);

      expect(mockPush).toHaveBeenCalledWith('/receive/search');
    });
  });
});

import { Route, Switch } from 'react-router-dom';
