export function Receive() {
  const wallet = useWalletFromPathParams();

  return (
    <ReceiveStepContainer wallet={wallet} learnMoreLink={LINK_CRYPTO_SUPPORT}>
      <Switch>
        <Route path={RoutesEnum.RECEIVE} exact component={ReceiveByAddress} />
        <Route path={RoutesEnum.RECEIVE_ADDRESS} exact component={ReceiveByAddress} />
        <Route path={RoutesEnum.RECEIVE_SEARCH_ASSET} exact component={SearchReceiveAsset} />
      </Switch>
    </ReceiveStepContainer>
  );
}

