import { SearchInput } from '@cbhq/cds-web/controls';
import { Box, VStack } from '@cbhq/cds-web/layout';

import { SearchReceiveAssetList } from './SearchReceiveAssetList';

const messages = defineMessages({
  screenTitle: {
    defaultMessage: 'Which asset are you receiving?',
    description:
      'header title for main SearchReceiveAsset screen. On this screen we show a list of assets for the user to choose',
  },
  searchInputPlaceholder: {
    defaultMessage: 'Search assets',
    description: 'Placeholder for asset search input',
  },

  learnMoreHyperText: {
    defaultMessage: 'Learn more',
    description: 'Copy for more infos hyperlink',
  },
  learnMoreDescription: {
    defaultMessage: 'about how the same asset can exist on different networks.',
    description:
      'Brief preview of what kind of information is going to be found on Learn more hyperlink',
  },
});

const SEARCH_ASSET_QUERY_DEBOUNCE_MS = 300;

function SearchReceiveAssetContent() {
  const { formatMessage } = useIntl();
  const [inputValue, setInputValue] = useState('');
  const [query, setQuery] = useState('');
  const { data, isLoading, error } = useAssetSearch(query);

  const debouncedQueryUpdate = useDebouncedCallback(setQuery, SEARCH_ASSET_QUERY_DEBOUNCE_MS);

  const handleInputChange = useCallback(
    (input: string) => {
      setInputValue(input);
      debouncedQueryUpdate(input);
    },
    [debouncedQueryUpdate],
  );

  return (
    <VStack flexGrow={1}>
      <Box spacingHorizontal={3} spacingBottom={2}>
        <SearchInput
          placeholder={formatMessage(messages.searchInputPlaceholder)}
          value={inputValue}
          onChangeText={handleInputChange}
          autoFocus
          testID="search-receive-address--search-input"
        />
      </Box>
      <SearchReceiveAssetList data={data} loading={isLoading} error={error} />
    </VStack>
  );
}

export function SearchReceiveAsset() {
  useSearchReceiveAssetViewed();

  return (
    <VStack flexGrow={1}>
      <SearchReceiveAssetContent />
    </VStack>
  );
}

