import { logEvent } from 'cb-wallet-analytics/utils/log';
import { cbReportError, shouldReport } from 'cb-wallet-data/errors/reportError';
import { renderWithAllProviders } from 'wallet-cds-web/test/testUtils';

import { ErrorFallback } from '../ErrorFallback/ErrorFallback';

import { RouteErrorBoundary } from './RouteErrorBoundary';

jest.unmock('react-router-dom');
jest.mock('../ErrorFallback/ErrorFallback', () => ({
  ErrorFallback: ({ onPrimaryButtonPress }: React.ComponentProps<typeof ErrorFallback>) => (
    <>
      <div>ErrorFallback__component</div>
      <button
        onClick={() => onPrimaryButtonPress?.()}
        data-testid="error-fallback-primary-button"
      />
    </>
  ),
}));

jest.mock('cb-wallet-analytics/utils/log');
jest.mock('cb-wallet-data/errors/reportError');

jest.mock('cb-wallet-data/hooks/KillSwitches/useOverridableKillSwitch', () => ({
  useOverridableKillSwitch: () => false,
}));
jest.mock('cb-wallet-data/stores/Accounts/hooks/useUserFacingAccountsData', () => ({
  useUserFacingAccountsData: () => ({ accountTotals: {} }),
}));
// disable error output
function onWindowError(e: Event) {
  e.preventDefault();
}

describe('RouteErrorBoundary', () => {
  const mockError = new Error('mock-error');

  beforeEach(() => {
    (shouldReport as jest.Mock).mockReturnValue(false);
    window.addEventListener('error', onWindowError);
  });

  afterEach(() => {
    window.removeEventListener('error', onWindowError);
  });

  const ErrorThrowingChild = () => {
    throw mockError;
  };

  function Home() {
    const history = useHistory();

    return (
      <button type="button" data-testid="go-to-error" onClick={() => history.push('/throw-error')}>
        Go to error
      </button>
    );
  }

  function App({ home }: { home: React.ReactNode }) {
    return (
      <IntlProvider locale="en">
        <MemoryRouter>
          <Switch>
            <Route
              exact
              path="/"
              render={() => <RouteErrorBoundary hideBackToHome>{home}</RouteErrorBoundary>}
            />
            <Route
              exact
              path="/throw-error"
              render={() => (
                <RouteErrorBoundary>
                  <ErrorThrowingChild />
                </RouteErrorBoundary>
              )}
            />
          </Switch>
        </MemoryRouter>
      </IntlProvider>
    );
  }

  async function goToErrorRoute() {
    const goToErrorButton = screen.getByTestId('go-to-error');

    fireEvent(
      goToErrorButton,
      new MouseEvent('click', {
        bubbles: true,
        cancelable: true,
      }),
    );

    await screen.findByText('ErrorFallback__component');
  }

  it('shows the fallback if there is an error', async () => {
    renderWithAllProviders(<App home={<Home />} />);

    await goToErrorRoute();

    expect(screen.getByText('ErrorFallback__component')).toBeDefined();

    expect(cbReportError).not.toHaveBeenCalled();
    expect(logEvent).toHaveBeenCalledOnceWith('route_error_viewed', {
      errorHash: undefined,
      errorMessage: 'mock-error',
      action: 'view',
      componentType: 'page',
    });
  });

  it('reports and logs error if should report', async () => {
    (shouldReport as jest.Mock).mockReturnValue(true);
    (cbReportError as jest.Mock).mockReturnValue({ errorHash: 'mock-errorHash' });

    renderWithAllProviders(<App home={<Home />} />);

    await goToErrorRoute();

    expect(screen.getByText('ErrorFallback__component')).toBeDefined();

    expect(cbReportError).toHaveBeenCalledOnceWith({
      error: mockError,
      errorInfo: expect.any(Object),
      metadata: { route: '/throw-error' },
      context: 'route_error',
      severity: 'error',
      isHandled: false,
    });
    expect(logEvent).toHaveBeenCalledOnceWith('route_error_viewed', {
      errorHash: 'mock-errorHash',
      errorMessage: 'mock-error',
      action: 'view',
      componentType: 'page',
    });
  });

  it('goes back to home when reset is called', async () => {
    renderWithAllProviders(<App home={<Home />} />);

    await goToErrorRoute();

    fireEvent(
      screen.getByTestId('error-fallback-primary-button'),
      new MouseEvent('click', {
        bubbles: true,
        cancelable: true,
      }),
    );

    expect(screen.getByTestId('go-to-error')).toBeDefined();
  });
});

import { ChangeEvent, useCallback, useMemo, useState } from 'react';
