type NoRecipientSuggestionsProps = {
  errorType: DestinationError | null;
  wallet: Wallet;
  handleSuggestionClick: (destination: DestinationSearchResultType) => void;
  handleDismissErrorClick: () => void;
  handleClearAddressClick: () => void;
};

function NoRecipientSuggestionsComponent({
  errorType,
  wallet,
  handleSuggestionClick,
  handleDismissErrorClick,
  handleClearAddressClick,
}: NoRecipientSuggestionsProps) {
  const isRecipientSuggestionsEnabled = useHasNewRecipientTabEnabled();

  const clearAddressClicked = useCallback(() => {
    logMaliciousAddressWarningClearAddressClicked({
      blockchain: wallet.blockchain.rawValue,
      chainId: wallet.network.asChain()?.chainId,
      chainName: wallet.network.asChain()?.displayName,
      currencyCode: wallet.currencyCode.code,
      contractAddress: wallet.contractAddress,
      errorType: errorType?.toString() ?? '',
    });
    handleClearAddressClick();
  }, [
    wallet.blockchain.rawValue,
    wallet.network,
    wallet.currencyCode.code,
    wallet.contractAddress,
    errorType,
    handleClearAddressClick,
  ]);

  const handleDismissClicked = useCallback(() => {
    logMaliciousAddressWarningDismissClicked({
      blockchain: wallet.blockchain.rawValue,
      chainId: wallet.network.asChain()?.chainId,
      chainName: wallet.network.asChain()?.displayName,
      currencyCode: wallet.currencyCode.code,
      contractAddress: wallet.contractAddress,
      errorType: errorType?.toString() ?? '',
    });
    handleDismissErrorClick();
  }, [
    wallet.blockchain.rawValue,
    wallet.network,
    wallet.currencyCode.code,
    wallet.contractAddress,
    errorType,
    handleDismissErrorClick,
  ]);

  useEffect(
    function logMaliciousAddressWarningViewedEffect() {
      if (
        errorType &&
        [DestinationError.containsHomoglyphs, DestinationError.maliciousAddress].includes(errorType)
      ) {
        logMaliciousAddressWarningViewed({
          blockchain: wallet.blockchain.rawValue,
          chainId: wallet.network.asChain()?.chainId,
          chainName: wallet.network.asChain()?.displayName,
          currencyCode: wallet.currencyCode.code,
          contractAddress: wallet.contractAddress,
          errorType: errorType?.toString() ?? '',
          source: 'send',
        });
      }
    },
    [
      errorType,
      wallet.blockchain.rawValue,
      wallet.contractAddress,
      wallet.currencyCode.code,
      wallet.network,
    ],
  );

  if (!errorType) {
    return isRecipientSuggestionsEnabled ? (
      <RecipientSuggestionsTab wallet={wallet} handleSuggestionClick={handleSuggestionClick} />
    ) : null;
  }

  // both homoglyphs and malicious addresses are technically valid and we do not want to hard block users
  const isErrorDismissable =
    errorType === DestinationError.containsHomoglyphs ||
    errorType === DestinationError.maliciousAddress;

  const { headline, message } = errorContent[errorType];

  return (
    <VStack alignItems="center">
      <Box>{headline}</Box>
      <TextLabel2
        as="p"
        align="center"
        color="foregroundMuted"
        spacingTop={1}
        spacingHorizontal={4}
      >
        {message}
      </TextLabel2>

      {isErrorDismissable && (
        <VStack spacingTop={3} gap={1} width="100%" spacingHorizontal={2}>
          <Button variant="primary" onPress={clearAddressClicked}>
            <FormattedMessage {...messages.clearAddressButtonText} />
          </Button>
          <Button variant="negative" onPress={handleDismissClicked}>
            <FormattedMessage {...messages.dismissErrorButtonText} />
          </Button>
        </VStack>
      )}
    </VStack>
  );
}

