import { SetPassword } from 'wallet-cds-extension/components/SetPassword/SetPassword';
import { ValidatedTextInput } from 'wallet-cds-extension/components/ValidatedTextInput/ValidatedTextInput';
import { useToast } from 'wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast';
import { Button } from '@cbhq/cds-web/buttons';
