  const profileAddress = useProfileAddressForWalletGroupId(walletGroup.id);
  const { profile } = useUserProfile(profileAddress);
  const sharedMessages = useHideWalletGroupCopy();
  const getShouldSuppressDIDFeature = useGetShouldSuppressDIDFeature();
  const themeColorPreference = useThemeColor({ walletGroupId: walletGroup.id });
  const spectrum = useSpectrum();
  const getAccountById = useGetAccountById();
  const isShowPrivateKeyFeatureEnabled = useIsFeatureEnabled('export_private_key');
  const canClaimSubdomainFromSettings = useCanClaimSubdomainFromSettings(
    activeWalletGroupId,
    profileAddress,
    walletGroup,
