  const showManageProfileLink = Boolean(profile?.isSubdomain) && !shouldSuppressDIDFeature;

  const displayName = useMemo(
    () => getWalletGroupDisplayName(walletGroup),
    [getWalletGroupDisplayName, walletGroup],
  );

  const availableWalletGroups = useMemo(
    () => visibleWalletGroups.filter((wg) => wg.id !== activeWalletGroupId),
    [visibleWalletGroups, activeWalletGroupId],
  );

  const newWalletGroupToDisplay = useWalletGroupToDisplay(availableWalletGroups[0]?.id);
  const showPrivateKey = useMemo(
    () =>
      isShowPrivateKeyFeatureEnabled && getAccountById(walletGroup.accountId)?.hasLocallyStoredKey,
    [getAccountById, isShowPrivateKeyFeatureEnabled, walletGroup.accountId],
  );

  const handleGoToNickname = useCallback(() => {
