const OUTER_SELECTOR_SIZE = 40;
const INNER_SELECTOR_SIZE = 24;

function entries<T extends Record<keyof T, T[keyof T]>>(item: T) {
  return Object.entries(item) as [keyof T, T[keyof T]][];
}

type ThemeColorSelectorProps = {
  preference: CombinedThemeColorPreference;
  walletGroupId: string;
  setPreference: (walletGroupId: string, preference: CombinedThemeColorPreference) => Promise<void>;
};

type ThemeColorSelectorItemProps = {
  name: CombinedThemeColorPreference;
  config:
    | (typeof themeColorConfigs)[ThemeColorPreference]
    | (typeof miamiThemeColorConfigs)[MiamiThemeColorPreference];
} & ThemeColorSelectorProps;

const messages = defineMessages({
  title: {
    description: 'Title for theme color settings page.',
    defaultMessage: 'Theme color',
  },
  switcherTitle: {
    description: 'Title for theme color switcher component',
    defaultMessage: 'Select color',
  },
});

const ThemeColorSelectorItem = memo(function ThemeColorSelectorItem({
  preference,
  config,
  walletGroupId,
  name,
  setPreference,
}: ThemeColorSelectorItemProps) {
  const spectrum = useSpectrum();
  const active = preference === name;
  const outerBackgroundColor = useSpectrumConditional({
    light: active ? 'background' : 'transparent',
    dark: active ? 'secondary' : 'transparent',
  } as const);

  const handleOnPress = useCallback(async () => {
    triggerThemeColorChange(preference, name);
    await setPreference(walletGroupId, name);
  }, [walletGroupId, name, setPreference, preference]);

  const preferenceBackground = useMemo(() => {
    return paletteValueToRgbaString(config.primary, spectrum);
  }, [config.primary, spectrum]);

  return (
    <Pressable
      background="secondary"
      borderRadius="roundedFull"
      onPress={handleOnPress}
      testID={`theme-color-preference-button-${name}`}
      transparentWhileInactive
    >
      <Box
        alignItems="center"
        background={outerBackgroundColor}
        borderRadius="roundedFull"
        height={OUTER_SELECTOR_SIZE}
        justifyContent="center"
        width={OUTER_SELECTOR_SIZE}
      >
        <Box
          width={INNER_SELECTOR_SIZE}
          height={INNER_SELECTOR_SIZE}
          borderRadius="roundedFull"
          dangerouslySetBackground={preferenceBackground}
        />
      </Box>
    </Pressable>
  );
});

export function ThemeColorPage() {
  const { goBack } = useHistory();
  const { formatMessage } = useIntl();
  const setPreference = useSetThemeColor();
  const { walletGroupId } = useParams<{ walletGroupId: string }>();
  const preference = useThemeColor({ walletGroupId: decodeURIComponent(walletGroupId) });
  triggerSettingsButtonClick('themes');
  return (
    <Screen
      header={
        <NavBar variant="secondary" title={formatMessage(messages.title)} handleBack={goBack} />
      }
    >
      <VStack spacingBottom={3} gap={3}>
        <ThemeColorIllustration preference={preference} />
        <VStack spacingHorizontal={3} gap={1}>
          <TextLabel2 as="p">{formatMessage(messages.switcherTitle)}</TextLabel2>
          <HStack
            spacing={0.5}
            gap={2}
            width="100%"
            alignItems="center"
            justifyContent="center"
            background="backgroundAlternate"
            borderRadius="roundedFull"
          >
            {entries(themeColorConfigs).map(([name, config]) => {
              return (
                <ThemeColorSelectorItem
                  key={name}
                  preference={preference}
                  walletGroupId={decodeURIComponent(walletGroupId)}
                  config={config}
                  name={name}
                  setPreference={setPreference}
                />
              );
            })}
          </HStack>
        </VStack>
      </VStack>
    </Screen>
  );
}

