    };
  }, [addIconBackGroundColor, borderColor]);

  const AddIcon = useMemo(() => {
    return (
      <Icon
        name="add"
        size="s"
        spacing={0.5}
        dangerouslySetColor={addIconColor}
        testID="add-icon"
      />
    );
  }, [addIconColor]);

  const media = useMemo(() => {
    if (walletGroupsToDisplay.length <= 1) {
      return (
        <Box bordered style={addIconSingleWalletGroupContainerStyle}>
          {AddIcon}
        </Box>
      );
    }

    return (
      <HStack alignItems="center" position="relative" width={70} spacingVertical={2}>
        <Box borderColor="transparent" bordered style={iconContainerStyle}>
          <WalletGroupAvatar
            walletGroup={walletGroupsToDisplay[0]}
            size="m"
            testID="wallet-avatar"
          />
        </Box>
        <Box bordered left={20} style={iconContainerStyle}>
          <WalletGroupAvatar
            walletGroup={walletGroupsToDisplay[1]}
            size="m"
            testID="wallet-avatar"
          />
        </Box>
        <Box bordered left={40} style={addIconMultiWalletGroupsContainerStyle}>
          {AddIcon}
        </Box>
      </HStack>
    );
  }, [
    AddIcon,
    addIconSingleWalletGroupContainerStyle,
    addIconMultiWalletGroupsContainerStyle,
    iconContainerStyle,
    walletGroupsToDisplay,
  ]);

  const handlePress = useCallback(
    function handleManageAllWalletsPress() {
      logSettingCategoryPressed({ context: 'manage_all_wallets' });
      navigate(SettingsRoutesEnum.MANAGE_WALLETS);
      onPress?.();
    },
    [navigate, onPress],
  );

  const config = useMemo<SettingCategoryConfig>(
    () => ({
      ...manageAllWalletsConfig,
      title: (
        <TextBody as="p" color="foregroundMuted">
          {manageAllWalletsConfig.title}
        </TextBody>
      ),
      media,
      innerSpacing: { spacingHorizontal: 0.5 },
      outerSpacing: NO_DESCRIPTION_OUTER_SPACING,
    }),
    [manageAllWalletsConfig, media],
  );

  return (
    <Box spacingHorizontal={2} spacingVertical={1}>
      <Pressable
        background="backgroundAlternate"
        borderRadius="roundedLarge"
        onPress={handlePress}
        testID="manage-all-wallets-pressable"
        block
        noScaleOnPress
      >
        <SettingCell config={config} />
      </Pressable>
    </Box>
  );
});

