import { useCallback, useMemo, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useSettingsSearch } from 'cb-wallet-data/stores/SettingsRedesign/hooks/useSettingsSearch';
import { SettingCategoryConfig } from 'cb-wallet-data/stores/SettingsRedesign/types';
import { Screen } from 'wallet-cds-extension/components/Screen/Screen';
import { SearchBar, SearchBarProps } from 'wallet-cds-extension/components/SearchBar/SearchBar';
import { NoopFn } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-web/buttons';
import { HStack, VStack } from '@cbhq/cds-web/layout';

import { SettingCategoriesListItem } from ':extension/screens/SettingsRedesign/components/SettingCategoriesListItem';

const messages = defineMessages({
  accessibilityLabel: {
    defaultMessage: 'Enter text to search settings',
    description: 'Accessibility label for the settings search bar',
  },
});

type SearchProps = {
  configs: SettingCategoryConfig[];
  onCancel: NoopFn;
};

export const SEARCH_INPUT_DEBOUNCE_TIME = 300;

export function Search({ configs, onCancel }: SearchProps) {
  const { formatMessage } = useIntl();

  const [query, setQuery] = useState('');

  const settingsSuggestions = useMemo(() => {
    return configs.reduce((suggestions: SettingCategoryConfig[], config) => {
      suggestions.push(config);
      for (const subCategory of config.subCategories ?? []) {
        suggestions.push(subCategory);
      }
      return suggestions;
    }, []);
  }, [configs]);

  const filteredSuggestions = useSettingsSearch({
    suggestions: settingsSuggestions,
    query,
  });

  const handleOnSearch = useCallback(
    function handleSettingSearch(queryText: string) {
      setQuery(queryText);
    },
    [setQuery],
  );

  const handleOnKeyDown = useCallback<NonNullable<SearchBarProps['onKeyDown']>>(
    function handleOnKeyDown(e) {
      if (!query && ['Enter', 'Escape'].includes(e.key)) {
        onCancel();
      }
    },
    [onCancel, query],
  );

  const renderConfig = useCallback(function renderConfig(config: SettingCategoryConfig, i: number) {
    if (config.isHiddenOnSearch) return null;

    return (
      <SettingCategoriesListItem item={config} key={config.testID ?? `setting-category-${i}`} />
    );
  }, []);

  return (
    <Screen testID="setting-search" height="100%">
      <HStack spacingTop={3} spacingEnd={3} spacingBottom={1} spacingStart={1} alignItems="center">
        <IconButton name="backArrow" onPress={onCancel} transparent testID="cancel-search" />
        <SearchBar
          accessibilityLabel={formatMessage(messages.accessibilityLabel)}
          onSearch={handleOnSearch}
          onKeyDown={handleOnKeyDown}
          testID="settings-search-bar"
          compact
          autoFocus
          hideStartIcon
        />
      </HStack>
      <VStack testID="setting-search-results-list">
        {filteredSuggestions.length > 0 && filteredSuggestions.map(renderConfig)}
      </VStack>
    </Screen>
  );
}

import { memo, useCallback, useMemo } from 'react';
import { useHistory } from 'react-router-dom';
import { triggerWalletGroupVisibilityToggled } from 'cb-wallet-analytics/accounts';
import { logSettingWalletSubCategoryPressed } from 'cb-wallet-analytics/settings';
import {
  SettingCategoryConfig,
  WalletsSubCategoryConfigsProps,
} from 'cb-wallet-data/stores/SettingsRedesign/types';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { useGetWalletGroupDisplayName } from 'cb-wallet-data/stores/WalletGroups/hooks/useGetWalletGroupDisplayName';
import { useHideWalletGroupCopy } from 'cb-wallet-data/stores/WalletGroups/hooks/useHideWalletGroupCopy';
import { useSetActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useSetActiveWalletGroupId';
import { useSetWalletGroupIsHidden } from 'cb-wallet-data/stores/WalletGroups/hooks/useSetWalletGroupIsHidden';
import { useWalletGroups } from 'cb-wallet-data/stores/WalletGroups/hooks/useWalletGroups';
import { useWalletGroupToDisplay } from 'cb-wallet-data/stores/WalletGroups/hooks/useWalletGroupToDisplay';
import { useToast } from 'wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast';
import { Switch } from '@cbhq/cds-web/controls';
import { Icon } from '@cbhq/cds-web/icons';
import { Box, HStack } from '@cbhq/cds-web/layout';
import { Tooltip } from '@cbhq/cds-web/overlays';
import { TextBody } from '@cbhq/cds-web/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';

import { RoutesEnum } from ':extension/screens/Routes/Routes';

import { innerSpacing } from '../consts/configs';

const DEFAULT_TOAST_BOTTOM_OFFSET = 50;

const HideWalletTitle = memo(function HideWalletTitle() {
  const messages = useHideWalletGroupCopy();

  return (
    <HStack alignItems="center" gap={1}>
      <TextBody as="p">{messages.hideWalletSettingTitle}</TextBody>
      <Tooltip testID="hide-wallet-tooltip" content={messages.hideWalletTooltipDetailText}>
        <Icon name="info" size="xs" color="foreground" />
      </Tooltip>
    </HStack>
  );
});

export function useHideAddressGroupConfig({ walletGroup }: WalletsSubCategoryConfigsProps) {
  const history = useHistory();
  const messages = useHideWalletGroupCopy();
  const setWalletGroupIsHidden = useSetWalletGroupIsHidden();
  const visibleWalletGroups = useWalletGroups({ visible: true });
  const toast = useToast();
  const activeWalletGroupId = useActiveWalletGroupId();
  const setActiveWalletGroupId = useSetActiveWalletGroupId();
  const getWalletGroupDisplayName = useGetWalletGroupDisplayName();

  const availableWalletGroups = useMemo(
    () => visibleWalletGroups.filter((wg) => wg.id !== activeWalletGroupId),
    [visibleWalletGroups, activeWalletGroupId],
  );

  const newWalletGroupToDisplay = useWalletGroupToDisplay(availableWalletGroups[0]?.id);

  const walletGroupDisplayName = useMemo(
    () => getWalletGroupDisplayName(walletGroup),
    [getWalletGroupDisplayName, walletGroup],
  );

  const undoHideWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
    } catch {
      toast.show(messages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    setWalletGroupIsHidden,
    messages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const undoUnhideWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
    } catch {
      toast.show(messages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    setWalletGroupIsHidden,
    messages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const undoHideActiveWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
      setActiveWalletGroupId(walletGroup.id);
    } catch {
      toast.show(messages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    setActiveWalletGroupId,
    setWalletGroupIsHidden,
    messages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const isPrevRouteSettings = useMemo(() => {
    return (
      // @ts-expect-error Type def for history is missing entries
      history.entries.length > 2 && history.entries.at(-2).pathname === RoutesEnum.SETTINGS
    );
  }, [history]);

  const handleChange = useCallback(async () => {
    try {
      const newIsHiddenStatus = !walletGroup.isHidden;
      await setWalletGroupIsHidden(walletGroup.id, newIsHiddenStatus);
      triggerWalletGroupVisibilityToggled({
        action: ActionType.click,
        componentType: ComponentType.checkbox,
        walletIndex: walletGroup.walletIndex.toString(),
        isHidden: newIsHiddenStatus,
      });
      logSettingWalletSubCategoryPressed({ context: 'hide_address_group' });
      if (activeWalletGroupId === walletGroup.id) {
        setActiveWalletGroupId(availableWalletGroups[0]?.id);
        // <walletGroupDisplayName> is hidden. Switched to <newWalletGroupDisplayName>
        toast.show(
          `${walletGroupDisplayName} ${
            messages.activeWalletHiddenToastText
          } ${getWalletGroupDisplayName(newWalletGroupToDisplay)}.`,
          {
            bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
            action: {
              label: 'Undo',
              onPress: undoHideActiveWallet,
            },
          },
        );

        if (isPrevRouteSettings) {
          history.push(RoutesEnum.PORTFOLIO);
        } else {
          history.goBack();
        }
      } else if (!walletGroup.isHidden) {
        // <walletGroupDisplayName> is hidden
        toast.show(`${walletGroupDisplayName} ${messages.walletHiddenToastText}`, {
          bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
          action: {
            label: 'Undo',
            onPress: undoHideWallet,
          },
        });
        history.goBack();
      } else {
        // <walletGroupDisplayName> is visible
        toast.show(`${walletGroupDisplayName} ${messages.walletVisibleToastText}`, {
          bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
          action: {
            label: 'Undo',
            onPress: undoUnhideWallet,
          },
        });
        history.go(-2); // Go back 2 screens to avoid the empty "Hidden Wallets" page
      }
    } catch {
      toast.show(messages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    walletGroup.isHidden,
    walletGroup.id,
    walletGroup.walletIndex,
    setWalletGroupIsHidden,
    activeWalletGroupId,
    setActiveWalletGroupId,
    availableWalletGroups,
    toast,
    walletGroupDisplayName,
    messages.activeWalletHiddenToastText,
    messages.walletHiddenToastText,
    messages.walletVisibleToastText,
    messages.hideWalletError,
    getWalletGroupDisplayName,
    newWalletGroupToDisplay,
    undoHideActiveWallet,
    isPrevRouteSettings,
    history,
    undoHideWallet,
    undoUnhideWallet,
  ]);

  const isHideWalletDisabled = useMemo(() => {
    return !walletGroup.isHidden && visibleWalletGroups.length <= 1;
  }, [visibleWalletGroups.length, walletGroup.isHidden]);

  const handleDisabledClick = useCallback(() => {
    toast.show(messages.disabledClickToastText, {
      bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
    });
  }, [messages.disabledClickToastText, toast]);

  const detail = useMemo(
    () => (
      <Box onClick={isHideWalletDisabled ? handleDisabledClick : undefined}>
        <Switch
          testID={`hide-wallet-switch${walletGroup.isHidden ? '-checked' : ''}`}
          onChange={handleChange}
          checked={walletGroup.isHidden}
          disabled={isHideWalletDisabled}
        />
      </Box>
    ),
    [handleChange, handleDisabledClick, isHideWalletDisabled, walletGroup.isHidden],
  );

  const config = useMemo<SettingCategoryConfig>(() => {
    return {
      title: <HideWalletTitle />,
      titleText: messages.hideWalletSettingTitle,
      testID: `hide-address-group-setting`,
      detail,
      detailWidth: 60,
      innerSpacing,
      isHiddenOnSearch: true,
    };
  }, [detail, messages.hideWalletSettingTitle]);

  return config;
}

