    submitPasswordResult,
  }: {
    submitPasswordResult: UnlockResult;
  }) => void;
};

export function ViewSecretPasswordInput({
  onPasswordEntrySuccess,
  accountId: uriEncodedAccountId,
}: ViewSecretPasswordInputProps) {
  const { formatMessage } = useIntl();
  const accountId = useMemo(() => decodeURIComponent(uriEncodedAccountId), [uriEncodedAccountId]);

  const [isChecked, setIsChecked] = useState<boolean>(false);
  const [passwordError, setPasswordError] = useState<boolean>(false);
  const [password, setPassword] = useState<string>('');

  useShowRecoveryPhraseViewed();

  const onPasswordChange = useCallback(
    (value: string) => {
      if (passwordError) {
        setPasswordError(!passwordError);
      }
      setPassword(value);
    },
    [passwordError],
  );

  const handleOnNext = useCallback(async () => {
    logEvent('show_recovery_phrase.next_btn', {
      loggingId: '0c8a7e38-d3b4-40cb-86b1-77d88a7734be',
      action: ActionType.click,
      componentType: ComponentType.button,
    });

    const submitPasswordResult = await appLockRepository.submitPassword(
      password,
      accountId,
      SecretAccessContext.ShowRecoveryPhrase,
    );

    if (submitPasswordResult.status === 'FAILURE') {
      logEvent('show_recovery_phrase.password_error', {
        loggingId: '0f6cbe6d-530a-451c-ba79-0883bf4982ad',
        action: ActionType.render,
        componentType: ComponentType.text,
      });
      setPasswordError(true);
      return;
    }

    setPasswordError(false);
    logEvent('show_recovery_phrase.password_success', {
      loggingId: '1f6cb833-90ec-48fe-88d4-f8712e0cc363',
      action: ActionType.render,
      componentType: ComponentType.unknown,
    });

    if (onPasswordEntrySuccess) {
      onPasswordEntrySuccess({ submitPasswordResult });
    }
  }, [password, accountId, onPasswordEntrySuccess]);

  const disabled = !isChecked || password.length <= 0;

  const handleCheckToggle = useCallback(() => {
    setIsChecked((checked) => !checked);
  }, []);

  const accountType = useMemo(() => {
    try {
      return Account.parseMnemonicOrPrivateKeyFromId(accountId);
    } catch (e: ErrorOrAny) {
      const err = coerceError(e, 'showSecret');
      cbReportError({
        error: err,
        context: 'secret',
        isHandled: false,
        severity: 'error',
      });
      throw e;
    }
  }, [accountId]);

  const backupSpecificMessages = useMemo(
    () => ({
      [AccountType.MNEMONIC]: {
        title: formatMessage(messages.pageTitle, {
          backupType: formatMessage(backupTypeMessages.backupTypeMnemonic),
        }),
        instructions: formatMessage(messages.pageInstructions, {
          backupType: formatMessage(backupTypeMessages.backupTypeMnemonic),
