        termsAndConditions: formatMessage(messages.pageTermsAndConditions, {
          backupType: formatMessage(backupTypeMessages.backupTypeMnemonic),
        }),
      },
      [AccountType.PRIVATE_KEY]: {
        title: formatMessage(messages.pageTitle, {
          backupType: formatMessage(backupTypeMessages.backupTypePrivateKey),
        }),
        instructions: formatMessage(messages.pageInstructions, {
          backupType: formatMessage(backupTypeMessages.backupTypePrivateKey),
        }),
        termsAndConditions: formatMessage(messages.pageTermsAndConditions, {
          backupType: formatMessage(backupTypeMessages.backupTypePrivateKey),
        }),
      },
    }),
    [formatMessage],
  );

  return (
    <VStack spacingHorizontal={3} justifyContent="space-between" height="100%">
      <VStack gap={2} spacingBottom={4}>
        <TextTitle1 as="h3">{backupSpecificMessages[accountType].title}</TextTitle1>
        <TextBody as="div" color="foregroundMuted">
          {backupSpecificMessages[accountType].instructions}
        </TextBody>
      </VStack>
      <VStack gap={1} flexGrow={1}>
        <ValidatedTextInput
          testID="show-secret-password"
          type="password"
          name="password"
          label={formatMessage(messages.password)}
          value={password}
          autoFocus
          onChange={onPasswordChange}
          givenError={passwordError ? formatMessage(messages.incorrectPassword) : undefined}
          onEnter={disabled ? undefined : handleOnNext}
        />
        <Checkbox
          testID="show-secret-checkbox"
          label={
            <TextLegal as="span">
              {backupSpecificMessages[accountType].termsAndConditions}
            </TextLegal>
          }
          isChecked={isChecked}
          onCheckToggle={handleCheckToggle}
        />
      </VStack>
      <VStack spacingVertical={3}>
        <Button testID="show-secret-next-btn" block onPress={handleOnNext} disabled={disabled}>
          {formatMessage(messages.next)}
        </Button>
      </VStack>
    </VStack>
  );
}

