export const TOSBackupSecretBeforeSignout = memo(function TOSBackupSecretBeforeSignout() {
  const { formatMessage } = useIntl();
  const { goBack, push } = useHistory();
  const { blurredTextPlaceholder } = useBackupRecoveryPhraseCopy();
  const activeAccountId = useActiveAccountId();

  useTOSBackupSecretViewed();

  const [secret, setSecret] = useState<string | undefined>();

  useEffect(
    function getDecryptedSecret() {
      (async () => {
        if (secret) return;

        const decryptedSecret = await appLockRepository.getSecretForAccountPromise({
          accountId: activeAccountId,
        });

        if (!decryptedSecret) {
          goBack();
        }

        setSecret(decryptedSecret);
      })();
    },
    [activeAccountId, goBack, secret],
  );

  const handleSubmit = useCallback(() => {
    logTOSBackupSecretDoneClicked();
    push('/tosSignoutConfirmation');
  }, [push]);

  if (!secret) return null;

  return (
    <Screen
      height="100%"
      header={
        <NavBar
          variant="secondary"
          title={formatMessage(messages.navBarTitle)}
          actions={
            <Pressable
              as="button"
              onPress={goBack}
              testID="nav-close-button"
              background="transparent"
            >
              <Icon name="close" size="s" color="foreground" />
            </Pressable>
          }
        />
      }
    >
      <VStack flexGrow={1} gap={2} spacingHorizontal={3}>
        <TextTitle3 as="p">{formatMessage(messages.title)}</TextTitle3>
        <TextBody as="p">{formatMessage(messages.info)}</TextBody>
        <BlurText text={secret} placeholder={blurredTextPlaceholder} />
      </VStack>
      <VStack spacingHorizontal={3}>
        <Button onPress={handleSubmit} testID="submit-btn">
          {formatMessage(messages.button)}
        </Button>
      </VStack>
    </Screen>
  );
});

