const messages = defineMessages({
  sendButton: {
    defaultMessage: 'Send',
    description: 'page title',
  },
  cancelButton: {
    defaultMessage: 'Cancel',
    description: 'cancel button',
  },
  copyText: {
    defaultMessage: 'Address copied',
    description: 'Text for copied address',
  },
  revokingApproval: {
    defaultMessage: 'Revoking approval',
    description: 'Text for revoking approval',
  },
});

type Props = {
  wallet: Wallet;
  unsignedTx: UnsignedTx;
  isTxScannerError: boolean;
  isTxScannerLoading: boolean;
  isTxScannerEnabled?: boolean;
  txScannerLoadStartTime: number | undefined;
  resetLoadTimer: () => void;
  parsedOperations?: CategorizedParsedOperations;
  headerDappName: string;
  txScannerNotices?: TxScannerNotice[];
};

export function TransactionRequestStep({
  wallet,
  unsignedTx,
  isTxScannerLoading,
  parsedOperations,
  txScannerNotices,
  isTxScannerError,
  txScannerLoadStartTime,
  resetLoadTimer,
  headerDappName,
  isTxScannerEnabled,
}: Props) {
  const exchangeRatesMap = useExchangeRatesMap();
  const activeFiatCurrency = useActiveFiatCurrency();
  const { setShowNavigation } = useContext(NavigationContext);
  const { formatMessage } = useIntl();
  const { hasLocallyStoredKey, isLedgerAccount } = useAccountById(wallet.accountId);
  const { goToStep } = useStepper(stepper);
  const currencyFormatter = useCurrencyFormatter();
  const { show } = useToast();
  const isAdjustableMinerFeeEnabled = useIsAdjustableMinerFeeEnabled();
  const is1559Enabled = useMemo(() => isNetwork1559Enabled(wallet.network), [wallet]);
  const isTxPreviewEnabled = useIsTxPreviewEnabled();
  const networkChainId = wallet.network.asChain()?.chainId;

  const isRevokeOperation = useIsRevokeOperation(parsedOperations);

  const isETHWallet = useMemo(
    () =>
      Blockchain.isEqual(wallet.blockchain, EthereumBlockchain) &&
      CurrencyCode.isEqual(wallet.currencyCode, CurrencyCode.ETH) &&
      Network.isEqual(wallet.network, new Network('ETHEREUM_CHAIN:1', false)) &&
      wallet.contractAddress === undefined,
    [wallet],
  );

  useOnMount(() => {
    revokeApprovalConfirmationScreenViewed();
  });
  useEffect(() => {
    setShowNavigation(false);
  }, [setShowNavigation]);

  const handleBackClick = useCallback(() => {
    setShowNavigation(true);
    goToStep('viewTokenApprovals');
  }, [goToStep, setShowNavigation]);

  const onCancelClick = useCallback(() => {
    revokeApprovalCancelOnConfirmation();
    handleBackClick();
  }, [handleBackClick]);

  const signError = useCallback(
    (signingError: Error) => {
      revokeApprovalSignErrorOnConfirmation();
      cbReportError({
        error: signingError,
        context: 'transactions',
        severity: 'error',
        isHandled: false,
      });
      handleBackClick();
    },
    [handleBackClick],
  );

  const signLedgerError = useCallback(
    (ledgerError: Error) => {
      cbReportError({
        error: new Error(ledgerError.message),
        context: 'ledger-error',
        severity: 'error',
        isHandled: false,
      });
      signError(ledgerError);
    },
    [signError],
  );

  const signSuccess = useCallback(
    (_signedTx: SignedTx) => {
      revokeApprovalSuccessfulSubmitOnConfirmation();
      show(formatMessage(messages.revokingApproval));
      handleBackClick();
    },
    [handleBackClick, show, formatMessage],
  );

  const handleUnlock = useHandleUnlockForSigning();
  const { signAndSubmitStandalone, isSignAndSubmitStandaloneLoading } = useSignAndSubmitStandalone({
    wallet,
    unsignedTx,
    signSuccess,
    signError,
    handleUnlock: handleUnlock(wallet.accountId),
  });

  const { signAndSubmitLedger, isHardwareWalletSigning, hardwareWalletScreen } =
    useSignAndSubmitLedger({
      unsignedTx,
      onSignSuccess: signSuccess,
      onSignError: signLedgerError,
      flow: Flow.Revoke,
    });

  const isLoading = isSignAndSubmitStandaloneLoading ?? isHardwareWalletSigning;

  const isAdjustableGasEnabled = useMemo(
    () => hasLocallyStoredKey && is1559Enabled && (!isProd() || isAdjustableMinerFeeEnabled),
    [isAdjustableMinerFeeEnabled, is1559Enabled, hasLocallyStoredKey],
  );
  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useTxFeeWallet(activeWalletGroupId, unsignedTx);

  const formattedNetworkFee = useMemo(() => {
    let fiatFee: string | undefined = '';

    if (is1559Enabled) {
      const eth1559Tx = unsignedTx as EthereumUnsigned1559Tx;
      fiatFee = currencyFormatter.formatToFiatFeeRange({
        fromCurrencyCode: eth1559Tx.feeCurrencyCode,
        decimals: eth1559Tx.feeCurrencyDecimal,
        upperBoundValue: eth1559Tx.upperBoundFee,
        isAbbreviated: false,
        lowerBoundValue: eth1559Tx.lowerBoundFee,
        network: eth1559Tx.network,
        blockchain: eth1559Tx.blockchain,
      });
    } else {
      fiatFee = currencyFormatter.formatToFiat(
        unsignedTx.feeCurrencyCode,
        unsignedTx.feeCurrencyDecimal,
        unsignedTx.estimatedFee,
        false,
        undefined,
        wallet.network,
        wallet.blockchain,
      );
    }

    return fiatFee ?? '';
  }, [currencyFormatter, is1559Enabled, unsignedTx, wallet.network, wallet.blockchain]);

  const openAdjustableGasPreset = useCallback(() => {
    goToStep('adjustGasPreset');
  }, [goToStep]);

  const AdjustGasPresetAction = useMemo(
    () =>
      isAdjustableGasEnabled ? (
        <Pressable
          as="button"
          testID="revoke-confirmation-adjustable-gas-entry"
          onPress={openAdjustableGasPreset}
          background="transparent"
        >
          <Icon name="gear" size="s" color="foreground" spacingStart={1} />
        </Pressable>
      ) : null,
    [isAdjustableGasEnabled, openAdjustableGasPreset],
  );

  const onCopy = useCallback(() => {
    navigator.clipboard.writeText(unsignedTx.recipientAddress);
    show(formatMessage(messages.copyText));
  }, [formatMessage, show, unsignedTx.recipientAddress]);

  const CopyContractAction = useMemo(
    () => (
      <Pressable as="button" onPress={onCopy} background="transparent">
        <Icon name="copy" size="s" color="foreground" spacingStart={1} />
      </Pressable>
    ),
    [onCopy],
  );

  const rowDetails = useMemo(
    () => ({
      formattedNetworkFee,
      wallet,
      AdjustGasPresetAction,
      contractAddress: unsignedTx.recipientAddress,
      CopyContractAction,
    }),
    [AdjustGasPresetAction, formattedNetworkFee, wallet, unsignedTx, CopyContractAction],
  );

  const detailRows = useTransactionDetailRowItems(rowDetails);

  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx,
    feeWallet,
    flow: 'revoke',
  });

  const analyticsData = useSignTransactionEventData({
    request: 'revoke',
    dappURL: '',
    blockchain: wallet.blockchain.toString(),
    txScannerData: parsedOperations,
    txScannerNotices,
    walletIndex: wallet.selectedIndex?.toString(),
    isTxPreviewEnabled,
  });

  const handleOnSend = useCallback(async () => {
    revokeApprovalSubmitOnConfirmation();
    if (hasLocallyStoredKey) {
      return signAndSubmitStandalone();
    }

    if (isLedgerAccount) {
      return signAndSubmitLedger();
    }
    goToStep('signOnPhone');
  }, [
    hasLocallyStoredKey,
    isLedgerAccount,
    goToStep,
    signAndSubmitStandalone,
    signAndSubmitLedger,
  ]);

  const buttonOptions: ButtonProps[] = useMemo(() => {
    return [
      {
        children: formatMessage(messages.cancelButton),
        variant: 'secondary',
        onPress: onCancelClick,
        testID: 'revoke-confirm-cancel-button',
      },
      {
        children: formatMessage(messages.sendButton),
        variant: transactionDetailsErrors?.isDisabled ? 'secondary' : 'primary',
        disabled: isLoading || transactionDetailsErrors?.isDisabled,
        loading: isLoading,
        onPress: handleOnSend,
        testID: 'revoke-confirm-button',
      },
    ];
  }, [formatMessage, onCancelClick, handleOnSend, isLoading, transactionDetailsErrors?.isDisabled]);

  const topSection = useMemo(() => {
    if (!isTxPreviewEnabled || isTxScannerError) {
      return (
        <TransactionScannerError
          analyticsData={analyticsData}
          txScannerNotices={txScannerNotices}
        />
      );
    }

    if (isTxScannerLoading) {
      return <TransactionScannerFallback />;
    }

    const hasParsedOperations =
      parsedOperations?.assetChangeOperations?.length ||
      parsedOperations?.preAuthorizeOperations?.length;

    if (hasParsedOperations) {
      return (
        <TxPreview
          resetLoadTimer={resetLoadTimer}
          txScannerLoadStartTime={txScannerLoadStartTime}
          parsedOperations={parsedOperations}
          userWalletAddress={wallet.primaryAddress}
          analyticsData={analyticsData}
          isRevokeOperation={isRevokeOperation}
          networkChainId={String(networkChainId)}
          exchangeRatesMap={exchangeRatesMap}
          activeFiatCurrency={activeFiatCurrency}
        />
      );
    }
    return (
      <TransactionScannerError analyticsData={analyticsData} txScannerNotices={txScannerNotices} />
    );
  }, [
    isTxPreviewEnabled,
    isTxScannerError,
    isTxScannerLoading,
    parsedOperations,
    analyticsData,
    txScannerNotices,
    resetLoadTimer,
    txScannerLoadStartTime,
    wallet.primaryAddress,
    isRevokeOperation,
    networkChainId,
    exchangeRatesMap,
    activeFiatCurrency,
  ]);

  const dappInfo = useMemo(
    () => ({
      dappURL: '',
      networkBadgeURL: isETHWallet ? wallet.imageURL : undefined,
      networkBadgeAlt: isETHWallet ? wallet.displayName : undefined,
    }),
    [isETHWallet, wallet.displayName, wallet.imageURL],
  );

  if (!feeWallet) {
    throw new Error('Something went wrong in ConfirmationStep');
  }

  if (isHardwareWalletSigning) {
    return hardwareWalletScreen;
  }

  return (
    <TxDetails
      headerText=""
      topSection={topSection}
      detailRowItems={detailRows}
      error={transactionDetailsErrors}
      buttonProps={buttonOptions}
      handleBackButton={onCancelClick}
      height="100%"
      shouldRenderTxPreviewHeader
      isRevokeOperation={isRevokeOperation}
      headerIcon="smartContract"
      headerDappName={headerDappName}
      dappInfo={dappInfo}
      hideNavbarInHeader
      isTxScannerEnabled={isTxScannerEnabled}
    />
  );
}

import { useCallback, useEffect, useMemo } from 'react';
import { useHistory } from 'react-router';
import { css } from '@linaria/core';
import {
  triggerSpeedUpCancelButtonClicked,
  triggerSpeedUpCancelUnsignedTxGas,
  useSpeedUpCancelScreenViewed,
} from 'cb-wallet-analytics/transactions';
import {
  isNetwork1559Enabled,
  TxMetadataKey_analyticsId,
} from 'cb-wallet-data/chains/AccountBased/Ethereum/config';
import { useFormattedSpeedUpAndCancelTransaction } from 'cb-wallet-data/chains/AccountBased/Ethereum/Transactions/useFormattedSpeedUpAndCancelTransaction';
import { useSpeedUpAndCancelFees } from 'cb-wallet-data/chains/AccountBased/Ethereum/Transactions/useSpeedUpAndCancelFees';
import {
  generateUnsignedSpeedUpCancelTx,
  useSpeedUpAndCancelTransaction,
} from 'cb-wallet-data/chains/AccountBased/Ethereum/Transactions/useSpeedUpAndCancelTransaction';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import {
  FeeAnalytics1559,
  useAnalyticsFeeData,
} from 'cb-wallet-data/stores/Swap/hooks/useAnalyticsFeeData';
import { useTransactionDetailsErrors } from 'cb-wallet-data/stores/Transactions/hooks/useTransactionDetailsErrors';
import { Transaction } from 'cb-wallet-data/stores/Transactions/models/Transaction';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { useTxFeeWallet } from 'cb-wallet-data/stores/Wallets/hooks/useTxFeeWallet';
