  EntityTypeEnum,
  useClickWatchlistDiscoveryCardEvent,
  useUnwatchableAssetEvent,
  useViewWatchlistDiscoveryCardEvent,
  useWatchlistButtonEvent,
} from 'cb-wallet-analytics/watchlist';
import { cbReportError } from 'cb-wallet-data/errors/reportError';
