type Props = {
  options: SignEthereumTransaction;
  wallet: Wallet;
  feeWallet: Wallet;
  unsignedTx: UnsignedTx;
  blockchain: AllPossibleBlockchainSymbol;
  approveOperation?: ParsedPreapprovalOperation;
  error?: Error;
  isTxScannerError: boolean;
  isTxScannerLoading: boolean;
  txScannerLoadStartTime: number | undefined;
  resetLoadTimer: () => void;
  parsedOperations?: CategorizedParsedOperations;
  txScannerNotices: TxScannerNotice[] | undefined;
  isTxScannerEnabled?: boolean;
  onCompleteRequest: (signedTx: SignedTx) => void;
  onCancelRequest: (error?: Error) => void;
};

export function TransactionRequestStep({
  options,
  wallet,
  feeWallet,
  unsignedTx,
  blockchain,
  approveOperation,
  error,
  isTxScannerLoading,
  parsedOperations,
  txScannerNotices,
  isTxScannerError,
  txScannerLoadStartTime,
  resetLoadTimer,
  isTxScannerEnabled,
  onCompleteRequest,
  onCancelRequest,
}: Props) {
  const exchangeRatesMap = useExchangeRatesMap();
  const activeFiatCurrency = useActiveFiatCurrency();
  const [blindSigningError, setBlindSigningError] = useState<string | undefined>();
  const setIsHardwareWalletSigning = useSetIsHardwareWalletSigning();
  const { toAddress, unsignedTransaction, initialGasLimit } = useFields(form);
  const { goToStep } = useStepper(stepper);
  const { formatMessage } = useIntl();
  const { request, dappURL, dappName } = options;
  const { disableConfirmButton } = useContext(BlocklistContext);
  const [
    showFraudConfirmation,
    { toggleOn: setShowFraudConfirmation, toggleOff: setHideFraudConfirmation },
  ] = useToggler(false);

  const isTxPreviewEnabled = useIsTxPreviewEnabled();

  const analyticsData = useSignTransactionEventData({
    request: request.method,
    dappURL: getHostNameForDapp(dappURL),
    blockchain: unsignedTransaction.value?.blockchain.rawValue,
    txScannerData: parsedOperations,
    isTxPreviewEnabled,
    txScannerNotices,
    walletIndex: wallet.selectedIndex?.toString(),
    chainId: wallet.network.asChain()?.chainId.toString(),
  });

  useEffect(
    function logEventForConfirmButtonEnabled() {
      if (!disableConfirmButton) {
        triggerWeb3RequestConfirmButtonEnabled({
          dappURL,
          request: request.method,
          blockchain,
        });
      }
    },
    [blockchain, dappURL, disableConfirmButton, request.method],
  );

  useTransactionRequestStepViewed(analyticsData);

  const txScannerContent = useTxScannerContent(
    parsedOperations?.preAuthorizeOperations,
    txScannerNotices,
  );

  const analyticsFeeData = useAnalyticsFeeData(unsignedTx, wallet);

  const triggerWeb3FraudWarningConfirmationClicked =
    useTriggerWeb3FraudWarningConfirmationClicked(analyticsData);
  const navigationToFraudWarningConfirmationScreenPressed = useCallback(() => {
    triggerWeb3FraudWarningConfirmationClicked();

    setShowFraudConfirmation();
  }, [setShowFraudConfirmation, triggerWeb3FraudWarningConfirmationClicked]);

  const triggerWeb3SignTransactionError = useTriggerWeb3SignTransactionError(analyticsData);

  const signError = useCallback(
    (signingError: Error) => {
      cbReportError({
        error: signingError,
        context: 'transactions',
        severity: 'error',
        isHandled: false,
      });
      triggerWeb3SignTransactionError({ errorMessage: signingError.message });
      onCancelRequest(signingError);
    },
    [triggerWeb3SignTransactionError, onCancelRequest],
  );

  const signLedgerError = useCallback(
    (ledgerError: Error) => {
      cbReportError({
        error: new Error(ledgerError.message),
        context: 'ledger-error',
        severity: 'error',
        isHandled: false,
      });
      if (ledgerError.name === 'EthAppPleaseEnableContractData') {
        setBlindSigningError(ledgerError.message);
      } else {
        signError(ledgerError);
      }
    },
    [signError],
  );

  const retryLedgerTransaction = useCallback(() => {
    setBlindSigningError(undefined);
    setIsHardwareWalletSigning(false);
    setHideFraudConfirmation();
  }, [setIsHardwareWalletSigning, setHideFraudConfirmation]);

  const handleUnlock = useHandleUnlockForSigning();
  const { hasLocallyStoredKey, isLedgerAccount } = useAccountById(wallet.accountId);
  const { signAndSubmitStandalone, isSignAndSubmitStandaloneLoading } = useSignAndSubmitStandalone({
    wallet,
    unsignedTx: unsignedTransaction.value,
    signSuccess: onCompleteRequest,
    signError,
    skipSubmit: !options.request.params.shouldSubmit,
    handleUnlock: handleUnlock(wallet.accountId),
    source: dappName,
  });

  const { signAndSubmitLedger, isHardwareWalletSigning, hardwareWalletScreen } =
    useSignAndSubmitLedger({
      flow: Flow.Dapp,
      unsignedTx,
      onSignSuccess: onCompleteRequest,
      onSignError: signLedgerError,
      dappURL,
      source: dappName,
    });

  const isLoading = isSignAndSubmitStandaloneLoading ?? isHardwareWalletSigning;

  if (!feeWallet) {
    throw new Error('Something went wrong in TransactionRequestStep');
  }

  // we store the signedTx in the form to be able to use it between steps,
  // we should update the form value when the unsignedTx prop changes
  useEffect(
    function parseUnsignedTx() {
      if (unsignedTx !== unsignedTransaction.value) {
        toAddress.onChange(request.params.toAddress!);
        unsignedTransaction.onChange(unsignedTx);
        if (isETH1559Tx(unsignedTx)) {
          initialGasLimit.onChange(unsignedTx.gasLimit);
        }
      }
    },
    [initialGasLimit, request.params.toAddress, toAddress, unsignedTransaction, unsignedTx],
  );

  const is1559Enabled = useMemo(() => {
    return isNetwork1559Enabled(wallet.network);
  }, [wallet.network]);

  const isAdjustableMinerFeeEnabled = useIsAdjustableMinerFeeEnabled();

  // TODO: @JM revisit hasLocallyStoredKey when custom walletlink messages enable basic wallet users to adjust gas
  // feature flag points to prod value. isProd hook is necessary until we decouple dev and prod.
  const isAdjustableGasEnabled =
    hasLocallyStoredKey && is1559Enabled && (!isProd() || isAdjustableMinerFeeEnabled);

  const openAdjustableGasPreset = useCallback(() => {
    triggerAdjustableGasDappTxnFlowEntryClicked();
    goToStep('adjustGasPreset');
  }, [goToStep]);

  const AdjustGasPresetAction = useMemo(
    () =>
      isAdjustableGasEnabled ? (
        <Pressable as="button" onPress={openAdjustableGasPreset} background="transparent">
          <Icon name="gear" size="s" color="foreground" spacingStart={1} />
        </Pressable>
      ) : null,
    [isAdjustableGasEnabled, openAdjustableGasPreset],
  );

  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx: unsignedTransaction.value,
    error,
    feeWallet,
    flow: 'dappTx',
  });

  const detailRows = useTransactionRequestDetails(
    wallet,
    isTxScannerLoading,
    unsignedTransaction.value,
    parsedOperations,
    txScannerContent,
    AdjustGasPresetAction,
    transactionDetailsErrors,
  );

  const triggerFraudWarningConfirmationBackButtonClicked =
    useTriggerFraudWarningConfirmationBackButtonClicked(analyticsData);

  const handleFraudConfirmationBackButtonClicked = useCallback(() => {
    triggerFraudWarningConfirmationBackButtonClicked();
    setHideFraudConfirmation();
  }, [setHideFraudConfirmation, triggerFraudWarningConfirmationBackButtonClicked]);

  const triggerWeb3CancelTransactionClicked = useTriggerWeb3CancelTransactionClicked(analyticsData);
  const triggerWeb3ConfirmTransactionClicked =
    useTriggerWeb3ConfirmTransactionClicked(analyticsData);

  const handleCancelButtonPress = useCallback(() => {
    triggerWeb3CancelTransactionClicked();
    onCancelRequest(standardErrors.provider.userRejectedRequest({}));
  }, [onCancelRequest, triggerWeb3CancelTransactionClicked]);

  const handlePrimaryButtonPress = useCallback(async () => {
    triggerWeb3ConfirmTransactionClicked();

    if (hasLocallyStoredKey) {
      return signAndSubmitStandalone();
    }

    if (isLedgerAccount) {
      return signAndSubmitLedger();
    }
  }, [
    triggerWeb3ConfirmTransactionClicked,
    hasLocallyStoredKey,
    isLedgerAccount,
    signAndSubmitStandalone,
    signAndSubmitLedger,
  ]);

  const buttonOptions: ButtonProps[] = useMemo(() => {
    return [
      {
        children: formatMessage(messages.cancel),
        variant: 'secondary',
        onPress: handleCancelButtonPress,
        testID: 'request-cancel-button',
      },
      {
        children: formatMessage(messages.confirm),
        variant: transactionDetailsErrors?.isDisabled ? 'secondary' : 'primary',
        disabled: (transactionDetailsErrors?.isDisabled ?? isLoading) || disableConfirmButton,
        loading: isLoading,
        onPress: txScannerContent?.fraudWarningConfirmationText
          ? navigationToFraudWarningConfirmationScreenPressed
          : handlePrimaryButtonPress,
        testID: 'request-confirm-button',
      },
    ];
  }, [
    formatMessage,
    handleCancelButtonPress,
    transactionDetailsErrors?.isDisabled,
    isLoading,
    disableConfirmButton,
    navigationToFraudWarningConfirmationScreenPressed,
    handlePrimaryButtonPress,
    txScannerContent,
  ]);

  const isEthWalletAtZeroIndex =
    Blockchain.isEqual(wallet.blockchain, EthereumBlockchain) &&
    CurrencyCode.isEqual(wallet.currencyCode, CurrencyCode.ETH) &&
    Network.isEqual(wallet.network, new Network('ETHEREUM_CHAIN:1', false)) &&
    wallet.contractAddress === undefined &&
    wallet.selectedIndex === 0n;

  const networkBadgeURL = !isEthWalletAtZeroIndex
    ? wallet.network.asChain()?.chainImageUrl ?? wallet.imageURL
    : undefined;
  const networkBadgeAlt = !isEthWalletAtZeroIndex
    ? wallet.network.asChain()?.displayName ?? wallet.displayName
    : undefined;

  const { gasLimit, analyticsId, chainId, feeCurrencyCode } =
    analyticsFeeData as FeeAnalyticsLegacy;
  const { networkFeeInUSD, networkFeeInCrypto } = analyticsFeeData as FeeAnalyticsLegacy;
  const { minFeeInUSD, maxFeeInUSD, minFeeInCrypto, maxFeeInCrypto } =
    analyticsFeeData as FeeAnalytics1559;

  const dappInfo = useMemo(() => {
    return {
      dappLogoURL: options.dappLogoURL,
      dappLogoURLAlt: options.dappLogoURLAlt,
      dappURL: options.dappURL,
      networkBadgeURL,
      networkBadgeAlt,
    };
  }, [
    networkBadgeAlt,
    networkBadgeURL,
    options.dappLogoURL,
    options.dappLogoURLAlt,
    options.dappURL,
  ]);

  const shouldRenderTxPreviewHeader = useMemo(() => {
    return Boolean(isTxPreviewEnabled && dappInfo);
  }, [dappInfo, isTxPreviewEnabled]);

  const networkChainId = wallet.network.asChain()?.chainId;

  const isRevokeOperation = useIsRevokeOperation(parsedOperations);

  const topSection = useMemo(() => {
    const isUpdatedApprovalUI = approveOperation?.operationType && options;

    if (isTxPreviewEnabled) {
      if (isTxScannerError) {
        return (
          <TransactionScannerError
            analyticsData={analyticsData}
            txScannerNotices={txScannerNotices}
          />
        );
      }

      if (isTxScannerLoading) {
        return <TransactionScannerFallback />;
      }

      const hasParsedOperations =
        parsedOperations?.assetChangeOperations?.length ||
        parsedOperations?.preAuthorizeOperations?.length;

      if (hasParsedOperations) {
        return (
          <TxPreview
            resetLoadTimer={resetLoadTimer}
            txScannerLoadStartTime={txScannerLoadStartTime}
            parsedOperations={parsedOperations}
            userWalletAddress={wallet.primaryAddress}
            analyticsData={analyticsData}
            isRevokeOperation={isRevokeOperation}
            networkChainId={String(networkChainId)}
            exchangeRatesMap={exchangeRatesMap}
            activeFiatCurrency={activeFiatCurrency}
          />
        );
      }

      // if hasParsedOperations is not returning any data, we render the error component
      return (
        <TransactionScannerError
          analyticsData={analyticsData}
          txScannerNotices={txScannerNotices}
        />
      );
    }

    if (isUpdatedApprovalUI) {
      return (
        <Box spacingTop={2}>
          <TxApproval
            dappLogoURL={options.dappLogoURL}
            dappLogoURLAlt={options.dappLogoURLAlt}
            dappURL={options.dappURL}
            networkBadgeURL={networkBadgeURL}
            networkBadgeAlt={networkBadgeAlt}
            approveOperation={approveOperation}
            request={request.method}
            blockchain={blockchain}
            chainId={String(networkChainId)}
          />
        </Box>
      );
    }

    return (
      <TransactionRequestTopSection
        dappLogoURL={options.dappLogoURL}
        dappLogoURLAlt={options.dappLogoURLAlt}
        dappURL={options.dappURL}
        networkBadgeURL={networkBadgeURL}
        networkBadgeAlt={networkBadgeAlt}
      />
    );
  }, [
    approveOperation,
    options,
    isTxPreviewEnabled,
    networkBadgeURL,
    networkBadgeAlt,
    isTxScannerError,
    isTxScannerLoading,
    parsedOperations,
    analyticsData,
    txScannerNotices,
    resetLoadTimer,
    txScannerLoadStartTime,
    wallet.primaryAddress,
    isRevokeOperation,
    networkChainId,
    exchangeRatesMap,
    activeFiatCurrency,
    request.method,
    blockchain,
  ]);

  useEffect(
    function sendNetworkFeeInfo() {
      const commonFields = { gasLimit, analyticsId, chainId, feeCurrencyCode };
      if (is1559Enabled) {
        triggerDappTxnConfirmationGasFeeViewed1559({
          ...commonFields,
          minFeeInUSD,
          maxFeeInUSD,
          minFeeInCrypto,
          maxFeeInCrypto,
        });
      } else {
        triggerDappTxnConfirmationGasFeeViewedLegacy({
          ...commonFields,
          networkFeeInUSD,
          networkFeeInCrypto,
        });
      }
    },
    [
      minFeeInUSD,
      maxFeeInUSD,
      minFeeInCrypto,
      maxFeeInCrypto,
      gasLimit,
      analyticsId,
      chainId,
      networkFeeInUSD,
      networkFeeInCrypto,
      feeCurrencyCode,
      is1559Enabled,
    ],
  );

  if (blindSigningError) {
    return (
      <PopupAwareVStack spacing={2} elevation={1} {...styles}>
        <HWTroubleConnecting handleBack={retryLedgerTransaction} errorMessage={blindSigningError} />
      </PopupAwareVStack>
    );
  }

  /* Hardware wallet signing state should always take precedence over TransactionDetails or Doubleconfirmation */
  if (isHardwareWalletSigning) {
    return hardwareWalletScreen;
  }

  if (showFraudConfirmation && txScannerContent?.fraudWarningConfirmationText) {
    return (
      <PopupAwareVStack spacing={2} elevation={1} {...styles}>
        <FraudWarningConfirmation
          handlePrimaryButtonPress={handlePrimaryButtonPress}
          isLoading={isLoading}
          warningContent={txScannerContent.fraudWarningConfirmationText}
          handleCancelButtonPress={handleCancelButtonPress}
          handleBackButton={handleFraudConfirmationBackButtonClicked}
          analyticsData={analyticsData}
          height={DEFAULT_VIEWPORT_HEIGHT}
        />
      </PopupAwareVStack>
    );
  }

  return wallet ? (
    <TxDetails
      isTxScannerEnabled={isTxScannerEnabled}
      shouldRenderTxPreviewHeader={shouldRenderTxPreviewHeader}
      dappInfo={dappInfo}
      headerText={formatMessage(messages.title)}
      topSection={topSection}
      detailRowItems={detailRows}
      disableBackBtn
      error={transactionDetailsErrors}
      buttonProps={buttonOptions}
      signingAddressToDisplay={wallet.primaryAddress}
      height={DEFAULT_VIEWPORT_FULL_HEIGHT}
      isRevokeOperation={isRevokeOperation}
    />
  ) : (
    <></>
  );
}

