  [BITCOIN_SYMBOL]: BitcoinWalletConfiguration.imageURL,
  [LITECOIN_SYMBOL]: LitecoinWalletConfiguration.imageURL,
  [DOGECOIN_SYMBOL]: DogecoinWalletConfiguration.imageURL,
};

