  -ms-overflow-style: none;
  scrollbar-width: none;
`;

import { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Animated, Easing, LayoutChangeEvent, ViewStyle } from 'react-native';
import { ControllerRenderProps, FieldValues, useForm } from 'react-hook-form';
import { defineMessages, useIntl } from 'react-intl';
import { KeyboardAwareScrollView } from 'react-native-keyboard-aware-scroll-view';
import { EthereumUnsigned1559Tx } from 'cb-wallet-data/chains/AccountBased/Ethereum/models/EthereumUnsigned1559Tx';
import { Blockchain } from 'cb-wallet-data/models/Blockchain';
import {
  AdjustableGasOnSubmitParams,
  useMinerFeeEstimates,
} from 'cb-wallet-data/stores/AdjustableMinerFees/hooks/useMinerFeeEstimates';
import { Network } from 'cb-wallet-data/stores/Networks/models/Network';
import { convertGweiToWei, convertWeiToGwei } from 'cb-wallet-data/utils/CurrencyUtil';
import { curves, durations } from '@cbhq/cds-common/motion/tokens';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { Box, Divider } from '@cbhq/cds-mobile/layout';
import { TextLabel2 } from '@cbhq/cds-mobile/typography';

import { device } from ':rn/shared/config/device';
import { useDimensions } from ':rn/shared/hooks/useDimensions';
import { useKeyboardHeight } from ':rn/shared/hooks/useKeyboardHeight';

import { NetworkBoundary } from '../ErrorBoundary/NetworkBoundary';
import { Button } from '../interactables/Button';

import { useAdjustableGasUtils } from './hooks/useAdjustableGasUtils';
import { useAdjustableGasValidators } from './hooks/useAdjustableGasValidators';
import { AdjustableGasCustomCell } from './AdjustableGasCustomCell';
import { AdjustableGasInput } from './AdjustableGasInput';

const FORM_INNER_CONTAINER_HEIGHT = 600;
const messages = defineMessages({
  confirm: {
    defaultMessage: 'Confirm',
    description: 'Label for confirm button',
  },
  invalidFeeRangeErrorMessage: {
    defaultMessage: 'Max fee must be greater than max priority fee.',
    description: 'Validation error if max fee is lower than max priority fee',
  },
  ctaGroup: {
    defaultMessage: 'Confirm adjustable gas or go back',
    description: 'Adjustable Gas CTA button group accessibility label',
  },
  goBack: {
    defaultMessage: 'Go back',
    description: 'Go back button text',
  },
});

// Computed using onLayout, see comment in below JSX
const BUTTON_CONTAINER_HEIGHT = 83;

const SMALL_DEVICE_SCREEN_HEIGHT = 550;

type Props = {
  transaction: EthereumUnsigned1559Tx;
  network: Network;
  blockchain: Blockchain;
  handleOnSubmit: (params: AdjustableGasOnSubmitParams) => void;
  onGoBack?: () => void;
  startingGasValues?: AdjustableGasOnSubmitParams | undefined;
};

const AdjustableGasCustom = memo(function AdjustableGasCustom({
  transaction,
  network,
  blockchain,
  handleOnSubmit,
  onGoBack,
  startingGasValues,
}: Props) {
  const { formatMessage } = useIntl();

  const estimates = useMinerFeeEstimates(transaction.gasLimit, network);
  if (!estimates) throw Error('Miner fees not defined');

  const keyboardHeight = useKeyboardHeight();
  const { bottom, screenHeight } = useDimensions();
  const animated = useRef(new Animated.Value(0)).current;
  const [formHeight, setFromHeight] = useState<number | undefined>();

  const handleFormInputHeight = useCallback((e: LayoutChangeEvent) => {
    const inputHeight = e.nativeEvent.layout.height;
    setFromHeight(3 * inputHeight);
  }, []);

  const formContainerHeight = useMemo(() => {
    // On small devices, there's not enough room for confirm button above the keyboard
    // So we let the keyboard cover it in order to keep a good vision of the form inputs
    if (screenHeight <= SMALL_DEVICE_SCREEN_HEIGHT || !device.isAndroid) {
      return formHeight;
    }

    return formHeight ? formHeight - keyboardHeight : undefined;
  }, [formHeight, keyboardHeight, screenHeight]);

  useEffect(() => {
    Animated.timing(animated, {
      toValue: keyboardHeight === 0 ? 0 : 1,
      duration: durations.moderate2,
      easing: Easing.bezier(...curves.global),
      delay: keyboardHeight === 0 ? 0 : durations.slow3,
      useNativeDriver: false,
    }).start();
  }, [animated, keyboardHeight]);

  // When determining the starting values we show to users in custom gas we prioritize
  // 1. Values passed in for this specific purpose (startingGasValues)
  // 2. Current market values
  // 3. Just display 0s
  const [values, setValues] = useState({
    baseFee: startingGasValues?.selectedBaseFeePerGas ?? estimates?.normal.baseFeePerGas ?? 0n,
    initialGasLimit: transaction.gasLimit.toString(),
    gasLimit: transaction.gasLimit.toString(),
    maxFeePerGas: convertWeiToGwei(
      startingGasValues?.selectedMaxFeePerGas ?? estimates?.normal.maxFeePerGas ?? 0n,
    ),
    maxPriorityFeePerGas: convertWeiToGwei(
      startingGasValues?.selectedMaxPriorityFeePerGas ??
        estimates?.normal.maxPriorityFeePerGas ??
        0n,
    ),
    l1GasFee: transaction.l1GasFee ?? 0n,
  });

  const { feeRangeLowerBound, feeRangeUpperBound, isInvalidGasLimit, isInvalidRange } =
    useAdjustableGasUtils(values);

  const isSubmitDisabled = useMemo(
    () =>
      !values.maxFeePerGas ||
      !values.maxPriorityFeePerGas ||
      !values.gasLimit ||
      isInvalidRange ||
      isInvalidGasLimit,
    [isInvalidGasLimit, isInvalidRange, values],
  );

  const {
    control,
    getValues,
    formState: { errors },
  } = useForm({ mode: 'onChange' });

  const handleSubmit = useCallback(() => {
    handleOnSubmit({
      selectedBaseFeePerGas: values.baseFee,
      selectedMaxFeePerGas: convertGweiToWei(values.maxFeePerGas),
      selectedMaxPriorityFeePerGas: convertGweiToWei(values.maxPriorityFeePerGas),
      selectedGasLimit: BigInt(values.gasLimit),
    });
  }, [
    handleOnSubmit,
    values.baseFee,
    values.gasLimit,
    values.maxFeePerGas,
    values.maxPriorityFeePerGas,
  ]);

  const handleOnChangeText = useCallback((field: ControllerRenderProps<FieldValues>) => {
    return (userInput: string) => {
      // Add a 0 if the user starts with a decimal
      const processedInput = userInput === '.' ? '0.' : userInput;

      // Check if the value is a number or not
      if (Number.isNaN(Number(processedInput))) return;

      field.onChange(processedInput);
      setValues((prev) => ({
        ...prev,
        [field.name]: processedInput,
      }));
    };
  }, []);

  const validators = useAdjustableGasValidators({
    getValues,
    slowPreset: estimates.slow,
    gasLimit: BigInt(values.initialGasLimit),
  });

  const dangerouslySetBottom = useMemo<Animated.WithAnimatedObject<ViewStyle>>(
    () =>
      device.isIOS
        ? {
            bottom: animated.interpolate({
              inputRange: [0, 1],
              // If the device has a safeArea inset thats a good starting point, otherwise
              // we set the starting point to one half of containing elements height
              outputRange: [bottom || BUTTON_CONTAINER_HEIGHT / 2, keyboardHeight - bottom],
            }),
          }
        : {
            bottom: 0,
            position: screenHeight < SMALL_DEVICE_SCREEN_HEIGHT ? 'absolute' : 'relative',
          },
    [animated, bottom, keyboardHeight, screenHeight],
  );

  return (
    <Box flexGrow={1}>
      <AdjustableGasCustomCell
        feeRangeLowerBound={feeRangeLowerBound}
        feeRangeUpperBound={feeRangeUpperBound}
        gasLimit={values.gasLimit}
        unsignedTx={transaction}
        network={network}
        blockchain={blockchain}
      />
      <Divider />
      <Box flexGrow={1} overflow="hidden" height={formContainerHeight}>
        <KeyboardAwareScrollView keyboardDismissMode="interactive" extraScrollHeight={0}>
          <Box spacingHorizontal={2} spacingTop={2} height={FORM_INNER_CONTAINER_HEIGHT}>
            <Box onLayout={handleFormInputHeight}>
              <AdjustableGasInput
                defaultValue={values.maxFeePerGas}
                name="maxFeePerGas"
                handleOnChangeText={handleOnChangeText}
                error={errors.maxFeePerGas}
                validator={validators.maxFeePerGas}
                control={control}
                testID="maxFeePerGas-custom-gas-input"
              />
            </Box>
            <AdjustableGasInput
              defaultValue={values.maxPriorityFeePerGas}
              name="maxPriorityFeePerGas"
              handleOnChangeText={handleOnChangeText}
              error={errors.maxPriorityFeePerGas}
              validator={validators.maxPriorityFeePerGas}
              control={control}
              testID="maxPriorityFeePerGas-custom-gas-input"
            />
            <AdjustableGasInput
              defaultValue={values.gasLimit}
              name="gasLimit"
              handleOnChangeText={handleOnChangeText}
              error={errors.gasLimit}
              validator={validators.gasLimit}
              control={control}
              testID="gasLimit-custom-gas-input"
            />
          </Box>
        </KeyboardAwareScrollView>
      </Box>

      {/* BUTTON_CONTAINER_HEIGHT was computed using onLayout on the below element. Please
          recalculate if you update the below JSX
      */}
      <Box animated style={dangerouslySetBottom} width="100%" background="background">
        {!!onGoBack && <Divider />}
        <Box spacingHorizontal={2} spacingTop={1}>
          {isInvalidRange && (
            <TextLabel2 spacingBottom={2} color="negative" align="center">
              {formatMessage(messages.invalidFeeRangeErrorMessage)}
            </TextLabel2>
          )}
          <ButtonGroup accessibilityLabel={formatMessage(messages.ctaGroup)} block>
            {!!onGoBack && (
              <Button onPress={onGoBack} variant="secondary">
                {formatMessage(messages.goBack)}
              </Button>
            )}
            <Button
              onPress={handleSubmit}
              disabled={isSubmitDisabled}
              testID="custom-gas-confirm-button"
            >
              {formatMessage(messages.confirm)}
            </Button>
          </ButtonGroup>
        </Box>
      </Box>
    </Box>
  );
});

const AdjustableGasCustomWithBoundary = memo(function AdjustableGasCustomWithBoundary({
  transaction,
  network,
  blockchain,
  handleOnSubmit,
  onGoBack,
  startingGasValues,
}: Props) {
  return (
    <NetworkBoundary
      fallback={null}
      errorFallback={null} // TODO
    >
      <AdjustableGasCustom
        transaction={transaction}
        network={network}
        blockchain={blockchain}
        handleOnSubmit={handleOnSubmit}
        onGoBack={onGoBack}
        startingGasValues={startingGasValues}
      />
    </NetworkBoundary>
  );
});

export { AdjustableGasCustomWithBoundary as AdjustableGasCustom };

import { memo, useCallback } from 'react';
import { Control, Controller, ControllerRenderProps, FieldValues } from 'react-hook-form';
import { defineMessages, useIntl } from 'react-intl';
import { TextInput } from '@cbhq/cds-mobile/controls/TextInput';
import { VStack } from '@cbhq/cds-mobile/layout';
import { TextLabel2 } from '@cbhq/cds-mobile/typography';

const messages = defineMessages({
  gasLimit: {
    defaultMessage: 'Gas limit',
    description: 'Label for gas limit',
  },
  maxFeePerGas: {
    defaultMessage: 'Gas price',
    description: 'Label for gas price',
  },
  maxPriorityFeePerGas: {
    defaultMessage: 'Max priority fee',
    description: 'Label for max priority fee',
  },
  unit: {
    defaultMessage: 'Gwei',
    description: 'Label for gas fee input units',
  },
});

type Props = {
  defaultValue: string;
  name: string;
  handleOnChangeText: (field: ControllerRenderProps<FieldValues>) => (val: string) => void;
  error: Record<string, string>;
  validator: Record<string, () => string | undefined>;
  control: Control<FieldValues, string>;
  testID?: string;
};

export const AdjustableGasInput = memo(function AdjustableGasInput({
  defaultValue,
  name,
  handleOnChangeText,
  error,
  validator,
  control,
  testID,
}: Props) {
  const { formatMessage } = useIntl();

  const renderField = useCallback(
    function renderField({ field }: { field: ControllerRenderProps<FieldValues> }) {
      const fields = field.name as 'maxFeePerGas' | 'maxPriorityFeePerGas' | 'gasLimit';

      return (
        <VStack spacingBottom={1}>
          <TextLabel2 spacingBottom={0.5}>{formatMessage(messages[fields])}</TextLabel2>
          <TextInput
            suffix={name !== 'gasLimit' ? formatMessage(messages.unit) : undefined}
            onChangeText={handleOnChangeText(field)}
            maxLength={11}
            value={field.value}
            key="adjustable-gas-input"
            ref={field.ref}
            keyboardType="numeric"
            variant={error?.message ? 'negative' : 'primary'}
            testID={testID}
          />
          <TextLabel2 color="negative" spacingTop={0.5}>
            {error?.message ?? ' '}
          </TextLabel2>
        </VStack>
      );
    },
    [error?.message, formatMessage, handleOnChangeText, name, testID],
  );

  return (
    <Controller
      control={control}
      defaultValue={defaultValue}
      name={name}
      render={renderField}
      rules={validator}
    />
  );
});

import { memo, useCallback, useMemo } from 'react';
import { LayoutChangeEvent, StyleProp, TextStyle } from 'react-native';
import { useIntl } from 'react-intl';
import { isUTXOBasedBlockchain } from 'cb-wallet-data/chains/blockchains';
import { GasEstimateTxType } from 'cb-wallet-data/hooks/useGetGasEstimate/useGetGasEstimate';
import { useIsEligibleForEstimateGasByUnsignedTx } from 'cb-wallet-data/hooks/useHasMaxButtonOnSendNon1559EthereumAssets/useIsEligibleForEstimateGasByUnsingedTx';
import { useIsBaseAssetMaxButtonEligible } from 'cb-wallet-data/hooks/useIsBaseAssetMaxButtonEligible/useIsBaseAssetMaxButtonEligible';
