type AmountInputLegacyContentProps = {
  adjustedStyles: StyleProp<TextStyle>;
  onLayout: (event: LayoutChangeEvent) => void;
} & AmountInputProps;

export const AmountInputLegacyContent = memo(function AmountInputLegacyContent({
  wallet,
  txType,
  hideMaxButton,
  onPressMaxButton,
  isLoadingMaxButton,
  sideIconBackground,
  allowChangeToFiat,
  primaryAmount,
  primaryTextColorOverride,
  onPrimaryAmountLongPress,
  secondaryAmount,
  toggleIsFiat,
  isFiat,
  activeFiatCurrency,
  tertiaryAmount,
  isTertiaryErrorState,
  onPressTertiaryInErrorState,
  adjustedStyles,
  onLayout,
}: AmountInputLegacyContentProps) {
  const { formatMessage } = useIntl();
  const isEligibleForEstimateGasByUnsignedTx = useIsEligibleForEstimateGasByUnsignedTx(wallet);
  const isNativeAssetMaxButtonEligible = useIsBaseAssetMaxButtonEligible(
    txType,
    wallet?.network.asChain()?.chainId,
  );

  const blockchainSymbol = wallet?.blockchain.rawValue;
  const isUTXO = blockchainSymbol && isUTXOBasedBlockchain(blockchainSymbol);
  const isNonBaseAsset = wallet?.contractAddress;

  const isMaxButtonEnabled = useMemo(() => {
    if (txType === GasEstimateTxType.BUY) return false;

    return (
      isUTXO ||
      isNonBaseAsset ||
      (isNativeAssetMaxButtonEligible && !wallet?.contractAddress) ||
      (isEligibleForEstimateGasByUnsignedTx && txType === GasEstimateTxType.SEND)
    );
  }, [
    isEligibleForEstimateGasByUnsignedTx,
    isNativeAssetMaxButtonEligible,
    isNonBaseAsset,
    isUTXO,
    txType,
    wallet?.contractAddress,
  ]);

  const handleToggleIsFiat = useCallback(() => {
    toggleIsFiat?.();
  }, [toggleIsFiat]);

  return (
    <VStack justifyContent="center" alignItems="center" testID="amount-input-v1">
      <HStack
        width="100%"
        flexGrow={1}
        flexWrap="nowrap"
        overflow="hidden"
        flexShrink={1}
        justifyContent="space-between"
        alignItems="center"
        position="relative"
        spacingBottom={1}
      >
        {!hideMaxButton && isMaxButtonEnabled && onPressMaxButton ? (
          <MaxButton
            onPressMaxButton={onPressMaxButton}
            isLoadingMaxButton={isLoadingMaxButton}
            sideIconBackground={sideIconBackground}
          />
        ) : (
          <MaxButtonPlaceholder allowChangeToFiat={!!allowChangeToFiat} />
        )}

        <Box flexShrink={1} alignItems="center" justifyContent="center" onLayout={onLayout}>
          <TextDisplay1
            testID="amount-input-primary-amount"
            adjustsFontSizeToFit
            ellipsize="tail"
            color={primaryTextColorOverride}
            minimumFontScale={0.05}
            style={adjustedStyles}
            onLongPress={onPrimaryAmountLongPress}
          >
            {primaryAmount}
          </TextDisplay1>
        </Box>
        {allowChangeToFiat ? (
          <SideIcon
            testID="amount-input-toggle-button"
            onPress={handleToggleIsFiat}
            accessibilityLabel={formatMessage(messages.switchAccessibilityLabel, {
              from: isFiat ? activeFiatCurrency?.name : wallet?.displayName,
              to: isFiat ? wallet?.displayName : activeFiatCurrency?.name,
            })}
            background={sideIconBackground}
          >
            <Icon size="s" name="arrowsVertical" color="foreground" />
          </SideIcon>
        ) : (
          <HStack testID="amount-input-toggle-button-placeholder" />
        )}
      </HStack>
      {secondaryAmount && (
        <TextLabel2 testID="amount-input-secondary-amount" color="foregroundMuted" align="center">
          {secondaryAmount}
        </TextLabel2>
      )}
      {tertiaryAmount &&
        (isTertiaryErrorState ? (
          <PressableOpacity onPress={onPressTertiaryInErrorState}>
            <HStack>
              <TextLabel2
                testID="amount-input-tertiary-amount-with-info"
                color="negative"
                align="center"
              >
                {formatMessage(messages.availableAmount, { amount: tertiaryAmount })}
              </TextLabel2>
              <Icon
                name="info"
                testID="tertiary-error-info-icon"
                size="xs"
                color="foregroundMuted"
                spacingTop={0.5}
                spacingStart={0.5}
              />
            </HStack>
          </PressableOpacity>
        ) : (
          <TextLabel2 testID="amount-input-tertiary-amount" color="foregroundMuted" align="center">
            {formatMessage(messages.availableAmount, { amount: tertiaryAmount })}
          </TextLabel2>
        ))}
      {!tertiaryAmount && (
        <TextLabel2 testID="placeholder-with-empty-text" color="foregroundMuted" align="center">
          {' '}
        </TextLabel2>
      )}
    </VStack>
  );
});

