import { memo, useMemo } from 'react';
import { StyleProp, TextStyle } from 'react-native';
import { useIntl } from 'react-intl';
import { CurrencyCode } from 'cb-wallet-data/models/CurrencyCode';
import { useIsPaymentsModeEnabled } from 'cb-wallet-data/stores/AppMode/useIsPaymentsModeEnabled';
import { useFormattedWalletBalance } from 'cb-wallet-data/stores/Wallets/hooks/useFormattedWalletBalance';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import { TextDisplay1 } from '@cbhq/cds-mobile/typography';

import { AmountInputSubtitle } from './AmountInputSubtitle';
import { AmountInputProps, AmountInputType, messages, SECONDARY_AMOUNT_HEIGHT } from './constants';

type StackedAmountInputContentProps = {
  adjustedStyles: StyleProp<TextStyle>;
} & AmountInputProps;

export const StackedAmountInput = memo(function StackedAmountInput({
  wallet,
  secondaryAmount,
  isLoadingSecondaryAmount,
  secondaryTextColorOverride,
  toggleIsFiat,
  type,
  allowChangeToFiat,
  primaryTextColorOverride,
  secondaryAmountHeightOverride,
  isFiat,
  activeFiatCurrency,
  isSmallScreen,
  primaryAmount,
  adjustedStyles,
}: StackedAmountInputContentProps) {
  const { formatMessage } = useIntl();
  const isPaymentsMode = useIsPaymentsModeEnabled();
  const { fiatBalance } = useFormattedWalletBalance({ wallet, formatZeroBalance: true });

  const { subtitleHeight, shouldShowToggleFiatButton } = useMemo(
    () => ({
      shouldShowToggleFiatButton: !!secondaryAmount && allowChangeToFiat,
      subtitleHeight: secondaryAmountHeightOverride ?? SECONDARY_AMOUNT_HEIGHT,
    }),
    [allowChangeToFiat, secondaryAmount, secondaryAmountHeightOverride],
  );

  const secondaryAmountComponent = useMemo(() => {
    // when is loading secondary amount,
    // we still want to render the fallback component
    if (!secondaryAmount && !isLoadingSecondaryAmount) {
      return null;
    }

    const amountText = (
      <AmountInputSubtitle
        text={secondaryAmount}
        height={subtitleHeight}
        isLoading={isLoadingSecondaryAmount}
        color={secondaryTextColorOverride}
        shouldShowIcon={shouldShowToggleFiatButton}
      />
    );

    if (shouldShowToggleFiatButton) {
      return (
        <PressableOpacity
          testID="toggle-fiat-currency-button"
          onPress={toggleIsFiat}
          accessibilityLabel="amount-input"
        >
          {amountText}
        </PressableOpacity>
      );
    }

    return amountText;
  }, [
    isLoadingSecondaryAmount,
    secondaryAmount,
    secondaryTextColorOverride,
    shouldShowToggleFiatButton,
    subtitleHeight,
    toggleIsFiat,
  ]);

  const primaryCurrencySymbol = useMemo(() => {
    if (isPaymentsMode) return isFiat ? activeFiatCurrency?.code.code : CurrencyCode.USD.code;
    return isFiat ? activeFiatCurrency?.code.code : wallet?.currencyCode.code;
  }, [activeFiatCurrency?.code.code, isFiat, isPaymentsMode, wallet?.currencyCode.code]);

  return (
    <VStack testID="amount-input-v2">
      <HStack gap={1} flexWrap="nowrap" width="100%" offsetBottom={isSmallScreen ? 1 : 0}>
        <TextDisplay1
          testID="amount-input-primary-amount"
          adjustsFontSizeToFit
          ellipsize="tail"
          color={primaryTextColorOverride}
          minimumFontScale={0.05}
          style={adjustedStyles}
        >
          {primaryAmount}
        </TextDisplay1>
        <TextDisplay1
          color="secondary"
          adjustsFontSizeToFit
          minimumFontScale={0.05}
          style={adjustedStyles}
        >
          {primaryCurrencySymbol}
        </TextDisplay1>
      </HStack>
      {secondaryAmountComponent}
      {type === AmountInputType.PAYMENTS_SEND && (
        <Box testID="amount-input-amount-available">
          <AmountInputSubtitle
            text={formatMessage(messages.availableAmount, { amount: fiatBalance })}
            height={subtitleHeight}
            isLoading={isLoadingSecondaryAmount}
            color={secondaryTextColorOverride}
            shouldShowIcon
            iconName="cash"
          />
        </Box>
      )}
    </VStack>
  );
});

