import { memo, useCallback, useEffect, useMemo, useState } from 'react';
import { FormProvider, useForm } from 'react-hook-form';
import { useIntl } from 'react-intl';
import { yupResolver } from '@hookform/resolvers/yup';
import { useDebounce } from 'cb-wallet-data/hooks/useDebounce';
import { Box, Spacer, VStack } from '@cbhq/cds-mobile/layout';
import { TextTitle1 } from '@cbhq/cds-mobile/typography';
import { TextBody } from '@cbhq/cds-mobile/typography/TextBody';

import { ControlledCheckbox } from ':rn/cds-wallet/forms/ControlledCheckbox';
import { ControlledSecureTextInput } from ':rn/cds-wallet/forms/ControlledSecureTextInput';
import { useLegalLinks } from ':rn/shared/hooks/useLegalLinks';

import { Button } from '../interactables/Button';

import {
  CloudBackupPasswordForm,
  createValidationSchema,
  initialValues,
} from './CloudBackupPassword.form';
import { messages } from './messages';

type CloudBackupPasswordConfirmProps = {
  onSubmit: (password: string) => void;
  isLoading?: boolean;
  buttonText?: string;
};

export const CloudBackupPasswordConfirm = memo(function CloudBackupPasswordConfirm({
  onSubmit,
  isLoading = false,
  buttonText,
}: CloudBackupPasswordConfirmProps) {
  const { formatMessage } = useIntl();
  const { privacyPolicyLink, termsOfServiceLink } = useLegalLinks();

  const validationSchema = useMemo(
    () => yupResolver(createValidationSchema(formatMessage)),
    [formatMessage],
  );

  const methods = useForm<CloudBackupPasswordForm>({
    mode: 'onChange',
    reValidateMode: 'onChange',
    defaultValues: initialValues,
    resolver: validationSchema,
  });

  const {
    formState: { isValid, isDirty, isSubmitting },
    getValues,
    getFieldState,
    watch,
    trigger,
  } = methods;

  // only display the confirmation password input after
  // we've entered a valid password once
  const [showPasswordConfirmation, setShowPasswordConfirmation] = useState(false);
  const passwordFieldIsValid = useDebounce(isDirty && !getFieldState('password').invalid, 100);

  const passwordValue = watch('password');

  useEffect(
    function verifyPasswordIsValid() {
      if (passwordFieldIsValid) {
        setShowPasswordConfirmation(true);
      }
    },
    [passwordFieldIsValid],
  );

  // react-hook-form is not propagating the errors from Yup into the form context errors dictionary,
  // which leads to the `passwordConfirmation` field to not validate unless the input control itself changes.
  // This workaround ensures that we retrigger a render that validates both passwords match.
  useEffect(
    function triggerPasswordValidation() {
      trigger('passwordConfirmation');
    },
    [passwordValue, trigger],
  );

  const handleSubmit = useCallback(
    function handleSubmit() {
      const password = getValues().password;
      onSubmit(password);
    },
    [getValues, onSubmit],
  );

  return (
    <VStack spacingHorizontal={3} flexGrow={1}>
      <VStack gap={2}>
        <TextTitle1>{formatMessage(messages.title)}</TextTitle1>
        <TextBody color="foregroundMuted">{formatMessage(messages.description)}</TextBody>
      </VStack>
      <VStack justifyContent="space-between" flexGrow={1}>
        <FormProvider {...methods}>
          <VStack spacingTop={6}>
            <ControlledSecureTextInput
              name="password"
              testID="backup-password"
              placeholder={formatMessage(messages.passwordPlaceholder)}
            />

            {showPasswordConfirmation && (
              <ControlledSecureTextInput
                name="passwordConfirmation"
                testID="backup-password-confirmation"
                placeholder={formatMessage(messages.passwordConfirmationPlaceholder)}
              />
            )}
          </VStack>
          <VStack>
            <Box spacingEnd={2}>
              <ControlledCheckbox
                name="acceptedPasswordResponsibility"
                accessibilityLabel={formatMessage(messages.acceptResponsibilityWithoutLinks)}
                label={formatMessage(messages.acceptResponsibility, {
                  t: termsOfServiceLink,
                  pp: privacyPolicyLink,
                })}
                testID="backup-password-checkbox"
              />
            </Box>
            <Spacer vertical={3} />
            <Button
              disabled={!isValid || !isDirty}
              loading={isSubmitting || isLoading}
              onPress={methods.handleSubmit(handleSubmit)}
              testID="backup-password-submit"
            >
              {buttonText ?? formatMessage(messages.continue)}
            </Button>
          </VStack>
        </FormProvider>
      </VStack>
    </VStack>
  );
});

