  tokenId,
  animationUrl,
  cachedAnimationUrl,
  imageUrl,
  cachedImageUrl,
  height,
  width,
  preview,
  chainId,
  shape,
  errorFallback,
  onMediaLoadSuccess,
  onMediaLoadError,
  testID = '',
  retrievalMethod = RetrievalMethod.UPLOAD,
  dangerouslySetRadius,
  dangerouslySetStyle,
  name = '',
  trackName = '',
  artistName = '',
  audioControlsEnabled = false,
  resizeMode = 'contain',
  hasUnretrievableMetadata = false,
  isLocalContent = false,
}: CollectibleAssetProps) {
  const { formatMessage } = useIntl();
  const [{ source, poster, mediaType, fromCache }, setMediaInfo] = useState<MediaInfo>({
    source: undefined,
    poster: undefined,
    mediaType: undefined,
    fromCache: true,
  });
  // need to track the previous media info to prevent unnecessary rerender attempts
  const previousMediaInfo = usePreviousValue<BaseMediaInfo>({
    source,
    mediaType,
  });
  const [mediaLoadFailed, setMediaLoadFailed] = useState(false);
  const { background, backgroundAlternate } = usePalette();
  const startTime = useRef<number>(Date.now());
  const shouldSandboxAllNFTs = useShouldSandboxAllNFTs();
  const isMounted = useIsMounted();

  const dangerousStyle = useMemo<StyleProp<ImageStyle> | undefined>(() => {
    if (!dangerouslySetStyle && !dangerouslySetRadius) return undefined;

    return { ...((dangerouslySetStyle as ImageStyle) ?? {}), borderRadius: dangerouslySetRadius };
  }, [dangerouslySetStyle, dangerouslySetRadius]);

  const handleMediaLoadSuccess = useCallback(
    function handleMediaLoadSuccess() {
      const logSuccessEvent = fromCache
        ? logCollectibleCachedMediaLoadSuccessEvent
        : logCollectibleMediaLoadSuccessEvent;

      const elapsedTime = Date.now() - startTime.current;

      logSuccessEvent({
        chainId,
        mediaType: mediaType || '',
        elapsedTime,
        cacheProvider: 'cloudinary',
        contractAddress,
      });

      onMediaLoadSuccess?.({
        contractAddress,
        tokenId,
        chainId,
        elapsedTime,
        mediaType,
      });
    },
    [tokenId, chainId, mediaType, fromCache, contractAddress, onMediaLoadSuccess],
  );

  const handleMediaLoadFailure = useCallback(
    async function handleMediaLoadFailure() {
      onMediaLoadError?.(chainId);
      if (fromCache) {
        logCollectibleCachedMediaLoadFailureEvent({
          chainId,
          mediaType: mediaType || '',
          elapsedTime: Date.now() - startTime.current,
          contractAddress,
        });
        getMediaInfo({
          imageUrl,
          animationUrl,
          preview,
          cachedMediaEnabled: false,
          retrievalMethod,
        })
          .then((result) => isMounted.current && setMediaInfo(result))
          .catch(() => setMediaInfo(ERROR_MEDIA_INFO));

        return;
      }

      logCollectibleMediaLoadFailureEvent({
        chainId,
        mediaType: mediaType || '',
        elapsedTime: Date.now() - startTime.current,
        contractAddress,
      });
      setMediaLoadFailed(true);
    },
    [
      fromCache,
      chainId,
      mediaType,
      contractAddress,
      onMediaLoadError,
      imageUrl,
      animationUrl,
      preview,
      retrievalMethod,
      isMounted,
    ],
  );

  const handleMediaMissing = useCallback(() => {
    logCollectibleMediaMissingEvent({
      chainId,
      mediaType: mediaType || '',
      elapsedTime: Date.now() - startTime.current,
      contractAddress,
      hasUnretrievableMetadata,
    });
  }, [chainId, mediaType, contractAddress, hasUnretrievableMetadata]);

  const handleRenderLoading = useCallback(() => {
    return (
      <CollectibleAssetLoading
        height={height}
        width={width}
        testID={`${testID}-loading`}
        shape={shape}
      />
    );
  }, [height, width, shape, testID]);

  // We wrap SVGs, videos, and audio inside a webview for security reasons.
  // We should also be doing the same for images, but doing so negatively affects performance drastically
  // so we currently show images directly.
  const htmlImageSource = useMemo(
    () => ({
      html: inlineImageHtml({
        background: hasBackground ? backgroundAlternate : background,
        mediaUrl: source ?? '',
        width,
        circle: shape === 'circle',
        onLoad: handleMediaLoadSuccess,
        onError: handleMediaLoadFailure,
        resizeMode,
      }),
    }),
    [
      background,
      backgroundAlternate,
      hasBackground,
      source,
      width,
      shape,
      handleMediaLoadSuccess,
      handleMediaLoadFailure,
      resizeMode,
    ],
  );

  const htmlVideoSource = useMemo(
    () => ({
      html: inlineVideoHtml({
        mediaUrl: source ?? '',
        posterUrl: poster ?? '',
        background: hasBackground ? backgroundAlternate : background,
        width,
        preview,
        circle: shape === 'circle',
        onLoad: handleMediaLoadSuccess,
        onError: handleMediaLoadFailure,
      }),
    }),
    [
      source,
      poster,
      width,
      preview,
      hasBackground,
      background,
      backgroundAlternate,
      shape,
      handleMediaLoadSuccess,
      handleMediaLoadFailure,
    ],
  );

  const htmlAudioSource = useMemo(
    () => ({
      html: inlineAudioHtml({
        mediaUrl: source ?? '',
        posterUrl: poster ?? '',
        background: hasBackground ? backgroundAlternate : background,
        width,
        preview,
        circle: shape === 'circle',
        onLoad: handleMediaLoadSuccess,
        onError: handleMediaLoadFailure,
      }),
    }),
    [
      source,
      poster,
      width,
      preview,
      shape,
      background,
      backgroundAlternate,
      hasBackground,
      handleMediaLoadSuccess,
      handleMediaLoadFailure,
    ],
  );

  const style = useMemo<React.ComponentProps<typeof WebView>['style']>(
    () => ({
      width: '100%',
      height,
      backgroundColor: background,
    }),
    [background, height],
  );

  useEffect(
    function getType() {
      const fetchAndSetMediaInfo = async () => {
        const data = await getMediaInfo({
          animationUrl,
          imageUrl,
          preview,
          cachedAnimationPath: cachedAnimationUrl?.cachedPath,
          cachedAnimationMimeType: cachedAnimationUrl?.mimeType,
          cachedImagePath: cachedImageUrl?.cachedPath,
          cachedImageMimeType: cachedImageUrl?.mimeType,
          cachedMediaEnabled: true,
          retrievalMethod,
        });

        if (isMounted.current) {
          if (
            data?.fromCache &&
            data?.mediaType &&
            !SUPPORTED_MEDIA_TYPES_REGEX.test(data?.mediaType)
          ) {
            logCollectibleCachedMediaUnsupportedEvent({
              chainId,
              mediaType: data.mediaType || '',
              elapsedTime: Date.now() - startTime.current,
              contractAddress,
            });

            const fallbackData = await getMediaInfo({
              imageUrl,
              animationUrl,
              preview,
              cachedMediaEnabled: false,
            });
            setMediaInfo(fallbackData);
          } else {
            setMediaInfo(data);
          }
        }
      };

      fetchAndSetMediaInfo();
    },
    [
      isMounted,
      animationUrl,
      imageUrl,
      preview,
      cachedAnimationUrl,
      cachedImageUrl,
      chainId,
      retrievalMethod,
      contractAddress,
    ],
  );

  useEffect(
    function attemptRerenderOnSourceOrMediaTypeChange() {
      // if the source changes, we'll try to rerender the asset
      // so we set the media load failure state to false

      if (
        mediaLoadFailed &&
        (source !== previousMediaInfo?.source || mediaType !== previousMediaInfo?.mediaType)
      ) {
        setMediaLoadFailed(false);
      }
    },
    [mediaLoadFailed, source, mediaType, previousMediaInfo?.source, previousMediaInfo?.mediaType],
  );

  const isSvg = mediaType === 'image/svg+xml';
  const isVideo = mediaType?.startsWith('video');
  const isAudio = mediaType?.startsWith('audio');
  const isImage = mediaType?.startsWith('image');

  const showMusicNFTControls = useMemo(() => {
    return audioControlsEnabled && fromCache && source && isAudio;
  }, [audioControlsEnabled, fromCache, isAudio, source]);

  const isSupportedMedia = isSvg || isVideo || isAudio || isImage || isLocalContent;
  const shouldSandbox =
    isSvg || isVideo || (isAudio && !showMusicNFTControls) || (shouldSandboxAllNFTs && isImage);

  const showCollectibleAssetError =
    (!imageUrl && !animationUrl && !cachedImageUrl && !cachedAnimationUrl) ||
    !isSupportedMedia ||
    mediaLoadFailed;

  const sandboxHtml = useMemo(() => {
    if (isVideo) return htmlVideoSource;
    if (isAudio) return htmlAudioSource;

    return htmlImageSource;
  }, [isVideo, isAudio, htmlImageSource, htmlVideoSource, htmlAudioSource]);

  const mediaTestID = useMemo(() => {
    if (isSvg) return `${testID}-svg`;
    if (isVideo) return `${testID}-video`;
    if (isAudio) return `${testID}-audio`;

    return `${testID}-image`;
  }, [isSvg, isVideo, isAudio, testID]);

  if (mediaType === undefined && !isLocalContent) {
    return (
      <CollectibleAssetLoading
        height={height}
        width={width}
        testID={`${testID}-loading`}
        shape={shape}
        dangerousStyle={dangerousStyle}
      />
    );
  }

  if (showCollectibleAssetError) {
    return (
      errorFallback || (
        <CollectibleAssetError
          width={width}
          height={height}
          onLoad={source === '' ? handleMediaMissing : undefined}
          testID={`${testID}-error`}
          dangerousStyle={dangerousStyle}
        />
      )
    );
  }

  return (
    <>
      <Box
        height={height}
        width={width ?? height}
        overflow="hidden"
        testID={testID}
        style={dangerousStyle}
        accessibilityLabel={formatMessage(messages.collectibleAssetAccessibilityLabel, {
          nftName: name,
        })}
      >
        {shouldSandbox ? (
          <WebView
            androidLayerType="hardware"
            cacheEnabled
            allowFileAccess={false}
            allowFileAccessFromFileURLs={false}
            allowUniversalAccessFromFileURLs={false}
            javascriptEnabled={false}
            javaScriptCanOpenWindowsAutomatically={false}
            setSupportMultipleWindows
            geolocationEnabled={false}
            originWhitelist={ORIGIN_WHITELIST}
            scrollEnabled={false}
            source={sandboxHtml}
            startInLoadingState
            style={style}
            renderLoading={handleRenderLoading}
            onLoad={handleMediaLoadSuccess}
            onError={handleMediaLoadFailure}
            onHttpError={handleMediaLoadFailure}
            allowsFullscreenVideo={false}
            allowsInlineMediaPlayback
            testID={mediaTestID}
            mixedContentMode="always"
          />
        ) : (
          <RemoteImageWithLoader
            source={showMusicNFTControls ? poster : source}
            hasBackground={hasBackground}
            borderRadius={borderRadius}
            height={height}
            onLoad={handleMediaLoadSuccess}
            onError={handleMediaLoadFailure}
            testID={mediaTestID}
            shape={shape}
            dangerouslySetStyle={dangerouslySetStyle}
            resizeMode={resizeMode}
          />
        )}
      </Box>
      {showMusicNFTControls && source ? (
        <>
          <Box spacingHorizontal={3}>
            <CollectibleAudioControls
              trackName={trackName || name}
              artistName={artistName}
              source={source}
              contractAddress={contractAddress}
              poster={poster}
            />
          </Box>
          <Divider />
        </>
      ) : null}
    </>
  );
});

import { memo, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { BridgeAsset } from 'cb-wallet-data/stores/Bridge/models/BridgeAsset';
import { SwapAsset } from 'cb-wallet-data/stores/Swap/models/SwapAsset';
import { Wallet } from 'cb-wallet-data/stores/Wallets/models/Wallet';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';

import { CurrencySelectorItem, Props as CurrencySelectorItemProps } from './CurrencySelectorItem';

const messages = defineMessages({
  from: {
    defaultMessage: 'From',
    description: "Label indicating the 'from' asset",
  },
  to: {
    defaultMessage: 'To',
    description: "Label indicating the 'to' asset",
  },
});

export type Props = {
  sourceWallet?: Wallet;
  targetSwapAsset: SwapAsset | BridgeAsset | undefined;
  isSwitchAssetEnabled: boolean;
  onSwitch: () => void;
  onPressSource: () => void;
  onPressTarget: () => void;
  isQuoteLoading: boolean;
  fromCryptoAmount: string | undefined;
  toCryptoAmount: string | undefined;
};

export const CurrencySelector = memo(function CurrencySelector({
  sourceWallet,
  targetSwapAsset,
  onPressSource,
  onPressTarget,
  isSwitchAssetEnabled,
  onSwitch,
  isQuoteLoading,
  fromCryptoAmount,
  toCryptoAmount,
}: Props) {
  const { formatMessage } = useIntl();

  const sourceSelector: CurrencySelectorItemProps = useMemo(() => {
    return {
      label: formatMessage(messages.from),
      isLayer2: Boolean(sourceWallet?.network.asChain()?.isLayer2),
      isNonEthChain: Boolean(sourceWallet?.network.asChain()?.isNonEthChain),
      isQuoteLoading,
      network: sourceWallet?.network,
      align: 'start',
      currencyCode: sourceWallet?.currencyCode.code,
      value: fromCryptoAmount || sourceWallet?.currencyCode.code,
      iconUrl: sourceWallet?.imageURL,
      onPress: onPressSource,
      isAssetsButtonDisabled: sourceWallet === undefined,
    };
  }, [formatMessage, fromCryptoAmount, isQuoteLoading, onPressSource, sourceWallet]);

  const targetSelector: CurrencySelectorItemProps = useMemo(() => {
    return {
      label: formatMessage(messages.to),
      isLayer2: Boolean(targetSwapAsset?.network.asChain()?.isLayer2),
      isNonEthChain: Boolean(targetSwapAsset?.network.asChain()?.isNonEthChain),
      isQuoteLoading,
      network: targetSwapAsset?.network,
      align: 'end',
      currencyCode: targetSwapAsset?.currencyCode?.code,
      value: toCryptoAmount || targetSwapAsset?.currencyCode?.code,
      iconUrl: targetSwapAsset?.imageURL,
      isAssetsButtonDisabled: sourceWallet === undefined,
      onPress: onPressTarget,
    };
  }, [
    formatMessage,
    isQuoteLoading,
    onPressTarget,
    sourceWallet,
    targetSwapAsset?.currencyCode?.code,
    targetSwapAsset?.imageURL,
    targetSwapAsset?.network,
    toCryptoAmount,
  ]);

  return (
    <HStack
      borderedTop
      borderedBottom
      borderColor="line"
      alignItems="center"
      justifyContent="space-between"
      spacing={2}
    >
      <CurrencySelectorItem {...sourceSelector} />
      <Pressable
        testID="swap-currency-selector-on-switch-button"
        disabled={!isSwitchAssetEnabled}
        background="transparent"
        onPress={onSwitch}
      >
        <Box
          borderedEnd
          borderColor="line"
          width={1}
          height={80}
          position="absolute"
          top={-20}
          left={20}
        />
        {isSwitchAssetEnabled ? (
          <Box
            width={40}
            height={40}
            bordered
            background="background"
            borderColor="line"
            borderRadius="roundedFull"
            alignItems="center"
            justifyContent="center"
          >
            <Icon size="s" name="arrowsHorizontal" color="foreground" />
          </Box>
        ) : (
          <Box width={40} height={40} background="transparent" />
        )}
      </Pressable>
      <CurrencySelectorItem {...targetSelector} />
    </HStack>
  );
});

import { defineMessages, useIntl } from 'react-intl';
import { Network } from 'cb-wallet-data/stores/Networks/models/Network';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody, TextHeadline } from '@cbhq/cds-mobile/typography';

import { Fallback } from ':rn/cds-wallet/components/Fallbacks/Fallback';
import { AssetIcon } from ':rn/cds-wallet/components/icons/AssetIcon';

const messages = defineMessages({
  noAssetSelected: {
    defaultMessage: 'Choose asset',
    description: 'Label indicating there is no asset selected',
  },
});

export type Props = {
  value: string | undefined;
  currencyCode: string | undefined;
  iconUrl: string | undefined;
  label: string;
  align: 'start' | 'end';
  onPress?: () => void;
  isLayer2: boolean;
  isNonEthChain: boolean;
  isQuoteLoading: boolean;
  network?: Network;
  isAssetsButtonDisabled?: boolean;
};

export function CurrencySelectorItem({
  network,
  isLayer2,
  isNonEthChain,
  value,
  currencyCode,
  iconUrl,
  label,
  align,
  isQuoteLoading,
  isAssetsButtonDisabled,
  onPress,
}: Props) {
  const { formatMessage } = useIntl();

  const isRightSelector = align === 'end';
  const testIDPrefix = `swap-currency-selector-item-${isRightSelector ? 'target' : 'source'}`;

  return (
    // We're applying this key aiming to force the CurrencySelectorItem component to rerender
    // if currencyCode change -- preventing an issue related to the React Native image component
    // Ref: https://github.com/facebook/react-native/issues/9195
    <Box key={`${testIDPrefix}-${currencyCode}`} flexGrow={1} flexBasis={1}>
      <Pressable
        testID={`${testIDPrefix}-pressable`}
        background="transparent"
        disabled={isAssetsButtonDisabled}
        onPress={onPress}
      >
        <Box
          flexGrow={1}
          spacingVertical={0}
          spacingBottom={0}
          spacingStart={isRightSelector ? 4 : 1}
          spacingEnd={isRightSelector ? 1 : 4}
        >
          {!value || !currencyCode ? (
            <VStack alignItems={isRightSelector ? 'flex-end' : 'flex-start'}>
              <TextBody
                testID={testIDPrefix}
                align={isRightSelector ? 'end' : 'start'}
                color="foregroundMuted"
              >
                {label}
              </TextBody>
              <TextHeadline
                testID={`${testIDPrefix}-no-asset-selected`}
                color="primary"
                align="center"
              >
                {formatMessage(messages.noAssetSelected)}
              </TextHeadline>
            </VStack>
          ) : (
            <Box flexDirection={isRightSelector ? 'row-reverse' : 'row'} alignItems="center">
              <AssetIcon
                currencyCode={currencyCode}
                network={network}
                showNetworkIcon={isLayer2 || isNonEthChain}
                iconUrl={iconUrl}
              />
              <VStack
                alignItems={isRightSelector ? 'flex-end' : 'flex-start'}
                spacingHorizontal={2}
              >
                <TextBody
                  testID={testIDPrefix}
                  align={isRightSelector ? 'end' : 'start'}
                  color="foregroundMuted"
                >
                  {label}
                </TextBody>
                {isQuoteLoading ? (
                  <Fallback
                    testID={`${testIDPrefix}-fallback`}
                    flexGrow={1}
                    width={40}
                    height={23}
                  />
                ) : (
                  <TextHeadline testID={`${testIDPrefix}-quote`} ellipsize="tail">
                    {value}
                  </TextHeadline>
                )}
              </VStack>
            </Box>
          )}
        </Box>
      </Pressable>
    </Box>
  );
}

import { useCallback, useMemo, useState } from 'react';
import { useIntl } from 'react-intl';
import { useChooseWalletRecoveryPhraseCopy } from 'cb-wallet-data/hooks/copy/useChooseWalletRecoveryPhraseCopy';
import { DecryptedMnemonicsHandle } from 'cb-wallet-data/stores/Accounts/models/DecryptedMnemonicsHandle';
import { ButtonGroup, IconButton } from '@cbhq/cds-mobile/buttons';

import {
  CloudBackupPasswordContent,
  messages as cloudBackupMessages,
} from ':rn/screens/Settings/screens/MnemonicBackup/CloudBackupPassword';
import {
  messages as recoveryPhraseMessages,
  RecoveryPhraseContent,
} from ':rn/screens/Settings/screens/MnemonicBackup/EscapeHatchRecoveryPhraseScreen';
import { SignoutConfirmContent } from ':rn/screens/Settings/screens/Signout/SignoutConfirmationScreen';
import { useHasInternetConnection } from ':rn/shared/network/useHasInternetConnection';

import { Screen } from '../layout/Screen';
import { NavBar } from '../NavBar/NavBar';

import { AppRestartButton } from './components/AppRestartButton';
import { ChooseWallet } from './components/ChooseWallet';
import { ErrorState } from './components/ErrorState';
import { StatusPageLinkButton } from './components/StatusPageLinkButton';
import { ViewSecretsOrSignOut } from './components/ViewSecretsOrSignOut';
import { ErrorFallbackStep, stepper, useEscapeHatchStepper } from './flow';

type ErrorFallbackProps = {
  shouldShowEscapeHatch?: boolean | undefined;
  message?: string | undefined;
  error?: Error;
  actions?: React.ReactNode;
  testID?: string | undefined;
  onSignOutClickAnalytics?: () => void;
  onViewRecoveryPhraseClickAnalytics?: () => void;
  onNavigateBack?: () => void;
  defaultStep?: ErrorFallbackStep;
};

function ErrorFallbackContent(props: ErrorFallbackProps) {
  const {
    actions,
    onNavigateBack,
    shouldShowEscapeHatch = true,
    onSignOutClickAnalytics,
    onViewRecoveryPhraseClickAnalytics,
  } = props;
  const isConnected = useHasInternetConnection();
  const { currentStep, goToStep } = useEscapeHatchStepper();
  const [mnemonicsHandle, setMnemonicsHandle] = useState<DecryptedMnemonicsHandle | undefined>(
    undefined,
  );

  const { formatMessage } = useIntl();

  const [selectedAccountId, setSelectedAccountId] = useState<string>('');
  const { title: chooseWalletTitle } = useChooseWalletRecoveryPhraseCopy();
  const handleRetrieveMnemonics = useCallback(
    (retrievedMnemonicsHandle: DecryptedMnemonicsHandle) => {
      const mnemonicAccountIds = Object.keys(retrievedMnemonicsHandle);
      if (mnemonicAccountIds.length === 1) {
        setSelectedAccountId(mnemonicAccountIds[0]);
      }
      setMnemonicsHandle(retrievedMnemonicsHandle);
    },
    [],
  );
  const handleSelectWallet = useCallback(
    (accountId: string) => {
      setSelectedAccountId(accountId);
      goToStep('recoveryPhrase');
    },
    [goToStep],
  );

  const accountIds = useMemo(() => Object.keys(mnemonicsHandle || {}), [mnemonicsHandle]);

  const getNavigateToStep = useCallback(
    (step: ErrorFallbackStep) => () => goToStep(step),
    [goToStep],
  );
  const handleBack = useMemo(() => {
    switch (currentStep) {
      case 'viewSecretsOrSignout': {
        return () => goToStep('errorState');
      }
      case 'chooseWallet': {
        return () => goToStep('viewSecretsOrSignout');
      }
      case 'recoveryPhrase': {
        return () => goToStep('viewSecretsOrSignout');
      }
      case 'signOutConfirmation': {
        return () => goToStep('viewSecretsOrSignout');
      }
      case 'cloudBackup': {
        return () => goToStep('recoveryPhrase');
      }
      case 'errorState': {
        return onNavigateBack ? () => onNavigateBack() : undefined;
      }
      default: {
        return undefined;
      }
    }
  }, [currentStep, goToStep, onNavigateBack]);

  const title = useMemo(() => {
    switch (currentStep) {
      case 'chooseWallet': {
        return chooseWalletTitle;
      }
      case 'recoveryPhrase': {
        return formatMessage(recoveryPhraseMessages.title);
      }
      case 'cloudBackup': {
        return formatMessage(cloudBackupMessages.title);
      }
      default: {
        return undefined;
      }
    }
  }, [chooseWalletTitle, currentStep, formatMessage]);

  const renderLeft = useCallback(
    () => <IconButton onPress={handleBack} name="backArrow" transparent testID="nav-back-arrow" />,
    [handleBack],
  );

  const navBar = useMemo(
    () => <NavBar left={handleBack && renderLeft} title={title} />,
    [handleBack, renderLeft, title],
  );

  return (
    <Screen full navBar={navBar}>
      <stepper.Steps>
        <ErrorState
          {...props}
          shouldShowEscapeHatch={shouldShowEscapeHatch}
          key="errorState"
          actions={
            actions ?? (
              <ButtonGroup direction="vertical">
                {isConnected ? <StatusPageLinkButton /> : null}
                <AppRestartButton variant="secondary" />
              </ButtonGroup>
            )
          }
        />
        <ViewSecretsOrSignOut
          key="viewSecretsOrSignout"
          onSignOutClickAnalytics={onSignOutClickAnalytics}
          onViewRecoveryPhraseClickAnalytics={onViewRecoveryPhraseClickAnalytics}
          onRetrieveMnemonics={handleRetrieveMnemonics}
        />
        <SignoutConfirmContent
          key="signOutConfirmation"
          onBack={handleBack}
          isMnemonicEscapeHatch
        />
        <ChooseWallet
          onPressWallet={handleSelectWallet}
          accountIds={accountIds}
          key="chooseWallet"
        />
        <RecoveryPhraseContent
          onNavigateToCloudBackup={getNavigateToStep('cloudBackup')}
          onAuthCancelled={handleBack}
          onBack={handleBack}
          accountId={selectedAccountId}
          mnemonicsHandle={mnemonicsHandle}
          key="recoveryPhrase"
        />
        <CloudBackupPasswordContent
          key="cloudBackup"
          accountId={selectedAccountId}
          onBack={handleBack}
          onCloudBackupSuccess={handleBack}
        />
      </stepper.Steps>
    </Screen>
  );
}

export function ErrorFallback(props: ErrorFallbackProps) {
  return (
    <stepper.Provider defaultStep={props.defaultStep}>
      <ErrorFallbackContent {...props} />
    </stepper.Provider>
  );
}

import { memo, useCallback, useMemo, useState } from 'react';
import type { OpenFrameResult } from '@open-frames/proxy-client';
import { TextInput } from '@cbhq/cds-mobile/controls';
import { VStack } from '@cbhq/cds-mobile/layout';

import { Button } from ':rn/cds-wallet/components/interactables/Button';

import { RemoteImageWithLoader } from '../RemoteImageWithLoader';

type OpenFrameProps = {
  frameData: OpenFrameResult;
  handleButtonPress?: (buttonIndex: string, postUrl?: string, inputText?: string) => Promise<void>;
};

const IMAGE_WIDTH = 250;
const DEFAULT_FRAME_IMAGE_RATIO = 1.91;

export const OpenFrame = memo(function OpenFrame({ frameData, handleButtonPress }: OpenFrameProps) {
  const { postUrl, image, textInput } = frameData;
  const [text, setText] = useState('');
  const [loading, setLoading] = useState<string | undefined>();
  const [disable, setDisable] = useState(false);

  const handleInputChange = useCallback(
    (value: string) => {
      setText(value);
    },
    [setText],
  );

  const onButtonPress = useCallback(
    (buttonKey: string) => async () => {
      setLoading(buttonKey);
      setDisable(true);
      await handleButtonPress?.(buttonKey, postUrl, text);
      setLoading(undefined);
      setDisable(false);
    },
    [handleButtonPress, postUrl, text],
  );

  const source = useMemo(() => {
    return image.content;
  }, [image]);

  const buttonKeys = useMemo(
    () => (frameData.buttons ? Object.keys(frameData.buttons) : []),
    [frameData.buttons],
  );

  const imageHeight = useMemo(() => {
    let ratio = DEFAULT_FRAME_IMAGE_RATIO;
    if (frameData.image?.aspectRatio) {
      const frameRatio = frameData.image.aspectRatio.split(':')[0];
      if (frameRatio) {
        ratio = Number(frameRatio);
      }
    }
    return IMAGE_WIDTH / ratio;
  }, [frameData.image?.aspectRatio]);

  return (
    <VStack spacing={1} gap={1} testID="open-frame">
      <RemoteImageWithLoader
        resizeMode="contain"
        width={IMAGE_WIDTH}
        height={imageHeight}
        source={source}
      />
      {!!textInput && (
        <TextInput
          compact
          width={IMAGE_WIDTH}
          value={text}
          placeholder={textInput?.content}
          onChangeText={handleInputChange}
          testID="frame-image"
        />
      )}
      <VStack gap={1} justifyContent="flex-end">
        {buttonKeys.map((buttonKey) => (
          <Button
            compact
            block={false}
            variant="primary"
            onPress={onButtonPress(buttonKey)}
            loading={loading === buttonKey}
            disabled={disable && loading !== buttonKey}
            key={`open-frame-button-${buttonKey}`}
            testID={`open-frame-button-${buttonKey}`}
          >
            {frameData.buttons?.[buttonKey].label ?? ''}
          </Button>
        ))}
      </VStack>
    </VStack>
  );
});

