const messages = defineMessages({
  popular: {
    defaultMessage: 'Popular',
    description: 'Fund your wallet Popular message',
  },
  otherAmount: {
    defaultMessage: 'Other amount',
    description: 'Fund your wallet other amount option',
  },
  otherAmountA11y: {
    defaultMessage: 'Select to fund with custom funding amount',
    description:
      'Accessibility label for the button that allows users to enter a custom funding amount.',
  },
  fundAmountA11y: {
    defaultMessage: 'Select a preset funding amount of: {fiatSymbol}{option} ({cryptoAmount})',
    description:
      'Accessibility label for buttons corresponding to preset funding amounts, including dynamic values for fiat symbol, option, and crypto amount.',
  },
});

const CRYPTO_DECIMAL_DISPLAY = 3n;

export const FundingPresetsMediaMap: Record<number, React.ReactNode> = {
  [EthereumNetworkMap.whitelisted.ETHEREUM_MAINNET.chainId]: <AddEth />,
  [EthereumNetworkMap.whitelisted.POLYGON_MAINNET.chainId]: <AddMatic />,
  [EthereumNetworkMap.whitelisted.BASE_MAINNET.chainId]: <AddEthOnBase />,
};

const popularOptionBackgroundColorMap: Record<number, PaletteValue> = {
  [EthereumNetworkMap.whitelisted.ETHEREUM_MAINNET.chainId]: 'blue30',
  [EthereumNetworkMap.whitelisted.POLYGON_MAINNET.chainId]: 'purple30',
  [EthereumNetworkMap.whitelisted.BASE_MAINNET.chainId]: 'blue30',
};

type FundingPresetsProps = {
  wallet?: Wallet;
  options: FundingOptions;
  onSelectOption: (option?: number) => void;
  testID?: string;
};

export const FundingPresets = memo(function FundingPresets({
  wallet,
  options,
  testID,
  onSelectOption,
}: FundingPresetsProps) {
  const { formatMessage } = useIntl();
  const currencyFormatter = useCurrencyFormatter();
  const { screenWidth } = useDimensions();
  const spacing = useSpacingScale();

  const optionWidth = useMemo(() => {
    return (screenWidth - spacing[3]) / 3 - spacing[1];
  }, [screenWidth, spacing]);

  const cryptoDecimals = useMemo(
    () => (wallet?.currencyCode.code === ETHEREUM_SYMBOL ? CRYPTO_DECIMAL_DISPLAY : 0n),
    [wallet?.currencyCode.code],
  );

  const popularOptionColor = useMemo(() => {
    const color = popularOptionBackgroundColorMap[wallet?.network.asChain()?.chainId ?? 0];

    return color || 'blue30';
  }, [wallet]);

  const getFormattedCryptoAmount = useCallback(
    function getFormattedCryptoAmount(amountValue: number) {
      if (!wallet) return;

      return currencyFormatter.formatToCrypto({
        currencyCode: wallet.currencyCode,
        decimals: wallet.decimals,
        maxDisplayDecimals: cryptoDecimals,
        minDisplayDecimals: cryptoDecimals,
        value: convertFiatToCrypto(amountValue, wallet, currencyFormatter),
      });
    },
    [cryptoDecimals, currencyFormatter, wallet],
  );

  const handleSelectOtherAmount = useCallback(() => onSelectOption(), [onSelectOption]);

  return (
    <VStack gap={1}>
      <HStack testID={testID} gap={1} spacingTop={3}>
        {options.map((option) => {
          return (
            <FundingPresetItem
              key={`funding-preset-amount-${option}`}
              option={option}
              testID={testID}
              width={optionWidth}
              isPopular={option === options[1]}
              popularOptionColor={popularOptionColor}
              onPress={onSelectOption}
              getFormattedCryptoAmount={getFormattedCryptoAmount}
            />
          );
        })}
      </HStack>
      <PressableOpacity
        onPress={handleSelectOtherAmount}
        testID={`${testID}-other-amount-pressable`}
        accessibilityLabel={formatMessage(messages.otherAmountA11y)}
      >
        <Box
          background="secondary"
          borderRadius="rounded"
          spacingHorizontal={4}
          spacingVertical={2}
        >
          <TextHeadline align="center">{formatMessage(messages.otherAmount)}</TextHeadline>
        </Box>
      </PressableOpacity>
    </VStack>
  );
});

type FundingPresetItemProps = {
  width: number;
  option: number;
  isPopular: boolean;
  popularOptionColor: PaletteValue;
  onPress: (option: number) => void;
  testID?: string;
  getFormattedCryptoAmount: (amountValue: number) => string | undefined;
};

function FundingPresetItem({
  popularOptionColor,
  onPress,
  option,
  isPopular,
  width,
  getFormattedCryptoAmount,
  testID,
}: FundingPresetItemProps) {
  const { formatMessage } = useIntl();
  const spectrum = useSpectrum();
  const activeFiatCode = useActiveFiatCurrency();
  const fiatSymbol = getFiatSymbol(activeFiatCode);

  const popularOptionBG = useMemo(
    () => paletteValueToRgbaString(popularOptionColor, spectrum),
    [popularOptionColor, spectrum],
  );

  const optionBG = useMemo(() => {
    return paletteValueToRgbaString('gray30', spectrum);
  }, [spectrum]);

  const cryptoAmount = useMemo(
    () => getFormattedCryptoAmount(option),
    [getFormattedCryptoAmount, option],
  );

  const handlePress = useCallback(() => {
    onPress(option);
  }, [onPress, option]);

  return (
    <VStack
      testID={`${testID}-item`}
      flexGrow={1}
      justifyContent="center"
      alignItems="center"
      borderRadius="rounded"
      width={width}
      dangerouslySetBackground={isPopular ? popularOptionBG : optionBG}
    >
      {isPopular && (
        <Box
          borderRadius="roundedFull"
          spacingHorizontal={1}
          spacingVertical={0.5}
          offsetTop={3}
          top={10}
          position="absolute"
          dangerouslySetBackground={paletteValueToRgbaString('yellow60', spectrum)}
        >
          <TextCaption color="primaryForeground">{formatMessage(messages.popular)}</TextCaption>
        </Box>
      )}
      <PressableOpacity
        testID={`${testID}-item-pressable`}
        onPress={handlePress}
        accessibilityLabel={formatMessage(messages.fundAmountA11y, {
          fiatSymbol,
          option,
          cryptoAmount,
        })}
      >
        <Box
          spacingHorizontal={1}
          spacingVertical={isPopular ? 2 : 3}
          dangerouslySetBackground={isPopular ? popularOptionBG : optionBG}
        >
          <TextTitle3 align="center">
            {fiatSymbol}
            {option}
          </TextTitle3>
          {cryptoAmount && <TextLegal align="center">{cryptoAmount}</TextLegal>}
        </Box>
      </PressableOpacity>
    </VStack>
  );
}

import { Children, memo, ReactNode } from 'react';
import { GestureResponderEvent } from 'react-native';
import { useIntl } from 'react-intl';
import { useIsPaymentsModeEnabled } from 'cb-wallet-data/stores/AppMode/useIsPaymentsModeEnabled';
import { IconButtonVariant, IconName } from '@cbhq/cds-mobile';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Tooltip } from '@cbhq/cds-mobile/overlays';
import { TextLegal } from '@cbhq/cds-mobile/typography';

import { actionMessages } from ':rn/cds-wallet/components/GlobalActions/actionMessages';
import { AutoHitSlopWrapper } from ':rn/cds-wallet/components/interactables/AutoHitSlopWrapper';

type GlobalActionProps = {
  label: keyof typeof actionMessages;
  iconName: IconName;
  onPress: ((event: GestureResponderEvent) => void) | null | undefined;
  variant?: IconButtonVariant;
  disabled?: boolean;
  testID?: string;
};

const MAX_ACTION_WIDTH = 67;
const MIN_ACTION_WIDTH = 64;
const ICON_WIDTH = 42;
const ACTION_ITEMS_LENGTH = 5;
const MAX_ACTIONS = 5;

export const GlobalAction = memo(function GlobalAction({
  label,
  iconName,
  onPress,
  variant = 'primary',
  disabled,
  testID,
}: GlobalActionProps) {
  const { formatMessage } = useIntl();

  return (
    <Box
      width={`${(1 / ACTION_ITEMS_LENGTH) * 100}%`}
      minWidth={MIN_ACTION_WIDTH}
      maxWidth={MAX_ACTION_WIDTH}
    >
      <VStack
        accessible
        testID={testID}
        alignItems="center"
        accessibilityLabel={formatMessage(actionMessages[label])}
        gap={1}
      >
        <Box maxWidth={ICON_WIDTH}>
          <AutoHitSlopWrapper>
            <IconButton
              disabled={disabled}
              name={iconName}
              variant={variant}
              onPress={onPress}
              testID={`${label}-global-action`}
            />
          </AutoHitSlopWrapper>
        </Box>
        <TextLegal align="center">{formatMessage(actionMessages[label])}</TextLegal>
      </VStack>
    </Box>
  );
});

export const DisabledGlobalAction = memo(function DisabledGlobalAction({
  label,
  iconName,
  variant = 'secondary',
}: Pick<GlobalActionProps, 'label' | 'iconName' | 'variant'>) {
  const { formatMessage } = useIntl();

  return (
    <Tooltip
      content={formatMessage(actionMessages.actionButtonError, {
        actionName: formatMessage(actionMessages[label]),
      })}
    >
      <GlobalAction
        testID={`asset-details-action-btn-${label}-disabled`}
        variant={variant}
        label={label}
        iconName={iconName}
        disabled
        onPress={null}
      />
    </Tooltip>
  );
});

type Props = {
  children: ReactNode;
  isMultiRow?: boolean;
};

export const GlobalActionContainer = memo(function GlobalActionContainer({
  children,
  isMultiRow = false,
}: Props) {
  const isPaymentsMode = useIsPaymentsModeEnabled();
  const justifyContent = isPaymentsMode ? 'space-evenly' : 'space-between';
  const gap = isPaymentsMode ? 1 : 0;
  const childrenArray = Children.toArray(children);
  const count = childrenArray.length;
  const isMultiRowDisplay = isMultiRow && count > MAX_ACTIONS;

  /**
   * We have two rows of actions in asset details, so we need to put min 5 actions in each row.
   * Each row is wrapped around HStack and we need to split the actions accordingly.
   * And each row should have equal number of actions.
   */
  if (isMultiRowDisplay) {
    // Round up if count is odd, this way the first row will have more elements than the second
    const halfCount = Math.ceil(count / 2);
    const firstRowChildren = childrenArray.slice(0, halfCount);
    const secondRowChildren = childrenArray.slice(halfCount);

    return (
      <VStack gap={3}>
        <HStack justifyContent={justifyContent} gap={gap}>
          {firstRowChildren}
        </HStack>
        <HStack justifyContent={justifyContent} gap={gap}>
          {secondRowChildren}
        </HStack>
      </VStack>
    );
  }

  return (
    <HStack justifyContent={justifyContent} gap={gap}>
      {children}
    </HStack>
  );
});

import { useMemo } from 'react';
import { GestureResponderHandlers, StyleSheet, View, ViewProps } from 'react-native';
import { useSpectrumConditional } from '@cbhq/cds-common/hooks/useSpectrumConditional';
import { handleBarHeight, handleBarOffset } from '@cbhq/cds-common/tokens/drawer';
import { usePalette } from '@cbhq/cds-mobile/hooks/usePalette';
import { useSpacingScale } from '@cbhq/cds-mobile/hooks/useSpacingScale';
import { Box } from '@cbhq/cds-mobile/layout';

type HandleBarProps = ViewProps & { panGestureHandlers?: GestureResponderHandlers };

/**
 * CDS Tray uses a Drawer implementation that does not allow us to apply pan gestures only to the drawer
 * handle bar. We have reached out to them and they were not willing to support it at the moment because
 * this component was already using several workarounds; which would be would be fixed by this wallet
 * implementation but would require some effort from them to test it on every client they have.
 *
 * We are going to keep the conversations with them to see if we can get it merged in their code base in
 * the future but, at the moment, we need to keep it in the wallet side.
 *
 * Note: We're not patching it because it'd be harder to maintain different patches (there is an already
 * existing one) of the same library.
 *
 * All our changes made in this component are indicated in this PR: https://github.cbhq.net/frontend/cds/pull/2201
 */
export function HandleBar({
  panGestureHandlers,
  accessibilityLabel,
  onAccessibilityTap,
}: HandleBarProps) {
  const colors = usePalette();

  const handleBarBackgroundColor = useSpectrumConditional({
    dark: colors.line,
    light: colors.backgroundAlternate,
  });

  const spacing = useSpacingScale();

  const handleBarStyles = useMemo(
    () => ({
      marginBottom: spacing[2],
      backgroundColor: handleBarBackgroundColor,
    }),
    [handleBarBackgroundColor, spacing],
  );

  const viewStyle = useMemo(() => {
    return [styles.handleBar, handleBarStyles];
  }, [handleBarStyles]);

  return (
    <Box
      accessible
      testID="handleBar"
      accessibilityLabel={accessibilityLabel}
      onAccessibilityTap={onAccessibilityTap}
      style={styles.touchableArea}
      {...panGestureHandlers}
    >
      <View style={viewStyle} />
    </Box>
  );
}

const styles = StyleSheet.create({
  touchableArea: {
    position: 'absolute',
    top: -handleBarOffset,
    left: 0,
    right: 0,
    height: handleBarOffset,
    alignItems: 'center',
    justifyContent: 'flex-end',
  },
  handleBar: {
    width: 64,
    height: handleBarHeight,
    borderRadius: 4,
  },
});

HandleBar.displayName = 'HandleBar';

import { memo, ReactNode, useMemo } from 'react';
import { View } from 'react-native';
import { SpacingScale } from '@cbhq/cds-common';
import { useInteractableHeight } from '@cbhq/cds-common/hooks/useInteractableHeight';
import { useSpacingValue } from '@cbhq/cds-mobile/hooks/useSpacingValue';
import { Pressable } from '@cbhq/cds-mobile/system';

export type CustomIconPressableProps = {
  children: ReactNode;
  onPress: () => void;
  disabled?: boolean;
  testID?: string;
  size?: number;
  spacingHorizontal?: SpacingScale;
  accessibilityLabel?: string | undefined;
};

const pressableStyles = {
  alignItems: 'center',
  justifyContent: 'center',
  display: 'flex',
} as const;

export const CustomIconPressable = memo(function CustomTransparentPressable({
  children,
  onPress,
  disabled,
  testID,
  size,
  spacingHorizontal,
  accessibilityLabel,
}: CustomIconPressableProps) {
  const compact = true;
  const height = useInteractableHeight(compact);
  const padding = useSpacingValue(spacingHorizontal ?? 0);

  const style = useMemo(
    () => [
      pressableStyles,
      {
        height: size ?? height,
        width: size ?? height,
        padding,
      },
    ],
    [size, height, padding],
  );

  return (
    <Pressable
      accessibilityRole="button"
      transparentWhileInactive={false}
      borderColor="transparent"
      borderRadius="roundedFull"
      borderWidth="button"
      feedback="light"
      background="background"
      onPress={onPress}
      disabled={disabled}
      testID={testID}
      accessibilityLabel={accessibilityLabel}
    >
      <View style={style}>{children}</View>
    </Pressable>
  );
});

