import { memo, useCallback, useEffect } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { logEvent } from 'cb-wallet-analytics/utils/log';
import { useOnForeground } from 'cb-wallet-data/hooks/useOnForeground';
import { usePrimaryEthReceiveAddress } from 'cb-wallet-data/stores/Wallets/hooks/usePrimaryEthReceiveAddress';
import { DotCount } from '@cbhq/cds-mobile/dots';
import { Box } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import { ActionType, ComponentType } from '@cbhq/client-analytics';
import { markJourney } from '@cbhq/core-vitals-mobile';

import { NetworkBoundary } from ':rn/cds-wallet/components/ErrorBoundary/NetworkBoundary';
import { AutoHitSlopWrapper } from ':rn/cds-wallet/components/interactables/AutoHitSlopWrapper';
import { ChatBubble } from ':rn/cds-wallet/images/ChatBubble/ChatBubble';
import { clickInboxIcon, clickInboxIconNux } from ':rn/screens/Messaging/constants';
import { useHasXmtpKeys } from ':rn/screens/Messaging/hooks/useHasXmtpKeys';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';
import { useGetBadgeCounts } from ':rn/shared/notifications/hooks/useGetBadgeCounts';
import { useUpdateAppBadge } from ':rn/shared/notifications/hooks/useUpdateAppBadge';
import { AssetsParamList } from ':rn/shared/types/ParamLists';

const InboxIcon = memo(function InboxIcon() {
  const { formatMessage } = useIntl();
  const { push } = useStackNavigation<AssetsParamList>();
  const primaryAddress = usePrimaryEthReceiveAddress();
  const { totalBadgeCount } = useGetBadgeCounts(primaryAddress);
  const updateAppBadge = useUpdateAppBadge();
  const { hasKeys, hasRequestedKeys } = useHasXmtpKeys();

  const messages = defineMessages({
    a11yLabel: {
      defaultMessage: '{amount} messages',
      description: 'Inbox messages accessibility label',
    },
  });

  useEffect(
    function updateAppLevelBadge() {
      updateAppBadge(totalBadgeCount);
    },
    [totalBadgeCount, updateAppBadge],
  );

  // Notifee resets the badgeCount when the appState changes.
  // XMTP notifications aren't cleared until you view or block an unread conversation.
  // In-app notifications aren't cleared until you view the Notification tab.
  // This effect resets the app icon on appState changes so that it's in sync with
  // this components count
  useOnForeground(() => updateAppBadge(totalBadgeCount));

  const handleOnInboxPress = useCallback(
    function handleOnInboxPress() {
      logEvent('messaging.inbox_icon.clicked', {
        action: ActionType.click,
        componentType: ComponentType.icon,
      });

      if (hasRequestedKeys) {
        markJourney(hasKeys ? clickInboxIcon : clickInboxIconNux);
      }

      push('MessagingStack', undefined, undefined);
    },
    [hasKeys, hasRequestedKeys, push],
  );

  return (
    <Box position="relative" testID="inbox-icon" spacingHorizontal={1}>
      <AutoHitSlopWrapper>
        <PressableOpacity
          onPress={handleOnInboxPress}
          testID="notification-bell"
          accessibilityLabel={formatMessage(messages.a11yLabel, {
            amount: totalBadgeCount > 0 ? totalBadgeCount : undefined,
          })}
        >
          <DotCount
            pin="top-end"
            overlap="circular"
            max={9}
            count={totalBadgeCount}
            testID="notification-bell-badge"
          >
            <ChatBubble />
          </DotCount>
        </PressableOpacity>
      </AutoHitSlopWrapper>
    </Box>
  );
});

function InboxIconContainer() {
  return (
    <NetworkBoundary errorFallback={null} fallback={null}>
      <InboxIcon />
    </NetworkBoundary>
  );
}

export { InboxIconContainer as InboxIcon };

