    defaultMessage: 'Back',
    description: 'Back button accessibility label',
  },
});

export function NavBarBase({
  left = 'empty',
  children,
  right,
  handleLeft,
  handleRight,
  disableLeft = false,
  background = true,
  height = NAVBAR_HEIGHT,
  animatedHeight,
}: NavBarBaseConfig) {
  const { formatMessage } = useIntl();
  const { canGoBack, goBack, popStack } = useStackNavigation();

  const leftContent = useMemo(() => {
    if (isFunction(left)) {
      return left();
    }

    let leftEnum: ReactNode;

    switch (left) {
      case 'back':
        if (canGoBack()) {
          leftEnum = (
            <IconButton
              name="backArrow"
              onPress={handleLeft || goBack}
              disabled={disableLeft}
              transparent
              accessibilityLabel={formatMessage(messages.backAccessibilityLabel)}
              testID="nav-back-arrow"
            />
          );
        }
        break;
      case 'close':
        if (canGoBack()) {
          leftEnum = (
            <IconButton
              name="close"
              onPress={handleLeft || goBack}
              disabled={disableLeft}
              transparent
              testID="nav-close-x-left"
            />
          );
        }
        break;
      default:
        // empty case
        break;
    }

    return (
      <HStack
        justifyContent="center"
        alignItems="center"
        width={ICON_MIN_DIMENSION}
        height={ICON_MIN_DIMENSION}
      >
        {leftEnum}
      </HStack>
    );
  }, [left, canGoBack, handleLeft, goBack, disableLeft, formatMessage]);

  const rightContent = useMemo(() => {
    if (isFunction(right)) {
      return right();
    }

    let rightElement: ReactNode = right;

    if (right === 'close') {
      rightElement = (
        <IconButton
          name="close"
          onPress={handleRight || popStack}
          transparent
          testID="nav-close-x"
        />
      );
    }

    return (
      <HStack justifyContent="center" alignItems="center">
        {rightElement}
      </HStack>
    );
  }, [handleRight, popStack, right]);

  return (
    <HStack
      animated={!!animatedHeight}
      style={animatedHeight}
      background={background}
      spacingHorizontal={2}
      alignItems="center"
      justifyContent="space-between"
      testID="nav-bar-base"
      height={animatedHeight ? undefined : height}
    >
      {leftContent}
      <VStack flexGrow={1} flexShrink={1}>
        {children}
      </VStack>
      {rightContent}
    </HStack>
  );
}

import { useCallback } from 'react';
import { IconButton } from '@cbhq/cds-mobile/buttons';
