import { SegmentedProgressBar } from '../ProgressBar/SegmentedProgressBar';

import { ICON_MIN_DIMENSION, NavBarBase } from './NavBarBase';

type NavBarConfig = {
  totalSteps: number; // total count
  currentStep: number; // zero-based index
  onBackPressed?: () => void;
};

export function NavBarStepper({ totalSteps, currentStep, onBackPressed }: NavBarConfig) {
  // only render the back button whenever a callback is passed
  // but make sure to render the empty container so the layout doesn't shift
  const backIcon = useCallback(() => {
    return onBackPressed ? (
      <IconButton
        name="backArrow"
        onPress={onBackPressed}
        transparent
        testID="nav-bar-stepper-back"
      />
    ) : (
      <HStack
        spacing={0}
        justifyContent="center"
        alignItems="center"
        width={ICON_MIN_DIMENSION}
        height={ICON_MIN_DIMENSION}
      />
    );
  }, [onBackPressed]);

  return (
    <NavBarBase left={backIcon}>
      <VStack spacingHorizontal={4} justifyContent="center">
        <SegmentedProgressBar totalSegments={totalSteps} filledSegments={currentStep + 1} />
      </VStack>
    </NavBarBase>
  );
}

