export type Props = {
  network: Network;
  balance?: Decimal;
  selected?: boolean;
  disabled?: boolean;
  onPress?: (network: Network) => void;
  showBalance?: boolean;
  iconSize?: number;
  compact?: boolean;
};

const messages = defineMessages({
  selectNetwork: {
    defaultMessage: 'Select the network: {networkName}.',
    description:
      'Accessibility label for selecting a network in the list, including dynamic values for network name.',
  },
});

export function NetworkListItem({
  network,
  balance,
  selected,
  onPress,
  disabled,
  showBalance = true,
  iconSize,
  compact,
}: Props) {
  const { formatters, formatMessage } = useIntl();

  const activeFiatCurrency = useActiveFiatCurrency();
  const networkAsChain = network.asChain();

  const onSelectNetwork = useCallback(() => {
    onPress?.(network);
  }, [network, onPress]);

  const formattedBalance = useMemo(() => {
    if (!showBalance) return null;

    const currencyFormatter = formatters.getNumberFormat(undefined, {
      style: 'currency',
      currency: activeFiatCurrency.code.rawValue,
    });

    const decimalFormatter = formatters.getNumberFormat(undefined, {
      style: 'decimal',
      currency: activeFiatCurrency.code.rawValue,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

    return formatDecimal({
      integerFormatter: currencyFormatter,
      decimalFormatter,
      value: balance ?? new Decimal(0),
    });
  }, [showBalance, formatters, activeFiatCurrency.code.rawValue, balance]);

  return (
    <ListCell
      testID={`network-list-item-${networkAsChain?.chainId}`}
      variant="positive"
      selected={selected}
      disabled={disabled}
      onPress={onSelectNetwork}
      detail={formattedBalance}
      title={networkAsChain?.displayName}
      media={<NetworkIcon network={network} size={iconSize} />}
      compact={compact}
      accessibilityLabel={formatMessage(messages.selectNetwork, {
        networkName: networkAsChain?.displayName,
      })}
    />
  );
}

