const messages = defineMessages({
  a11yLabel: {
    defaultMessage: '{amount} notifications',
    description: 'Notifications accessibility label',
  },
});

type Props = {
  onPress: () => void;
};

const NotificationsBell = memo(function NotificationsBell({ onPress }: Props) {
  const { formatMessage } = useIntl();
  const { data: badgeCountData } = useUnreadNotificationCount();
  const updateAppBadge = useUpdateAppBadge();

  const badgeCount = useMemo(() => badgeCountData?.count || 0, [badgeCountData]);

  useEffect(
    function updateAppLevelBadge() {
      updateAppBadge(badgeCount);
    },
    [badgeCount, updateAppBadge],
  );

  // Notifee resets the badgeCount when the appState changes.
  // XMTP notifications aren't cleared until you view or block an unread conversation.
  // In-app notifications aren't cleared until you view the Notification tab.
  // This effect resets the app icon on appState changes so that it's in sync with
  // this components count
  useOnForeground(() => updateAppBadge(badgeCount));

  return (
    <Box position="relative" spacingHorizontal={1}>
      <AutoHitSlopWrapper>
        <PressableOpacity
          onPress={onPress}
          testID="notification-bell"
          accessibilityLabel={formatMessage(messages.a11yLabel, {
            amount: badgeCount > 0 ? badgeCount : undefined,
          })}
        >
          <DotCount
            pin="top-end"
            overlap="circular"
            count={badgeCount}
            max={9}
            testID="notification-bell-badge"
          >
            <NavigationIcon name="bell" size="m" />
          </DotCount>
        </PressableOpacity>
      </AutoHitSlopWrapper>
    </Box>
  );
});

function NotificationsBellContainer({ onPress }: Props) {
  return (
    <ErrorBoundary errorFallback={null}>
      <NotificationsBell onPress={onPress} />
    </ErrorBoundary>
  );
}

export { NotificationsBellContainer as NotificationsBell };

