// Original code from: https://github.com/breeffy/react-native-popup-menu
// Converted to functional components and rebuilt with CDS components where possible
import {
  forwardRef,
  memo,
  MutableRefObject,
  ReactNode,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from 'react';
import {
  Animated,
  Easing,
  LayoutChangeEvent,
  Modal,
  Platform,
  StyleProp,
  StyleSheet,
  TouchableWithoutFeedback,
  View,
  ViewStyle,
} from 'react-native';
import { useTheme } from '@react-navigation/native';
import { curves, durations } from '@cbhq/cds-common/motion/tokens';
import { borderRadius } from '@cbhq/cds-common/tokens/borderRadius';
import { usePalette } from '@cbhq/cds-mobile/hooks/usePalette';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { Overlay } from '@cbhq/cds-mobile/overlays';

export enum Position {
  TOP_LEFT,
  TOP_RIGHT,
  TOP_CENTER,
  BOTTOM_LEFT,
  BOTTOM_RIGHT,
  BOTTOM_CENTER,
}

type Offset = {
  top?: number;
  left?: number;
  right?: number;
  bottom?: number;
};

type ComputeOffsetCallback =
  | ((left: number, top: number, width: number, height: number) => Offset)
  | null;

const SCREEN_INDENT = 8;

const enum State {
  MEASURING,
  CALCULATING,
  SHOWN,
  HIDDEN,
  ANIMATING,
}

type PositionShift = {
  left: number;
  top: number;
};

type ComponentLayout = {
  left: number;
  top: number;
  width: number;
  height: number;
};

function normalizeOffset(extraOffset: Offset): PositionShift {
  const reducer = (
    { left, top }: { left: number; top: number },
    [prop, value]: [string, number],
  ) => {
    let leftOffset = left;
    let topOffset = top;
    if (prop === 'left') {
      leftOffset += value;
    } else if (prop === 'right') {
      leftOffset -= value;
    } else if (prop === 'top') {
      topOffset += value;
    } else if (prop === 'bottom') {
      topOffset -= value;
    }
    return { left: leftOffset, top: topOffset };
  };

  return Object.entries(extraOffset).reduce(reducer, { left: 0, top: 0 });
}

function getSummarizedOffset(offsetList: PositionShift[]) {
  const reducer = (acc: PositionShift, { left, top }: PositionShift) => ({
    left: acc.left + left,
    top: acc.top + top,
  });
  return offsetList.reduce(reducer, { left: 0, top: 0 });
}

function getMenuOffset(
  stickTo: Position,
  component: ComponentLayout,
  menu: ComponentLayout,
): PositionShift {
  if (stickTo === Position.TOP_RIGHT) {
    const left = component.left + (component.width - menu.width);
    const top = component.top;
    return { left, top };
  }
  if (stickTo === Position.BOTTOM_LEFT) {
    const left = component.left;
    const top = component.top + component.height;
    return { left, top };
  }
  if (stickTo === Position.BOTTOM_RIGHT) {
    const left = component.left + (component.width - menu.width);
    const top = component.top + component.height;
    return { left, top };
  }
  if (stickTo === Position.TOP_LEFT) {
    const left = component.left;
    const top = component.top;
    return { left, top };
  }
  if (stickTo === Position.TOP_CENTER) {
    const left = component.left + Math.round((component.width - menu.width) / 2);
    const top = component.top;
    return { left, top };
  }
  if (stickTo === Position.BOTTOM_CENTER) {
    const left = component.left + Math.round((component.width - menu.width) / 2);
    const top = component.top + component.height;
    return { left, top };
  }

  return { left: 0, top: 0 };
}

function getComputedOffset({
  computeOffset,
  left,
  top,
  width,
  height,
}: {
  computeOffset?: ComputeOffsetCallback;
  left: number;
  top: number;
  width: number;
  height: number;
}) {
  if (computeOffset) {
    const extraOffset = computeOffset(left, top, width, height);
    return normalizeOffset(extraOffset);
  }
  return null;
}

type PopoverMenuProps = {
  testID?: string;
  style?: StyleProp<ViewStyle>;
  onHidden?: () => void;
  children: ReactNode;
};

type ShowParams = {
  anchorRef: MutableRefObject<View>['current'] | null;
  stickToPosition?: Position;
  extraOffset?: Offset;
  computeOffset?: ComputeOffsetCallback;
};

export type PopoverRef = {
  show: ({ anchorRef, stickToPosition, extraOffset, computeOffset }: ShowParams) => void;
  /**
   * callback is fired when the hide action completes its animation to close the menu
   */
  hide: (callback?: () => void) => void;
};

export const PopoverMenu = memo(
  forwardRef<PopoverRef, PopoverMenuProps>(function PopoverMenu(
    { testID, style, onHidden, children },
    ref,
  ) {
    const { background, backgroundAlternate } = usePalette();
    const { dark } = useTheme();

    const opacityAnimation = useRef<Animated.Value>(new Animated.Value(0)).current;
    const [menuState, setMenuState] = useState<State>(State.HIDDEN);
    const [stickTo, setStickTo] = useState<Position>(Position.TOP_LEFT);
    const [staticOffset, setStaticOffset] = useState<PositionShift>({ left: 0, top: 0 });
    const [computedOffset, setComputedOffset] = useState<PositionShift>({ left: 0, top: 0 });
    const [component, setComponent] = useState<ComponentLayout>({
      left: 0,
      top: 0,
      width: 0,
      height: 0,
    });
    const [menu, setMenu] = useState<ComponentLayout>({
      left: 0,
      top: 0,
      width: 0,
      height: 0,
    });

    useImperativeHandle(ref, () => ({
      show,
      hide,
    }));

    const animationStarted = useMemo(() => menuState === State.ANIMATING, [menuState]);

    const modalVisible = useMemo(
      () =>
        menuState === State.MEASURING ||
        menuState === State.CALCULATING ||
        menuState === State.SHOWN ||
        animationStarted,
      [menuState, animationStarted],
    );

    const show = useCallback(
      ({ anchorRef, stickToPosition, extraOffset, computeOffset }: ShowParams) => {
        if (anchorRef !== null) {
          if (typeof anchorRef.measureInWindow !== 'function') {
            throw Error(`Provide reference to component which has method measureInWindow`);
          }

          anchorRef.measureInWindow((x: number, y: number, width: number, height: number) => {
            if (x === undefined || y === undefined || width === undefined || height === undefined) {
              throw Error(
                `Can't calculate popup menu position because measureInWindow returned undefined value: [x: ${x}, y: ${y}, width: ${width}, height: ${height}]; Hint: set collapsable={false} View property`,
              );
            }
            const top = Math.max(SCREEN_INDENT, y);
            const left = Math.max(SCREEN_INDENT, x);

            const newComputedOffset = getComputedOffset({
              computeOffset,
              left,
              top,
              width,
              height,
            });

            setMenuState(State.MEASURING);
            setComponent({ left, top, width, height });
            if (extraOffset) setStaticOffset(normalizeOffset(extraOffset));
            if (newComputedOffset) setComputedOffset(newComputedOffset);
            if (stickToPosition) setStickTo(stickToPosition);
          });
        }
      },
      [],
    );

    /* Measure new menu width and height */
    const _onMenuLayout = useCallback(
      function _onMenuLayout(event: LayoutChangeEvent): void {
        const { width, height } = event.nativeEvent.layout;
        if (menuState === State.MEASURING) {
          setMenuState(State.CALCULATING);
          setMenu((prev) => ({
            ...prev,
            width,
            height,
          }));
        }
      },
      [menuState],
    );

    const _onDismiss = useCallback(() => {
      if (onHidden) {
        onHidden();
      }
    }, [onHidden]);

    const hide = useCallback(
      (callback?: () => void) => {
        Animated.timing(opacityAnimation, {
          toValue: 0,
          duration: durations.moderate3,
          easing: Easing.bezier(...curves.global),
          useNativeDriver: true,
        }).start(() => {
          /* Reset state */
          setMenuState(State.HIDDEN);
          if (callback) callback();
          if (onHidden) onHidden();
        });
      },
      [onHidden, opacityAnimation],
    );

    useEffect(
      function menuShown() {
        if (menuState === State.SHOWN) {
          setMenuState(State.ANIMATING);
          Animated.timing(opacityAnimation, {
            toValue: 1,
            duration: durations.moderate3,
            easing: Easing.bezier(...curves.global),
            useNativeDriver: true,
          }).start();
        }
      },
      [menu, menuState, opacityAnimation],
    );

    useEffect(
      function menuCalculating() {
        if (menuState === State.CALCULATING) {
          const baseOffset = getMenuOffset(stickTo, component, menu);
          const allOffsets = [baseOffset, staticOffset, computedOffset];
          const finalOffset = getSummarizedOffset(allOffsets);

          setMenuState(State.SHOWN);
          setMenu((prev) => ({
            ...prev,
            left: finalOffset.left,
            top: finalOffset.top,
          }));
        }
      },
      [component, computedOffset, menu, menuState, staticOffset, stickTo],
    );

    const shadowMenuContainerStyle = useMemo(
      () => ({
        opacity: opacityAnimation,
        transform: [
          {
            translateY: opacityAnimation.interpolate({
              inputRange: [0, 1],
              outputRange: [-16, 0],
            }),
          },
        ],
        left: menu.left,
        top: menu.top,
        backgroundColor: dark ? backgroundAlternate : background,
      }),
      [opacityAnimation, menu.left, menu.top, dark, backgroundAlternate, background],
    );

    const supportedOrientations:
      | (
          | 'portrait'
          | 'portrait-upside-down'
          | 'landscape'
          | 'landscape-left'
          | 'landscape-right'
        )[] = useMemo(
      () => ['portrait', 'portrait-upside-down', 'landscape', 'landscape-left', 'landscape-right'],
      [],
    );

    const animatedViewStyle = useMemo(
      () => [styles.shadowMenuContainer, shadowMenuContainerStyle, style],
      [shadowMenuContainerStyle, style],
    );

    const handlePressHide = useCallback(() => hide(), [hide]);

    return (
      <Box collapsable={false} testID={testID}>
        <Modal
          visible={modalVisible}
          onRequestClose={handlePressHide}
          supportedOrientations={supportedOrientations}
          transparent
          onDismiss={_onDismiss}
          presentationStyle="overFullScreen"
        >
          <Overlay opacity={opacityAnimation} />
          <TouchableWithoutFeedback onPress={handlePressHide}>
            <Box style={StyleSheet.absoluteFill}>
              <Box
                animated
                {...(!animationStarted ? { onLayout: _onMenuLayout } : {})}
                style={animatedViewStyle}
              >
                <Box spacing={1} animated overflow="hidden">
                  <VStack>{children}</VStack>
                </Box>
              </Box>
            </Box>
          </TouchableWithoutFeedback>
        </Modal>
      </Box>
    );
  }),
);

const styles = StyleSheet.create({
  shadowMenuContainer: {
    position: 'absolute',
    borderRadius: borderRadius.rounded,
    opacity: 0,
    /* Shadow */
    ...Platform.select({
      ios: {
        shadowColor: 'black',
        shadowOffset: { width: 0, height: 2 },
        shadowOpacity: 0.25,
        shadowRadius: 2,
      },
      android: {
        elevation: 8,
      },
    }),
  },
});

