type AddressQRCodeTransferValueInfos = {
  amount: string;
  blockchain: AllPossibleBlockchainSymbol;
  contractAddress?: string;
  decimals: string;
};

type AddressQRCodeProps = Omit<
  AddressQRCardProps,
  'addressHeadline' | 'handleCopyClick' | 'addressType'
> & {
  transferValueInfos?: AddressQRCodeTransferValueInfos;
};

const protocolMap = new Map<BlockchainSymbol, CryptoQRCodeProtocol>([
  ['ETH', 'ethereum'],
  ['SOL', 'solana'],
  ['BTC', 'bitcoin'],
  ['DOGE', 'dogecoin'],
  ['LTC', 'litecoin'],
]);

export function AddressQRCode({
  address,
  addressImageURL,
  currencyCode,
  blockchainSymbol,
  transferValueInfos,
  handleQRTap,
}: AddressQRCodeProps) {
  const value = useMemo(
    () =>
      transferValueInfos ? generateCryptoSendUri({ ...transferValueInfos, address }) : address,
    [transferValueInfos, address],
  );

  // TODO: Asset Metadata V4, use enforced parameters
  const { asset, isFetched } = useAsset({ assetSymbol: currencyCode });

  const isAddressObservabilityEnabled = useIsFeatureEnabled('utxo_address_observability');

  const protocol = protocolMap.get(blockchainSymbol);
  const qrCodeValue = useMemo(() => (protocol ? `${protocol}:${value}` : value), [protocol, value]);
  const assetColor = useMemo(() => asset?.color ?? '#000000', [asset?.color]);
  const logo = useMemo(() => {
    return addressImageURL ? { uri: addressImageURL } : undefined;
  }, [addressImageURL]);

  const handleQRPress = useCallback(() => {
    handleQRTap();
  }, [handleQRTap]);

  return (
    <Box alignItems="center" spacingTop={1} testID="address-qr-code">
      {isAddressObservabilityEnabled && isUTXOBasedBlockchain(blockchainSymbol) ? (
        <Pressable
          background="transparent"
          onPress={handleQRPress}
          noScaleOnPress
          testID="pressable-qr-code"
        >
          <QRCodeComponent
            value={qrCodeValue}
            color={assetColor}
            logo={logo}
            isAsyncDataFetched={isFetched}
          />
        </Pressable>
      ) : (
        <QRCodeComponent
          value={qrCodeValue}
          color={assetColor}
          logo={logo}
          isAsyncDataFetched={isFetched}
        />
      )}
    </Box>
  );
}

