type ReceiveAddressListItemProps = {
  wallet: Wallet | undefined;
  blockchainConfig: WalletConfiguration;
  onPressSideEffect?: () => void;
  minHeight?: number;
  onPressInfoIcon: (c: ChainsWithAddressInfoTray) => void;
};

export function ReceiveAddressListItem({
  wallet,
  blockchainConfig,
  onPressSideEffect,
  minHeight,
  onPressInfoIcon,
}: ReceiveAddressListItemProps) {
  const { copyToClipboard } = useClipboard();
  const { formatMessage } = useIntl();
  const { openModal, closeModal } = useModal();
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);

  const isNetworkAllowed = useIsNetworkAllowed();

  const rawValue = blockchainConfig.defaultReceiveType.rawValue;
  const chainSymbol = blockchainConfig.blockchain.rawValue as AllPossibleBlockchainSymbol;
  const blockchainImageURL = blockchainConfig.imageURL;
  // TODO: Asset Metadata V4, use enforced parameters
  useAsset({ assetSymbol: chainSymbol }); // prefetch asset so QR code doesn't take forever to fetch asset color

  const receiveValue = useMemo<CustomReceiveValue | undefined>(
    () =>
      wallet
        ? {
            wallet,
            value: 0n,
          }
        : undefined,
    [wallet],
  );

  const blockchainConfigMessageMap = useMemo(
    () => ({
      [SolanaAddressType.rawValue]: 'Solana',
      [BitcoinSegwitAddressType.rawValue]: 'Bitcoin',
      [EthereumAddressType.rawValue]: 'Ethereum',
    }),
    [],
  );

  const blockchainName = useMemo(
    () => (rawValue in blockchainConfigMessageMap ? blockchainConfigMessageMap[rawValue] : ''),
    [blockchainConfigMessageMap, rawValue],
  );

  const headlineMessage = useMemo(
    () =>
      rawValue in blockchainConfigMessageMap
        ? formatMessage(messages.addressHeadline, { blockchainName })
        : formatMessage(messages.otherAssetsHeadline),
    [blockchainConfigMessageMap, blockchainName, formatMessage, rawValue],
  );

  const qrCodeAccessibilityLabel = useMemo(
    () => formatMessage(messages.qrCodeAccessibilityLabel, { blockchainName }),
    [blockchainName, formatMessage],
  );

  const copyAddressAccessibilityLabel = useMemo(
    () => formatMessage(messages.copyAddressAccessibilityLabel, { blockchainName }),
    [blockchainName, formatMessage],
  );

  const onInfoIconPress = useCallback(
    function onInfoIconPress() {
      const c = chainSymbol as ChainsWithAddressInfoTray;
      onPressInfoIcon(c);
    },
    [chainSymbol, onPressInfoIcon],
  );

  const supportedChainIcons = useMemo<JSX.Element[]>(() => {
    let networks: { name: string; network: Network }[] = [];
    switch (rawValue) {
      case SolanaAddressType.rawValue:
        networks = [...SolanaNetworkSetting.mainnets];
        break;
      case EthereumAddressType.rawValue:
        networks = [...EthereumNetworkSetting.mainnets];
        break;
      default:
        networks = [];
    }

    networks = networks
      .filter((network) => {
        const shouldShowIcon = SUPPORTED_ACCOUNT_BASED_ADDRESS_TYPE_NETWORK_ICONS.get(
          rawValue,
        )?.includes(network.name);
        const isAllowed = isNetworkAllowed(network.network);

        return shouldShowIcon && isAllowed;
      })
      .sort(sortNetworksWithPrioritization);

    return networks.map((network) => {
      return <NetworkIcon network={network.network} key={network.name} />;
    });
  }, [rawValue, isNetworkAllowed]);

  const handleCloseQRCodeModal = useCallback(
    function handleCloseQRCodeModal() {
      onPressSideEffect?.();
      setIsModalOpen(false);
      closeModal();
    },
    [closeModal, onPressSideEffect],
  );

  const [startOpenReceiveQrModalPerfMark] = usePerfMark(
    PERF_MARKS.receive,
    RECEIVE_MARKS.open_receive_qr_modal,
  );

  const onPressQRCode = useCallback(() => {
    if (wallet) {
      startOpenReceiveQrModalPerfMark();
      openModal(
        <ReceiveAddressModal
          visible
          addresses={wallet.addresses}
          addressImageURL={wallet?.imageURL || wallet.network.asChain()?.chainImageUrl}
          chainSymbol={chainSymbol}
          testID="generic-receive-wallet-address-modal"
          onRequestClose={handleCloseQRCodeModal}
          receiveValue={receiveValue}
        />,
      );
      setIsModalOpen(true);
      triggerReceiveByGenericQrCodeClicked(chainSymbol);
    } else {
      // log if user somehow attempts to view address with no wallet present. Should never happen
      reportComponentError({
        error: new Error(
          `Attempt to open ReceiveAddressModal with no wallet present for ${chainSymbol}`,
        ),
        severity: 'error',
        isHandled: false,
      });
    }
  }, [
    wallet,
    startOpenReceiveQrModalPerfMark,
    openModal,
    chainSymbol,
    handleCloseQRCodeModal,
    receiveValue,
  ]);

  const imageSource = useMemo(() => ({ uri: blockchainImageURL }), [blockchainImageURL]);

  const handlePressCopy = useCallback(() => {
    triggerReceiveByGenericCopyAddressClicked(chainSymbol);
  }, [chainSymbol]);

  const handleAddressItemPress = useCallback(
    function handleAddressItemPress() {
      copyToClipboard(wallet?.primaryAddress);
      triggerReceiveByGenericAddressItemClicked(chainSymbol);
      if (onPressSideEffect) {
        setTimeout(() => {
          onPressSideEffect();
        }, TimeSpanDelay.SHORT);
      }
    },
    [chainSymbol, copyToClipboard, onPressSideEffect, wallet?.primaryAddress],
  );

  const hasInfoTray = !chainsWithoutAddressInfoTray.includes(chainSymbol);
  const shouldShowInfoTray = device.isAndroid && isModalOpen && hasInfoTray;

  return (
    <Box spacingVertical={1}>
      {shouldShowInfoTray && (
        <ReceiveAddressInfoTray chainSymbol={chainSymbol as ChainsWithAddressInfoTray} />
      )}
      <Pressable
        background="transparent"
        onPress={handleAddressItemPress}
        testID={`receive-address-list-item-pressable-${chainSymbol}`}
        accessible={false}
      >
        <LegacyCard
          spacingHorizontal={2}
          spacingTop={1}
          spacingBottom={3}
          opacity={wallet ? 1 : 0.6}
          spacingVertical={1}
          minHeight={minHeight}
        >
          <HStack alignItems="center" minHeight={40}>
            <TextHeadline testID={`wallet-address-headline-${chainSymbol}`}>
              {headlineMessage}
            </TextHeadline>
            {hasInfoTray && (
              <AutoHitSlopWrapper>
                <Pressable
                  background="transparent"
                  onPress={onInfoIconPress}
                  testID={`address-info-icon-button-${chainSymbol}`}
                  accessibilityLabel={formatMessage(messages.addressInfoAccessibilityLabel)}
                >
                  <Icon name="info" size="xs" color="foreground" spacing={0.5} />
                </Pressable>
              </AutoHitSlopWrapper>
            )}
          </HStack>
          <HStack justifyContent="space-between" gap={2}>
            <VStack>
              <TextLabel2 color="foregroundMuted" testID={`wallet-address-string-${chainSymbol}`}>
                {wallet
                  ? truncateMiddle(wallet?.primaryAddress, chainSymbol === 'ETH' ? 6 : 4, 6)
                  : formatMessage(messages.scanningAddresses)}
              </TextLabel2>
              {supportedChainIcons.length && wallet ? (
                <HStack gap={0.5} testID="wallet-address-chain-icons" spacingTop={1}>
                  {supportedChainIcons}
                </HStack>
              ) : (
                <Box spacingVertical={1}>
                  {!!blockchainImageURL && (
                    <RemoteImage
                      source={imageSource}
                      height={20}
                      width={20}
                      resizeMode="cover"
                      testID={`${blockchainImageURL}`}
                    />
                  )}
                </Box>
              )}
            </VStack>
            <HStack gap={1}>
              <IconButton
                name="qrCode"
                onPress={onPressQRCode}
                testID={`wallet-address-qr-code-button-${chainSymbol}`}
                disabled={!wallet}
                accessible
                accessibilityLabel={qrCodeAccessibilityLabel}
              />
              <CopyButton
                value={wallet?.primaryAddress}
                testID={`wallet-address-copy-button-${chainSymbol}`}
                type="icon"
                onTransitionDelay={onPressSideEffect}
                disabled={!wallet}
                onPress={handlePressCopy}
                accessible
                accessibilityLabel={copyAddressAccessibilityLabel}
              />
            </HStack>
          </HStack>
        </LegacyCard>
      </Pressable>
    </Box>
  );
}

import { useCallback, useMemo } from 'react';
