type ReceiveAddressListItemProps = {
  wallet: Wallet | undefined;
  blockchainConfig: WalletConfiguration;
  onPressSideEffect?: () => void;
};

export function ReceiveAddressListItemV2({
  wallet,
  blockchainConfig,
  onPressSideEffect,
}: ReceiveAddressListItemProps) {
  const { copyToClipboard } = useClipboard();
  const { formatMessage } = useIntl();
  const { openModal, closeModal } = useModal();

  const receiveTypeRawValue = blockchainConfig.defaultReceiveType.rawValue;
  const isNetworkAllowed = useIsNetworkAllowed();
  const chainSymbol = blockchainConfig.blockchain.rawValue as AllPossibleBlockchainSymbol;
  const blockchainImageURL = blockchainConfig.imageURL;
  // TODO: Asset Metadata V4, use enforced parameters
  useAsset({ assetSymbol: chainSymbol }); // prefetch asset so QR code doesn't take forever to fetch asset color

  const receiveValue = useMemo<CustomReceiveValue | undefined>(
    () =>
      wallet
        ? {
            wallet,
            value: 0n,
          }
        : undefined,
    [wallet],
  );
  const blockchainConfigMessageMap = useMemo(
    () => ({
      [SolanaAddressType.rawValue]: 'Solana',
      [BitcoinSegwitAddressType.rawValue]: 'Bitcoin',
      [EthereumAddressType.rawValue]: 'Ethereum',
      [LitecoinSegwitAddressType.rawValue]: 'Litecoin',
      [DogecoinAddressType.rawValue]: 'Dogecoin',
    }),
    [],
  );

  const blockchainName = useMemo(
    () =>
      receiveTypeRawValue in blockchainConfigMessageMap
        ? blockchainConfigMessageMap[receiveTypeRawValue]
        : '',
    [blockchainConfigMessageMap, receiveTypeRawValue],
  );

  const headlineMessage = useMemo(
    () =>
      receiveTypeRawValue in blockchainConfigMessageMap
        ? formatMessage(messages.addressHeadline, { blockchainName })
        : formatMessage(messages.otherAssetsHeadline),
    [blockchainConfigMessageMap, blockchainName, formatMessage, receiveTypeRawValue],
  );

  const qrCodeAccessibilityLabel = useMemo(
    () => formatMessage(messages.qrCodeAccessibilityLabel, { blockchainName }),
    [blockchainName, formatMessage],
  );

  const copyAddressAccessibilityLabel = useMemo(
    () => formatMessage(messages.copyAddressAccessibilityLabel, { blockchainName }),
    [blockchainName, formatMessage],
  );

  const supportedChainIcons = useMemo<JSX.Element[]>(() => {
    let networks: { name: string; network: Network }[] = [];
    switch (receiveTypeRawValue) {
      case EthereumAddressType.rawValue:
        networks = [...EthereumNetworkSetting.mainnets];
        break;
      default:
        networks = [];
    }

    networks = networks
      .filter((network) => {
        const shouldShowIcon =
          SUPPORTED_ACCOUNT_BASED_ADDRESS_TYPE_NETWORK_ICONS.get(receiveTypeRawValue)?.includes(
            network.name,
          ) && network.name !== EthereumNetworkSetting.defaultMainnet.name;
        const isAllowed = isNetworkAllowed(network.network);

        return shouldShowIcon && isAllowed;
      })
      .sort(sortNetworksWithPrioritization);

    const icons = networks.map((network) => {
      return <NetworkIcon network={network.network} key={network.name} />;
    });

    return icons.length < 5
      ? icons
      : icons.slice(0, 5).concat([
          <Box spacing={0.5}>
            <Icon name="add" size="xs" color="foreground" />
          </Box>,
        ]);
  }, [receiveTypeRawValue, isNetworkAllowed]);

  const handleCloseQRCodeModal = useCallback(
    function handleCloseQRCodeModal() {
      onPressSideEffect?.();
      closeModal();
    },
    [closeModal, onPressSideEffect],
  );

  const [startOpenReceiveQrModalPerfMark] = usePerfMark(
    PERF_MARKS.receive,
    RECEIVE_MARKS.open_receive_qr_modal,
  );

  const onPressQRCode = useCallback(() => {
    if (wallet) {
      startOpenReceiveQrModalPerfMark();
      openModal(
        <ReceiveAddressModal
          visible
          addresses={wallet.addresses}
          addressImageURL={wallet?.imageURL || wallet.network.asChain()?.chainImageUrl}
          chainSymbol={chainSymbol}
          testID="generic-receive-wallet-address-modal"
          onRequestClose={handleCloseQRCodeModal}
          receiveValue={receiveValue}
        />,
      );
      triggerReceiveByGenericQrCodeClicked(chainSymbol);
    } else {
      // log if user somehow attempts to view address with no wallet present. Should never happen
      reportComponentError({
        error: new Error(
          `Attempt to open ReceiveAddressModal with no wallet present for ${chainSymbol}`,
        ),
        isHandled: false,
        severity: 'error',
      });
    }
  }, [
    wallet,
    startOpenReceiveQrModalPerfMark,
    openModal,
    chainSymbol,
    handleCloseQRCodeModal,
    receiveValue,
  ]);

  const imageSource = useMemo(() => ({ uri: blockchainImageURL }), [blockchainImageURL]);

  const handlePressCopy = useCallback(() => {
    triggerReceiveByGenericCopyAddressClicked(chainSymbol);
  }, [chainSymbol]);

  const handleAddressItemPress = useCallback(
    function handleAddressItemPress() {
      copyToClipboard(wallet?.primaryAddress);
      triggerReceiveByGenericAddressItemClicked(chainSymbol);
      if (onPressSideEffect) {
        setTimeout(() => {
          onPressSideEffect();
        }, TimeSpanDelay.SHORT);
      }
    },
    [chainSymbol, copyToClipboard, onPressSideEffect, wallet?.primaryAddress],
  );

  return (
    <Pressable
      background="transparent"
      testID={`receive-address-list-item-pressable-${chainSymbol}-v2`}
      accessible={false}
      onPress={handleAddressItemPress}
    >
      <HStack width="100%" spacingVertical={1}>
        <HStack
          alignItems="center"
          justifyContent="space-between"
          spacingHorizontal={2}
          spacingVertical={2}
          borderRadius="rounded"
          bordered
          borderColor="secondary"
          width="100%"
          gap={1}
        >
          <HStack alignItems="center" gap={4} flexGrow={1} flexShrink={1}>
            {!!blockchainImageURL && (
              <RemoteImage
                source={imageSource}
                height={32}
                width={32}
                shape="circle"
                resizeMode="cover"
                testID={`${blockchainImageURL}`}
              />
            )}
            <VStack maxWidth="70%">
              <TextHeadline testID={`wallet-address-headline-${chainSymbol}`}>
                {headlineMessage}
              </TextHeadline>
              <TextLabel2
                color="foregroundMuted"
                testID={`wallet-address-string-${chainSymbol}`}
                numberOfLines={1}
              >
                {wallet
                  ? abridgeAddress(wallet.primaryAddress)
                  : formatMessage(messages.scanningAddresses)}
              </TextLabel2>
              {!!supportedChainIcons?.length && wallet && (
                <HStack gap={0.5} testID="wallet-address-chain-icons" spacingTop={1}>
                  {supportedChainIcons}
                </HStack>
              )}
            </VStack>
          </HStack>
          <HStack gap={1}>
            <IconButton
              name="qrCode"
              onPress={onPressQRCode}
              testID={`wallet-address-qr-code-button-${chainSymbol}`}
              disabled={!wallet}
              accessible
              accessibilityLabel={qrCodeAccessibilityLabel}
            />
            <CopyButton
              value={wallet?.primaryAddress}
              testID={`wallet-address-copy-button-${chainSymbol}`}
              type="icon"
              onTransitionDelay={onPressSideEffect}
              disabled={!wallet}
              onPress={handlePressCopy}
              accessible
              accessibilityLabel={copyAddressAccessibilityLabel}
            />
          </HStack>
        </HStack>
      </HStack>
    </Pressable>
  );
}

import { memo, useCallback } from 'react';
import {
  logUSDTReceiveCellPressed,
  useLogUSDTReceiveCellViewed,
} from 'cb-wallet-analytics/receive';
import { abridgeAddress } from 'cb-wallet-data/utils/abridgeAddress';
import { Icon } from '@cbhq/cds-mobile/icons';
import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';
import { TextHeadline, TextLabel2 } from '@cbhq/cds-mobile/typography';

import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { ReceiveAddressListCellVariant } from '../types';

import { useReceiveAddressTronCellVariant } from './useReceiveAddressTronCellVariant';

export type ReceiveAddressListTronCellProps = {
  onPressSideEffect?: () => void;
  variant: ReceiveAddressListCellVariant;
};

export const ReceiveAddressListTronCell = memo(function ReceiveAddressListTronCell({
  variant,
  onPressSideEffect,
}: ReceiveAddressListTronCellProps) {
  const { navigate } = useStackNavigation();

  useLogUSDTReceiveCellViewed();

  const handleNavigation = useCallback(() => {
    logUSDTReceiveCellPressed();

    navigate('Receive', { screen: 'ReceiveTronUSDTScreen' });
  }, [navigate]);

  const handlePress = useCallback(() => {
    onPressSideEffect?.();

    // We need to wait 500ms here to avoid crashing the app while trying to show a modal
    // and navigate to another screen at the same time
    if (onPressSideEffect) {
      setTimeout(() => {
        handleNavigation();
      }, 500);
    } else {
      handleNavigation();
    }
  }, [handleNavigation, onPressSideEffect]);

  const { media, label, walletAddress, bottom, gap } = useReceiveAddressTronCellVariant({
    variant,
  });

  return (
    <Pressable
      onPress={handlePress}
      background="transparent"
      testID={`receive-address-list-item-pressable-tron-${variant}`}
    >
      <HStack width="100%" spacingVertical={1}>
        <HStack
          gap={1}
          bordered
          spacing={2}
          width="100%"
          alignItems="center"
          borderRadius="rounded"
          borderColor="secondary"
          justifyContent="space-between"
        >
          <HStack alignItems="center" gap={gap} flexGrow={1} flexShrink={1}>
            {media}

            <VStack maxWidth="70%">
              <TextHeadline testID="receive-address-list-item-headline">{label}</TextHeadline>

              {walletAddress ? (
                <TextLabel2
                  numberOfLines={1}
                  color="foregroundMuted"
                  testID="wallet-address-string-tron"
                >
                  {abridgeAddress(walletAddress)}
                </TextLabel2>
              ) : null}

              {bottom}
            </VStack>
          </HStack>
          <Icon
            testID="receive-address-list-item-icon"
            size="s"
            name="caretRight"
            color="foregroundMuted"
          />
        </HStack>
      </HStack>
    </Pressable>
  );
});

import { useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
