const messages = defineMessages({
  genericOnrampHeadline: {
    defaultMessage: 'Buy crypto',
    description: 'Headline for generic onramp',
  },
  receiveFromCoinbaseConnectedHeadline: {
    defaultMessage: 'Receive from Coinbase',
    description: 'Headline for receive from Coinbase when connected',
  },
  receiveFromCoinbaseUnconnectedDescription: {
    defaultMessage:
      'Coinbase is a separate service that lets you buy crypto. Connect or sign up for an account now',
    description: 'Description for Connect to Coinbase when unconnected',
  },
  createCoinbaseAccountDescription: {
    defaultMessage: 'Coinbase is a separate service that lets you buy crypto.',
    description: 'Create a coinbase account description',
  },
  connectToCoinbase: {
    defaultMessage: 'Connect to Coinbase',
    description: 'Button text for Connect to Coinbase when unconnected',
  },
});

type ReceiveOtherAssetsCardProps = {
  isQuickCopyUI?: boolean;
  onPress?: (callback?: () => void) => void;
};

export function ReceiveOnrampCard({ isQuickCopyUI = false, onPress }: ReceiveOtherAssetsCardProps) {
  const { formatMessage } = useIntl();

  const { isConnected } = useIsConnectedToCoinbase();
  const { email, isLoading: isEmailLoading } = useUserEmail();
  const onrampEligibility = useOnrampEligibility();
  const isCbPayEligible = useIsCBPayProviderCountry();

  const launchBuyFlow = useLaunchBuyFlow();
  const connectToCoinbase = useConnectToCoinbase();

  const handlePress = useCallback(() => {
    if (isCbPayEligible && !isConnected) {
      connectToCoinbase();
    } else {
      triggerReceiveOnrampCardClicked(isCbPayEligible);
      launchBuyFlow();
    }
  }, [launchBuyFlow, connectToCoinbase, isCbPayEligible, isConnected]);

  const handleOnPress = useCallback(() => {
    if (isQuickCopyUI) {
      // The function performing navigation is passed as a callback to onPress because it needs to be invoked
      // after the quick copy Tray is dismissed, otherwise the Tray doesn't dismiss correctly, breaking the
      // ReceiveOtherAssets UI.
      onPress?.(handlePress);
    } else {
      handlePress();
      onPress?.();
    }
  }, [isQuickCopyUI, handlePress, onPress]);

  const { viewBox, path } = useLogoMark({ foreground: false });

  const nonCBPayCard = useMemo(() => {
    return (
      <LegacyCard spacing={2} justifyContent="center">
        <HStack justifyContent="space-between" gap={2} alignItems="center">
          <VStack style={longDescriptionStyle}>
            <TextHeadline testID="non-cb-pay-card-title">
              {formatMessage(messages.genericOnrampHeadline)}
            </TextHeadline>
          </VStack>
          <Icon size="s" name="caretRight" color="foregroundMuted" />
        </HStack>
      </LegacyCard>
    );
  }, [formatMessage]);

  const cbPayLoggedInCard = useMemo(() => {
    return (
      <LegacyCard spacing={2} justifyContent="center">
        <HStack gap={4} alignItems="center">
          <Svg viewBox={viewBox} width={26} height={26}>
            <Path d={path} fill={blue} />
          </Svg>
          <VStack flexGrow={1} maxWidth="75%" spacingStart={0.5}>
            <TextHeadline testID="cb-pay-logged-in-title">
              {formatMessage(messages.receiveFromCoinbaseConnectedHeadline)}
            </TextHeadline>
            {isEmailLoading ? (
              <Fallback height={24} width="100%" />
            ) : (
              <TextHeadline color="foregroundMuted" testID="cb-pay-logged-in-email">
                {email}
              </TextHeadline>
            )}
          </VStack>
          <VStack alignItems="flex-end">
            <Icon size="s" name="caretRight" color="foregroundMuted" />
          </VStack>
        </HStack>
      </LegacyCard>
    );
  }, [email, formatMessage, isEmailLoading, path, viewBox]);

  const cbPayUpsellCard = useMemo(() => {
    return (
      <Box
        borderRadius="rounded"
        bordered
        borderColor="line"
        background="backgroundAlternate"
        spacing={2}
        justifyContent="center"
      >
        <Box flexDirection="row" justifyContent="flex-start" alignItems="center">
          <Box spacingEnd={3}>
            <Svg viewBox={viewBox} width={40} height={40}>
              <Path d={path} fill={blue} />
            </Svg>
          </Box>
          <Box style={longDescriptionStyle} spacingEnd={3}>
            <TextHeadline testID="cb-pay-upsell-card-title">
              {formatMessage(messages.connectToCoinbase)}
            </TextHeadline>
            <TextBody spacingTop={0.5} color="foregroundMuted" testID="cb-pay-upsell-card-body">
              {formatMessage(messages.createCoinbaseAccountDescription)}
            </TextBody>
            <Box flexDirection="row" alignItems="center" spacingTop={1}>
              <TextHeadline color="primary" testID="cb-pay-upsell-card-headline">
                {formatMessage(messages.connectToCoinbase)}
              </TextHeadline>
              <Icon name="forwardArrow" size="xs" spacingStart={1} />
            </Box>
          </Box>
        </Box>
      </Box>
    );
  }, [formatMessage, path, viewBox]);

  const cbPayCard = useMemo(() => {
    return isConnected ? cbPayLoggedInCard : cbPayUpsellCard;
  }, [cbPayLoggedInCard, cbPayUpsellCard, isConnected]);

  // If the user is not eligible for onramp, return null
  if (!onrampEligibility?.isSupported) {
    return null;
  }

  return (
    <Box spacingVertical={1} testID={`receive-onramp-card${isQuickCopyUI ? `-quickCopyUI` : ''}`}>
      <Pressable onPress={handleOnPress} background="background" testID="onramp-card-pressable">
        {isCbPayEligible ? cbPayCard : nonCBPayCard}
      </Pressable>
    </Box>
  );
}

