const messages = defineMessages({
  otherAssetsHeadline: {
    defaultMessage: 'Other assets',
    description: 'Headline for other assets',
  },
});

type ReceiveOtherAssetsCardProps = {
  isQuickCopyUI?: boolean;
  onPress?: (callback?: () => void) => void;
  minHeight?: number;
};

export function ReceiveOtherAssetsCard({
  isQuickCopyUI = false,
  onPress,
  minHeight,
}: ReceiveOtherAssetsCardProps) {
  const { otherWalletConfigs } = useReceiveGroupedWalletConfigs(isQuickCopyUI);
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();

  const [startNavigateToReceiveOtherAssetsPerfMark] = usePerfMark(
    PERF_MARKS.receive,
    RECEIVE_MARKS.navigate_to_receive_other_assets,
  );

  const handleOnPress = useCallback(
    function handleOnPress() {
      startNavigateToReceiveOtherAssetsPerfMark();

      if (isQuickCopyUI) {
        // The function performing navigation is passed as a callback to onPress because it needs to be invoked
        // after the quick copy Tray is dismissed, otherwise the Tray doesn't dismiss correctly, breaking the
        // ReceiveOtherAssets UI.
        onPress?.(() =>
          navigate('Receive', { screen: 'ReceiveOtherAssets', params: { isQuickCopyUI } }),
        );
      } else {
        navigate('ReceiveOtherAssets');
        onPress?.();
      }
    },
    [isQuickCopyUI, navigate, onPress, startNavigateToReceiveOtherAssetsPerfMark],
  );

  if (!otherWalletConfigs.length) return null;
  return (
    <Box spacingVertical={1} testID={`other-assets-card${isQuickCopyUI ? `-quickCopyUI` : ''}`}>
      <Pressable onPress={handleOnPress} background="background">
        <LegacyCard
          spacingHorizontal={2}
          spacingVertical={2}
          justifyContent="center"
          minHeight={minHeight}
          borderColor={isQuickCopyUI ? 'transparent' : undefined}
        >
          <HStack justifyContent="space-between" gap={2} alignItems="center">
            <HStack gap={2}>
              {!isQuickCopyUI && (
                <HStack gap={0.5} spacingTop={0.5} testID="wallet-address-chain-icons">
                  {otherWalletConfigs.map((c) => {
                    // eslint-disable-next-line react-perf/jsx-no-new-object-as-prop
                    const source = { uri: c.imageURL?.toString() || '' };
                    return (
                      <RemoteImage
                        key={c.blockchain.rawValue}
                        source={source}
                        resizeMode="contain"
                        shape="circle"
                        width={20}
                        height={20}
                        testID={`image-${source.uri}`}
                      />
                    );
                  })}
                </HStack>
              )}
              <TextHeadline testID="wallet-address-headline" spacingStart={0.5}>
                {formatMessage(messages.otherAssetsHeadline)}
              </TextHeadline>
            </HStack>
            <Icon size="s" name="caretRight" color="foregroundMuted" />
          </HStack>
        </LegacyCard>
      </Pressable>
    </Box>
  );
}

