import { memo, ReactNode, useCallback, useEffect, useState } from 'react';
import { Animated } from 'react-native';
import Swipeable from 'react-native-gesture-handler/Swipeable';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { Haptics } from '@cbhq/react-native-haptics';

const THRESHOLD = 70;

type DeleteAnimationProps = {
  progress: Animated.AnimatedInterpolation<number | string>;
  dragX: Animated.AnimatedInterpolation<number | string>;
  rowWidth: number;
  onAction: () => void;
};

const DeleteAnimation = memo(function DeleteAnimation({
  progress,
  rowWidth,
  onAction,
}: DeleteAnimationProps) {
  const [buttonSize, setButtonSize] = useState<'s' | 'm'>('s');

  useEffect(
    function swiperProgress() {
      const id = progress.addListener(({ value = 0 }) => {
        const pixelDistanceSwiped = rowWidth * value;
        if (pixelDistanceSwiped === THRESHOLD) {
          Haptics.lightImpact();
        }
        if (pixelDistanceSwiped > THRESHOLD) {
          setButtonSize('m');
          return;
        }
        setButtonSize('s');
      });
      return () => progress.removeListener(id);
    },
    [progress, rowWidth],
  );

  return (
    <HStack
      animated
      flexGrow={1}
      background="negative"
      justifyContent="flex-end"
      alignItems="center"
      height="100%"
    >
      <Pressable onPress={onAction} background="transparent">
        <Icon spacingHorizontal={3} color="negativeForeground" name="trashCan" size={buttonSize} />
      </Pressable>
    </HStack>
  );
});

function renderRightActions(
  progress: Animated.AnimatedInterpolation<number | string>,
  dragX: Animated.AnimatedInterpolation<number | string>,
  rowWidth: number,
  onAction: () => void,
) {
  return (
    <DeleteAnimation progress={progress} dragX={dragX} onAction={onAction} rowWidth={rowWidth} />
  );
}

type SwipeToDeleteProps = { children: ReactNode; rowWidth: number; onAction: () => void };

export const SwipeToDelete = memo(function SwipeToDelete({
  children,
  rowWidth,
  onAction,
}: SwipeToDeleteProps) {
  const actions = useCallback(
    (
      progress: Animated.AnimatedInterpolation<number | string>,
      dragX: Animated.AnimatedInterpolation<number | string>,
    ) => renderRightActions(progress, dragX, rowWidth, onAction),
    [onAction, rowWidth],
  );

  return (
    <Swipeable
      friction={2}
      renderRightActions={actions}
      onSwipeableOpen={onAction}
      rightThreshold={THRESHOLD}
      useNativeAnimations
    >
      <Box background="background">{children}</Box>
    </Swipeable>
  );
});

import { useCallback, useEffect, useMemo, useState } from 'react';
import {
  triggerSpeedUpCancelButtonClicked,
  triggerSpeedUpCancelUnsignedTxGas,
  useSpeedUpCancelScreenViewed,
} from 'cb-wallet-analytics/transactions';
import { TxMetadataKey_analyticsId } from 'cb-wallet-data/chains/AccountBased/Ethereum/config';
import { EthereumUnsigned1559Tx } from 'cb-wallet-data/chains/AccountBased/Ethereum/models/EthereumUnsigned1559Tx';
import {
  isTransactionFee1559Info,
  isTransactionFeeUTXOInfo,
  TransactionFee1559Info,
} from 'cb-wallet-data/chains/AccountBased/Ethereum/Transactions/types';
import { useFormattedSpeedUpAndCancelTransaction } from 'cb-wallet-data/chains/AccountBased/Ethereum/Transactions/useFormattedSpeedUpAndCancelTransaction';
import { useSpeedUpAndCancelFees } from 'cb-wallet-data/chains/AccountBased/Ethereum/Transactions/useSpeedUpAndCancelFees';
import {
