  TextHeadline,
  TextLabel2,
  TextLegal,
  TextTitle3,
} from '@cbhq/cds-mobile/typography';

import { Fallback } from ':rn/cds-wallet/components/Fallbacks/Fallback';
import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { useHandleUnlockForSigning } from ':rn/shared/components/SignTransaction/hooks/useHandleUnlockForSigning';

import { Button } from '../interactables/Button';

import { TransactionsActionsTrayAdjustableGas } from './TransactionsActionsTrayAdjustableGas';

type TransactionsActionsTrayContentProps = {
  transaction: Transaction;
  isSpeedUp: boolean;
  wallet: Wallet;
  handleError: (error: Error) => void;
  handleSuccess: () => void;
  handleClose: () => void;
};

/**
 * Tray that is displayed when tapping `speed up` or `cancel` buttons from the transaction detail page of a pending
 * transaction
 */
export function TransactionsActionsTrayContent({
  transaction,
  isSpeedUp,
  wallet,
  handleSuccess,
  handleError,
  handleClose,
}: TransactionsActionsTrayContentProps) {
  const isMounted = useIsMounted();

  const [unsignedTxResult, setUnsignedTxResult] = useState<UnsignedTxResult<UnsignedTx>>();
  const [customGasVisible, { toggleOn: showCustomGas, toggleOff: hideCustomGas }] =
    useToggler(false);

  const defaultNetworkFeeInfo = useSpeedUpAndCancelFees(transaction, wallet);

  const [customNetworkFeeInfo, setCustomNetworkFeeInfo] = useState<TransactionFee1559Info>();

  const handleUnlock = useHandleUnlockForSigning();

  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useTxFeeWallet(activeWalletGroupId, transaction);
  const isUTXOTransaction = isUTXOBasedBlockchain(wallet.blockchain.rawValue);

  useSpeedUpCancelScreenViewed(isSpeedUp ? 'speedup' : 'cancel', wallet.blockchain.rawValue);
  const analyticsFeeData = useAnalyticsFeeData(unsignedTxResult?.transaction, wallet);

  if (!feeWallet) {
    throw new Error('No fee wallet in SpeedUpCancelStep');
  }
  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx: unsignedTxResult?.transaction,
    feeWallet,
    flow: 'speedUpCancel',
  });

  const generateUnsignedTxWithCleanup = useCallback(
    async function generateUnsignedTxWithCleanup() {
      const generateTx = async () => {
        // do not generate an unsigned transaction if we don't have any fee data
        // it would generate an invalid transaction - and may create race conditions against our valid transactions
        if (!unsignedTxResult && (defaultNetworkFeeInfo || customNetworkFeeInfo)) {
          const result = await generateUnsignedSpeedUpCancelTx({
            txSubmissionType: isSpeedUp ? 'speedUp' : 'cancel',
            originalTransaction: transaction,
            wallet,
            networkFeeInfo: customNetworkFeeInfo ?? defaultNetworkFeeInfo,
          });
          if (isMounted.current) {
            // Prevent state updates if tray is dismissed
            setUnsignedTxResult(result);
          }
        }
      };
      generateTx();
      return () => {
        setUnsignedTxResult(undefined);
      };
    },
    [
      isMounted,
      isSpeedUp,
      customNetworkFeeInfo,
      defaultNetworkFeeInfo,
      transaction,
      unsignedTxResult,
      wallet,
    ],
  );

  useEffect(() => {
    generateUnsignedTxWithCleanup();
  }, [defaultNetworkFeeInfo, generateUnsignedTxWithCleanup]);

  useEffect(
    function sendFeeAnalytics() {
      if (unsignedTxResult?.transaction) {
        const {
          gasLimit,
          chainId,
          feeCurrencyCode,
          minFeeInUSD,
          maxFeeInUSD,
          maxFeeInCrypto,
          minFeeInCrypto,
        } = analyticsFeeData as FeeAnalytics1559;
        const analyticsId = transaction.metadata.get(TxMetadataKey_analyticsId)?.toString();
        triggerSpeedUpCancelUnsignedTxGas(isSpeedUp ? 'speedup' : 'cancel', {
          gasLimit,
          analyticsId,
          chainId,
          feeCurrencyCode,
          minFeeInUSD,
          maxFeeInUSD,
          maxFeeInCrypto,
          minFeeInCrypto,
          blockchain: wallet.blockchain.rawValue,
        });
      }
    },
    [
      isSpeedUp,
      unsignedTxResult?.transaction,
      analyticsFeeData,
      transaction.metadata,
      wallet.blockchain.rawValue,
    ],
  );

  const { signAndSubmitStandalone, isSignAndSubmitStandaloneLoading } =
    useSpeedUpAndCancelTransaction({
      txSubmissionType: isSpeedUp ? 'speedUp' : 'cancel',
      originalTransaction: transaction,
      wallet,
      handleUnlock: handleUnlock(wallet.accountId),
      handleSuccess,
      handleError,
      unsignedTxResult,
    });

  const { title, header, body, networkFeeLabel, tooltip, buttonLabel, cancelLabel, feeFiatRange } =
    useFormattedSpeedUpAndCancelTransaction({
      txSubmissionType: isSpeedUp ? 'speedUp' : 'cancel',
      originalTransaction: transaction,
      wallet,
      // don't show defaultNetworkFeeInfo here - wait until a valid tx is generated
      networkFeeInfo: customNetworkFeeInfo,
      unsignedTxResult,
    });

  const handleCustomGasOnSubmit = useCallback(
    async function handleCustomGasOnSubmit(customFee: AdjustableGasOnSubmitParams) {
      // Set the network fees based on the custom gas input
      const updatedCustomNetworkFeeInfo = {
        gasLimit: customFee.selectedGasLimit,
        maxFee: customFee.selectedMaxFeePerGas,
        maxPriorityFee: customFee.selectedMaxPriorityFeePerGas,
        baseFee: customFee.selectedBaseFeePerGas,
      };
      setCustomNetworkFeeInfo(updatedCustomNetworkFeeInfo);
      setUnsignedTxResult(undefined);
      // Generate a new unsigned tx with custom fees
      await generateUnsignedTxWithCleanup();
      hideCustomGas();
    },
    [generateUnsignedTxWithCleanup, hideCustomGas],
  );

  const handleCTAPressed = useCallback(
    function handleCTAPressed() {
      triggerSpeedUpCancelButtonClicked(
        isSpeedUp ? 'speedup' : 'cancel',
        wallet.blockchain.rawValue,
      );
      signAndSubmitStandalone();
    },
    [isSpeedUp, signAndSubmitStandalone, wallet.blockchain.rawValue],
  );

  const startingGasValues = useMemo(() => {
    if (customNetworkFeeInfo) {
      return {
        selectedBaseFeePerGas: customNetworkFeeInfo.baseFee,
        selectedMaxFeePerGas: customNetworkFeeInfo.maxFee,
        selectedMaxPriorityFeePerGas: customNetworkFeeInfo.maxPriorityFee,
        selectedGasLimit: customNetworkFeeInfo.gasLimit,
      };
    }
    if (defaultNetworkFeeInfo) {
      if (isTransactionFeeUTXOInfo(defaultNetworkFeeInfo)) {
        // adjustable gas is not enabled for utxo transactions
        return undefined;
      }
      if (isTransactionFee1559Info(defaultNetworkFeeInfo)) {
        return {
          selectedBaseFeePerGas: defaultNetworkFeeInfo.baseFee,
          selectedMaxFeePerGas: defaultNetworkFeeInfo.maxFee,
          selectedMaxPriorityFeePerGas: defaultNetworkFeeInfo.maxPriorityFee,
          selectedGasLimit: defaultNetworkFeeInfo.gasLimit,
        };
      }
    }
    return undefined;
  }, [customNetworkFeeInfo, defaultNetworkFeeInfo]);

  return customGasVisible && unsignedTxResult?.transaction ? (
    <TransactionsActionsTrayAdjustableGas
      transaction={unsignedTxResult.transaction as EthereumUnsigned1559Tx}
      network={wallet.network}
      blockchain={wallet.blockchain}
      handleOnSubmit={handleCustomGasOnSubmit}
      onGoBack={hideCustomGas}
      actionType={isSpeedUp ? 'speedup' : 'cancel'}
      startingGasValues={startingGasValues}
    />
  ) : (
    <VStack spacingHorizontal={3}>
      <Box alignItems="center" spacingBottom={1}>
        <TextHeadline>{title}</TextHeadline>
      </Box>
      <VStack spacing={3} bordered borderRadius="rounded" elevation={1}>
        {isSpeedUp ? (
          <Icon testID="speedUpHeaderIcon" name="lightningBolt" size="l" bordered />
        ) : (
          <Icon testID="cancelHeaderIcon" name="close" size="l" color="negative" bordered />
        )}
        <TextLabel2 spacingTop={1}>{header}</TextLabel2>
        <TextTitle3 testID="txn_to_address">{transaction.entityDisplayName(true)}</TextTitle3>
      </VStack>

      <HStack justifyContent="space-between" spacingTop={3}>
        <HStack gap={1} alignItems="center">
          <TextBody>{networkFeeLabel}</TextBody>
          <Tooltip content={tooltip} placement="bottom">
            <Icon name="info" size="xs" color="foregroundMuted" />
          </Tooltip>
        </HStack>

        <HStack alignItems="center">
          <TextBody testID="txn_fee_range" color="foregroundMuted">
            {feeFiatRange ?? <Fallback width={100} height={20} />}
          </TextBody>
          {!isUTXOTransaction && (
            <PressableOpacity onPress={showCustomGas}>
              <Icon name="gear" size="s" color="foreground" spacingStart={1} />
            </PressableOpacity>
          )}
        </HStack>
      </HStack>
      <TextBody spacingVertical={2}>{body}</TextBody>
      {transactionDetailsErrors && (
        <VStack spacingBottom={1}>
          <TextLegal spacingBottom={3} testID="transaction_detail_error_message">
            {transactionDetailsErrors.message}
          </TextLegal>
        </VStack>
      )}
      <ButtonGroup accessibilityLabel="Pending transaction actions" block>
        <Button variant="secondary" onPress={handleClose}>
          {cancelLabel}
        </Button>
        <Button
          testID="transactions-actions-tray-cta"
          variant={isSpeedUp ? 'primary' : 'negative'}
          onPress={handleCTAPressed}
          disabled={isSignAndSubmitStandaloneLoading || transactionDetailsErrors?.isDisabled}
          loading={!unsignedTxResult || isSignAndSubmitStandaloneLoading}
        >
          {buttonLabel}
        </Button>
      </ButtonGroup>
    </VStack>
  );
}

type TransactionsActionsTrayProps = {
  transaction: Transaction;
  isSpeedUp: boolean;
  onCloseComplete: () => void;
  wallet: Wallet;
  handleError: (error: Error) => void;
  handleSuccess: () => void;
};

export function TransactionsActionsTray({
  transaction,
  isSpeedUp,
  wallet,
  handleSuccess,
  handleError,
  onCloseComplete,
}: TransactionsActionsTrayProps) {
  return (
    <Tray onCloseComplete={onCloseComplete} testID="transactions-actions-tray">
      {({ handleClose }) => {
        return (
          <PortalProvider>
            <TransactionsActionsTrayContent
              transaction={transaction}
              isSpeedUp={isSpeedUp}
              wallet={wallet}
              handleSuccess={handleSuccess}
              handleError={handleError}
              handleClose={handleClose}
            />
          </PortalProvider>
        );
      }}
    </Tray>
  );
}

import { useMemo } from 'react';
import { ButtonPropsType } from 'cb-wallet-data/hooks/Swap/useTransactionDetailButtons/useTransactionDetailButtons';
import { TransactionDetailsError } from 'cb-wallet-data/hooks/transactionDetailsErrorTypes';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { ButtonGroup, ButtonProps } from '@cbhq/cds-mobile/buttons';
import { VStack } from '@cbhq/cds-mobile/layout';

import { Button } from '../interactables/Button';

type Props = {
  vertical?: boolean;
  error?: TransactionDetailsError;
  buttonProps?: ButtonPropsType[];
  onPrimaryButtonDisabled?: (error: { errorType: string }) => void;
};

export function TransactionDetailButtonGroup({
  vertical,
  error,
  buttonProps,
  onPrimaryButtonDisabled,
}: Props) {
  const confirmButton = useMemo(() => {
    return buttonProps?.find((buttonProp) => {
      return buttonProp.name === 'confirmButton';
    });
  }, [buttonProps]);

  useOnMount(function triggerAnalyticsForPrimaryButtonDisabled() {
    if (confirmButton?.disabled) {
      onPrimaryButtonDisabled?.({
        errorType: error?.type ?? '',
      });
    }
  });

  if (!buttonProps || buttonProps.length === 0) return null;

  return (
    <VStack spacingTop={0} spacingHorizontal={3}>
      <ButtonGroup
        accessibilityLabel="Group"
        block
        direction={vertical ? 'vertical' : 'horizontal'}
      >
        {buttonProps.map(({ children, ...rest }) => {
          return (
            <Button {...(rest as ButtonProps)} key={rest.name}>
              {children}
            </Button>
          );
        })}
      </ButtonGroup>
    </VStack>
  );
}

import { useCallback, useMemo, useState } from 'react';
import { logConfirmationErrorBannerViewed } from 'cb-wallet-analytics/swap';
import { TransactionDetailErrorEventData } from 'cb-wallet-data/hooks/transactionDetailsErrorTypes';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack, Spacer } from '@cbhq/cds-mobile/layout';
import { Link, TextLabel2 } from '@cbhq/cds-mobile/typography';

export type Props = {
  type: string;
  isDismissible?: boolean;
  showErrorIcon?: boolean;
  message: string;
  learnMore?: {
    label: string;
    url: string;
  };
  analytics?: TransactionDetailErrorEventData;
  shouldIgnoreNotEnoughBalanceForMinerFee?: boolean;
};

export function TransactionDetailError({
  type,
  isDismissible,
  showErrorIcon,
  message,
  learnMore,
  shouldIgnoreNotEnoughBalanceForMinerFee,
}: Props) {
  const [isErrorVisible, setIsErrorVisible] = useState(true);
  const onDismissError = useCallback(() => {
    setIsErrorVisible(false);
  }, []);

  useOnMount(() =>
    logConfirmationErrorBannerViewed({
      type,
      message,
    }),
  );

  const description = useMemo(() => {
    if (learnMore) {
      return (
        <TextLabel2>
          {message}{' '}
          <Link variant="label2" to={learnMore.url}>
            {learnMore.label}
          </Link>
        </TextLabel2>
      );
    }

    return <TextLabel2>{message}</TextLabel2>;
  }, [learnMore, message]);

  // Don't show error if it's not dismissible or if it's a notEnoughBalanceForMinerFee error
  if (
    !isErrorVisible ||
    (type === 'notEnoughBalanceForMinerFee' && shouldIgnoreNotEnoughBalanceForMinerFee)
  )
    return null;

  return (
    <HStack
      borderedTop
      alignItems="center"
      justifyContent="center"
      spacingVertical={2}
      width="100%"
    >
      <HStack alignItems="center" spacingStart={3} spacingEnd={isDismissible ? 1 : 3} width="100%">
        {showErrorIcon && <Icon name="warning" size="s" color="negative" />}
        <Box spacingHorizontal={2}>{description}</Box>
        {isDismissible && (
          <>
            <Spacer />
            <IconButton
              transparent
              name="close"
              variant="foregroundMuted"
              onPress={onDismissError}
            />
          </>
        )}
      </HStack>
    </HStack>
  );
}

