import { useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { TouchableWithoutFeedback } from 'react-native-gesture-handler';
import { TransactionDetailRowItem } from 'cb-wallet-data/hooks/Swap/useTransactionDetailRowItems/useTransactionDetailRowItems';
import { abridgeAddress } from 'cb-wallet-data/utils/abridgeAddress';
import { PaletteForeground } from '@cbhq/cds-common';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Divider } from '@cbhq/cds-mobile/layout/Divider';
import { Link, TextBody, TextCaption, TextLegal, TextTitle3 } from '@cbhq/cds-mobile/typography';

import { Fallback } from ':rn/cds-wallet/components/Fallbacks/Fallback';
import { OutlineBox } from ':rn/cds-wallet/components/OutlineBox/OutlineBox';

import { TextWithIcon } from '../icons/TextWithIcon';
import { TooltipIcon } from '../icons/TootltipIcon';

type Props = TransactionDetailRowItem;

const warningTooltipIconProps = { color: 'negative' as PaletteForeground };

const messages = defineMessages({
  coinbaseFeeLabel: {
    defaultMessage: 'Coinbase fee',
    description: 'Label for coinbase fee row in tooltip',
  },
  networkFeeLabel: {
    defaultMessage: 'Network fee (est.)',
    description: 'Label for network fee row in tooltip',
  },
  extraFeeLabel: {
    defaultMessage: 'Account creation fee',
    description: 'Label for transaction detail row displaying the account creation fee',
  },
  coinbaseFeeDiscountPercentage: {
    defaultMessage: '{discountPercentage}% off',
    description: 'Label for transaction detail row displaying the account creation fee',
  },
  contractAddressAccessibilityLabel: {
    defaultMessage: 'Open contract link in the browser',
    description: 'Contract address link accessibility label',
  },
});

export function TxDetailRow({
  label,
  labelPreFormatted,
  subLabel,
  subLabelIcon,
  detailText,
  detailTextPreFormatted,
  onDetailTextPress,
  subDetailText,
  detailTextLabel,
  tooltipLabel,
  tooltipText,
  tooltipObject,
  tooltipAccessibilityLabel,
  warningTooltipLabel,
  warningTooltipText,
  actionIcon,
  testID,
  withWarning = false,
  detailTextColor = 'foregroundMuted',
  tooltipDetailTitle,
  tooltipDetailText,
  outlineDetailText,
  loadingLabelNode,
  loadingDetailTextNode,
  keyLabel,
  detailTextComponent,
}: Props) {
  const { formatMessage } = useIntl();
  const textDetail = useMemo(() => {
    if (detailTextComponent) return detailTextComponent;

    const detailTextString = typeof detailText === 'string' ? detailText : undefined;
    const detailTextContractAddress = typeof detailText !== 'string' ? detailText : undefined;

    if (detailTextString || detailTextPreFormatted) {
      return (
        <HStack gap={1} alignItems="center" justifyContent="center">
          {detailTextLabel ? (
            <Box
              spacingHorizontal={1}
              borderRadius="rounded"
              background="positive"
              width={75}
              justifyContent="center"
              alignItems="center"
            >
              <TextCaption align="center" color="primaryForeground">
                {formatMessage(messages.coinbaseFeeDiscountPercentage, {
                  discountPercentage: detailTextLabel,
                })}
              </TextCaption>
            </Box>
          ) : null}

          <TouchableWithoutFeedback onPress={onDetailTextPress} testID={`${testID}-pressable`}>
            <TextBody align="end" color={detailTextColor}>
              {detailTextPreFormatted || detailTextString}
            </TextBody>
          </TouchableWithoutFeedback>
        </HStack>
      );
    }

    if (loadingDetailTextNode) {
      return (
        <HStack alignItems="center">
          <Fallback width={100} height={25} testID={`${testID}-detail-loader`} />
        </HStack>
      );
    }

    return detailTextContractAddress ? (
      <HStack alignItems="center">
        <TextBody spacingEnd={1} data-testid={`${testID}-details`} color="foregroundMuted">
          {abridgeAddress(detailTextContractAddress.text)}
        </TextBody>

        <Link
          to={detailTextContractAddress.blockExplorerUrl}
          accessibilityLabel={formatMessage(messages.contractAddressAccessibilityLabel)}
          testID="tx-detail-row-contract-address-link"
        >
          <Icon name="externalLink" color="foreground" size="s" />
        </Link>
      </HStack>
    ) : null;
  }, [
    detailTextComponent,
    detailText,
    detailTextPreFormatted,
    loadingDetailTextNode,
    testID,
    formatMessage,
    detailTextLabel,
    onDetailTextPress,
    detailTextColor,
  ]);

  const tooltipContent = useMemo(() => {
    if (tooltipObject?.rowType === 'estimatedFees') {
      const { message, networkFeeRange, extraFee } = tooltipObject;
      return (
        <VStack>
          <TextTitle3 spacingBottom={2}>{message}</TextTitle3>
          <Divider color="lineHeavy" opacity={0.66} />
          <VStack spacingTop={2}>
            {extraFee ? (
              <HStack justifyContent="space-between">
                <TextBody color="foregroundMuted">{formatMessage(messages.extraFeeLabel)}</TextBody>
                <TextBody color="foregroundMuted">{extraFee}</TextBody>
              </HStack>
            ) : null}
            <HStack justifyContent="space-between">
              <TextBody color="foregroundMuted">{formatMessage(messages.networkFeeLabel)}</TextBody>
              <TextBody color="foregroundMuted">{networkFeeRange}</TextBody>
            </HStack>
          </VStack>
        </VStack>
      );
    }
  }, [formatMessage, tooltipObject]);

  return (
    <VStack key={keyLabel || label} spacingVertical={1} position="relative" width="100%">
      <HStack justifyContent="space-between" alignItems="flex-start" gap={2}>
        <HStack justifyContent="flex-start" alignItems="center" flexShrink={5}>
          {Boolean(loadingLabelNode) && (
            <HStack alignItems="center">
              <Fallback width={120} height={25} testID={`${testID}-label-loader`} />
            </HStack>
          )}
          <TextBody color="foreground">{labelPreFormatted}</TextBody>
          <TextBody color="foreground">{label}</TextBody>

          {tooltipText && (
            <TooltipIcon
              description={tooltipText}
              title={tooltipLabel ?? label}
              iconName="info"
              testID={`${testID}-tooltip-icon`}
              accessibilityLabel={tooltipAccessibilityLabel}
            />
          )}
          {tooltipContent ? (
            <TooltipIcon
              content={tooltipContent}
              iconName="info"
              testID={`${testID}-tooltip-icon`}
            />
          ) : null}
          {warningTooltipLabel && warningTooltipText && (
            <TooltipIcon
              description={warningTooltipText}
              title={warningTooltipLabel}
              iconName="warning"
              iconProps={warningTooltipIconProps}
              testID={`${testID}-warning-tooltip-icon`}
            />
          )}
        </HStack>
        <HStack justifyContent="flex-end" alignItems="center" gap={0.5} flexShrink={1}>
          {Boolean(tooltipDetailText) && (
            <TooltipIcon
              iconSize="s"
              textDetail={textDetail}
              testID={`${testID}-tooltipDetail`}
              title={tooltipDetailTitle}
              description={tooltipDetailText}
              iconProps={warningTooltipIconProps}
              iconName={withWarning ? 'warning' : undefined}
            />
          )}
          {Boolean(withWarning) && Boolean(outlineDetailText) && (
            <TextWithIcon
              textDetail={textDetail}
              iconColor="negative"
              iconSize="s"
              iconName="warning"
            />
          )}
          {!outlineDetailText && !tooltipDetailText ? textDetail : null}
          {actionIcon}
        </HStack>
      </HStack>
      {Boolean(outlineDetailText) && (
        <HStack spacingTop={1} position="relative">
          <OutlineBox>
            <TextBody color="negative" spacingVertical={1} spacingHorizontal={1}>
              {outlineDetailText}
            </TextBody>
          </OutlineBox>
        </HStack>
      )}
      {Boolean(subLabel || !!subDetailText) && (
        <HStack justifyContent="space-between" alignItems="center">
          <HStack justifyContent="flex-start" alignItems="center">
            {subLabelIcon ?? null}
            {typeof subLabel === 'string' ? (
              <TextLegal testID={testID} color="foregroundMuted">
                {subLabel}
              </TextLegal>
            ) : (
              subLabel
            )}
          </HStack>
          <HStack justifyContent="flex-end" alignItems="center">
            {typeof subDetailText === 'string' ? (
              <>
                <TextLegal testID={`${testID}-details`} align="end" color="foregroundMuted">
                  {subDetailText}
                </TextLegal>
                {actionIcon}
              </>
            ) : (
              subDetailText
            )}
          </HStack>
        </HStack>
      )}
    </VStack>
  );
}

import { memo, ReactNode } from 'react';
