export type TransactionStatusProps = {
  buttonProps: ButtonProps[];
} & ContentProps;

type ContentProps = SuccessProps | FailureProps;

type SuccessProps = {
  status: 'success';
  title: string;
  amount?: string;
  timeMessage?: string;
  disclaimer?: string;
  description?: string;
  descriptionIcon?: ReactNode;
  descriptionColor?: PaletteForeground;
  successAnalytics?: () => void;
  card?: ReactNode;
  tray?: ReactNode;
};

type FailureProps = {
  status: 'failure';
  title: string;
  amount?: undefined;
  subtitle: string | ReactNode;
  network?: undefined;
  failureAnalytics?: () => void;
};

const testID = 'transaction-status';

export function TransactionStatusScreenContent({ buttonProps, ...props }: TransactionStatusProps) {
  const isSuccessState = props.status !== 'failure';

  return (
    <VStack justifyContent="space-between" height="100%" spacing={3}>
      {isSuccessState ? <SuccessContent {...props} /> : <FailureContent {...props} />}
      <VStack spacingBottom={5} gap={1}>
        {isSuccessState && props.disclaimer ? (
          <TextLabel2 align="center" color="foregroundMuted">
            {props.disclaimer}
          </TextLabel2>
        ) : null}
        {isSuccessState && props.card ? props.card : null}
        <ButtonGroup accessibilityLabel="Group" direction="vertical">
          {buttonProps.map((buttonProp) => {
            return <Button {...buttonProp} />;
          })}
        </ButtonGroup>
      </VStack>
    </VStack>
  );
}

function SuccessContent({
  status,
  title,
  amount,
  timeMessage,
  description,
  descriptionIcon,
  descriptionColor,
  successAnalytics,
  card,
  tray,
}: SuccessProps) {
  successAnalytics?.();

  return (
    <VStack testID={`${testID}-success`} alignItems="center" spacingTop={card ? 0 : 8} gap={1}>
      <LottieStatusAnimation height={160} status={status} />
      <TextTitle3 align="center" testID={`${testID}-success-title`}>
        {title}
      </TextTitle3>
      {amount ? (
        <TextTitle1 align="center" color="primary" testID={`${testID}-success-amount`}>
          {amount}
        </TextTitle1>
      ) : null}
      {timeMessage ? (
        <HStack alignItems="center" gap={1}>
          <Icon name="clockOutline" size="s" color="foreground" />
          <TextBody color="foreground">{timeMessage}</TextBody>
        </HStack>
      ) : null}
      {description ? (
        <HStack gap={1}>
          {descriptionIcon}
          <TextBody align="center" color={descriptionColor}>
            {description}
          </TextBody>
        </HStack>
      ) : null}
      {tray || null}
    </VStack>
  );
}

function FailureContent({ title, subtitle, status, failureAnalytics }: FailureProps) {
  failureAnalytics?.();
  return (
    <VStack testID={`${testID}-failure`} alignItems="center" spacingTop={8}>
      <LottieStatusAnimation height={160} status={status} />
      <TextTitle3 testID={`${testID}-failure-title`}>{title}</TextTitle3>
      <Spacer vertical={2} />
      <TextBody testID={`${testID}-failure-subtitle`} align="center" color="foregroundMuted">
        {subtitle}
      </TextBody>
    </VStack>
  );
}

const TransactionStatusScreenWithBoundary = memo(function TransactionStatusScreenWithBoundary(
  props: TransactionStatusProps,
) {
  return (
    <ScreenBoundary>
      <Screen full>
        <TransactionStatusScreenContent {...props} />
      </Screen>
    </ScreenBoundary>
  );
});
export { TransactionStatusScreenWithBoundary as TransactionStatusScreen };

import {
  forwardRef,
  memo,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useState,
} from 'react';
import {
  Animated,
  BackHandler,
  LayoutChangeEvent,
  NativeEventSubscription,
  StyleSheet,
  View,
  ViewProps,
} from 'react-native';
import { TouchableWithoutFeedback } from 'react-native-gesture-handler';
import { useSpectrum } from '@cbhq/cds-common';
import { drawerAnimationDefaultDuration } from '@cbhq/cds-common/animation/drawer';
import { useSpectrumConditional } from '@cbhq/cds-common/hooks/useSpectrumConditional';
import { handleBarHeight, handleBarOffset } from '@cbhq/cds-common/tokens/drawer';
import type { DrawerRefBaseProps, TrayBaseProps } from '@cbhq/cds-common/types';
import { usePalette } from '@cbhq/cds-mobile/hooks/usePalette';
import { useSpacingScale } from '@cbhq/cds-mobile/hooks/useSpacingScale';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Overlay, useOverlayAnimation } from '@cbhq/cds-mobile/overlays';
import { useDrawerAnimation } from '@cbhq/cds-mobile/overlays/Drawer/useDrawerAnimation';
import { useDrawerPanResponder } from '@cbhq/cds-mobile/overlays/Drawer/useDrawerPanResponder';
import { TextTitle3 } from '@cbhq/cds-mobile/typography';

import { device } from ':rn/shared/config/device';
import { useDimensions } from ':rn/shared/hooks/useDimensions';

/**
 * CDS trays/modals cannot coexist in the screen at the same level
 * This is a blocker for GlobalSignTransaction component. If we
 * show the sign transaction component in a tray, no other tray or modal
 * in the screen will be able to show up (e.g gas fees tray).
 *
 * It gets even worse for users that are using numeric passcode, given
 * the passcode screen is presented as a modal
 *
 * This component is meant to emulate a tray experience without calling the native drawer
 * Because it doesn't use it, consumers are able to show custom trays/modals on top of it, without the risk
 * of freezing the app on iOS
 *
 * This is not a generic purpose tray. It should only be used through GlobalTrayProvider. Calling it standalone
 * will not work as expected (it may not overlay other components)
 */
export const VirtualTrayComponent = memo(
  forwardRef<DrawerRefBaseProps, TrayBaseProps>(function VirtualTray(
    {
      testID,
      children,
      disableCapturePanGestureToDismiss,
      verticalDrawerPercentageOfView,
      preventDismissGestures,
      hideHandleBar,
      title,
      onCloseComplete,
      onBlur,
      onVisibilityChange,
    },
    ref,
  ) {
    /**
     * height of the children component, updated by children onLayout event (if used)
     */
    const [childrenContainerHeight, setChildrenContainerHeight] = useState<number | undefined>();
    const { screenHeight, bottom } = useDimensions();
    const [isVisible, setVisible] = useState(true);

    const scheme = useSpectrum();

    const trayDefaultHeight = screenHeight * 0.7;

    /**
     * Final position for the tray when visible
     */
    const trayHeight = useMemo(() => {
      const contentHeight = (childrenContainerHeight ?? trayDefaultHeight) + 20;
      if (verticalDrawerPercentageOfView) {
        const maxHeight = screenHeight * verticalDrawerPercentageOfView;
        return Math.min(contentHeight, maxHeight);
      }
      return contentHeight;
    }, [childrenContainerHeight, screenHeight, trayDefaultHeight, verticalDrawerPercentageOfView]);

    const isChildrenFunction = children instanceof Function;

    const isTrayReadyToOpen = useMemo(() => {
      /**
       * children can be a function that returns a ReactNode when we need
       * to calculate the children container height. In those cases, we need
       * to use the first render cycle to calculate the height and then show the tray
       */
      if (isChildrenFunction) {
        return childrenContainerHeight !== undefined;
      }

      return true;
    }, [childrenContainerHeight, isChildrenFunction]);

    const { drawerAnimation, drawerAnimationStyles, animateDrawerIn, animateDrawerOut } =
      useDrawerAnimation('bottom');

    const [opacityAnimation, animateOverlayIn, animateOverlayOut] = useOverlayAnimation(
      drawerAnimationDefaultDuration,
    );

    const openTray = useCallback(
      function openTray() {
        Animated.parallel([animateOverlayIn, animateDrawerIn]).start();
      },
      [animateDrawerIn, animateOverlayIn],
    );

    const closeTrayAnimation = useCallback(() => {
      Animated.parallel([animateDrawerOut, animateOverlayOut]).start(onCloseComplete);
    }, [animateDrawerOut, animateOverlayOut, onCloseComplete]);

    const closeTray = useCallback(() => {
      setVisible(false);
    }, []);

    const dismissTray = useCallback(() => {
      if (!preventDismissGestures) {
        onBlur?.();
        closeTray();
      }
    }, [closeTray, onBlur, preventDismissGestures]);

    const handleSwipeToClose = useCallback(() => {
      dismissTray();
    }, [dismissTray]);

    const panResponder = useDrawerPanResponder({
      pin: 'bottom',
      drawerAnimation,
      opacityAnimation,
      animateDrawerIn,
      handleSwipeToClose,
      disableCapturePanGestureToDismiss: false,
      verticalDrawerPercentageOfView: 0.9,
    });

    const onLayout = useCallback(
      (e: LayoutChangeEvent) => {
        /**
         * onLayout callback is triggered many times with different heights.
         * There is a small noise when calculating the component height
         * We just need the first measurement
         */
        if (
          !childrenContainerHeight ||
          e.nativeEvent.layout.height - childrenContainerHeight > 50
        ) {
          setChildrenContainerHeight(e.nativeEvent.layout.height);
        }
      },
      [childrenContainerHeight],
    );

    const bottomSafeInsets = useMemo(
      () => ({
        paddingBottom: bottom + (device.isAndroid ? 45 : 30),
      }),
      [bottom],
    );

    const panHandlers = useMemo(
      () =>
        !(disableCapturePanGestureToDismiss || preventDismissGestures)
          ? panResponder.panHandlers
          : {},
      [disableCapturePanGestureToDismiss, panResponder.panHandlers, preventDismissGestures],
    );

    const handleHardwareBackButtonPress = useCallback(() => {
      closeTray();

      // it needs to return true in order to prevent hardware back button default behavior
      return true;
    }, [closeTray]);

    useEffect(
      function updateTrayVisibility() {
        if (isVisible) {
          if (isTrayReadyToOpen) {
            onVisibilityChange?.('visible');
            openTray();
          }
        } else {
          onVisibilityChange?.('hidden');
          closeTrayAnimation();
        }
      },
      [
        closeTray,
        openTray,
        isTrayReadyToOpen,
        isVisible,
        childrenContainerHeight,
        closeTrayAnimation,
        onVisibilityChange,
      ],
    );

    // needed to prevent hardware back button from triggering navigation while the tray is visible
    useEffect(
      function interceptHardwareBackButton() {
        let backHandler: NativeEventSubscription | undefined;
        if (isVisible) {
          backHandler = BackHandler.addEventListener(
            'hardwareBackPress',
            handleHardwareBackButtonPress,
          );
        }

        return () => backHandler?.remove();
      },
      [handleHardwareBackButtonPress, isVisible],
    );

    useImperativeHandle(
      ref,
      () => ({
        handleClose: closeTray,
      }),
      [closeTray],
    );

    return (
      <VStack
        position="absolute"
        top={0}
        justifyContent="flex-end"
        left={0}
        bottom={0}
        right={0}
        testID={testID}
      >
        <TouchableWithoutFeedback
          onPress={dismissTray}
          style={styles.touchableWFContainer}
          containerStyle={styles.touchableWFContent}
        >
          <Overlay opacity={opacityAnimation} testID="virtual-tray-overlay" />
        </TouchableWithoutFeedback>
        <Box
          {...panHandlers}
          animated
          style={drawerAnimationStyles}
          onAccessibilityEscape={closeTray}
          pin="bottom"
          overflow="hidden"
        >
          {!hideHandleBar && (
            <HandleBar accessibilityRole="button" onAccessibilityTap={closeTray} />
          )}
          <Box
            bordered={scheme === 'dark'}
            background="background"
            borderRadius="roundedLarge"
            elevation={scheme === 'dark' ? 2 : 0}
          >
            <VStack flexGrow={1} style={bottomSafeInsets}>
              <VStack height={trayHeight} alignItems="center" justifyContent="center">
                <Box onLayout={onLayout} width="100%">
                  {title ? (
                    <HStack
                      spacingHorizontal={3}
                      spacingTop={2}
                      spacingBottom={1}
                      alignItems="center"
                    >
                      <TextTitle3>{title}</TextTitle3>
                    </HStack>
                  ) : null}

                  {children instanceof Function ? children({ handleClose: closeTray }) : children}
                </Box>
              </VStack>
            </VStack>
          </Box>
        </Box>
      </VStack>
    );
  }),
);

function HandleBar(props: ViewProps) {
  const colors = usePalette();
  const handleBarBackgroundColor = useSpectrumConditional({
    dark: colors.backgroundOverlay,
    light: colors.backgroundAlternate,
  });
  const spacing = useSpacingScale();

  const handleBarStyles = useMemo(
    () => [
      styles.handleBar,
      {
        backgroundColor: handleBarBackgroundColor,
        marginBottom: spacing[2],
      },
    ],
    [handleBarBackgroundColor, spacing],
  );

  return (
    <View accessible style={styles.touchableArea} testID="virtual-tray-handle-bar" {...props}>
      <View style={handleBarStyles} />
    </View>
  );
}

