type MessagePaymentItemProps = {
  isSameAddress: boolean;
  item: ConversationMessageListItem;
  sponsoredTxHash: string | undefined;
  sponsoredTxId: string | undefined;
};

function MessagePaymentItemContent({
  isSameAddress,
  item,
  sponsoredTxHash,
  sponsoredTxId,
}: MessagePaymentItemProps) {
  const content = item.content as MessagingPaymentActivityContent;
  const { navigate } = useStackNavigation<SuperAppModeStackParamList>();
  const date = new Date(item.sent);
  const [loadingTransaction, setLoadingTransaction] = useState(true);
  const transaction = useGetMessagingTransaction({
    transactionHash: sponsoredTxHash || content.transactionHash,
    fromAddress: content.fromAddress,
    loadingTransaction,
    setLoading: setLoadingTransaction,
    sponsoredTxId,
  });

  const isHRTEnabled = useIsFeatureEnabled('human_readable_transactions_ui');

  const handleMessagePress = useCallback(() => {
    if (transaction) {
      if (isHRTEnabled) {
        navigate('HRTransactionDetail', {
          transactionId: transaction.id,
          from: 'Messaging',
        });
      } else {
        navigate('TransactionDetail', {
          transactionId: transaction.id,
          from: 'Messaging',
        });
      }
    }
  }, [transaction, isHRTEnabled, navigate]);

  const { formatMessage } = useIntl();
  const spectrum = useSpectrum();
  const palette = usePalette();
  const { boxBackground, borderRadii } = useMessageStyles({
    item,
    isSameAddress,
  });

  const paymentSentStyle = useMemo(() => {
    if (spectrum === 'light') {
      return isSameAddress ? palette.backgroundAlternate : palette.foregroundMuted;
    }
    return palette.foreground;
  }, [spectrum, isSameAddress, palette]);

  const renderTransactionOrError = useCallback(
    function renderTransactionOrError() {
      if (loadingTransaction) {
        logEvent('messaging.payment_item.loading', {
          componentType: ComponentType.card,
          action: ActionType.render,
          transactionHash: content.transactionHash,
          sponsoredTransactionHash: sponsoredTxHash,
        });
        if (content.network?.rawValue) {
          // sponsored transaction recieved in a loading state, render network and fallback
          const network = Network.create(content.network.rawValue);
          let currencyCode;
          if (content.currencyCode) {
            currencyCode = new CurrencyCode(content.currencyCode?.code);
          } else {
            currencyCode = CurrencyCode.USD;
          }
          return (
            <Box spacing={1} testID="message-list-item-detailed-spinner">
              <HStack>
                <MessagePaymentTransactionIcon
                  network={network}
                  currencyCode={currencyCode}
                  isSameAddress={isSameAddress}
                />
                <Box spacingStart={2} alignContent="center" justifyContent="center">
                  <Fallback height={12} width={42} spacingBottom={0.5} shape="rectangle" />
                  <Fallback height={12} width={52} shape="rectangle" />
                </Box>
              </HStack>
            </Box>
          );
        }
      } else {
        <Box spacing={1}>
          <Spinner testID="message-list-item-spinner" color={paymentSentStyle} />
        </Box>;
      }
      if (!loadingTransaction && !transaction) {
        return <TextLabel1 color="negative">{formatMessage(messages.txError)}</TextLabel1>;
      }
      if (transaction) {
        logEvent('messaging.payment_item.loaded', {
          componentType: ComponentType.card,
          action: ActionType.render,
          transactionHash: content.transactionHash,
          sponsoredTransactionHash: sponsoredTxHash,
        });
        return (
          <MessagePaymentItemTransaction transaction={transaction} isSameAddress={isSameAddress} />
        );
      }
    },
    [
      loadingTransaction,
      transaction,
      formatMessage,
      isSameAddress,
      paymentSentStyle,
      content.transactionHash,
      sponsoredTxHash,
      content.network?.rawValue,
      content.currencyCode,
    ],
  );

  const sentTextStyle = useMemo(() => {
    return { marginBottom: -4 };
  }, []);

  const handleErrorPress = useCallback(() => {
    handleMessagePress?.();
  }, [handleMessagePress]);

  function renderMessageStatusOrDate() {
    if (!transaction || transaction?.state === TxState.PENDING) {
      return (
        <TextLegal
          color="foregroundMuted"
          spacingTop={0.5}
          spacingBottom={1}
          testID="tx-pending-text"
        >
          {formatMessage(messages.txPending)}
        </TextLegal>
      );
    }
    if (transaction?.state === TxState.FAILED) {
      return (
        <TextLegal color="negative" spacingTop={0.5} spacingBottom={1} testID="tx-failed-text">
          {formatMessage(messages.txFailed)}
        </TextLegal>
      );
    }
    if (item.hasTimestamp || !!item.error) {
      return (
        <MessageStatus
          date={date}
          isError={!!item.error}
          isSameAddress={isSameAddress}
          itemId={item.id}
          handleErrorPress={handleErrorPress}
        />
      );
    }
  }

  return (
    <Pressable onPress={handleMessagePress}>
      <MessageContainer hasBorderRadius={item.hasBorderRadius} isSameAddress={isSameAddress}>
        <Box
          alignItems={isSameAddress ? 'flex-end' : 'flex-start'}
          testID="message-list-item-container"
        >
          <HStack gap={1} alignItems="center">
            <Box
              background={isSameAddress ? 'primary' : 'secondary'}
              dangerouslySetBackground={boxBackground}
              borderRadius="rounded"
              style={borderRadii}
              maxWidth="80%"
              spacing={1}
              spacingHorizontal={2}
            >
              <Box>
                <TextLabel2 dangerouslySetColor={paymentSentStyle} style={sentTextStyle}>
                  {formatMessage(messages.sent)}
                </TextLabel2>
                {renderTransactionOrError()}
              </Box>
            </Box>
            {transaction?.state === TxState.FAILED && (
              <AutoHitSlopWrapper>
                <PressableOpacity onPress={handleErrorPress}>
                  <Pictogram name="strongWarning" scaleMultiplier={0.5} />
                </PressableOpacity>
              </AutoHitSlopWrapper>
            )}
          </HStack>
        </Box>
        {renderMessageStatusOrDate()}
      </MessageContainer>
    </Pressable>
  );
}

export const MessagePaymentItem = memo(function MessagePaymentItem({
  isSameAddress,
  item,
  sponsoredTxHash,
  sponsoredTxId,
}: MessagePaymentItemProps) {
  return (
    <ErrorBoundary errorFallback={null}>
      <MessagePaymentItemContent
        sponsoredTxHash={sponsoredTxHash}
        item={item}
        isSameAddress={isSameAddress}
        sponsoredTxId={sponsoredTxId}
      />
    </ErrorBoundary>
  );
});

import { forwardRef, memo, ReactNode, useCallback, useImperativeHandle, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useToggler } from '@cbhq/cds-common';
import { Icon, IconProps } from '@cbhq/cds-mobile/icons/Icon';
import { Box, BoxProps, HStack } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import { useTypographyStyles } from '@cbhq/cds-mobile/typography';

import { AutoHitSlopWrapper } from ':rn/cds-wallet/components/interactables/AutoHitSlopWrapper';

import { TooltipTray, TooltipTrayProps } from '../TooltipTray/TooltipTray';

const messages = defineMessages({
  tooltipButtonText: {
    defaultMessage: 'Got it',
    description: 'Button text for the dismiss toolip button',
  },
});

type TooltipIconProps = {
  title?: string;
  description?: string;
  content?: ReactNode;
  iconName?: IconProps['name'];
  iconSize?: IconProps['size'];
  iconProps?: Omit<IconProps, 'name' | 'size'>;
  boxProps?: BoxProps;
  accessibilityLabel?: string;
  testID?: string;
  textDetail?: ReactNode;
};

export type TooltipIconRef = {
  openTooltip: () => void;
};

export const TooltipIcon = memo(
  forwardRef<TooltipIconRef, TooltipIconProps>(function TooltipIcon(
    {
      iconName,
      iconSize = 'xs',
      iconProps = defaultIconProps,
      boxProps = defaultBoxProps,
      accessibilityLabel,
      title,
      description,
      testID,
      content,
      textDetail,
    },
    ref,
  ) {
    useImperativeHandle(ref, () => ({
      openTooltip: handleTooltipPress,
    }));

    const { lineHeight } = useTypographyStyles('body', false);
    const { formatMessage } = useIntl();
    const [tooltipVisible, { toggleOn: showTooltip, toggleOff: hideTooltip }] = useToggler(false);
    const [tooltipTrayProps, setTooltipTrayProps] = useState<TooltipTrayProps>({
      title: '',
      description: '',
      visible: tooltipVisible,
      toggleOff: hideTooltip,
      content,
      buttonText: formatMessage(messages.tooltipButtonText),
    });

    const handleTooltipPress = useCallback(
      function handleTooltipPress() {
        showTooltip();
        setTooltipTrayProps({
          ...tooltipTrayProps,
          title,
          description,
        });
      },
      [description, showTooltip, title, tooltipTrayProps],
    );

    return (
      <>
        <AutoHitSlopWrapper>
          <PressableOpacity onPress={handleTooltipPress}>
            <HStack spacingHorizontal={0} justifyContent="flex-end">
              {Boolean(textDetail) && <Box spacingHorizontal={1}>{textDetail}</Box>}
              {iconName ? (
                <Box
                  alignItems="flex-end"
                  justifyContent="flex-end"
                  spacingHorizontal={0}
                  {...boxProps}
                  height={lineHeight}
                  width={20}
                  accessibilityLabel={accessibilityLabel}
                >
                  <Icon name={iconName} size={iconSize} {...iconProps} testID={testID} />
                </Box>
              ) : null}
            </HStack>
          </PressableOpacity>
        </AutoHitSlopWrapper>
        <TooltipTray {...tooltipTrayProps} visible={tooltipVisible} />
      </>
    );
  }),
);

const defaultIconProps: Omit<IconProps, 'name' | 'size'> = {
  color: 'foreground',
};

const defaultBoxProps: BoxProps = {
  alignItems: 'center',
  justifyContent: 'center',
};

import { View } from 'react-native';
import { fireEvent, render, screen } from '@testing-library/react-native';
import { mockConsoleLog, restoreConsoleLog } from 'cb-wallet-data/test/console';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextTitle1 } from '@cbhq/cds-mobile/typography';

import { AutoHitSlopWrapper } from './AutoHitSlopWrapper';

describe('AutoHitSlopWrapper', () => {
  it('should add correct hitslop to small target', async () => {
    render(
      <AutoHitSlopWrapper testID="hitslop-wrapper">
        <Pressable testID="touch-target" background="line">
          <View />
        </Pressable>
      </AutoHitSlopWrapper>,
    );

    const view = screen.getByTestId('hitslop-wrapper');
    fireEvent(view, 'layout', {
      nativeEvent: {
        layout: {
          width: 10,
          height: 30,
        },
      },
    });

    const appliedHitSlop = (await screen.findByTestId('touch-target')).props.hitSlop;
    expect(appliedHitSlop).toStrictEqual({ bottom: 10, top: 10, left: 20, right: 20 });
  });
  it('should not add hitslop to large target', async () => {
    render(
      <AutoHitSlopWrapper testID="hitslop-wrapper">
        <Pressable testID="touch-target" background="line">
          <View />
        </Pressable>
      </AutoHitSlopWrapper>,
    );

    const view = screen.getByTestId('hitslop-wrapper');
    fireEvent(view, 'layout', {
      nativeEvent: {
        layout: {
          width: 55,
          height: 55,
        },
      },
    });

    const appliedHitSlop = (await screen.findByTestId('touch-target')).props.hitSlop;
    expect(appliedHitSlop).toStrictEqual({ bottom: 0, top: 0, left: 0, right: 0 });
  });
  it('should add hitslop to short target', async () => {
    render(
      <AutoHitSlopWrapper testID="hitslop-wrapper">
        <Pressable testID="touch-target" background="line">
          <View />
        </Pressable>
      </AutoHitSlopWrapper>,
    );

    const view = screen.getByTestId('hitslop-wrapper');
    fireEvent(view, 'layout', {
      nativeEvent: {
        layout: {
          width: 50,
          height: 20,
        },
      },
    });

    const appliedHitSlop = (await screen.findByTestId('touch-target')).props.hitSlop;
    expect(appliedHitSlop).toStrictEqual({ bottom: 15, top: 15, left: 0, right: 0 });
  });
  it('should add hitslop to narrow target', async () => {
    render(
      <AutoHitSlopWrapper testID="hitslop-wrapper">
        <Pressable testID="touch-target" background="line">
          <View />
        </Pressable>
      </AutoHitSlopWrapper>,
    );

    const view = screen.getByTestId('hitslop-wrapper');
    fireEvent(view, 'layout', {
      nativeEvent: {
        layout: {
          width: 30,
          height: 350,
        },
      },
    });

    const appliedHitSlop = (await screen.findByTestId('touch-target')).props.hitSlop;
    expect(appliedHitSlop).toStrictEqual({ bottom: 0, top: 0, left: 10, right: 10 });
  });

  describe('rendering more than one child', () => {
    beforeEach(mockConsoleLog);

    afterEach(restoreConsoleLog);

    it('should throw an error', () => {
      expect(() => {
        render(
          // @ts-expect-error TS(2746): This JSX tag's 'children' prop expects a single ch... Remove this comment to see the full error message
          <AutoHitSlopWrapper testID="hitslop-wrapper">
            <Pressable testID="touch-target" background="line">
              <View />
            </Pressable>
            <Pressable testID="touch-target-2" background="line">
              <View />
            </Pressable>
          </AutoHitSlopWrapper>,
        );
      }).toThrow();
    });
  });

  it('passes accessibility audit', async () => {
    const { root } = render(
      <AutoHitSlopWrapper testID="hitslop-wrapper">
        <Pressable testID="touch-target" background="line">
          <TextTitle1>Item</TextTitle1>
        </Pressable>
      </AutoHitSlopWrapper>,
    );

    expect(root).toBeAccessible();
  });
});

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Animated, Easing, LayoutChangeEvent, Pressable, View } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { TimeSpanDelay } from 'cb-wallet-data/utils/styleConstants';
import { durations } from '@cbhq/cds-common/motion/tokens';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { TextLabel1 } from '@cbhq/cds-mobile/typography';

import { Button } from '../Button';

import { useClipboard } from './useClipboard';

const messages = defineMessages({
  label: {
    defaultMessage: 'Copy',
    description: 'label for the "copy to clipboard" control',
  },
  copiedLabel: {
    defaultMessage: 'Copied',
    description: 'Copy button text after is has been pressed',
  },
  copiedLabelVerbose: {
    defaultMessage: 'Copied to clipboard',
    description: 'Copy button text after is has been pressed on verbose mode',
  },
  copiedLabelWithTimeout: {
    defaultMessage: 'Copied for 1 minute',
    description: 'Copy button text after is has been pressed on verbose mode',
  },
  verboseTitle: {
    defaultMessage: 'Copy to clipboard',
    description: 'label for the "copy to clipboard" control',
  },
});

type ButtonPropsSubset = Omit<React.ComponentProps<typeof IconButton>, 'children' | 'name'>;

type CopyButtonProps = ButtonPropsSubset & {
  value?: string;
  type?:
    | 'basic'
    | 'block'
    | 'verbose'
    | 'icon'
    | 'referral'
    | 'referralSecondary'
    | 'smallPressIcon';
  buttonTransitionDelay?: number;
  toastBottomOffset?: number;
  buttonText?: string;
  onPress?: () => void;
  onTransitionDelay?: () => void;
  disabled?: boolean;
  clearAfterTimeout?: boolean;
  clipboardLabel?: string;
  labelOverride?: string;
  testID?: string;
  compact?: boolean;
  confirmationToast?: string;
};

export function CopyButton({
  value,
  type = 'basic',
  buttonTransitionDelay = TimeSpanDelay.SHORT,
  toastBottomOffset,
  onPress,
  onTransitionDelay,
  buttonText: buttonTextFromProps,
  disabled = false,
  clearAfterTimeout,
  clipboardLabel,
  labelOverride,
  testID,
  compact,
  loading = false,
  confirmationToast,
  ...otherIconButtonProps
}: CopyButtonProps) {
  const { formatMessage } = useIntl();
  const { copyToClipboard } = useClipboard();
  const [isPressed, setIsPressed] = useState(false);
  const label = labelOverride ?? formatMessage(messages.label);

  const [copiedButtonWidth, setCopiedButtonWidth] = useState(0);

  const buttonText = useMemo(() => {
    if (buttonTextFromProps) {
      return buttonTextFromProps;
    }

    if (isPressed) {
      if (clearAfterTimeout) {
        return formatMessage(messages.copiedLabelWithTimeout);
      }

      return type === 'verbose'
        ? formatMessage(messages.copiedLabelVerbose)
        : formatMessage(messages.copiedLabel);
    }

    return type === 'verbose' ? formatMessage(messages.verboseTitle) : label;
  }, [buttonTextFromProps, isPressed, type, formatMessage, label, clearAfterTimeout]);

  const primaryVariant = isPressed ? 'positive' : 'primary';
  const secondaryVariant = isPressed ? 'positive' : 'secondary';
  const iconCopied = type === 'verbose' ? 'circleCheckmark' : 'checkmark';
  const iconName = isPressed ? iconCopied : 'copy';
  const iconColor = isPressed ? 'positive' : 'foreground';
  const copyButtonOpacityValue = useRef(new Animated.Value(1)).current;
  const copiedButtonOpacityValue = copyButtonOpacityValue.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 0],
  });

  const mounted = useRef(true);
  useEffect(function detectUnmounted() {
    return () => {
      mounted.current = false;
    };
  }, []);

  const handlePress = useCallback<NonNullable<React.ComponentProps<typeof IconButton>['onPress']>>(
    function handlePress() {
      if (type === 'basic' || type === 'block') {
        Animated.timing(copyButtonOpacityValue, {
          toValue: 0,
          duration: durations.fast3,
          easing: Easing.linear,
          useNativeDriver: false,
        }).start();

        setTimeout(() => {
          Animated.timing(copyButtonOpacityValue, {
            toValue: 1,
            duration: durations.fast3,
            easing: Easing.linear,
            useNativeDriver: false,
          }).start();
        }, buttonTransitionDelay);
      }

      onPress?.();

      setIsPressed(true);

      copyToClipboard(
        value,
        undefined,
        confirmationToast ?? undefined,
        toastBottomOffset,
        clearAfterTimeout,
        clipboardLabel,
      );

      setTimeout(() => {
        onTransitionDelay?.();
        if (mounted.current) setIsPressed(false);
      }, buttonTransitionDelay);
    },
    [
      type,
      onPress,
      copyToClipboard,
      value,
      confirmationToast,
      toastBottomOffset,
      clearAfterTimeout,
      clipboardLabel,
      buttonTransitionDelay,
      copyButtonOpacityValue,
      onTransitionDelay,
    ],
  );

  const commonStyle = useMemo(
    () => ({
      right: 0,
      position: 'absolute' as const,
      opacity: 0,
    }),
    [],
  );

  const copyButtonStyle = useMemo(
    () => ({
      ...commonStyle,
      opacity: copyButtonOpacityValue,
    }),
    [commonStyle, copyButtonOpacityValue],
  );

  const blockButtonStyle = useMemo(
    () => ({
      ...commonStyle,
      opacity: copyButtonOpacityValue,
      width: '100%' as `${number}%`,
    }),
    [commonStyle, copyButtonOpacityValue],
  );

  const copiedButtonStyle = useMemo(
    () => ({
      ...commonStyle,
      opacity: copiedButtonOpacityValue,
    }),
    [commonStyle, copiedButtonOpacityValue],
  );

  const copiedBlockButtonStyle = useMemo(
    () => ({
      ...blockButtonStyle,
      opacity: copiedButtonOpacityValue,
    }),
    [blockButtonStyle, copiedButtonOpacityValue],
  );

  const setCopiedButtonLayoutWidth = useCallback(
    (event: LayoutChangeEvent) => {
      if (!copiedButtonWidth) {
        // store copied button width only if it was 0 earlier i.e. on first layout.
        // We need to animate width of copied button from copyButtonWidth to this value only
        setCopiedButtonWidth(Math.ceil(event.nativeEvent.layout.width));
      }
    },
    [copiedButtonWidth],
  );

  const CopyVerboseButton = useMemo(() => {
    return (
      <Pressable
        onPress={handlePress}
        testID="verbose-copy-btn"
        disabled={disabled}
        accessibilityLabel={buttonText}
        accessibilityRole="button"
      >
        <HStack spacingTop={2} spacingBottom={1} alignItems="center">
          <Icon name={iconName} size="s" color={iconColor} spacingEnd={1} />
          <TextLabel1>{buttonText}</TextLabel1>
        </HStack>
      </Pressable>
    );
  }, [buttonText, disabled, handlePress, iconColor, iconName]);

  const CopyIconButton = useMemo(() => {
    return (
      <IconButton
        {...otherIconButtonProps}
        name={iconName}
        compact
        loading={loading}
        onPress={handlePress}
        testID="icon-copy-btn"
        disabled={disabled}
      />
    );
  }, [disabled, handlePress, iconName, loading, otherIconButtonProps]);

  const CopyReferralButton = useMemo(() => {
    return (
      <Button
        onPress={handlePress}
        variant={primaryVariant}
        testID="primary-copy-btn"
        disabled={disabled}
        endIcon={iconName}
        block
      >
        <TextLabel1>{buttonText}</TextLabel1>
      </Button>
    );
  }, [buttonText, disabled, handlePress, iconName, primaryVariant]);

  const CopyReferralSecondaryButton = useMemo(() => {
    return (
      <Button
        onPress={handlePress}
        variant={secondaryVariant}
        testID="secondary-copy-btn"
        disabled={disabled}
        endIcon={iconName}
        compact={compact}
      >
        <TextLabel1>{buttonText}</TextLabel1>
      </Button>
    );
  }, [buttonText, compact, disabled, handlePress, iconName, secondaryVariant]);

  const CopySmallPressIconButton = useMemo(() => {
    return (
      <Pressable onPress={handlePress} testID="small-icon-copy-btn" disabled={disabled}>
        <Box spacingStart={1}>
          <Icon name={iconName} size="s" color="foreground" testID={`${testID}-copy-button`} />
        </Box>
      </Pressable>
    );
  }, [disabled, handlePress, iconName, testID]);

  const CopyBasicButton = useMemo(() => {
    return (
      <View>
        <Animated.View
          style={copiedButtonWidth > 0 ? copiedButtonStyle : commonStyle}
          onLayout={setCopiedButtonLayoutWidth}
          testID="basic-copied-btn-wrapper"
        >
          <Button variant="positive" compact>
            <TextLabel1>{formatMessage(messages.copiedLabel)}</TextLabel1>
          </Button>
        </Animated.View>
        <Animated.View style={copyButtonStyle}>
          <Button
            compact
            loading={loading}
            variant="secondary"
            disabled={disabled}
            onPress={handlePress}
            testID="basic-copy-btn"
          >
            <TextLabel1>{formatMessage(messages.label)}</TextLabel1>
          </Button>
        </Animated.View>
      </View>
    );
  }, [
    commonStyle,
    copiedButtonStyle,
    copiedButtonWidth,
    copyButtonStyle,
    disabled,
    formatMessage,
    handlePress,
    loading,
    setCopiedButtonLayoutWidth,
  ]);

  const CopyBlockButton = useMemo(() => {
    return (
      <View>
        <Animated.View style={copiedBlockButtonStyle} testID="block-copied-btn-wrapper">
          <Button variant="positive" compact>
            <TextLabel1>{formatMessage(messages.copiedLabel)}</TextLabel1>
          </Button>
        </Animated.View>

        <Animated.View style={blockButtonStyle}>
          <Button
            compact
            loading={loading}
            variant="secondary"
            disabled={disabled}
            onPress={handlePress}
            testID="block-copy-btn"
          >
            <TextLabel1>{buttonText}</TextLabel1>
          </Button>
        </Animated.View>
      </View>
    );
  }, [
    blockButtonStyle,
    buttonText,
    copiedBlockButtonStyle,
    disabled,
    formatMessage,
    handlePress,
    loading,
  ]);

  const typeToButton: Record<typeof type, JSX.Element> = {
    basic: CopyBasicButton,
    block: CopyBlockButton,
    verbose: CopyVerboseButton,
    icon: CopyIconButton,
    referral: CopyReferralButton,
    referralSecondary: CopyReferralSecondaryButton,
    smallPressIcon: CopySmallPressIconButton,
  };

  return typeToButton[type] || CopyBasicButton;
}

import { useCallback, useMemo } from 'react';
import { Pressable, StyleSheet, ViewProps } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { getDecimalSeparator } from 'cb-wallet-data/CurrencyFormatter/utils/amount';
import { SpacingProps } from '@cbhq/cds-common';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { TextTitle2, TextTitle3 } from '@cbhq/cds-mobile/typography';
import { Haptics } from '@cbhq/react-native-haptics';

import { app } from ':rn/shared/config/app';

export type NumPadValue = number | 'EMPTY' | 'BACKSPACE' | 'SEPARATOR';

const messages = defineMessages({
  deleteButtonAccessibilityLabel: {
    defaultMessage: 'Delete',
    description: 'Delete button accessibility label',
  },
  separatorAccessibilityLabel: {
    defaultMessage: 'Separator',
    description: 'Accessibility label for separator when entering a numeric passcode',
  },
});

type NumPadCommonProps = {
  height?: string | number;
  onPress: (value: NumPadValue) => void;
  onLongPress?: (value: NumPadValue) => void;
  disabled?: boolean;
  allowDecimalSeparator?: boolean;
  onLayout?: ViewProps['onLayout'];
  compact?: boolean;
};

export type NumPadItemProps = {
  value: NumPadValue;
} & NumPadCommonProps;

export type NumPadProps = NumPadCommonProps & SpacingProps;

const buttonValues: NumPadValue[][] = [
  [1, 2, 3],
  [4, 5, 6],
  [7, 8, 9],
  ['SEPARATOR', 0, 'BACKSPACE'],
];

const DEFAULT_NUM_PAD_HEIGHT = 230;

export function NumPad({
  onPress,
  onLongPress,
  height = DEFAULT_NUM_PAD_HEIGHT,
  allowDecimalSeparator = false,
  disabled = false,
  compact,
  ...props
}: NumPadProps) {
  const handleOnPress = useCallback(
    function handleOnPress(value: NumPadValue) {
      Haptics.lightImpact();
      onPress(value);
    },
    [onPress],
  );

  const buttons = useMemo(() => {
    return buttonValues.map((values, i) => (
      <HStack
        // eslint-disable-next-line react/no-array-index-key
        key={`num-pad-row-${i}`}
        spacing={0}
        alignItems="stretch"
        justifyContent="space-between"
        flexWrap="nowrap"
      >
        {values.map((value) => (
          <NumPadItem
            key={`num-pad-${value.toString().toLowerCase()}`}
            allowDecimalSeparator={allowDecimalSeparator}
            value={value}
            onPress={handleOnPress}
            onLongPress={onLongPress}
            disabled={disabled}
            compact={compact}
          />
        ))}
      </HStack>
    ));
  }, [allowDecimalSeparator, compact, disabled, handleOnPress, onLongPress]);

  return (
    <VStack
      {...props}
      flexGrow={0}
      flexShrink={0}
      height={height}
      minHeight={height}
      justifyContent="space-between"
    >
      {buttons}
    </VStack>
  );
}

function NumPadItem({
  value,
  compact,
  allowDecimalSeparator,
  onPress,
  onLongPress,
  disabled: disabledFromProps,
}: NumPadItemProps) {
  const { formatMessage } = useIntl();
  const disabled = disabledFromProps || (!allowDecimalSeparator && value === 'SEPARATOR');
  const TextComponent = compact ? TextTitle3 : TextTitle2;

  const accessibilityLabel = useMemo(() => {
    if (value === 'BACKSPACE') {
      return formatMessage(messages.deleteButtonAccessibilityLabel);
    }
    if (value === 'SEPARATOR') {
      return formatMessage(messages.separatorAccessibilityLabel);
    }
    return value.toString();
  }, [value, formatMessage]);

  const icon = useMemo(() => {
    if (value === 'BACKSPACE') {
      return (
        <Box>
          <Icon size="s" name="backArrow" color="foreground" />
        </Box>
      );
    }

    if (value === 'SEPARATOR') {
      return (
        <TextComponent align="center" spacing={0}>
          {allowDecimalSeparator ? getDecimalSeparator(app.locale) : ' '}
        </TextComponent>
      );
    }

    return (
      <TextComponent align="center" spacing={0}>
        {value}
      </TextComponent>
    );
  }, [TextComponent, allowDecimalSeparator, value]);

  const handleOnPress = useCallback(() => {
    onPress(value);
  }, [onPress, value]);

  const handleLongPress = useCallback(() => {
    onLongPress?.(value);
  }, [onLongPress, value]);

  return (
    <Pressable
      accessibilityRole="button"
      accessibilityLabel={accessibilityLabel}
      onPress={handleOnPress}
      onLongPress={handleLongPress}
      style={styles.touchable}
      disabled={disabled}
      testID={`NumPad_${value.toString().toLowerCase()}`}
    >
      {icon}
    </Pressable>
  );
}

