});

import { memo, useCallback, useState } from 'react';
import { NativeSyntheticEvent, Pressable, ScrollView, TextLayoutEventData } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { useToggler } from '@cbhq/cds-mobile';
import { VStack } from '@cbhq/cds-mobile/layout';
import { Box } from '@cbhq/cds-mobile/layout/Box';
import { PortalProvider } from '@cbhq/cds-mobile/overlays/PortalProvider';
import { TextBody, TextLabel1, TextTitle3 } from '@cbhq/cds-mobile/typography';

import { Tray } from ':rn/cds-wallet/components/Tray/Tray';

type TextRevealProps = {
  maxNumberOfLines: number;
  children: string;
  title?: string;
  testID?: string;
};

const messages = defineMessages({
  revealButton: {
    defaultMessage: 'Read more +',
    description: 'label for button that reveals additional text',
  },
  trayTitle: {
    defaultMessage: 'Description',
    description: 'title for tray',
  },
});

// ScrollView with height=0 prevents a flash of long text
// when the line count is computed.
const scrollViewStyle = { height: 0 };

const TextReveal = memo(function TextReveal({
  maxNumberOfLines,
  children,
  title,
  testID,
}: TextRevealProps) {
  const [trayVisible, { toggleOn: showTray, toggleOff: hideTray }] = useToggler(false);
  const { formatMessage } = useIntl();
  const [lines, setLines] = useState(0);

  const onTextLayout = useCallback(({ nativeEvent }: NativeSyntheticEvent<TextLayoutEventData>) => {
    setLines(nativeEvent.lines.length);
  }, []);

  if (lines > maxNumberOfLines) {
    return (
      <>
        <TextBody
          spacingBottom={1}
          numberOfLines={maxNumberOfLines}
          color="foregroundMuted"
          testID={testID}
        >
          {children}
        </TextBody>

        <TextLabel1 onPress={showTray}>{formatMessage(messages.revealButton)}</TextLabel1>

        {trayVisible && (
          <Tray
            onCloseComplete={hideTray}
            disableCapturePanGestureToDismiss
            testID={`${testID}__description_tray`}
          >
            <Box spacingHorizontal={3}>
              <TextTitle3>{title || formatMessage(messages.trayTitle)}</TextTitle3>
            </Box>
            <ScrollView scrollEnabled>
              <Pressable>
                <PortalProvider>
                  <VStack flexGrow={1} spacingTop={2} spacingBottom={10} spacingHorizontal={3}>
                    <TextBody color="foregroundMuted">{children}</TextBody>
                  </VStack>
                </PortalProvider>
              </Pressable>
            </ScrollView>
          </Tray>
        )}
      </>
    );
  }

  if (lines) {
    return (
      <TextBody
        spacingBottom={1}
        onTextLayout={onTextLayout}
        color="foregroundMuted"
        testID={testID}
      >
        {children}
      </TextBody>
    );
  }

  return (
    <ScrollView style={scrollViewStyle} scrollEnabled={false}>
      <TextBody onTextLayout={onTextLayout} testID={testID}>
        {children}
      </TextBody>
    </ScrollView>
  );
});

export { TextReveal };

import { ReactNode, useCallback, useMemo } from 'react';
import { StyleProp, StyleSheet, View, ViewStyle } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { BoxBaseProps } from '@cbhq/cds-common';
