import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextLabel2 } from '@cbhq/cds-mobile/typography';

import { ErrorShakeAnimation } from '../Animations/ErrorShakeAnimation';

const messages = defineMessages({
  first: {
    defaultMessage: 'First',
    description: 'First selected word overlay label',
  },
  last: {
    defaultMessage: 'Last',
    description: 'Last selected word overlay label',
  },
});

export type SelectedMnemonic = {
  word: string;
  index: number;
};

type MnemonicRowProps = {
  firstWord: string;
  secondWord: string;
  firstWordSelected: SelectedMnemonic;
  lastWordSelected: SelectedMnemonic;
  handlePress: (mnemonic: SelectedMnemonic) => void;
  showError: boolean;
  rowIndex: number;
};

type MnemonicWordProps = SelectedMnemonic &
  BoxBaseProps &
  Omit<MnemonicRowProps, 'firstWord' | 'secondWord'>;

type WordContainerProps = {
  rowIndex: number;
  children: ReactNode;
};

type MnemonicTooltipProps = {
  selectedTag: string;
};

function WordContainer({ rowIndex, children }: WordContainerProps) {
  const style = useMemo<StyleProp<ViewStyle>>(
    () => ({
      paddingLeft: rowIndex % 2 === 0 ? 0 : '25%',
      paddingRight: rowIndex % 2 === 0 ? '25%' : 0,
    }),
    [rowIndex],
  );

  return <View style={style}>{children}</View>;
}

function MnemonicTooltip({ selectedTag }: MnemonicTooltipProps) {
  const { background, foreground } = usePalette();

  const style = useMemo(() => [styles.tooltip, { backgroundColor: foreground }], [foreground]);

  return (
    <View style={style}>
      <TextLabel2 dangerouslySetColor={background} noWrap>
        {selectedTag}
      </TextLabel2>
    </View>
  );
}

function MnemonicWord({
  word,
  handlePress,
  firstWordSelected,
  lastWordSelected,
  index,
  rowIndex,
  showError,
}: MnemonicWordProps) {
  const { background } = usePalette();
  const { formatMessage } = useIntl();

  const selected =
    (word === firstWordSelected.word && index === firstWordSelected.index) ||
    (word === lastWordSelected.word && index === lastWordSelected.index);

  const selectedTag = useMemo(() => {
    if (word === firstWordSelected.word && index === firstWordSelected.index) {
      return formatMessage(messages.first);
    }
    if (word === lastWordSelected.word && index === lastWordSelected.index) {
      return formatMessage(messages.last);
    }
  }, [word, index, firstWordSelected, lastWordSelected, formatMessage]);

  const clickWordHandler = useCallback(() => {
    handlePress({ word, index });
  }, [handlePress, index, word]);

  return (
    <WordContainer rowIndex={rowIndex}>
      <ErrorShakeAnimation showError={showError}>
        {selected && selectedTag && <MnemonicTooltip selectedTag={selectedTag} />}
        <Pressable
          onPress={clickWordHandler}
          background={selected ? 'primary' : 'secondary'}
          borderWidth="button"
          borderRadius="roundedSmall"
          borderColor="line"
          style={styles.word}
          testID={`verify-mnemonic-${word}`}
          accessibilityLabel={word}
        >
          <Box spacing={1}>
            <TextLabel2 align="center" dangerouslySetColor={selected ? background : undefined}>
              {word}
            </TextLabel2>
          </Box>
        </Pressable>
      </ErrorShakeAnimation>
    </WordContainer>
  );
}

export function MnemonicRow({ firstWord, secondWord, rowIndex, ...props }: MnemonicRowProps) {
  return (
    <HStack justifyContent="space-around">
      <MnemonicWord
        key={firstWord}
        index={rowIndex * 2}
        rowIndex={rowIndex}
        word={firstWord}
        {...props}
      />
      <MnemonicWord
        key={secondWord}
        index={rowIndex * 2 + 1}
        rowIndex={rowIndex}
        word={secondWord}
        {...props}
      />
    </HStack>
  );
}

