const DEFAULT_INPUT_HEIGHT = 120;

type MnemonicTextDisplayProps = {
  value: string;
  onCopy?: () => void;
  onToggleBlur?: () => void;
  shouldShowCopyButton?: boolean;
  shouldShowBlurButton?: boolean;
};

const messages = defineMessages({
  clipboardLabel: {
    defaultMessage: 'Recovery phrase',
    description: 'Recovery phrase clipboard label',
  },
});

export function MnemonicTextDisplay({
  value,
  onCopy,
  onToggleBlur,
  shouldShowCopyButton = true,
  shouldShowBlurButton = true,
}: MnemonicTextDisplayProps) {
  const { formatMessage } = useIntl();
  const blurImageSrc = useBlurredImageSrc();
  const time = useRef<NodeJS.Timeout | null>(null);
  const [blurred, setBlurred] = useState(true);
  const [style, setStyle] = useState({
    height: DEFAULT_INPUT_HEIGHT,

    ...styles.blurredInput,
  });
  const toggleBlur = useCallback(
    function toggleBlur() {
      onToggleBlur?.();
      triggerSecretBlurText({ isBlur: !blurred, accountType: AccountType.MNEMONIC });
      setBlurred((isBlurred) => !isBlurred);
    },
    [blurred, onToggleBlur],
  );
  const navigation = useNavigation();

  useEffect(
    function autoBlurRecoveryPhrases() {
      if (!blurred) {
        time.current = global.setTimeout(() => {
          triggerSecretBlurText({ isBlur: true, accountType: AccountType.MNEMONIC });
          setBlurred(true);
        }, 30000);
      }
      return () => {
        if (time.current) {
          clearTimeout(time.current);
        }
      };
    },
    [blurred],
  );

  useEffect(
    function blurRecoveryPhraseOnNavigationBlur() {
      const unsubscribe = navigation.addListener('blur', () => {
        setBlurred(true);
      });
      return unsubscribe;
    },
    [blurred, navigation],
  );

  useOnBackground(() => {
    setBlurred(true);
  });

  const [inputHeight, setInputHeight] = useState(DEFAULT_INPUT_HEIGHT);
  const handleLayoutChange = useCallback(({ nativeEvent }: LayoutChangeEvent) => {
    setInputHeight(nativeEvent.layout.height);
    setStyle({
      height: nativeEvent.layout.height,
      ...styles.blurredInput,
    });
  }, []);

  return (
    <>
      <HStack
        testID={`mnemonic-text-display${blurred ? '-blurred' : ''}`}
        accessibilityLabel={value}
        importantForAccessibility="no-hide-descendants" // Gustuff protection
        justifyContent="flex-end"
        spacing={0}
        bordered
        borderRadius="rounded"
        borderColor="lineHeavy"
        flexGrow={1}
      >
        {blurred ? (
          <Image source={blurImageSrc} style={style} testID="blurred-image" />
        ) : (
          <HStack
            width="90%"
            flexGrow={1}
            flexWrap="wrap"
            overflow="hidden"
            spacing={2}
            justifyContent="flex-start"
            onLayout={handleLayoutChange}
          >
            <CBSecureView>
              <TextBody color="foreground" spacingBottom={0.5} testID="mnemonic-text-content">
                {value}
              </TextBody>
            </CBSecureView>
          </HStack>
        )}

        {shouldShowBlurButton && (
          <ToggleBlurButton
            testID="mnemonic-text-display-blur-toggle"
            height={inputHeight}
            minHeight={DEFAULT_INPUT_HEIGHT}
            onPress={toggleBlur}
            blurred={blurred}
          />
        )}
      </HStack>
      {shouldShowCopyButton && (
        <CopyButton
          value={value}
          type="verbose"
          onPress={onCopy}
          clearAfterTimeout
          clipboardLabel={formatMessage(messages.clipboardLabel)}
        />
      )}
    </>
  );
}

