import { ReactNode, useCallback } from 'react';
import { Controller, ControllerProps, useFormContext } from 'react-hook-form';
import {
  Checkbox as CDSCheckbox,
  CheckboxProps as CDSCheckboxProps,
} from '@cbhq/cds-mobile/controls';
import { HStack } from '@cbhq/cds-mobile/layout';
import { TextLegal } from '@cbhq/cds-mobile/typography';

type CheckboxProps<T extends string> = {
  value: boolean;
  onChange: (...event: any[]) => void;
  label: string | ReactNode;
  onCheckToggle?: (value: boolean) => void;
} & CDSCheckboxProps<T>;

function Checkbox<T extends string>({
  value,
  onChange,
  label,
  onCheckToggle,
  ...props
}: CheckboxProps<T>) {
  const handleChange = useCallback(
    function handleChange() {
      onCheckToggle?.(!value);
      onChange(!value);
    },
    [onChange, onCheckToggle, value],
  );

  return (
    <HStack width="100%" alignItems="center" justifyContent="flex-start">
      <CDSCheckbox {...props} checked={value} onChange={handleChange} />
      <TextLegal spacingStart={1} onPress={handleChange} accessibilityRole="link">
        {label}
      </TextLegal>
    </HStack>
  );
}

type ControlledCheckboxProps = {
  name: string;
  accessibilityLabel: string;
  label: string | ReactNode;
  testID?: string;
  onCheckToggle?: (value: boolean) => void;
};

export function ControlledCheckbox({
  name,
  accessibilityLabel,
  label,
  testID,
  onCheckToggle,
}: ControlledCheckboxProps) {
  const { control } = useFormContext();

  const render = useCallback<ControllerProps['render']>(
    ({ field: { value, onChange } }) => {
      return (
        <Checkbox
          value={value}
          onChange={onChange}
          onCheckToggle={onCheckToggle}
          accessibilityLabel={accessibilityLabel}
          accessibilityRole="radio"
          label={label}
          testID={testID}
        />
      );
    },
    [accessibilityLabel, label, onCheckToggle, testID],
  );

  return <Controller control={control} name={name} render={render} />;
}

import { useCallback } from 'react';
import { AccessibilityState } from 'react-native';
import { BottomTabBarProps } from '@react-navigation/bottom-tabs';
import { NavigationState } from '@react-navigation/native';
import { PressableOpacity } from '@cbhq/cds-mobile/system/PressableOpacity';
import { markJourneyOnce } from '@cbhq/core-vitals-mobile';

import {
  tabNavigationLongPressed,
  tabNavigationPressed,
} from ':rn/shared/analytics/tabNavigationPressed';
import { TabNavigatorParamList } from ':rn/shared/types/ParamLists';
import { leaveNavigationBreadcrumb } from ':rn/shared/utils/leaveNavigationBreadcrumb';

import { BottomNav } from './BottomNav';
import { BottomNavItem } from './BottomNavItem';
import { useIsTabBarVisible } from './useIsTabBarVisible';

const accessibilitySelectedState: AccessibilityState = { selected: true };

type TabBarRoute = NavigationState['routes'][number];

export function TabBar({
  state,
  descriptors,
  navigation,
  onLongPress,
}: BottomTabBarProps & { onLongPress: (prevRoute: string, nextRoute: string) => void }) {
  const isTabBarVisible = useIsTabBarVisible();

  const leaveTabNavigationBreadcrumb = useCallback((tab: keyof TabNavigatorParamList) => {
    leaveNavigationBreadcrumb({
      action: 'tabNavigate',
      metadata: { tab },
    });
  }, []);

  const onPress = useCallback(
    (isFocused: boolean, route: TabBarRoute) => {
      return () => {
        leaveTabNavigationBreadcrumb(route.name as keyof TabNavigatorParamList);

        if (route.name === 'BrowserTab') {
          markJourneyOnce('navigate_to_browser_home');
        }
        if (route.name === 'ExploreTab') {
          markJourneyOnce('navigate_to_explore_tab');
        }
        if (route.name === 'TransactionsTab') {
          markJourneyOnce('navigate_to_transactions');
        }
        if (route.name === 'SettingsTab') {
          markJourneyOnce('navigate_to_settings_tab');
        }
        if (route.name === 'TransactTab') {
          markJourneyOnce('navigate_to_transact_tab');
        }
        if (route.name === 'HomeTab') {
          markJourneyOnce('navigate_to_home_tab');
        }
        if (route.name === 'WalletTab') {
          markJourneyOnce('navigate_to_wallet_tab');
        }

        const { routes: prevRoutes, index: prevIndex } = navigation.getState();
        const prevRoute = prevRoutes[prevIndex].name;
        const nextRoute = route.name;

        const event = navigation.emit({
          type: 'tabPress',
          target: route.key,
          canPreventDefault: true,
        });

        if (!isFocused && !event.defaultPrevented) {
          navigation.navigate(route.name);
        }

        tabNavigationPressed(prevRoute, nextRoute);
      };
    },
    [navigation, leaveTabNavigationBreadcrumb],
  );

  const handleLongPressDefault = useCallback(
    (route: TabBarRoute) => {
      return () => {
        const { routes: prevRoutes, index: prevIndex } = navigation.getState();
        const prevRoute = prevRoutes[prevIndex].name;
        const nextRoute = route.name;
        navigation.emit({
          type: 'tabLongPress',
          target: route.key,
        });
        tabNavigationLongPressed(prevRoute, nextRoute);

        onLongPress(prevRoute, nextRoute);
      };
    },
    [navigation, onLongPress],
  );

  if (!isTabBarVisible) return <></>;

  return (
    <BottomNav>
      {state.routes.map((route: TabBarRoute, index: number) => {
        const { options } = descriptors[route.key];
        const isFocused = state.index === index;
        const label = options.tabBarLabel;

        return (
          <PressableOpacity
            key={route.key}
            testID={options.tabBarTestID}
            accessibilityLabel={options.tabBarAccessibilityLabel}
            accessibilityRole="button"
            accessibilityState={isFocused ? accessibilitySelectedState : undefined}
            onPress={onPress(isFocused, route)}
            onLongPress={handleLongPressDefault(route)}
          >
            {/* eslint-disable @typescript-eslint/no-explicit-any */}
            {/* @ts-expect-error FIXME: @react-navigation/bottom-tabs probably needs to be updated to fix this type issue. */}
            <BottomNavItem active={isFocused} icon={options.tabBarIcon as any} label={label} />
          </PressableOpacity>
        );
      })}
    </BottomNav>
  );
}

