import { memo, useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { logNftFilterOptionSelected, logNftFilterViewed } from 'cb-wallet-analytics/collectible';
import { useActiveCollectionsView } from 'cb-wallet-data/hooks/Collections/useActiveCollectionsView';
import {
  ALL_NETWORKS_CONFIG_ENTRY,
  useCollectionsNetworkFilter,
} from 'cb-wallet-data/hooks/Collections/useCollectionsNetworkFilter';
import { useCollectionsNetworkFilterLabel } from 'cb-wallet-data/hooks/Collections/useCollectionsNetworkFilterLabel';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { useViewNFTChainEnabledConfig } from 'cb-wallet-data/stores/Collection/hooks/useViewNFTChainEnabledConfig';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { Box, VStack } from '@cbhq/cds-mobile/layout';

import { CollectionsFilterListCell } from ':rn/cds-wallet/components/cells/CollectionsFilterListCell';
import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Tray } from ':rn/cds-wallet/components/Tray/Tray';

import { CollectionsNetworkFilterIcon } from './CollectionsNetworkFilterIcon';

const NETWORK_FILTER_TYPE = 'network';

const messages = defineMessages({
  chains: {
    defaultMessage: 'Chains',
    description: 'Title for the network filter screen',
  },
  doneButton: {
    defaultMessage: 'Done',
    description: 'Label for done sorting button',
  },
});

type CollectionsNetworkFilterTrayProps = {
  visible: boolean;
  handleCloseComplete: () => void;
};

const CollectionsNetworkFilterTrayContent = memo(function CollectionsNetworkFilterTrayContent({
  handleCloseComplete,
}: CollectionsNetworkFilterTrayProps) {
  const { formatMessage } = useIntl();
  const defaultChainConfig = useViewNFTChainEnabledConfig();
  const enabledChainConfigEntries = useMemo(() => {
    const entries = Array.from(defaultChainConfig.entries()).filter((entry) => {
      const [, networkEnabledSetting] = entry;
      return networkEnabledSetting.enabled;
    });

    return [ALL_NETWORKS_CONFIG_ENTRY, ...entries];
  }, [defaultChainConfig]);

  const { activeCollectionsView } = useActiveCollectionsView();
  const { network, setNetwork } = useCollectionsNetworkFilter();

  useOnMount(() => {
    logNftFilterViewed({ type: NETWORK_FILTER_TYPE, currentView: activeCollectionsView });
  });

  const handlePress = useCallback(
    (newNetwork: string) => {
      return () => {
        logNftFilterOptionSelected({
          type: NETWORK_FILTER_TYPE,
          oldValue: network,
          newValue: newNetwork,
          currentView: activeCollectionsView,
        });
        setNetwork(newNetwork);
        handleCloseComplete();
      };
    },
    [handleCloseComplete, setNetwork, network, activeCollectionsView],
  );

  const label = useCollectionsNetworkFilterLabel();

  return (
    <Tray
      testID="collectible-network-tray"
      verticalDrawerPercentageOfView={0.8}
      onCloseComplete={handleCloseComplete}
      disableCapturePanGestureToDismiss
    >
      <Box offsetTop={2}>
        <VStack>
          {enabledChainConfigEntries.map((entry) => {
            const [networkName, networkEnabledSetting] = entry;

            return (
              <CollectionsFilterListCell
                key={networkName}
                icon={
                  <CollectionsNetworkFilterIcon
                    chainId={networkEnabledSetting.chainId}
                    addressType={networkEnabledSetting.addressType}
                    chainImageUrl={networkEnabledSetting.chainImageUrl}
                  />
                }
                title={label(networkName)}
                onPress={handlePress(networkName)}
                selected={network === networkName}
              />
            );
          })}

          <Box spacingHorizontal={3} spacingTop={2}>
            <ButtonGroup block accessibilityLabel="CollectibleAllOffersSortTrayButtonsLabel">
              <Button onPress={handleCloseComplete}>{formatMessage(messages.doneButton)}</Button>
            </ButtonGroup>
          </Box>
        </VStack>
      </Box>
    </Tray>
  );
});

export const CollectionsNetworkFilterTray = memo(function CollectionsNetworkFilterTray({
  visible,
  ...props
}: CollectionsNetworkFilterTrayProps) {
  if (!visible) return null;

  return (
    <ErrorBoundary errorFallback={<></>}>
      <CollectionsNetworkFilterTrayContent visible={visible} {...props} />
    </ErrorBoundary>
  );
});

import { memo, useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { logNftFilterOptionSelected, logNftFilterViewed } from 'cb-wallet-analytics/collectible';
import { useActiveCollectionsView } from 'cb-wallet-data/hooks/Collections/useActiveCollectionsView';
import { useCollectionsSortFilter } from 'cb-wallet-data/hooks/Collections/useCollectionsSortFilter';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import {
  CollectionsSortMethodType,
  CollectionsSortOrderType,
} from 'cb-wallet-data/stores/Collection/types';
import { getIconNameForCollectionsSort } from 'cb-wallet-data/stores/Collection/utils';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { Icon } from '@cbhq/cds-mobile/icons';
import { Box, VStack } from '@cbhq/cds-mobile/layout';

import { CollectionsFilterListCell } from ':rn/cds-wallet/components/cells/CollectionsFilterListCell';
import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { Alphabet } from ':rn/cds-wallet/images/Alphabet/Alphabet';

const SORT_FILTER_TYPE = 'sort';

const defaultSortOrderForMethod: Record<CollectionsSortMethodType, CollectionsSortOrderType> = {
  // eslint-disable-next-line camelcase
  recently_added: 'desc',
  // eslint-disable-next-line camelcase
  collection_name: 'asc',
};

export const messages = defineMessages({
  dateReceived: {
    defaultMessage: 'Date received',
    description: 'Label for date received sort method',
  },
  collectionName: {
    defaultMessage: 'Collection name',
    description: 'Label for the collection name sort method',
  },
  doneButton: {
    defaultMessage: 'Done',
    description: 'Label for done sorting button',
  },
  newToOld: {
    defaultMessage: 'New to old',
    description: 'Label for new to old sort order',
  },
  oldToNew: {
    defaultMessage: 'Old to new',
    description: 'Label for old to new sort order',
  },
  aToZ: {
    defaultMessage: 'A to Z',
    description: 'Label for A to Z sort order',
  },
  zToA: {
    defaultMessage: 'Z to A',
    description: 'Label for Z to A sort order',
  },
});

type Props = {
  visible: boolean;
  handleCloseComplete: () => void;
};

const CollectionsSortFilterTrayContent = memo(function CollectionsSortFilterTrayContent({
  handleCloseComplete,
}: Props) {
  const { formatMessage } = useIntl();
  const { activeCollectionsView } = useActiveCollectionsView();
  const { collectionsSortFilter, setCollectionsSortFilter } = useCollectionsSortFilter();
  const { sortMethod, sortOrder } = collectionsSortFilter;

  useOnMount(() => {
    logNftFilterViewed({ type: SORT_FILTER_TYPE, currentView: activeCollectionsView });
  });

  const handlePress = useCallback(
    (newSortFilter: CollectionsSortMethodType) => {
      return () => {
        if (sortMethod === newSortFilter) {
          const newSortOrder = sortOrder === 'asc' ? 'desc' : 'asc';

          // if the user clicks on one option and it's currently selected, flip the order around
          logNftFilterOptionSelected({
            type: SORT_FILTER_TYPE,
            oldValue: `${sortMethod},${sortOrder}`,
            newValue: `${sortMethod},${newSortOrder}`,
            currentView: activeCollectionsView,
          });
          setCollectionsSortFilter({
            sortMethod,
            sortOrder: newSortOrder,
          });
          return;
        }

        logNftFilterOptionSelected({
          type: SORT_FILTER_TYPE,
          oldValue: `${sortMethod},${sortOrder}`,
          newValue: `${newSortFilter},${defaultSortOrderForMethod[newSortFilter]}`,
          currentView: activeCollectionsView,
        });
        setCollectionsSortFilter({
          sortMethod: newSortFilter,
          sortOrder: defaultSortOrderForMethod[newSortFilter],
        });
      };
    },
    [setCollectionsSortFilter, sortMethod, sortOrder, activeCollectionsView],
  );

  const recentlyAddedSubtitle = useMemo(() => {
    if (sortMethod !== 'recently_added') return '';

    return sortOrder === 'desc'
      ? formatMessage(messages.newToOld)
      : formatMessage(messages.oldToNew);
  }, [sortMethod, sortOrder, formatMessage]);

  const collectionNameSubtitle = useMemo(() => {
    if (sortMethod !== 'collection_name') return '';

    return sortOrder === 'desc' ? formatMessage(messages.zToA) : formatMessage(messages.aToZ);
  }, [sortMethod, sortOrder, formatMessage]);

  const selectedIconName = useMemo(() => {
    return getIconNameForCollectionsSort({ sortMethod, sortOrder });
  }, [sortMethod, sortOrder]);

  return (
    <Tray
      testID="collections-sort-filter-tray"
      onCloseComplete={handleCloseComplete}
      disableCapturePanGestureToDismiss
    >
      <Box offsetTop={2}>
        <VStack>
          <CollectionsFilterListCell
            key="grid"
            icon={<Icon name="calendar" size="s" color="foreground" />}
            title={formatMessage(messages.dateReceived)}
            subtitle={recentlyAddedSubtitle}
            onPress={handlePress('recently_added')}
            selected={sortMethod === 'recently_added'}
            selectedIcon={<Icon name={selectedIconName} size="s" />}
          />
          <CollectionsFilterListCell
            key="collections"
            icon={<Alphabet />}
            title={formatMessage(messages.collectionName)}
            subtitle={collectionNameSubtitle}
            onPress={handlePress('collection_name')}
            selected={sortMethod === 'collection_name'}
            selectedIcon={<Icon name={selectedIconName} size="s" />}
          />
        </VStack>

        <Box spacingHorizontal={3} spacingTop={2}>
          <ButtonGroup block accessibilityLabel="CollectibleAllOffersSortTrayButtonsLabel">
