import { memo, useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { logNftFilterOptionSelected, logNftFilterViewed } from 'cb-wallet-analytics/collectible';
import { useIsFeatureEnabled } from 'cb-wallet-data/FeatureManager/hooks/useIsFeatureEnabled';
import { useActiveCollectionsView } from 'cb-wallet-data/hooks/Collections/useActiveCollectionsView';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { CollectionsViewSelection } from 'cb-wallet-data/stores/Collection/types';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { markJourney } from '@cbhq/core-vitals-mobile';

import { CollectionsFilterListCell } from ':rn/cds-wallet/components/cells/CollectionsFilterListCell';
import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { CollectionsGrid } from ':rn/cds-wallet/images/CollectionsGrid/CollectionsGrid';
import { NFTGrid } from ':rn/cds-wallet/images/NFTGrid/NFTGrid';

const VIEW_SETTING_TYPE = 'viewSetting';

export const messages = defineMessages({
  nftsOnly: {
    defaultMessage: 'NFTs',
    description: 'Label for the nfts only filter (NFT grid view)',
  },
  collectionsAndNFTs: {
    defaultMessage: 'Collections and NFTs',
    description: 'Label for the collections only filter (collection grid view)',
  },
  collectionsGrid: {
    defaultMessage: 'Collections',
    description: 'Title for the collection grid view option in active view screen',
  },
  doneButton: {
    defaultMessage: 'Done',
    description: 'Label for done button',
  },
});

type Props = {
  visible: boolean;
  handleCloseComplete: () => void;
};

const CollectionsViewFilterTrayContent = memo(function CollectionsViewFilterTrayContent({
  handleCloseComplete,
}: Props) {
  const { formatMessage } = useIntl();
  const { activeCollectionsView, setActiveCollectionsView } = useActiveCollectionsView();
  const isNftGridViewEnabled = useIsFeatureEnabled('nft_grid_views');
  const isCollectionsGridViewEnabled = useIsFeatureEnabled('collections_grid_view');

  const getNewViewJourneyMark = useCallback(
    (newViewSelection: CollectionsViewSelection) => {
      switch (newViewSelection) {
        case 'nftsOnly':
          return 'navigate_to_nft_grid_view_tab';
        default:
          return isCollectionsGridViewEnabled
            ? 'navigate_to_nft_collections_grid_view_tab'
            : 'navigate_to_paginated_collections_tab';
      }
    },
    [isCollectionsGridViewEnabled],
  );

  const handlePress = useCallback(
    (newViewSelection: CollectionsViewSelection) => {
      return () => {
        if (activeCollectionsView === newViewSelection) {
          handleCloseComplete();
          return;
        }

        markJourney(getNewViewJourneyMark(newViewSelection));
        logNftFilterOptionSelected({
          type: VIEW_SETTING_TYPE,
          currentView: activeCollectionsView,
          oldValue: activeCollectionsView,
          newValue: newViewSelection,
        });
        setActiveCollectionsView(newViewSelection);
        handleCloseComplete();
      };
    },
    [setActiveCollectionsView, handleCloseComplete, activeCollectionsView, getNewViewJourneyMark],
  );

  useOnMount(() => {
    logNftFilterViewed({ type: VIEW_SETTING_TYPE, currentView: activeCollectionsView });
  });

  return (
    <Tray
      testID="collections-view-filter-tray"
      onCloseComplete={handleCloseComplete}
      disableCapturePanGestureToDismiss
    >
      <Box offsetTop={2}>
        <VStack>
          {isNftGridViewEnabled ? (
            <CollectionsFilterListCell
              key="nftGrid"
              icon={<NFTGrid />}
              title={formatMessage(messages.nftsOnly)}
              onPress={handlePress('nftsOnly')}
              selected={activeCollectionsView === 'nftsOnly'}
            />
          ) : null}
          {isCollectionsGridViewEnabled ? (
            <CollectionsFilterListCell
              key="collectionsGrid"
              icon={<CollectionsGrid />}
              title={formatMessage(messages.collectionsGrid)}
              onPress={handlePress('collectionsAndNfts')}
              selected={activeCollectionsView === 'collectionsAndNfts'}
            />
          ) : null}
          <Box spacingHorizontal={3} spacingTop={2}>
            <ButtonGroup block accessibilityLabel="collections-view-filter-tray-buttons">
              <Button onPress={handleCloseComplete}>{formatMessage(messages.doneButton)}</Button>
            </ButtonGroup>
          </Box>
        </VStack>
      </Box>
    </Tray>
  );
});

