  if (!visible) return null;

  return (
    <ErrorBoundary errorFallback={<></>}>
      <CollectionsViewFilterTrayContent visible={visible} {...props} />
    </ErrorBoundary>
  );
});

import { useEffect, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { usePendingAssetViewed } from 'cb-wallet-analytics/assets';
import { EthereumNetworkMap } from 'cb-wallet-data/chains/AccountBased/Ethereum/EthereumChain';
import { SolanaNetworkMap } from 'cb-wallet-data/chains/AccountBased/Solana/models/SolanaChain';
import { useOnUnmount } from 'cb-wallet-data/hooks/useOnUnmount';
import {
  pendingAssetAtom,
  PendingAssetData,
} from 'cb-wallet-data/stores/Assets/states/pendingAssetAtom';
import { usePspsOrderDetailsQuery } from 'cb-wallet-data/stores/BuyNonCb/api/useBuyNonCbOrderDetails';
import { BuyNonCbOrderStatus } from 'cb-wallet-data/stores/BuyNonCb/types/BuyNonCbOrderDetails';
import { BuyNonCbVendorId } from 'cb-wallet-data/stores/BuyNonCb/types/BuyNonCbVendor';
import { Network } from 'cb-wallet-data/stores/Networks/models/Network';
import { useSetRecoilState } from 'recoil';
import { CellMedia, ListCell } from '@cbhq/cds-mobile/cells';
import { TextBody, TextLabel2 } from '@cbhq/cds-mobile/typography';

import { AssetsScreenContentContainer } from ':rn/cds-wallet/components/Assets/AssetsScreenContentContainer';
import { AssetIcon } from ':rn/cds-wallet/components/icons/AssetIcon';
import { AssetTabKey } from ':rn/shared/hooks/useLocalizedPortfolio';

const messages = defineMessages({
  pending: {
    defaultMessage: 'Pending...',
    description: 'Label for pending asset',
  },
});

type PendingAssetProps = {
  asset: PendingAssetData;
};

export const NETWORK_CHAIN_IDS = [
  ...Object.values(EthereumNetworkMap.whitelisted).map((item) => item.chainId),
  ...Object.values(SolanaNetworkMap.whitelisted).map((item) => item.chainId),
];

export function PendingAsset({ asset }: PendingAssetProps) {
  const { formatMessage } = useIntl();
  const setPendingAssetData = useSetRecoilState(pendingAssetAtom);

  const { data } = usePspsOrderDetailsQuery({
    vendor: asset.pspsVendor ?? BuyNonCbVendorId.Transak,
    vendorOrderId: asset.pspsOrderId ?? '',
    queryOptions: {
      enabled: Boolean(asset.pspsVendor && asset.pspsOrderId),
      refetchInterval: 10 * 1000,
      suspense: false,
      staleTime: 0,
    },
  });

  usePendingAssetViewed({ currencyCode: asset.currencyCode });

  useOnUnmount(() => {
    setPendingAssetData(undefined);
  });

  useEffect(
    function clearPendingAssetIfPspsOrderFailed() {
      if (
        data?.status &&
        ![BuyNonCbOrderStatus.Processing, BuyNonCbOrderStatus.Completed].includes(data?.status)
      ) {
        setPendingAssetData(undefined);
      }
    },
    [data?.status, setPendingAssetData],
  );

  const assetIcon = useMemo(() => {
    // Fallback to CDS CellMedia if it's not able to create a network using chainId
    // or chainId is not one of the account base networks
    if (!asset?.chainId || !NETWORK_CHAIN_IDS.includes(asset?.chainId)) {
      return (
        <CellMedia
          type="asset"
          source={asset.imageURL}
          accessibilityLabel={asset.currencyCode}
          testID="pending-asset-cell-media"
        />
      );
    }

    const network = Network.fromChainId({ chainId: BigInt(asset.chainId) });

    return (
      <AssetIcon
        network={network}
        iconUrl={asset.imageURL}
        currencyCode={asset.currencyCode}
        showNetworkIcon={false}
      />
    );
  }, [asset]);

  return (
    <AssetsScreenContentContainer
      tabKey={AssetTabKey.WALLETS}
      testID={`pending-asset-${asset.currencyCode}`}
    >
      <ListCell
        title={<TextBody>{asset.name}</TextBody>}
        detail={<TextLabel2 color="foregroundMuted">{formatMessage(messages.pending)}</TextLabel2>}
        variant="foregroundMuted"
        media={assetIcon}
        testID={`pending-asset-item-${asset.currencyCode}`}
      />
    </AssetsScreenContentContainer>
  );
}

