import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

export const StoreKeys_referralHubBannerDismissed = new LocalStorageStoreKey<string>(
  'referralHubBannerDismissed',
);

const messages = defineMessages({
  title: {
    defaultMessage: 'Invite your friends',
    description: 'Title for referral hub entry point',
  },
  description: {
    defaultMessage: 'Invite your friends to download Coinbase Wallet',
    description: 'Description for referral hub entry point',
  },
  dismissAriaLabel: {
    defaultMessage: 'Dismiss the Invite your friends banner',
    description:
      'Aria label for the icon button that dismisses the entry point to the Referral Hub landing screen',
  },
});

export const ReferralHubAddressBookBanner = memo(function ReferralsBanner() {
  const [dismissed, setDismissed] = useState(false);
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const dateUserDismissedBanner = Store.get<string>(StoreKeys_referralHubBannerDismissed);
  const userIsInCoolOutPeriod = useMemo(
    () =>
      dateUserDismissedBanner &&
      differenceInDays(new Date(), new Date(dateUserDismissedBanner)) <= 15,

    [dateUserDismissedBanner],
  );
  const onPress = useCallback(
    function onPress() {
      logReferralHubButtonEvent({ type: 'entry_cta' });
      navigate('ReferralHub', { screen: 'Landing' });
    },
    [navigate],
  );

  // Store the date on which the user has dismissed the banner, we will use this to ensure the banner is only shown to
  // the user after 15 days as elapsed.
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const onDismiss = useCallback(function onDismiss(event: any) {
    event.stopPropagation();

    logReferralHubButtonEvent({ type: 'entry_dismiss' });
    Store.set<string>(StoreKeys_referralHubBannerDismissed, new Date().toISOString());
    setDismissed(true);
  }, []);

  if (dismissed || userIsInCoolOutPeriod) {
    return null;
  }

  return (
    <Pressable
      background="transparent"
      onPress={onPress}
      accessibilityRole="button"
      testID="referral-hub-banner"
    >
      <VStack>
        <HStack spacingHorizontal={2} justifyContent="space-evenly" alignItems="flex-start">
          <ListCell
            multiline
            title={<TextLabel1>{formatMessage(messages.title)}</TextLabel1>}
            description={
              <TextLabel2 color="foregroundMuted">{formatMessage(messages.description)}</TextLabel2>
            }
            media={<Pictogram name="holdingCoin" />}
            testID="referral-hub-banner-content"
          />
          <Box spacingVertical={1}>
            <IconButton
              testID="referral-hub-banner-dismiss"
              onPress={onDismiss}
              variant="foregroundMuted"
              name="close"
              transparent
              compact
              accessibilityLabel={formatMessage(messages.dismissAriaLabel)}
              accessibilityRole="button"
            />
          </Box>
        </HStack>
        <Divider direction="horizontal" width="100%" spacingTop={1} />
      </VStack>
    </Pressable>
  );
});

