export function CloudBackupTray({ toggleOff }: TrayCommonProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const cloud = useCloudBackupProviderName();
  const activeAccountId = useActiveAccountId();

  const { triggerAuth } = useMnemonic({
    requireAuthentication: true,
  });

  const onBackupPress = useCallback(
    async function onBackupPress() {
      toggleOff();

      triggerAuth({
        accountId: activeAccountId,
        successCallback: () => {
          // Without this delay, the recovery phrase backup tray won't show
          setTimeout(() => navigate('RecoveryPhrase', { accountId: activeAccountId }), 200);
        },
        mnemonicAccessContext: MnemonicAccessContext.CloudBackup,
      });
    },
    [activeAccountId, navigate, toggleOff, triggerAuth],
  );

  return (
    <Tray onCloseComplete={toggleOff} disableCapturePanGestureToDismiss testID="cloud-backup-tray">
      {({ handleClose }) => {
        return (
          <ScrollView>
            <Pressable>
              <PortalProvider>
