                  </VStack>
                  <VStack alignItems="center" spacingVertical={5}>
                    <MiamiIllustrationWrapper illustration="ProtectedNotesMiami">
                      <SpotRectangle name="protectedNotes" />
                    </MiamiIllustrationWrapper>
                  </VStack>
                  <VStack gap={2}>
                    {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
                    {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
                    <Button testID="cloud-backup-tray-cta" onPress={onBackupPress}>
                      {formatMessage(messages.backupCta, { cloud })}
