export type BrowserSearchInputProps = {
  inputRef: React.RefObject<RNTextInput>;
  isEditing: boolean;
  currentUrl: string;
  webViewOpen: boolean;
  currentInput: string;
  suggestions: LinkItem[];
  setCurrentInput: React.Dispatch<React.SetStateAction<string>>;
  debouncedSetQuery: DebouncedFunc<(input: string) => void>;
  onReset: () => void;
  onURLSubmitted: ({
    url,
    method,
  }: {
    url: string;
    method: OpenUrlInWebViewParams['method'];
  }) => void;
  onEditingOff: () => void;
  onEditingOn: () => void;
  onReloadPage: () => void;
};

export const BrowserSearchInput = memo(function Omnibox({
  currentUrl,
  onURLSubmitted,
  inputRef,
  onReset,
  isEditing,
  onEditingOff,
  onEditingOn,
  currentInput,
  setCurrentInput,
  suggestions,
  debouncedSetQuery,
  onReloadPage,
  webViewOpen,
}: BrowserSearchInputProps) {
  const { formatMessage } = useIntl();
  const triggerClearUrlInput = useBrowserWebViewUrlClearInputClicked(currentUrl);
  const { show } = useRateLimitedToast({});

  useEffect(
    function applyInputFocusOnPress() {
      if (isEditing && !inputRef.current?.isFocused()) {
        inputRef.current?.focus();
      }
    },
    [inputRef, isEditing],
  );

  useEffect(
    function updateInputStateOnBlur() {
      if (!isEditing && !inputRef.current?.isFocused() && !currentInput && currentUrl) {
        setCurrentInput(currentUrl);
      }
    },
    [currentInput, currentUrl, inputRef, isEditing, setCurrentInput],
  );

  useEffect(
    function keepInputUpdatedWithUrl() {
      setCurrentInput(currentUrl ?? '');
    },
    [currentUrl, setCurrentInput],
  );

  const onChangeText = useCallback(
    function onChangeText(text: string) {
      setCurrentInput(text);
      debouncedSetQuery(text);
    },
    [setCurrentInput, debouncedSetQuery],
  );

  const onPress = useCallback(() => {
    onEditingOn();
  }, [onEditingOn]);

  const onEndContentPress = useCallback(
    function onEndContentPress() {
      triggerClearUrlInput();
      onChangeText('');
    },
    [onChangeText, triggerClearUrlInput],
  );

  const onBlur = useCallback(() => {
    onEditingOff();
  }, [onEditingOff]);

  const onStartContentPress = useCallback(() => {
    if (isEditing) {
      onReloadPage();
      onBlur();
    } else {
      onPress();
    }
  }, [isEditing, onBlur, onPress, onReloadPage]);

  const safeSubmitURL = useCallback(
    (url: string) => {
      const urlValidationResult = buildValidURL(url).toString();

      if (urlValidationResult.startsWith(BUILD_VALID_URL_ERROR_PREFIX)) {
        show(formatMessage(messages.urlValidationError));
        return;
      }

      onURLSubmitted({ url: urlValidationResult, method: 'search' });
    },
    [formatMessage, onURLSubmitted, show],
  );

  const onSubmit = useCallback(
    function onSubmit(event: NativeSyntheticEvent<TextInputSubmitEditingEventData>) {
      const text = event.nativeEvent.text.trim();
      const isUrl = isURL(text);
      if (text.length > 0) {
        if (isUrl) {
          safeSubmitURL(text);
        } else if (suggestions.length > 0) {
          if (suggestions.length === 1) {
            onURLSubmitted({ url: googleSearchURL(text).toString(), method: 'search' });
            return;
          }
          safeSubmitURL(suggestions[0].url);
        } else {
          onURLSubmitted({ url: googleSearchURL(text).toString(), method: 'search' });
        }
      }
      onReset();
    },
    [onReset, onURLSubmitted, safeSubmitURL, suggestions],
  );

  const start = useMemo(() => {
    const refreshable = webViewOpen && isEditing;
    return <InputStart url={currentUrl} onPress={onStartContentPress} refreshable={refreshable} />;
  }, [currentUrl, isEditing, onStartContentPress, webViewOpen]);

  const end = useMemo(
    () => webViewOpen && isEditing && <InputEnd onPress={onEndContentPress} />,
    [isEditing, onEndContentPress, webViewOpen],
  );

  const trimmedValue = useMemo(() => {
    if (!isEditing) {
      return trimHref(currentUrl);
    }
    return currentInput;
  }, [currentInput, currentUrl, isEditing]);

  return (
    <Box width="100%">
      {isEditing ? (
        <TextInput
          compact
          editable
          selectTextOnFocus
          key="browser-search-input"
          height={FOCUSED_URL_BAR_HEIGHT}
          borderRadius="roundedFull"
          testID="browser-search-input"
          placeholder={formatMessage(messages.searchPlaceholder)}
          keyboardAppearance="default"
          accessibilityRole="search"
          keyboardType="web-search"
          variant="foregroundMuted"
          autoCapitalize="none"
          autoCorrect={false}
          ref={inputRef}
          onBlur={onBlur}
          defaultValue={currentUrl}
          onChangeText={onChangeText}
          onSubmitEditing={onSubmit}
          returnKeyType="go"
          // @ts-expect-error TS(2322): Type '"auto"' is not assignable to type '"left" | ... Remove this comment to see the full error message
          textAlign="auto"
          value={trimmedValue}
          start={start}
          end={end}
          autoFocus
        />
      ) : (
        <PressableOpacity testID="browser-search-input-mask" noScaleOnPress onPress={onPress}>
          <HStack
            alignItems="center"
            justifyContent="center"
            background="backgroundAlternate"
            borderRadius="roundedFull"
            spacingStart={0.5}
            spacingEnd={1}
            height={URL_BAR_HEIGHT}
            flexGrow={1}
            flexShrink={1}
          >
            {!!currentUrl && <BrowsingIcon url={currentUrl} />}
            <Box flexShrink={1} spacingHorizontal={0.5}>
              <TextBody
                align="center"
                color="foregroundMuted"
                numberOfLines={1}
                ellipsizeMode="tail"
              >
                {currentUrl ? trimmedValue : formatMessage(messages.searchPlaceholder)}
              </TextBody>
            </Box>
          </HStack>
        </PressableOpacity>
      )}
    </Box>
  );
});

