type MenuItemObjProps = Omit<MenuItemProps, 'handleClose'> & { key: string };

export const BrowserMenu = memo(function BrowserMenu() {
  const { formatMessage } = useIntl();
  const { minimizeWebViewAndJumpTo, jumpTo, currentScreen } = useBrowserTabNavigation();
  const { addBookmark, removeBookmark, findBookmarkForUrl, bookmarks, deleteAllBookmarks } =
    useBrowserBookmarks();
  const { browserHistory, clearHistory } = useBrowserHistory();
  const { activeTabSession, removeAllTabs, tabs } = useBrowserTabs();
  const { showNetworkSwitcher } = useBrowserNetworkSwitcher();
  const platformSpecificBrowserHomeScreen = usePlatformSpecificBrowserHomeScreen();
  const triggerClearedHistory = useBrowserHistoryCleared(browserHistory.length);
  const triggerClosedAllTabs = useBrowserTabsCloseAll(tabs.length);
  const triggerMenuOpened = useBrowserMenuOpened(currentScreen);
  const triggerMenuClosed = useBrowserMenuClosed(currentScreen);
  const menuAnchorRef = useRef<View>(null);
  const menuRef = useRef<PopoverRef>(null);
  const { url, title } = activeTabSession?.sessionInfo ?? {};

  const onMenuPress = useCallback(
    function onMenuPress() {
      menuRef.current?.show({
        anchorRef: menuAnchorRef.current,
        stickToPosition: Position.BOTTOM_RIGHT,
        extraOffset: { left: 8, top: 12 },
      });
      triggerMenuOpened();
    },
    [triggerMenuOpened],
  );

  const handleClose = useCallback((callback?: () => void) => {
    menuRef.current?.hide(callback);
  }, []);

  const handleMenuHide = useCallback(() => {
    triggerMenuClosed();
  }, [triggerMenuClosed]);

  const existingBookmark = useMemo(
    () => (url ? findBookmarkForUrl(url) : undefined),
    [findBookmarkForUrl, url],
  );

  const handleShare = useCallback(
    async function handleShare() {
      const sharedResult = await onShare(url ?? '');
      browserMenuSiteShared(sharedResult);
    },
    [url],
  );

  const bookmarkPage = useCallback(() => {
    if (url) {
      addBookmark({
        url,
        title: title || parseUrl(url).hostname,
      });
      triggerBrowserBookmarkAdded(url);
    }
  }, [url, title, addBookmark]);

  const handleCloseAllTabs = useCallback(
    function handleCloseAllTabs() {
      removeAllTabs();
      triggerClosedAllTabs();
    },
    [removeAllTabs, triggerClosedAllTabs],
  );

  const handleClearHistory = useCallback(
    function handleClearHistory() {
      clearHistory();
      triggerClearedHistory();
    },
    [clearHistory, triggerClearedHistory],
  );

  const handleDeleteAllBookmarks = useCallback(
    function handleDeleteAllBookmarks() {
      deleteAllBookmarks();
      triggerDeleteAllBookmarks(bookmarks.length);
    },
    [bookmarks.length, deleteAllBookmarks],
  );

  const removeBookmarkForUrl = useCallback(() => {
    if (existingBookmark) {
      removeBookmark(existingBookmark.id);
      triggerBrowserBookmarkDeleted(existingBookmark.url);
    }
  }, [existingBookmark, removeBookmark]);

  const minimizeWebViewAndGoHome = useCallback(() => {
    minimizeWebViewAndJumpTo(platformSpecificBrowserHomeScreen);
  }, [minimizeWebViewAndJumpTo, platformSpecificBrowserHomeScreen]);

  const menuItems = useMemo(() => {
    const homeScreenMenuItems = [
      {
        key: 'home',
        text: formatMessage(messages.home),
        icon: 'globe',
        onClose: () => jumpTo(platformSpecificBrowserHomeScreen),
      },
      ...(platformSpecificBrowserHomeScreen === 'BrowserHome'
        ? [
            {
              key: 'tabs',
              text: formatMessage(messages.tabs),
              icon: 'copy',
              onClose: () => jumpTo('BrowserTabs'),
            },
          ]
        : []),
      {
        key: 'bookmarks',
        text: formatMessage(messages.bookmarks),
        icon: 'bookmarkActive',
        onClose: () => jumpTo('BrowserBookmarks'),
      },
      {
        key: 'history',
        text: formatMessage(messages.history),
        icon: 'clock',
        onClose: () => jumpTo('BrowserHistory'),
      },
    ];

    const goHomeMenuItem = {
      key: 'goHome',
      text: formatMessage(messages.home),
      icon: 'globe',
      onClose: minimizeWebViewAndGoHome,
    };

    const browserTabsMenuItems = [
      goHomeMenuItem,
      {
        key: 'closeAllTabs',
        text: formatMessage(messages.closeAllTabs),
        icon: 'trashCan',
        disabled: !tabs.length,
        onClose: handleCloseAllTabs,
      },
    ];

    const platformSpecificHomeScreenMenuItems = [
      ...homeScreenMenuItems,
      ...(platformSpecificBrowserHomeScreen === 'BrowserTabs' ? browserTabsMenuItems : []),
    ];

    switch (currentScreen) {
      case 'BrowserWebViews':
        return [
          goHomeMenuItem,
          {
            key: 'bookmarkPage',
            text: existingBookmark
              ? formatMessage(messages.removeBookmark)
              : formatMessage(messages.addBookmark),
            icon: existingBookmark ? 'bookmarkActive' : 'bookmarkInactive',
            onClose: existingBookmark ? removeBookmarkForUrl : bookmarkPage,
          },
          {
            key: 'switchNetwork',
            text: formatMessage(messages.switchNetwork),
            icon: 'blockchain',
            onClose: showNetworkSwitcher,
          },
          {
            key: 'sharePage',
            text: formatMessage(messages.shareSite),
            icon: 'share',
            onPress: handleShare,
          },
        ];
      case platformSpecificBrowserHomeScreen:
        // This will override the following case statement on iOS
        // since the homescreen is BrowserTabs on iOS
        return platformSpecificHomeScreenMenuItems;
      case 'BrowserTabs':
        return browserTabsMenuItems;
      case 'BrowserHistory':
        return [
          {
            key: 'clearHistory',
            text: formatMessage(messages.clearHistory),
            icon: 'trashCan',
            disabled: !browserHistory.length,
            onClose: handleClearHistory,
          },
        ];
      case 'BrowserBookmarks':
        return [
          {
            key: 'deleteAllBrowserBookmarks',
            text: formatMessage(messages.deleteAllBookmarks),
            icon: 'trashCan',
            disabled: !bookmarks.length,
            onClose: handleDeleteAllBookmarks,
          },
        ];
      default:
        return [];
    }
  }, [
    bookmarkPage,
    bookmarks.length,
    browserHistory.length,
    minimizeWebViewAndGoHome,
    currentScreen,
    existingBookmark,
    formatMessage,
    handleClearHistory,
    handleCloseAllTabs,
    handleDeleteAllBookmarks,
    handleShare,
    jumpTo,
    platformSpecificBrowserHomeScreen,
    removeBookmarkForUrl,
    showNetworkSwitcher,
    tabs.length,
  ]) as MenuItemObjProps[];

  return (
    <Box ref={menuAnchorRef} collapsable={false} justifyContent="center" alignItems="center">
      <MenuButton
        onPress={onMenuPress}
        iconName="more"
        testID="browser-menu"
        accessibilityLabel={formatMessage(messages.moreA11yLabel)}
      />
      <PopoverMenu key="browser-menu" ref={menuRef} onHidden={handleMenuHide}>
        <BrowserPopoverMenu
          sessionInfo={activeTabSession?.sessionInfo}
          menuItems={menuItems}
          currentScreen={currentScreen}
          handleClose={handleClose}
        />
      </PopoverMenu>
    </Box>
  );
});

async function onShare(url: string): Promise<BrowserMenuSiteSharedResult> {
  try {
    if (!url) throw new Error('No URL was provided');
    const result = await Share.share({
      title: 'Share this site',
      message: `Check out this site! ${url}`,
      url,
    });

    if (result.action === Share.sharedAction) {
      return { url, type: result.activityType ?? undefined, response: 'success' };
    }

    return { url, response: 'dismissed' };
  } catch (error: ErrorOrAny) {
    return { url, response: 'error', error: error?.message ?? 'unknown error' };
  }
}

import { memo, useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { IconButton } from '@cbhq/cds-mobile/buttons';
