import { MenuItem, MenuItemProps } from './MenuItem';

type MenuItemObjProps = Omit<MenuItemProps, 'handleClose'> & { key: string };

const messages = defineMessages({
  refresh: {
    defaultMessage: 'Refresh',
    description: 'Refresh tab',
  },
});

type BrowserPopoverMenuProps = {
  sessionInfo: Partial<SessionInfo> | undefined;
  menuItems: MenuItemObjProps[];
  currentScreen: BrowserScreen;
  handleClose: (callback?: () => void) => void;
};

export const BrowserPopoverMenu = memo(function BrowserPopoverMenu({
  sessionInfo,
  menuItems,
  currentScreen,
  handleClose,
}: BrowserPopoverMenuProps) {
  const { url } = sessionInfo ?? {};
  const homeAction = menuItems.find(({ key }) => ['goHome', 'home'].includes(key))?.onClose;
  const { formatMessage } = useIntl();
  const { jumpTo } = useBrowserTabNavigation();
  const goBack = useCallback(
    function goBack() {
      sessionInfo?.goBack?.();
      handleClose();
    },
    [handleClose, sessionInfo],
  );
  const goForward = useCallback(
    function goForward() {
      sessionInfo?.goForward?.();
      handleClose();
    },
    [handleClose, sessionInfo],
  );
  const goHome = useCallback(
    function goHome() {
      // Fallback to browser navigation in case homeAction is undefined.
      if (homeAction) {
        homeAction();
      } else {
        jumpTo('BrowserHome');
      }
      handleClose();
    },
    [handleClose, homeAction, jumpTo],
  );

  return (
    <VStack>
      <HStack justifyContent="space-between" spacingVertical={2} spacingHorizontal={1}>
        <IconButton
          testID="goBack"
          disabled={!sessionInfo?.canGoBack}
          onPress={goBack}
          name="caretLeft"
        />
        <IconButton
          testID="goForward"
          disabled={!sessionInfo?.canGoForward}
          onPress={goForward}
          name="caretRight"
        />
        <IconButton testID="home" onPress={goHome} name="home" />
      </HStack>
      <Divider offsetHorizontal={1} />
      {currentScreen === 'BrowserWebViews' ? (
        <MenuItem
          currentScreen={currentScreen}
          url={url}
          key="RefreshPage"
          text={formatMessage(messages.refresh)}
          icon="undo"
          onClose={sessionInfo?.reload}
          handleClose={handleClose}
        />
      ) : null}
      {menuItems
        .filter(({ key }) => !['switchNetwork', 'goHome', 'home'].includes(key))
        .map(({ text, icon, onPress, onClose, key, disabled }) => (
          <MenuItem
            currentScreen={currentScreen}
            url={url}
            key={key}
            text={text}
            icon={icon}
            onPress={onPress}
            onClose={onClose}
            disabled={disabled}
            handleClose={handleClose}
          />
        ))}
    </VStack>
  );
});

