type BrowserURLBarProps = {
  isEditing: boolean;
  sessionInfo: Partial<SessionInfo> | undefined;
  onReset: () => void;
  onEditingOff: () => void;
  onEditingOn: () => void;
  onReloadPage: () => void;
  onURLSubmitted: ({
    url,
    method,
  }: {
    url: string;
    method: OpenUrlInWebViewParams['method'];
  }) => void;
  showNavBarHeader: boolean;
};

export const BrowserURLBar = memo(function BrowserURLBar({
  isEditing,
  onEditingOff,
  onEditingOn,
  onReset,
  onReloadPage,
  onURLSubmitted,
  sessionInfo,
  showNavBarHeader,
}: BrowserURLBarProps) {
  const inputRef = useRef<RNTextInput>(null);
  const { formatMessage, locale } = useIntl();
  const { debouncedInput, debouncedSetInput } = useDebouncedTextInput(200);
  const { currentScreen, closeWebViewAndJumpTo } = useBrowserTabNavigation();
  const { tabs } = useBrowserTabs();
  const [currentInput, setCurrentInput] = useState<string>(sessionInfo?.url ?? '');
  const triggerBrowserBackButtonPressed = useBrowserWebViewNavigationPressed('back');
  const { browserHistory, recentlyVisited } = useBrowserHistory();
  const platformSpecificBrowserHomeScreen = usePlatformSpecificBrowserHomeScreen();
  const [suggestions, setSuggestions] = useState<LinkItem[]>([]);
  const [historySuggestions, setHistorySuggestions] = useState<LinkItem[]>([]);
  const hasHistory = useMemo(() => !!browserHistory.length, [browserHistory.length]);
  const isSearching = useMemo(
    () => isEditing && (!sessionInfo || sessionInfo?.url !== currentInput),
    [currentInput, isEditing, sessionInfo],
  );

  const goBack = useCallback(
    function goBack() {
      triggerBrowserBackButtonPressed();
      if (!sessionInfo?.canGoBack) {
        closeWebViewAndJumpTo(platformSpecificBrowserHomeScreen);
      } else {
        sessionInfo?.goBack?.();
      }
    },
    [
      closeWebViewAndJumpTo,
      platformSpecificBrowserHomeScreen,
      sessionInfo,
      triggerBrowserBackButtonPressed,
    ],
  );

  const handleReset = useCallback(
    function handleReset() {
      inputRef.current?.blur();
      onEditingOff();
      debouncedSetInput('');
      setCurrentInput('');
      if (!sessionInfo?.url) {
        onReset();
      }
    },
    [debouncedSetInput, inputRef, onReset, onEditingOff, sessionInfo],
  );

  const handleResetSearchSuggestions = useCallback(
    function handleResetSearchSuggestions() {
      debouncedSetInput('');
      setCurrentInput('');
    },
    [debouncedSetInput],
  );

  const formatDapps = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (dappList: any) => {
      return dappList.map((dapp: Dapp) => ({
        ...dapp,
        description: formatMessage(dapp.description as MessageDescriptor),
      }));
    },
    [formatMessage],
  );

  const formattedTopDapps = useMemo(() => {
    return platformSpecificBrowserHomeScreen === 'BrowserHome' ? formatDapps(topFiveDapps) : [];
  }, [formatDapps, platformSpecificBrowserHomeScreen]);

  type DAppObject = Omit<Dapp, 'description'> & { description: string };
  const hasSponsoredDapp = useSponsoredDapp();

  const suggest = useCallback(
    async function suggest() {
      const searchAPIResults = debouncedInput
        ? await getDAppList(locale, debouncedInput)
        : undefined;
      const searchAPIList = transformDAppList(
        searchAPIResults?.edges ?? [],
        hasSponsoredDapp,
      ) as DAppObject[];

      const itemsToSearch: {
        id: string;
        url: string;
        title: string;
        description?: string;
      }[] = [...searchAPIList];

      const historyItemsToSearch: {
        id: string;
        url: string;
        title: string | ReactNode;
        description?: string;
      }[] = [...browserHistory];

      const suggestableList = itemsToSearch.filter((item) => {
        return Object.entries(item)
          .filter(([key]) => ['url', 'title', 'description', 'category'].includes(key))
          .some(([, val]) => val.toString().toLowerCase().includes(debouncedInput.toLowerCase()));
      });

      const historySuggestableList = historyItemsToSearch.filter((item) => {
        return Object.entries(item)
          .filter(([key]) => ['url', 'title', 'description', 'category'].includes(key))
          .some(([, val]) => val?.toString().toLowerCase().includes(debouncedInput.toLowerCase()));
      });

      const suggestable = [...new Map(suggestableList.map((item) => [item.url, item])).values()];

      const historySuggestable = [
        ...new Map(historySuggestableList.map((item) => [item.url, item])).values(),
      ];

      const generateLinkListItemProps = (items: LinkItem[]): LinkListItemProps[] => {
        return items.map((item) => ({
          ...item,
          iconUrl: findDappByUrl(item.url)?.iconUrl ?? item.iconUrl,
        }));
      };

      if (debouncedInput.length < 1) {
        // When there is no query:
        // If user has history, show first 5 history items
        // Otherwise show Jeff H's top 5 dapps
        setSuggestions(
          generateLinkListItemProps(hasHistory ? recentlyVisited.slice(0, 5) : formattedTopDapps),
        );
        setHistorySuggestions([]);
        return;
      }

      const suggestableWithSearchOption = [
        ...suggestable,
        {
          id: 'search_by_string',
          url: `https://www.google.com/search?q=${encodeURIComponent(debouncedInput)}`,
          title: `Search "${debouncedInput}"`,
          showDescription: false,
        },
      ];
      setSuggestions(generateLinkListItemProps(suggestableWithSearchOption));
      setHistorySuggestions(generateLinkListItemProps(historySuggestable));
    },
    [
      browserHistory,
      debouncedInput,
      formattedTopDapps,
      hasHistory,
      hasSponsoredDapp,
      locale,
      recentlyVisited,
    ],
  );

  useEffect(() => {
    suggest();
  }, [debouncedInput, suggest]);

  return (
    <VStack flexGrow={1}>
      {!showNavBarHeader || isSearching ? (
        <HStack
          testID="defi-omnibox"
          spacingHorizontal={2}
          spacingBottom={1}
          alignItems="center"
          justifyContent="center"
        >
          {!isEditing && (
            <MenuButton
              testID="browser-nav-back"
              disabled={currentScreen === platformSpecificBrowserHomeScreen}
              onPress={goBack}
              iconName="backArrow"
              accessibilityLabel={formatMessage(messages.a11yBackLabel)}
            />
          )}
          <HStack flexShrink={1} flexGrow={1} spacingHorizontal={1}>
            <BrowserSearchInput
              onReset={handleReset}
              inputRef={inputRef}
              isEditing={isEditing}
              currentUrl={sessionInfo?.url ?? ''}
              onURLSubmitted={onURLSubmitted}
              onReloadPage={onReloadPage}
              onEditingOff={onEditingOff}
              onEditingOn={onEditingOn}
              currentInput={currentInput}
              setCurrentInput={setCurrentInput}
              suggestions={suggestions}
              debouncedSetQuery={debouncedSetInput}
              webViewOpen={!!sessionInfo}
            />
          </HStack>
          {!isEditing && (
            <HStack>
              <NetworkSwitcherButton />
              <TabsButton />
              <BrowserMenu />
            </HStack>
          )}
          {isEditing && (
            <HStack flexShrink={0} spacingHorizontal={1}>
              <PressableOpacity disabled={!isEditing} onPress={handleReset}>
                <TextLabel1 color="foreground">{formatMessage(messages.cancel)}</TextLabel1>
              </PressableOpacity>
            </HStack>
          )}
        </HStack>
      ) : (
        <BrowserNavBarHeader
          title={formatMessage(
            messages[
              `${currentScreen as 'BrowserTabs' | 'BrowserBookmarks' | 'BrowserHistory'}ScreenTitle`
            ],
            { tabs: tabs.length },
          )}
        />
      )}
      {isSearching && (
        <VStack flexGrow={1} height="100%" background>
          <KeyboardAvoidingView>
            <SearchSuggestions
              query={debouncedInput}
              suggestions={suggestions}
              historySuggestions={historySuggestions}
              onUnmount={handleResetSearchSuggestions}
            />
          </KeyboardAvoidingView>
        </VStack>
      )}
    </VStack>
  );
});

