import { ICON_SIZE, ICON_SPACING } from './constants';

const messages = defineMessages({
  a11yLabel: {
    defaultMessage: 'Manage tabs',
    description: 'Tab buttons accessibility label',
  },
});

export const TabsButton = memo(function TabsButton() {
  const { formatMessage } = useIntl();
  const { foreground } = usePalette();
  const { tabs } = useBrowserTabs();
  const { minimizeWebViewAndJumpTo, currentScreen } = useBrowserTabNavigation();
  const platformSpecificBrowserHomeScreen = usePlatformSpecificBrowserHomeScreen();
  const hasZeroTabs = useMemo(() => tabs.length === 0, [tabs]);
  const numTabs = useMemo(() => tabs.length, [tabs.length]);

  const boxStyle: StyleProp<ViewStyle> = useMemo(
    () => ({
      borderColor: foreground,
      borderWidth: 2,
      borderRadius: 4,
      display: 'flex',
      height: 18,
      width: 18,
      alignItems: 'center',
      justifyContent: 'center',
    }),
    [foreground],
  );

  const textStyle: StyleProp<TextStyle> = useMemo(
    () => ({
      width: 16,
      textAlign: 'center',
      color: foreground,
      lineHeight: 14,
      fontSize: hasZeroTabs ? 13 : 10,
    }),
    [foreground, hasZeroTabs],
  );

  const onPress = useCallback(() => {
    minimizeWebViewAndJumpTo('BrowserTabs');
  }, [minimizeWebViewAndJumpTo]);

  const tabIconContent = useMemo(() => {
    if (hasZeroTabs) return '+';
    return numTabs > 99 ? '💥' : numTabs;
  }, [hasZeroTabs, numTabs]);

  return (
    <AutoHitSlopWrapper>
      <CustomIconPressable
        onPress={onPress}
        disabled={
          platformSpecificBrowserHomeScreen === 'BrowserTabs' && currentScreen === 'BrowserTabs'
        }
        testID="browser-tabs-button"
        size={ICON_SIZE}
        spacingHorizontal={ICON_SPACING}
        accessibilityLabel={formatMessage(messages.a11yLabel)}
      >
        <View style={boxStyle}>
          <Text style={textStyle} allowFontScaling={false}>
            {tabIconContent}
          </Text>
        </View>
      </CustomIconPressable>
    </AutoHitSlopWrapper>
  );
});

