import { memo, useCallback } from 'react';
import { Pressable, ScrollView } from 'react-native';
import { SolanaWeb3Response } from 'cb-wallet-solana-provider/src/types';
import { Box } from '@cbhq/cds-mobile/layout';
import { PortalProvider } from '@cbhq/cds-mobile/overlays/PortalProvider';

import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { Modal } from ':rn/cds-wallet/components/Modal/Modal';
import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { logBrowserResponse } from ':rn/screens/Browser/analytics/browserWeb3';
import { useBrowserNetworkSwitcher } from ':rn/screens/Browser/hooks/useBrowserNetworkSwitcher';
import { useDialogQueue } from ':rn/screens/Browser/hooks/useDialogQueue';
import { useOpenBrowserNuxFundingTray } from ':rn/screens/Browser/hooks/useOpenBrowserNuxFundingTray';
import { useWeb3 } from ':rn/screens/Browser/hooks/useWeb3';
import { Web3DialogErrorFallback } from ':rn/shared/components/Web3/Web3DialogErrorFallback';
import { Web3CallResponse } from ':rn/shared/types/web3Types';

import { BrowserNetworkSwitcher } from '../BrowserNetworkSwitcher/BrowserNetworkSwitcher';

const messages = { genericCancellation: 'User rejected request' };

export const Web3Dialogs = memo(function Web3Dialogs() {
  const { evmWallet, onResponse, dappMetadata: metadata } = useWeb3();
  const { currentDialog, clearCompletedDialog } = useDialogQueue();
  const { switchingNetwork, hideNetworkSwitcher } = useBrowserNetworkSwitcher();

  useOpenBrowserNuxFundingTray();

  const handleCancel = useCallback(
    function handleCancel() {
      if (!currentDialog?.data || currentDialog.type === 'browserNuxFundingTray') {
        return;
      }

      let errorData;
      const errorMessage = messages.genericCancellation;
      switch (currentDialog.data.request.method) {
        case 'signEthereumMessage':
          logBrowserResponse({
            method: 'signEthereumMessage',
            blockchain: 'ETH',
            userAction: 'deny',
            metadata,
          });
          break;
        case 'signEthereumTransaction':
          logBrowserResponse({
            method: 'signEthereumTransaction',
            blockchain: 'ETH',
            userAction: 'deny',
            metadata,
          });
          break;
        case 'addEthereumChain':
          logBrowserResponse({
            method: 'addEthereumChain',
            blockchain: 'ETH',
            userAction: 'deny',
            metadata,
            chainId: currentDialog.data?.request.params.chainId as string,
          });
          break;
        case 'watchAsset':
          logBrowserResponse({
            method: 'watchAsset',
            blockchain: 'ETH',
            userAction: 'deny',
            metadata,
          });
          break;
        case 'signMessage':
          errorData = {
            action: SolanaWeb3Response.web3RequestCanceled,
          };
          logBrowserResponse({
            method: 'signMessage',
            blockchain: 'SOL',
            userAction: 'deny',
            metadata,
          });
          break;
        case 'signTransaction':
          errorData = {
            action: SolanaWeb3Response.web3RequestCanceled,
          };
          logBrowserResponse({
            method: 'signTransaction',
            blockchain: 'SOL',
            userAction: 'deny',
            metadata,
          });
          break;
        case 'sendTransaction':
          errorData = {
            action: SolanaWeb3Response.web3RequestCanceled,
          };
          logBrowserResponse({
            method: 'sendTransaction',
            blockchain: 'SOL',
            userAction: 'deny',
            metadata,
          });
          break;
        case 'signAllTransactions':
          errorData = {
            action: SolanaWeb3Response.web3RequestCanceled,
          };
          logBrowserResponse({
            method: 'signAllTransactions',
            blockchain: 'SOL',
            userAction: 'deny',
            metadata,
          });
          break;
        case 'relayNFCPaymentRequest':
          logBrowserResponse({
            method: 'relayNFCPaymentRequest',
            blockchain: 'ETH',
            userAction: 'deny',
            metadata,
          });
          break;
        default:
          logBrowserResponse({
            method: currentDialog.data.request.method,
            blockchain: 'unknown',
            userAction: 'deny',
            metadata,
          });
          throw new Error('Attempted to return error message for unsupported web3 method');
      }

      onResponse(
        { id: currentDialog.data.id, errorMessage, errorData, errorCode: 4001 },
        currentDialog.data.request.method,
      );
    },
    [currentDialog?.data, currentDialog?.type, metadata, onResponse],
  );

  const cancelAndCloseConfirmationDialog = useCallback(
    function cancelAndCloseConfirmationDialog() {
      handleCancel();
      clearCompletedDialog();
    },
    [clearCompletedDialog, handleCancel],
  );

  const handleConfirm = useCallback(
    function handleConfirm(data?: Web3CallResponse) {
      if (!currentDialog) {
        return;
      }

      let supported = true;
      switch (currentDialog.type) {
        case 'signEthereumMessage':
          logBrowserResponse({
            method: 'signEthereumMessage',
            blockchain: 'ETH',
            userAction: 'confirm',
            metadata,
          });
          break;
        case 'signEthereumTransaction':
          logBrowserResponse({
            method: 'signEthereumTransaction',
            blockchain: 'ETH',
            userAction: 'confirm',
            metadata,
          });
          break;
        case 'addEthereumChain':
          logBrowserResponse({
            method: 'addEthereumChain',
            blockchain: 'ETH',
            userAction: 'confirm',
            metadata,
            chainId: currentDialog.data?.request.params.chainId as string,
          });
          break;
        case 'watchAsset':
          logBrowserResponse({
            method: 'watchAsset',
            blockchain: 'ETH',
            userAction: 'confirm',
            metadata,
          });
          break;
        case 'signMessage':
          logBrowserResponse({
            method: 'signMessage',
            blockchain: 'SOL',
            userAction: 'confirm',
            metadata,
          });
          break;
        case 'signTransaction':
          logBrowserResponse({
            method: 'signTransaction',
            blockchain: 'SOL',
            userAction: 'confirm',
            metadata,
          });
          break;
        case 'sendTransaction':
          logBrowserResponse({
            method: 'sendTransaction',
            blockchain: 'SOL',
            userAction: 'confirm',
            metadata,
          });
          break;
        case 'signAllTransactions':
          logBrowserResponse({
            method: 'signAllTransactions',
            blockchain: 'SOL',
            userAction: 'confirm',
            metadata,
          });
          break;
        case 'relayNFCPaymentRequest':
          logBrowserResponse({
            method: 'relayNFCPaymentRequest',
            blockchain: 'ETH',
            userAction: 'confirm',
            metadata,
          });
          break;
        default:
          supported = false;
          logBrowserResponse({
            method: currentDialog.data?.request.method ?? 'unknown',
            blockchain: 'unknown',
            userAction: 'confirm',
            metadata,
          });
      }
      if (supported && currentDialog.data) {
        onResponse(data!, currentDialog.data.request.method);
        clearCompletedDialog();
      }
    },
    [clearCompletedDialog, currentDialog, metadata, onResponse],
  );

  return (
    <>
      {!!currentDialog &&
        (currentDialog.fullscreen ? (
          <Modal
            hideDividers
            visible
            onRequestClose={cancelAndCloseConfirmationDialog}
            testID="web3-dialog-fullscreen-modal"
          >
            <PortalProvider>
              <Box flexGrow={1} flexShrink={1} justifyContent="space-between">
                <ErrorBoundary
                  context="web3-dialogs"
                  errorFallback={
                    <Web3DialogErrorFallback
                      onPressTryAgain={cancelAndCloseConfirmationDialog}
                      fullscreen
                    />
                  }
                >
                  <currentDialog.component
                    wallet={evmWallet}
                    data={currentDialog.data}
                    metadata={metadata}
                    onConfirm={handleConfirm}
                    onDismiss={cancelAndCloseConfirmationDialog}
                  />
                </ErrorBoundary>
              </Box>
            </PortalProvider>
          </Modal>
        ) : (
          <Tray
            onCloseComplete={cancelAndCloseConfirmationDialog}
            disableCapturePanGestureToDismiss
            verticalDrawerPercentageOfView={0.9}
            testID="web3-dialog-tray"
          >
            {({ handleClose }) => {
              const { component: ConfirmationDialog, data } = currentDialog;
              return (
                <PortalProvider>
                  <ScrollView testID="web3-dialog-tray-scrollview">
                    <Pressable accessibilityRole="button">
                      <ErrorBoundary
                        context="web3-dialogs"
                        errorFallback={
                          <Web3DialogErrorFallback
                            onPressTryAgain={cancelAndCloseConfirmationDialog}
                          />
                        }
                      >
                        {/* eslint-disable-next-line @cbhq/react-no-nested-component */}
                        <ConfirmationDialog
                          wallet={evmWallet}
                          data={data}
                          metadata={metadata}
                          onConfirm={handleConfirm}
                          onDismiss={handleClose}
                          launchBuyFlow={currentDialog?.launchBuyFlow}
                          activeChainId={currentDialog?.activeChainId}
                        />
                      </ErrorBoundary>
                    </Pressable>
                  </ScrollView>
                </PortalProvider>
              );
            }}
          </Tray>
        ))}
      {!!switchingNetwork && <BrowserNetworkSwitcher onCloseComplete={hideNetworkSwitcher} />}
    </>
  );
});

