import { memo, useCallback, useMemo, useRef } from 'react';
import { Animated, Easing, ImageBackground, StyleProp, ViewStyle } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { getFavicon } from 'cb-wallet-data/utils/getFavicon';
import URLParse from 'url-parse';
import { curves, durations } from '@cbhq/cds-common/motion/tokens';
import { Icon } from '@cbhq/cds-mobile/icons/Icon';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable, PressableOpacity } from '@cbhq/cds-mobile/system';
import { TextLegal } from '@cbhq/cds-mobile/typography';

import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { AutoHitSlopWrapper } from ':rn/cds-wallet/components/interactables/AutoHitSlopWrapper';
import { RemoteFaviconImage } from ':rn/cds-wallet/components/RemoteFaviconImage/RemoteFaviconImage';
import { useBrowserTabNavigation } from ':rn/screens/Browser/hooks/useBrowserTabNavigation';
import { Tab } from ':rn/screens/Browser/types/LinkDataTypes';
import { useDimensions } from ':rn/shared/hooks/useDimensions';

import { BrowserTabItemIcon } from './BrowserTabItemIcon';

export const NEW_TAB_PLACEHOLDER = { id: 'NEW_TAB_PLACEHOLDER', url: '' };
const ROW_HEIGHT = 190;
const IMAGE_STYLE = { height: ROW_HEIGHT + 72 };
const EDGE_GUTTER_WIDTH = 24;
const CENTER_GUTTER_WIDTH = 16;
const TABS_PER_ROW = 2;

const messages = defineMessages({
  newTabA11yLabel: {
    defaultMessage: 'New tab',
    description: 'Browser new tab accessibility label',
  },
  tabA11yLabel: {
    defaultMessage: 'Tab {name}',
    description: 'Browser tab accessibility label',
  },
  closetabA11yLabel: {
    defaultMessage: 'Close {name} tab',
    description: 'Browser close tab accessibility label',
  },
});

type BrowserTabItemProps = {
  id: string;
  url: string;
  image: Tab['image'];
  handleRemoveTab: () => void;
  index?: number;
};

export const BrowserTabItem = memo(function BrowserTabItem({
  url,
  image,
  handleRemoveTab,
  id,
  index,
}: BrowserTabItemProps) {
  const { formatMessage } = useIntl();
  const animated = useRef(new Animated.Value(1)).current;
  const { screenWidth } = useDimensions();
  const tabWidth = useMemo(
    () => (screenWidth - EDGE_GUTTER_WIDTH * 2 - CENTER_GUTTER_WIDTH) / TABS_PER_ROW,
    [screenWidth],
  );
  const isTabPlaceholder = useMemo(() => id === NEW_TAB_PLACEHOLDER.id, [id]);

  const source = useMemo(() => ({ uri: `data:image/png;base64,${image?.uri}` }), [image]);
  const { openUrlInWebView, search } = useBrowserTabNavigation();

  const onRemoveTab = useCallback(() => {
    Animated.timing(animated, {
      toValue: 0,
      duration: durations.moderate2,
      easing: Easing.bezier(...curves.global),
      useNativeDriver: true,
    }).start(() => handleRemoveTab());
  }, [animated, handleRemoveTab]);

  const onPressTab = useCallback(
    function onPressTab() {
      Animated.timing(animated, {
        toValue: 2,
        duration: durations.moderate2,
        easing: Easing.bezier(...curves.global),
        useNativeDriver: true,
      }).start(() => {
        // Resetting the animation inside of here without a setTimeout causes an infinite loop
        setImmediate(() => animated.setValue(1));
      });
      // Using setTimeouts as a way to continue the animation after the WebView opens
      // otherwise there is a short pause after animation completes and it looks bad
      setTimeout(
        () =>
          isTabPlaceholder ? search() : openUrlInWebView({ url, tabId: id, type: 'browser_tab' }),
        durations.moderate2 / 2,
      );
    },
    [animated, isTabPlaceholder, search, openUrlInWebView, url, id],
  );

  const rowStyles = useMemo(
    () => [
      {
        opacity: animated.interpolate({
          inputRange: [0, 1, 2],
          outputRange: [0, 1, 0],
          extrapolate: 'clamp',
        }),
        transform: [
          {
            scale: animated.interpolate({
              inputRange: [0, 1, 2],
              outputRange: [0, 1, 1.2],
              extrapolate: 'clamp',
            }),
          },
        ],
        zIndex: animated.interpolate({
          inputRange: [0, 1, 2],
          outputRange: [1, 1, 100],
          extrapolate: 'clamp',
        }),
      },
      {
        display: 'flex',
        flexshrink: 0,
        margin: 8,
      },
    ],
    [animated],
  );

  const hostname = useMemo(() => URLParse(url).hostname, [url]);

  const fallbackFavicon = useMemo(() => {
    return `https://${hostname}/favicon.ico`;
  }, [hostname]);

  const largeFaviconUrl = useMemo(() => {
    return getFavicon({ url, faviconQuality: 64 }) ?? fallbackFavicon;
  }, [url, fallbackFavicon]);

  const smallFaviconUrl = useMemo(() => {
    return getFavicon({ url, faviconQuality: 16 }) ?? fallbackFavicon;
  }, [url, fallbackFavicon]);

  return (
    <Animated.View style={rowStyles as Animated.WithAnimatedObject<ViewStyle>}>
      <Box alignItems="center">
        <PressableOpacity
