export const OnrampEntryContent = memo(function OnrampEntryContent() {
  const { formatMessage } = useIntl();
  const isSmallScreen = useIsSmallScreen();
  const { pop } = useStackNavigation<BuyParamList>();
  const {
    amount = '0',
    fiatCurrency,
    sourceWallet,
    selectedAsset,
    selectedProvider,
    formattedCryptoAmount,
    selectedPaymentMethod,
    hideQuotePreview,
    isQuotePreviewVisible,
    isExternalProviderWebviewVisible,
    toggleIsExternalProviderWebviewVisible,
    is3rdPartyLegalNoticeModalVisible,
    toggleIs3rdPartyLegalNoticeModalVisible,
    setOnrampErrorMessage,
  } = useOnrampContext();

  const userFacingError = useOnrampUserFacingError();

  const [isMoreOptionTrayVisible, { toggleOn: showMoreOptionTray, toggleOff: hideMoreOptionTray }] =
    useToggler(false);

  const spacings = useMemo<Record<string, SpacingScale>>(() => {
    return {
      gap: isSmallScreen ? 0 : 1,
      spacingVertical: isSmallScreen ? 0 : 2,
      secondaryAmountHeightOverride: (isSmallScreen ? 20 : 25) as SpacingScale,
    };
  }, [isSmallScreen]);

  const secondaryAmount = useMemo(() => formattedCryptoAmount, [formattedCryptoAmount]);

  // if formattedCryptoAmount is not available
  // then we are loading the secondary amount
  const isLoadingSecondaryAmount = useMemo(() => {
    return !formattedCryptoAmount;
  }, [formattedCryptoAmount]);

  const handleMoreOptionPress = useCallback(() => {
    logOnrampMoreOptionClicked();
    showMoreOptionTray();
  }, [showMoreOptionTray]);

  const handleAmountInputPress = useCallback(() => {
    return isQuotePreviewVisible ? hideQuotePreview() : undefined;
  }, [hideQuotePreview, isQuotePreviewVisible]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      title: formatMessage(messages.title),
      left: 'back',
      handleLeft: () => {
        if (isQuotePreviewVisible) {
          hideQuotePreview();
          setOnrampErrorMessage(undefined);
        } else {
          logOnrampExit();
          pop();
        }
      },
      right: (
        <IconButton
          name="more"
          onPress={handleMoreOptionPress}
          transparent
          testID="onramp-more-options-button"
        />
      ),
    }),
    [
      formatMessage,
      handleMoreOptionPress,
      hideQuotePreview,
      isQuotePreviewVisible,
      pop,
      setOnrampErrorMessage,
    ],
  );

  useEffect(
    function hideQuotePreviewAfterChanges() {
      hideQuotePreview();
    },
    [selectedProvider, selectedAsset, selectedPaymentMethod, hideQuotePreview],
  );

  useLogOnrampEntryViewed();

  useFocusEffect(
    useCallback(() => {
      markJourney('loaded_onramp_entry');
    }, []),
  );

  return (
    <Screen
      full
      scrollableWithFlexGrow
      navBar={navBar}
      scrollable={isSmallScreen}
      testID="onramp-entry-screen"
    >
      <VStack spacingHorizontal={3} flexGrow={1} justifyContent="center">
        <PressableOpacity noScaleOnPress onPress={handleAmountInputPress}>
          <AmountInput
            isFiat
            wallet={sourceWallet}
            primaryAmount={amount}
            secondaryAmount={secondaryAmount}
            type={AmountInputType.BUY}
            isSmallScreen={isSmallScreen}
            txType={GasEstimateTxType.BUY}
            activeFiatCurrency={fiatCurrency}
            allowChangeToFiat={false}
            isLoadingSecondaryAmount={isLoadingSecondaryAmount}
            secondaryAmountHeightOverride={spacings.secondaryAmountHeightOverride}
          />
        </PressableOpacity>

        <HStack minHeight={25} alignItems="center">
          {userFacingError.messageComponent}
        </HStack>
      </VStack>

      <VStack
        spacingVertical={spacings.spacingVertical}
        borderedVertical
        alignContent="center"
        justifyContent="center"
      >
        <OnrampEntryNetworkSelector />

        <OnrampEntryAssetSelector />

        <Box
          accessible
          spacingStart={0}
          offsetVertical={1}
          accessibilityLabel={formatMessage(messages.arrowDownAccessibilityLabel)}
        >
          <Icon name="verticalLine" size="s" spacingStart={4} color="foregroundMuted" />
        </Box>

        <OnrampEntryPaymentMethodSelector />
      </VStack>

      {!isQuotePreviewVisible ? <OnrampEntryValues /> : <OnrampEntryQuotePreview />}

      <ExternalProviderWebviewTray
        visible={isExternalProviderWebviewVisible}
        toggleOff={toggleIsExternalProviderWebviewVisible}
      />

      <OnrampThirdPartyLegalNoticeModal
        visible={is3rdPartyLegalNoticeModalVisible}
        onClose={toggleIs3rdPartyLegalNoticeModalVisible}
      />

      <OnrampMoreOptionTray visible={isMoreOptionTrayVisible} toggleOff={hideMoreOptionTray} />
    </Screen>
  );
});

