import { useEffect, useMemo } from 'react';
import { KeyboardAvoidingView, Platform } from 'react-native';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { RemoteImage } from '@cbhq/cds-mobile/media';
import { ThemeProvider } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';
import { markJourney } from '@cbhq/core-vitals-mobile';

import { ScrollableTray } from ':rn/cds-wallet/components/ScrollableTray/ScrollableTray';
import { useOnrampContext } from ':rn/screens/Buy/contexts/OnrampContext';
import { useExternalProviderLauncher } from ':rn/shared/coinbase-connect/hooks/useExternalProviderLauncher';
import { useDimensions } from ':rn/shared/hooks/useDimensions';

import { TransakWidgetWebview } from './TransakWidgetWebview';

const EXTERNAL_PROVIDER_TRAY_TOP_OFFSET = 40;
const EXTERNAL_PROVIDER_TRAY_ICON_WIDTH = 40;

export type ExternalProviderWebviewTrayProps = {
  visible: boolean;
  toggleOff: () => void;
};

export function ExternalProviderWebviewTray({
  visible,
  toggleOff,
}: ExternalProviderWebviewTrayProps) {
  const { screenHeight } = useDimensions();
  const launchExternalProviderLauncher = useExternalProviderLauncher();

  const {
    selectedAsset,
    sanitizedAmount,
    checkoutSession,
    selectedProvider,
    selectedPaymentMethod,
  } = useOnrampContext();

  const isVisible = useMemo(() => {
    return Boolean(visible && selectedAsset);
  }, [selectedAsset, visible]);

  useEffect(
    function launchExternalProviderIABIfRequired() {
      if (isVisible && checkoutSession?.checkoutUrl) {
        launchExternalProviderLauncher(checkoutSession.checkoutUrl, toggleOff);
      }
    },
    [checkoutSession?.checkoutUrl, isVisible, launchExternalProviderLauncher, toggleOff],
  );

  useEffect(
    function markJourneyOnVisible() {
      if (isVisible) {
        markJourney('loaded_onramp_external_provider');
      }
    },
    [isVisible],
  );

  if (!visible || !selectedAsset) return null;

  // If the provider requires a checkout session, we should use IAB
  if (selectedProvider?.checkoutSessionRequired) return null;

  // Otherwise, we should use the webview tray implementation (Transak)
  return (
    <ThemeProvider name="external-provider-widget" spectrum="light">
      <ScrollableTray
        testID="provider-selector-tray"
        disableCapturePanGestureToDismiss
        verticalDrawerPercentageOfView={0.9}
        onCloseComplete={toggleOff}
      >
        {({ handleClose }) => {
          const webview = (
            <VStack
              height={(screenHeight / 4) * 3.5 - EXTERNAL_PROVIDER_TRAY_TOP_OFFSET}
              offsetTop={2}
            >
              <HStack
                gap={1}
                borderedBottom
                alignItems="center"
                spacingVertical={1}
                spacingHorizontal={2}
                justifyContent="space-between"
                background="backgroundAlternate"
              >
                <Box width={EXTERNAL_PROVIDER_TRAY_ICON_WIDTH} />
                <HStack gap={1} alignItems="center">
                  <RemoteImage
                    width={36}
                    height={36}
                    resizeMode="contain"
                    source={selectedProvider?.imageUrl}
                  />
                  <TextBody color="foreground">{selectedProvider?.name}</TextBody>
                </HStack>
                <IconButton name="close" onPress={toggleOff} />
              </HStack>
              {/*
               * We're still loading the transak webview manually here because we didn't enable a backend-driven.
               * checkoutSession for Transak yet. Once we do, we can remove this and use the above webview instead.
               * */}
              <TransakWidgetWebview
                asset={selectedAsset}
                amount={sanitizedAmount}
                close={handleClose}
                paymentMethod={selectedPaymentMethod?.providerPaymentMethodId}
              />
            </VStack>
          );

          // For iOS we don't need to handle keyboard avoiding view because it already works out by default
          if (Platform.OS === 'ios') {
            return webview;
          }

          // For Android we need to ensure the keyboard avoid view configs below,
          // otherwise the webview fields will be hidden by the keyboard
          return (
            <KeyboardAvoidingView behavior="height" keyboardVerticalOffset={100}>
              {webview}
            </KeyboardAvoidingView>
          );
        }}
      </ScrollableTray>
    </ThemeProvider>
  );
}

import { memo, useCallback, useMemo } from 'react';
