const messages = defineMessages({
  contractAddressAccessibilityLabel: {
    defaultMessage: 'Open contract link in the browser',
    description: 'Contract address link accessibility label',
  },
});

type Props = {
  selected: boolean;
  asset: OnrampAsset;
  onItemSelected: (asset: OnrampAsset) => void;
};

function OnrampAssetCellComponent({ selected, asset, onItemSelected }: Props) {
  const { formatMessage } = useIntl();

  const onPress = useCallback(() => {
    onItemSelected(asset);
  }, [onItemSelected, asset]);

  const shouldShowNetworkIcon = useMemo(() => {
    return asset.isLayer2Network() || asset.isSolanaNetwork();
  }, [asset]);

  const action = useMemo(() => {
    if (!asset.swappable && !asset.isMgx) {
      return null;
    }

    const blockExplorerUrl = getBlockExplorerUrl(asset);

    return blockExplorerUrl ? (
      <HStack alignItems="center">
        <TextBody color="foregroundMuted" testID="onramp-swap-asset-contract-address">
          {getTruncatedAddress(asset.contractAddress || '')}
        </TextBody>
        <Link
          to={blockExplorerUrl}
          accessibilityLabel={formatMessage(messages.contractAddressAccessibilityLabel)}
        >
          <Box spacingVertical={2} spacingStart={2}>
            <Icon
              name="externalLink"
              color="foreground"
              size="s"
              testID="onramp-swap-asset-external-link"
            />
          </Box>
        </Link>
      </HStack>
    ) : null;
  }, [asset, formatMessage]);

  return (
    <AssetListCell
      id={asset.id}
      name={asset.name}
      onPress={onPress}
      selected={selected}
      network={asset.network}
      description={asset.code}
      testID={`${asset.id}-asset-cell`}
      currencyCode={asset.code}
      imageUrl={asset.imageUrl || undefined}
      showNetworkIcon={shouldShowNetworkIcon}
      action={action}
    />
  );
}

