    [currencyFormatter],
  );

  return (
    <ButtonGroup accessibilityLabel="Onramp suggested funding options">
      <Button
        compact
        variant="secondary"
        onPress={handlePressOptionButton(FIRST_OPTION)}
        testID="first-suggested-option-button"
      >
        <TextBody align="center">{getFormattedCryptoAmount(FIRST_OPTION)}</TextBody>
      </Button>
      <Button
        compact
        variant="secondary"
        onPress={handlePressOptionButton(SECOND_OPTION)}
        testID="second-suggested-option-button"
      >
        <TextBody align="center">{getFormattedCryptoAmount(SECOND_OPTION)}</TextBody>
      </Button>
      <Button
        compact
        variant="secondary"
        onPress={handlePressOptionButton(THIRD_OPTION)}
        testID="third-suggested-option-button"
