type Props = {
  wallet: Wallet;
  transaction: UnsignedTx;
  withdrawalAccount: WithdrawalAccount;
  destination: GetRetailAddressResponse;
};

const QuoteRefetchInterval = 4000;

function getUserEnteredAmount(wallet: Wallet, transaction: UnsignedTx) {
  return {
    currency: wallet.currencyCode.rawValue,
    value: toDecimal(transaction.transferValue, wallet.decimals)?.toString() ?? '0',
  };
}

function CashoutConfirmation({ transaction, withdrawalAccount, wallet, destination }: Props) {
  const { currency, value } = getUserEnteredAmount(wallet, transaction);
  const { setTransactionInfo: setSendTransactionContext, refreshUnsignedTx } =
    useTransactionContext();
  const {
    data,
    isLoading: isLoadingQuote,
    isSuccess: isQuoteFetched,
    fiatRate,
  } = useCreateCashout(
    {
      fromAddress: transaction.fromAddress,
      amount: {
        currency,
        value,
      },
      assetCode: transaction.currencyCode.value,
      networkId: wallet.network.asChain()?.wacNetworkId ?? '',
      provider: {
        name: 'simple_trade',
        accountId: destination.accountUuid,
        paymentMethod: withdrawalAccount.uuid,
        id: SIMPLE_TRADE_PROVIDER,
      },
      withdrawalCurrencyCode: withdrawalAccount.currency,
    },
    QuoteRefetchInterval,
  );

  const { formatMessage, formatNumber } = useIntl();
  const { goBack, popStack, replace, navigate } = useStackNavigation<CashoutParamList>();
  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useTxFeeWallet(activeWalletGroupId, transaction);
  const [isConfirmTxVisible, { toggleOff: closeFraudWarningConfirmationTray }] = useToggler(false);
  const { commitCashout } = useCommitCashout();
  const saveTransaction = useSaveTransactions();
  const authState = useRecoilValue(authStateAtom);

  const { isLoading: isLoadingGasFee, lastUpdateTime } = useRealtimeGasFee({
    wallet,
    refreshUnsignedTx,
    isSponsoredTx: false,
  });
  const transactionCost = useNetworkFee({ wallet, transaction, hideTotalCost: false });
  const transactionDetailRows = useTransactionDetailRowItems({
    transactionCost,
    cashoutFees: data?.cashout.quote.fees,
    isGasFeeLoading: isLoadingGasFee,
    GasPaymentMethod: <GasPaymentMethod feeWallet={feeWallet} />,
    lastUpdateTime,
    fiatAmount: data?.cashout.quote.cashoutFiatAmount,
    fiatRate,
  });

  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx: transaction,
    feeWallet,
    flow: 'cashout',
    isTxSponsored: false,
  });

  useCashoutConfirmationViewed({
    currencyCode: wallet.currencyCode.rawValue,
    chainId: wallet.network.asChain()?.chainId,
    networkName: wallet.network.asChain()?.displayName,
    network: wallet.network.asChain()?.wacNetworkId,
    type: withdrawalAccount.type,
  });
  useJourneyMarkOnMount('loaded_cashout_preview');

  const handleLeft = useCallback(() => {
    logCashoutConfirmationBack();
    goBack();
  }, [goBack]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      title: formatMessage(messages.screenTitle),
      left: 'back',
      handleLeft,
    }),
    [formatMessage, handleLeft],
  );

  const onSignSuccess = useCallback(
    async function startTxTimer({ signedTx }: SignTxSuccess) {
      if (!signedTx?.signedTxData || !data?.cashout.quote || !data?.cashout.idem) return;
      logCashoutConfirmationConfirmPressed({
        currencyCode: wallet.currencyCode.rawValue,
        chainId: wallet.network.asChain()?.chainId,
        networkName: wallet.network.asChain()?.displayName,
        network: wallet.network.asChain()?.wacNetworkId,
        type: withdrawalAccount.type,
        networkFee: transactionCost.amount,
      });
      markJourney('navigate_to_cashout_status');
      const hexString = ensureHexString(hexFromBuffer(signedTx?.signedTxData), true);
      const { gasLimit, gasPrice } = getGasPriceAndLimit(transaction);

      const cashoutTx = await createCashoutTransaction({
        transaction,
        signedTxHash: signedTx.txHash,
        nonce: signedTx.nonce,
        wallet,
        quote: data.cashout.quote,
        idem: data.cashout.idem,
      });

      commitCashout(
        {
          idem: data?.cashout.idem ?? '',
          provider: SIMPLE_TRADE_PROVIDER,
          gasLimit,
          gasPrice,
          signedTxHex: hexString,
        },
        {
          onSuccess({ cashout: commitCashoutSuccess }) {
            newTimer(createSubmitTimerName(signedTx.txHash));
            saveTransaction([cashoutTx]);
            replace('CashoutStatus', {
              idem: commitCashoutSuccess.idem,
              provider: SIMPLE_TRADE_PROVIDER,
              destination,
              withdrawalAccount,
            });
          },
          onError(error) {
            const err = coerceError(error, 'Error while committing transaction');
            cbReportError({
              error: err,
              severity: 'error',
              isHandled: false,
              context: 'cashout',
            });
            navigate('CashoutError', { error });
          },
        },
      );
    },
    [
      commitCashout,
      data?.cashout.idem,
      data?.cashout.quote,
      destination,
      navigate,
      replace,
      saveTransaction,
      transaction,
      transactionCost.amount,
      wallet,
      withdrawalAccount,
    ],
  );

  const onSignError = useCallback(
    (err: Error) => {
      setSendTransactionContext((prev) => ({
        ...prev,
        error: err,
        success: undefined,
      }));
      const error = coerceError(err, 'Error signing transaction');
      cbReportError({
        error,
        severity: 'error',
        isHandled: false,
        context: 'cashout',
      });
    },
    [setSendTransactionContext],
  );

  // With Cashouts we will be submitting the transaction in offramp-service so this hook will only sign and not submit the transaction
  const { confirmAndSubmit: confirmAndSign, isSubmissionLoading: isSigningLoading } =
    useConfirmSignAndSubmit({
      wallet,
      transaction,
      onDismiss: popStack,
      closeFraudWarningConfirmationTray,
      shouldSubmit: false,
      flow: 'cashout',
      isTxSponsored: false,
      onSignSuccess,
      onSignError,
    });

  const handleConfirm = useCallback(() => {
    if (authState?.appLockType === 'biometrics') {
      markJourney('navigate_to_complete_biometrics');
    } else {
      markJourney('navigate_to_enter_passcode');
    }

    confirmAndSign();
  }, [authState?.appLockType, confirmAndSign]);

  const cancelCashout = useCallback(() => {
    logCashoutConfirmationCancelPressed();
    popStack();
  }, [popStack]);

  const isSubmitLoading = useMemo(
    () => isSigningLoading || isLoadingQuote || isLoadingGasFee,
    [isLoadingGasFee, isLoadingQuote, isSigningLoading],
  );

  if (!isQuoteFetched || !data) {
    return <></>;
  }

  return (
    <Screen navBar={navBar} full>
      {!isConfirmTxVisible && (
        <Box flexGrow={1}>
          <ScrollView>
            <CashoutDetailsCard
              wallet={wallet}
              transaction={transaction}
              withdrawalAccount={withdrawalAccount}
              cashoutAmount={data?.cashout.quote.cashoutFiatAmount}
              exchangeRate={data?.cashout.quote.unitPrice.targetToFiat.amount}
            />
            <VStack spacingHorizontal={3} spacingTop={1}>
              <HStack
                justifyContent="space-between"
                alignItems="flex-start"
                gap={2}
                spacingBottom={1}
              >
                <HStack justifyContent="flex-start" alignItems="center" flexShrink={5}>
                  <TextBody color="foreground">
                    {formatMessage(messages.priceLabel, {
                      currencyCode: wallet.currencyCode.rawValue,
                    })}
                  </TextBody>
                  <TooltipIcon
                    content={
                      <CashoutPriceDetails
                        quote={data?.cashout.quote}
                        wallet={wallet}
                        transaction={transaction}
                      />
                    }
                    iconName="info"
                    testID="cashout-price-details"
                  />
                </HStack>
                <HStack justifyContent="flex-start" alignItems="flex-start" flexShrink={1}>
                  <TextBody color="foregroundMuted">
                    {formatNumber(Number(data.cashout.quote.unitPrice.targetToFiat.amount.value), {
                      style: 'currency',
                      currency: data.cashout.quote.unitPrice.targetToFiat.amount.currency,
                    })}
                  </TextBody>
                </HStack>
              </HStack>
              <SwapTransactionDetails transactionDetailRowItems={transactionDetailRows} />
            </VStack>
          </ScrollView>
          <VStack flexShrink={0} spacingTop={1} borderedTop>
            <Box spacingHorizontal={2}>
              {transactionDetailsErrors && (
                <VStack spacingBottom={1}>
                  <TextLegal align="center" color="negative">
                    {transactionDetailsErrors.message}
                  </TextLegal>
                </VStack>
              )}
              <ButtonGroup accessibilityLabel={formatMessage(messages.ctaGroup)} block>
                <Button
                  variant="secondary"
                  onPress={cancelCashout}
                  disabled={isSubmitLoading}
                  testID="sign-transaction-cancel-button"
                >
                  {formatMessage(messages.cancel)}
                </Button>
                <Button
                  disabled={transactionDetailsErrors?.isDisabled}
                  loading={isSubmitLoading}
                  onPress={handleConfirm}
                  testID="sign-transaction-confirm-button"
                >
                  {formatMessage(messages.confirmSendButton)}
                </Button>
              </ButtonGroup>
              <PoweredByCoinbase />
            </Box>
          </VStack>
        </Box>
      )}
    </Screen>
  );
}

function CashoutConfirmationWithBoundary() {
  const { withdrawalAccount, destination } = useParams<CashoutParamList, 'CashoutConfirmation'>();
  const { transactionInfo: sendContext, resetAdjustableGasParams } = useTransactionContext();

  if (!sendContext.unsignedTransaction) {
    throw new Error('CashoutConfirmation: missing unsignedTransaction.');
  }

  if (!sendContext.unsignedTransaction.wallet) {
    throw new Error('CashoutConfirmation: unsignedTransaction missing wallet.');
  }

  if (!sendContext.unsignedTransaction.transaction) {
    throw new Error('CashoutConfirmation: unsignedTransaction missing transaction.');
  }

  if (!destination || !withdrawalAccount) {
    throw new Error('CashoutConfirmation: missing destination or withdrawalAccount.');
  }

  const isRealTimeGasFeeEnabled = useIsRealTimeSendGasFeeKilled();

  useEffect(
    // Resetting the gas fee preset on the TransactionContext when the screen unmounts
    function resetLastAdjustableGasParams() {
      return () => {
        if (isRealTimeGasFeeEnabled) {
          resetAdjustableGasParams();
        }
      };
    },
    [isRealTimeGasFeeEnabled, resetAdjustableGasParams],
  );

  return (
    <CashoutConfirmation
      withdrawalAccount={withdrawalAccount}
      transaction={sendContext.unsignedTransaction.transaction}
      wallet={sendContext.unsignedTransaction.wallet}
      destination={destination}
    />
  );
}

export const CashoutConfirmationScreen = withScreenBoundary(CashoutConfirmationWithBoundary, {
  errorFallback: <CashoutErrorScreen />,
});

