import { ZeroBalanceCell } from '../components/ZeroBalanceCell';
import { useCashoutAssetByWallet } from '../hooks/useCashoutAssetByWallet';
import { useCashoutAssets } from '../hooks/useCashoutAssets';
import { useCashoutGenerateUnsignedTx } from '../hooks/useCashoutGenerateUnsignedTx';
import { useCashoutWallet } from '../hooks/useCashoutWallet';
import { useIsCashoutLimitExceeding } from '../hooks/useIsCashoutLimitExceeding';

import { CashoutErrorScreen } from './CashoutErrorScreen';

const messages = defineMessages({
  screenTitle: {
    defaultMessage: 'Cash out',
    description: 'Cashout input screen title',
  },
  continue: {
    defaultMessage: 'Continue',
    description: 'Cashout input preview continue button label',
  },
  arrowDownAccessibilityLabel: {
    defaultMessage: 'To',
    description: 'Cashout flow arrow down accessibility label in Cashout input screen',
  },
  addBankAccount: {
    defaultMessage: 'Add bank account',
    description: 'Cashout flow add bank account button label in Cashout input screen',
  },
  genericError: {
    defaultMessage: 'Something went wrong',
    description: 'Message to be displayed as an generic error',
  },
  exceedingMax: {
    defaultMessage: 'Amount exceeds available for cash out, you have {amount} available.',
    description: 'Message to be displayed when the amount exceeds the available balance',
  },
  exceedingWithdrawalLimit: {
    defaultMessage:
      'This exceeds your deposit limit of {amount} {time}. Select a new place to deposit.',
    description: 'Message to be displayed when the amount exceeds the withdrawal limit',
  },
});

export const CASHOUT_ERROR_HEIGHT = 25;

const CashoutInput = memo(function CashoutInput() {
  const { formatMessage } = useIntl();
  const { withdrawalAccount, entryPoint, ...walletParams } = useParams<
    CashoutParamList,
    'CashoutInput'
  >();
  const [cryptoAmount, updateCryptoAmount] = useState(0n);
  const { goBack, push } = useStackNavigation<CashoutParamList>();
  const { isConnectedCBAccountUsable: isConnectedToCoinbase, isLoading: isLoadingConnection } =
    useIsConnectedCBAccountUsable({
      isUserRestrictionHandled: true,
      restrictionOptions: {
        sells: true,
        withdrawals: true,
      },
    });
  const isSmallScreen = useIsSmallScreen();
  // Cashout Asset
  const { assets: supportedAssets, isLoading: isLoadingCashoutAssets } = useCashoutAssets();
  const wallet = useCashoutWallet(walletParams, supportedAssets);
  const cashoutAsset = useCashoutAssetByWallet(wallet, supportedAssets);
  const {
    isLoading: isLoadingCashoutWithdrawalAccount,
    defaultWithdrawalAccount,
    withdrawalAccounts,
  } = useCashoutWithdrawalAccounts({
    isConnectedToCoinbase: isConnectedToCoinbase && !isLoadingConnection,
    isSellOnly: Boolean(cashoutAsset?.sellOnly),
  });

  /**
   * When user switches between assets, the withdrawal accounts they can select may change
   * we want to filter and be sure the selected one is present, if the selected account
   * is not present we will return default withdrawalAccount
   */
  const selectedWithdrawalAccount = useMemo(() => {
    if (!withdrawalAccount) {
      return defaultWithdrawalAccount;
    }

    return (
      withdrawalAccounts.find((account) => account.uuid === withdrawalAccount.uuid) ??
      defaultWithdrawalAccount
    );
  }, [defaultWithdrawalAccount, withdrawalAccount, withdrawalAccounts]);
  const { openTopUpTray } = useTopUpTray({ source: 'cashout' });
  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useGetFeeWallet(activeWalletGroupId, wallet?.network);
  const getGasFeeError = useGetGasFeeError();
  const { setTransactionInfo: setSendContext, transactionInfo: sendContext } =
    useTransactionContext();
  const [isLoading, setIsLoading] = useState(false);
  const generateUnsignedTx = useCashoutGenerateUnsignedTx();
  const activeFiatCurrency = useActiveFiatCurrency();
  const { isExceeding: isExceedingWithdrawalLimit, limitInFiatDisplay: withdrawalLimitInFiat } =
    useIsCashoutLimitExceeding({
      wallet,
      amount: cryptoAmount,
      withdrawalAccount: selectedWithdrawalAccount,
    });

  const handleValueChange = useCallback(
    function handleValueChange() {
      if (sendContext.error) {
        setSendContext((prev) => ({
          ...prev,
          error: undefined,
        }));
      }
    },
    [sendContext.error, setSendContext],
  );

  // Analytics
  useCashoutInputViewed({
    entryPoint,
    chainId: wallet?.network.asChain()?.chainId,
    chainName: wallet?.network.asChain()?.displayName,
    contractAddress: wallet?.contractAddress,
    currencyCode: wallet?.currencyCode.rawValue,
    withdrawalAccount: selectedWithdrawalAccount?.type,
  });
  usePerfMarkOnMount(
    PERF_MARKS.cashout,
    CASHOUT_MARKS.navigate_to_cashout_input,
    stableEndTypeOption,
  );
  useJourneyMarkOnMount('loaded_cashout');

  const {
    primaryAmount,
    secondaryAmount,
    toggleIsFiat,
    onChange,
    allowChangeToFiat,
    availableBalance,
    isFiat,
    isExceedingMax,
  } = useAmountInputValues({
    cryptoAmount,
    updateCryptoAmount,
    sourceWallet: wallet,
    requireExchangeRate: true,
    txType: GasEstimateTxType.SEND,
    includeCode: false,
    onCryptoAmountChange: handleValueChange,
  });

  const handleLongPress = useCallback((numPadKey: NumPadValue) => {
    // clear input
    if (numPadKey === 'BACKSPACE') {
      updateCryptoAmount(0n);
    }
  }, []);

  const handleSelectAsset = useCallback(() => {
    markJourney('navigate_to_casohut_asset_selector');
    logCashoutSelectAssetPressed();
    push('CashoutSelectAsset', {
      walletId: wallet?.id,
      withdrawalAccount: selectedWithdrawalAccount,
    });
  }, [push, selectedWithdrawalAccount, wallet?.id]);

  const handleAddWithdrawalMethod = useCallback(() => {
    logCashoutSelectWithdrawalAccountPressed(Boolean(isConnectedToCoinbase));
    if (isConnectedToCoinbase) {
      markJourney('navigate_to_cashout_withdrawal_account_selector');
      push('CashoutSelectWithdrawalAccount', {
        withdrawalAccount: selectedWithdrawalAccount,
        walletId: wallet?.id,
        isSellOnly: Boolean(cashoutAsset?.sellOnly),
      });
    } else {
      markJourney('navigate_to_cashout_connect');
      push('CashoutConnect', undefined);
    }
  }, [cashoutAsset, isConnectedToCoinbase, push, selectedWithdrawalAccount, wallet?.id]);

  const handleContinue = useCallback(
    async function handleContinue() {
      setIsLoading(true);
      const amount: TransactionAmount = {
        kind: TransactionKind.AMOUNT,
        value: cryptoAmount,
      };

      try {
        const gasFeeError = await getGasFeeError({
          amount,
          wallet,
          feeWallet,
          disableSponsoredSend: true,
        });

        // Fee Wallet is assumed to be present as it's condition for enabling the Continue Button
        if (gasFeeError && feeWallet) {
          openTopUpTray({
            wallet: feeWallet,
            amountNeeded: gasFeeError.amountGasFeeNeeded,
          });
          setIsLoading(false);
          return;
        }

        logCashoutInputNextPressed({
          amount: String(cryptoAmount),
          currencyCode: wallet.currencyCode.rawValue,
        });
        markJourney('navigate_to_cashout_preview');

        if (selectedWithdrawalAccount) {
          const { transaction: unsignedTransaction, destination } = await generateUnsignedTx({
            amount,
            wallet,
            withdrawalAccount: selectedWithdrawalAccount,
          });

          setSendContext((prev) => ({
            ...prev,
            collectible: undefined,
            senderWallet: {
              walletId: wallet.id,
              amount,
            },
            unsignedTransaction,
          }));
          push('CashoutConfirmation', {
            destination,
            withdrawalAccount: selectedWithdrawalAccount,
          });
        }

        setIsLoading(false);
      } catch (err: ErrorOrAny) {
        const error = err instanceof Error ? err : new Error(formatMessage(messages.genericError));
        setSendContext((prev) => ({
          ...prev,
          error,
        }));
        setIsLoading(false);
      }
    },
    [
      cryptoAmount,
      feeWallet,
      formatMessage,
      generateUnsignedTx,
      getGasFeeError,
      openTopUpTray,
      push,
      selectedWithdrawalAccount,
      setSendContext,
      wallet,
    ],
  );

  const handleLeft = useCallback(() => {
    logCashoutInputBack();
    goBack();
  }, [goBack]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      title: formatMessage(messages.screenTitle),
      left: 'back',
      handleLeft,
    }),
    [formatMessage, handleLeft],
  );

  const isLimitError = useMemo(() => {
    return isExceedingMax || isExceedingWithdrawalLimit;
  }, [isExceedingMax, isExceedingWithdrawalLimit]);

  const limitErrorText = useMemo(() => {
    if (isExceedingMax) {
      return formatMessage(messages.exceedingMax, { amount: availableBalance });
    }

    if (isExceedingWithdrawalLimit) {
      return formatMessage(messages.exceedingWithdrawalLimit, {
        amount: withdrawalLimitInFiat,
        time: selectedWithdrawalAccount?.limit?.periodInDays === 1 ? 'per day' : 'per week',
      });
    }
  }, [
    availableBalance,
    formatMessage,
    isExceedingMax,
    isExceedingWithdrawalLimit,
    selectedWithdrawalAccount?.limit?.periodInDays,
    withdrawalLimitInFiat,
  ]);

  const isContinueDisabled = useMemo(() => {
    if (
      primaryAmount === '0' ||
      !wallet?.id ||
      !selectedWithdrawalAccount?.id ||
      cryptoAmount === 0n
    ) {
      return true;
    }

    return isLimitError || Boolean(sendContext.error);
  }, [
    cryptoAmount,
    isLimitError,
    primaryAmount,
    selectedWithdrawalAccount?.id,
    sendContext.error,
    wallet?.id,
  ]);

  return (
    <Screen full navBar={navBar}>
      <VStack height="100%" justifyContent="space-between" spacingBottom={6}>
        <Box
          flexGrow={1}
          spacingHorizontal={3}
          justifyContent="center"
          offsetTop={isSmallScreen ? 1 : 0}
        >
          <AmountInput
            wallet={wallet}
            primaryAmount={primaryAmount}
            secondaryAmount={!isLimitError ? secondaryAmount : limitErrorText}
            toggleIsFiat={toggleIsFiat}
            allowChangeToFiat={allowChangeToFiat}
            tertiaryAmount={availableBalance}
            txType={GasEstimateTxType.SEND}
            type={AmountInputType.CASHOUT}
            isFiat={isFiat}
            isSmallScreen={isSmallScreen}
            secondaryTextColorOverride={isLimitError ? 'negative' : 'foregroundMuted'}
            activeFiatCurrency={activeFiatCurrency}
          />
          <Box justifyContent="flex-start" height={CASHOUT_ERROR_HEIGHT}>
            {sendContext.error?.message && (
              <TextLabel2 color="negative">{sendContext.error.message}</TextLabel2>
            )}
          </Box>
        </Box>
        <VStack
          flexGrow={1}
          justifyContent="flex-end"
          gap={isSmallScreen ? 1 : 2}
          offsetVertical={isSmallScreen ? 1 : 0}
        >
          <VStack gap={1} borderedVertical alignContent="center">
            {wallet?.balance || isLoadingCashoutAssets ? (
              <VStack
                spacingVertical={isSmallScreen ? 0 : 2}
                spacingHorizontal={3}
                offsetHorizontal={3}
              >
                <CashoutAssetCell
                  isLoading={isLoadingCashoutAssets}
                  wallet={wallet}
                  handleSelectAsset={handleSelectAsset}
                  availableBalance={availableBalance}
                  withdrawalAccount={selectedWithdrawalAccount}
                />
                {Boolean(selectedWithdrawalAccount) || isLoadingCashoutWithdrawalAccount ? (
                  <Box
                    accessible
                    spacingStart={0}
                    offsetVertical={1}
                    offsetHorizontal={0.5}
                    accessibilityLabel={formatMessage(messages.arrowDownAccessibilityLabel)}
                  >
                    <Icon name="verticalLine" size="s" spacingStart={4} color="foregroundMuted" />
                  </Box>
                ) : (
                  <Box height={5} />
                )}
                <WithdrawalAccountCell
                  selectedWithdrawalAccount={selectedWithdrawalAccount ?? defaultWithdrawalAccount}
                  handleAddWithdrawalMethod={handleAddWithdrawalMethod}
                  isLoading={isLoadingCashoutWithdrawalAccount || isLoadingConnection}
                />
              </VStack>
            ) : (
              <ZeroBalanceCell
                handleSelectAsset={handleSelectAsset}
                isSmallScreen={isSmallScreen}
              />
            )}
          </VStack>
          <VStack gap={1}>
            <NumPad allowDecimalSeparator onPress={onChange} onLongPress={handleLongPress} />
            <Box spacingHorizontal={3}>
              <Button
                variant="primary"
                disabled={isContinueDisabled}
                onPress={handleContinue}
                loading={isLoading}
                testID="continue-btn"
              >
                {formatMessage(messages.continue)}
              </Button>
            </Box>
          </VStack>
        </VStack>
      </VStack>
    </Screen>
  );
});

export const CashoutInputScreen = withScreenBoundary(CashoutInput, {
  errorFallback: <CashoutErrorScreen />,
});

