type TransactionSortListCellProps = {
  iconName: IconName;
  title: string;
  onPress: () => void;
  selected: boolean;
};

const TransactionSortListCell = memo(function TransactionSortListCell({
  iconName,
  title,
  onPress,
  selected,
}: TransactionSortListCellProps) {
  const { formatMessage } = useIntl();
  const { sortOrder, setSortOrder } = useCollectibleAllOffersSort();

  const sortArg = useMemo(() => title.toLowerCase(), [title]);

  const intermediaryLabel = useMemo(() => {
    if (sortArg === 'date received') {
      return sortOrder === 'descending'
        ? formatMessage(messages.dateDesc)
        : formatMessage(messages.dateAsc);
    }

    if (sortArg === 'expiration') {
      return sortOrder === 'descending'
        ? formatMessage(messages.expirationDesc)
        : formatMessage(messages.expirationAsc);
    }

    return sortOrder === 'descending'
      ? formatMessage(messages.amountDesc)
      : formatMessage(messages.amountAsc);
  }, [formatMessage, sortOrder, sortArg]);

  const intermediary = useMemo(() => {
    return (
      <Box flexGrow={0} justifyContent="center">
        <HStack alignItems="center" justifyContent="flex-end" gap={2}>
          <TextBody>{intermediaryLabel}</TextBody>
          <Icon
            name={sortOrder === 'ascending' ? 'downArrow' : 'upArrow'}
            color="primary"
            size="s"
          />
        </HStack>
      </Box>
    );
  }, [intermediaryLabel, sortOrder]);

  const handleSelect = useCallback(
    function handleSelect() {
      setSortOrder(sortOrder === 'descending' ? 'ascending' : 'descending');
      onPress();
    },
    [setSortOrder, sortOrder, onPress],
  );

  return (
    <Cell testID="transactions-sort-list-item" compact selected={selected} onPress={handleSelect}>
      <HStack justifyContent="space-between" alignItems="center">
        <HStack alignItems="center" gap={2}>
          <Icon name={iconName} color="foreground" size="s" />
          <TextHeadline>{title}</TextHeadline>
        </HStack>

        {selected && intermediary}
      </HStack>
    </Cell>
  );
});

type CollectibleAllOffersSortTrayProps = {
  visible: boolean;
  handleCloseComplete: () => void;
};

export const CollectibleAllOffersSortTray = memo(function CollectibleAllOffersSortTray({
  visible,
  handleCloseComplete,
}: CollectibleAllOffersSortTrayProps) {
  useCollectibleAllOffersSortViewed();

  const { formatMessage } = useIntl();
  const { sort, setSort, setSortOrder } = useCollectibleAllOffersSort();

  const handleReceivedSortBy = useCallback(() => {
    if (sort !== 'dateCreated') {
      setSort('dateCreated');
      setSortOrder('descending');
    }
  }, [setSort, setSortOrder, sort]);

  const handleExpirationSortBy = useCallback(() => {
    if (sort !== 'expiryDate') {
      setSort('expiryDate');
      setSortOrder('ascending');
    }
  }, [setSort, setSortOrder, sort]);

  const handlePriceSortBy = useCallback(() => {
    if (sort !== 'bidValue') {
      setSort('bidValue');
      setSortOrder('descending');
    }
  }, [setSort, setSortOrder, sort]);

  const handleReset = useCallback(
    function handleReset() {
      setSort('dateCreated');
      setSortOrder('descending');
    },
    [setSort, setSortOrder],
  );

  if (!visible) return null;

  return (
    <Tray
      testID="collectible-all-offers-sort-tray"
      verticalDrawerPercentageOfView={0.8}
      onCloseComplete={handleCloseComplete}
      disableCapturePanGestureToDismiss
    >
      <Box offsetTop={2}>
        <VStack>
          <TransactionSortListCell
            iconName="calendar"
            title={formatMessage(messages.dateReceived)}
            onPress={handleReceivedSortBy}
            selected={sort === 'dateCreated'}
          />
          <TransactionSortListCell
            iconName="clock"
            title={formatMessage(messages.expiration)}
            onPress={handleExpirationSortBy}
            selected={sort === 'expiryDate'}
          />
          <TransactionSortListCell
            iconName="cash"
            title={formatMessage(messages.price)}
            onPress={handlePriceSortBy}
            selected={sort === 'bidValue'}
          />
          <Box spacingHorizontal={3} spacingTop={2}>
            <ButtonGroup block accessibilityLabel="CollectibleAllOffersSortTrayButtonsLabel">
              <Button onPress={handleReset} variant="secondary">
                {formatMessage(messages.resetButton)}
              </Button>
              <Button onPress={handleCloseComplete}>{formatMessage(messages.doneButton)}</Button>
            </ButtonGroup>
          </Box>
        </VStack>
      </Box>
    </Tray>
  );
});

