type TrayContentProps = {
  links: CollectibleLink[];
  hideTray: () => void;
};

const TrayContent = memo(function TrayContent({ links, hideTray }: TrayContentProps) {
  const openInBrowser = useOpenUrlInBrowser();

  const handlePress = useCallback(
    (url: string, type: string) => {
      return () => {
        triggerCollectibleLinkClicked(type);
        openInBrowser(url);

        hideTray();
      };
    },
    [hideTray, openInBrowser],
  );

  return (
    <VStack>
      {links.map(({ name: optionType, url, iconUrl }) => {
        return (
          <ListCell
            key={optionType.toString()}
            media={<CollectibleLinkIcon optionType={optionType} iconUrl={iconUrl} />}
            onPress={handlePress(url, optionType)}
            title={optionType.toString()}
          />
        );
      })}
    </VStack>
  );
});

type CollectibleLinkButtonProps = {
  links: CollectibleLink[];
  showButtonText?: boolean;
  transparent?: boolean;
};

export const CollectibleLinkButton = memo(function CollectibleLinkButton({
  links,
  showButtonText = true,
  transparent = false,
}: CollectibleLinkButtonProps) {
  const { formatMessage } = useIntl();

  const [trayVisible, { toggleOn: showTray, toggleOff: hideTray }] = useToggler(false);

  const triggerAnalyticsCollectibleOpeninClicked = useCollectibleDetailOpeninClicked();

  const openTray = useCallback(
    function openTray() {
      showTray();
      triggerAnalyticsCollectibleOpeninClicked();
    },
    [triggerAnalyticsCollectibleOpeninClicked, showTray],
  );

  const validLinks = useGetValidExternalLinks(links);

  return (
    <VStack alignItems="center" minWidth={COLLECTIBLE_BUTTON_BAR_BUTTON_WIDTH}>
      {trayVisible && (
        <Tray onCloseComplete={hideTray} testID="collectible-link-button-open-in-tray">
          <Box>
            <TextTitle3 spacingStart={3} spacingBottom={1}>
              {formatMessage(messages.openIn)}
            </TextTitle3>
            <TrayContent links={validLinks} hideTray={hideTray} />
          </Box>
        </Tray>
      )}
      <IconButton
        name="externalLink"
        variant="secondary"
        transparent={transparent}
        testID="collectible-detail-commerce-open-in-btn"
        onPress={openTray}
      />
      {showButtonText ? (
        <TextLegal spacingTop={1}>{formatMessage(messages.openIn)}</TextLegal>
      ) : undefined}
    </VStack>
  );
});

type CollectibleButtonBarProps = {
  sendOnPress?: () => void;
  refreshOnPress: () => void;
  links: CollectibleLink[];
  chainId: string;
  sendEnabledFlow: boolean;
  enableRefresh?: boolean;
  collectible: Collectible;
  skipNextScreenOnReport?: boolean;
};

export function CollectibleButtonBar({
  sendOnPress,
  refreshOnPress,
  links,
  sendEnabledFlow,
  enableRefresh = true,
  collectible,
  chainId,
  skipNextScreenOnReport = false,
}: CollectibleButtonBarProps) {
  const [visible, { toggleOff }] = useToggler(false);
  const { push } = useStackNavigation<AssetsParamList>();
  const { formatMessage } = useIntl();

  const isNFTTicketingEnabled = useIsFeatureEnabled('nft_ticketing');
  const killNftSend = useIsNFTSendKilled();
  const isSendEnabled = sendEnabledFlow && sendOnPress && !collectible.isPending;

  const [showQRCodeScanner, { toggleOn: openQRCodeScanner, toggleOff: closeQRCodeScanner }] =
    useToggler(false);

  const [ticketTrayVisible, { toggleOn: showTicketTray, toggleOff: hideTicketTray }] =
    useToggler(false);

  const isNFTVerifier = useMemo(() => {
    return collectible.contractAddress === VERIFIER_CONTRACT;
  }, [collectible.contractAddress]);

  const isNFTTicket = useMemo(() => {
    return collectible.contractAddress === TICKET_CONTRACT;
  }, [collectible.contractAddress]);

  const showSendButton = useMemo(() => {
    return !killNftSend && isSendEnabled;
  }, [isSendEnabled, killNftSend]);

  const { hideUserCollectible, unhideUserCollectible, hideAndReportSpamCollectible } =
    useHideUserCollectible({ ...collectible, chainId: BigInt(chainId) });

  const handleHideAndReportSpamCollectible = useCallback(() => {
    return hideAndReportSpamCollectible('nftdetail');
  }, [hideAndReportSpamCollectible]);

  const activeWalletGroupId = useActiveWalletGroupId();
  const wallets = useWalletsForWalletGroupId(activeWalletGroupId);
  const wallet = wallets[0];

  const handleGenerateQRCode = useCallback(
    (message: string) => {
      push('CollectibleQRCode', { message });
    },
    [push],
  );

  const handleSignMessage = useGenerateSignedAddress({
    accountId: wallet.accountId,
    ownerAddress: collectible.ownerAddress ?? wallet.primaryAddress,
    contractAddress: collectible.contractAddress,
    tokenId: collectible.tokenId,
    chainId,
    navigate: handleGenerateQRCode,
  });

  const handleQRCodePressed = useCallback(() => {
    logCollectibleQRCodeClicked({
      contractAddress: collectible.contractAddress,
      chainId,
      tokenId: collectible.tokenId,
    });
    hideTicketTray();
    handleSignMessage();
  }, [
    chainId,
    collectible.contractAddress,
    collectible.tokenId,
    handleSignMessage,
    hideTicketTray,
  ]);

  const handleVerifyTicket = useCallback(() => {
    logCollectibleVerifierClicked({
      contractAddress: collectible.contractAddress,
      chainId,
      tokenId: collectible.tokenId,
    });
    openQRCodeScanner();
  }, [chainId, collectible.contractAddress, collectible.tokenId, openQRCodeScanner]);

  const { reportAssetAndNavigateAway: handleReportButtonPress } = useHideAssetActions({
    assetName: collectible.name ?? collectible.tokenId,
    onHide: hideUserCollectible,
    onReport: handleHideAndReportSpamCollectible,
    onUndo: unhideUserCollectible,
    skipAssetHiddenScreen: skipNextScreenOnReport,
  });

  const showReportButton = useMemo(() => collectible.ownedByWallet, [collectible]);

  return (
    <VStack spacingHorizontal={3}>
      {isNFTTicketingEnabled && isNFTTicket ? (
        <>
          <Box spacingTop={3}>
            <Button onPress={showTicketTray} testID="collectible-detail-commerce-qrcode-btn">
              {formatMessage(messages.generateQRCode)}
            </Button>
          </Box>
          {ticketTrayVisible && (
            <Tray
              onCloseComplete={hideTicketTray}
              disableCapturePanGestureToDismiss
              testID="collectible-detail-commerce-qrcode-confirmation-tray"
            >
              <VStack spacingHorizontal={3} gap={2}>
                <TextTitle3>{formatMessage(messages.trayTitle)}</TextTitle3>
                <TextBody color="foregroundMuted">
                  {formatMessage(messages.trayDescription)}
                </TextBody>
                <Button
                  onPress={handleQRCodePressed}
                  testID="collectible-detail-commerce-qrcode-confirmation-btn"
                >
                  {formatMessage(messages.trayButton)}
                </Button>
              </VStack>
            </Tray>
          )}
        </>
      ) : null}
      {isNFTTicketingEnabled && isNFTVerifier ? (
        <Box spacingTop={3}>
          <Button onPress={handleVerifyTicket} testID="collectible-detail-commerce-verify-btn">
            {formatMessage(messages.scanTicket)}
          </Button>
        </Box>
      ) : null}
      <HStack
        spacingVertical={3}
        spacingHorizontal={3}
        justifyContent={showSendButton ? 'space-between' : 'space-around'}
        background
        testID="collectible-detail-commerce-button-bar"
      >
        {showSendButton ? (
          <CollectibleButton
            onPress={sendOnPress}
            iconName="upArrow"
            buttonText={formatMessage(messages.send)}
            testID="collectible-detail-commerce-send-btn"
          />
        ) : null}
        {enableRefresh ? (
          <CollectibleButton
            onPress={refreshOnPress}
            iconName="refresh"
            buttonText={formatMessage(messages.refresh)}
            testID="collectible-detail-commerce-refresh-btn"
          />
        ) : null}
        <CollectibleLinkButton links={links} />
        {showReportButton ? (
          <CollectibleButton
            onPress={handleReportButtonPress}
            iconName="reportInactive"
            buttonText={formatMessage(messages.report)}
            testID="collectible-detail-commerce-report-btn"
          />
        ) : null}
        <TooltipTray
          title={formatMessage(messages.sendNotAvailableTitle)}
          description={formatMessage(messages.sendNotAvailableMessage)}
          descriptionTestID="ios-send-NFT-tray"
          visible={visible}
          buttonText={formatMessage(messages.sendNotAvailableButtonText)}
          toggleOff={toggleOff}
        />
      </HStack>
      <CollectibleQRCodeScannerModal
        visible={showQRCodeScanner}
        onClose={closeQRCodeScanner}
        subPrompt={formatMessage(messages.scanSubprompt, { event: collectible.name })}
      />
    </VStack>
  );
}

