import { TabNavigation } from ':rn/cds-wallet/components/TabNavigatorWithOffset';

const messages = defineMessages({
  about: {
    defaultMessage: 'About',
    description: 'Label for about tab in collectible detail selector',
  },
  history: {
    defaultMessage: 'History',
    description: 'Label for history tab in collectible detail selector',
  },
  offers: {
    defaultMessage: 'Offers',
    description: 'Label for offers tab in collectible detail selector',
  },
});

export type CollectibleDetailTab = 'about' | 'history' | 'offers';

type CollectibleDetailSelectorProps = {
  onTabSelected: (tab: CollectibleDetailTab) => void;
  currentTab: CollectibleDetailTab;
  transactions: CollectibleTransactionCombined[];
  offers: CollectibleBid[];
  shouldDisplayAsVerificationToken?: boolean;
  chainId: string;
  showOffersTab?: boolean;
  showHistoryTab?: boolean;
};

export const CollectibleDetailSelector = memo(function CollectibleDetailSelector({
  onTabSelected,
  currentTab,
  shouldDisplayAsVerificationToken,
  showOffersTab = true,
  showHistoryTab = true,
}: CollectibleDetailSelectorProps) {
  const { formatMessage } = useIntl();

  const [startNavigateToCollectibleHistoryPerfMark] = usePerfMark(
    PERF_MARKS.nft_detail_history_tab,
    COLLECTION_MARKS.load_collectible_detail_history,
  );

  const [startNavigateToCollectibleOffersPerfMark] = usePerfMark(
    PERF_MARKS.nft_detail_reservoir_offers_tab,
    COLLECTION_MARKS.load_collectible_detail_offers,
  );

  const triggerAnalyticsCollectibleAboutTabClicked = useCollectibleDetailAboutTabClicked();
  const triggerAnalyticsCollectibleHistoryTabClicked = useCollectibleDetailHistoryTabClicked();
  const triggerAnalyticsCollectibleOffersTabClicked = useCollectibleDetailOffersTabClicked();

  const isOffersKilled = useKillSwitch('kill_switch_nft_offers_tab_rn');
  const isHistoryKilled = useKillSwitch('kill_switch_nft_history_tab_rn');

  const tabs = useMemo(() => {
    const result = [
      {
        id: 'about',
        label: formatMessage(messages.about),
        testID: 'about-tab',
      },
    ];

    if (!isHistoryKilled && showHistoryTab) {
      result.push({
        id: 'history',
        label: formatMessage(messages.history),
        testID: 'history-tab',
      });
    }

    const showOffers = !isOffersKilled && !shouldDisplayAsVerificationToken && showOffersTab;

    // POLYGON NFT's don't have offers, temporarily hide
    if (showOffers) {
      result.push({
        id: 'offers',
        label: formatMessage(messages.offers),
        testID: 'offers-tab',
      });
    }
    return result;
  }, [
    formatMessage,
    isHistoryKilled,
    isOffersKilled,
    shouldDisplayAsVerificationToken,
    showHistoryTab,
    showOffersTab,
  ]);

  const handleOnChange = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    function handleOnChange(tabId: any) {
      switch (tabId) {
        case 'history':
          startNavigateToCollectibleHistoryPerfMark();
          break;
        case 'offers':
          startNavigateToCollectibleOffersPerfMark();
          break;
        default:
          break;
      }
      onTabSelected(tabId);
      switch (tabId) {
        case 'about':
          triggerAnalyticsCollectibleAboutTabClicked();
          break;
        case 'history':
          triggerAnalyticsCollectibleHistoryTabClicked();
          break;
        case 'offers':
          triggerAnalyticsCollectibleOffersTabClicked();
          break;
        default:
          break;
      }
    },
    [
      onTabSelected,
      startNavigateToCollectibleHistoryPerfMark,
      startNavigateToCollectibleOffersPerfMark,
      triggerAnalyticsCollectibleAboutTabClicked,
      triggerAnalyticsCollectibleHistoryTabClicked,
      triggerAnalyticsCollectibleOffersTabClicked,
    ],
  );

  return (
    <VStack width="100%" borderedBottom>
      <TabNavigation
        testID="collectible-details-tab"
        zIndex={1}
        offsetTop={2}
        tabSpacingEnd={3}
        tabSpacingStart={3}
        tabs={tabs}
        value={currentTab}
        onChange={handleOnChange}
        accessibilityLabel={undefined}
        accessibilityLabelledBy={undefined}
      />
    </VStack>
  );
});

