      <HStack gap={3}>
        {!!expirationTimeMessage && (
          <HStack alignItems="center" gap={1}>
            <Icon size="xs" name="clock" color="foreground" />
            <TextLabel2>{expirationTimeMessage}</TextLabel2>
          </HStack>
        )}
        <HStack alignItems="center" gap={1}>
          {getPlatformIcon({ platform, size: 's' })}
          <TextLabel2>
            {isBestPrice ? formatMessage(messages.bestPriceLabel) : getPlatformName({ platform })}
