type VerifyTicketContainerProps = {
  ticketInfo: NftTicketParserSuccess;
  onFail: () => void;
  onReset: () => void;
};

export const VerifyTicketContainer = memo(function VerifyTicketContainer({
  ticketInfo,
  onFail,
  onReset,
}: VerifyTicketContainerProps) {
  const { data, isLoading } = useVerifyNFTTicket(ticketInfo);

  useEffect(
    function resetVerification() {
      if (data && !isLoading) {
        onReset();
      }
    },
    [data, isLoading, onReset],
  );

  if (isLoading) {
    return null;
  }

  if (!data?.verified) {
    onFail();
  }

  return (
    <Box alignItems="center" spacingTop={1}>
      <Pictogram
        name={data?.verified ? 'checkmark' : 'error'}
        testID={`collectible-ticket-verify-status-${data?.verified ? 'checkmark' : 'error'}`}
      />
    </Box>
  );
});

type Props = {
  visible: boolean;
  onClose: () => void;
} & Omit<CollectibleQRCodeScannerProps, 'onScan'>;

function CollectibleQRCodeScannerModal({ visible, onClose, ...qrCodeScannerProps }: Props) {
  const { formatMessage } = useIntl();
  const { top: paddingTop } = useSafeAreaInsets();
  const qrCodeScannerViewed = useQRCodeScannerViewed();
  const qrCodeScannerClosed = useQRCodeScannerClosed();
  const [viewEventLogged, setViewEventLogged] = useState(false);
  const [error, setError] = useState<string | undefined>();
  const [qrCodeResponse, setQRCodeResponse] = useState<NftTicketParserSuccess | undefined>();

  const handleError = useCallback((errorMessage: string) => {
    setError(errorMessage);
  }, []);

  const onVerifyFail = useCallback(() => {
    handleError(formatMessage(messages.scanError));
  }, [formatMessage, handleError]);

  const onVerifyReset = useCallback(() => {
    // setup timer to reset
    setTimeout(() => {
      setQRCodeResponse(undefined);
    }, 2000);
  }, [setQRCodeResponse]);

  useEffect(
    function logModalViewEvent() {
      if (visible && !viewEventLogged) {
        qrCodeScannerViewed();
        setViewEventLogged(true);
      }

      if (!visible && viewEventLogged) {
        qrCodeScannerClosed();
        setViewEventLogged(false);
        setError(undefined);
      }
    },
    [qrCodeScannerClosed, qrCodeScannerViewed, viewEventLogged, visible],
  );

  const handleOnScan = useCallback(
    function onScan(response: QRCodeScannerResponse) {
      if (
        !response ||
        (response?.type === QRCodeType.NFT_TICKET_QR_CODE &&
          (!response.data.chainId ||
            !response.data.claimer ||
            !response.data.collectionAddress ||
            !response.data.signature ||
            !response.data.tokenId))
      ) {
        onVerifyFail();
        return;
      }

      // trigger api call
      setQRCodeResponse(response.data as NftTicketParserSuccess);
    },
    [onVerifyFail],
  );

  return (
    <Modal animationType="slide" visible={visible} onRequestClose={onClose}>
      <StatusBar barStyle="light-content" />
      <ThemeProvider name="qrScanner" spectrum="dark">
        <VStack flexGrow={1}>
          <HStack
            position="absolute"
            background="transparent"
            top={paddingTop as SpacingScale}
            zIndex={1}
          >
            <HStack justifyContent="center" alignItems="center" flexGrow={1}>
              <Box
                position="absolute"
                top={0}
                left={0}
                bottom={0}
                justifyContent="center"
                spacingStart={1}
              >
                <IconButton transparent name="close" onPress={onClose} />
              </Box>

              <TextHeadline>{formatMessage(messages.screenTitle)}</TextHeadline>
            </HStack>
          </HStack>

          <CollectibleQRCodeScanner
            {...qrCodeScannerProps}
            isVerifying={qrCodeResponse !== undefined}
            onScan={handleOnScan}
            onError={handleError}
            status={
              qrCodeResponse ? (
                <VerifyTicketContainer
                  ticketInfo={qrCodeResponse}
                  onFail={onVerifyFail}
                  onReset={onVerifyReset}
                />
              ) : null
            }
          />

          <HStack
            position="absolute"
            background="transparent"
            bottom={0}
            width="100%"
            zIndex={1}
            spacingHorizontal={3}
            spacingBottom={3}
            alignItems="center"
            justifyContent="center"
          >
            {Boolean(error) && (
              <TextBody align="center" color="negative">
                {error}
              </TextBody>
            )}
          </HStack>
        </VStack>
      </ThemeProvider>
    </Modal>
  );
}

function CollectibleQRCodeScannerModalWithBoundary(props: Props) {
  return (
    <ScreenBoundary>
      <CollectibleQRCodeScannerModal {...props} />
    </ScreenBoundary>
  );
}

