type ExploreCardProps = {
  asset: ExploreAsset;
  onPress?: () => void;
  onFocus: EffectCallback;
};

export function ExploreCardWide({ asset, onPress, onFocus }: ExploreCardProps) {
  const { formattedAmount, formattedPercent, percentArrow, percentColor } = useGetPriceDetail(
    asset.currencyCode.code,
    asset.uuid,
    true, // no need to fetch / cache price history
  );

  const isValidExploreAsset = useValidateExploreAsset(asset);
  useFocusEffect(onFocus);

  if (!isValidExploreAsset) {
    return null;
  }

  return (
    <Box spacingEnd={1} width={EXPLORE_CARD_WIDE_WIDTH}>
      <Pressable
        background="backgroundAlternate"
        borderColor="secondary"
        borderWidth="none"
        borderRadius="roundedLarge"
        onPress={onPress}
      >
        <HStack
          spacingVertical={1}
          spacingHorizontal={2}
          alignItems="center"
          justifyContent="space-between"
        >
          <HStack alignItems="center">
            <AssetIcon
              currencyCode={asset.currencyCode.code}
              network={asset.network}
              showNetworkIcon={false}
              iconUrl={asset.imageURL}
              width={ICON_SIZE}
              height={ICON_SIZE}
            />
            <VStack spacingStart={2} width={EXPLORE_CARD_WIDE_DETAIL_WIDTH}>
              <TextHeadline ellipsize="tail">{asset.name}</TextHeadline>
              <TextBody color="foregroundMuted">{asset.currencyCode.code}</TextBody>
            </VStack>
          </HStack>
          <VStack spacingStart={2} width={EXPLORE_CARD_WIDE_DETAIL_WIDTH}>
            {formattedAmount ? (
              <>
                <TextBody align="end" ellipsize="tail">
                  {formattedAmount}
                </TextBody>
                <HStack alignItems="center" gap={0.5} justifyContent="flex-end">
                  <TextHeadline color={percentColor} ellipsize="tail">
                    {`${percentArrow}${formattedPercent}`}
                  </TextHeadline>
                </HStack>
              </>
            ) : (
              <>
                <Spacer vertical={3} />
                <Box alignItems="flex-end">
                  <Icon name="minus" size="xs" color="foregroundMuted" />
                </Box>
              </>
            )}
          </VStack>
        </HStack>
      </Pressable>
    </Box>
  );
}

