type ExploreFeedCardProps = {
  id: string;
  onEmpty?: (isEmpty: boolean) => void;
  rowIndex: number;
};

const ExploreFeedCardComponent = memo((props: ExploreFeedCardProps) => {
  const { feedCard, isLoading } = useExploreFeedCard(props.id);
  const content = exploreFeedCardFromResponse(feedCard);

  if (isLoading || !feedCard || !content) {
    return null;
  }

  return (
    <ExploreFeedCardComponentContent feedCard={feedCard} content={content} index={props.rowIndex} />
  );
});

type ExploreFeedCardComponentContentProps = {
  feedCard: ExploreFeedCard;
  content: ExploreFeedCardType;
  index: number;
};

const ExploreFeedCardComponentContent = memo(
  ({ feedCard, content, index }: ExploreFeedCardComponentContentProps) => {
    const { id, contentType, header, body, cta, socialProof, dataPoints, presentationAnalytics } =
      feedCard;

    const baseAnalytics = useMemo(() => {
      const metadata = { ...presentationAnalytics.metadata, cardOrder: index };

      return {
        order: index,
        ...presentationAnalytics,
        metadata,
      };
    }, [index, presentationAnalytics]);

    useOnMount(() => {
      logExploreFeedCard({
        ...baseAnalytics,
        componentType: ComponentType.card,
        action: ActionType.view,
        triggerPointEventName: TriggerPointEventName.DynamicFeedCard,
        actionSource: ActionSource.DynamicFeedCard,
      });
    });

    const handleOnPress = useCallback(() => {
      logExploreFeedCard({
        ...baseAnalytics,
        componentType: ComponentType.button,
        action: ActionType.click,
        triggerPointEventName: TriggerPointEventName.DynamicFeedButton,
        actionSource: ActionSource.DynamicFeedButton,
      });
    }, [baseAnalytics]);

    return (
      <VStack gap={1} spacingHorizontal={FEED_CARD_SPACING} testID={`explore-feed-card-${id}`}>
        <Header {...header} />

        <Box background="backgroundAlternate" borderRadius="roundedLarge">
          <VStack spacing={2} gap={1}>
            <ExploreFeedBody content={content} contentType={contentType} />
            <Body {...body} />
            {dataPoints?.length ? (
              <HStack gap={2}>
                {dataPoints?.map(({ infoText, infoIcon }: ExploreFeedDataPoint) => (
                  <DataPoint infoText={infoText} infoIcon={infoIcon} key={infoText.text} />
                ))}
              </HStack>
            ) : null}
            <HStack spacingVertical={0.5} justifyContent="space-between">
              <SocialProof {...socialProof} />
              <CTA {...cta} handleOnPress={handleOnPress} />
            </HStack>
          </VStack>
        </Box>
      </VStack>
    );
  },
);

const Header = memo(({ title, image, description }: ExploreFeedCardHeader) => {
  const { url } = image;
  const imageSource = useMemo(() => ({ uri: url }), [url]);

  return (
    <HStack gap={2} alignItems="center">
      <RemoteImage
        key={url}
        source={imageSource}
        resizeMode="contain"
        shape="circle"
        width={SMALL_ICON_SIZE}
        height={SMALL_ICON_SIZE}
        testID={`image-${url}`}
      />
      <VStack gap={0.5}>
        <TextLabel1 color="foreground">{title.text}</TextLabel1>
        <TextLegal color="foregroundMuted">{description.text}</TextLegal>
      </VStack>
      <Spacer />

      <IconButton name="more" transparent compact />
    </HStack>
  );
});

const Body = memo(({ title, description }: ExploreFeedCardBody) => {
  return (
    <VStack>
      <TextTitle4>{title.text}</TextTitle4>
      <TextLabel2 numberOfLines={2} color="foregroundMuted">
        {description.text}
      </TextLabel2>
    </VStack>
  );
});

type CTAProps = {
  handleOnPress?: () => void;
};
const CTA = memo(({ text, url, params, handleOnPress }: ExploreFeedCta & CTAProps) => {
  const openUrlInBrowser = useOpenUrlInBrowser();
  const { navigateToDeeplinkUrl, isDeeplink } = useNavigateToDeeplink();
  const { navigate } = useStackNavigation();

  const onPress = useCallback(() => {
    handleOnPress?.();
    if (isURL(url)) {
      openUrlInBrowser(url);
    } else if (isDeeplink(url)) {
      navigateToDeeplinkUrl(url);
    } else {
      navigate(url, params);
    }
  }, [handleOnPress, params, isDeeplink, navigate, navigateToDeeplinkUrl, openUrlInBrowser, url]);

  return (
    <HStack justifyContent="flex-end">
      <Button variant="secondary" onPress={onPress} compact testID="explore-feed-cta-button">
        {text}
      </Button>
    </HStack>
  );
});

function exploreFeedCardFromResponse(
  response: ExploreFeedCard | undefined,
): ExploreFeedCardType | undefined {
  if (!response) return undefined;

  const {
    contentType,
    imageContent,
    multiImageContent,
    mediaContent,
    progressBarContent,
    gradientCircleContent,
  } = response;

  switch (contentType) {
    case ExploreFeedCardContentType.Image:
      return imageContent;
    case ExploreFeedCardContentType.MultiImage:
      return multiImageContent;
    case ExploreFeedCardContentType.ProgressBar:
      return progressBarContent;
    case ExploreFeedCardContentType.Media:
      return mediaContent;
    case ExploreFeedCardContentType.GradientCircle:
      return gradientCircleContent;
    case ExploreFeedCardContentType.Unknown:
      break;
    default:
      return undefined;
  }
}

export { ExploreFeedCardComponent as ExploreFeedCard };

import { memo, useCallback, useMemo } from 'react';
import { logExploreCardClicked, logExploreCardViewed } from 'cb-wallet-analytics/explore';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { ExploreCard } from 'cb-wallet-data/stores/Explore/types/ExploreCard';
import { isURL } from 'cb-wallet-data/utils/urlUtils';
