import { useHandleUniversalLink } from ':rn/shared/hooks/useDeeplinking/useHandleUniversalLink';
import { useOpenUrlInBrowser } from ':rn/shared/hooks/useOpenUrlInBrowser';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { SectionHeader } from '../SectionHeader/SectionHeader';
import { ExploreAnalyticsProps } from '../type';

type GenericExploreCardProps = ExploreAnalyticsProps & {
  card: ExploreCard;
  width?: DimensionValue;
  isSingleCardSection?: boolean; // for styling
};

export const GENERIC_EXPLORE_CARD_SMALL_IMAGE_HEIGHT = 86;

export function GenericExploreCard({
  card,
  rowIndex,
  width,
  isSingleCardSection = false,
}: GenericExploreCardProps) {
  const {
    id: componentName,
    sectionHeader,
    title,
    subtext,
    caption,
    image,
    imageUrl,
    targetParams,
    onPress,
    testID,
  } = card;
  const openUrlInBrowser = useOpenUrlInBrowser();
  const { navigate } = useStackNavigation();

  const handleDeeplink = useHandleUniversalLink();

  useOnMount(() => {
    logExploreCardViewed({ componentName, rowIndex });
  });

  const handleOnPress = useCallback(
    function handleOnPress() {
      onPress?.();
      logExploreCardClicked({ componentName, rowIndex });

      const { targetUrl } = card;
      if (!targetUrl) return;

      if (handleDeeplink(targetUrl)) return;

      if (isURL(targetUrl)) {
        openUrlInBrowser(targetUrl);
      } else {
        navigate(targetUrl, targetParams);
      }
    },
    [
      card,
      componentName,
      handleDeeplink,
      navigate,
      onPress,
      openUrlInBrowser,
      rowIndex,
      targetParams,
    ],
  );

  const containerStyle: BoxProps = useMemo(() => {
    if (isSingleCardSection) {
      return { spacingHorizontal: 3 };
    }

    // multi card section already have list styling
    return { spacingStart: 0, spacingEnd: 1 };
  }, [isSingleCardSection]);

  return (
    <VStack gap={1}>
      <SectionHeader label={sectionHeader} />
      <Box testID={testID} width={width} {...containerStyle}>
        <Pressable
          background="backgroundAlternate"
          borderRadius="roundedLarge"
          onPress={handleOnPress}
          testID="generic-explore-card"
        >
          <HStack justifyContent="space-between" spacing={2}>
            <VStack gap={0.5} width="60%">
              <TextHeadline ellipsize="tail" numberOfLines={2}>
                {title}
              </TextHeadline>

              <TextLabel2 color="foregroundMuted" testID="card-subtext" numberOfLines={3}>
                {subtext}
              </TextLabel2>

              {caption}
            </VStack>

            <Box
              width="40%"
              borderRadius="roundedLarge"
              borderColor="secondary"
              alignSelf="center"
              alignItems="flex-end"
            >
              {imageUrl ? (
                <RemoteImageWithLoader
                  height={GENERIC_EXPLORE_CARD_SMALL_IMAGE_HEIGHT}
                  width={GENERIC_EXPLORE_CARD_SMALL_IMAGE_HEIGHT}
                  source={imageUrl}
                  hasBackground
                  testID="generic-explore-card-media"
                  borderRadius="roundedLarge"
                />
              ) : (
                image
              )}
            </Box>
          </HStack>
        </Pressable>
      </Box>
    </VStack>
  );
}

export const GenericExploreCardLoader = memo(function GenericExploreCardLoader() {
  return (
    <HStack spacingStart={3} spacingTop={1} testID="generic-card-loader">
      {Array(3)
