import { useHasNotification } from ':rn/screens/Explore/hooks/useHasNotification';

type CollectionCardProps = {
  drop: ExploreDrop;
  includeMarketplaceLinks: boolean;
  onPress: (hasReminder: boolean) => void;
  onMediaLoadSuccess?: () => void;
  onMediaLoadError?: () => void;
  onLivePress?: () => void;
};

export function NFTDrop({
  drop,
  includeMarketplaceLinks,
  onPress,
  onMediaLoadSuccess,
  onMediaLoadError,
  onLivePress,
}: CollectionCardProps) {
  const countdownText = useGetCountdownText(drop.releaseTime);
  const hasNotificationStored = useHasNotification(drop.name, includeMarketplaceLinks);
  const [hasNotification, setHasNotification] = useState(hasNotificationStored);

  useEffect(
    function setNotificationStatus() {
      if (!includeMarketplaceLinks) {
        setHasNotification(hasNotificationStored);
      }
    },
    [hasNotificationStored, includeMarketplaceLinks],
  );

  const enableNotification = useMemo(() => {
    const today = new Date();

    const difference = drop.releaseTime.getTime() - today.getTime();
    return difference > 0;
  }, [drop.releaseTime]);

  const handlePress = useCallback(
    function handlePress() {
      if (enableNotification) {
        onPress(hasNotification);
        if (!includeMarketplaceLinks) {
          setHasNotification((prevHasNotification) => !prevHasNotification);
        }
      } else {
        onLivePress?.();
      }
    },
    [enableNotification, onPress, hasNotification, includeMarketplaceLinks, onLivePress],
  );

  return (
    <Box width={316}>
      <Pressable background="transparent" borderRadius="rounded" onPress={handlePress}>
        <VStack>
          <CollectibleAsset
            contractAddress={drop.contractAddress}
            height={EXPLORE_DROP_IMAGE_HEIGHT}
            width={EXPLORE_DROP_IMAGE_WIDTH}
            animationUrl=""
            imageUrl={drop.imageUrl}
            cachedImageUrl={drop.cachedImageUrl}
            chainId="1"
            borderRadius="roundedLarge"
            retrievalMethod={RetrievalMethod.FETCH}
            onMediaLoadSuccess={onMediaLoadSuccess}
            onMediaLoadError={onMediaLoadError}
            testID="upcoming-drop"
            hasBackground
            preview
            resizeMode="cover"
          />
          <TextHeadline ellipsize="tail" spacingTop={0.5}>
            {drop.name}
          </TextHeadline>
          <OverlayText
            left={10}
            top={10}
            position="absolute"
            opacity={0.8}
            borderRadius="roundedSmall"
          >
            <TextLabel1 color="foreground" testID="upcoming-drop-countdown-overlay">
              {countdownText}
            </TextLabel1>
          </OverlayText>
          {enableNotification ? (
            <OverlayText
              right={10}
              top={10}
              position="absolute"
              opacity={0.8}
              borderRadius="roundedFull"
            >
              {/* TODO Update to Icon once CDS is updated */}
              <NavigationIcon
                name="bell"
                active={hasNotification}
                size="m"
                testID="upcoming-drop-notification-overlay"
                // @ts-expect-error TS(2322): Type '{ name: "bell"; active: boolean; size: "m"; ... Remove this comment to see the full error message
                color="foreground"
              />
            </OverlayText>
          ) : null}
          <TextBody testID="upcoming-drop-release-time">
            <FormattedDateParts value={drop.releaseTime} month="short" day="2-digit">
              {(parts: Intl.DateTimeFormatPart[]) => (
                <>{`${parts[0].value}${parts[1].value}${parts[2].value},`}</>
              )}
            </FormattedDateParts>
            <Spacer horizontal={0.5} />
            <FormattedTimeParts value={drop.releaseTime} hour="numeric" minute="numeric">
              {(parts: Intl.DateTimeFormatPart[]) => (
                <>{`${parts[0].value}${parts[1].value}${parts[2].value}${parts[4]?.value ?? ''}`}</>
              )}
            </FormattedTimeParts>
          </TextBody>
        </VStack>
      </Pressable>
    </Box>
  );
}

