type WatchlistCardProps = {
  cardMaxWidth: number;
  index: number;
  nameMaxWidth: number;
  watchlistItem: WatchlistItem;
  rowIndex: number;
};

const WatchlistCard = memo(function WatchlistCard({
  cardMaxWidth,
  index,
  nameMaxWidth,
  watchlistItem,
  rowIndex,
}: WatchlistCardProps) {
  const { navigate } = useStackNavigation();

  const stableWatchlistItem = useMemo(
    () => ({ ...watchlistItem, address: watchlistItem.contractAddress }),
    [watchlistItem],
  );

  const asset = useWatchlistItem(stableWatchlistItem);
  const formattedAmount = useWatchedAssetPrice(asset);
  const activeWalletGroupId = useActiveWalletGroupId();
  const getExploreAssetWallet = useGetExploreAssetWallet(activeWalletGroupId);
  const assetWallet = getExploreAssetWallet(asset.id);

  const { variant, label } = useFormatPercentChange({ percentChange: asset.priceChange });

  const eventData = useMemo(
    () => ({
      chainName: stableWatchlistItem.blockchain,
      componentPlacement: ComponentPlacementEnum.L1,
      entityName: stableWatchlistItem.name,
      entityType:
        stableWatchlistItem.type === 'OBJECT_TYPE_NFT' ? EntityTypeEnum.NFT : EntityTypeEnum.ASSET,
      rankIndex: index,
      rowIndex,
    }),
    [
      index,
      rowIndex,
