import { ActionType, ComponentType } from '@cbhq/client-analytics';

import { AssetAvatar } from ':rn/screens/GlobalSearch/components/avatars/AssetAvatar';
import { GenericAvatar } from ':rn/screens/GlobalSearch/components/avatars/GenericAvatar';
import { useRecentSearches } from ':rn/screens/GlobalSearch/hooks/useRecentSearches';
import {
  GlobalSearchEntitySubTitles,
  GlobalSearchRoutes,
} from ':rn/screens/GlobalSearch/utils/constants';
import { SearchResultAvatar as ENSAvatar } from ':rn/screens/Search/components/SearchResultAvatar';
import { useIsWalletNewArchEnabled } from ':rn/shared/hooks/useIsWalletNewArchEnabled';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

const messages = defineMessages({
  title: {
    defaultMessage: 'Recent',
    description: 'Title for recent searches',
  },
  clearLabel: {
    defaultMessage: 'Clear',
    description: 'Label for clearing all searches',
  },
  a11yLabel: {
    defaultMessage: 'Button to clear all recent searches',
    description: 'Accessibility label to clear all searches',
  },
});

const outerCellSpacing: CellSpacing = { spacingHorizontal: 2 };

export function RecentSearches() {
  const isWalletNewArchEnabled = useIsWalletNewArchEnabled();
  const { formatMessage } = useIntl();
  const { recentSearches, deleteAllRecentSearches } = useRecentSearches();
  const { navigate } = useStackNavigation();

  const handlePress = useCallback(
    ({ assetName, searchEntity, navigationProps }: RecentSearch<GlobalSearchEntity>) => {
      return function handleRecentSearchItemPress() {
        const navigateTo =
          isWalletNewArchEnabled &&
          searchEntity === GlobalSearchEntity.SEARCH_ENTITY_NFT_COLLECTIONS
            ? 'HomeTab'
            : GlobalSearchRoutes[searchEntity];
        logEvent('global_search.recent_search.clicked', {
          action: ActionType.click,
          componentType: ComponentType.button,
          searchResultName: assetName,
          searchResultType: searchEntity,
        });
        navigate(navigateTo, navigationProps);
      };
    },
    [isWalletNewArchEnabled, navigate],
  );

  const handleClearPress = useCallback(() => {
    deleteAllRecentSearches();
  }, [deleteAllRecentSearches]);

  const renderRecentSearchItem = useCallback(
    ({ item: searchItem }: ListRenderItemInfo<RecentSearch<GlobalSearchEntity>>) => {
      const { key, assetName, assetImageSrc, searchEntity, assetCurrencyCode, assetNetworkBadge } =
        searchItem;
      let mediaComponent;

      switch (searchEntity) {
        case GlobalSearchEntity.SEARCH_ENTITY_ASSET:
          mediaComponent = (
            <AssetAvatar
              testID="recent-search-asset-avatar"
              assetSrc={assetImageSrc}
              assetCurrencyCode={assetCurrencyCode}
              networkBadgeSrc={assetNetworkBadge}
            />
          );
          break;
        case GlobalSearchEntity.SEARCH_ENTITY_ENS:
          mediaComponent = <ENSAvatar size="l" imageUrl={assetImageSrc} />;
          break;
        default:
          mediaComponent = (
            <GenericAvatar
              testID="recent-search-generic-avatar"
              src={assetImageSrc}
              size="l"
              shape="circle"
            />
          );
      }

      return (
        <ListCell
          key={key}
          title={assetName}
          description={GlobalSearchEntitySubTitles[searchEntity]}
          media={mediaComponent}
          onPress={handlePress(searchItem)}
          outerSpacing={outerCellSpacing}
        />
      );
    },
    [handlePress],
  );

  if (!recentSearches.length) {
    return null;
  }

  return (
    <VStack spacingTop={3} height="90%">
      <HStack spacingHorizontal={2} justifyContent="space-between" spacingBottom={2}>
        <TextTitle3>{formatMessage(messages.title)}</TextTitle3>
        <TextHeadline
          testID="recent-seaches-clear-button"
          onPress={handleClearPress}
          color="primary"
          accessibilityLabel={formatMessage(messages.a11yLabel)}
          accessibilityRole="link"
        >
          {formatMessage(messages.clearLabel)}
        </TextHeadline>
      </HStack>
      <FlatList
        testID="recent-search-list"
        data={recentSearches}
        renderItem={renderRecentSearchItem}
        keyboardShouldPersistTaps="always"
        keyboardDismissMode="on-drag"
      />
    </VStack>
  );
}

import { ReactElement, useCallback, useEffect, useMemo, useRef } from 'react';
import { SectionList, SectionListData } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { logEvent, useLogEventOnMount } from 'cb-wallet-analytics/utils/log';
import { useIsFeatureEnabled } from 'cb-wallet-data/FeatureManager/hooks/useIsFeatureEnabled';
import { GlobalSearchEntity } from 'cb-wallet-data/stores/Search/types';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';
import { markJourney, useJourneyMarkOnMount } from '@cbhq/core-vitals-mobile';

import { Loader } from ':rn/screens/GlobalSearch/components/Loader';
import { SearchFilter } from ':rn/screens/GlobalSearch/components/SearchFilter';
import { useGlobalSearchResults } from ':rn/screens/GlobalSearch/hooks/useGlobalSearchResults';

import { SearchResultListItem, SearchResultProps } from './SearchResultListItem';

const messages = defineMessages({
  noResultsFound: {
    defaultMessage: 'No results for "{query}"',
    description: 'Helper message for no results found',
  },
  a11yLabel: {
    defaultMessage: 'Search Result {title}',
    description: ' Accessibility label to choose a search result',
  },
});

type SearchResultListProps = {
  query: string;
  searchFilter: GlobalSearchEntity;
  setSearchFilter: (filter: GlobalSearchEntity) => void;
};

export function SearchResultList({ query, searchFilter, setSearchFilter }: SearchResultListProps) {
  const { formatMessage } = useIntl();
  const { sections, isLoading } = useGlobalSearchResults(query, searchFilter);
  const previousSectionsRef = useRef(sections);
  const isGlobalSearchUsingWacEnabled = useIsFeatureEnabled('global_search_using_wac');
  const isEmptyState = useMemo(
    () => sections.reduce((acc, section) => acc + section.data.length, 0) === 0,
    [sections],
  );

  useEffect(
    function logSearchQuery() {
      logEvent('global_search.search_bar.query', {
        action: ActionType.search,
        componentType: ComponentType.search_bar,
        searchQuery: query,
        searchFilter,
      });
      markJourney('start_global_search_fetch');
    },
    [query, searchFilter],
  );

  const sectionsToRender = useMemo(() => {
    // If we are loading and there is no data from client side filtering,
    // we want to keep the previous sections to avoid flickering
    if (isLoading && isEmptyState) return previousSectionsRef.current;

    previousSectionsRef.current = sections;

    // If we are searching via WAC, we don't need to filter the sections as the results are driven from BE
    if (isGlobalSearchUsingWacEnabled) {
      return sections;
    }

    if (searchFilter !== GlobalSearchEntity.SEARCH_ENTITY_UNSPECIFIED) {
      return sections.filter((section) => section.searchEntity === searchFilter);
    }

    return sections;
  }, [isLoading, isEmptyState, sections, isGlobalSearchUsingWacEnabled, searchFilter]);

  const isEmptyStateWithFilters = useMemo(
    () => sectionsToRender.reduce((acc, section) => acc + section.data.length, 0) === 0,
    [sectionsToRender],
  );

  const renderItem = useCallback(
    ({
      item,
      section,
    }: {
      item: SearchResultProps<GlobalSearchEntity>;
      section: SectionListData<SearchResultProps<GlobalSearchEntity>>;
    }) => {
      return (
        <PressableOpacity
          key={item.key}
          accessibilityLabel={formatMessage(messages.a11yLabel, { title: item.title })}
        >
          <SearchResultListItem
            {...item}
            searchEntity={
              section.searchEntity !== GlobalSearchEntity.SEARCH_ENTITY_UNSPECIFIED
                ? section.searchEntity
                : item.searchEntity
            }
          />
        </PressableOpacity>
      );
    },
    [formatMessage],
  );

  return (
    <VStack height="90%">
      <SearchFilter selectedFilter={searchFilter} setSelectedFilter={setSearchFilter} />
      {isLoading ? (
        <Loader />
      ) : (
        <SearchResultListItems
          renderItem={renderItem}
          sections={sectionsToRender}
          query={query}
          isEmptyState={isEmptyStateWithFilters}
        />
      )}
    </VStack>
  );
}

type SearchResultListItemsProps = {
  renderItem: ({
    item,
    section,
  }: {
    item: SearchResultProps<GlobalSearchEntity>;
    section: SectionListData<SearchResultProps<GlobalSearchEntity>>;
  }) => ReactElement;
  sections: SectionListData<SearchResultProps<GlobalSearchEntity>>[];
  query: string;
  isEmptyState: boolean;
};

function SearchResultListItems({
  renderItem,
  sections,
  query,
  isEmptyState,
}: SearchResultListItemsProps) {
  useJourneyMarkOnMount('loaded_global_search_results');
  const { formatMessage } = useIntl();
  useLogEventOnMount('global_search.results_list.viewed', {
    action: ActionType.view,
    componentType: ComponentType.page,
    searchQuery: query,
    isEmptyResults: isEmptyState,
  });

  return isEmptyState ? (
    <Box justifyContent="center" alignItems="center" spacingTop={2}>
      <TextBody color="foregroundMuted">
        {formatMessage(messages.noResultsFound, { query })}
      </TextBody>
    </Box>
  ) : (
    <SectionList
      sections={sections}
      renderItem={renderItem}
      keyboardShouldPersistTaps="always"
      keyboardDismissMode="on-drag"
    />
  );
}

import { memo, useCallback, useMemo, useState } from 'react';
import {
  triggerWalletGroupNicknameUpdated,
  useTriggerEditWalletNicknameScreenViewed,
} from 'cb-wallet-analytics/accounts';
import { useUserFacingTerminology } from 'cb-wallet-data/hooks/copy/useUserFacingTerminology';
