export const testID = `edit-nickname`;

function EditNickname() {
  const { goBack } = useStackNavigation();
  const { walletGroupId } = useParams<ManageWalletsParamList, 'EditWallet'>();
  const toast = useRateLimitedToast({});
  const updateWalletGroupNickname = useUpdateWalletGroupNickname();
  const walletGroup = useWalletGroupToDisplay(walletGroupId);
  const messages = useEditNicknameCopy();
  const { uiTermForWalletGroup } = useUserFacingTerminology();

  const [newNickname, setNewNickname] = useState<string>(walletGroup?.nickname || '');

  useTriggerEditWalletNicknameScreenViewed({
    componentType: ComponentType.page,
    walletIndex: walletGroup?.walletIndex.toString(),
  });

  if (!walletGroup) {
    throw new Error('Wallet group does not exist');
  }

  const handleNicknameInputChange = useCallback(
    (nickname: string) => {
      setNewNickname(nickname);
    },
    [setNewNickname],
  );

  const handlePressSave = useCallback(async () => {
    try {
      await updateWalletGroupNickname(walletGroupId, newNickname.trim());
      triggerWalletGroupNicknameUpdated({
        action: ActionType.click,
        componentType: ComponentType.button,
        walletIndex: walletGroup.walletIndex.toString(),
      });

      goBack();
    } catch {
      toast.show(messages.editLabelError, { bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET });
    }
  }, [
    newNickname,
    walletGroupId,
    walletGroup.walletIndex,
    updateWalletGroupNickname,
    messages.editLabelError,
    goBack,
    toast,
  ]);
  const defaultNickname = `${uiTermForWalletGroup} ${walletGroup.order}`;
  const navBar = useMemo<NavBarConfig>(() => ({ left: 'back' }), []);
  return (
    <Screen navBar={navBar}>
      <KeyboardAvoidingView>
        <VStack height="100%" justifyContent="space-between" spacingHorizontal={3}>
          <VStack gap={2} spacingBottom={6}>
            <TextTitle1 testID={`${testID}-title`}>{messages.editLabelTitle}</TextTitle1>
            <TextBody testID={`${testID}-description`} spacingBottom={1} color="foregroundMuted">
              {messages.editLabelDescription}
            </TextBody>
            <TextInput
              testID={`${testID}-input`}
              onChangeText={handleNicknameInputChange}
              placeholder={defaultNickname}
              autoCorrect={false}
              autoCapitalize="none"
              autoComplete="off"
              autoFocus
              label={messages.walletLabel}
              value={newNickname}
            />
          </VStack>
          <Box spacingBottom={2}>
            <Button testID={`${testID}-save-button`} onPress={handlePressSave}>
              {messages.saveButtonLabel}
            </Button>
          </Box>
        </VStack>
      </KeyboardAvoidingView>
    </Screen>
  );
}

const EditNicknameWithBoundary = memo(function EditNicknameWithBoundary() {
  return (
    <ScreenBoundary>
      <EditNickname />
    </ScreenBoundary>
  );
});

export { EditNicknameWithBoundary as EditNickname };

