import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

const HideWalletTitle = memo(function HideWalletTitle() {
  const sharedMessages = useHideWalletGroupCopy();

  return (
    <HStack alignItems="center" gap={1}>
      <TextBody>{sharedMessages.hideWalletSettingTitle}</TextBody>
      <TooltipIcon
        testID="hide-wallet-tooltip"
        iconName="info"
        title={sharedMessages.hideWalletSettingTitle}
        description={sharedMessages.hideWalletTooltipDetailText}
      />
    </HStack>
  );
});

type HideWalletSettingListCellProps = {
  walletGroup: WalletGroupToDisplay;
};

export const HideWalletSettingListCell = memo(function HideWalletSettingListCell({
  walletGroup,
}: HideWalletSettingListCellProps) {
  const { goBack, pop, getState, reset } = useStackNavigation();
  const { routes } = getState();
  const sharedMessages = useHideWalletGroupCopy();
  const setWalletGroupIsHidden = useSetWalletGroupIsHidden();
  const visibleWalletGroups = useWalletGroups({ visible: true });
  const toast = useRateLimitedToast({});
  const activeWalletGroupId = useActiveWalletGroupId();
  const setActiveWalletGroupId = useSetActiveWalletGroupId();
  const getWalletGroupDisplayName = useGetWalletGroupDisplayName();

  const availableWalletGroups = useMemo(
    () => visibleWalletGroups.filter((wg) => wg.id !== activeWalletGroupId),
    [visibleWalletGroups, activeWalletGroupId],
  );

  const newWalletGroupToDisplay = useWalletGroupToDisplay(availableWalletGroups[0]?.id);

  const walletGroupDisplayName = useMemo(
    () => getWalletGroupDisplayName(walletGroup),
    [getWalletGroupDisplayName, walletGroup],
  );

  const undoHideWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
    } catch {
      toast.show(sharedMessages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    setWalletGroupIsHidden,
    sharedMessages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const undoUnhideWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
    } catch {
      toast.show(sharedMessages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    setWalletGroupIsHidden,
    sharedMessages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const undoHideActiveWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
      setActiveWalletGroupId(walletGroup.id);
    } catch {
      toast.show(sharedMessages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    setActiveWalletGroupId,
    setWalletGroupIsHidden,
    sharedMessages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const navigateToAssets = useCallback(() => {
    reset({
      routes: [
        {
          name: 'TabNavigator',
          params: {
            screen: 'AssetsTab',
          },
        },
      ],
    });
  }, [reset]);

  const handleChange = useCallback(async () => {
    try {
      const newIsHiddenStatus = !walletGroup.isHidden;
      await setWalletGroupIsHidden(walletGroup.id, newIsHiddenStatus);
      triggerWalletGroupVisibilityToggled({
        action: ActionType.click,
        componentType: ComponentType.checkbox,
        walletIndex: walletGroup.walletIndex.toString(),
        isHidden: newIsHiddenStatus,
      });

      if (activeWalletGroupId === walletGroup.id) {
        setActiveWalletGroupId(availableWalletGroups[0]?.id);
        // <walletGroupDisplayName> is hidden. Switched to <newWalletGroupDisplayName>
        toast.show(
          `${walletGroupDisplayName} ${
            sharedMessages.activeWalletHiddenToastText
          } ${getWalletGroupDisplayName(newWalletGroupToDisplay)}.`,
          {
            bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
            action: {
              label: 'Undo',
              onPress: undoHideActiveWallet,
            },
          },
        );

        const prevRoute = routes[routes.length - 2].name;
        if (prevRoute === 'Settings') {
          navigateToAssets();
        } else {
          goBack();
        }
      } else if (!walletGroup.isHidden) {
        // <walletGroupDisplayName> is hidden
        toast.show(`${walletGroupDisplayName} ${sharedMessages.walletHiddenToastText}`, {
          bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
          action: {
            label: 'Undo',
            onPress: undoHideWallet,
          },
        });
        goBack();
      } else {
        // <walletGroupDisplayName> is visible
        toast.show(`${walletGroupDisplayName} ${sharedMessages.walletVisibleToastText}`, {
          bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
          action: {
            label: 'Undo',
            onPress: undoUnhideWallet,
          },
        });
        pop(2); // Go back 2 screens to avoid the empty "Hidden Wallets" page
      }
    } catch {
      toast.show(sharedMessages.hideWalletError, {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
    }
  }, [
    setWalletGroupIsHidden,
    walletGroup.id,
    walletGroup.isHidden,
    walletGroup.walletIndex,
    activeWalletGroupId,
    setActiveWalletGroupId,
    availableWalletGroups,
    toast,
    walletGroupDisplayName,
    sharedMessages.activeWalletHiddenToastText,
    sharedMessages.walletHiddenToastText,
    sharedMessages.walletVisibleToastText,
    sharedMessages.hideWalletError,
    getWalletGroupDisplayName,
    newWalletGroupToDisplay,
    undoHideActiveWallet,
    goBack,
    undoHideWallet,
    undoUnhideWallet,
    pop,
    routes,
    navigateToAssets,
  ]);

  const isHideWalletDisabled = useMemo(() => {
    return !walletGroup.isHidden && visibleWalletGroups.length <= 1;
  }, [visibleWalletGroups.length, walletGroup.isHidden]);

  const handleDisabledClick = useCallback(() => {
    toast.show(sharedMessages.disabledClickToastText, {
      bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
    });
  }, [sharedMessages.disabledClickToastText, toast]);

  return (
    <ListCell
      title={<HideWalletTitle />}
      action={
        <PressableOpacity onPress={isHideWalletDisabled ? handleDisabledClick : undefined}>
          <Switch
            testID={`hide-wallet-switch${walletGroup.isHidden ? '-checked' : ''}`}
            accessibilityLabel={sharedMessages.hideWalletSwitchLabel}
            onChange={handleChange}
            checked={walletGroup.isHidden}
            disabled={isHideWalletDisabled}
          />
        </PressableOpacity>
      }
    />
  );
});

import { memo, useCallback, useEffect, useRef } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import ViewShot, { CaptureOptions, captureRef } from 'react-native-view-shot';
import { logEvent } from 'cb-wallet-analytics/utils/log';
import { reportComponentError } from 'cb-wallet-data/errors/reportError';
import { isNFTAvatar } from 'cb-wallet-data/stores/DecentralizedID/types';
import { VStack } from '@cbhq/cds-mobile/layout';
import { ModalBody, ModalFooter, ModalHeader } from '@cbhq/cds-mobile/overlays';
import { TextBody, TextTitle1 } from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';
import { markJourney } from '@cbhq/core-vitals-mobile';

import { DEFAULT_TOAST_BOTTOM_OFFSET } from ':rn/cds-wallet/components/constants';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Modal } from ':rn/cds-wallet/components/Modal/Modal';
import {
  QR_CODE_SIZE,
  QR_LOGO_RADIUS,
  QR_LOGO_SIZE,
} from ':rn/cds-wallet/components/QRCode/QRCode';
import { QRCodeSVG } from ':rn/cds-wallet/components/QRCode/styled-qr/QRCodeSVG';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import { loadedQr } from ':rn/screens/Messaging/constants';
import { useInviteInformation } from ':rn/screens/Messaging/hooks/useInviteInformation';
import { useInviteToMessaging } from ':rn/screens/Messaging/hooks/useInviteToMessaging';
import { useShareQRCode } from ':rn/screens/Messaging/hooks/useShareQRCode';

const messages = defineMessages({
  ctaText: {
    defaultMessage: 'Invite friends',
    description: 'Text for CTA',
  },
  shareText: {
    defaultMessage: 'Share QR code',
    description: 'Text for share button',
  },
  shareFailedText: {
    defaultMessage: 'Unable to share QR code',
    description: 'Text for unable to share QR code toast',
  },
});

const options: CaptureOptions = { format: 'png', quality: 1 };

type MessagingInviteQrModalProps = {
  isVisible: boolean;
  closeModal: () => void;
};

export const MessagingInviteQrModal = memo(function MessagingInviteQrModal({
  isVisible,
  closeModal,
}: MessagingInviteQrModalProps) {
  const { formatMessage } = useIntl();
  const { isFetched, shareUrl, logo, subdomain, truncatedAddress } = useInviteInformation();
  const viewShotRef = useRef<ViewShot>(null);

  const handleInvite = useInviteToMessaging({ source: 'inbox' });
  const shareQRCode = useShareQRCode();
  const toast = useRateLimitedToast({});

  const handleShareQRCode = useCallback(async () => {
    const uri = await captureRef(viewShotRef, options);
    if (!uri) {
      reportComponentError({
        error: new Error('Url is undefined when sharing messaging QR code'),
        severity: 'error',
        isHandled: false,
      });
      toast.show(
        formatMessage(messages.shareFailedText, { bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET }),
      );
      closeModal();
      return;
    }

    shareQRCode(uri);
  }, [shareQRCode, closeModal, formatMessage, toast]);

  const isNftPfp = isNFTAvatar(logo?.uri);

  useEffect(
    function handleModalVisible() {
      if (isVisible) {
        logEvent('messaging.qr_modal.viewed', {
          componentType: ComponentType.modal,
          action: ActionType.view,
        });
        markJourney(loadedQr);
      }
    },
    [isVisible],
  );

  return (
    <Modal
      visible={isVisible}
      onRequestClose={closeModal}
      testID="messaging-invite-modal"
      hideDividers
    >
      <ModalHeader />
      <ModalBody>
        <ViewShot ref={viewShotRef}>
          <VStack alignItems="center" gap={3} spacingTop={8}>
            <QRCodeSVG
              isAsyncDataFetched={isFetched}
              value={shareUrl}
              size={QR_CODE_SIZE}
              logo={!isNftPfp ? logo : undefined}
              logoBorderRadius={QR_LOGO_RADIUS}
              logoSize={QR_LOGO_SIZE}
            />
            <TextTitle1 color="primary">{subdomain || truncatedAddress}</TextTitle1>
            {subdomain && (
              <TextBody testID="messaging-invite-modal-subdomain" color="foregroundMuted">
                {truncatedAddress}
              </TextBody>
            )}
          </VStack>
        </ViewShot>
      </ModalBody>
      <ModalFooter
        primaryAction={
          <VStack gap={2}>
            {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
            {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
            <Button
              endIcon="qrCode"
              onPress={handleShareQRCode}
              testID="messaging-share-qrcode-modal-button"
              accessibilityLabel={formatMessage(messages.shareText)}
            >
              {formatMessage(messages.shareText)}
            </Button>
            {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
            {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
            <Button
              variant="secondary"
              endIcon="share"
              onPress={handleInvite}
              testID="messaging-invite-modal-button"
              accessibilityLabel={formatMessage(messages.ctaText)}
            >
              {formatMessage(messages.ctaText)}
            </Button>
          </VStack>
        }
      />
    </Modal>
  );
});

import { memo, useCallback, useContext } from 'react';
import { DeviceEventEmitter } from 'react-native';
import { logEvent } from 'cb-wallet-analytics/utils/log';
import { RnEvents } from 'cb-wallet-data/stores/Messaging/constants';
import { clearConversationPreviewTable } from 'cb-wallet-data/stores/Messaging/database';
import { Box } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { ActionType, ComponentType } from '@cbhq/client-analytics';
import { markJourney } from '@cbhq/core-vitals-mobile';

import { NewMessageButton as NewMessageIcon } from ':rn/cds-wallet/images/Messaging/NewMessageButton';
import { isProduction } from ':rn/shared/config/env';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { navigateToComposer } from '../constants';
import { defaultMessagingContext, MessagingContext } from '../providers/MessagingContext';
import { InboxTab } from '../screens/Inbox/hooks/useInboxTabs';

type NewMessageButtonProps = {
  activeTab: InboxTab;
};

export const NewMessageButton = memo(function NewMessageButton({
  activeTab,
}: NewMessageButtonProps) {
  const { navigate } = useStackNavigation();
  const { setMessagingContext, messagingContext } = useContext(MessagingContext);

  const handleDisconnect = useCallback(
    function handleDisconnect() {
      if (isProduction) return;

      DeviceEventEmitter.emit(RnEvents.DISCONNECT);
      setMessagingContext(() => ({
        ...defaultMessagingContext.messagingContext,
        isLoading: false,
        isSignerReady: true,
      }));

      clearConversationPreviewTable();
    },
    [setMessagingContext],
  );

  const handleNewMessagePress = useCallback(() => {
    logEvent('messaging.composer.clicked', {
      action: ActionType.click,
      componentType: ComponentType.icon,
    });
    markJourney(navigateToComposer);
    navigate('NewMessage');
  }, [navigate]);

  const shouldHideButton =
    messagingContext.isLoading || !messagingContext.keys || activeTab !== InboxTab.messages;

  if (shouldHideButton) {
    return null;
  }

  return (
    <Box
      pin="bottom"
      alignItems="flex-end"
      spacingEnd={3}
      spacingBottom={3}
      pointerEvents="box-none"
    >
      <Pressable
        background="primary"
        borderRadius="roundedFull"
        elevation={2}
        testID="new-conversation-button"
        delayLongPress={1000}
        onPress={handleNewMessagePress}
        onLongPress={handleDisconnect}
      >
        <NewMessageIcon />
      </Pressable>
    </Box>
  );
});

import { memo, useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { triggerNotificationPressed } from 'cb-wallet-analytics/notifications/hubEvents';
import { useNotificationsHub } from 'cb-wallet-data/stores/NotificationsHub/hooks/useNotificationsHub';
import { useUpdateNotificationState } from 'cb-wallet-data/stores/NotificationsHub/hooks/useUpdateNotificationState';
import { ExternalNotificationItem } from 'cb-wallet-data/stores/NotificationsHub/types';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody, TextTitle3 } from '@cbhq/cds-mobile/typography';

import { NetworkBoundary } from ':rn/cds-wallet/components/ErrorBoundary/NetworkBoundary';
import { NotificationListCell } from ':rn/screens/NotificationsHub/Components/NotificationGroupList';
import { useNavigateToDeeplink } from ':rn/shared/hooks/useDeeplinking/useNavigateToDeeplink';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

const messages = defineMessages({
  notifications: {
    defaultMessage: 'Notifications',
    description: 'Title for notifications section',
  },
  seeAll: {
    defaultMessage: 'See all ({number})',
    description: 'Button text for see all notifications',
  },
  noNewNotifications: {
    defaultMessage: 'No new notifications',
    description: "Text for when there's no notifications",
  },
});

const NotificationsContent = memo(function Notifications() {
  const { navigate } = useStackNavigation();
  const { formatMessage } = useIntl();
  const { data } = useNotificationsHub();
  const { navigateToDeeplinkUrl } = useNavigateToDeeplink();
  const updateNotificationsAction = useUpdateNotificationState();
  const notifications = useMemo(
    () =>
      (data?.pages || [])
        .map((page) => {
          if (page.response.items) {
            return page.response.items;
          }
          return [];
        })
        .flat(),
    [data],
  );

  const onPressNotification = useCallback(
    (notification: ExternalNotificationItem) => {
      const url = notification?.payload.Payload.InAppStatic.url;
      updateNotificationsAction([notification]);
      triggerNotificationPressed({
        communicationId: notification.communication_id,
        notificationTitle: notification.payload.Payload.InAppStatic.title,
        notificationBody: notification.payload.Payload.InAppStatic.body,
        messageId: notification.notification_id,
        template: notification.template_name,
      });

      if (!url) {
        return;
      }
      navigateToDeeplinkUrl(url);
    },
    [navigateToDeeplinkUrl, updateNotificationsAction],
  );

  const handleSeeAllPress = useCallback(() => navigate('NotificationsHub'), [navigate]);

  return (
    <>
      <HStack
        justifyContent="space-between"
        alignItems="flex-end"
        spacingHorizontal={3}
        spacingTop={2}
      >
        <TextTitle3>{formatMessage(messages.notifications)}</TextTitle3>
        {notifications.length > 0 && (
          <Pressable
            onPress={handleSeeAllPress}
            background="transparent"
            testID="see-all-notifications"
          >
            <TextBody color="primary">
              {formatMessage(messages.seeAll, { number: notifications.length })}
            </TextBody>
          </Pressable>
        )}
      </HStack>

      <VStack>
        {!notifications.length && (
          <Box spacingTop={1} spacingStart={3}>
            <TextBody color="foregroundMuted" testID="no-new-notifications">
              {formatMessage(messages.noNewNotifications)}
            </TextBody>
          </Box>
        )}
        {!!notifications.length && (
          <NotificationListCell notification={notifications[0]} onPress={onPressNotification} />
        )}
      </VStack>
    </>
  );
});

export const Notifications = memo(function Notifications() {
  return (
    <NetworkBoundary fallback={null} errorFallback={null}>
      <NotificationsContent />
    </NetworkBoundary>
  );
});

import { memo, useCallback, useContext, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { logEvent } from 'cb-wallet-analytics/utils/log';
import { ETHEREUM_SYMBOL } from 'cb-wallet-data/chains/AccountBased/Ethereum/constants';
import { useOnBackground } from 'cb-wallet-data/hooks/useOnBackground';
import { useInvalidateMessagingSuggestionsQuery } from 'cb-wallet-data/stores/Messaging/hooks/useMessagingSuggestions';
import { ConversationBackTo } from 'cb-wallet-data/stores/Messaging/types';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { getTruncatedAddress } from 'cb-wallet-data/utils/getTruncatedAddress';
import { useSelectedWallet } from 'cb-wallet-data/Web3/hooks/useSelectedWallet';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system/PressableOpacity';
import { TextLegal, TextTitle3 } from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';

import { DEFAULT_TOAST_BOTTOM_OFFSET } from ':rn/cds-wallet/components/constants';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import { SubscribeIcon } from ':rn/cds-wallet/images/Messaging/Subscribe';
import { UnsubscribeIcon } from ':rn/cds-wallet/images/Messaging/Unsubscribe';
import { LensAppDomain } from ':rn/screens/Messaging/constants';
import { MessagingContext } from ':rn/screens/Messaging/providers/MessagingContext';
import { MessagingAvatar } from ':rn/screens/Messaging/screens/Inbox/components/MessagingAvatar';
import { useSprig } from ':rn/shared/analytics/sprig';
import { useConversationSubscribeTray } from ':rn/shared/components/GlobalTrayManager/ConversationSubscribeTray/hooks/useConversationSubscribeTray';
import { useOnNavigationEvent } from ':rn/shared/hooks/useOnNavigationEvent';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { useSubscribe } from '../hooks/useSubscribe';
import { getConversationMetadataByKey } from '../utils/getConversationMetadataByKey';

import { ConversationNavBarMenu } from './ConversationNavBarMenu';

type Props = {
  avatarSource: string | undefined;
  name: string;
  peerAddress: string;
  conversationKey: string;
  isNewConversation: boolean;
  hasDomainName?: boolean;
  appDomain?: string;
  backTo?: ConversationBackTo;
  isBlockedView?: boolean;
  conversationStartSource?: string;
  isRecipientOnNetwork: boolean;
};

export const messages = defineMessages({
  subscribeConfirmation: {
    defaultMessage: 'You are subscribed',
    description: 'Confirmation text for subscribing to a wallet address',
  },
  unsubscribeConfirmation: {
    defaultMessage: 'You are unsubscribed',
    description: 'Confirmation text for unsubscribing to a wallet address',
  },
  undo: {
    defaultMessage: 'Undo',
    description: 'Text for undo subscribe toast action',
  },
  subscribeFailed: {
    defaultMessage: 'Something went wrong when subscribing. Please try again.',
    description: 'Error message for failed subscribe',
  },
  unsubscribeFailed: {
    defaultMessage: 'Something went wrong when unsubscribing. Please try again.',
    description: 'Error message for failed unsubscribe',
  },
  navbarAccessibilityLabel: {
    defaultMessage: 'Conversation nav bar',
    description: 'accessibility label for conversation navbar',
  },
});

type SubscriptionEventContext =
  | 'subscribe'
  | 'unsubscribe'
  | 'undo_subscribe'
  | 'undo_unsubscribe'
  | 'subscribe_error'
  | 'unsubscribe_error';

export const ConversationNavBar = memo(function ConversationNavBar({
  avatarSource,
  name,
  peerAddress,
  conversationKey,
  isNewConversation,
  hasDomainName,
  appDomain,
  backTo,
  isBlockedView,
  conversationStartSource,
  isRecipientOnNetwork,
}: Props) {
  const { formatMessage } = useIntl();
  const { goBack, navigate, popStack } = useStackNavigation();
  const { sprigEventTrack } = useSprig();
  const { messagingContext } = useContext(MessagingContext);
  const { conversations } = messagingContext;

  const activeWalletGroupId = useActiveWalletGroupId();
  const evmWallet = useSelectedWallet(activeWalletGroupId, { blockchainSymbol: ETHEREUM_SYMBOL });
  const primaryAddress = evmWallet?.primaryAddress;
  const invalidateMessagingSuggestions = useInvalidateMessagingSuggestionsQuery();

  if (!primaryAddress) {
    throw new Error('Conversation: missing primary ETH address or account ID');
  }

  const includesLensIcon = useMemo(() => appDomain?.startsWith(LensAppDomain), [appDomain]);
  const lensPosition = useMemo(
    () => (includesLensIcon ? { right: -12, bottom: -2 } : undefined),
    [includesLensIcon],
  );
  const { isSubscribable, isSubscribed, subscribe, unsubscribe } = useSubscribe({ peerAddress });
  const { openConversationSubscribeTray } = useConversationSubscribeTray({ source: 'messaging' });

  const toast = useRateLimitedToast({});

  const conversationMetadata = useMemo(
    () => getConversationMetadataByKey(conversations, conversationKey),
    [conversationKey, conversations],
  );

  const conversationTopic = useMemo(() => conversationMetadata?.topic, [conversationMetadata]);

  const handleInvalidateMessagingSuggestions = useCallback(() => {
    // isNewConversation is true when navigating to a suggested conversation and is
    // updated after the first message is sent. This allows us to invalidate the
    // endpoint only after a user starts a conversation with a suggestion.
    if (conversationStartSource === 'suggestion' && !isNewConversation) {
      invalidateMessagingSuggestions(primaryAddress);
    }
  }, [conversationStartSource, invalidateMessagingSuggestions, isNewConversation, primaryAddress]);

  // invalidate suggestion query if user navigates away from the conversation
  useOnNavigationEvent('beforeRemove', handleInvalidateMessagingSuggestions);

  // invalidate suggestion query if user kills the app before navigating away from the conversation
  useOnBackground(handleInvalidateMessagingSuggestions);

  const handleBackPress = useCallback(() => {
    if (backTo === 'explore_profile') {
      popStack(); // resets AssetsTab to iniital route
      navigate('ExploreTab', {}); // navigates back to explore tab and renders the last explore screen
    } else if (backTo === 'inbox') {
      navigate('Inbox', { tabIndex: 0 });
    } else {
      goBack();
    }
    if (conversationStartSource === 'suggestion') {
      sprigEventTrack('messagingSuggestionBack');
    }
  }, [backTo, conversationStartSource, goBack, navigate, popStack, sprigEventTrack]);

  const handleProfilePress = useCallback(() => {
    navigate('Profile', { address: peerAddress });
  }, [navigate, peerAddress]);

  const logSubscribeEvent = useCallback(
    (context: SubscriptionEventContext) => {
      logEvent('messaging.subscription_action.clicked', {
        componentType: ComponentType.button,
        action: ActionType.click,
        walletAddress: peerAddress,
        context,
      });
    },
    [peerAddress],
  );

  const showErrorToast = useCallback(
    (message: string, subscriptionAction: 'subscribe' | 'unsubscribe') => {
      toast.show(message, {
        variant: 'negative',
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
      });
      logSubscribeEvent(`${subscriptionAction}_error`);
    },
    [toast, logSubscribeEvent],
  );

  const handleToggleSubscribePress = useCallback(async () => {
    if (isSubscribed) {
      try {
        await unsubscribe();
        logSubscribeEvent('unsubscribe');
      } catch {
        showErrorToast(formatMessage(messages.unsubscribeFailed), 'unsubscribe');
        return;
      }

      toast.show(formatMessage(messages.unsubscribeConfirmation), {
        bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
        action: {
          label: formatMessage(messages.undo),
          onPress: async () => {
            try {
              await subscribe(conversationTopic);
              logSubscribeEvent('undo_unsubscribe');
            } catch {
              showErrorToast(formatMessage(messages.subscribeFailed), 'subscribe');
            }
          },
        },
      });
    } else {
      openConversationSubscribeTray(peerAddress);
    }
  }, [
    isSubscribed,
    subscribe,
    unsubscribe,
    conversationTopic,
    showErrorToast,
    logSubscribeEvent,
    openConversationSubscribeTray,
    toast,
    formatMessage,
    peerAddress,
  ]);

  return (
    <HStack alignItems="center" spacingBottom={1} spacingHorizontal={1}>
      <IconButton
        name="backArrow"
        onPress={handleBackPress}
        transparent
        testID="conversation-nav-back-arrow"
      />

      <Box flexShrink={1} flexGrow={1}>
        <PressableOpacity
          onPress={handleProfilePress}
          testID="conversation-nav-name"
          accessibilityLabel={formatMessage(messages.navbarAccessibilityLabel)}
        >
          <HStack alignItems="center">
            <Box spacingEnd={includesLensIcon ? 2 : 1} justifyContent="center">
              <MessagingAvatar
                address={peerAddress}
                count={undefined}
                avatar={avatarSource}
                appDomain={appDomain}
                size="xl"
                lensPosition={lensPosition}
                lensIconSizeMultiplier={0.75}
              />
            </Box>
            <VStack flexShrink={1}>
              <HStack alignItems="center" gap={0.5}>
                <TextTitle3 noWrap ellipsizeMode="middle">
                  {name}
                </TextTitle3>
              </HStack>
              {!hasDomainName && (
                <TextLegal color="foregroundMuted">{getTruncatedAddress(peerAddress)}</TextLegal>
              )}
            </VStack>
          </HStack>
        </PressableOpacity>
      </Box>

      <HStack alignItems="center">
        {isRecipientOnNetwork && isSubscribable && (
          <PressableOpacity
            onPress={handleToggleSubscribePress}
            testID="conversation-nav-subscription-button"
          >
            {isSubscribed ? <UnsubscribeIcon /> : <SubscribeIcon />}
          </PressableOpacity>
        )}
        {isRecipientOnNetwork && (
          <ConversationNavBarMenu
            peerAddress={peerAddress}
            conversationKey={conversationKey}
            isNewConversation={isNewConversation}
            isBlockedView={isBlockedView}
          />
        )}
      </HStack>
    </HStack>
  );
});

