export const ConversationNavBarMenu = memo(function ConversationNavBarMenu({
  peerAddress,
  conversationKey,
  isNewConversation,
  isBlockedView,
}: ConversationNavBarMenuProps) {
  const { formatMessage } = useIntl();
  const { messagingContext } = useContext(MessagingContext);
  const { conversations } = messagingContext;
  const conversationStatuses = useConversationStatuses();
  const activeWalletGroupId = useActiveWalletGroupId();
  const evmWallet = useSelectedWallet(activeWalletGroupId, { blockchainSymbol: ETHEREUM_SYMBOL });
  const primaryAddress = evmWallet?.primaryAddress;

  const popOverRef = useRef<PopoverRef>(null);
  const anchorRef = useRef<View | null>(null);

  const isMuteEnabled = useIsFeatureEnabled('messaging_mute_conversation');
  const isReportEnabled = useIsFeatureEnabled('messaging_report_wallet_address');

  if (!primaryAddress) {
    throw new Error('Conversation: missing primary ETH address or account ID');
  }

  const conversationMetadata = useMemo(
    () => getConversationMetadataByKey(conversations, conversationKey),
    [conversationKey, conversations],
  );

  const conversationTopic = useMemo(() => conversationMetadata?.topic, [conversationMetadata]);

  const conversationStatus = useMemo(
    () =>
      forceStatusToNumber(
        getConversationStatusByConvoTopic(conversationStatuses, conversationTopic),
      ),
    [conversationTopic, conversationStatuses],
  );

  const isMuted = useMemo(
    () => getConversationIsMutedByConvoTopic(conversationStatuses, conversationTopic),
    [conversationTopic, conversationStatuses],
  );

  const unblockProps = useMemo(
    () => ({ address: primaryAddress, hasStatus: !!conversationStatus, conversationMetadata }),
    [conversationStatus, primaryAddress, conversationMetadata],
  );

  const blockProps = useMemo(
    () => ({
      address: primaryAddress,
      hasStatus: !!conversationStatus,
      conversationMetadata,
      peerAddress,
    }),
    [primaryAddress, conversationStatus, conversationMetadata, peerAddress],
  );

  const reportProps = useMemo(
    () => ({ ...blockProps, isBlockedView: !!isBlockedView }),
    [blockProps, isBlockedView],
  );

  const handleBlock = useHandleBlockPress({ ...blockProps });
  const handleUnblock = useHandleUnblockPress({ ...unblockProps });
  const handleReport = useHandleReportPress(reportProps);

  const updateConversationMute = useUpdateConversationMute();

  const handleToggleMute = useCallback(() => {
    updateConversationMute({ walletAddress: primaryAddress, conversationTopic, isMuted: !isMuted });
  }, [isMuted, primaryAddress, conversationTopic, updateConversationMute]);

  useLogEventOnMount('messaging.conversation_navbar.viewed', {
    componentType: ComponentType.page,
    action: ActionType.view,
    context: isBlockedView ? 'blocked' : 'approved',
  });

  const handleMorePress = useCallback(() => {
    popOverRef.current?.show({
      anchorRef: anchorRef.current,
      stickToPosition: Position.BOTTOM_RIGHT,
    });
  }, []);

  const handleBlockPress = useCallback(() => {
    logEvent('messaging.conversation_block.clicked', {
      componentType: ComponentType.button,
      action: ActionType.click,
    });
    handleBlock();
    popOverRef.current?.hide();
  }, [handleBlock]);

  const handleUnblockPress = useCallback(() => {
    logEvent('messaging.conversation_unblock.clicked', {
      componentType: ComponentType.button,
      action: ActionType.click,
    });
    handleUnblock();
    popOverRef.current?.hide();
  }, [handleUnblock]);

  const handleReportPress = useCallback(() => {
    logEvent('messaging.conversation_report.clicked', {
      componentType: ComponentType.button,
      action: ActionType.click,
    });
    handleReport();
    popOverRef.current?.hide();
  }, [handleReport]);

  const handleToggleMutePress = useCallback(() => {
    logEvent(
      isMuted ? 'messaging.conversation_unmute.clicked' : 'messaging.conversation_mute.clicked',
      {
        componentType: ComponentType.button,
        action: ActionType.click,
      },
    );

    handleToggleMute();
    popOverRef.current?.hide();
  }, [handleToggleMute, isMuted]);

  return (
    <Box ref={anchorRef} testID="conversation-nav-bar-menu">
      <IconButton
        testID="conversation-nav-bar-menu-icon"
        name="more"
        transparent
        onPress={handleMorePress}
      />
      <PopoverMenu
        key="conversation-nav-bar-menu"
        ref={popOverRef}
        testID="conversation-nav-bar-menu-popover"
      >
        {isMuteEnabled && (
          <ConversationNavBarMenuItem
            testID={isMuted ? 'unmute' : 'mute'}
            label={isMuted ? formatMessage(messages.unmute) : formatMessage(messages.mute)}
            disabled={isNewConversation}
            onPress={handleToggleMutePress}
          />
        )}
        <ConversationNavBarMenuItem
          testID={isBlockedView ? 'unblock' : 'block'}
          label={isBlockedView ? formatMessage(messages.unblock) : formatMessage(messages.block)}
          color="negative"
          onPress={isBlockedView ? handleUnblockPress : handleBlockPress}
        />
        {isReportEnabled && (
          <ConversationNavBarMenuItem
            testID="report"
            label={formatMessage(messages.report)}
            color="negative"
            onPress={handleReportPress}
          />
        )}
      </PopoverMenu>
    </Box>
  );
});

