export const ConversationPaymentTile = memo(function ConversationPaymentTile({
  showMaxButton = true,
  allowExceedMax = true,
  isLoading = false,
  errorMessage,
  onContinue,
  onClose,
  onOpenAssetSelector,
  onAmountChange,
  onMaxButtonPress,
}: ConversationPaymentTileProps) {
  const { formatMessage } = useIntl();
  const [cryptoAmount, updateCryptoAmount] = useState(0n);
  const [sourceWallet, setSourceWallet] = useState<Wallet | undefined>();
  const isSmallScreen = useIsSmallScreen();
  const [
    walletsSelectorModalVisible,
    { toggleOn: showWalletsSelectorModal, toggleOff: hideWalletsSelectorModal },
  ] = useToggler(false);
  const isSponsoredWallet = Boolean(useGetSponsoredSendInfo(sourceWallet));
  const wallets = useVisiblePortfolioWallets();
  const evmWallets = useMemo(
    () => wallets?.filter((wallet) => wallet.blockchain?.rawValue === ETHEREUM_SYMBOL),
    [wallets],
  );

  const {
    primaryAmount,
    secondaryAmount,
    availableBalance,
    onChange,
    toggleIsFiat,
    isFiat,
    activeFiatCurrency,
    onPressMaxButton,
    isExceedingMax,
  } = useAmountInputValues({
    allowExceedMax,
    cryptoAmount,
    updateCryptoAmount,
    sourceWallet,
    requireExchangeRate: false,
    onCryptoAmountChange: undefined,
    txType: GasEstimateTxType.SEND,
  });

  const disableContinue = useMemo(
    () => cryptoAmount === 0n || isExceedingMax || Boolean(errorMessage),
    [cryptoAmount, isExceedingMax, errorMessage],
  );

  const handleOnPressWallet = useCallback(() => {
    onOpenAssetSelector?.();
    showWalletsSelectorModal();
  }, [showWalletsSelectorModal, onOpenAssetSelector]);

  const handleOnSelectWallet = useCallback(
    (wallet: Wallet) => {
      setSourceWallet(wallet);
      hideWalletsSelectorModal();
    },
    [hideWalletsSelectorModal],
  );

  const handleOnAmountChange = useCallback(
    (numPadValue: NumPadValue) => {
      onAmountChange?.(numPadValue);
      onChange(numPadValue);
    },
    [onChange, onAmountChange],
  );

  const handleMaxButtonPress = useCallback(() => {
    onMaxButtonPress?.();
    onPressMaxButton();
  }, [onMaxButtonPress, onPressMaxButton]);

  const handleContinuePress = useCallback(() => {
    onContinue({
      amount: cryptoAmount,
      wallet: sourceWallet,
      isSponsored: isSponsoredWallet,
    });
  }, [cryptoAmount, sourceWallet, onContinue, isSponsoredWallet]);

  const preferredWallet = usePreferredUsdcWallet();
  useOnMount(function setDefaultSourceWallet() {
    if (!sourceWallet && evmWallets?.length) {
      setSourceWallet(preferredWallet || evmWallets[0]);
    }
  });

  return (
    <Tray
      testID="conversation-payment-tile"
      onCloseComplete={onClose}
      preventDismissGestures={walletsSelectorModalVisible}
    >
      {!evmWallets?.length && <EmptyWallet onAddCryptoPress={onClose} />}
      {!!evmWallets?.length && (
        <VStack gap={1} spacingHorizontal={2} spacingBottom={4}>
          <HStack justifyContent="center" alignItems="center" gap={0.5}>
            <AssetIcon
              network={sourceWallet?.network}
              iconUrl={sourceWallet?.imageURL?.toString() ?? ''}
              currencyCode={sourceWallet?.currencyCode?.code ?? ''}
              showNetworkIcon
              height={ASSET_ICON_HEIGHT}
              width={ASSET_ICON_HEIGHT}
            />
            <Pressable
              onPress={handleOnPressWallet}
              background="transparent"
              transparentWhilePressed
            >
              <HStack justifyContent="center" alignItems="center">
                <VStack spacingEnd={1}>
                  <TextHeadline spacingStart={1}>{sourceWallet?.displayName}</TextHeadline>
                  {isSponsoredWallet && (
                    <TextLabel1 spacingStart={1} color="positive">
                      {formatMessage(messages.freeToSend)}
                    </TextLabel1>
                  )}
                </VStack>
                <Icon name="caretDown" color="secondaryForeground" size="s" />
              </HStack>
            </Pressable>
          </HStack>
          <AmountInput
            wallet={sourceWallet}
            primaryAmount={primaryAmount}
            secondaryAmount={secondaryAmount}
            toggleIsFiat={toggleIsFiat}
            activeFiatCurrency={activeFiatCurrency}
            tertiaryAmount={availableBalance}
            isFiat={isFiat}
            isSmallScreen={isSmallScreen}
            hideMaxButton={!showMaxButton}
            onPressMaxButton={handleMaxButtonPress}
          />
          <NumPad allowDecimalSeparator onPress={handleOnAmountChange} />
          <Button
            testID="conversation-payment-tile-continue-button"
            block
            onPress={handleContinuePress}
            disabled={disableContinue}
            loading={isLoading}
          >
            {formatMessage(messages.continueButton)}
          </Button>
          {Boolean(errorMessage) && (
            <TextBody align="center" color="negative">
              {errorMessage}
            </TextBody>
          )}
        </VStack>
      )}
      <ConversationWalletSelector
        visible={walletsSelectorModalVisible}
        onSelect={handleOnSelectWallet}
        onClose={hideWalletsSelectorModal}
      />
    </Tray>
  );
});

