import { useGetTransactionErrorMessage } from '../hooks/useGetTransactionErrorMessage';
import { useHandleMessagingAttachments } from '../hooks/useHandleMessagingAttachment';
import { useHandleMessagingSendCryptoSignSuccess } from '../hooks/useHandleMessagingSendCryptoSignSuccess';
import { useSignTransactionAndSendMessage } from '../hooks/useSignTransactionAndSendMessage';

import { useImageDimensionStyles } from './MessageAttachment/hooks/useImageDimensionStyles';
import { attachmentBase64Uri } from './MessageAttachment/utils';
import { ComposerButton } from './ComposerButton';
import { ContinueParams, ConversationPaymentTile } from './ConversationPaymentTile';

const messages = defineMessages({
  messageComposerPlaceholder: {
    defaultMessage: 'Message...',
    description: 'placeholder for messaging text input',
  },
  accessibilityLabel: {
    defaultMessage: 'send message',
    description: 'accessibility label for a submit button',
  },
});

type Props = {
  handleSendMessage: (
    event: GestureResponderEvent | NativeSyntheticEvent<TextInputSubmitEditingEventData>,
  ) => void;
  message: string;
  setMessage: Dispatch<SetStateAction<string>>;
  peerAddress: string;
  primaryAddress: string;
  conversationTopic: string | undefined;
  conversationKey: string | undefined;
  isNewConversation: boolean;
  attachment: ExtendedAttachment | undefined;
  setAttachment: Dispatch<SetStateAction<ExtendedAttachment | undefined>>;
};

export const COMPOSER_DIMENSION = 44;

export const MessageComposer = memo(function MessageComposer({
  handleSendMessage,
  message,
  setMessage,
  peerAddress,
  primaryAddress,
  conversationTopic,
  isNewConversation,
  attachment,
  setAttachment,
}: Props) {
  const { formatMessage } = useIntl();
  const palette = usePalette();
  const spectrum = useSpectrum();
  const [inputHeight, setInputHeight] = useState(0);
  const [errorMessage, setErrorMessage] = useState('');
  const [isTxnLoading, setIsTxnLoading] = useState(false);
  const initialInputHeight = useRef();
  const isMultilineInput =
    !!attachment || (initialInputHeight.current && inputHeight > initialInputHeight.current);
  const textInputStyle = useMemo(
    () => ({
      maxHeight:
        isMultilineInput && initialInputHeight.current
          ? initialInputHeight.current * 2.75
          : undefined,
      paddingStart: 10,
      paddingEnd: 10,
      paddingTop: 15,
      paddingBottom: 10,
      color: palette.foreground,
      fontFamily: 'CoinbaseSans-Regular',
      fontSize: 16,
    }),
    [isMultilineInput, palette.foreground],
  );
  const showSendButton = useMemo(
    () => !!message.trim().length || !!attachment,
    [attachment, message],
  );
  const isPaymentMessagingFlowKilled = useKillSwitch('kill_payment_messsaging_flow');
  const isMessagingAttachmentSendsEnabled = useIsFeatureEnabled('messaging_attachment_sends');
  const [paymentTileVisible, { toggleOn: showPaymentTile, toggleOff: hidePaymentTile }] =
    useToggler(false);
  const signTransactionAndSendMessage = useSignTransactionAndSendMessage();
  const getTransactionErrorMessage = useGetTransactionErrorMessage();
  const handleMaliciousAddressError = useHandleMaliciousAddress('messaging');
  const handleMessagingSendCryptoSignSuccess = useHandleMessagingSendCryptoSignSuccess();

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleHeightChange = useCallback(function handleHeightChange({ nativeEvent }: any) {
    if (!initialInputHeight.current) {
      initialInputHeight.current = nativeEvent.layout.height;
    }

    setInputHeight(nativeEvent.layout.height);
  }, []);

  const shouldShowPaymentSendButton = useMemo(
    () => !isPaymentMessagingFlowKilled && !isNewConversation && !attachment,
    [isPaymentMessagingFlowKilled, isNewConversation, attachment],
  );

  const clearErrorMessage = useCallback(() => {
    setErrorMessage('');
  }, []);

  const onPaymentTileClose = useCallback(() => {
    clearErrorMessage();
    hidePaymentTile();
  }, [clearErrorMessage, hidePaymentTile]);

  const handleMessagingAttachments = useHandleMessagingAttachments();

  const handleImageButtonPress = useCallback(async () => {
    logEvent('messaging.image_attachment.clicked', {
      componentType: ComponentType.button,
      action: ActionType.click,
    });
    const selectedAttachment = await handleMessagingAttachments();
    setAttachment(selectedAttachment);
  }, [handleMessagingAttachments, setAttachment]);

  const handleClearImageAttachment = useCallback(() => {
    setAttachment(undefined);
  }, [setAttachment]);

  const handlePaymentTileOpen = useCallback(
    function handlePaymentTileOpen() {
      logEvent('messaging.messaging_send_crypto.clicked', {
        componentType: ComponentType.tray,
        action: ActionType.click,
      });

      if (Keyboard.isVisible()) {
        Keyboard.dismiss();
      }

      showPaymentTile();
    },
    [showPaymentTile],
  );

  const handleOnContinue = useCallback(
    async function handleOnContinue({ amount, wallet, isSponsored }: ContinueParams) {
      logEvent('messaging.messaging_send_crypto_continue.clicked', {
        componentType: ComponentType.button,
        action: ActionType.click,
      });
      clearErrorMessage();
      try {
        setIsTxnLoading(true);
        await signTransactionAndSendMessage({
          amount,
          wallet,
          toAddress: peerAddress,
          fromAddress: primaryAddress,
          conversationTopic,
          isSponsored,
          onOpenSigningTray: hidePaymentTile,
        });
      } catch (err: ErrorOrAny) {
        const errMessage = getTransactionErrorMessage(err);

        if (
          err instanceof DataSanitizationError &&
          err.errorRawType === DataSanitizationErrorType.MALICIOUS_ADDRESS
        ) {
          hidePaymentTile();
          handleMaliciousAddressError(err, undefined, {
            onSignSuccess: (result) => {
              handleMessagingSendCryptoSignSuccess({
                result,
                toAddress: peerAddress,
                fromAddress: primaryAddress,
                conversationTopic,
                isSponsored,
              });
            },
          });
          return;
        }

        setErrorMessage(errMessage);
      } finally {
        setIsTxnLoading(false);
      }
    },
    [
      clearErrorMessage,
      signTransactionAndSendMessage,
      peerAddress,
      primaryAddress,
      conversationTopic,
      hidePaymentTile,
      getTransactionErrorMessage,
      handleMaliciousAddressError,
      handleMessagingSendCryptoSignSuccess,
    ],
  );

  const imageStyleDimensions = useImageDimensionStyles();
  const image = useMemo(() => {
    const imageUri = attachment
      ? attachmentBase64Uri({ extendedAttachment: attachment })
      : undefined;
    return {
      source: imageUri,
      styles: imageUri
        ? imageStyleDimensions({
            imageUri,
            heightBoundary: 0.2,
          })
        : undefined,
    };
  }, [attachment, imageStyleDimensions]);

  return (
    <>
      <Box>
        <HStack alignItems="flex-end" gap={1} spacing={2} spacingBottom={3}>
          {shouldShowPaymentSendButton && (
            <ComposerButton
              onPress={handlePaymentTileOpen}
              name="cashUSD"
              testID="send-funds-button"
            />
          )}
          {isMessagingAttachmentSendsEnabled && !attachment && (
            <ComposerButton
              onPress={handleImageButtonPress}
              testID="messaging-attachments-button"
              name="camera"
            />
          )}

          <Box
            background="backgroundAlternate"
            minHeight={COMPOSER_DIMENSION}
            borderRadius={isMultilineInput ? 'roundedLarge' : 'roundedFull'}
            flexGrow={1}
            flexShrink={1}
            spacingStart={1}
          >
            {attachment && (
              <Box height={image.styles?.maxHeight} spacing={1}>
                <PressableOpacity onPress={handleClearImageAttachment}>
                  <RemoteImageWithLoader
                    source={image.source}
                    height={image.styles?.maxHeight || 1}
                    resizeMode="cover"
                    // eslint-disable-next-line react/forbid-component-props
                    dangerouslySetStyle={image.styles}
                    borderRadius="rounded"
                  />
                </PressableOpacity>
              </Box>
            )}
            <Box spacingVertical={attachment ? 1 : 0}>
              <TextInput
                blurOnSubmit={false}
                keyboardAppearance={spectrum}
                keyboardType="default"
                multiline
                onChangeText={setMessage}
                onLayout={handleHeightChange}
                placeholder={formatMessage(messages.messageComposerPlaceholder)}
                placeholderTextColor={palette.foregroundMuted}
                // eslint-disable-next-line react/forbid-component-props
                style={textInputStyle}
                testID="message-composer-input"
                value={message}
                scrollEnabled={isMultilineInput}
              />
            </Box>
          </Box>
          {showSendButton && (
            <Box spacingBottom={0.5}>
              <IconButton
                accessibilityLabel={formatMessage(messages.accessibilityLabel)}
                name="paperAirplane"
                onPress={handleSendMessage}
                testID="message-composer-button"
                variant="primary"
              />
            </Box>
          )}
        </HStack>
      </Box>
      {paymentTileVisible && (
        <ConversationPaymentTile
          isLoading={isTxnLoading}
          showMaxButton
          allowExceedMax={false}
          errorMessage={errorMessage}
          onContinue={handleOnContinue}
          onClose={onPaymentTileClose}
          onOpenAssetSelector={clearErrorMessage}
          onAmountChange={clearErrorMessage}
          onMaxButtonPress={clearErrorMessage}
        />
      )}
    </>
  );
});

import { memo, useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { MessagingFullScreenTakeoverContent } from 'cb-wallet-data/stores/Messaging/types';
import { Box } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system';

import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { RemoteImageWithLoader } from ':rn/cds-wallet/components/RemoteImageWithLoader';
import { ConversationMessageListItem } from ':rn/screens/Messaging/screens/Conversation/hooks/useConversationSectionListData';
import { useMessageStyles } from ':rn/screens/Messaging/screens/Conversation/hooks/useMessageStyles';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { useImageDimensionStyles } from '../MessageAttachment/hooks/useImageDimensionStyles';
import { MessageContainer } from '../MessageContainer';
import { MessageStatus } from '../MessageStatus';

const messages = defineMessages({
  imageButtonAccessibilityLabel: {
    defaultMessage: 'Full screen takeover image button',
    description: 'accessibility label for FSTO button',
  },
});

type MessageFullScreenTakeoverProps = {
  item: ConversationMessageListItem;
  isSameAddress: boolean;
};

const IMAGE_BORDER_RADIUS = 8;
const lastPopupKeyPrefix = 'lastPopupMessageID';
const thirtySecondsInMilliseconds = 30 * 1000;

function MessageFullScreenTakeoverContent({ item, isSameAddress }: MessageFullScreenTakeoverProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const getImageDimensions = useImageDimensionStyles();
  const handleErrorPress = useCallback(() => {}, []);
  const fstoContent = item.content as MessagingFullScreenTakeoverContent;
  const imageStyles = getImageDimensions({ imageUri: fstoContent.imageURL });
  const { borderRadii } = useMessageStyles({
    item,
    isSameAddress,
  });
  const imageStyle = useMemo(
    () => ({
      ...imageStyles,
      borderRadius: IMAGE_BORDER_RADIUS,
      ...borderRadii,
    }),
    [imageStyles, borderRadii],
  );

  const handleImagePress = useCallback(() => {
    navigate('ImagePreview', { imageUri: fstoContent.imageURL });
  }, [fstoContent.imageURL, navigate]);

  useOnMount(() => {
    const lastPopupKey = `${lastPopupKeyPrefix}_${item.senderAddress}`;
    const lastPopupMessageID = localStorage.getItem(lastPopupKey);
    // check if sent time is within 30 seconds
    const sentTime = new Date(item.sent);
    const isWithin30Seconds =
      new Date().getTime() - sentTime.getTime() < thirtySecondsInMilliseconds;
    if (isWithin30Seconds && item.id !== lastPopupMessageID && fstoContent.displayPopup) {
      localStorage.setItem(lastPopupKey, item.id);
      navigate('FullScreenTakeover', {
        imageURL: fstoContent.imageURL,
        headerText: fstoContent.headerText,
        titleText: fstoContent.titleText,
        descriptionText: fstoContent.descriptionText,
        ctaType: fstoContent.ctaType,
        peerAddress: item.senderAddress,
      });
    }
  });

  if (!fstoContent.displayImageInChat) {
    return <></>;
  }

  return (
    <MessageContainer hasBorderRadius={item.hasBorderRadius} isSameAddress={isSameAddress}>
      <Box
        borderRadius="rounded"
        // eslint-disable-next-line react/forbid-component-props
        style={borderRadii}
        elevation={2}
        overflow="hidden"
      >
        <PressableOpacity
          accessibilityLabel={formatMessage(messages.imageButtonAccessibilityLabel)}
          testID="fsto-image"
          onPress={handleImagePress}
          noScaleOnPress
        >
          <RemoteImageWithLoader
            source={(item.content as unknown as MessagingFullScreenTakeoverContent).imageURL}
            height={imageStyle.height}
            resizeMode="cover"
            // eslint-disable-next-line react/forbid-component-props
            dangerouslySetStyle={imageStyle}
            borderRadius="rounded"
          />
        </PressableOpacity>
      </Box>

      {item.isLastItem && (
        <MessageStatus
          date={new Date(item.sent)}
          isError={!!item.error}
          isSameAddress={isSameAddress}
          itemId={item.id}
          handleErrorPress={handleErrorPress}
        />
      )}
    </MessageContainer>
  );
}

export const MessageFullScreenTakeover = memo(function MessageFullScreenTakeover({
  item,
  isSameAddress,
}: MessageFullScreenTakeoverProps) {
  return (
    <ErrorBoundary errorFallback={null}>
      <MessageFullScreenTakeoverContent item={item} isSameAddress={isSameAddress} />
    </ErrorBoundary>
  );
});

