type ListItemCheckboxProps = {
  preview: FormattedConversationPreview;
  isSelectable?: boolean;
};

export const ListItemCheckbox = memo(function ListItemCheckbox({
  preview,
  isSelectable,
}: ListItemCheckboxProps) {
  const requestsToManage = useRequestsToBlock();

  const convoTopic = preview.metadata?.topic;

  const isChecked = useMemo(
    () => !!convoTopic && requestsToManage.has(convoTopic),
    [requestsToManage, convoTopic],
  );

  const handleBulkBlockCheck = useHandleBulkBlockCheck();

  const handleOnChange = useCallback(() => {
    handleBulkBlockCheck({
      convoTopic,
      isChecked,
