  if (!isSelectable) return <></>;

  return (
    <Box spacingStart={3}>
      <Checkbox
        checked={isChecked}
        onChange={handleOnChange}
        value={preview.key}
        accessibilityLabel={preview.key}
        accessibilityRole="radio"
        testID="inbox-list-item-checkbox"
      />
    </Box>
  );
});

