import { memo, useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  SuggestionItem,
  SuggestionMetadata,
  SuggestionType,
} from 'cb-wallet-data/stores/Messaging/models/MessagingSuggestions';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Avatar } from '@cbhq/cds-mobile/media';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import { TextBody, TextHeadline } from '@cbhq/cds-mobile/typography';

import { FarcasterIcon } from ':rn/cds-wallet/images/Farcaster/Farcaster';
import { LensIcon } from ':rn/cds-wallet/images/Lens/Lens';
import { TransactedBefore } from ':rn/cds-wallet/images/Messaging/TransactedBefore';

const messages = defineMessages({
  transactedBefore: {
    defaultMessage: 'Transacted before',
    description: 'text for users who have sent crypto to someone in the past',
  },
  farcasterFollowing: {
    defaultMessage: 'Following on Farcaster',
    description: 'text for users who are following someone on farcaster social',
  },
  lensFollowing: {
    defaultMessage: 'Following on Lens',
    description: 'text for users who are following someone on lens social',
  },
  poapConnection: {
    defaultMessage: 'Poap in common',
    description: 'text for users who own a poap nft',
  },
});

type Params = {
  avatar: React.ReactNode;
  handlePress: (item: SuggestionItem) => void;
  item: SuggestionItem;
  name: string;
};

export const SuggestedConnectionListItem = memo(function SuggestedConnectionListItem({
  avatar,
  handlePress,
  item,
  name,
}: Params) {
  const { formatMessage } = useIntl();

  const handleOnPress = useCallback(() => {
    handlePress(item);
  }, [handlePress, item]);

  const renderSuggestion = useCallback(
    (idx: number, icon: React.ReactNode, suggestionText: string) => {
      return (
        <HStack key={idx} spacingTop={0.5} testID={`suggestion-data-${idx}`}>
          <Box width={25}>{icon}</Box>
          <Box maxWidth="85%">
            <TextBody spacingStart={1} ellipsize="tail" color="foregroundMuted">
              {suggestionText}
            </TextBody>
          </Box>
        </HStack>
      );
    },
    [],
  );

  const renderSuggestionMetadata = useCallback(
    (metadata: SuggestionMetadata, idx: number) => {
      switch (metadata.type) {
        case SuggestionType.SUGGESTION_TYPE_POAP:
          return renderSuggestion(
            idx,
            <Avatar size="m" alt="POAP" src={metadata.imageUrl} testID="pfp-avatar" />,
            formatMessage(messages.poapConnection),
          );
        case SuggestionType.SUGGESTION_TYPE_TRANSACTED_WITH:
          return renderSuggestion(
            idx,
            <TransactedBefore scaleMultiplier={1} />,
            formatMessage(messages.transactedBefore),
          );
        case SuggestionType.SUGGESTION_TYPE_LENS_FOLLOW:
          return renderSuggestion(
            idx,
            <LensIcon scaleMultiplier={1} />,
            formatMessage(messages.lensFollowing),
          );
        case SuggestionType.SUGGESTION_TYPE_FARCASTER_FOLLOW:
          return renderSuggestion(
            idx,
            <FarcasterIcon scaleMultiplier={1} />,
            formatMessage(messages.farcasterFollowing),
          );
        case SuggestionType.SUGGESTION_TYPE_UNSPECIFIED:
        default:
          return <></>;
      }
    },
    [renderSuggestion, formatMessage],
  );

  return (
    <PressableOpacity
      testID="connection-suggestion-item"
      onPress={handleOnPress}
      accessibilityLabel={name}
    >
      <HStack spacingBottom={1}>
        {avatar}
        <VStack width="100%" spacingTop={2}>
          <Box maxWidth="75%" spacingTop={0.5}>
            <TextHeadline ellipsize="middle" testID="suggestion-domain">
              {name}
            </TextHeadline>
            {item.suggestionMetadata.map(renderSuggestionMetadata)}
          </Box>
        </VStack>
      </HStack>
    </PressableOpacity>
  );
});

