import { SearchTabButton } from './SearchTabButton';

const messages = defineMessages({
  newMessage: {
    defaultMessage: 'New message',
    description: 'Title for new message flow',
  },
  invite: {
    defaultMessage: 'Invite',
    description: 'Text for invite button',
  },
  characterLimit: {
    defaultMessage: 'Type at least 3 characters to search',
    description: 'Minimum character limit for typeahead to start searching',
  },
  ens: {
    defaultMessage: 'ENS',
    description: 'Text for ENS search tab',
  },
  lens: {
    defaultMessage: 'Lens',
    description: 'Text for Lens search tab',
  },
  lensProfilePlaceholder: {
    defaultMessage: 'Lens profile',
    description: 'Text for Lens profile search placeholder',
  },
});

const NewMessage = memo(function NewMessage() {
  const { formatMessage } = useIntl();
  const [query, setQuery] = useState('');
  const [isEnsTabSelected, setIsEnsTabSelected] = useState(true);
  const debouncedQuery = useDebounce(query, 300).trim();
  const isProperLength = useIsProperSearchLength(debouncedQuery);
  const isValidEthAddress = useMemo(() => isValidAddress(debouncedQuery), [debouncedQuery]);
  const activeWalletGroupId = useActiveWalletGroupId();
  const evmWallet = useSelectedWallet(activeWalletGroupId, {
    blockchainSymbol: ETHEREUM_SYMBOL,
  });

  const isMessagingTabSearchEnabled = !useKillSwitch('kill_messaging_tab_search');

  if (!evmWallet?.primaryAddress || !evmWallet?.accountId) {
    throw new Error('Inbox missing Ethereum Wallet');
  }

  const handleInvite = useInviteToMessaging({ source: 'new_conversation' });
  useJourneyMarkOnMount(loadedComposer);
  useLogEventOnMount('messaging.composer.viewed', {
    componentType: ComponentType.page,
    action: ActionType.view,
  });

  const inviteButton = useCallback(() => {
    return (
      <Pressable background="transparent" onPress={handleInvite} testID="send-invite">
        <TextBody color="primary" spacingEnd={1}>
          {formatMessage(messages.invite)}
        </TextBody>
      </Pressable>
    );
  }, [formatMessage, handleInvite]);

  const handleSearchTabButtonPress = useCallback((value: boolean, context: string) => {
    logEvent('messaging.search_tab_button.clicked', {
      action: ActionType.click,
      componentType: ComponentType.icon,
      context,
    });
    return () => {
      setIsEnsTabSelected(value);
    };
  }, []);

  const searchBar = useMemo(() => {
    return (
      <Box spacing={2} testID="new-message-search">
        <SearchBar
          query={query}
          setQuery={setQuery}
          placeholderText={
            !isEnsTabSelected ? formatMessage(messages.lensProfilePlaceholder) : undefined
          }
        />
        {isMessagingTabSearchEnabled && (
          <HStack spacingTop={2} gap={1} testID="new-message-search-tab-buttons">
            <SearchTabButton
              isActive={isEnsTabSelected}
              text={formatMessage(messages.ens)}
              onPress={handleSearchTabButtonPress(true, 'ens')}
            />
            <SearchTabButton
              isActive={!isEnsTabSelected}
              text={formatMessage(messages.lens)}
              onPress={handleSearchTabButtonPress(false, 'lens')}
            />
          </HStack>
        )}
      </Box>
    );
  }, [
    formatMessage,
    handleSearchTabButtonPress,
    isEnsTabSelected,
    isMessagingTabSearchEnabled,
    query,
  ]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: 'back',
      right: inviteButton,
      title: formatMessage(messages.newMessage),
    }),
    [formatMessage, inviteButton],
  );

  const isUserAddress = useMemo(() => {
    return debouncedQuery.toLowerCase() === evmWallet.primaryAddress.toLowerCase();
  }, [debouncedQuery, evmWallet.primaryAddress]);

  return (
    <Screen navBar={navBar} navStickyBottom={searchBar} testID="new-message-screen">
      <KeyboardAwareScrollView
        keyboardDismissMode="interactive"
        extraScrollHeight={-100}
        keyboardShouldPersistTaps="always"
      >
        <VStack spacingTop={1}>
          {!debouncedQuery && <NewMessageDefaultState />}
          {isEnsTabSelected && isProperLength && !!debouncedQuery && !isValidEthAddress && (
            <ResultsList query={debouncedQuery} userAddress={evmWallet.primaryAddress} />
          )}
          {isEnsTabSelected && !!debouncedQuery && !isProperLength && (
            <TextLabel2 color="foregroundMuted" spacingHorizontal={3}>
              {formatMessage(messages.characterLimit)}
            </TextLabel2>
          )}
          {isValidEthAddress && !isUserAddress && <ExactAddressMatch address={debouncedQuery} />}
          {isMessagingTabSearchEnabled && isProperLength && !!debouncedQuery && (
            <LensProfilesResultsList query={debouncedQuery} isVisible={!isEnsTabSelected} />
          )}
        </VStack>
      </KeyboardAwareScrollView>
    </Screen>
  );
});

export const NewMessageScreen = withScreenBoundary(NewMessage);

