});

type SuggestionProps = {
  name: string;
  address: string;
  domain?: string;
  avatar?: string;
};
function Suggestion({ name, address, avatar, domain }: SuggestionProps) {
  const navigateToConversation = useNavigateToConversation(true);
  const getFirstActiveConversationKeyByAddress = useGetFirstConversationKeyByAddress();
  const { isSubscribed } = useSubscribe({ peerAddress: address });
  const { openConversationSubscribeTray } = useConversationSubscribeTray({ source: 'messaging' });

  const handleCellPress = useCallback(() => {
    const conversationKey = getFirstActiveConversationKeyByAddress(address);
    navigateToConversation({
      conversationKey: conversationKey ?? address,
      conversationStartSource: 'clicked_address',
    });
  }, [address, getFirstActiveConversationKeyByAddress, navigateToConversation]);

  const handleSubscribe = useCallback(() => {
    logEvent('messaging.inbox_discover_subscriptions.clicked', {
      componentType: ComponentType.card,
      action: ActionType.click,
      context: 'inbox_suggestion',
    });
    openConversationSubscribeTray(address);
  }, [address, openConversationSubscribeTray]);

  return (
    <VStack spacingTop={2}>
      <PressableOpacity testID="inbox-subscription-suggestion" onPress={handleCellPress}>
        <HStack spacingBottom={1} alignItems="center">
          <Box spacingEnd={2}>
            <ProfileAvatar size="xxxl" avatar={avatar} address={address} />
          </Box>
          <HStack justifyContent="space-between" alignItems="center" width="100%" flexShrink={1}>
            <Box>
              <TextHeadline ellipsize="middle" testID="inbox-subscription-suggestion-domain">
                {name}
              </TextHeadline>
              <TextBody ellipsize="middle" color="foregroundMuted">
                {domain}
              </TextBody>
            </Box>
            <Box spacingEnd={2}>
              <IconButton name="bell" onPress={handleSubscribe} disabled={isSubscribed} />
            </Box>
          </HStack>
        </HStack>
      </PressableOpacity>
    </VStack>
  );
}

function InboxSubscriptionSuggestionsContent() {
  const { formatMessage } = useIntl();
  const { publicProfiles, hardcodedSuggestions, suggestionsToShow } =
    useDiscoverSubscriptionSuggestions();
  const { navigate } = useStackNavigation();
  const isSubscribed = useIsSubscribed();

  const suggestionsWithoutSubscriptionToDisplay = useMemo(() => {
    const suggestions: string[] = [];

    for (const suggestion of suggestionsToShow) {
      if (suggestions.length === 2) return suggestions;

      if (!isSubscribed(suggestion)) {
        suggestions.push(suggestion);
      }
    }

    return suggestions;
  }, [isSubscribed, suggestionsToShow]);

  const renderItem = useCallback(
    function renderItem({ item: address }: { item: string }) {
      const profile = publicProfiles.find((p) => p.address === address);
      const { name: domainName } = getRecipientInfo(profile, address);
      const avatar = getAvatarSource(profile);
      const { name } = hardcodedSuggestions[address];
      return <Suggestion name={name} address={address} avatar={avatar} domain={domainName} />;
    },
    [hardcodedSuggestions, publicProfiles],
  );

  const keyExtractor = useCallback((item: string) => item, []);

  const handleSeeAll = useCallback(() => {
    logEvent('messaging.inbox_discover_subscriptions.clicked', {
      componentType: ComponentType.card,
      action: ActionType.click,
      context: 'inbox_see_all',
    });
    navigate('DiscoverSubscriptions');
  }, [navigate]);

  if (!suggestionsWithoutSubscriptionToDisplay.length) return <></>;

  return (
    <Box spacing={2} borderedTop testID="inbox-subscription-suggestions">
      <HStack justifyContent="space-between">
        <TextHeadline>{formatMessage(messages.title)}</TextHeadline>
        <PressableOpacity onPress={handleSeeAll} testID="inbox-subscription-suggestions-see-all">
          <TextBody color="primary">{formatMessage(messages.seeAll)}</TextBody>
        </PressableOpacity>
      </HStack>
      <TextLegal color="foregroundMuted">{formatMessage(messages.subtitle)}</TextLegal>
      <FlatList
        data={suggestionsWithoutSubscriptionToDisplay}
        keyExtractor={keyExtractor}
        renderItem={renderItem}
      />
    </Box>
  );
}

export const InboxSubscriptionSuggestions = memo(function InboxSubscriptionSuggestions() {
  return (
    <ErrorBoundary errorFallback={null}>
      <InboxSubscriptionSuggestionsContent />
    </ErrorBoundary>
  );
});

import { memo, useCallback, useMemo } from 'react';
import { Animated } from 'react-native';
import { useNotificationDateFormated } from 'cb-wallet-data/stores/NotificationsHub/hooks/useNotificationDateFormated';
import { ExternalNotificationItem, STATE_READ } from 'cb-wallet-data/stores/NotificationsHub/types';
import { listHeight } from '@cbhq/cds-common/tokens/cell';
import { CellMedia, ListCell } from '@cbhq/cds-mobile/cells';
import { Box } from '@cbhq/cds-mobile/layout/Box';

import { RefreshControl } from ':rn/cds-wallet/components/RefreshControl';

type NotificationListCellProps = {
  notification: ExternalNotificationItem;
  onPress?: (notification: ExternalNotificationItem) => void;
  testID?: string;
};

export const NotificationListCell = memo(function NotificationListCell({
  notification,
  onPress,
  testID,
}: NotificationListCellProps) {
  const { image_url: imageUrl, title, body } = notification.payload.Payload.InAppStatic;
  const { state, created_at: dateCreated } = notification;

  const formatedDate = useNotificationDateFormated(dateCreated.seconds);
  const opacity = useMemo(() => {
    return state === STATE_READ ? 0.5 : 1;
  }, [state]);

  const onPressHandler = useCallback(() => {
    if (onPress) {
      onPress(notification);
    }
  }, [notification, onPress]);

  return (
    <Box opacity={opacity}>
      <ListCell
        multiline
        title={`${title?.trim()} ${formatedDate}`}
        description={body?.trim()}
        onPress={onPressHandler}
        priority="end"
        media={
          imageUrl ? <CellMedia type="image" source={imageUrl} accessibilityLabel="" /> : undefined
        }
        testID={testID}
      />
    </Box>
  );
});

export type NotificationGroupListProps = {
  notifications: ExternalNotificationItem[];
  onPress?: (notification: ExternalNotificationItem) => void;
  onEndReached?: () => void;
  onRefresh?: () => Promise<unknown>;
};

const viewabilityConfig = {
  minimumViewTime: 100,
  viewAreaCoveragePercentThreshold: 100,
};

export const NotificationGroupList = memo(function NotificationGroupListCell({
  notifications,
  onPress,
  onEndReached,
  onRefresh,
}: NotificationGroupListProps) {
  const renderItem = useCallback(
    ({ item, index }: { item: ExternalNotificationItem; index: number }) => {
      return (
        <NotificationListCell
          testID={`notifications-hub-cell-${index}`}
          notification={item}
          onPress={onPress}
        />
      );
    },
    [onPress],
  );

  const keyExtractor = useCallback((_: ExternalNotificationItem, index: number) => `${index}`, []);

  const getItemLayout = useCallback<
    NonNullable<React.ComponentProps<typeof Animated.FlatList>['getItemLayout']>
  >((_, index) => {
    return { length: listHeight.normal, offset: listHeight.normal * index, index };
  }, []);

  return (
    <Animated.FlatList
      data={notifications}
      keyExtractor={keyExtractor}
      renderItem={renderItem}
      onEndReached={onEndReached}
      onEndReachedThreshold={0.1}
      getItemLayout={getItemLayout}
      viewabilityConfig={viewabilityConfig}
      refreshControl={onRefresh ? <RefreshControl onRefresh={onRefresh} /> : undefined}
    />
  );
});

