const StoreKeys_notificationHubScreenViewCount = new LocalStorageStoreKey<number>(
  'notificationHubScreenViewCount',
);
const Frequency = 2;
export const notificationHubScreenVisitCountAtom = atom({
  key: 'notificationHubScreenVisitCountAtom',
  default: 0,
  effects: [atomLocalStorageEffect(StoreKeys_notificationHubScreenViewCount)],
});

function NotificationsHub() {
  const { formatMessage } = useIntl();
