type NotificationsHubContentProps = {
  activeTab?: string;
};

// 3/17/2023 (Aaron): exporting this content for the tabbed Inbox.
// If the tabbed inbox experiment is resolved to treatment and is enabled for
// non-0th-indexed addresses, we can refactor this component to not have a screen container
export function NotificationsHubContent({ activeTab }: NotificationsHubContentProps) {
  const { data, hasNextPage, fetchNextPage, refetch, isFetching } = useNotificationsHub();
  const { navigateToDeeplinkUrl } = useNavigateToDeeplink();
  const clearBadgeCount = useClearUnreadNotifications();
  const queryClient = useQueryClient();
  const updateNotificationsAction = useUpdateNotificationState();
  const [showNotificationTray, setShowNotificationTray] = useState(false);

  const { visible: notificationTrayVisible, closeTray: closeNotificationTray } =
    useNotificationPermissionTrayVisibility({ shouldBlockTray: !showNotificationTray });

  const [notificationHubScreenVisitCount, setNotificationHubScreenVisitCount] = useRecoilState(
    notificationHubScreenVisitCountAtom,
  );
  const isEligibleForNotificationOptInExperiment = useIsFeatureEnabled(
    'wallet_settings_hub_notif_optin',
  );

  useNotificationHubViewed();

  useEffect(
    function toggleNotificationTray() {
      if (
        isEligibleForNotificationOptInExperiment &&
        notificationHubScreenVisitCount % Frequency === 0 &&
        activeTab === InboxTab.notifications
      ) {
        setShowNotificationTray(true);
      }
    },
    [
      activeTab,
      isEligibleForNotificationOptInExperiment,
      notificationHubScreenVisitCount,
      notificationTrayVisible,
    ],
  );

  useOnUnmount(() => {
    if (!isEligibleForNotificationOptInExperiment) {
      clearBadgeCount();
    }
    queryClient.removeQueries([FETCH_NOTIFICATIONS_KEY]);
    setNotificationHubScreenVisitCount((prevVisitCount) => prevVisitCount + 1);
  });

  useOnMount(() => {
    // mark all notifs as read on mount instead of on unmount
    // this is net new behavior for the new notif hub
    if (isEligableForNotificationHubLibraryExperiment) {
      clearBadgeCount();
    }
  });

  const notifications = useMemo(
    () =>
      (data?.pages || [])
        .map((page) => {
          if (page.response.items) {
            return page.response.items;
          }
          return [];
        })
        .flat(),
    [data],
  );

  const onPressNotification = useCallback(
    function onPressNotification(notification: ExternalNotificationItem) {
      const url = notification?.payload.Payload.InAppStatic.url;
      updateNotificationsAction([notification]);
      triggerNotificationPressed({
        communicationId: notification.communication_id,
        notificationTitle: notification.payload.Payload.InAppStatic.title,
        notificationBody: notification.payload.Payload.InAppStatic.body,
        messageId: notification.notification_id,
        template: notification.template_name,
      });

      if (!url) {
        return;
      }
      navigateToDeeplinkUrl(url);
    },
    [navigateToDeeplinkUrl, updateNotificationsAction],
  );

  const onEndReached = useCallback(() => {
    if (hasNextPage) {
      fetchNextPage();
    }
  }, [fetchNextPage, hasNextPage]);

  const isEligableForNotificationHubLibraryExperiment = useIsFeatureEnabled(
    'notification_hub_library',
  );

  const spectrum = useSpectrum();

  if (isEligableForNotificationHubLibraryExperiment) {
    return (
      <>
        <NotificationsFrameworkProvider locale="en" spectrum={spectrum} platform="wallet-mobile">
          <NotificationsFromLibrary
            notifications={notifications}
            onPressNotification={onPressNotification}
            isFetching={isFetching}
            hasNext={!!hasNextPage}
            refetch={refetch}
            onEndReached={onEndReached}
            hasNextPage={!!hasNextPage}
            fetchNextPage={fetchNextPage}
          />
          {notificationTrayVisible && (
            <NotificationPermissionTray toggleOff={closeNotificationTray} />
          )}
        </NotificationsFrameworkProvider>
      </>
    );
  }

  // Loading State
  if (isFetching && notifications.length === 0) {
    return <NotificationsHubLoadingState />;
  }

  return (
    <>
      {notifications.length === 0 ? (
        <NotificationsHubEmptyState />
      ) : (
        <NotificationGroupList
          notifications={notifications}
          onEndReached={onEndReached}
          onRefresh={refetch}
          onPress={onPressNotification}
        />
      )}
      {notificationTrayVisible && <NotificationPermissionTray toggleOff={closeNotificationTray} />}
    </>
  );
}

