import { ReactNode, useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  triggerOnboardingPasswordPrivacyLinkClick,
  triggerOnboardingPasswordTOSLinkClick,
  triggerOnboardingTOSCheckboxPressed,
} from 'cb-wallet-analytics/onboarding';
import { PRIVACY_POLICY_URL, TERMS_OF_SERVICE_URL } from 'cb-wallet-data/utils/externalLinks';
import { Checkbox } from '@cbhq/cds-mobile/controls';
import { HStack } from '@cbhq/cds-mobile/layout';
import { TextLabel2 } from '@cbhq/cds-mobile/typography/TextLabel2';

import { OnboardingLink } from ':rn/cds-wallet/components/interactables/OnboardingLink';

const messages = defineMessages({
  agreeToTerms: {
    defaultMessage: 'I agree to the <t>terms</t> and <pp>privacy policy</pp>',
    description: 'Text for checkbox where user agrees to the legal terms and privacy policy',
  },
  agreeToTermsWithoutLinks: {
    defaultMessage: 'I agree to the terms and privacy policy',
    description: 'Text for checkbox where user agrees to the legal terms and privacy policy',
  },
});

type Props = {
  accepted: boolean;
  onToggle: () => void;
  disabled?: boolean;
};

export function TermsOfServiceAgreement({ onToggle, accepted, disabled }: Props) {
  const { formatMessage } = useIntl();

  const handleTOSPress = useCallback(() => {
    triggerOnboardingPasswordTOSLinkClick();
  }, []);

  const handlePrivacyPress = useCallback(() => {
    triggerOnboardingPasswordPrivacyLinkClick();
  }, []);

  const termsOfServiceLink = useCallback(
    (text: NonNullable<ReactNode>) => (
      <OnboardingLink variant="label1" to={TERMS_OF_SERVICE_URL} onPress={handleTOSPress}>
        {text}
      </OnboardingLink>
    ),
    [handleTOSPress],
  );

  const privacyPolicyLink = useCallback(
    (text: NonNullable<ReactNode>) => (
      <OnboardingLink variant="label1" to={PRIVACY_POLICY_URL} onPress={handlePrivacyPress}>
        {text}
      </OnboardingLink>
    ),
    [handlePrivacyPress],
  );

  const handlePress = useCallback(() => {
    // TextLabel2 disabled property does not disable onPress.
    // This will prevent the user from toggling the checkbox disabled.
    if (disabled) return;

    triggerOnboardingTOSCheckboxPressed(!accepted);
    onToggle();
  }, [accepted, disabled, onToggle]);

  return (
    <HStack width="100%" alignItems="center" justifyContent="flex-start">
      <Checkbox
        testID="accept-terms"
        checked={accepted}
        onChange={handlePress}
        accessibilityLabel={formatMessage(messages.agreeToTermsWithoutLinks)}
        accessibilityRole="radio"
        disabled={disabled}
      />
      <TextLabel2
        spacingStart={1}
        onPress={handlePress}
        disabled={disabled}
        testID="accept-terms-text"
        accessibilityRole="link"
      >
        {formatMessage(messages.agreeToTerms, {
          t: termsOfServiceLink,
          pp: privacyPolicyLink,
        })}
      </TextLabel2>
    </HStack>
  );
}

