type TurnOffPaymentsModeModalProps = {
  action?: string;
  title?: string;
  body?: string;
  illustration?: React.ReactNode;
  primaryActionLabel?: string;
  secondaryActionLabel?: string;
  onPrimaryPress?: () => void;
  onSecondaryPress?: () => void;
};

export function TurnOffPaymentsModeModal({
  action,
  title,
  body,
  illustration,
  primaryActionLabel,
  secondaryActionLabel,
  onPrimaryPress,
  onSecondaryPress,
}: TurnOffPaymentsModeModalProps) {
  const { formatMessage } = useIntl();

  const { reset } = useStackNavigation<SignedInNavigatorParamList>();
  const [, setApplicationMode] = useApplicationMode();

  useTurnOffPaymentsModeViewed();

  const handleBack = useCallback(() => {
    logTurnOffPaymentsModeCancelClicked();
    if (onSecondaryPress) {
      onSecondaryPress();
    } else {
      reset({
        routes: [
          {
            name: 'PaymentsModeStack',
            params: { screen: 'SendInput' },
          },
        ],
      });
    }
  }, [reset, onSecondaryPress]);

  const closeButton = useMemo(() => {
    return <IconButton name="close" onPress={handleBack} transparent />;
  }, [handleBack]);

  const { openModeToggleTray } = useModeToggleTray({ source: 'mode_toggle' });

  const handleDisablePayments = useCallback(() => {
    logTurnOffPaymentsModeConfirmClicked();
    setApplicationMode('superapp');

    if (onPrimaryPress) {
      onPrimaryPress();
    } else {
      reset({
        routes: [
          {
            name: 'SuperAppModeStack',
            params: { screen: 'TabNavigator' },
          },
        ],
      });
    }

    setTimeout(() => {
      openModeToggleTray({});
    }, 1000);
  }, [setApplicationMode, onPrimaryPress, reset, openModeToggleTray]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      right: closeButton,
    }),
    [closeButton],
  );

  return (
    <Screen navBar={navBar} full testID="disable-payments-mode">
      <VStack height="100%" spacing={3}>
        <VStack flexGrow={1} alignItems="center" justifyContent="center">
          {illustration ?? (
            <MiamiIllustrationWrapper illustration="LedgerFailedMiami">
              <SpotRectangle name="ledgerFailed" />
            </MiamiIllustrationWrapper>
          )}
          <TextTitle3 spacingTop={2}>
            {title ?? formatMessage(messages.title, { action })}
          </TextTitle3>
          <TextBody color="foregroundMuted" align="center" spacingTop={1}>
            {body ?? formatMessage(messages.descrption, { action })}
          </TextBody>
        </VStack>
        <ButtonGroup direction="vertical">
          <Button onPress={handleDisablePayments} block spacingBottom={2}>
            {primaryActionLabel ?? formatMessage(messages.disablePaymentsMode)}
          </Button>
          <Button onPress={handleBack} block variant="secondary" spacingBottom={4}>
            {secondaryActionLabel ?? formatMessage(messages.maybeLater)}
          </Button>
        </ButtonGroup>
      </VStack>
    </Screen>
  );
}

