type PaymentsProfileContentProps = {
  wallet: Wallet;
};

const PaymentsProfileContent = memo(function PaymentsProfileContent({
  wallet,
}: PaymentsProfileContentProps) {
  usePaymentsWalletViewed();
  const { formatMessage } = useIntl();
  const [receiveTrayVisible, { toggleOff: toggleReceiveTrayOff }] = useToggler(false);
  const [nuxVisible, setNuxVisible] = useState(true);

  const isPaymentsModeAnnouncementsEnabled = useIsFeatureEnabled('payments_mode_announcements');

  const { copyToClipboard } = useClipboard();
  const { navigate } = useStackNavigation();

  const handleCashoutClickedAnalytics = usePaymentsCashoutClicked();

  const { headerTranslation } = usePortfolioContext();

  const { walletSwitcherTrayVisible, toggleWalletSwitcherTrayOff, toggleWalletSwitcherTrayOn } =
    useToggleWalletSwitcherTray();

  const setPrivacyMode = useSetPrivacyMode();
  const refreshTransactions = useRefreshTransactionHistory();
  const accountId = useActiveAccountId();
  const launchCashout = useLaunchCashout({
    entryPoint: 'global',
  });

  const { fiatBalance, usdFiatBalance } = useFormattedWalletBalance({
    wallet,
    formatZeroBalance: true,
  });

  const launchBuyFlow = useLaunchBuyFlow();

  const closeNux = useCallback(
    function closeNux() {
      setNuxVisible(false);
    },
    [setNuxVisible],
  );

  const handleCopyIconPress = useCallback(() => {
    copyToClipboard(wallet.primaryAddress, true, formatMessage(messages.addressCopied));
  }, [copyToClipboard, formatMessage, wallet.primaryAddress]);

  const navBar = useMemo(() => {
    return (
      <NavBarWithSuspense
        navBarRightSection={<WalletNavBarRight onCopyIconPress={handleCopyIconPress} />}
        handleUsernameTap={toggleWalletSwitcherTrayOn}
        headerRef={headerTranslation}
      />
    );
  }, [handleCopyIconPress, headerTranslation, toggleWalletSwitcherTrayOn]);

  const handleTogglePrivacyMode = useCallback(
    function handleTogglePrivacyMode() {
      setPrivacyMode((prev) => !prev);
    },
    [setPrivacyMode],
  );

  const [startClaimSubdomainPerfMark] = usePerfMark(
    PERF_MARKS.profile,
    PROFILE_MARKS.claim_subdomain_load,
    {
      logMetric: true,
    },
  );

  const handleClaimUsernamePress = useCallback(
    function handleClaimUsernamePress() {
      startClaimSubdomainPerfMark();
      markJourney('navigate_to_claim_subdomain_existing_account');
      navigate('AuthenticatedClaimSubdomain', {
        screen: 'SubdomainExistingUserEducation',
      });
    },
    [navigate, startClaimSubdomainPerfMark],
  );

  const handleBuyUSDCPress = useCallback(
    function handleAddCryptoPress() {
      launchBuyFlow({
        asset: CurrencyCode.USDC.code,
        chainId: EthereumNetworkMap.whitelisted.BASE_MAINNET.chainId,
      });
    },
    [launchBuyFlow],
  );

  const handleCashoutPress = useCallback(
    function navigateToCashout(providers: CashoutProvider[]) {
      handleCashoutClickedAnalytics();
      launchCashout(providers);
    },
    [handleCashoutClickedAnalytics, launchCashout],
  );

  const handleRefresh = useCallback(async () => {
    resetSyncedBlockheights(accountId, 'transactions');

    await refreshTransactions();
  }, [refreshTransactions, accountId]);

  const refreshControl = useMemo(() => {
    return <RefreshControl onRefresh={handleRefresh} />;
  }, [handleRefresh]);

  const transactionsRenderProps = useMemo(
    () => ({
      wallet,
      source: AssetDetailSource.Token,
      refreshControl,
    }),
    [refreshControl, wallet],
  );

  const hasWalletBalance = useMemo(() => (wallet.balance ?? 0) > 0, [wallet.balance]);

  return (
    <DeferredRendererScreen navBar={navBar}>
      <VStack flexGrow={1} flexShrink={1} flexBasis={0}>
        <Box testID="asset-detail-balance-header" spacingHorizontal={1} spacingTop={2}>
          <PressableOpacity
            testID="asset-detail-header-pressable"
            onLongPress={handleTogglePrivacyMode}
          >
            <TextDisplay1 align="center">{usdFiatBalance}</TextDisplay1>
            <TextBody align="center">{fiatBalance}</TextBody>
          </PressableOpacity>
        </Box>
        <Suspense fallback={<ActionButtonsFallback />}>
          <ActionButtons
            hasWalletBalance={hasWalletBalance}
            handleCashoutPress={handleCashoutPress}
            handleBuyUSDCPress={handleBuyUSDCPress}
          />
        </Suspense>
        {isPaymentsModeAnnouncementsEnabled && (
          <ForbiddenSuspenseBoundary componentKey="AnnouncementCardCarousel" fallback={null}>
            <AnnouncementCardCarousel />
          </ForbiddenSuspenseBoundary>
        )}
        {hasWalletBalance && (
          <DeferredRenderer
            tag="AssetTransactionDetailsContent"
            render={AssetTransactionDetailsContent}
            renderProps={transactionsRenderProps}
            key="transactionDetails"
            fallback={<TransactionFallback />}
          />
        )}
        {!hasWalletBalance && nuxVisible && (
          <Box spacing={3}>
            <PaymentsModeNux
              key="nux"
              onActionClicked={handleClaimUsernamePress}
              onClose={closeNux}
            />
          </Box>
        )}
      </VStack>
      <AssetsTrayManager
        receiveTrayVisible={receiveTrayVisible}
        toggleReceiveTrayOff={toggleReceiveTrayOff}
        walletSwitcherTrayVisible={walletSwitcherTrayVisible}
        toggleWalletSwitcherTrayOff={toggleWalletSwitcherTrayOff}
      />
    </DeferredRendererScreen>
  );
});

