          height={HEIGHT}
          width={WIDTH}
          onError={onError}
        />
      )}
    </Box>
  );
});

const ProfileActivityTray = memo(function ProfileActivityTray({
  item,
  onViewTxn,
  onClose,
}: ProfileActivityTrayProps) {
  const testID = item.id;
  const { formatMessage, formatDate } = useIntl();
  const date = useMemo(() => {
    return formatDate(item.createdAt ?? '', {
      month: 'short',
      day: '2-digit',
      year: 'numeric',
    });
  }, [formatDate, item]);

  const summary = useMemo(() => {
    if (isReceiveTokenTxn(item)) {
      return formatMessage(messages.receiveTokenSummary, { date });
    }
    if (isReceiveNftTxn(item)) {
      return formatMessage(messages.receiveNFTSummary, { date });
    }

    if (isSendTokenTxn(item)) {
      return formatMessage(messages.sendTokenSummary, { date });
    }

    if (isSendNftTxn(item)) {
      return formatMessage(messages.sendNFTSummary, { date });
    }

    if (isMintTxn(item)) {
      return formatMessage(messages.mintSummary, { date });
    }

    if (isSwapTxn(item)) {
      return formatMessage(messages.swapSummary, { date });
    }

    if (isApproveTxn(item)) {
      return formatMessage(messages.approvedSummary, { date });
    }

    return formatMessage(messages.executeSmartContractSummary, { date });
  }, [formatMessage, item, date]);

  return (
    <Tray onCloseComplete={onClose} testID={`profile-activity-tray-${testID}`}>
      <VStack spacing={2} background="background">
        <TextBody color="foregroundMuted" align="center">
          {summary}
        </TextBody>
        <Button onPress={onViewTxn} spacingTop={2} testID={`profile-activity-open-${testID}`}>
          {formatMessage(messages.viewOnBlockExplorer)}
        </Button>
      </VStack>
    </Tray>
  );
});

export const ProfileActivityCellContent = memo(function ProfileActivityCellContent({
  item,
}: Props) {
  const openWebBrowser = useOpenWebBrowser();
  const { title, description, action, subAction, icon, imageUri } = useProfileActivityItem(item);
  const [hasError, setError] = useState(false);
  const [trayVisible, { toggleOn: showTray, toggleOff: hideTray }] = useToggler(false);

  const detail = useMemo(() => {
    return action ? (
      <TextHeadline
        color={item.status === UserProfileHistoryStatus.Failed ? 'negative' : undefined}
      >
        {action}
      </TextHeadline>
    ) : null;
  }, [action, item.status]);

  const handleError = useCallback(() => {
    setError(true);
  }, []);

  const viewOnBlockExplorer = useCallback(
    function viewOnBlockExplorer() {
      const txnHash = item.id;
      openWebBrowser(`${ETHERSCAN_URL}/${txnHash}`);
    },
    [openWebBrowser, item.id],
  );

  return (
    <>
      <Pressable onPress={showTray} background="transparent" testID={`profile-activity-${item.id}`}>
        <VStack>
          <ListCell
            title={title}
            description={description}
            detail={detail}
            priority="start"
            subdetail={subAction}
            media={<TransactionIcon type={icon} currencyCode={CurrencyCode.USD} />}
            variant="foregroundMuted"
            outerSpacing={
              {
                spacingHorizontal: 2,
                spacingVertical: 0,
              } as const
            }
          />
          {hasError || Boolean(imageUri) ? (
            <ProfileActivityImage imageUri={imageUri} hasError={hasError} onError={handleError} />
          ) : null}
        </VStack>
      </Pressable>
      {trayVisible ? (
        <ProfileActivityTray item={item} onViewTxn={viewOnBlockExplorer} onClose={hideTray} />
      ) : null}
    </>
  );
});

