import { memo, useCallback, useMemo } from 'react';
import { Linking } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { PROTOCOL_REPLACER, SOCIAL_REPLACER } from 'cb-wallet-data/stores/Profile/constants';
import type { IconName } from '@cbhq/cds-mobile';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { ListCell } from '@cbhq/cds-mobile/cells';
import { Icon } from '@cbhq/cds-mobile/icons';

import { isSocialIcon, SocialIcon } from './SocialLink/SocialIcon';
import type { ProfileRecordName } from './ProfileRecord';

const messages = defineMessages({
  url: {
    defaultMessage: 'Website',
    description: 'List cell title for URL record',
  },
  email: {
    defaultMessage: 'Email',
    description: 'List cell title for Email record',
  },
  twitter: {
    defaultMessage: 'Twitter',
    description: 'List cell title for Twitter record',
  },
  reddit: {
    defaultMessage: 'Reddit',
    description: 'List cell title for Reddit record',
  },
  github: {
    defaultMessage: 'GitHub',
    description: 'List cell title for GitHub record',
  },
});

const nonSocialIcons: Record<string, IconName> = {
  url: 'globe',
  email: 'email',
};

type ProfileDetailsRecordProps = {
  name: ProfileRecordName;
  value?: string;
};

export const ProfileDetailsRecord = memo(function ProfileDetailsRecord({
  name,
  value,
}: ProfileDetailsRecordProps) {
  const { formatMessage } = useIntl();
  const description = useMemo(() => {
    if (!value) {
      return;
    }
    if (isSocialIcon(name)) {
      return value.replace(SOCIAL_REPLACER, '@');
    }

    if (name === 'url') {
      return value.replace(PROTOCOL_REPLACER, '');
    }

    return value;
  }, [name, value]);

  const handleLinkPress = useCallback(
    function handleLinkPress() {
      if (!value) return;

      let formattedValue = value;

      if (name === 'email') {
        formattedValue = `mailto:${value}`;
      }

      if (name === 'url') {
        formattedValue = value.startsWith('http')
          ? value.replace(PROTOCOL_REPLACER, '')
          : `https://${value}`;
      }

      Linking.openURL(formattedValue);
    },
    [name, value],
  );

  if (!value) {
    return null;
  }

  return (
    <ListCell
      testID={`profile-details-record-${name}`}
      media={
        isSocialIcon(name) ? (
          <SocialIcon name={name} />
        ) : (
          <Icon name={nonSocialIcons[name]} size="s" color="foregroundMuted" />
        )
      }
      title={formatMessage(messages[name])}
      description={description}
      action={
        <IconButton
          name="externalLink"
          variant="secondary"
          transparent
          onPress={handleLinkPress}
          testID={`profile-details-record-${name}-btn`}
        />
      }
    />
  );
});

