import { memo, useCallback, useMemo } from 'react';
import { useOverridableKillSwitch as useKillSwitch } from 'cb-wallet-data/hooks/KillSwitches/useOverridableKillSwitch';
import { usePublicSubdomainProfile } from 'cb-wallet-data/stores/DecentralizedID/hooks/usePublicSubdomainProfile';
import { useProfileDetails } from 'cb-wallet-data/stores/Profile/hooks/useProfileDetails';
