  logProfileListCardPressed,
  ProfileEventData,
  useLogProfileListCardViewed,
} from '../ProfileAnalytics';

import { ProfileAvatar } from './ProfileAvatar';
import { ProfileFollowButton } from './ProfileFollowButton';

type ProfileListCardProps = {
  title: string;
  address: string;
  onPress: () => void;
  category?: string;
};
export const ProfileListCard = memo(function ProfileListCard(props: ProfileListCardProps) {
  const isDefaultPfp = useKillSwitch('kill_profile_pfp_list_cell');

  return isDefaultPfp ? (
    <ProfileListCardWithoutPfp {...props} />
  ) : (
    <ProfileListCardWithPfp {...props} />
  );
});

const ProfileListCardWithoutPfp = memo(function ProfileListCardWithoutPfp(
  props: ProfileListCardProps,
) {
  const avatar = useMemo(() => {
    return <ProfileAvatar address={props.address} size="xxxl" />;
  }, [props.address]);

  return <ProfileListCardContent {...{ ...props, avatar }} />;
});

const ProfileListCardWithPfp = memo(function ProfileListCardWithPfp(props: ProfileListCardProps) {
  const { profile: followeePublicProfile } = usePublicSubdomainProfile(props.title);

  const avatar = useMemo(() => {
    return (
      <ProfileAvatar address={props.address} avatar={followeePublicProfile?.avatar} size="xxxl" />
    );
  }, [followeePublicProfile?.avatar, props.address]);

  return <ProfileListCardContent {...{ ...props, avatar }} />;
});

type ProfileListCardContentProps = ProfileListCardProps & { avatar: React.ReactNode };

const PROFILE_LIST_CARD_WIDTH = EXPLORE_CARD_WIDTH;
const PROFILE_LIST_CARD_HEIGHT = 208;

// The profile list card is written so it can be consumed by multiple surfaces,
// but it is only being used for suggested profiles on the explore module.
const CONTEXT = 'suggestion';
const COMPONENT_PLACEMENT = 'explore';

const ProfileListCardContent = memo(
  ({ title, address, onPress, avatar, category }: ProfileListCardContentProps) => {
    const activeWalletGroupId = useActiveWalletGroupId();
    const { follower } = useProfileDetails(activeWalletGroupId, address);
    const analytics: ProfileEventData = useMemo(
      () => ({
        walletAddress: address,
        context: CONTEXT,
        componentPlacement: COMPONENT_PLACEMENT,
      }),
      [address],
    );

    const handleOnPress = useCallback(
      function handleOnPress() {
        logProfileListCardPressed(analytics);
        onPress();
      },
      [analytics, onPress],
    );

    useLogProfileListCardViewed(analytics);

    return (
      <Box
        width={PROFILE_LIST_CARD_WIDTH}
        height={PROFILE_LIST_CARD_HEIGHT}
        spacingEnd={1}
        justifyContent="center"
        testID="profile-list-card"
