          <VStack alignItems="center" gap={2} spacingVertical={2}>
            {avatar}

            <VStack alignItems="center" spacingHorizontal={1}>
              <TextLabel1 numberOfLines={1}>{title}</TextLabel1>

              <Box minHeight="15%" justifyContent="center">
                <TextLegal
                  numberOfLines={2}
                  noWrap={false}
                  color="foregroundMuted"
                  align="center"
                  ellipsize="tail"
                >
                  {category}
                </TextLegal>
              </Box>
            </VStack>

            <ProfileFollowButton
              address={address}
              activeProfileAddress={follower.address}
              context={CONTEXT}
              componentPlacement={COMPONENT_PLACEMENT}
            />
          </VStack>
        </Pressable>
      </Box>
    );
  },
);

import { useCallback, useMemo, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useOverridableKillSwitch as useKillSwitch } from 'cb-wallet-data/hooks/KillSwitches/useOverridableKillSwitch';
import { useCreateFollow } from 'cb-wallet-data/stores/Profile/hooks/useCreateFollow';
import { useDeleteFollow } from 'cb-wallet-data/stores/Profile/hooks/useDeleteFollow';
import { useProfileAddress } from 'cb-wallet-data/stores/Profile/hooks/useProfileAddress';
import { useUserProfile } from 'cb-wallet-data/stores/Profile/hooks/useUserProfile';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { getTruncatedAddress } from 'cb-wallet-data/utils/getTruncatedAddress';
import { isSameAddress } from 'cb-wallet-data/utils/isSameAddress';
import { PERF_MARKS, PROFILE_MARKS } from 'cb-wallet-data/utils/perf-constants';
import { useToggler } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { HStack } from '@cbhq/cds-mobile/layout';
import { usePerfMark } from '@cbhq/core-vitals/hooks';

import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { useClipboard } from ':rn/cds-wallet/components/interactables/CopyButtons/useClipboard';
import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { logProfileCardButtonClick, ProfileCardContext } from '../ProfileAnalytics';
import { invalidateFollows } from '../utils/invalidateFollows';

import { ProfileListCard } from './ProfileListCard';
import { ProfileListCellContent, ProfileListCellContentWithPfp } from './ProfileListCellContent';

const messages = defineMessages({
  copyAddress: {
    defaultMessage: 'Copy address',
    description: 'Button to allow user to copy an address',
  },
  unfollow: {
    defaultMessage: 'Unfollow',
    description: 'Button to allow user to unfollow a user',
  },
  addressCopied: {
    defaultMessage: 'Address copied',
    description: 'Toast message for when address is copied',
  },
  unfollowed: {
    defaultMessage: 'Unfollowed',
    description: 'Toast message for when a user unfollows a user',
  },
});

type ProfileListCellProps = {
  address: string;
  context: ProfileCardContext;
  ensDomain?: string;
  isFollowing?: boolean;
  isCard?: boolean;
  category?: string;
};

export function ProfileListCell({
  address,
  context,
  ensDomain,
  isFollowing,
  isCard,
  category,
}: ProfileListCellProps) {
  const activeWalletGroupId = useActiveWalletGroupId();
  const defaultProfileAddress = useProfileAddress(activeWalletGroupId);
  const { profile } = useUserProfile(defaultProfileAddress);

  const { formatMessage } = useIntl();
  const { push } = useStackNavigation();
  const { copyToClipboard } = useClipboard();
  const createFollow = useCreateFollow(defaultProfileAddress);
  const deleteFollow = useDeleteFollow(defaultProfileAddress);
  const isFollowButtonKilled = useKillSwitch('kill_profile_list_cell_follow_button');
  const isDefaultPfp = useKillSwitch('kill_profile_pfp_list_cell');
  const [isProcessingFollow, setIsProcessingFollow] = useState(false);
  const [isTrayOpen, { toggleOn: toggleTrayOpen, toggleOff: toggleTrayClosed }] = useToggler(false);
  const toast = useRateLimitedToast({});

  const [startProfilePageLoadPerfMark] = usePerfMark(
    PERF_MARKS.profile,
    PROFILE_MARKS.profile_page_load,
    {
      logMetric: true,
    },
  );

  const isUserAddress = useMemo(() => {
    return isSameAddress(address, profile?.address);
  }, [address, profile?.address]);

  const handleFollowPress = useCallback(
    function handleFollowPress() {
      logProfileCardButtonClick({ walletAddress: address, context }, 'follow');
      setIsProcessingFollow(true);
      createFollow(address)
        .then(() => {
          setIsProcessingFollow(false);
          invalidateFollows();
        })
        .catch(() => {
          setIsProcessingFollow(false);
        });
    },
    [address, context, createFollow],
  );

  const handleMenuPress = useCallback(
    function handleMenuPress() {
      logProfileCardButtonClick({ walletAddress: address, context }, 'menu');
      toggleTrayOpen();
    },
    [address, context, toggleTrayOpen],
  );

  const handleCopyPress = useCallback(
    function handleCopyPress() {
      logProfileCardButtonClick({ walletAddress: address, context }, 'copy_address');
      copyToClipboard(address);
      toast.show(formatMessage(messages.addressCopied));
      toggleTrayClosed();
    },
    [address, context, copyToClipboard, formatMessage, toast, toggleTrayClosed],
  );

  const handleUnfollowPress = useCallback(
    function handleUnfollowPress() {
      logProfileCardButtonClick({ walletAddress: address, context }, 'unfollow');
      setIsProcessingFollow(true);
      deleteFollow(address)
        .then(() => {
          setIsProcessingFollow(false);
          invalidateFollows();
          toast.show(formatMessage(messages.unfollowed));
          toggleTrayClosed();
        })
        .catch(() => {
          setIsProcessingFollow(false);
        });
    },
    [address, context, deleteFollow, formatMessage, toast, toggleTrayClosed],
  );

  const title = useMemo(() => ensDomain || getTruncatedAddress(address), [address, ensDomain]);

  const detail = useMemo(() => {
    return !isFollowing ? (
      <IconButton
        name="followInactive"
        variant="secondary"
        testID="profile-list-item-follow"
        onPress={handleFollowPress}
        disabled={isProcessingFollow}
      />
    ) : (
      <IconButton name="more" variant="secondary" onPress={handleMenuPress} />
    );
  }, [handleFollowPress, handleMenuPress, isProcessingFollow, isFollowing]);

  const tray = useMemo(() => {
    return (
      <>
        {isTrayOpen && (
          <Tray
            title={title}
            onCloseComplete={toggleTrayClosed}
            testID="profile-list-cell-copy-address-tray"
          >
            <HStack spacingHorizontal={2} gap={1}>
              {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
              {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
              <Button onPress={handleCopyPress}>{formatMessage(messages.copyAddress)}</Button>
              {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
              {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
              <Button
                disabled={isProcessingFollow}
                onPress={handleUnfollowPress}
                variant="secondary"
              >
                {formatMessage(messages.unfollow)}
              </Button>
            </HStack>
          </Tray>
        )}
      </>
    );
  }, [
    formatMessage,
    handleCopyPress,
    handleUnfollowPress,
    isProcessingFollow,
    isTrayOpen,
    title,
    toggleTrayClosed,
  ]);

  const handlePress = useCallback(
    function handlePress() {
      startProfilePageLoadPerfMark();
      push('Profile', { address, ens: ensDomain });
    },
    [address, ensDomain, push, startProfilePageLoadPerfMark],
  );

  const cellContentProps = useMemo(
    () => ({
      onPress: handlePress,
      title,
      detail: !isFollowButtonKilled && !isUserAddress ? detail : null,
      tray,
      address,
      category,
    }),
    [address, category, detail, handlePress, isFollowButtonKilled, isUserAddress, title, tray],
  );

  if (isCard) {
    return <ProfileListCard {...cellContentProps} />;
  }

  return isDefaultPfp ? (
    <ProfileListCellContent {...cellContentProps} />
  ) : (
    <ProfileListCellContentWithPfp {...cellContentProps} />
  );
}

import { memo, useCallback, useMemo } from 'react';
import { Linking } from 'react-native';
import { PROTOCOL_REPLACER, SOCIAL_REPLACER } from 'cb-wallet-data/stores/Profile/constants';
import type { IconName } from '@cbhq/cds-mobile';
import { Icon } from '@cbhq/cds-mobile/icons';
import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';

import { isSocialIcon, SocialIcon } from './SocialLink/SocialIcon';

const nonSocialIcons: Record<string, IconName> = {
  url: 'globe',
  email: 'email',
};

export type ProfileRecordName = 'url' | 'email' | 'twitter' | 'reddit' | 'github';

export type ProfileRecordProps = {
  recordName: ProfileRecordName;
  value?: string;
};

export const ProfileRecord = memo(function ProfileRecord({
  recordName,
  value,
}: ProfileRecordProps) {
  const description = useMemo(() => {
    if (!value) {
      return;
    }

    if (isSocialIcon(recordName)) {
      return value.replace(SOCIAL_REPLACER, '');
    }

    if (recordName === 'url') {
      return value.replace(PROTOCOL_REPLACER, '');
    }

    return value;
  }, [recordName, value]);

  const handleLinkPress = useCallback(
    function handleLinkPress() {
      if (!value) return;

      let formattedValue = value;

      if (recordName === 'email') {
        formattedValue = `mailto:${value}`;
      }

      if (recordName === 'url') {
        formattedValue = value.startsWith('http')
          ? value.replace(PROTOCOL_REPLACER, 'https://')
          : `https://${value}`;
      }

      Linking.openURL(formattedValue);
    },
    [recordName, value],
  );

  return (
    <VStack spacingEnd={1}>
      <Pressable
        onPress={handleLinkPress}
        background="transparent"
        testID={`profile-record-${recordName}`}
      >
        <HStack>
          <VStack spacingTop={0.5} spacingEnd={0.5}>
            {isSocialIcon(recordName) ? (
              <SocialIcon name={recordName} testID={`social-icon-${recordName}`} />
            ) : (
              <Icon
                name={nonSocialIcons[recordName]}
                size="s"
                color="foregroundMuted"
                testID={`icon-${recordName}`}
              />
            )}
          </VStack>
          <TextBody
            color="foregroundMuted"
            numberOfLines={1}
            spacingStart={0.5}
            ellipsizeMode="tail"
          >
            {description}
          </TextBody>
        </HStack>
      </Pressable>
    </VStack>
  );
});

