type QuestDetailsContentProps = {
  selectedQuest: QuestMetadata;
  source?: string;
};

function QuestDetailsContent({ selectedQuest, source }: QuestDetailsContentProps) {
  const { formatMessage } = useIntl();
  const { screenWidth, top: paddingTop, bottom: paddingBottom } = useDimensions();
  const [showHeader, setShowHeader] = useState(false);
  const [headerZIndex, setHeaderZIndex] = useState(0);
  const { navigate, goBack } = useStackNavigation<QuestsParamList>();
  const [questLessonsViewed] = useQuestLessonsViewed();

  const {
    completionTime,
    imageUrl,
    progress,
    secondaryTitle,
    title,
    status,
    startUrl,
    lessonSlug,
    questId,
    description,
    steps,
    stepDescriptions,
    stepTitles,
  } = selectedQuest;

  const {
    isAutoClaimingRewards,
    questNotificationTrayVisible,
    isRewardModalVisible,
    closeQuestNotificationTray,
    refetchQuestStatus,
  } = useQuestsContext();

  const [questStatuses] = useQuestStatuses();

  const { isLoading, startAndNavigateToQuest } = useQuestStartContext();

  const currentQuestStatus = useMemo(() => {
    return questStatuses?.find((s) => s.forQuest === questId);
  }, [questId, questStatuses]);

  const questLessonViewed = useMemo(() => {
    return questLessonsViewed.some((lesson) => lesson === lessonSlug);
  }, [lessonSlug, questLessonsViewed]);

  const onButtonPress = useCallback(
    function onButtonPress() {
      if (lessonSlug && !progress && !questLessonViewed) {
        navigate('QuestLesson', { lessonSlug, questId });
      } else {
        startAndNavigateToQuest();
      }
    },
    [lessonSlug, navigate, progress, questId, questLessonViewed, startAndNavigateToQuest],
  );

  const goToQuestList = useCallback(
    function goToQuestList() {
      navigate('QuestsList');
    },
    [navigate],
  );

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleScroll = useCallback(function handleScroll(event: any) {
    const positionY = event.nativeEvent.contentOffset.y;
    if (positionY < 40) {
      setShowHeader(false);
    } else {
      setShowHeader(true);
    }
  }, []);

  const handleBackPress = useCallback(
    function handleBackPress() {
      refetchQuestStatus();
      goBack();
    },
    [refetchQuestStatus, goBack],
  );

  useEffect(
    function logQuestDetailsViewed() {
      logBrowserQuestDetailsViewed({
        questId,
        title,
        source,
      });
    },
    [questId, source, title],
  );

  const fadeInAnimation = useRef(new Animated.Value(0)).current;
  const animatedNavBarStyle = useMemo<React.ComponentProps<typeof Animated.View>['style']>(() => {
    const position = 'absolute' as const;

    return {
      position,
      top: 0,
      zIndex: headerZIndex,
      width: '100%',
      opacity: fadeInAnimation,
    };
  }, [fadeInAnimation, headerZIndex]);

  useEffect(
    function animateHeader() {
      if (showHeader) {
        setHeaderZIndex(1);
        Animated.timing(fadeInAnimation, {
          toValue: 1,
          duration: 300,
          useNativeDriver: true,
        }).start();
      } else {
        Animated.timing(fadeInAnimation, {
          toValue: 0,
          duration: 300,
          useNativeDriver: true,
        }).start(() => setHeaderZIndex(0));
      }
    },
    [fadeInAnimation, showHeader],
  );

  const rewardMessage = useQuestRewardText(selectedQuest, true);

  const rewardText = useMemo(() => {
    return rewardMessage || selectedQuest.rewardText;
  }, [rewardMessage, selectedQuest.rewardText]);

  const [descriptionTags, stepsTags, stepDescriptionsTags] = useMemo(() => {
    const questDescription = parseTags(description);
    const questSteps = steps.map((step) => parseTags(step));
    const questStepDescriptions = stepDescriptions?.map((step) => parseTags(step));
    return [questDescription, questSteps, questStepDescriptions];
  }, [description, steps, stepDescriptions]);

  const stepTitlesAndTags = useMemo(() => {
    if (!stepDescriptionsTags || !stepTitles) {
      return [];
    }
    return stepDescriptionsTags.map((stepDescription, index) => {
      if (!stepTitles) {
        // this should never happen but typescript is complaining below
        return {
          stepTitle: '',
          stepDescription,
        };
      }
      return {
        stepTitle: stepTitles[index],
        stepDescription,
      };
    });
  }, [stepDescriptionsTags, stepTitles]);

  const questIsActive = status === QuestStatus.ACTIVE;
  const isRetailUpsell = isRetailUpsellQuestUrl(startUrl);

  const questCompletedOrRewarded = ['rewarded', 'completed'].includes(progress ?? 'undefined');
  const questInProgressOrSuspended = ['in_progress', 'suspended'].includes(progress ?? 'undefined');
  const awaitingRewardUnlock =
    questIsActive &&
    questInProgressOrSuspended &&
    selectedQuest.rewardUnlockDate !== undefined &&
    selectedQuest.questType === 'timelock';

  const showUnsupportedTokenWarning = useShowUnsupportedAssetWarning(selectedQuest);

  const ctaButtonText = useMemo(() => {
    if (isRetailUpsell) {
      return formatMessage(messages.retailQuestCTA);
    }
    if (!questIsActive && progress !== 'rewarded') {
      return formatMessage(messages.questExpired);
    }
    if (questCompletedOrRewarded) {
      return formatMessage(messages.completed);
    }
    if (awaitingRewardUnlock) {
      return formatMessage(messages.rewardUnlocksSoon);
    }
    if (currentQuestStatus?.status) {
      return formatMessage(getQuestButtonMessage(currentQuestStatus.status));
    }
    if (questLessonViewed) {
      return formatMessage(questProgressMessages.in_progress);
    }
    return formatMessage(questProgressMessages.notStarted);
  }, [
    awaitingRewardUnlock,
    currentQuestStatus?.status,
    formatMessage,
    isRetailUpsell,
    progress,
    questCompletedOrRewarded,
    questIsActive,
    questLessonViewed,
  ]);

  const imageSource = useMemo(() => ({ uri: imageUrl }), [imageUrl]);

  return (
    <>
      {/* eslint-disable-next-line react/forbid-component-props */}
      <Animated.View style={animatedNavBarStyle}>
        <Box background height={paddingTop} />
        <NavBar left="back" handleLeft={handleBackPress} title={formatMessage(messages.quests)} />
      </Animated.View>
      <ScrollView bounces={false} onScroll={handleScroll} scrollEventThrottle={16}>
        <VStack gap={2} background>
          <RemoteImage
            testID="quest-image"
            source={imageSource}
            resizeMode="cover"
            width={screenWidth}
            height={250}
            shape="rectangle"
          />
          <Box position="absolute" top={paddingTop} spacingHorizontal={2} spacingVertical={1}>
            <IconButton variant="secondary" name="backArrow" onPress={handleBackPress} />
          </Box>
          <VStack gap={2} width="90%" alignSelf="center">
            {showUnsupportedTokenWarning && <UnsupportedAssetWarning quest={selectedQuest} />}
            {isRetailUpsell && (
              <Banner
                title={formatMessage(messages.retailQuestCalloutTitle)}
                variant="promotional"
                startIcon="info"
                testID="retail-quest-callout"
              >
                {formatMessage(messages.retailQuestCalloutBody)}
              </Banner>
            )}
            <TextTitle1>{title}</TextTitle1>
            {secondaryTitle && <TextBody>{secondaryTitle}</TextBody>}
            <HStack gap={2} spacingTop={1} alignItems="center">
              <HStack gap={1} alignItems="center">
                <Icon name="clockOutline" size="s" color="foregroundMuted" />
                <TextBody color="foregroundMuted">{completionTime}</TextBody>
              </HStack>
              <HStack gap={1} alignItems="center">
                <Icon name="nftSaleInactive" size="s" color="foregroundMuted" />
                <TextBody color="foregroundMuted">{formatMessage(messages.singleTask)}</TextBody>
              </HStack>
            </HStack>
            {questIsActive && questInProgressOrSuspended && (
              <ProgressBar weight="heavy" progress={0.6} testID="quest-details-progress-bar" />
            )}
            {!questIsActive && questInProgressOrSuspended && (
