function QuestDetails() {
  const { questId, source: deeplinkSource } = useParams<QuestsParamList, 'QuestDetails'>();
  const [, setSource] = useQuestDeeplinkSource();

  const activeWalletGroupId = useActiveWalletGroupId();
  const { queryRetailUserId } = useRetailUserId();
  const { data: retailUserId, isLoading: isRetailUserIdLoading } = queryRetailUserId;

  const { questsWithStatus, refetchQuestStatus } = useFetchQuestsData({
    walletGroupId: activeWalletGroupId,
    retailUserId,
    suspense: true,
    enableQuery: !isRetailUserIdLoading,
  });
  const { replace } = useStackNavigation<QuestsParamList>();

  useRefreshOnFocus(refetchQuestStatus);
  useEffect(
    function syncDeeplinkSource() {
      if (deeplinkSource) {
        setSource(deeplinkSource);
      }
    },
    [deeplinkSource, setSource],
  );

  const selectedQuest = useMemo(() => {
    return questsWithStatus?.find((quest) => quest.questId === questId);
  }, [questId, questsWithStatus]);

  useEffect(
    function handleInvalidDeeplink() {
      // invalid deeplink, replace current route with quests list
      if (!selectedQuest && questsWithStatus && questsWithStatus.length > 0) {
        replace('QuestsList', {});
      }
    },
    [questsWithStatus, replace, selectedQuest],
  );

  if (!selectedQuest) {
    return <LoadingFallback />;
  }

  return (
    <QuestStartProvider selectedQuest={selectedQuest}>
      <QuestDetailsContent selectedQuest={selectedQuest} source={deeplinkSource} />
    </QuestStartProvider>
  );
}

function QuestDetailsWithBoundary() {
  return (
    <ScreenBoundary fallback={<LoadingFallback />}>
      <QuestDetails />
    </ScreenBoundary>
  );
}

export { QuestDetailsWithBoundary as QuestDetails };

