type QuestRewardCardsProps = {
  quest: QuestMetadata;
};

export function QuestRewardCards({ quest }: QuestRewardCardsProps) {
  const { questId } = quest;
  const { data } = useGetQuestRewardContent(questId);
  const activeQuests = useActiveQuests();
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const isReferralEnabled = useIsFeatureEnabled('referral_program');
  const { navigateToDeeplinkUrl } = useNavigateToDeeplink();

  useLogQuestRewardCardsViewed();

  const onMorePress = useCallback(
    function onMorePress() {
      navigate('QuestsList');
    },
    [navigate],
  );

  const renderQuestRewardLinkCard = useCallback(function renderQuestRewardLinkCard({
    item,
  }: {
    item: QuestRewardCardType | undefined;
  }) {
    if (!item) return null;
    return <QuestRewardCard key={item.heading} card={item} />;
  },
  []);

  const nextQuest = useMemo(() => {
    if (!activeQuests) return undefined;

    const nextQuests = activeQuests.filter(({ progress }) => !progress);
    if (!nextQuests.length) return undefined;

    const nextPartnerQuest = nextQuests.find(({ partner }) => partner === quest.partner);
    return nextPartnerQuest ?? nextQuests[0];
  }, [activeQuests, quest.partner]);

  const nextQuestReward = useQuestRewardText(nextQuest, true);

  const nextQuestCard = useMemo(() => {
    return nextQuest
      ? ({
          heading: formatMessage(messages.startNext),
          subheading: formatMessage(messages.startNextDescription, {
            questTitle: nextQuest.title,
            reward: nextQuestReward,
          }),
          linkText: formatMessage(messages.startQuest),
          linkType: 'deeplink',
          linkUrl: `cbwallet://quests/${nextQuest.questId}/?source=rewardScreen`,
          asset: {
            contentType: 'illustration',
            cdsIllustrationName: 'congratulationsOnEarningCrypto',
          },
        } as QuestRewardCardType)
      : undefined;
  }, [formatMessage, nextQuest, nextQuestReward]);

  const referralCard = useMemo(() => {
    return isReferralEnabled
      ? ({
          heading: formatMessage(messages.referTitle),
          subheading: formatMessage(messages.referDescription),
          linkText: formatMessage(messages.earnMore),
          linkType: 'deeplink',
          linkUrl: `cbwallet://invite`,
          asset: {
            contentType: 'illustration',
            cdsIllustrationName: 'referralsPeople',
          },
        } as QuestRewardCardType)
      : undefined;
  }, [formatMessage, isReferralEnabled]);

  const cards = useMemo(() => {
    const tempCards = data?.cards
      ? [nextQuestCard, ...data.cards, referralCard]
      : [nextQuestCard, referralCard];
    return tempCards.filter((card) => card);
  }, [data, nextQuestCard, referralCard]);

  const renderItemSeparator = useCallback(function renderItemSeparator() {
    return <Box height={16} />;
  }, []);

  const showFullScreenReferralPromo = useMemo(() => {
    return cards.length === 1 && cards[0]?.linkUrl === `cbwallet://invite`;
  }, [cards]);

  const onNextQuestPress = useCallback(
    function onNextQuestPress() {
      if (nextQuestCard) {
        navigateToDeeplinkUrl(nextQuestCard.linkUrl);
      }
    },
    [navigateToDeeplinkUrl, nextQuestCard],
  );

  if (showFullScreenReferralPromo) {
    return <QuestRewardReferralPromo />;
  }

  return (
    <>
      <VStack spacingHorizontal={2} flexGrow={1} flexShrink={1} gap={1}>
        <TextTitle1>{data?.heading ?? formatMessage(messages.suggestedForYou)}</TextTitle1>
        <TextBody color="foregroundMuted" spacingBottom={1}>
          {data?.subheading ?? formatMessage(messages.youMightAlsoLike)}
        </TextBody>
        <FlatList
          data={cards}
          renderItem={renderQuestRewardLinkCard}
          ItemSeparatorComponent={renderItemSeparator}
          showsVerticalScrollIndicator={false}
        />
      </VStack>
      {nextQuestCard && (
        <VStack spacingHorizontal={3} spacingVertical={2}>
          <ButtonGroup accessibilityLabel="Group" direction="vertical">
            <Button
              variant="primary"
              onPress={onNextQuestPress}
              testID="quest-rewards-modal-next-quest-btn"
            >
              {formatMessage(messages.nextQuestCTA)}
            </Button>
            <Button
              variant={nextQuestCard ? 'secondary' : 'primary'}
              onPress={onMorePress}
              testID="quest-rewards-modal-more-btn"
            >
              {formatMessage(messages.checkOutMore)}
            </Button>
          </ButtonGroup>
        </VStack>
      )}
    </>
  );
}

