type QuestTermsTrayProps = {
  toggleOff: () => void;
  onAccept: () => void;
};

export function QuestTermsTray({ toggleOff, onAccept }: QuestTermsTrayProps) {
  const { formatMessage } = useIntl();
  const { setHasAgreedToQuestTerms } = useHasAgreedToQuestTerms();
  const [termsChecked, { toggle }] = useToggler(false);
  useBrowserQuestTermsTrayViewed();
  const { height } = useWindowDimensions();

  const onCloseComplete = useCallback(() => {
    toggleOff();
  }, [toggleOff]);

  const handleToggle = useCallback(
    function handleToggle() {
      if (termsChecked) {
        setHasAgreedToQuestTerms(false);
      } else {
        setHasAgreedToQuestTerms(true);
      }
      toggle();
    },
    [setHasAgreedToQuestTerms, termsChecked, toggle],
  );

  const onCTAClick = useCallback(
    function onCTAClick() {
      toggleOff();
      onAccept();
    },
    [onAccept, toggleOff],
  );

  return (
    <Tray
      onCloseComplete={onCloseComplete}
      disableCapturePanGestureToDismiss
      testID="quest-terms-tray"
    >
      <VStack height={(height / 3) * 2}>
        <ScrollView>
          <Pressable>
            <PortalProvider>
              <VStack spacingVertical={2} spacingHorizontal={3} gap={3}>
                <TextTitle3>{formatMessage(messages.termsTitle)}</TextTitle3>
                <TextBody color="foregroundMuted">{formatMessage(messages.terms)}</TextBody>
                <CDSPressable background="transparent" onPress={handleToggle}>
                  <HStack gap={2} width="85%">
                    <Checkbox
                      checked={termsChecked}
                      onChange={handleToggle}
                      accessibilityLabel={formatMessage(messages.checkbox)}
                      testID="quest-terms-checkbox"
                    />
                    <TextBody testID="quest-terms-label">
                      {formatMessage(messages.checkbox)}
                    </TextBody>
                  </HStack>
                </CDSPressable>
              </VStack>
            </PortalProvider>
          </Pressable>
        </ScrollView>
        <Divider />
        <Box width="90%" spacingTop={2} alignSelf="center">
          <Button
            variant="primary"
            testID="quest-terms-cta"
            onPress={onCTAClick}
            disabled={!termsChecked}
          >
            {formatMessage(messages.continue)}
          </Button>
        </Box>
      </VStack>
    </Tray>
  );
}

