export const LESSON_FOOTER_HEIGHT = 72;

type LessonFooterProps = {
  slides: QuestLessonSlide[];
  currentIndex: number;
  onForwardPress: () => void;
  onBackPress: () => void;
  onCTAPress: (button: QuestLessonButton) => void;
  isLoading: boolean;
};

export function LessonFooter({
  slides,
  currentIndex,
  onCTAPress,
  onForwardPress,
  onBackPress,
  isLoading,
}: LessonFooterProps) {
  const { bottom } = useDimensions();
  const button = slides[currentIndex].button;

  return (
    <VStack>
      <HStack height={LESSON_FOOTER_HEIGHT} width="100%" alignItems="center" spacingHorizontal={3}>
        {currentIndex > 0 && <IconButton disableDebounce name="backArrow" onPress={onBackPress} />}
        <Spacer minHorizontal={1} />
        {button ? (
          <Button
            compact
            flexShrink={1}
            spacingBottom={0}
            variant={button.variant}
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onPress={() => onCTAPress(button)}
            loading={isLoading}
          >
            {button.label}
          </Button>
        ) : (
          <IconButton disableDebounce name="forwardArrow" onPress={onForwardPress} />
        )}
      </HStack>
      <Box height={bottom} />
