type StepProgressProps = {
  spectrum: 'dark' | 'light';
  totalSegments: number;
  index: number;
};

function StepProgress({ spectrum, totalSegments, index }: StepProgressProps) {
  const height = useProgressSize('thin');
  const palette = usePalette();
  const background = usePaletteValueToRgbaString(spectrum === 'light' ? 'gray10' : 'gray20');

  return (
    <HStack
      justifyContent="space-between"
      alignItems="flex-start"
      flexShrink={1}
      height={height}
      borderRadius="rounded"
      gap={0.5}
    >
      {range(0, totalSegments).map((value) => {
        const filled = value === index;
        return (
          <Box
            key={`segment-${value}`}
            justifyContent="center"
            alignItems="flex-start"
            maxWidth={40}
            height={height}
            flexShrink={0}
            flexGrow={1}
            spacingEnd={2}
            borderRadius="rounded"
            dangerouslySetBackground={filled ? palette.foreground : background}
          />
        );
      })}
    </HStack>
  );
}

