function QuestClaimRewardContent() {
  const { formatMessage } = useIntl();
  const { isConnected } = useIsConnectedToCoinbase();
  const [
    isQuestConnectTrayVisible,
    { toggleOn: toggleOnConnetTray, toggleOff: toggleOffConnectTray },
  ] = useToggler(false);
  const claimReward = useClaimReward();
  const { navigate, canGoBack, goBack } = useStackNavigation();
  const { fetchRetailUserId } = useRetailUserId();
  const activeWalletGroupId = useActiveWalletGroupId();
  const evmWallet = useSelectedWallet(activeWalletGroupId, { blockchainSymbol: 'ETH' });
  const isWalletNewArchEnabled = useIsWalletNewArchEnabled();

  const [claimSuccess, setClaimSuccess] = useState<boolean | null>(null);

  const onClaimPress = useCallback(async () => {
    if (!isConnected) {
      toggleOnConnetTray();
      return;
    }
    if (!evmWallet) {
      setClaimSuccess(false);
      return;
    }
    try {
      const retailUserId = await fetchRetailUserId();
      const response = await claimReward({
        address: evmWallet.primaryAddress,
        retailUserId,
      });
      if (response.success && response.success.length > 0) {
        return setClaimSuccess(true);
      }
      return setClaimSuccess(false);
    } catch (e: ErrorOrAny) {
      return setClaimSuccess(false);
    }
  }, [isConnected, evmWallet, toggleOnConnetTray, fetchRetailUserId, claimReward]);

  const onCTAPress = useCallback(() => {
    if (claimSuccess === null) {
      onClaimPress();
    } else if (canGoBack()) {
      goBack();
    } else {
      // navigate to home
      if (isWalletNewArchEnabled) {
        return navigate('HomeTab', {
          screen: 'Home',
        });
      }
      return navigate('Assets', {
        screen: 'Assets',
      });
    }
  }, [canGoBack, claimSuccess, goBack, isWalletNewArchEnabled, navigate, onClaimPress]);

  const CTAmessage = useMemo(() => {
    if (claimSuccess === null) {
      return formatMessage(messages.claimRewards);
    }

    return formatMessage(messages.gotIt);
  }, [claimSuccess, formatMessage]);

  const renderContent = useCallback(() => {
    if (claimSuccess === null) {
      return <QuestClaimRewardLanding />;
    }

    return claimSuccess ? <QuestClaimRewardSuccess /> : <QuestClaimRewardFailed />;
  }, [claimSuccess]);

  return (
    <Screen
      full
      navBar={<NavBar left="back" title={formatMessage(messages.quests)} />}
      testID="quest-claim-rewards"
    >
      {renderContent()}
      <VStack spacingHorizontal={2}>
        <ButtonGroup accessibilityLabel="Group" direction="vertical">
          <Button variant="primary" onPress={onCTAPress} testID="quest-rewards-continue-btn">
            {CTAmessage}
          </Button>
        </ButtonGroup>
      </VStack>
      {isQuestConnectTrayVisible && (
        <QuestConnectTray questId="0" toggleOff={toggleOffConnectTray} />
      )}
    </Screen>
  );
}

