function QuestRewardContent({ questOverlay }: QuestRewardContentProps) {
  const { formatMessage } = useIntl();
  const questsWithStatus = useQuestsWithStatus();
  const [showCards, setShowCards] = useState(false);

  const quest = useMemo(() => {
    return questsWithStatus?.find((q) => q.questId === questOverlay?.questId);
