export function QuestReward() {
  const [questRewardModalsViewed, setQuestRewardModalsViewed] = useQuestRewardModalsViewed();
  const { questOverlay } = useParams<QuestsParamList, 'QuestReward'>();

  // here we want to track that the reward screen has been viewed
  // this is necessary for automatically navigating to this screen when
  // quest status changes from completed to rewarded
  useEffect(
    function markOverlayAsViewed() {
      if (questOverlay && !questRewardModalsViewed.includes(questOverlay.questId)) {
        setQuestRewardModalsViewed([...questRewardModalsViewed, questOverlay.questId]);
      }
    },
    [questOverlay, questRewardModalsViewed, setQuestRewardModalsViewed],
  );

  return (
    <ScreenBoundary>
      <NetworkBoundary fallback={<Fallback />} errorFallback={<Fallback />}>
        {questOverlay && <QuestRewardContent questOverlay={questOverlay} />}
      </NetworkBoundary>
    </ScreenBoundary>
  );
}

