const messages = defineMessages({
  screenTitle: {
    defaultMessage: 'Which asset are you receiving?',
    description:
      'header title for main SearchReceiveAsset screen. On this screen we show a list of assets for the user to choose',
  },
  searchInputPlaceholder: {
    defaultMessage: 'Search assets',
    description: 'Placeholder for asset search input',
  },

  learnMoreHyperText: {
    defaultMessage: 'Learn more',
    description: 'Copy for more infos hyperlink',
  },
  learnMoreDescription: {
    defaultMessage: 'Asset can exist on different networks.',
    description:
      'Brief preview of what kind of information is going to be found on Learn more hyperlink',
  },
  cancel: {
    defaultMessage: 'Cancel',
    description: 'Label for cancel button',
  },
});

function SearchReceiveAssetContent() {
  const { formatMessage } = useIntl();
  const [inputValue, setInputValue] = useState('');
  const [query, setQuery] = useState('');
  const { data, isLoading, error } = useAssetSearch(query);
  const { bottom, top } = useSafeAreaInsets();
  const footerSectionHeight = useMemo(() => 50 + bottom, [bottom]);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const footerSectionPadding = useMemo<StyleProp<Record<string, any>>>(
    () => ({ paddingBottom: bottom }),
    [bottom],
  );

  const { goBack } = useStackNavigation();

  const [containerHeight, setContainerHeight] = useState<number | undefined>(undefined);
  const [searchBarHeight, setSearchBarHeight] = useState<number | undefined>(undefined);

  const shouldHideFooterSection = useMemo(
    () => data && data.length === 0 && !isLoading && !error,
    [data, error, isLoading],
  );

  const assetsListHeight = useMemo(() => {
    const footerOffset = shouldHideFooterSection ? 0 : footerSectionHeight;
    if (containerHeight && searchBarHeight) {
      return containerHeight - searchBarHeight - footerOffset;
    }
  }, [containerHeight, footerSectionHeight, searchBarHeight, shouldHideFooterSection]);

  const handleContainerLayoutChange = useCallback(
    (e: LayoutChangeEvent) => {
      if (!containerHeight) {
        setContainerHeight(e.nativeEvent.layout.height);
      }
    },
    [containerHeight],
  );

  const handleSearchBarLayoutChange = useCallback(
    (e: LayoutChangeEvent) => {
      if (!searchBarHeight) {
        setSearchBarHeight(e.nativeEvent.layout.height);
      }
    },
    [searchBarHeight],
  );

  const debouncedQueryUpdate = useDebouncedCallback(setQuery, SEARCH_ASSET_QUERY_DEBOUNCE_MS);

  const handleInputChange = useCallback(
    (input: string) => {
      setInputValue(input);
      debouncedQueryUpdate(input);
    },
    [debouncedQueryUpdate],
  );

  const openWebBrowser = useOpenWebBrowser();

  const handleLearnMorePress = useCallback(() => {
    triggerSearchReceiveAssetLearnMoreClicked();
    openWebBrowser(SEARCH_RECEIVE_ASSETS_MORE_INFOS_URL);
  }, [openWebBrowser]);

  return (
    <VStack flexGrow={1} onLayout={handleContainerLayoutChange} top={top} spacingTop={2}>
      <HStack width="100%" alignItems="center" spacingHorizontal={3} spacingBottom={2} gap={3}>
        <Box onLayout={handleSearchBarLayoutChange} flexGrow={1}>
          <SearchInput
            placeholder={formatMessage(messages.searchInputPlaceholder)}
            value={inputValue}
            onChangeText={handleInputChange}
            disableBackArrow
            autoFocus
            testID="search-receive-address--search-input"
          />
        </Box>
        <Pressable
          background="transparent"
          onPress={goBack}
          testID="search-receive-address--go-back-button"
        >
          <TextHeadline>{formatMessage(messages.cancel)}</TextHeadline>
        </Pressable>
      </HStack>
      <SearchReceiveAssetList
        data={data}
        height={assetsListHeight}
        loading={isLoading}
        error={error}
      />
      {!shouldHideFooterSection && (
        <VStack
          height={footerSectionHeight}
          alignItems="center"
          justifyContent="center"
          // eslint-disable-next-line react/forbid-component-props
          style={footerSectionPadding}
          testID="search-receive-address--footer-section"
          position="absolute"
          bottom={bottom}
          width="100%"
          spacingVertical={2}
          minHeight={80}
          background="background"
        >
          <TextLabel2 color="foregroundMuted" align="center">
            {formatMessage(messages.learnMoreDescription)}
          </TextLabel2>
          <TextLabel2
            align="center"
            color="primary"
            onPress={handleLearnMorePress}
            spacingBottom={3}
          >
            {formatMessage(messages.learnMoreHyperText)}
          </TextLabel2>
        </VStack>
      )}
    </VStack>
  );
}

function SearchReceiveAsset() {
  useSearchReceiveAssetViewed();

  return <SearchReceiveAssetContent />;
}

