const REWARD_CONTENT_HEIGHT = 300;

type ReferralInviteScreenContentProps = {
  data: ReferralLinkV2ReturnType;
  refetchReferralLink: () => Promise<void>;
  walletAddress: string;
};

const ReferralInviteScreenContent = memo(function ReferralInviteScreenContent({
  data,
  refetchReferralLink,
  walletAddress,
}: ReferralInviteScreenContentProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation<ReferralProgramParamList>();
  const [trayVisible, { toggleOn: showTray, toggleOff: hideTray }] = useToggler(false);
  const [tosTrayVisible, { toggleOn: showTOSTray, toggleOff: hideTOSTray }] = useToggler(false);
  const { bottom } = useDimensions();
  const defaultSpacerHeight = useSpacingScale()[3];
  const [spacerHeight, setSpacerHeight] = useState<number>(defaultSpacerHeight);
  const [isScrollable, setScrollable] = useState<boolean>(false);
  const [scrollViewContentHeight, setScrollViewContentHeight] = useState<number>();
  const [scrollViewHeight, setScrollViewHeight] = useState<number>();
  const currencyFormatter = useCurrencyFormatter();
  const isReferralV2Enabled = useIsFeatureEnabled('referral_v2');
  const isReferralClaimCTAEnabled = useIsFeatureEnabled('referral_claim_cta');

  const redeemReferralBalance = useRedeemReferralV2Balance();

  useOnMount(() => {
    if (!walletAddress) {
      throw new Error('Wallet address is not available');
    }
  });

  if (!isReferralV2Enabled) {
    throw new Error('Page is not found.');
  }

  useEffect(
    function updateSpacerHeight() {
      if (!scrollViewContentHeight || !scrollViewHeight) return;

      setScrollable(scrollViewContentHeight > scrollViewHeight);

      // When the scroll view content height is less than the scroll view height (content is not scrollable),
      // we add a spacer to the top and bottom of the scroll view content to center the gradient circle.
      if (scrollViewContentHeight < scrollViewHeight) {
        const spacerDiff = (scrollViewHeight - scrollViewContentHeight) / 2;
        setSpacerHeight((prev) => prev + spacerDiff);
      }
    },
    [scrollViewContentHeight, scrollViewHeight],
  );

  const handleClaimPress = useCallback(async () => {
    hideTray();

    try {
      logReferralProgramClaimPressed(data.balance, getReferralId(data.href) ?? 'none', true);
      await redeemReferralBalance({ address: walletAddress });
      navigate('ReferralV2ClaimSuccessScreen', { amount: data.balance });
    } catch (error) {
      const err = coerceError(error, 'useRedeemReferralBalanceV2');
      cbReportError({
        error: err,
        context: 'referral_program',
        severity: 'error',
        isHandled: true,
      });
      navigate('ReferralClaimError');
    }
  }, [data.balance, data.href, hideTray, navigate, redeemReferralBalance, walletAddress]);

  const reward = useMemo(() => {
    const balanceValue = currencyFormatter.fiatValue(
      CurrencyCode.USDC,
      0n,
      BigInt(data.balance),
      USDC_ON_BASE,
      new Network(`ETHEREUM_CHAIN:8453`, false),
      new Blockchain(ETHEREUM_SYMBOL),
      0,
    );
    const balance = balanceValue
      ? currencyFormatter.fiatValueString(balanceValue, true, undefined, 0)
      : 'N/A';

    if (!data.rewardValue)
      return {
        refererBonusAmount: '-',
        fundAmount: '-',
        symbol: 'ETH',
        balance: balanceValue
          ? currencyFormatter.fiatValueString(balanceValue, true, undefined, 0)
          : '-',
      };

    const refererBonusAmountValue = currencyFormatter.fiatValue(
      CurrencyCode.USDC,
      0n,
      BigInt(data.rewardValue.amount),
      USDC_ON_BASE,
      new Network(`ETHEREUM_CHAIN:8453`, false),
      new Blockchain(ETHEREUM_SYMBOL),
      0,
    );

    const fundAmountValue = currencyFormatter.fiatValue(
      CurrencyCode.USDC,
      0n,
      BigInt(data.rewardValue.fundAmount),
      USDC_ON_BASE,
      new Network(`ETHEREUM_CHAIN:8453`, false),
      new Blockchain(ETHEREUM_SYMBOL),
      0,
    );

    return {
      refererBonusAmount: refererBonusAmountValue
        ? currencyFormatter.fiatValueString(refererBonusAmountValue, true, true, 0)
        : '-',
      fundAmount: fundAmountValue
        ? currencyFormatter.fiatValueString(fundAmountValue, true, true, 0)
        : '-',
      symbol: data.rewardValue.symbol ?? 'ETH',
      balance,
    };
  }, [currencyFormatter, data.balance, data.rewardValue]);

  const handleSharePress = useCallback(async () => {
    logReferralProgramSharePressed(getReferralId(data.href) ?? 'none', true);
    await Share.share({
      message: formatMessage(messages.shareMessage, {
        href: data.href,
      }),
      url: data.href,
    });
  }, [data.href, formatMessage]);

  const showRewardBalance = useMemo(() => data.conversions > 0, [data.conversions]);

  const handleInfoPress = useCallback(() => {
    navigate('ReferralV2InfoScreen', {
      fundAmount: reward.fundAmount,
      referralBonusAmount: reward.refererBonusAmount,
      symbol: reward.symbol,
    });
  }, [navigate, reward.fundAmount, reward.refererBonusAmount, reward.symbol]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: 'close',
      right: (
        <Pressable background="transparent" onPress={handleInfoPress}>
          <Icon name="info" size="s" color="foreground" />
        </Pressable>
      ),
    }),
    [handleInfoPress],
  );

  const handleScrollViewLayout = useCallback(
    (event: LayoutChangeEvent) => setScrollViewHeight(event.nativeEvent.layout.height),
    [],
  );

  const handleScrollViewContentSizeChange = useCallback(
    (_: number, height: number) => setScrollViewContentHeight(height),
    [],
  );

  const claimButton = useMemo(() => {
    if (!isReferralClaimCTAEnabled) return null;

    // Loading or no conversion or no balance to claim
    if (data.conversions === 0 || data.balance === '0') {
      return (
        <Button disabled spacingBottom={0} variant="secondary" endIcon="forwardArrow">
          {formatMessage(messages.claimReferralRewardsTitle)}
        </Button>
      );
    }

    // Show tooltip if status is not ready
    const showTooltip = data.redemptionStatus !== RedemptionStatus.REDEMPTION_STATUS_NOT_FOUND;
    const button = (
      <Button
        spacingBottom={0}
        disabled={showTooltip}
        variant="secondary"
        onPress={showTray}
        endIcon="forwardArrow"
      >
        {formatMessage(messages.claimReferralRewardsTitle)}
      </Button>
    );

    if (showTooltip) {
      return <Tooltip content={formatMessage(messages.claimTooltipMessage)}>{button}</Tooltip>;
    }

    return button;
  }, [
    data.balance,
    data.conversions,
    data.redemptionStatus,
    formatMessage,
    isReferralClaimCTAEnabled,
    showTray,
  ]);

  useReferralProgramViewed(true);

  return (
    <Screen navBar={navBar}>
      <ScrollView
        refreshControl={<RefreshControl onRefresh={refetchReferralLink} />}
        onLayout={handleScrollViewLayout}
        onContentSizeChange={handleScrollViewContentSizeChange}
      >
        <VStack
          alignItems="center"
          justifyContent="center"
          gap={2}
          spacingHorizontal={4}
          spacingTop={3}
        >
          <TextTitle2 align="center">
            {formatMessage(messages.promoHeaderDescription, {
              referrerRewardAmount: reward.refererBonusAmount,
            })}
          </TextTitle2>
          <>
            <TextHeadline align="center" color="foregroundMuted">
              {formatMessage(messages.promoMessageDescription, {
                referrerRewardAmount: reward.refererBonusAmount,
                fundAmount: reward.fundAmount,
                symbol: reward.symbol,
              })}
            </TextHeadline>
            <TermsLink onPress={showTOSTray} />
          </>
        </VStack>
        <Box height={spacerHeight} />
        {showRewardBalance ? (
          <RewardBalance amount={reward.balance} height={REWARD_CONTENT_HEIGHT} />
        ) : (
          <VStack
            alignItems="center"
            justifyContent="center"
            height={REWARD_CONTENT_HEIGHT}
            flexGrow={1}
            gap={2}
            testID="referral-screen-miami-illustration-wrapper"
          >
            <MiamiIllustrationWrapper illustration="ReferralsAvatarsMiami">
              <HeroSquare name="referralsAvatars" />
            </MiamiIllustrationWrapper>
          </VStack>
        )}
        <Box height={spacerHeight} />
      </ScrollView>
      <Box borderedTop={isScrollable} spacingHorizontal={2} spacingTop={2}>
        <ButtonGroup direction="vertical">
          <Button spacingBottom={0} variant="primary" onPress={handleSharePress} endIcon="share">
            {formatMessage(messages.shareButtonTitle)}
          </Button>
          {claimButton}
          <Box height={bottom} />
        </ButtonGroup>
      </Box>
      {trayVisible && (
        <Tray onCloseComplete={hideTray} testID="claim-referral-rewards-tray">
          <VStack spacingHorizontal={3} gap={2}>
            <TextTitle3>{formatMessage(messages.claimReferralRewardsTitle)}</TextTitle3>
            <TextBody color="foregroundMuted">
              {formatMessage(messages.claimReferralRewardsMessage, {
                balance: reward.balance,
              })}
            </TextBody>
          </VStack>
          <VStack spacingTop={3} spacingHorizontal={3} gap={0.5}>
            {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
            {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
            <Button variant="primary" onPress={handleClaimPress}>
              {formatMessage(messages.claimCTAText, { balance: reward.balance })}
            </Button>
            {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
            {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
            <Button variant="secondary" onPress={hideTray}>
              {formatMessage(messages.cancelCTAText)}
            </Button>
          </VStack>
        </Tray>
      )}
      {tosTrayVisible && (
        <Tray onCloseComplete={hideTOSTray} testID="tos-tray">
          <VStack spacingHorizontal={3} gap={2}>
            <TextTitle3>{formatMessage(messages.tosTitle)}</TextTitle3>
            <TextBody color="foregroundMuted">{formatMessage(messages.tosContent)}</TextBody>
          </VStack>
          <VStack spacingTop={3} spacingHorizontal={3}>
            <Button variant="primary" onPress={hideTOSTray}>
              {formatMessage(messages.primaryCTAText)}
            </Button>
          </VStack>
        </Tray>
      )}
    </Screen>
  );
});

function ReferralV2InviteScreen() {
  const activeWalletGroupId = useActiveWalletGroupId();
  const walletAddress = usePrimaryReceiveAddresses(activeWalletGroupId).get('ETH')?.address;
  const {
    data,
    error: fetchReferralLinkError,
    isLoading: isFetchReferralLinkLoading,
    refetch: refetchReferralLink,
  } = useGetReferralV2Link({ address: walletAddress });

  // TODO: we could display a better error screen.
  if (fetchReferralLinkError) {
    // Backend returns a 403 when the user is not eligible for the referral program
    if (fetchReferralLinkError instanceof HTTPError && fetchReferralLinkError.status === 403) {
      return <IneligibleState />;
    }

    cbReportError({
      error: fetchReferralLinkError,
      context: 'referral_program',
      severity: 'error',
      isHandled: true,
    });
    throw fetchReferralLinkError;
  }

  if (isFetchReferralLinkLoading || !data || !walletAddress) {
    return <Loader testID="referral-screen-loader" size="large" />;
  }

  return (
    <ReferralInviteScreenContent
      data={data}
      refetchReferralLink={refetchReferralLink}
      walletAddress={walletAddress}
    />
  );
}

function ReferralV2InviteScreenWithBoundary() {
  return (
    <ScreenBoundary>
      <ReferralV2InviteScreen />
    </ScreenBoundary>
  );
}

function getReferralId(url: string) {
  const parsed = safeParseUrl(url);
  return parsed.params.referral_id;
}

export { ReferralV2InviteScreenWithBoundary as ReferralV2InviteScreen };

