type WarmWelcomeAction = {
  title: string;
  subtitle: string;
  icon: UiIconName;
  selected?: boolean;
  deeplink: string;
};

export function ReferralWarmWelcomeScreen() {
  const params = useParams<ReferralProgramParamList, 'ReferralWarmWelcomeScreen'>();
  const { formatMessage } = useIntl();
  const { navigateToDeeplinkUrl } = useNavigateToDeeplink();
  const { bottom: bottomInset } = useDimensions();
  const setReferralId = useSetRecoilState(referralIdAtom);

  const activeWalletGroupId = useActiveWalletGroupId();
  const { queryRetailUserId } = useRetailUserId();
  const { data: retailUserId, isLoading: isRetailUserIdLoading } = queryRetailUserId;

  const { isLoading } = useFetchQuestsData({
    walletGroupId: activeWalletGroupId,
    retailUserId,
    suspense: false,
    enableQuery: !isRetailUserIdLoading,
  });
  const questFiatReward = useFiatRewardsToDisplay();

  useEffect(
    function updateReferralId() {
      if (params.referralId) {
        logReferralIdUpdated(params.referralId);
        setReferralId(params.referralId);
      }
    },
    [params.referralId, setReferralId],
  );

  const { columnOne, columnTwo } = useMemo(() => {
    const items: WarmWelcomeAction[] = [
      {
        title: questFiatReward
          ? formatMessage(messages.questTileTitle, { fiatAmount: questFiatReward })
          : formatMessage(messages.questTileTitleFallback),
        subtitle: formatMessage(messages.questTileSubtitle),
        icon: 'trophy',
        selected: true,
        deeplink: 'cbwallet://quests',
      },
      {
        title: formatMessage(messages.addCryptoTileTitle),
        subtitle: formatMessage(messages.addCryptoTileSubtitle),
        icon: 'wallet',
        deeplink: 'cbwallet://buy',
      },
      // add more actions once available: (Send via Link, Referrals, etc)
    ];
    return {
      columnOne: items.filter((_, index) => index % 2 === 0),
      columnTwo: items.filter((_, index) => index % 2 === 1),
    };
  }, [formatMessage, questFiatReward]);

  const handleTilePress = useCallback(
    function handleTilePress(item: WarmWelcomeAction) {
      logReferralWarmWelcomeTilePressed(item.deeplink);
      navigateToDeeplinkUrl(item.deeplink);
    },
    [navigateToDeeplinkUrl],
  );

  const handleContinuePress = useCallback(
    function handleContinuePress() {
      logReferralWarmWelcomeContinuePressed('cbwallet://quests');
      navigateToDeeplinkUrl('cbwallet://quests');
    },
    [navigateToDeeplinkUrl],
  );

  const navBarConfig: NavBarConfig = useMemo(() => ({ left: 'back' }), []);

  if (isLoading) {
    return (
      <ScreenBoundary>
        <Loader testID="referral-warm-welcome-loader" size="large" />
      </ScreenBoundary>
    );
  }

  return (
    <ScreenBoundary>
      <Screen navBar={navBarConfig}>
        <VStack flexGrow={1} spacingHorizontal={3} alignItems="center" justifyContent="center">
          <MiamiIllustrationWrapper illustration="ReferralsBonusMiami">
            <SpotRectangle name="referralsBonus" />
          </MiamiIllustrationWrapper>
          <VStack spacingVertical={2} spacingHorizontal={3} gap={1} alignItems="center">
            <TextTitle2 align="center">{formatMessage(messages.title)}</TextTitle2>
            <TextBody align="center" color="foregroundMuted">
              {formatMessage(messages.description)}
            </TextBody>
          </VStack>
          <HStack spacing={2} gap={2}>
            <VStack flexBasis="50%" gap={2}>
              {columnOne.map((item) => (
                <ActionTile key={item.title} item={item} onPress={handleTilePress} />
              ))}
            </VStack>
            <VStack flexBasis="50%" gap={2}>
              {columnTwo.map((item) => (
                <ActionTile key={item.title} item={item} onPress={handleTilePress} />
              ))}
            </VStack>
          </HStack>
        </VStack>
        <Button spacingHorizontal={3} spacingBottom={0} onPress={handleContinuePress}>
          {formatMessage(messages.ctaButtonLabel)}
        </Button>
        <Box height={bottomInset} />
      </Screen>
    </ScreenBoundary>
  );
}

type ActionTileProps = {
  item: WarmWelcomeAction;
  onPress: (item: WarmWelcomeAction) => void;
};

const borderStyle: ViewStyle = { borderWidth: 4 };

function ActionTile({ item, onPress }: ActionTileProps) {
  const { title, subtitle, icon, selected } = item;

  const handlePress = useCallback(() => onPress(item), [item, onPress]);

  return (
    <PressableOpacity
      testID={`${title}-action-title`}
      onPress={handlePress}
      accessibilityRole="button"
      feedback="light"
    >
      <VStack
        aspectRatio={1}
        borderRadius="roundedLarge"
        background="backgroundAlternate"
        spacing={2}
        bordered={selected}
        borderColor={selected ? 'primary' : 'transparent'}
        // eslint-disable-next-line react/forbid-component-props
        style={borderStyle}
      >
        <IconButton onPress={handlePress} name={icon} variant="primary" feedback="none" />
        <TextLegal spacingTop={2} color="foregroundMuted" numberOfLines={1} ellipsizeMode="tail">
          {subtitle}
        </TextLegal>
        <TextHeadline spacingTop={0.5} numberOfLines={2} ellipsizeMode="tail">
          {title}
        </TextHeadline>
      </VStack>
    </PressableOpacity>
  );
}

