import { SpacingScale } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Box, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { StatusBar } from '@cbhq/cds-mobile/system';
import { ThemeProvider } from '@cbhq/cds-mobile/system/ThemeProvider';
import { TextBody, TextHeadline } from '@cbhq/cds-mobile/typography';

import { ScreenBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ScreenBoundary';

import { QRCodeScanner, QRCodeScannerProps } from './components/QRCodeScanner';

const messages = defineMessages({
  screenTitle: {
    defaultMessage: 'Scan QR code',
    description: 'Title for screen on which a user can scan a QR code.',
  },
});

type Props = {
  visible: boolean;
  onClose: () => void;
} & QRCodeScannerProps;

function QRCodeScannerModal({ visible, onClose, ...qrCodeScannerProps }: Props) {
  const { formatMessage } = useIntl();
  const { top: paddingTop } = useSafeAreaInsets();
  const qrCodeScannerViewed = useQRCodeScannerViewed();
  const qrCodeScannerClosed = useQRCodeScannerClosed();
  const [viewEventLogged, setViewEventLogged] = useState(false);
  const [error, setError] = useState<string | undefined>();

  const handleError = useCallback((errorMessage: string) => {
    setError(errorMessage);
  }, []);

  useEffect(
    function logModalViewEvent() {
      if (visible && !viewEventLogged) {
        qrCodeScannerViewed();
        setViewEventLogged(true);
      }

      if (!visible && viewEventLogged) {
        qrCodeScannerClosed();
        setViewEventLogged(false);
        setError(undefined);
      }
    },
    [qrCodeScannerClosed, qrCodeScannerViewed, viewEventLogged, visible],
  );

  return (
    <Modal animationType="slide" visible={visible} onRequestClose={onClose}>
      <StatusBar barStyle="light-content" />
      <ThemeProvider name="qrScanner" spectrum="dark">
        <VStack flexGrow={1}>
          <HStack
            position="absolute"
            background="transparent"
            top={paddingTop as SpacingScale}
            zIndex={1}
          >
            <HStack justifyContent="center" alignItems="center" flexGrow={1}>
              <Box
                position="absolute"
                top={0}
                left={0}
                bottom={0}
                justifyContent="center"
                spacingStart={1}
              >
                <IconButton transparent name="close" onPress={onClose} />
              </Box>

              <TextHeadline>{formatMessage(messages.screenTitle)}</TextHeadline>
            </HStack>
          </HStack>

          <QRCodeScanner {...qrCodeScannerProps} onError={handleError} />
          <HStack
            position="absolute"
            background="transparent"
            bottom={0}
            width="100%"
            zIndex={1}
            spacingHorizontal={3}
            spacingBottom={3}
            alignItems="center"
            justifyContent="center"
          >
            {Boolean(error) && (
              <TextBody align="center" color="negative">
                {error}
              </TextBody>
            )}
          </HStack>
        </VStack>
      </ThemeProvider>
    </Modal>
  );
}

function QRCodeScannerModalWithBoundary(props: Props) {
  return (
    <ScreenBoundary>
      <QRCodeScannerModal {...props} />
    </ScreenBoundary>
  );
}

export { QRCodeScannerModalWithBoundary as QRCodeScannerModal };

