}));

function Fixture() {
  const component = useCallback(() => {
    return (
      <MockedProviders>
        <ScanGlobalAction />
      </MockedProviders>
    );
  }, []);

  return <MockedNavigator component={component} />;
}

describe('ScanGlobalAction', () => {
  const navigateMock = jest.fn();
  const saveSessionMock = jest.fn();

  beforeEach(() => {
    (useStackNavigation as jest.Mock).mockReturnValue({ navigate: navigateMock });
    (useSaveSession as jest.Mock).mockReturnValue(saveSessionMock);
    (usePortfolioWallets as jest.Mock).mockReturnValue([
      mockUTXOWallet,
      mockETHWallet,
      mockSHIBWallet,
    ]);
    (useHandleCryptoTransferDeeplink as jest.Mock).mockReturnValue(
      mockHandleCryptoTransferDeeplink,
    );
  });

  it('should navigate to SendSelectAssest', async () => {
    render(<Fixture />);
    const data = {
      source: 'qr_code_scan',
      type: PrefilledTransactionType.CRYPTO,
      data: {
        chain: 'ETH',
        address: '',
        params: {},
      },
    };

    fireEvent.press(screen.getByLabelText('mockQRCodeRead'), data);

    expect(mockHandleCryptoTransferDeeplink).toHaveBeenCalledWith(data);
  });

  it('should navigate to Browser', async () => {
    render(<Fixture />);

    fireEvent.press(screen.getByLabelText('mockQRCodeRead'), {
      type: QRCodeType.URL,
      data: {
        url: { href: 'zapper.io' },
      },
    });

    await waitFor(() => expect(navigateMock).toHaveBeenCalledTimes(1));
    expect(navigateMock).toHaveBeenCalledWith('BrowserTab', {
      deeplinkUrl: 'zapper.io',
      activeTabId: undefined,
      action: 'browse',
    });
  });

  it('should handle SVL QR code', async () => {
    render(<Fixture />);

    mockHandleSvlQr.mockReturnValue(true);
    fireEvent.press(screen.getByLabelText('mockQRCodeRead'), {
      type: QRCodeType.URL,
      data: {
        url: { href: '/claim/#/code=123456' },
      },
    });

    await waitFor(() => expect(navigateMock).not.toHaveBeenCalled());
  });

  it('should navigate to process universal deeplink url', async () => {
    render(<Fixture />);

    fireEvent.press(screen.getByLabelText('mockQRCodeRead'), {
      type: QRCodeType.UNIVERSAL_LINK,
      data: {
        url: { href: 'https://go.cb-w.com?foo=bar' },
      },
    });

    await waitFor(() => expect(mockHandleUniversalLink).toHaveBeenCalledTimes(1));
    expect(mockHandleUniversalLink).toHaveBeenCalledWith('https://go.cb-w.com?foo=bar');
  });

  it('should save a walletlink session', async () => {
    render(<Fixture />);

    fireEvent.press(screen.getByLabelText('mockQRCodeRead'), {
      type: QRCodeType.WALLET_LINK,
      data: {
        sessionId: '123',
        secret: 'secret',
        url: 'url',
        version: '1.2.3',
        isParent: true,
      },
    });

    await waitFor(() => expect(saveSessionMock).toHaveBeenCalledTimes(1));
    expect(saveSessionMock).toHaveBeenCalledWith({
      id: '123',
      secret: 'secret',
      url: 'url',
      version: '1.2.3',
      isParent: true,
      chainId: 1,
    });
  });
});

import { memo, useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { logAssetsScanClicked } from 'cb-wallet-analytics/assets';
import { usePortfolioWallets } from 'cb-wallet-data/stores/Wallets/hooks/usePortfolioWallets';
import { useToggler } from '@cbhq/cds-common';
import { NavigationIcon } from '@cbhq/cds-mobile/icons';
import { PressableOpacity } from '@cbhq/cds-mobile/system';

import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { GlobalAction } from ':rn/cds-wallet/components/GlobalActions/GlobalActions';
import { AutoHitSlopWrapper } from ':rn/cds-wallet/components/interactables/AutoHitSlopWrapper';
import { useHandleUniversalLink } from ':rn/shared/hooks/useDeeplinking/useHandleUniversalLink';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';
import { useSaveSession } from ':rn/shared/walletlink/hooks/useSaveSession';

import { useHandleCryptoTransferDeeplink } from './hooks/useHandleCryptoTransferDeeplink';
import { useHandleSvlQr } from './hooks/useHandleSvlQr';
import { QRCodeScannerModal } from './QRCodeScannerModal';
import { QRCodeScannerResponse, QRCodeType } from './types';

const messages = defineMessages({
  a11yLabel: {
    defaultMessage: 'Scan QR Code',
    description: 'Scan Global Action accessibility label',
  },
});

type Props = {
  type?: 'actionButton' | 'navBarButton';
};

function ScanGlobalAction({ type = 'actionButton' }: Props) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const wallets = usePortfolioWallets();
  const saveSession = useSaveSession();

  const handleSvlQr = useHandleSvlQr();
  const handleUniversalLink = useHandleUniversalLink();
  const handleCryptoTransferDeeplink = useHandleCryptoTransferDeeplink({ fromQRCodeScan: true });
  const [showQRCodeScanner, { toggleOn: openQRCodeScanner, toggleOff: closeQRCodeScanner }] =
    useToggler(false);

  const handleScanActionPressed = useCallback(
    function handleScanActionPressed() {
      logAssetsScanClicked();
      openQRCodeScanner();
    },
    [openQRCodeScanner],
  );

  const handleSendNavigation = useCallback(
    function handleSendNavigation(response: QRCodeScannerResponse) {
      if (wallets === undefined || response?.type !== QRCodeType.CRYPTO || !response.data) {
        return;
      }

      handleCryptoTransferDeeplink(response);
    },
    [handleCryptoTransferDeeplink, wallets],
  );

  const handleOnScan = useCallback(
    function onScan(response: QRCodeScannerResponse) {
      closeQRCodeScanner();

      if (!response) {
        return;
      }

      switch (response.type) {
        case QRCodeType.UNIVERSAL_LINK:
          handleUniversalLink(response.data.url.href);
          break;
        case QRCodeType.CRYPTO:
          handleSendNavigation(response);
          break;
        case QRCodeType.URL:
          // handle edge case of claim link QR Code triggered from within CBW
          if (handleSvlQr(response.data.url.href)) {
            break;
          }

          // otherwise open the browser tab
          navigate('BrowserTab', {
            deeplinkUrl: response.data.url.href,
            activeTabId: undefined,
            action: 'browse',
          });
          break;
        case QRCodeType.WALLET_LINK:
          saveSession({
            id: response.data.sessionId,
            secret: response.data.secret,
            url: response.data.url,
            version: response.data.version,
            isParent: response.data.isParent,
            chainId: response.data.chainId ?? 1,
          });
          break;
        default:
          break;
      }
    },
    [
      closeQRCodeScanner,
      handleSendNavigation,
      handleSvlQr,
      handleUniversalLink,
      navigate,
      saveSession,
    ],
  );

  return (
    <>
      {type === 'navBarButton' ? (
        <AutoHitSlopWrapper>
          <PressableOpacity
            onPress={handleScanActionPressed}
            testID="assets-action-btn-scan"
            accessibilityLabel={formatMessage(messages.a11yLabel)}
          >
            <NavigationIcon size="m" name="scanQrCode" />
          </PressableOpacity>
        </AutoHitSlopWrapper>
      ) : (
        <GlobalAction
          testID="assets-action-btn-scan"
          label="scan"
          iconName="qrCode"
          onPress={handleScanActionPressed}
        />
      )}
      <QRCodeScannerModal
        visible={showQRCodeScanner}
        onScan={handleOnScan}
        onClose={closeQRCodeScanner}
      />
    </>
  );
}

const ScanGlobalActionWithBoundary = memo(function ScanGlobalActionWithBoundary({
  type = 'actionButton',
}: Props) {
  return (
    <ErrorBoundary errorFallback={null}>
      <ScanGlobalAction type={type} />
    </ErrorBoundary>
  );
});

export { ScanGlobalActionWithBoundary as ScanGlobalAction };

import { useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { usePublicDomainProfile } from 'cb-wallet-data/stores/DecentralizedID/hooks/usePublicDomainProfile';
import { SearchEntity, SearchResponse } from 'cb-wallet-data/stores/Search/types';
import { getTruncatedAddress } from 'cb-wallet-data/utils/getTruncatedAddress';
import { PERF_MARKS, PROFILE_MARKS } from 'cb-wallet-data/utils/perf-constants';
import { ListCell } from '@cbhq/cds-mobile/cells';
import { VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';
import { usePerfMark } from '@cbhq/core-vitals/hooks';
import { markJourney } from '@cbhq/core-vitals-mobile';

import { saveToRecentSearches } from ':rn/screens/Search/recentSearchUtils';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { SearchResultAvatar } from '../SearchResultAvatar';

type ExactAddressMatchProps = {
  address: string;
};

const messages = defineMessages({
  goToWallet: {
    defaultMessage: 'Go to wallet',
    description: 'CTA text for an exact address match',
  },
});

function generateAddressField(address: string) {
  return { key: 'Address', value: address };
}

export function ExactAddressMatch({ address }: ExactAddressMatchProps) {
  const { navigate } = useStackNavigation();
  const { formatMessage } = useIntl();

  const [startProfilePageLoadPerfMark] = usePerfMark(
    PERF_MARKS.profile,
    PROFILE_MARKS.profile_page_load,
    {
      logMetric: true,
    },
  );
  const truncatedAddress = getTruncatedAddress(address);

  const publicDomainProfile = usePublicDomainProfile({ address });

  const handleOnPress = useCallback(
    function handleOnPress() {
      const response: SearchResponse = {
        fields: [generateAddressField(address)],
        name: truncatedAddress,
        type: SearchEntity.SEARCH_ENTITY_ENS,
      };
      saveToRecentSearches(response);
      startProfilePageLoadPerfMark();
      markJourney('navigate_to_profile_from_explore_search');
      navigate('Profile', { address });
    },
    [address, navigate, startProfilePageLoadPerfMark, truncatedAddress],
  );
  return (
    <VStack testID="exact-address-match">
      <ListCell
        testID="exact-address-match-cell"
        onPress={handleOnPress}
        title={truncatedAddress}
        media={
          <SearchResultAvatar
            address={address}
            imageUrl={publicDomainProfile?.profileTextRecords?.avatar}
          />
        }
      />
      <Pressable noScaleOnPress onPress={handleOnPress} background="transparent">
        <TextBody spacingHorizontal={2} color="primary">
          {formatMessage(messages.goToWallet)}
        </TextBody>
      </Pressable>
    </VStack>
  );
}

import { useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { allDeprecatedBlockchains } from 'cb-wallet-data/chains/blockchains';
import { useFormatPercent } from 'cb-wallet-data/hooks/useFormatPercent';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { useGetExploreAssetWallet } from 'cb-wallet-data/stores/Explore/hooks/useGetExploreAssetWallet';
import { Network } from 'cb-wallet-data/stores/Networks/models/Network';
import { SearchEntity, SearchResponse } from 'cb-wallet-data/stores/Search/types';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { PERF_MARKS, PROFILE_MARKS } from 'cb-wallet-data/utils/perf-constants';
import { subheadIconSignMap } from '@cbhq/cds-common/tokens/sparkline';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Icon } from '@cbhq/cds-mobile/icons';
import { usePerfMark } from '@cbhq/core-vitals/hooks';
import { markJourney } from '@cbhq/core-vitals-mobile';

import { AssetIcon } from ':rn/cds-wallet/components/icons/AssetIcon';
import { ARROW_DOWN_DIAGONAL, ARROW_UP_DIAGONAL } from ':rn/screens/Explore/constants';
import {
  logAssetCardViewed,
  logAssetResultClick,
  logProfileCardClicked,
  logProfileCardViewed,
  logSearchSuggestionClick,
  SearchContext,
} from ':rn/screens/Search/eventing';
import { useSearchResult } from ':rn/screens/Search/hooks/useSearchResult';
import {
  getRecentSearches,
  removeFromRecentSearch,
  saveToRecentSearches,
} from ':rn/screens/Search/recentSearchUtils';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';
import { AssetDetailSource } from ':rn/shared/types/ParamLists';

import { SearchResultAvatar } from '../SearchResultAvatar';

import { SearchResultListCell } from './SearchResultListCell';

type SearchResultProps = {
  isRecent?: boolean;
  isTypeahead?: boolean;
  searchResponse: SearchResponse;
  rankIndex: number;
  requestId?: string;
  onRemoveRecentSearch?: (updatedSearchList: SearchResponse[]) => void;
};

const ASSET_ICON_SIZE = 32;

const messages = defineMessages({
  deleteButtonAriaLabel: {
    defaultMessage: 'Delete result from recent searches',

    description:
      'Aria label that tells the user they are focused on the button to delete selected search result',
  },
});

export function SearchResult({
  isRecent,
  searchResponse,
  rankIndex,
  requestId,
  isTypeahead = false,
  onRemoveRecentSearch,
}: SearchResultProps) {
  const { navigate } = useStackNavigation();
  const { formatMessage } = useIntl();
  const activeWalletGroupId = useActiveWalletGroupId();
  const getExploreAssetWallet = useGetExploreAssetWallet(activeWalletGroupId);
  const formatPercent = useFormatPercent();
  const [startProfilePageLoadPerfMark] = usePerfMark(
    PERF_MARKS.profile,
    PROFILE_MARKS.profile_page_load,
    {
      logMetric: true,
    },
  );

  const searchResult = useSearchResult(searchResponse);

  const isDeprecatedAssetResult = useMemo(
    () =>
      searchResult?.type === SearchEntity.SEARCH_ENTITY_ASSET &&
      allDeprecatedBlockchains.includes(searchResult?.asset?.blockchain?.rawValue),
    [searchResult],
  );

  const icon = useMemo(() => {
    switch (searchResult?.type) {
      case SearchEntity.SEARCH_ENTITY_ASSET: {
        return (
          <AssetIcon
            iconUrl={searchResult.imageUrl}
            currencyCode={searchResult.subTitleText}
            showNetworkIcon
            network={
              searchResult.chainID
                ? Network.fromChainId({ chainId: BigInt(searchResult.chainID) })
                : undefined
            }
            height={ASSET_ICON_SIZE}
            width={ASSET_ICON_SIZE}
          />
        );
      }
      case SearchEntity.SEARCH_ENTITY_ENS: {
        return (
          <SearchResultAvatar
            address={searchResult?.address}
            imageUrl={searchResult?.imageUrl}
            size="l"
          />
        );
      }
      case SearchEntity.SEARCH_ENTITY_QUERY: {
        return <Icon name="search" size="s" color="foregroundMuted" />;
      }

      default:
        break;
    }
  }, [searchResult]);

  const title = searchResult?.titleText;

  const description = useMemo(() => {
    if (isRecent) return;
    switch (searchResult?.type) {
      case SearchEntity.SEARCH_ENTITY_ASSET: {
        return searchResult.subTitleText;
      }
      default:
        break;
    }
  }, [isRecent, searchResult]);

  const percent = useMemo(() => {
    if (!isRecent && searchResult?.subDetail) {
      return formatPercent(Number(searchResult?.subDetail), 2);
    }
  }, [formatPercent, isRecent, searchResult?.subDetail]);

  const variant = useMemo(() => {
    if (percent) {
      return Number(searchResult?.subDetail) > 0 ? 'positive' : 'negative';
    }
  }, [searchResult?.subDetail, percent]);

  const subdetail = useMemo(() => {
    if (variant === 'positive') {
      return `${subheadIconSignMap[ARROW_UP_DIAGONAL]}${percent}`;
    }
    if (variant === 'negative') {
      return `${subheadIconSignMap[ARROW_DOWN_DIAGONAL]}${percent}`;
    }
  }, [percent, variant]);

  const eventData = useMemo(
    () => ({ searchRequestId: requestId, rankIndex }),
    [rankIndex, requestId],
  );

  useOnMount(() => {
    if (isRecent || isTypeahead) return;
    switch (searchResult?.type) {
      case SearchEntity.SEARCH_ENTITY_ASSET: {
        logAssetCardViewed({
          asset: description,
          ...eventData,
        });
        break;
      }
      case SearchEntity.SEARCH_ENTITY_ENS: {
        logProfileCardViewed({
          walletAddress: searchResult?.address,
          ...eventData,
        });
        break;
      }
      default:
        break;
    }
  });

  const searchResultType: SearchContext = useMemo(() => {
    if (isRecent) return 'recent';
    return isTypeahead ? 'typeahead' : 'full';
  }, [isRecent, isTypeahead]);

  const logAssetPress = useCallback(() => {
    logAssetResultClick({
      context: searchResultType,
      asset: description,
      ...eventData,
    });
  }, [description, eventData, searchResultType]);

  const logProfilePress = useCallback(() => {
    logProfileCardClicked({
      context: searchResultType,
      walletAddress: searchResult?.address,
      ...eventData,
    });
  }, [eventData, searchResultType, searchResult?.address]);

  const logSearchSuggestionPress = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (searchTermType: any) => {
      logSearchSuggestionClick({
        rankIndex,
        context: 'recent',
        term: title,
        termType: searchTermType,
      });
    },
    [rankIndex, title],
  );

  const handleRemoveFromRecentSearch = useCallback(
    function handleRemoveFromRecentSearch() {
      removeFromRecentSearch(searchResponse);

      onRemoveRecentSearch?.(getRecentSearches());
    },
    [searchResponse, onRemoveRecentSearch],
  );

  const handlePress = useCallback(() => {
    switch (searchResult?.type) {
      case SearchEntity.SEARCH_ENTITY_ASSET: {
        saveToRecentSearches(searchResponse);
        logAssetPress();
        logSearchSuggestionPress('asset');
        const assetWallet = getExploreAssetWallet(searchResult.asset.id);
        navigate('AssetDetail', {
          walletId: assetWallet?.id ?? searchResult.asset.id,
          source: AssetDetailSource.Explore,
        });
        break;
      }
      case SearchEntity.SEARCH_ENTITY_ENS: {
        logProfilePress();
        logSearchSuggestionPress('profile');
        saveToRecentSearches(searchResponse);
        startProfilePageLoadPerfMark();
        markJourney('navigate_to_profile_from_explore_search');
        navigate('Profile', {
          address: searchResult.address,
          // title can be either a plain ETH address, an ENS domain, or a cb.id domain
          // this check passes forward the latter 2 as `domain` param to `Profile` screen
          domain: title?.includes('.') ? title : undefined,
        });
        break;
      }
      case SearchEntity.SEARCH_ENTITY_QUERY: {
        saveToRecentSearches(searchResponse);
        logSearchSuggestionPress('search');
        navigate('AllResults', { query: title, isRecent });
        break;
      }
      default:
        break;
    }
  }, [
    isRecent,
    searchResult,
    startProfilePageLoadPerfMark,
    title,
    searchResponse,
    logAssetPress,
    getExploreAssetWallet,
    navigate,
    logProfilePress,
    logSearchSuggestionPress,
  ]);

  if (
    (searchResult?.type === SearchEntity.SEARCH_ENTITY_ENS && !searchResult?.address) ||
    isDeprecatedAssetResult
  ) {
    return null;
  }

  return (
    <SearchResultListCell
      testID={`search-result-${searchResult?.type}`}
