export const ContactRecipientSuggestion = memo(function ContactRecipientSuggestion({
  contact,
  wallet,
  disabled,
  onSelectSendViaLink,
}: ContactRecipientSuggestionProps) {
  const { recordID } = contact;
  const [isTrayVisible, { toggleOn, toggleOff }] = useToggler(false);
  const defaultContactMethod = useDefaultContactMethod(recordID);
  const setContactDefault = useSetDefaultContactMethod();
  const getAddressBookContact = useAddressBookContact();
  const { transactionInfo: sendContext } = useTransactionContext();
  const { amount } = sendContext.senderWallet;

  const { displayContact, displayName, avatar, contactMethods, initials } = useMemo(
    () => getAddressBookContact(contact),
    [contact, getAddressBookContact],
  );

  useLayoutEffect(() => {
    const shouldWipeDefaultContact =
      !!defaultContactMethod && !isDefaultContactMethodActive(defaultContactMethod, contactMethods);

    if (!defaultContactMethod) {
      setContactDefault(recordID, contactMethods[0]);
    } else if (shouldWipeDefaultContact) {
      setContactDefault(recordID, undefined);
    }
  }, [contactMethods, defaultContactMethod, recordID, setContactDefault]);

  const eventProps = useMemo<SendDetailsProps>(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      chainName: wallet.network.asChain()?.displayName,
      currencyCode: wallet.currencyCode.rawValue,
      chainId: wallet.network.asChain()?.chainId,
      contractAddress: wallet.contractAddress,
    }),
    [
      wallet.blockchain.rawValue,
      wallet.contractAddress,
      wallet.currencyCode.rawValue,
      wallet.network,
    ],
  );

  const handleContactCellPress = useCallback(() => {
    logContactRecipientSuggestionClicked({
      ...eventProps,
      hasContactRecordID: !!defaultContactMethod,
    });
    if (defaultContactMethod) {
      onSelectSendViaLink({
        amount: amount.value.toString(),
        walletId: wallet.id,
        source: 'send',
        contactRecordID: recordID,
      });
      return;
    }
    toggleOn();
  }, [
    amount.value,
    defaultContactMethod,
    eventProps,
    recordID,
    toggleOn,
    wallet.id,
    onSelectSendViaLink,
  ]);

  const handleMorePress = useCallback(() => {
    logContactRecipientSuggestionClicked(eventProps);
    toggleOn();
  }, [eventProps, toggleOn]);

  const moreIcon = useMemo(() => {
    if (!hasSingleContactMethod(contactMethods) && defaultContactMethod) {
      return (
        <Box spacingEnd={0.5}>
          <IconButton
            name="more"
            variant="foregroundMuted"
            testID="contact-recipient-suggestion-more"
            transparent
            onPress={handleMorePress}
          />
        </Box>
      );
    }
  }, [defaultContactMethod, contactMethods, handleMorePress]);

  const displayAvatar = useMemo(() => {
    if (contact.hasThumbnail) {
      return <ProfileAvatar avatar={avatar} size="xl" isLocalContent />;
    }

    if (initials) {
      return <InitialsAvatar initials={initials} />;
    }

    return <ProfileAvatar />;
  }, [avatar, contact.hasThumbnail, initials]);

  const listCelInnerSpacing = useMemo(() => ({ spacingEnd: 1 } as CellSpacing), []);

  const description = useMemo(() => {
    if (defaultContactMethod && isWhatsApp(defaultContactMethod)) {
      return `${WHATSAPP.label} ${defaultContactMethod.number}`;
    }
    return defaultContactMethod ? getContactMethodInfo(defaultContactMethod) : displayContact;
  }, [defaultContactMethod, displayContact]);

  return (
    <Box>
      <ListCell
        title={displayName}
        description={description}
        media={displayAvatar}
        onPress={handleContactCellPress}
        action={moreIcon}
        testID="contact-recipient-suggestion"
        innerSpacing={listCelInnerSpacing}
        disabled={disabled}
      />
      {isTrayVisible && (
        <ContactRecipientTray
          contactMethods={contactMethods}
          recordID={recordID}
          onCloseComplete={toggleOff}
          onSelectSendViaLink={onSelectSendViaLink}
        />
      )}
    </Box>
  );
});

import { forwardRef, memo, useCallback } from 'react';
import { TextInput as RNTextInput } from 'react-native';
import { Controller, useFormContext } from 'react-hook-form';
import { IconName } from '@cbhq/cds-mobile';
import { InputIconButton } from '@cbhq/cds-mobile/controls/InputIconButton';
import { TextInput } from '@cbhq/cds-mobile/controls/TextInput';
import { TextLabel2 } from '@cbhq/cds-mobile/typography/TextLabel2';

type Props = {
  placeholder: string;
  updateValue: (text: string) => void;
  openQRCodeScanner: () => void;
  startIcon: IconName;
  name: string;
};

type Ref = RNTextInput | null;

export const RecipientInput = memo(
  forwardRef<Ref, Props>(
    ({ placeholder, updateValue, openQRCodeScanner, startIcon, name }, ref) => {
      const {
        control,
        setValue,
        formState: { errors },
      } = useFormContext();

      const handleUpdateValue = useCallback(
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        (field: any) => {
          return (val: string) => {
            field.onChange(val);
            updateValue(val);
          };
        },
        [updateValue],
      );

      const handleOpenQRCodeScanner = useCallback(() => {
        openQRCodeScanner?.();
      }, [openQRCodeScanner]);

      const handleClearInput = useCallback(
        function handleClearInput() {
          setValue(name, '');
          updateValue('');
        },
        [name, setValue, updateValue],
      );

      const renderField = useCallback(
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        ({ field }: any) => {
          return (
            <>
              <TextInput
                key="send-recipient-input"
                testID={`${name}-recipient-input`}
                ref={ref}
                placeholder={placeholder}
                value={field.value}
                onChangeText={handleUpdateValue(field)}
                autoCapitalize="none"
                autoCorrect={false}
                start={<InputIconButton name={startIcon} />}
                end={
                  <InputIconButton
                    testID="qr-code"
                    name={field.value ? 'close' : 'qrCode'}
                    onPress={field.value ? handleClearInput : handleOpenQRCodeScanner}
                  />
                }
                variant={errors?.[name] ? 'negative' : undefined}
                borderRadius="roundedFull"
              />
              <TextLabel2 color="negative" spacingTop={0.5} spacingStart={1}>
                {errors?.[name]?.message}
              </TextLabel2>
            </>
          );
        },
        [
          ref,
          placeholder,
          handleUpdateValue,
          startIcon,
          handleClearInput,
          handleOpenQRCodeScanner,
          errors,
          name,
        ],
      );

      return <Controller control={control} name={name} render={renderField} />;
    },
  ),
);

import { memo, useCallback, useMemo } from 'react';
import { useIntl } from 'react-intl';
import { logAssetsReceiveClicked } from 'cb-wallet-analytics/assets';
import { usePaymentsReceiveClicked } from 'cb-wallet-analytics/wallet';
import { useIsMiamiViceFeatureEnabled } from 'cb-wallet-data/hooks/useIsMiamiViceFeatureEnabled/useIsMiamiViceFeatureEnabled';
