import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { messages } from '../sendInputMessages';

type SendInputButtonsProps = {
  cryptoAmount: bigint;
  wallet: Wallet;
  isFromSendViaLinkBanner: boolean;
  isLoading: boolean;
  isContinueSendButtonDisabled: boolean;
  handlePushToSelectRecipient: () => Promise<void>;
  isExceedingMax?: boolean;
};

export const SendInputButtons = memo(function SendInputButtons({
  cryptoAmount,
  wallet,
  isFromSendViaLinkBanner,
  isLoading,
  isContinueSendButtonDisabled,
  handlePushToSelectRecipient,
  isExceedingMax,
}: SendInputButtonsProps) {
  const { formatMessage } = useIntl();
  const { push, navigate } = useStackNavigation();
  const isPaymentsMode = useIsPaymentsModeEnabled();

  const isPaymentsTabEnabled = useIsMiamiViceFeatureEnabled('wallet_redesign_payments_tab');

  const handleReceiveClickedAnalytics = usePaymentsReceiveClicked();

  const isWithinTransactTab = useIsWithinTab('TransactTab');
  const isWithinPaymentsSendTab = useIsWithinTab('PaymentsSendTab');

  const [startNavigateToReceiveTabsPerfMark] = usePerfMark(
    PERF_MARKS.receive,
    RECEIVE_MARKS.navigate_to_receive_tabs,
  );

  const handleContinuePress = useCallback(() => {
    if (isFromSendViaLinkBanner) {
      push('PreviewSendLink', {
        walletId: wallet.id,
        amount: cryptoAmount.toString(),
        source: 'send',
      });
      return;
    }
    handlePushToSelectRecipient();
  }, [cryptoAmount, handlePushToSelectRecipient, isFromSendViaLinkBanner, push, wallet.id]);

  const shouldShowSendReceiveButton = useMemo(
    () =>
      (isPaymentsMode || isPaymentsTabEnabled) && (isWithinTransactTab || isWithinPaymentsSendTab),
    [isPaymentsMode, isPaymentsTabEnabled, isWithinPaymentsSendTab, isWithinTransactTab],
  );

  const handleReceiveClick = useCallback(
    async function handleReceiveClick() {
      if (isPaymentsMode) {
        handleReceiveClickedAnalytics();
      } else {
        logAssetsReceiveClicked();
      }
      startNavigateToReceiveTabsPerfMark();
      navigate('Receive');
    },
    [handleReceiveClickedAnalytics, isPaymentsMode, navigate, startNavigateToReceiveTabsPerfMark],
  );

  return (
    <Box spacingHorizontal={2} spacingBottom={isPaymentsMode ? 3 : 0}>
      {shouldShowSendReceiveButton ? (
        <ButtonGroup block accessibilityLabel="send-receive-button-group">
          <Button
            testID="receive-continue-button"
            variant="secondary"
            onPress={handleReceiveClick}
            disabled={isLoading}
          >
            {formatMessage(messages.receiveButton)}
          </Button>
          <Button
            testID="send-continue-button"
            onPress={handlePushToSelectRecipient}
            disabled={isContinueSendButtonDisabled || isLoading}
            loading={isLoading}
          >
            {isExceedingMax ? formatMessage(messages.topUp) : formatMessage(messages.sendButton)}
          </Button>
        </ButtonGroup>
      ) : (
        <Button
          testID="send-continue-button"
          onPress={handleContinuePress}
          loading={isLoading}
          disabled={isContinueSendButtonDisabled || isLoading}
        >
          {formatMessage(messages.continueButton)}
        </Button>
      )}
    </Box>
  );
});

