type SendInputContentProps = {
  wallet: Wallet;
  prefilledTransaction?: PrefilledTransaction;
  initialAmount?: bigint;
} & Pick<SendParamList['SendInput'], 'entryPoint'>;

export const SendInputContent = memo(function SendInputContent({
  wallet,
  prefilledTransaction,
  entryPoint,
  initialAmount,
}: SendInputContentProps) {
  const { formatMessage } = useIntl();
  const [cryptoAmount, updateCryptoAmount] = useState(initialAmount ?? 0n);
  const [isAmountFilled, setIsAmountFilled] = useState(false);
  const [isLoading, setLoading] = useState(false);
  const [isPushedToSelectRecipient, setIsPushedToSelectRecipient] = useState(false);
  const [isImpactedByPendingUTXOs, setIsImpactedByPendingUTXOs] = useState<boolean | undefined>();
  const [balanceOverride, setBalanceOverride] = useState<bigint | undefined>();
  const [isLoadingBalance, setIsLoadingBalance] = useState<boolean>(true);
  const isPendingUTXOAwareBalancesEnabled = useIsPendingUTXOAwareBalancesEnabled();
  const {
    setTransactionInfo: setSendContext,
    transactionInfo: sendContext,
    isSponsoredTx,
  } = useTransactionContext();

  const isSupportedAmount = useIsTransferAmountSupported(wallet, cryptoAmount);

  const isFromSendViaLinkBanner = useMemo(
    () => entryPoint === 'sendViaLinkBanner' || entryPoint === 'textSendAssetDetailBalance',
    [entryPoint],
  );

  const { push, replace } = useStackNavigation();
  const toast = useRateLimitedToast({});

  const [notEnoughBalanceError, setNotEnoughBalanceError] = useState<
    GenerateTransactionsError | undefined
  >(undefined);

  const [amountGasFeeNeeded, setAmountGasFeeNeeded] = useState<bigint | undefined>(undefined);

  const sponsoredSendInfo = useGetSponsoredSendInfo(wallet);
  const activeAccount = useActiveAccount();
  const activeWalletGroup = useActiveWalletGroup();
  const activeFiatCurrency = useActiveFiatCurrency();

  const isSendOnrampTrayEnabled = useIsSendOnrampTrayEnabled();
  const isUTXOPendingTxTrayEnabled = useIsUTXOPendingTxTrayEnabled();
  const { openTopUpTray } = useTopUpTray({ source: 'send' });
  const { openUTXOPendingTxTray } = useUTXOPendingTxTray({ source: 'send' });
  // TODO: Asset Metadata V4, use enforced parameters
  const { asset } = useAsset({ assetSymbol: wallet.currencyCode.code, uuid: wallet.assetUUID });
  const isAssetTopUpEnabled = useIsTopUpForAllSupportedAssetsEnabled();

  const isPaymentsMode = useIsPaymentsModeEnabled();
  const isPaymentsTabEnabled = useIsMiamiViceFeatureEnabled('wallet_redesign_payments_tab');
  const isWithinTransactTab = useIsWithinTab('TransactTab');
  const isWithinPaymentsSendTab = useIsWithinTab('PaymentsSendTab');

  // Analytics
  const viewEvent = useSendEntryViewed({
    entryPoint,
    walletType: WalletType.standalone,
    accountType: activeAccount.type,
    walletIndex: activeWalletGroup?.walletIndex.toString(),
    currencyCode: wallet.currencyCode.value,
    contractAddress: wallet.contractAddress,
    chainName: wallet.network.asChain()?.displayName,
    chainId: wallet.network.asChain()?.chainId,
    isSponsoredTx: isSponsoredTx(),
  });
  const sendWalletSectorClicked = useSendWalletSectorClicked();

  const sendEntryBackClicked = useSendEntryBackClicked(wallet.blockchain.rawValue);
  const entryGetMaxValueButton = useEntryGetMaxValueButton(wallet.blockchain.rawValue);
  const entrySwitchDisplayButton = useEntrySwitchDisplayButton(wallet.blockchain.rawValue);

  const isTapToPayEnabled = useIsFeatureEnabled('wallet_tap_to_pay');

  useFocusEffect(
    useCallback(
      function sendInputViewed() {
        viewEvent({ prefilledTransactionSource: prefilledTransaction?.source });
      },
      [prefilledTransaction?.source, viewEvent],
    ),
  );

  // Performance monitoring
  usePerfMarkOnMount(PERF_MARKS.send, SEND_MARKS.navigate_to_send_input, stableEndTypeOption);
  useJourneyMarkOnMount('loaded_launch_send');

  const [startNavigateToSendSelectAssetPerfMark] = usePerfMark(
    PERF_MARKS.send,
    SEND_MARKS.navigate_to_send_select_asset,
  );

  const [trayVisible, { toggleOn: showTray, toggleOff: hideTray }] = useToggler(false);

  const activeWalletGroupId = useActiveWalletGroupId();
  // will display error immediately upon landing on screen, if user has zero units of base asset
  const zeroBaseAssetError = useBaseAssetZeroBalanceError(activeWalletGroupId, {
    network: wallet.network,
  });

  const handleValueChange = useCallback(
    function handleValueChange() {
      if (notEnoughBalanceError) {
        // unsetting error
        setNotEnoughBalanceError(undefined);
      }
      if (sendContext.unsignedTransaction) {
        setSendContext((prev: TransactionInfo) => ({
          ...prev,
          unsignedTransaction: undefined,
        }));
      }
    },
    [notEnoughBalanceError, sendContext.unsignedTransaction, setSendContext],
  );

  useEffect(
    function fetchBalance() {
      const fetchAvailableBalance = async () => {
        if (
          isUTXOBasedBlockchain(wallet?.blockchain?.rawValue) &&
          isPendingUTXOAwareBalancesEnabled
        ) {
          try {
            const dryRunResult = await generateDryRunTransactionForBalance(wallet);
            setIsImpactedByPendingUTXOs(dryRunResult.impactedByPendingUTXOs);
            if (dryRunResult.impactedByPendingUTXOs) {
              // if the user has pending transactions, show the user the balance they can actually send
              setBalanceOverride(dryRunResult.availableBalance);
            }
          } catch (e) {
            setIsImpactedByPendingUTXOs(false);
            setBalanceOverride(undefined);
          }
        } else {
          setIsImpactedByPendingUTXOs(false);
        }
        setIsLoadingBalance(false);
      };
      fetchAvailableBalance();
    },
    [wallet, isPendingUTXOAwareBalancesEnabled],
  );

  const {
    primaryAmount,
    secondaryAmount,
    estimatedFee,
    toggleIsFiat,
    onPressMaxButton,
    onChange,
    setAmount,
    isExceedingMax,
    allowChangeToFiat,
    availableBalance,
    cryptoBalance,
    isFiat,
    isLoadingMaxButton,
  } = useAmountInputValues({
    cryptoAmount,
    updateCryptoAmount,
    sourceWallet: wallet,
    requireExchangeRate: false,
    onCryptoAmountChange: handleValueChange,
    txType: GasEstimateTxType.SEND,
    balanceOverride,
    isLoadingBalance,
    defaultDisplayMode: isPaymentsMode ? DisplayMode.crypto : DisplayMode.fiat,
  });

  const feeValueForBaseAssetTopUp = useMemo(() => {
    if (sponsoredSendInfo) {
      return 0n;
    }
    return wallet.isBaseAsset && estimatedFee ? estimatedFee : 0n;
  }, [estimatedFee, sponsoredSendInfo, wallet.isBaseAsset]);

  const { minCryptoAmount, minFiatAmount, maxCryptoAmount, maxFiatAmount } =
    useGetSendLinkTransferLimitCopies(wallet);

  const minAmountCopy = useMemo(() => {
    if (isFiat && minFiatAmount) {
      return minFiatAmount;
    }

    return minCryptoAmount;
  }, [isFiat, minCryptoAmount, minFiatAmount]);

  const maxAmountCopy = useMemo(() => {
    if (isFiat && maxFiatAmount) {
      return maxFiatAmount;
    }

    return maxCryptoAmount;
  }, [isFiat, maxCryptoAmount, maxFiatAmount]);

  const shouldShowSendLinkTransferLimitsError =
    isFromSendViaLinkBanner && !isExceedingMax && !isSupportedAmount && !!cryptoAmount;

  const secondaryText = useMemo(
    () =>
      shouldShowSendLinkTransferLimitsError
        ? formatMessage(messages.unsupportedAmountSendViaLink, {
            minAmount: minAmountCopy,
            maxAmount: maxAmountCopy,
          })
        : secondaryAmount,
    [
      formatMessage,
      maxAmountCopy,
      minAmountCopy,
      secondaryAmount,
      shouldShowSendLinkTransferLimitsError,
    ],
  );

  const handleKeyboardChange = useCallback(
    (numpadKey: NumPadValue) => {
      setSendContext({
        ...sendContext,
        senderWallet: {
          walletId: wallet.id,
          amount: {
            kind: TransactionKind.AMOUNT,
            value: cryptoAmount,
          },
        },
      });

      onChange(numpadKey);
    },
    [cryptoAmount, onChange, sendContext, setSendContext, wallet.id],
  );

  const isContinueSendButtonDisabled = useMemo(() => {
    if (cryptoAmount === 0n) return true;

    if (isFromSendViaLinkBanner) {
      return !isSupportedAmount || isExceedingMax;
    }

    return isExceedingMax && (!asset?.listed || !isAssetTopUpEnabled);
  }, [
    asset?.listed,
    cryptoAmount,
    isAssetTopUpEnabled,
    isExceedingMax,
    isFromSendViaLinkBanner,
    isSupportedAmount,
  ]);

  const handlePrimaryAmountLongPress = useCallback(async () => {
    const value = await Clipboard.getStringAsync();

    if (!Number(value)) {
      toast.show(formatMessage(messages.inValidAmountPaste), { variant: 'negative' });
      return;
    }

    setAmount(value);
  }, [formatMessage, setAmount, toast]);

  const handleOnPressMaxButton = useCallback(
    function handleOnPressMaxButton() {
      entryGetMaxValueButton({
        isBaseAsset: wallet.isBaseAsset,
        is1559NetworkEnabled: isNetwork1559Enabled(wallet.network),
      });
      onPressMaxButton();

      // we need to explicitly set kind: 'EntireBalance' if the MAX button is pressed so that
      // subsequent steps can calculate the transfer amount correctly based on changing network fees
      const amount: TransactionAmount = {
        kind: TransactionKind.ENTIRE_BALANCE,
        value: cryptoAmount,
      };

      setSendContext((prev: TransactionInfo) => ({
        ...prev,
        senderWallet: {
          walletId: wallet.id,
          amount,
        },
      }));
    },
    [
      entryGetMaxValueButton,
      wallet.isBaseAsset,
      wallet.network,
      wallet.id,
      onPressMaxButton,
      cryptoAmount,
      setSendContext,
    ],
  );

  const handleToggleIsFiat = useCallback(
    function handleToggleIsFiat() {
      entrySwitchDisplayButton();
      toggleIsFiat();
    },
    [entrySwitchDisplayButton, toggleIsFiat],
  );

  const feeWallet = useGetFeeWallet(activeWalletGroupId, wallet.network);

  const handlePushToSelectRecipient = useHandlePushToSelectRecipient({
    wallet,
    feeWallet,
    isExceedingMax,
    isImpactedByPendingUTXOs,
    cryptoAmount,
    cryptoBalance,
    feeValueForBaseAssetTopUp,
    setLoading,
    setAmountGasFeeNeeded,
    setNotEnoughBalanceError,
  });

  const handlePushToAssetSelector = useCallback(
    function handlePushToAssetSelector() {
      startNavigateToSendSelectAssetPerfMark();
      sendWalletSectorClicked();

      push('SendSelectAsset', {
        filterByChain: prefilledTransaction?.data?.chain,
        visibleWallets: [],
        prefilledTransaction,
        isOpenedFromSendInput: true,
      });
    },
    [prefilledTransaction, push, sendWalletSectorClicked, startNavigateToSendSelectAssetPerfMark],
  );

  const backButton = useBackButtonWithActionAndGoBack({
    action: () => {
      sendEntryBackClicked();

      // if coming from unknow place (via a replace) then go back to the navigator
      if (entryPoint === undefined) {
        const tabNavigator = isPaymentsMode ? 'PaymentsTabNavigator' : 'TabNavigator';
        replace(tabNavigator, { screen: 'PaymentsSendTab' });
      }
    },
  });

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleLongPress = useCallback((numPadKey: any) => {
    // clear input
    if (numPadKey === 'BACKSPACE') {
      updateCryptoAmount(0n);
    }
  }, []);

  const handleNfcPress = useStartNfcReadMode();

  const sendViaLinkNavOption = useMemo(() => {
    return isWithinPaymentsSendTab ? (
      <HStack gap={2} alignItems="center" spacingHorizontal={1}>
        {isTapToPayEnabled && (
          <AutoHitSlopWrapper>
            <PressableOpacity
              onPress={handleNfcPress}
              testID="nfc-action-btn-scan"
              accessibilityLabel={formatMessage(messages.nfcActionLabel)}
            >
              <NavigationIcon size="m" name="pay" />
            </PressableOpacity>
          </AutoHitSlopWrapper>
        )}
        <ScanGlobalAction type="navBarButton" />
      </HStack>
    ) : (
      <SendViaLinkNavOption
        wallet={wallet}
        amount={cryptoAmount}
        isFromSendViaLinkBanner={isFromSendViaLinkBanner}
      />
    );
  }, [
    cryptoAmount,
    formatMessage,
    handleNfcPress,
    isFromSendViaLinkBanner,
    isTapToPayEnabled,
    isWithinPaymentsSendTab,
    wallet,
  ]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      title:
        isWithinTransactTab || isWithinPaymentsSendTab
          ? undefined
          : formatMessage(messages.screenTitle),
      left: isWithinTransactTab || isWithinPaymentsSendTab ? undefined : backButton,
      right: sendViaLinkNavOption,
    }),
    [backButton, formatMessage, isWithinPaymentsSendTab, isWithinTransactTab, sendViaLinkNavOption],
  );

  useEffect(
    function setPrefilledTransaction() {
      if (prefilledTransaction) {
        setSendContext((prev: TransactionInfo) => ({
          ...prev,
          prefilledTransaction,
        }));
      }
    },
    [prefilledTransaction, setSendContext],
  );

  useEffect(
    function fillAmountAndProceed() {
      if (
        prefilledTransaction?.type !== PrefilledTransactionType.CRYPTO ||
        !prefilledTransaction.data
      ) {
        return;
      }

      const amountFromParam =
        prefilledTransaction.data.params.value ||
        getDownScaledDecimal(
          prefilledTransaction.data.params.uint256 || 0,
          BigInt(wallet.decimals),
        ).toString();

      // Number() might lose precision but as we are using this method for negative exponent and
      // js supports 15 decimals, so its already very small.
      const amount = amountFromParam.includes('e')
        ? scientificToDecimal(Number(amountFromParam))
        : amountFromParam;

      if (Number(amount) && !isAmountFilled) {
        if (isFiat) {
          toggleIsFiat();
        } else {
          setAmount(amount);
          setIsAmountFilled(true);
        }
      }
      if (!isContinueSendButtonDisabled) {
        if (
          isAmountFilled &&
          !isPushedToSelectRecipient &&
          !isUTXOBasedBlockchain(wallet.blockchain.rawValue)
        ) {
          handlePushToSelectRecipient();
        }
        setIsPushedToSelectRecipient(true);
      }
    },
    [
      handlePushToSelectRecipient,
      prefilledTransaction,
      isAmountFilled,
      isContinueSendButtonDisabled,
      isFiat,
      isPushedToSelectRecipient,
      onChange,
      setAmount,
      toggleIsFiat,
      wallet.decimals,
      wallet.blockchain.rawValue,
    ],
  );

  const generateTransactionError = useMemo(() => {
    if (!sponsoredSendInfo && zeroBaseAssetError && !isWithinTransactTab && !isPaymentsMode) {
      return zeroBaseAssetError;
    }

    return notEnoughBalanceError;
  }, [
    isPaymentsMode,
    isWithinTransactTab,
    notEnoughBalanceError,
    sponsoredSendInfo,
    zeroBaseAssetError,
  ]);

  const showGlobalTray = useCallback(() => {
    if (
      isUTXOBasedBlockchain(wallet.blockchain.rawValue) &&
      isUTXOPendingTxTrayEnabled &&
      isImpactedByPendingUTXOs
    ) {
      openUTXOPendingTxTray(wallet);
      return null;
    }

    const networkChain = wallet.network.asChain();

    if (
      !generateTransactionError ||
      !networkChain?.baseAssetCurrencyCode ||
      !networkChain?.displayName
    ) {
      return null;
    }

    if (isSendOnrampTrayEnabled && feeWallet && notEnoughBalanceError) {
      openTopUpTray({ wallet: feeWallet, amountNeeded: amountGasFeeNeeded });

      return null;
    }
    showTray();
  }, [
    amountGasFeeNeeded,
    feeWallet,
    generateTransactionError,
    isImpactedByPendingUTXOs,
    isSendOnrampTrayEnabled,
    isUTXOPendingTxTrayEnabled,
    notEnoughBalanceError,
    openTopUpTray,
    openUTXOPendingTxTray,
    showTray,
    wallet,
  ]);

  const tray = useMemo(() => {
    const networkChain = wallet.network.asChain();

    if (
      !generateTransactionError ||
      !networkChain?.baseAssetCurrencyCode ||
      !networkChain?.displayName
    ) {
      return null;
    }

    if (isSendOnrampTrayEnabled && feeWallet && notEnoughBalanceError) {
      openTopUpTray({ wallet: feeWallet, amountNeeded: amountGasFeeNeeded });

      return null;
    }

    return (
      <Tray onCloseComplete={hideTray} testID="generate-send-transaction-error-tooltip-tray">
        <Box spacingHorizontal={3}>
          <GenerateTransactionErrorTooltipTray
            zeroBaseAssetError={zeroBaseAssetError}
            network={wallet.network}
          />
        </Box>
      </Tray>
    );
  }, [
    amountGasFeeNeeded,
    feeWallet,
    generateTransactionError,
    hideTray,
    isSendOnrampTrayEnabled,
    notEnoughBalanceError,
    openTopUpTray,
    wallet.network,
    zeroBaseAssetError,
  ]);

  const sendButtons = useMemo(() => {
    return (
      <SendInputButtons
        cryptoAmount={cryptoAmount}
        wallet={wallet}
        isContinueSendButtonDisabled={isContinueSendButtonDisabled}
        isFromSendViaLinkBanner={isFromSendViaLinkBanner}
        isLoading={isLoading}
        handlePushToSelectRecipient={handlePushToSelectRecipient}
        isExceedingMax={isExceedingMax}
      />
    );
  }, [
    cryptoAmount,
    handlePushToSelectRecipient,
    isContinueSendButtonDisabled,
    isExceedingMax,
    isFromSendViaLinkBanner,
    isLoading,
    wallet,
  ]);

  const sideIconBackground = useMemo(() => {
    if (isPaymentsMode || isPaymentsTabEnabled) {
      return 'secondary';
    }
  }, [isPaymentsMode, isPaymentsTabEnabled]);

  return (
    <Screen navBar={navBar} full>
      <Spacer />
      <Box spacingHorizontal={2}>
        <AmountInput
          wallet={wallet}
          primaryAmount={primaryAmount}
          secondaryAmount={secondaryText}
          toggleIsFiat={handleToggleIsFiat}
          onPressMaxButton={handleOnPressMaxButton}
          allowChangeToFiat={allowChangeToFiat}
          tertiaryAmount={isImpactedByPendingUTXOs === undefined ? '' : availableBalance}
          txType={GasEstimateTxType.SEND}
          isLoadingMaxButton={isLoadingMaxButton}
          onPrimaryAmountLongPress={handlePrimaryAmountLongPress}
          isTertiaryErrorState={isImpactedByPendingUTXOs}
          onPressTertiaryInErrorState={isImpactedByPendingUTXOs ? showGlobalTray : noop}
          sideIconBackground={sideIconBackground}
          type={isPaymentsMode ? AmountInputType.PAYMENTS_SEND : undefined}
          activeFiatCurrency={activeFiatCurrency}
          isFiat={isFiat}
        />
      </Box>
      {!isPaymentsMode && (
        <>
          <Spacer />
          <SendCurrencySelector
            wallet={wallet}
            onPress={handlePushToAssetSelector}
            isPressable={!isFromSendViaLinkBanner}
          />
        </>
      )}

      {generateTransactionError?.message ? (
        <Box justifyContent="center" alignItems="center" spacingTop={3} spacingBottom={3}>
          <TextLabel2
            color="negative"
            align="center"
            spacingHorizontal={2}
            onPress={generateTransactionError ? showGlobalTray : noop}
          >
            {generateTransactionError?.message}
            {generateTransactionError ? (
              <Icon spacingStart={3} name="info" size="xs" color="negative" />
            ) : null}
          </TextLabel2>
        </Box>
      ) : (
        <Spacer />
      )}

      {trayVisible && tray}

      {isPaymentsMode && sendButtons}

      <Box>
        <NumPad
          allowDecimalSeparator
          onPress={handleKeyboardChange}
          onLongPress={handleLongPress}
        />
      </Box>
      {!isPaymentsMode && (
        <>
          <Spacer />
          {sendButtons}
        </>
      )}
    </Screen>
  );
});

