export type SendViaLinkSuggestionsEmptyStateProps = {
  isEmptyResult?: boolean;
  isLoading?: boolean;
  onSelectSendViaLink: (contact: OnSelectSendViaLinkProps) => void;
} & MyAddressesSuggestionsTabProps;

export const SendViaLinkSuggestionsEmptyState = memo(function SendViaLinkSuggestionsEmptyState({
  wallet,
  onSelectRecipient,
  onSelectSendViaLink,
  suggestedRetailAddresses,
  isLoadingRetailAccount,
  isEmptyResult = false,
  isLoading,
}: SendViaLinkSuggestionsEmptyStateProps) {
  const { formatMessage } = useIntl();
  const { transactionInfo: sendContext } = useTransactionContext();
  const { amount } = sendContext.senderWallet;
  const { syncContacts } = useSyncContacts();
  const toast = useRateLimitedToast({});

  const eventProps = useMemo(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      chainName: wallet.network.asChain()?.displayName,
      currencyCode: wallet.currencyCode.rawValue,
      chainId: wallet.network.asChain()?.chainId,
      contractAddress: wallet.contractAddress,
    }),
    [
      wallet.blockchain.rawValue,
      wallet.contractAddress,
      wallet.currencyCode.rawValue,
      wallet.network,
    ],
  );

  const handleSendViaLinkPress = useCallback(() => {
    logSendViaLinkBannerPressed(eventProps);
    onSelectSendViaLink({
      amount: amount.value.toString(),
      walletId: wallet.id,
      source: 'send',
    });
  }, [amount.value, eventProps, onSelectSendViaLink, wallet.id]);

  const onSyncSuccess = useCallback(() => {
    toast.show(formatMessage(messages.contactsImportedToast));
  }, [formatMessage, toast]);

  const handleSendToContactsPress = useCallback(async () => {
    logSendSelectRecipientSyncContactsClicked(eventProps);
    await syncContacts({ onSuccess: onSyncSuccess });
  }, [eventProps, onSyncSuccess, syncContacts]);

  if (isEmptyResult) {
    return (
      <Box spacing={2} testID="svl-suggestions-empty-results">
        <TextTitle3>{formatMessage(messages.noResults)}</TextTitle3>
        <TextBody color="foregroundMuted" spacingBottom={2}>
          {formatMessage(messages.noResultsDescription)}
        </TextBody>
        <SectionHeader />
        <EmptyStateCard onPress={handleSendToContactsPress} />
      </Box>
    );
  }

  return (
    <Box testID="send-via-link-suggestions-empty-state">
      <Box spacing={2}>
        <SectionHeader />
        <EmptyStateCard onPress={handleSendToContactsPress} />
      </Box>
      <ListCell
        media={
          <Box width={32} height={32} justifyContent="center" alignItems="center">
            <Icon name="telephone" size="m" color="foreground" />
          </Box>
        }
        title={formatMessage(messages.svlCardTitle)}
        description={formatMessage(messages.svlCardDescription)}
        onPress={handleSendViaLinkPress}
        testID="empty-state-svl-card"
        disabled={isLoading}
      />
      <Box spacingHorizontal={3}>
        <MyWalletsBanner
          wallet={wallet}
          onSelectRecipient={onSelectRecipient}
          isLoadingRetailAccount={isLoadingRetailAccount}
          suggestedRetailAddresses={suggestedRetailAddresses}
          isLoading={isLoading}
        />
      </Box>
    </Box>
  );
});

