});

type GaslessSendUpsellProps = {
  isVisibleOnMount: boolean;
  wallet?: Wallet;
  source?: string;
  onPressEnabled?: boolean;
};

export const GASLESS_SEND_NFC_CONTENT_ID = '7vHvVPcPJfC5skrGiabzTn';

export function GaslessSendUpsell({
  isVisibleOnMount,
  wallet,
  source,
  onPressEnabled,
}: GaslessSendUpsellProps) {
  const [isVisible, setVisible] = useState(isVisibleOnMount);
  const isEligible = useIsGaslessUpsellEligible(wallet);
  const { navigate } = useStackNavigation();

  const { formatMessage } = useIntl();

  const warning = useMemo(
    () => ({
      title: formatMessage(messages.title),
      description: formatMessage(messages.description),
    }),
    [formatMessage],
  );

  useOnMount(() => {
    if (isVisibleOnMount) {
      logEvent('gasless_send_upsell.shown', {
        source,
        action: ActionType.view,
        componentType: ComponentType.banner,
      });
    }
  });

  const baseNetworkIcon = useMemo(() => {
    const network = Network.fromChainId({ chainId: BigInt(8453) });

    return (
      <Box spacingEnd={1} spacingBottom={0.5}>
        <NetworkIcon network={network} size={20} />
      </Box>
    );
  }, []);

  const onDismiss = useCallback(() => {
    setVisible(false);
    logEvent('gasless_send_upsell.dismissed', {
      source,
      action: ActionType.dismiss,
      componentType: ComponentType.banner,
    });
  }, [source]);

  const onPress = useCallback(() => {
    logEvent('gasless_send_upsell.pressed', {
      source,
      action: ActionType.dismiss,
      componentType: ComponentType.banner,
    });
    navigate('NFCContent', { entryId: GASLESS_SEND_NFC_CONTENT_ID });
  }, [navigate, source]);

  const WrapperComponent = useMemo(() => (onPressEnabled ? Pressable : Box), [onPressEnabled]);

  return isVisible && isEligible ? (
    <WrapperComponent background="transparent" onPress={onPress} width="100%">
      <Box flexDirection="row" spacing={2} testID="warning-tile">
        <Box width="100%">
          <VStack flexShrink={1}>
            <HStack alignItems="center" justifyContent="space-between">
              <Box flexDirection="row" alignItems="center">
                {baseNetworkIcon}
                <Box spacingStart={0.5}>
                  <TextHeadline spacingBottom={0.5} spacingStart={1}>
                    {warning.title}
                  </TextHeadline>
                </Box>
              </Box>
              <Box>
                <Pressable onPress={onDismiss} background="transparent" testID="dismiss-button">
                  <Icon size="s" name="close" color="foregroundMuted" />
                </Pressable>
              </Box>
            </HStack>
            <Box width="90%">
              <TextBody color="foregroundMuted" spacingStart={5}>
                {warning.description}
              </TextBody>
            </Box>
          </VStack>
        </Box>
      </Box>
    </WrapperComponent>
  ) : null;
}

