const messages = defineMessages({
  screenTitle: {
    defaultMessage: 'Select send amount',
    description: 'Screen title displayed in the header',
  },
  screenHeading: {
    defaultMessage: 'Select amount to send',
    description: 'Heading displayed in the screen content',
  },
  screenSubHeading: {
    defaultMessage: 'You have multiple copies of this asset. How many would you like to send?',
    description: 'Sub-heading displayed in the screen content',
  },
  amountInputLabel: {
    defaultMessage: 'Send amount',
    description: 'Label of the input component for inputting send amount',
  },
  amountInputHelperText: {
    defaultMessage: 'You can send up to {amount}',
    description: 'Helper text of the input component for inputting send amount',
  },
  primaryButton: {
    defaultMessage: 'Continue',
    description: 'Text for primary button in the screen to proceed',
  },
});

const AMOUNT_FIELD_NAME = 'amount';

type AmountInputProps = { maxAmount: string };

const AmountInput = memo(function AmountInput({ maxAmount }: AmountInputProps) {
  const { formatMessage } = useIntl();
  const {
    control,
    formState: { errors },
  } = useFormContext();

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleUpdateValue = useCallback((field: any) => {
    return (val: string) => {
      field.onChange(val);
    };
  }, []);

  const renderAmountField = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ({ field }: any) => {
      return (
        <>
          <TextInput
            testID="amount-input"
            label={formatMessage(messages.amountInputLabel)}
            value={field.value}
            keyboardType="number-pad"
            onChangeText={handleUpdateValue(field)}
            autoCapitalize="none"
            autoCorrect={false}
            variant={errors?.[AMOUNT_FIELD_NAME] ? 'negative' : undefined}
          />
          <TextLabel2 color="foregroundMuted" spacingTop={0.5} spacingStart={1}>
            {formatMessage(messages.amountInputHelperText, {
              amount: maxAmount,
            })}
          </TextLabel2>
        </>
      );
    },
    [handleUpdateValue, errors, formatMessage, maxAmount],
  );

  const fieldRules = useMemo(() => {
    return {
      validate: (fieldValueStr: string) => {
        if (!fieldValueStr.match(/^[1-9]\d*$/)) {
          return false;
        }
        const fieldValue = BigInt(fieldValueStr);
        return fieldValue >= 1n && fieldValue <= BigInt(maxAmount);
      },
    };
  }, [maxAmount]);

  return (
    <Controller
      control={control}
      name={AMOUNT_FIELD_NAME}
      render={renderAmountField}
      rules={fieldRules}
    />
  );
});

const SendCollectibleAmountInput = memo(function SendCollectibleAmountInput() {
  const { navigate } = useStackNavigation();
  const { setTransactionInfo: setSendContext } = useTransactionContext();
  const methods = useForm({
    mode: 'onChange',
    defaultValues: {
      [AMOUNT_FIELD_NAME]: '1',
    },
  });
  const amount = methods.getValues(AMOUNT_FIELD_NAME);
  const { formatMessage } = useIntl();
  const { collectible, collectionWalletId } = useParams<
    SendParamList,
    'SendCollectibleAmountInput'
  >();

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: 'back',
      title: formatMessage(messages.screenTitle),
    }),
    [formatMessage],
  );

  const handleSubmit = useCallback(
    function handleSubmit() {
      setSendContext((prev: TransactionInfo) => ({
        ...prev,
        collectibleAmount: BigInt(amount),
      }));
      navigate('Send', {
        screen: 'SelectRecipient',
        params: {
          collectible,
          collectionWalletId,
        },
      });
    },
    [amount, collectible, collectionWalletId, navigate, setSendContext],
  );

  return (
    <Screen full navBar={navBar}>
      <FormProvider {...methods}>
        <Box flexGrow={1} spacing={2} spacingBottom={0}>
          <KeyboardAwareScrollView keyboardDismissMode="interactive" extraScrollHeight={0}>
            <TextTitle3>{formatMessage(messages.screenHeading)}</TextTitle3>
            <TextBody color="foregroundMuted" spacingTop={1} spacingBottom={3}>
              {formatMessage(messages.screenSubHeading)}
            </TextBody>
            <AmountInput maxAmount={collectible.tokenCount} />
          </KeyboardAwareScrollView>
        </Box>
        <Box spacingHorizontal={2} spacingBottom={2}>
          <Button disabled={!!methods.formState.errors?.[AMOUNT_FIELD_NAME]} onPress={handleSubmit}>
            {formatMessage(messages.primaryButton)}
          </Button>
        </Box>
      </FormProvider>
    </Screen>
  );
});

