type PreviewSendLinkContentProps = {
  wallet: Wallet;
  amount: string;
  contactRecordID?: string;
  phoneNumber?: string;
  emailAddress?: string;
};

type TransactionClaimLink = {
  previewApproveTx?: UnsignedTx;
  previewSendInfoTx?: UnsignedTx;
  previewContractFeeTx?: UnsignedTx;
  claimLink?: ClaimLinkInstanceInterface;
  transactionGenerationError?: Error;
  notEnoughBalanceError?: SendViaLinkNotEnoughBalanceError;
};

const PreviewSendLinkContent = memo(function PreviewSendLinkContent({
  wallet,
  amount,
  contactRecordID = '',
  phoneNumber,
  emailAddress,
}: PreviewSendLinkContentProps) {
  const { source } = useParams<SendParamList, 'PreviewSendLink'>();

  const { formatMessage } = useIntl();
  const { navigate, goBack, reset } = useStackNavigation<SendParamList>();
  const [buttonGroupHeight, setButtonGroupHeight] = useState<number | undefined>();
  const { show } = useRateLimitedToast({});
  const handleUnlock = useHandleUnlock();
  const claimLinksVersion = useClaimLinksVersion();
  const { contactsResponse } = useContactsContext();
  const amountBigInt = useMemo(() => BigInt(amount), [amount]);
  const defaultContactMethod = useDefaultContactMethod(contactRecordID);
  const getAddressBookContact = useAddressBookContact();
  const { openTopUpTray } = useTopUpTray({ source: 'send_via_link' });
  const isTopUpForAllSupportedAssetsEnabled = useIsTopUpForAllSupportedAssetsEnabled();
  const { asset } = useAsset({ assetSymbol: wallet.currencyCode.code, uuid: wallet.assetUUID });

  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useGetFeeWallet(activeWalletGroupId, wallet.network);
  const { asset: feeAsset } = useAsset({
    assetSymbol: feeWallet?.currencyCode.code || '',
    uuid: feeWallet?.assetUUID,
  });

  const [
    {
      previewApproveTx,
      previewSendInfoTx,
      previewContractFeeTx,
      claimLink,
      transactionGenerationError,
      notEnoughBalanceError,
    },
    setTransactionClaimLink,
  ] = useState<TransactionClaimLink>({
    previewApproveTx: undefined,
    previewSendInfoTx: undefined,
    claimLink: undefined,
    transactionGenerationError: undefined,
    notEnoughBalanceError: undefined,
  });

  const contact = useMemo(
    () =>
      contactRecordID && contactsResponse?.contacts?.find((c) => c.recordID === contactRecordID),
    [contactRecordID, contactsResponse?.contacts],
  );

  const transferAmount = useMemo(
    () => ({
      value: amountBigInt,
      kind:
        amountBigInt === wallet.balance ? TransactionKind.ENTIRE_BALANCE : TransactionKind.AMOUNT,
    }),
    [amountBigInt, wallet.balance],
  );

  const generateUnsignedClaimLinkTx = useGenerateUnsignedClaimLinkTx({ wallet, transferAmount });

  const handleOpenTopUpTray = useCallback(() => {
    const isTopUpWalletAssetListed =
      (notEnoughBalanceError?.code === 'notEnoughBalanceForSendViaLinkMinerFee' &&
        feeAsset?.listed) ||
      (notEnoughBalanceError?.code === 'notEnoughBalanceForSendViaLinkAmount' && asset?.listed);

    if (
      !isTopUpForAllSupportedAssetsEnabled ||
      !notEnoughBalanceError ||
      !isTopUpWalletAssetListed
    ) {
      return;
    }

    openTopUpTray({
      wallet: notEnoughBalanceError.wallet,
      amountNeeded: notEnoughBalanceError.amountGasFeeNeeded,
    });
  }, [isTopUpForAllSupportedAssetsEnabled, notEnoughBalanceError, openTopUpTray, asset, feeAsset]);

  useOnMount(function generateClaimLinkTxOnMount() {
    async function generateAndSetClaimLinkTxData() {
      const {
        previewApproveTx: previewApproveTxForClaimLink,
        previewSendInfoTx: previewSendInfoTxForClaimLink,
        previewContractFeeTx: previewContractFeeTxForClaimLink,
        claimLink: link,
        transactionGenerationError: txGenerationError,
        notEnoughBalanceError: balanceError,
      } = await generateUnsignedClaimLinkTx();

      setTransactionClaimLink({
        previewApproveTx: previewApproveTxForClaimLink,
        previewSendInfoTx: previewSendInfoTxForClaimLink,
        previewContractFeeTx: previewContractFeeTxForClaimLink,
        claimLink: link,
        transactionGenerationError: txGenerationError,
        notEnoughBalanceError: balanceError,
      });

      const isTopUpWalletAssetListed =
        (balanceError?.code === 'notEnoughBalanceForSendViaLinkMinerFee' && feeAsset?.listed) ||
        (balanceError?.code === 'notEnoughBalanceForSendViaLinkAmount' && asset?.listed);

      if (isTopUpForAllSupportedAssetsEnabled && balanceError && isTopUpWalletAssetListed) {
        openTopUpTray({
          wallet: balanceError.wallet,
          amountNeeded: balanceError.amountGasFeeNeeded,
        });
      }

      if (txGenerationError) {
        logPreviewSendLinkGeneratePreviewFailed({
          ...eventProps,
          errorMessage: txGenerationError.message,
        });
      } else if (previewSendInfoTxForClaimLink) {
        logPreviewSendLinkGeneratePreviewSucceeded(eventProps);
      }
    }

    generateAndSetClaimLinkTxData();
  });

  const addressBookContact = useMemo(() => {
    if (!contact) {
      return;
    }
    return getAddressBookContact(contact);
  }, [contact, getAddressBookContact]);

  const contactMethodWithFallback = useMemo(() => {
    if (!contactRecordID) return;
    if (defaultContactMethod) return defaultContactMethod;

    const firstContactMethod = addressBookContact?.contactMethods[0];
    if (!firstContactMethod) {
      throw new Error('No contact method found');
    }
    return firstContactMethod;
  }, [addressBookContact?.contactMethods, contactRecordID, defaultContactMethod]);

  const contactMethodType = useMemo(() => {
    if (!contactMethodWithFallback) return;

    if (isWhatsApp(contactMethodWithFallback)) return contactMethodWithFallback.type;

    return isPhoneNumberContactMethod(contactMethodWithFallback) ? 'sms' : 'email';
  }, [contactMethodWithFallback]);

  const {
    submitClaimLink,
    depositResult,
    isLoading,
    error: claimLinkError,
  } = useSubmitClaimLink({
    wallet,
    amount,
    from: wallet.primaryAddress,
    claimLink,
    handleUnlock,
    contactRecordID,
  });

  const getShareMessage = useGetShareMessage({ wallet, amount: amountBigInt });
  const getUrlEncodedClaimLink = useGetUrlEncodedClaimLink();
  const sendContactLink = useContactSend();
  const isPaymentsModeEnabled = useIsPaymentsModeEnabled();

  const isDeeplinkInPaymentsMode = useMemo(
    () => isPaymentsModeEnabled && source === 'prefilledSvl',
    [isPaymentsModeEnabled, source],
  );

  const navBarBack = useMemo(
    () => (isDeeplinkInPaymentsMode ? undefined : 'back'),
    [isDeeplinkInPaymentsMode],
  );

  const navBarTitle = useMemo(
    () => (isDeeplinkInPaymentsMode ? undefined : formatMessage(messages.screenTitle)),
    [formatMessage, isDeeplinkInPaymentsMode],
  );

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: navBarBack,
      title: navBarTitle,
    }),
    [navBarBack, navBarTitle],
  );

  const { directContactMethod, directContactMethodType } = useMemo(() => {
    let type: ContactMethodType | undefined;

    if (phoneNumber) {
      type = 'sms';
    } else if (emailAddress) {
      type = 'email';
    }

    return {
      directContactMethod: phoneNumber || emailAddress,
      directContactMethodType: type,
    };
  }, [emailAddress, phoneNumber]);

  const eventProps = useMemo(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      chainName: wallet.network.asChain()?.displayName,
      currencyCode: wallet.currencyCode.rawValue,
      chainId: wallet.network.asChain()?.chainId,
      contractAddress: wallet.contractAddress,
      version: claimLinksVersion,
      hasContactRecordID: !!contactRecordID,
      context: contactRecordID ? contactMethodType : directContactMethodType,
    }),
    [
      claimLinksVersion,
      contactMethodType,
      contactRecordID,
      directContactMethodType,
      wallet.blockchain.rawValue,
      wallet.contractAddress,
      wallet.currencyCode.rawValue,
      wallet.network,
    ],
  );

  useOnMount(() => {
    logSendSyncContactsStatus({ context: 'success' });
    logPreviewSendLinkViewed(eventProps);
  });

  const handleCancel = useCallback(() => {
    logPreviewSendLinkCancelled(eventProps);
    if (isDeeplinkInPaymentsMode) {
      reset({
        index: 0,
        routes: [{ name: 'SendInput' }],
      });
    } else {
      goBack();
    }
  }, [eventProps, goBack, isDeeplinkInPaymentsMode, reset]);

  const handleSendLink = useCallback(
    async function handleSendLink(claimUrl: string) {
      const formattedClaimLink = getUrlEncodedClaimLink(claimUrl);
      const { body, subject } = getShareMessage(formattedClaimLink);
      if (contactMethodWithFallback && contactMethodType) {
        logPreviewSendLinkContactSend(eventProps);
        sendContactLink({
          subject,
          body,
          contactMethod: getContactMethodInfo(contactMethodWithFallback),
          type: contactMethodType,
        });
        return;
      }

      if (directContactMethod) {
        logPreviewSendLinkContactSend(eventProps);
        sendContactLink({
          subject,
          body,
          contactMethod: directContactMethod,
          type: phoneNumber ? 'sms' : 'email',
        });
      }
    },
    [
      contactMethodType,
      contactMethodWithFallback,
      directContactMethod,
      eventProps,
      getUrlEncodedClaimLink,
      getShareMessage,
      phoneNumber,
      sendContactLink,
    ],
  );

  useEffect(
    function navigateAfterDeposit() {
      if (!isLoading && depositResult) {
        logPreviewSendLinkCreated({ ...eventProps, txHash: depositResult.txHash });
        if (addressBookContact || directContactMethod) {
          handleSendLink(depositResult.claimUrl);
        }
        navigate('ShareSendLink', {
          amount,
          walletId: wallet.id,
          txHash: depositResult.txHash,
          linkUrl: depositResult.claimUrl,
          chainId: wallet.network.asChain()?.chainId,
        });
      }
    },
    [
      addressBookContact,
      amount,
      amountBigInt,
      depositResult,
      directContactMethod,
      eventProps,
      handleSendLink,
      isLoading,
      navigate,
      wallet.id,
      wallet.network,
    ],
  );

  useEffect(
    function logOnError() {
      if (claimLinkError) {
        show(formatMessage(messages.sww));
        logPreviewSendLinkFailed({ ...eventProps, errorMessage: claimLinkError?.message });
      }
    },
    [claimLinkError, claimLinkError?.message, eventProps, formatMessage, show],
  );

  const handleCreateSendLink = useCallback(async () => {
    logPreviewSendLinkCreatePressed(eventProps);
    submitClaimLink();
  }, [eventProps, submitClaimLink]);

  const onLayout = useCallback(
    function updateButtonGroupHeight(e: LayoutChangeEvent) {
      if (!buttonGroupHeight) {
        setButtonGroupHeight(e.nativeEvent.layout.height);
      }
    },
    [buttonGroupHeight],
  );

  const isCreateButtonDisabled = useMemo(
    () =>
      !previewSendInfoTx ||
      !claimLink ||
      !!transactionGenerationError ||
      !!notEnoughBalanceError ||
      isLoading,
    [previewSendInfoTx, claimLink, transactionGenerationError, notEnoughBalanceError, isLoading],
  );

  const contactDestination = useMemo(() => {
    if (!contactMethodWithFallback) {
      return;
    }
    if (isWhatsApp(contactMethodWithFallback)) {
      return `${WHATSAPP.label} ${getContactMethodInfo(contactMethodWithFallback)}`;
    }
    return getContactMethodInfo(contactMethodWithFallback);
  }, [contactMethodWithFallback]);

  const destination = useMemo(() => {
    if (directContactMethod) {
      return {
        type: 'contact_record_id',
        label: directContactMethod,
        contactDestination: directContactMethod,
        defaultAvatarOverride: <ProfileAvatar />,
      } as DestinationResolutionResultType;
    }
    const initials = addressBookContact?.initials;
    return {
      type: 'contact_record_id',
      label: addressBookContact?.displayName,
      contactDestination,
      avatarURL: addressBookContact?.avatar,
      defaultAvatarOverride: initials ? <InitialsAvatar initials={initials} /> : undefined,
    } as DestinationResolutionResultType;
  }, [
    addressBookContact?.avatar,
    addressBookContact?.displayName,
    addressBookContact?.initials,
    contactDestination,
    directContactMethod,
  ]);

  const shouldShowSimpleSignTransactionTopSection = useMemo(
    () => previewSendInfoTx && (contactRecordID || directContactMethod),
    [contactRecordID, directContactMethod, previewSendInfoTx],
  );

  const isContactSend = useMemo(
    () => contactRecordID || directContactMethod,
    [contactRecordID, directContactMethod],
  );

  // We need to create a new error object to avoid the error fallback from freezing
  if (transactionGenerationError?.message) {
    throw new Error(transactionGenerationError?.message);
  }

  return (
    <Screen full={!isPaymentsModeEnabled} navBar={navBar} testID="preview-send-link">
      <VStack flexGrow={1} flexShrink={1} justifyContent="space-between">
        <ScrollView>
          {shouldShowSimpleSignTransactionTopSection ? (
            <SimpleSignTransactionTopSection
              wallet={wallet}
              transaction={previewSendInfoTx!}
              destination={destination}
              showBalanceAmount
            />
          ) : undefined}
          <Box spacingHorizontal={3}>
            {!isContactSend && (
              <>
                <Box>
                  <TextTitle2>{formatMessage(messages.title)}</TextTitle2>
                  <TextBody spacingTop={1} color="foregroundMuted">
                    {formatMessage(messages.description)}
                  </TextBody>
                </Box>
                <Box spacingVertical={2}>
                  <TransactionPreviewCard wallet={wallet} amount={amountBigInt} />
                </Box>
              </>
            )}
            <VStack key="tx-details">
              {notEnoughBalanceError?.message ? (
                <Box justifyContent="center" alignItems="center">
                  <TextLabel2
                    color="negative"
                    align="center"
                    spacingHorizontal={2}
                    onPress={handleOpenTopUpTray}
                    testID="not-enough-balance-error"
                  >
                    {notEnoughBalanceError?.message}
                    {notEnoughBalanceError ? (
                      <Icon spacingStart={3} name="info" size="xs" color="negative" />
                    ) : null}
                  </TextLabel2>
                </Box>
              ) : (
                <TransactionDetailsWithFallback
                  unsignedApproveTx={previewApproveTx}
                  unsignedTx={previewSendInfoTx}
                  unsignedContractFeeTx={previewContractFeeTx}
                  wallet={wallet}
                />
              )}
            </VStack>
          </Box>
        </ScrollView>
      </VStack>
      <Box
        spacingHorizontal={3}
        spacingTop={1}
        spacingBottom={isPaymentsModeEnabled ? 3 : 0}
        onLayout={onLayout}
      >
        <TextLabel2 color="foregroundMuted" align="center">
          {`${formatMessage(isContactSend ? messages.contactSendTip : messages.tip)} ${
            directContactMethod ? formatMessage(messages.directContactMethodSendNote) : ''
          }`}
        </TextLabel2>
        <Box spacingTop={2}>
          <ButtonGroup accessibilityLabel="Group" block>
            <Button variant="secondary" onPress={handleCancel}>
              {formatMessage(messages.cancel)}
            </Button>
            <Button
              testID="create-send-via-link-button"
              onPress={handleCreateSendLink}
              disabled={isCreateButtonDisabled}
              variant="primary"
              loading={isLoading}
            >
              {formatMessage(isContactSend ? messages.confirmButton : messages.createLink)}
            </Button>
          </ButtonGroup>
        </Box>
      </Box>
    </Screen>
  );
});

const PreviewSendLinkStandardContainer = memo(function PreviewSendLinkStandardContainer() {
  const { formatMessage } = useIntl();
  const { walletId, amount, contactRecordID, phoneNumber, emailAddress } = useParams<
    SendParamList,
    'PreviewSendLink'
  >();
  const { goBack } = useStackNavigation();

  const walletGroupId = useActiveWalletGroupId();
  const wallet = useWalletById(walletGroupId, walletId);

  const claimLinkConfigs = useGetClaimLinkConfigs();

  const escrowAddress = useMemo(() => {
    const asset = new ClaimLinkAssetConfig({
      erc20ContractAddress: wallet?.contractAddress,
      chainId: wallet?.network?.asChain()?.chainId,
      isEnabled: false,
    });

    const claimLinkAsset = claimLinkConfigs.get(asset.key());

    const escrowContractAddressPosition =
      (claimLinkAsset?.escrowContractAddresses?.length ?? 0) - 1;

    return (
      claimLinkAsset?.escrowContractAddress ??
      claimLinkAsset?.escrowContractAddresses?.[escrowContractAddressPosition]
    );
  }, [claimLinkConfigs, wallet?.contractAddress, wallet?.network]);

  if (!wallet) {
    throw new Error('Asset not found');
  }

  if (!amount) {
    throw new Error('Missing amount info');
  }

  // We assume that an amount of 0 means the user is trying to send an NFT
  if (!escrowAddress || BigInt(amount) <= 0) {
    return (
      <CustomScreenErrorFallback
        message={formatMessage(messages.unsupportedAsset)}
        description={formatMessage(messages.assetNotSupportedDescription)}
        actions={<Button onPress={goBack}>{formatMessage(messages.goBack)}</Button>}
      />
    );
  }
  return (
    <PreviewSendLinkContent
      wallet={wallet}
      amount={amount}
      contactRecordID={contactRecordID}
      phoneNumber={phoneNumber}
      emailAddress={emailAddress}
    />
  );
});

const PreviewSendLinkPrefilledContainer = memo(function PreviewSendLinkPrefilledContainer() {
  const { formatMessage } = useIntl();

  const {
    blockchain: blockchainParam,
    contractAddress,
    chainId,
    amount: amountParam,
  } = useParams<SendParamList, 'PreviewSendLink'>();
  const { replace } = useStackNavigation();

  const blockchain = blockchainParam ?? ('' as BlockchainSymbol);

  const walletGroupId = useActiveWalletGroupId();
  const primaryAddress = usePrimaryReceiveAddresses(walletGroupId).get(blockchain)?.address;

  const [isLoading, setLoading] = useState(true);
  const [wallet, setWallet] = useState<Wallet | undefined>();

  const amount = getTransactionAmount({ uint256: amountParam }, wallet) ?? 0n;

  const claimLinkConfigs = useGetClaimLinkConfigs();
  const claimLinkAsset = getClaimLinkConfigForAsset(claimLinkConfigs, wallet);

  const escrowAddress = useMemo(() => {
    const escrowContractAddressPosition =
      (claimLinkAsset?.escrowContractAddresses?.length ?? 0) - 1;

    return (
      claimLinkAsset?.escrowContractAddress ??
      claimLinkAsset?.escrowContractAddresses?.[escrowContractAddressPosition]
    );
  }, [claimLinkAsset?.escrowContractAddress, claimLinkAsset?.escrowContractAddresses]);

  const isTransactionAmountSupported = useIsTransferAmountSupported(wallet, amount);
  const { isSupported: isAssetSupportedBySendViaLink } = useIsAssetSupportedBySendViaLink(wallet);

  const isValidSetup = useMemo(() => {
    if (!wallet?.balance || !amount) return false;

    if (!isAssetSupportedBySendViaLink || !isTransactionAmountSupported) return false;

    return true;
  }, [amount, isAssetSupportedBySendViaLink, isTransactionAmountSupported, wallet]);

  const getWalletInstance = useGetWalletInstance({
    shouldSearchOnActiveWallets: true,
    shouldFetchDataFromAPI: false,
  });

  useEffect(
    function loadWallet() {
      async function fetchWallet() {
        try {
          if (!primaryAddress) return;

          const walletInstance = await getWalletInstance({
            chainId,
            blockchain,
            contractAddress,
            primaryAddress,
          });
          setWallet(walletInstance);
        } catch {
          triggerPrefilledSendViaLinkFailed({ blockchain, chainId, contractAddress });
        } finally {
          setLoading(false);
        }
      }
      fetchWallet();
    },
    [blockchain, chainId, contractAddress, getWalletInstance, primaryAddress],
  );

  useEffect(
    function logSendViaLinkPrefillResult() {
      if (isLoading) return;
      if (!isValidSetup || !escrowAddress) {
        triggerPrefilledSendViaLinkFailed({ blockchain, chainId, contractAddress });
      } else {
        triggerPrefilledSendViaLinkSucceed({ blockchain, chainId, contractAddress });
      }
    },
    [blockchain, chainId, contractAddress, escrowAddress, isLoading, isValidSetup],
  );

  const showTurnOffPaymentsModeModal = useShouldRenderTurnOffPaymentsModeModal({
    contractAddress,
    chainId,
  });

  if (isLoading) {
    return <FullScreenLoader testID="preview-send-link-loader" />;
  }

  if (!wallet || !isValidSetup || !escrowAddress) {
    replace('Send', {
      screen: 'SendInput',
      params: {
        entryPoint: 'prefilledSend',
        blockchain,
        chainId,
        contractAddress,
        amount: amountParam,
      },
      merge: true,
    });
    return <></>;
  }

  if (showTurnOffPaymentsModeModal) {
    return <TurnOffPaymentsModeModal action={formatMessage(messages.sendAction)} />;
  }

  return <PreviewSendLinkContent wallet={wallet} amount={amount.toString()} />;
});

const PreviewSendLinkInner = memo(function PreviewSendLinkInner() {
