import { useCallback, useMemo, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  logMaxSendLinkAmountTrayViewed,
  logMinSendLinkAmountTrayViewed,
  logNoAmountTrayViewed,
  logNotEnoughBalanceTrayViewed,
  logSendInputLinkEntrypointPressed,
} from 'cb-wallet-analytics/send/Send';
import { useGetSendLinkTransferLimits } from 'cb-wallet-data/ClaimLinks/hooks/useGetSendLinkTransferLimits';
import { useIsAssetSupportedBySendViaLink } from 'cb-wallet-data/ClaimLinks/hooks/useIsAssetSupportedBySendViaLink';
import { useIsTransferAmountSupported } from 'cb-wallet-data/ClaimLinks/hooks/useIsTransferAmountSupported';
import { useCurrencyFormatter } from 'cb-wallet-data/CurrencyFormatter/hooks/useCurrencyFormatter';
import { useIsFeatureEnabled } from 'cb-wallet-data/FeatureManager/hooks/useIsFeatureEnabled';
import { Wallet } from 'cb-wallet-data/stores/Wallets/models/Wallet';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody, TextLabel2, TextTitle2 } from '@cbhq/cds-mobile/typography';

