type SendViaLinkNavOptionProps = {
  wallet: Wallet;
  amount: bigint;
  isFromSendViaLinkBanner?: boolean;
};

const messages = defineMessages({
  getALink: {
    defaultMessage: 'Send via text',
    description: 'Button label to generate a link',
  },
  gotIt: {
    defaultMessage: 'Got it',
    description: 'Button label to close a tray',
  },
  insufficientAmountTitle: {
    defaultMessage: 'Enter an amount to continue',
    description: 'Title of tray that shows when user has not entered an amount',
  },
  exceedingMaxSendLinkAmountTitle: {
    defaultMessage: 'Enter an amount below {maxFiatAmount}',
    description: 'Title of tray that shows when user has entered an amount that is too high',
  },
  belowTheMinimumTitle: {
    defaultMessage: 'Enter an amount above {minFiatAmount}',
    description: 'Title of tray that shows when user has entered an amount that is too low',
  },
  wrongAmountTrayDescription: {
    defaultMessage:
      'You can now send crypto with a text message, email, or your favorite app. Please enter an amount below {maxFiatAmount}',
    description: 'Description section of wrong amount tray',
  },
  notEnoughBalanceTitle: {
    defaultMessage: 'You do not have enough {currencyCode} in this account',
  },
});

export function SendViaLinkNavOption({
  wallet,
  amount,
  isFromSendViaLinkBanner,
}: SendViaLinkNavOptionProps) {
  const { push } = useStackNavigation();
  const { formatMessage } = useIntl();
  const transferLimits = useGetSendLinkTransferLimits(wallet);
  const [isMaxSendLinkAmountTrayVisible, setMaxSendLinkAmountTrayVisible] = useState(false);
  const [isMinSendLinkAmountTrayVisible, setMinSendLinkAmountTrayVisible] = useState(false);
  const [isNoAmountTrayVisible, setNoAmountTrayVisible] = useState(false);
  const [isNotEnoughBalanceTrayVisible, setNotEnoughBalanceTrayVisible] = useState(false);

  const eventProps = useMemo(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      chainName: wallet.network.asChain()?.displayName,
      currencyCode: wallet.currencyCode.rawValue,
      chainId: wallet.network.asChain()?.chainId,
      contractAddress: wallet.contractAddress,
    }),
    [
      wallet.blockchain.rawValue,
      wallet.contractAddress,
      wallet.currencyCode.rawValue,
      wallet.network,
    ],
  );

  const openNoAmountTray = useCallback(() => {
    logNoAmountTrayViewed(eventProps);
    setNoAmountTrayVisible(true);
  }, [eventProps]);

  const closeNoAmountTray = useCallback(() => {
    setNoAmountTrayVisible(false);
  }, []);

  const openMaxSendLinkAmountTray = useCallback(() => {
    logMaxSendLinkAmountTrayViewed(eventProps);
    setMaxSendLinkAmountTrayVisible(true);
  }, [eventProps]);

  const closeMaxSendLinkAmountTray = useCallback(() => {
    setMaxSendLinkAmountTrayVisible(false);
  }, []);

  const openMinSendLinkAmountTray = useCallback(() => {
    logMinSendLinkAmountTrayViewed(eventProps);
    setMinSendLinkAmountTrayVisible(true);
  }, [eventProps]);

  const closeMinSendLinkAmountTray = useCallback(() => {
    setMinSendLinkAmountTrayVisible(false);
  }, []);

  const openNotEnoughBalanceTray = useCallback(() => {
    logNotEnoughBalanceTrayViewed(eventProps);
    setNotEnoughBalanceTrayVisible(true);
  }, [eventProps]);

  const closeNotEnoughBalanceTray = useCallback(() => {
    setNotEnoughBalanceTrayVisible(false);
  }, []);

  const isSendLinkOptionEnabled = useIsFeatureEnabled('send_via_link_send_input_option');

  const isSupportedAmount = useIsTransferAmountSupported(wallet, amount);

  const { isSupported: isSupportedAsset } = useIsAssetSupportedBySendViaLink(wallet);

  const isExceedingSendLinkMax = useMemo(() => {
    return transferLimits?.max && amount > BigInt(transferLimits.max);
  }, [amount, transferLimits?.max]);

  const isBelowSendLinkMin = useMemo(() => {
    return transferLimits?.min && amount < BigInt(transferLimits.min);
  }, [amount, transferLimits?.min]);

  const isNotEnoughBalance = amount > (wallet.balance ?? 0n);

  const { formatToFiat } = useCurrencyFormatter();

  const maxAmount = useMemo(() => {
    return BigInt(transferLimits?.max ?? wallet.balance?.toString() ?? '0');
  }, [transferLimits?.max, wallet.balance]);

  const minAmount = useMemo(() => {
    return BigInt(transferLimits?.min ?? '0');
  }, [transferLimits?.min]);

  const maxFiatAmount = useMemo(() => {
    return formatToFiat(
      wallet.currencyCode,
      wallet.decimals,
      maxAmount,
      false,
      wallet.contractAddress,
      wallet.network,
      wallet.blockchain,
      true,
    );
  }, [formatToFiat, maxAmount, wallet]);

  const minFiatAmount = useMemo(() => {
    return formatToFiat(
      wallet.currencyCode,
      wallet.decimals,
      minAmount,
      false,
      wallet.contractAddress,
      wallet.network,
      wallet.blockchain,
      true,
    );
  }, [formatToFiat, minAmount, wallet]);

  const shouldShowSendViaLinkOnNav = isSendLinkOptionEnabled && !isFromSendViaLinkBanner;

  const shouldGenerateLink = isSupportedAsset && isSupportedAmount;

  const shouldShowSendLinkInfo = !isSupportedAsset;

  const handlePressSendViaLinkNavOption = useCallback(
    function handlePressSendViaLinkNavOption() {
      logSendInputLinkEntrypointPressed(eventProps);

      if (isNotEnoughBalance) {
        openNotEnoughBalanceTray();
        return;
      }

      if (isSupportedAsset && isExceedingSendLinkMax) {
        openMaxSendLinkAmountTray();
        return;
      }

      if (isSupportedAsset && !amount) {
        openNoAmountTray();
        return;
      }

      if (isSupportedAsset && isBelowSendLinkMin) {
        openMinSendLinkAmountTray();
        return;
      }

      if (shouldGenerateLink) {
        push('PreviewSendLink', {
          walletId: wallet.id,
          amount: amount.toString(),
          source: 'send',
        });
        return;
      }

      if (shouldShowSendLinkInfo) {
        push('SendViaLinkEducational', undefined);
      }
    },
    [
      amount,
      eventProps,
      isBelowSendLinkMin,
      isExceedingSendLinkMax,
      isNotEnoughBalance,
      isSupportedAsset,
      openMaxSendLinkAmountTray,
      openMinSendLinkAmountTray,
      openNoAmountTray,
      openNotEnoughBalanceTray,
      push,
      shouldGenerateLink,
      shouldShowSendLinkInfo,
      wallet.id,
    ],
  );

  return shouldShowSendViaLinkOnNav ? (
    <Box>
      <Pressable
        background="transparent"
        onPress={handlePressSendViaLinkNavOption}
        testID="send-via-link-nav-option"
      >
        <TextBody color="primary">{formatMessage(messages.getALink)}</TextBody>
      </Pressable>
      {isMaxSendLinkAmountTrayVisible && (
        <Tray onCloseComplete={closeMaxSendLinkAmountTray} testID="max-send-link-tray">
          {({ handleClose }) => (
            <AmountErrorTrayContent
              title={formatMessage(messages.exceedingMaxSendLinkAmountTitle, { maxFiatAmount })}
              description={formatMessage(messages.wrongAmountTrayDescription, { maxFiatAmount })}
              onButtonPress={handleClose}
            />
          )}
        </Tray>
      )}
      {isNoAmountTrayVisible && (
        <Tray onCloseComplete={closeNoAmountTray} testID="no-amount-tray">
          {({ handleClose }) => (
            <AmountErrorTrayContent
              title={formatMessage(messages.insufficientAmountTitle)}
              description={formatMessage(messages.wrongAmountTrayDescription, { maxFiatAmount })}
              onButtonPress={handleClose}
            />
          )}
        </Tray>
      )}
      {isNotEnoughBalanceTrayVisible && (
        <Tray onCloseComplete={closeNotEnoughBalanceTray} testID="not-enough-balance-tray">
          {({ handleClose }) => (
            <AmountErrorTrayContent
              title={formatMessage(messages.notEnoughBalanceTitle, {
                currencyCode: wallet.currencyCode.rawValue,
              })}
              description={formatMessage(messages.wrongAmountTrayDescription, { maxFiatAmount })}
              onButtonPress={handleClose}
            />
          )}
        </Tray>
      )}
      {isMinSendLinkAmountTrayVisible && (
        <Tray onCloseComplete={closeMinSendLinkAmountTray} testID="min-send-link-tray">
          {({ handleClose }) => (
            <AmountErrorTrayContent
              title={formatMessage(messages.belowTheMinimumTitle, { minFiatAmount })}
              description={formatMessage(messages.wrongAmountTrayDescription, { maxFiatAmount })}
              onButtonPress={handleClose}
            />
          )}
        </Tray>
      )}
    </Box>
  ) : null;
}

type AmountErrorTrayContentProps = {
  title: string;
  description: string;
  onButtonPress: () => void;
};

function AmountErrorTrayContent({
  title,
  description,
  onButtonPress,
}: AmountErrorTrayContentProps) {
  const { formatMessage } = useIntl();
  return (
    <VStack spacingHorizontal={2}>
      <Box width="100%" alignItems="center" justifyContent="center" spacingTop={2}>
        <SendViaLinkEducationalMiami />
      </Box>
      <VStack spacingHorizontal={4} spacingTop={2} spacingBottom={6}>
        <TextTitle2 align="center" spacingBottom={1}>
          {title}
        </TextTitle2>
        <TextLabel2 align="center" color="foregroundMuted">
          {description}
        </TextLabel2>
      </VStack>
      <Button variant="primary" block onPress={onButtonPress}>
        {formatMessage(messages.gotIt)}
      </Button>
    </VStack>
  );
}

