// Window width - screen horizontal spacing
const FALLBACK_BUTTON_WIDTH = Dimensions.get('window').width - 48;

type ShareSendLinkContentProps = {
  wallet: Wallet;
  amount: bigint;
  linkUrl: string;
  txHash: string;
  chainId?: number;
};

const ShareSendLinkContent = memo(function ShareSendLink({
  wallet,
  amount,
  txHash,
  chainId,
  linkUrl: claimLinkUrl,
}: ShareSendLinkContentProps) {
  const { formatMessage } = useIntl();
  const { popStack } = useStackNavigation<SendParamList>();
  const [buttonGroupHeight, setButtonGroupHeight] = useState<number | undefined>();
  const { formatToFiat, formatToCrypto } = useCurrencyFormatter();
  const sendViaLinkQrEnabled = useIsFeatureEnabled('send_via_link_qr_code');

  const claimLinksVersion = useClaimLinksVersion();

  const { status } = useSendLinkStatus({
    txHash,
    chainId,
  });

  const formatClaimLinkShareUrl = useFormatClaimLinkShareUrl();
  const { openModal, closeModal } = useModal();

  const linkUrl = useMemo(() => {
    return formatClaimLinkShareUrl(claimLinkUrl);
  }, [claimLinkUrl, formatClaimLinkShareUrl]);

  const fiatAmount = useMemo(
    () =>
      formatToFiat(
        wallet.currencyCode,
        wallet.decimals,
        amount,
        false,
        wallet.contractAddress,
        wallet.network,
        wallet.blockchain,
        true,
      ),
    [amount, formatToFiat, wallet],
  );

  const eventProps = useMemo(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      chainName: wallet.network.asChain()?.displayName,
      currencyCode: wallet.currencyCode.rawValue,
      chainId: wallet.network.asChain()?.chainId,
      contractAddress: wallet.contractAddress,
      version: claimLinksVersion,
    }),
    [
      claimLinksVersion,
      wallet.blockchain.rawValue,
      wallet.contractAddress,
      wallet.currencyCode.rawValue,
      wallet.network,
    ],
  );

  const cryptoAmount = useMemo(() => {
    return formatToCrypto({
      currencyCode: wallet.currencyCode,
      decimals: wallet.decimals,
      value: amount,
      overridePrivacy: true,
      maxDisplayDecimals: 4n,
    });
  }, [formatToCrypto, amount, wallet.currencyCode, wallet.decimals]);

  const handleDisplayQr = useCallback(() => {
    logShareSendLinkQrCodeViewed(eventProps);

    return openModal(
      <Modal
        testID="share-send-link--qr-code-modal"
        onRequestClose={closeModal}
        visible
        hideDividers
      >
        <ModalHeader />
        <ModalSafeAreaView>
          <SendViaQr claimLink={linkUrl} onClose={closeModal} />
        </ModalSafeAreaView>
      </Modal>,
    );
  }, [closeModal, eventProps, linkUrl, openModal]);

  useOnMount(() => {
    logShareSendLinkViewed(eventProps);
  });

  const shareMessage = useMemo(
    () =>
      `${formatMessage(messages.shareMessage, {
        fiatAmount,
        cryptoAmount,
        networkName: wallet.network.asChain()?.displayName,
        currencyCode: wallet.currencyCode.rawValue,
      })}\n\n${linkUrl}`,
    [
      cryptoAmount,
      fiatAmount,
      formatMessage,
      linkUrl,
      wallet.currencyCode.rawValue,
      wallet.network,
    ],
  );

  const share = useShare({
    message: shareMessage,
  });

  const handleClose = useCallback(() => {
    logShareSendLinkClosed(eventProps);
    popStack();
  }, [eventProps, popStack]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      right: 'close',
      left: () => null,
      handleRight: handleClose,
    }),
    [handleClose],
  );

  const handleShareSendLink = useCallback(() => {
    logShareSendLinkShared(eventProps);
    share();
  }, [eventProps, share]);

  const onCopy = useCallback(() => {
    logShareSendLinkCopied(eventProps);
  }, [eventProps]);

  const onLayout = useCallback(
    function updateButtonGroupHeight(e: LayoutChangeEvent) {
      if (!buttonGroupHeight) {
        setButtonGroupHeight(e.nativeEvent.layout.height);
      }
    },
    [buttonGroupHeight],
  );

  const scrollViewStyle = useMemo(
    () => ({
      style: {
        height: 350,
      },
    }),
    [],
  );

  const isTransactionReady = useMemo(() => {
    return status && !['created', 'depositing'].includes(status);
  }, [status]);

  const qrCodeButtons = useMemo(() => {
    if (!sendViaLinkQrEnabled) return null;

    if (!isTransactionReady) {
      return (
        <Fallback
          height={42}
          shape="circle"
          width={FALLBACK_BUTTON_WIDTH}
          testID="share-send-link-loading-fallback"
        />
      );
    }

    return (
      <ButtonGroup testID="share-send-link-buttons" block>
        <Button
          block
          compact
          accessible
          variant="secondary"
          onPress={handleDisplayQr}
          loading={!isTransactionReady}
          testID="svl-send-qr-code-button"
          accessibilityLabel={formatMessage(messages.qrCodeAccessibilityLabel)}
        >
          <TextLabel1>{formatMessage(messages.viewQrButtonText)}</TextLabel1>
        </Button>

        <Box flexGrow={1} spacingBottom={5} testID="copy-button" alignItems="flex-end">
          <CopyButton
            compact
            type="block"
            value={linkUrl}
            onPress={onCopy}
            variant="secondary"
            loading={!isTransactionReady}
            buttonText={formatMessage(messages.copyButtonText)}
          />
        </Box>
      </ButtonGroup>
    );
  }, [formatMessage, handleDisplayQr, isTransactionReady, linkUrl, onCopy, sendViaLinkQrEnabled]);

  return (
    <Screen full navBar={navBar} testID="share-send-link">
      <VStack flexGrow={1} justifyContent="space-between">
        <ScrollView {...scrollViewStyle}>
          <Box spacingHorizontal={3}>
            <Box width="100%" alignItems="center" justifyContent="center">
              <TextTitle2 align="center">{formatMessage(messages.title)}</TextTitle2>
              <TextBody align="center" spacingTop={1} color="foregroundMuted">
                {formatMessage(messages.description)}
              </TextBody>
            </Box>
            <Box spacingVertical={2}>
              <TransactionPreviewCard wallet={wallet} amount={amount} />
            </Box>

            {qrCodeButtons}

            {!sendViaLinkQrEnabled && (
              <HStack height={50} alignItems="center" justifyContent="space-between">
                <Box width="70%">
                  <TextHeadline>{formatMessage(messages.claimLink)}</TextHeadline>
                  <TextBody color="foregroundMuted" numberOfLines={1}>
                    {linkUrl}
                  </TextBody>
                </Box>
                <Box spacingBottom={5} testID="copy-button">
                  <CopyButton value={linkUrl} onPress={onCopy} />
                </Box>
              </HStack>
            )}

            <TextBody spacingTop={1} color="foregroundMuted">
              {formatMessage(messages.linkDescription)}
            </TextBody>
          </Box>
        </ScrollView>
      </VStack>
      <VStack gap={2} spacingHorizontal={3} spacingTop={1} onLayout={onLayout}>
        <TextLabel2 color="foregroundMuted" align="center">
          {formatMessage(messages.tip)}
        </TextLabel2>
