  WarningOnSendConfirmation,
} from '../hooks/useGetWarningOnSendConfirmation';

import { GaslessSendUpsell } from './GaslessSendUpsell';

/**
 * Component that allows a user to approve or cancel signing of a transaction for send flow
 *
 * Consumers should be able to use this in any screen, so we should not access/change the transaction context
 * in this scope. Any update on TransactionContext should happen on the parent component, through prop callbacks
 *
 */
export const SignSendTransaction = memo(function SignSendTransactionBody(
  props: SendSignTransactionProps,
) {
  const {
    wallet,
    transaction,
    transactions,
    onDismiss,
    onPressAdjustGas,
    showAddressField,
    destination,
    dismissTrayAnalyticsEvent,
    onRefreshGasFee,
    showBalanceAmount = true,
    isTxSponsored,
  } = props;

  const sponsoredInfo = useGetSponsoredSendInfo(wallet);
  const isGaslessUpsellOnSendConfirmationEnabled = useIsFeatureEnabled(
    'send_confirmation_gasless_upsell',
  );

  const { formatMessage } = useIntl();

  const is1559Enabled = useMemo(() => isNetwork1559Enabled(wallet.network), [wallet.network]);
  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useTxFeeWallet(activeWalletGroupId, transaction);
  const isRealTimeGasFeesEnabled = useIsRealTimeGasFeesEnabled(wallet);
  const saveRecentRecipient = useSaveRecentRecipient();
  const [lastUpdateTime, setLastUpdateTime] = useState<Date>(new Date());
  const [isRefreshingUnsignedTx, setIsRefreshingUnsignedTx] = useState(false);

  const shouldShowRealTimeGasFeeCountdown = useMemo(
    () => isRealTimeGasFeesEnabled && !!onRefreshGasFee,
    [isRealTimeGasFeesEnabled, onRefreshGasFee],
  );

  const realTimeGasFeesParams = useMemo(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      isBaseAsset: wallet.isBaseAsset,
      is1559NetworkEnabled: isNetwork1559Enabled(wallet.network),
    }),
    [wallet.blockchain.rawValue, wallet.isBaseAsset, wallet.network],
  );

  const sendGasFeeRefreshed = useSendRealTimeGasFeesRefreshSucceed(realTimeGasFeesParams);
  const sendGasFeeFailed = useSendRealTimeGasFeesRefreshFailed(realTimeGasFeesParams);

  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx: transaction,
    feeWallet,
    flow: 'send',
    isTxSponsored: isTxSponsored ?? false,
  });
  useTransactionCostAnalytics({ wallet, transaction, is1559Enabled, transactionDetailsErrors });

  const [warning, setWarning] = useState<WarningOnSendConfirmation | undefined>(undefined);
  const getWarningOnSendConfirmation = useGetWarningOnSendConfirmation();
  const removeWarning = useCallback(() => setWarning(undefined), []);

  useEffect(
    function getWarning() {
      const newWarning = getWarningOnSendConfirmation({ wallet });
      const networkChain = wallet.network.asChain();

      if (newWarning?.type === 'spam_token') {
        logSendSpamTokenWarningViewed({
          blockchain: wallet.blockchain.rawValue,
          chainId: networkChain?.chainId,
          chainName: networkChain?.displayName,
          currencyCode: wallet.currencyCode.rawValue,
          contractAddress: wallet.contractAddress,
        });
      }
      setWarning(newWarning);
    },
    [getWarningOnSendConfirmation, wallet],
  );

  const [isConfirmTxVisible, { toggleOff: closeFraudWarningConfirmationTray }] = useToggler(false);
  const AdjustGasPresetAction = useMemo(
    () =>
      is1559Enabled && onPressAdjustGas ? (
        <Pressable
          onPress={onPressAdjustGas}
          background="transparent"
          testID="show-adjustable-gas-button"
        >
          <Icon name="gear" size="s" color="foreground" spacingStart={1} />
        </Pressable>
      ) : null,
    [is1559Enabled, onPressAdjustGas],
  );

  const refreshNetworkFeeCallback = useCallback(async () => {
    if (shouldShowRealTimeGasFeeCountdown) {
      setIsRefreshingUnsignedTx(true);
      onRefreshGasFee?.()
        .then(() => sendGasFeeRefreshed())
        .catch((err) => sendGasFeeFailed({ errorMessage: err?.message }))
        .finally(() => {
          setLastUpdateTime(new Date());
          setIsRefreshingUnsignedTx(false);
        });
    }
  }, [shouldShowRealTimeGasFeeCountdown, onRefreshGasFee, sendGasFeeFailed, sendGasFeeRefreshed]);

  useIntervalForPromises(refreshNetworkFeeCallback, { interval: 31000 });

  const hideTotalCost = useHideTotalCost({
    wallet,
  });

  const saveRecipient = useCallback(() => {
    saveRecentRecipient(transaction.recipientAddress, wallet.blockchain, destination?.label);
  }, [saveRecentRecipient, transaction.recipientAddress, wallet.blockchain, destination?.label]);

  const onSubmitSuccess = useCallback(
    function startTxTimer(success: SignedTx) {
      if (!success?.txHash) return;
      saveRecipient();
      newTimer(createSubmitTimerName(success.txHash));
    },
    [saveRecipient],
  );

  const { confirmAndSubmit, isSubmissionLoading } = useConfirmSignAndSubmit({
    ...props,
    sponsoredInfo,
    closeFraudWarningConfirmationTray,
    shouldSubmit: true,
    flow: 'send',
    onSubmit: onSubmitSuccess,
    isTxSponsored,
  });

  const isSubmitLoading = useMemo(() => {
    return isSubmissionLoading || isRefreshingUnsignedTx;
  }, [isSubmissionLoading, isRefreshingUnsignedTx]);

  const transactionCost = useTransactionCost({ wallet, transaction, transactions, hideTotalCost });

  const sendRowDetails: SendRowDetails = useMemo(() => {
    return {
      transactionCost,
      wallet,
      AdjustGasPresetAction,
      showAddressField,
      unsignedTx: transaction,
      isTxScannerLoading: false,
      isTxSponsored,
      toAddressItem: undefined,
      lastUpdateTime: shouldShowRealTimeGasFeeCountdown ? lastUpdateTime : undefined,
      isPageLoading: isRefreshingUnsignedTx,
    };
  }, [
    transactionCost,
    wallet,
    AdjustGasPresetAction,
    showAddressField,
    transaction,
    shouldShowRealTimeGasFeeCountdown,
    lastUpdateTime,
    isRefreshingUnsignedTx,
    isTxSponsored,
  ]);

  const detailRows = useTransactionDetailRowItems(sendRowDetails);

  const onDismissView = useCallback(() => {
    if (onDismiss) {
      dismissTrayAnalyticsEvent?.();
      onDismiss();
    }
  }, [dismissTrayAnalyticsEvent, onDismiss]);

  const shouldShowUnsafeSendWarning = useMemo(
    () => warning && !transactionDetailsErrors,
    [transactionDetailsErrors, warning],
  );

  const shouldShowGaslessUpsell = useMemo(
    () => !shouldShowUnsafeSendWarning && isGaslessUpsellOnSendConfirmationEnabled,
    [isGaslessUpsellOnSendConfirmationEnabled, shouldShowUnsafeSendWarning],
  );

  return (
    <>
      {!isConfirmTxVisible && (
        <Box flexGrow={1} flexShrink={1}>
          <ScrollView>
            <VStack spacingHorizontal={1} key="tx-request-header">
              <SimpleSignTransactionTopSection
                wallet={wallet}
                transaction={transaction}
                collectible={props.collectible}
                handleCollectiblePress={props.handleCollectiblePress}
                showBalanceAmount={showBalanceAmount}
                destination={destination}
              />
            </VStack>
            <VStack spacingHorizontal={3} spacingTop={1} key="tx-details">
              <TransactionDetails transactionDetailRowItems={detailRows} />
              <Spacer />
            </VStack>
          </ScrollView>

          <VStack flexShrink={0} borderedTop spacingTop={1}>
            {shouldShowUnsafeSendWarning && warning && (
              <WarningOnSendConfirmationTile
                warning={warning}
                onDismiss={removeWarning}
                icon="warning"
              />
            )}
            <GaslessSendUpsell
              isVisibleOnMount={shouldShowGaslessUpsell}
              wallet={wallet}
              onPressEnabled
              source="sign_transaction"
            />
            <Box spacingHorizontal={2}>
              {transactionDetailsErrors && (
                <VStack spacingBottom={1}>
                  <TextLegal align="center">{transactionDetailsErrors.message}</TextLegal>
                </VStack>
              )}

              <ButtonGroup accessibilityLabel={formatMessage(messages.ctaGroup)} block>
                {onDismiss && (
                  <Button
                    variant="secondary"
                    disabled={isSubmitLoading}
                    onPress={onDismissView}
                    testID="sign-transaction-cancel-button"
                  >
                    {formatMessage(messages.cancel)}
                  </Button>
                )}
                <Button
                  loading={isSubmitLoading}
                  disabled={transactionDetailsErrors?.isDisabled}
                  onPress={confirmAndSubmit}
                  testID="sign-transaction-confirm-button"
                >
                  {formatMessage(messages.confirmSendButton)}
                </Button>
              </ButtonGroup>
            </Box>
          </VStack>
        </Box>
      )}
    </>
  );
});

import { useCallback, useMemo, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  ethereumAddressDerivationPath,
  EthereumBlockchain,
} from 'cb-wallet-data/chains/AccountBased/Ethereum/config';
import { ETHEREUM_SYMBOL } from 'cb-wallet-data/chains/AccountBased/Ethereum/constants';
import { importAddress } from 'cb-wallet-data/chains/AccountBased/operations/importAddress';
import { Blockchain } from 'cb-wallet-data/models/Blockchain';
import { useActiveAccountId } from 'cb-wallet-data/stores/Accounts/hooks/useActiveAccountId';
import { useCreateWalletGroups } from 'cb-wallet-data/stores/WalletGroups/hooks/useCreateWalletGroups';
import { useSetActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useSetActiveWalletGroupId';
import { useAllWallets } from 'cb-wallet-data/stores/Wallets/hooks/useAllWallets';
import { TextInput } from '@cbhq/cds-mobile/controls/TextInput';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { TextHeadline } from '@cbhq/cds-mobile/typography';

import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';

const messages = defineMessages({
  overrideAddressTitle: {
    defaultMessage: 'Ethereum Address Override',
    description: 'Instruction for a developer only feature that overrides an ethereum address',
  },
  overrideAddressLabel: {
    defaultMessage: 'Enter an Ethereum address to override',
    description: 'Instruction for a developer only feature that overrides an ethereum address',
  },
  overrideAddressButton: {
    defaultMessage: 'Override',
    description: 'Button that overrides an ethereum address',
  },
  overrideSuccessMessage: {
    defaultMessage: 'Address override applied',
    description: 'Success message for adding a debug wallet',
  },
  overrideClearSuccessMessage: {
    defaultMessage: 'Debug wallet cleared',
    description: 'Success message for clearing a debug wallet',
  },
  overrideErrorMessage: {
    defaultMessage: 'Failed to override address',
    description: 'Error message for adding a wallet index',
  },
  overrideWalletGroupNickname: {
    defaultMessage: 'Debug: ETH Override',
    description: 'Default nickname given to debug wallet group',
  },
});

const DEBUG_FAUX_WALLET_INDEX = 9999;

/**
 * Provides a way to input an ETH address override, from Settings > Debug menu >
 * Address Override.
 *
 * Once an ETH address is saved, a new wallet group will be created and activated
 * with only ETH assets, that all correspond to the given address and active account.
 *
 * Wallets, addresses and this wallet group all utilize a matching faux index so
 * that the app will associate everything together and function as normal, but not
 * collide with true wallet creation.
 *
 * NOTE: No functionality that involves the mnemonic will work properly when the
 * override is applied.
 *
 * TODO: After using this feature once, there is currently no way to remove the created
 * wallet group without signing out. Adding this would involve starting to build out
 * wallet group deletion functionality.
 */
export function AddressOverride() {
  const { formatMessage } = useIntl();
  const toast = useRateLimitedToast({});

  const activeAccountId = useActiveAccountId();
  const allWallets = useAllWallets();
  const debugWallet = useMemo(
    () =>
      allWallets.find(
        (w) =>
          Blockchain.isEqual(w.blockchain, EthereumBlockchain) &&
          w.accountId === activeAccountId &&
          w.selectedIndex === BigInt(DEBUG_FAUX_WALLET_INDEX),
      ),
    [allWallets, activeAccountId],
  );

  const defaultFieldValue = debugWallet?.primaryAddress ?? ''; // Will be undefined if override never saved before.
  const [fieldValue, setFieldValue] = useState(defaultFieldValue);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const createWalletGroups = useCreateWalletGroups();
  const setActiveWalletGroupId = useSetActiveWalletGroupId();

  const handleFieldSubmit = useCallback(
    async function handleFieldSubmit() {
      setIsSubmitting(true);

      try {
        const walletIndex = BigInt(DEBUG_FAUX_WALLET_INDEX);

        const walletGroupToCreateOptions = {
          accountId: activeAccountId,
          walletIndex,
          nickname: formatMessage(messages.overrideWalletGroupNickname),
        };

        const importableAddress = {
          index: walletIndex,
          address: fieldValue,
          accountId: activeAccountId,
          derivationPath: ethereumAddressDerivationPath(walletIndex),
        };

        const [[createdWalletGroup]] = await Promise.all([
          createWalletGroups([walletGroupToCreateOptions]),
          importAddress(ETHEREUM_SYMBOL, importableAddress),
        ]);

        setActiveWalletGroupId(createdWalletGroup.id);
        toast.show(formatMessage(messages.overrideSuccessMessage));
      } catch (error) {
        toast.show(formatMessage(messages.overrideErrorMessage));
      } finally {
        setIsSubmitting(false);
      }
    },
    [
      fieldValue,
      activeAccountId,
      createWalletGroups,
      setActiveWalletGroupId,
      formatMessage,
      toast,
      setIsSubmitting,
    ],
  );

  return (
    <VStack flexGrow={1} justifyContent="center" alignItems="flex-start" spacing={3}>
      <TextHeadline>{formatMessage(messages.overrideAddressTitle)}</TextHeadline>
      <TextInput
        label={formatMessage(messages.overrideAddressLabel)}
        value={fieldValue}
        onChangeText={setFieldValue}
      />
      <Box spacingVertical={2}>
        <Button block compact onPress={handleFieldSubmit} loading={isSubmitting}>
          {formatMessage(messages.overrideAddressButton)}
        </Button>
      </Box>
    </VStack>
  );
}

import { useCallback, useEffect, useMemo, useState } from 'react';
import { useIntl } from 'react-intl';
import { MnemonicAccessContext } from 'cb-wallet-analytics/auth';
import { generateMnemonic } from 'cb-wallet-data/crypto/generateMnemonic';
import { usePreviousValue } from 'cb-wallet-data/hooks/usePreviousValue';
import { useActiveAccountId } from 'cb-wallet-data/stores/Accounts/hooks/useActiveAccountId';
import { useCreateAccountForMnemonic } from 'cb-wallet-data/stores/Accounts/hooks/useCreateAccountForMnemonic';
import { deriveDeterministicAccountIdForMnemonic } from 'cb-wallet-data/stores/Accounts/utils/deriveDeterministicAccountIdForMnemonic';
import { NUMBER_OF_ADDRESSES } from 'cb-wallet-data/stores/User/hooks/useCreateUserWithMnemonic';
import { useCreateActiveWalletGroupAtIndex } from 'cb-wallet-data/stores/WalletGroups/hooks/useCreateActiveWalletGroupAtIndex';
import { useCreateWalletGroups } from 'cb-wallet-data/stores/WalletGroups/hooks/useCreateWalletGroups';
import { useCreateWallets } from 'cb-wallet-data/stores/Wallets/hooks/useCreateWallets';
import { useCreateWalletsAtIndex } from 'cb-wallet-data/stores/Wallets/hooks/useCreateWalletsAtIndex';
import { useSendCreateWalletsPostRequest } from 'cb-wallet-data/stores/Wallets/hooks/useSendCreateWalletsPostRequest';
import { useRecoilValue } from 'recoil';
import { TextInput } from '@cbhq/cds-mobile/controls/TextInput';
import { VStack } from '@cbhq/cds-mobile/layout';
import { TextBody } from '@cbhq/cds-mobile/typography';
import { ProgressBar } from '@cbhq/cds-mobile/visualizations/ProgressBar';

import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Screen } from ':rn/cds-wallet/components/layout/Screen';
import { NavBarConfig } from ':rn/cds-wallet/components/NavBar/NavBar';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import {
  saveMnemonicForAccountUsingBiometrics,
  saveMnemonicForAccountUsingPIN,
} from ':rn/shared/auth/Auth';
import { authStateAtom } from ':rn/shared/auth/stores/authState';
import { useMnemonic } from ':rn/shared/hooks/useMnemonic';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { messages } from './util/messages';

const DEFAULT_NUM_MNEMONICS = 1;
const DEFAULT_NUM_WALLET_GROUPS = 1;

export function DataSeedingCreateMnemonics() {
  const { formatMessage } = useIntl();
  const toast = useRateLimitedToast({});
  const { goBack } = useStackNavigation();

  const [numMnemonics, setNumMnemonics] = useState(String(DEFAULT_NUM_MNEMONICS));
  const [numWalletGroups, setNumWalletGroups] = useState(String(DEFAULT_NUM_WALLET_GROUPS));
  const [submitProgress, setSubmitProgress] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const authState = useRecoilValue(authStateAtom);
  const { triggerAuth } = useMnemonic({ requireAuthentication: true });
  const activeAccountId = useActiveAccountId();
  const createAccountForMnemonic = useCreateAccountForMnemonic();
  const createActiveWalletGroupAtIndex = useCreateActiveWalletGroupAtIndex();
  const createWalletGroups = useCreateWalletGroups();
  const createWallets = useCreateWallets();
  const createWalletsAtIndex = useCreateWalletsAtIndex();
  const sendCreateWalletsPostRequest = useSendCreateWalletsPostRequest();
  const [numMnemonicsToCreate, setNumMnemonicsToCreate] = useState(0);
  const [pinState, setPinState] = useState('');
  const prevNumMnemonicsToCreate = usePreviousValue(numMnemonicsToCreate);

  const navBar = useMemo<NavBarConfig>(
    () => ({ title: formatMessage(messages.dataSeedingCreateMnemonicsTitle), left: 'back' }),
    [formatMessage],
  );

  const createSingleMnemonic = useCallback(async () => {
    try {
      const numWalletGroupsToCreate = parseInt(numWalletGroups);
      const mnemonic = await generateMnemonic();
      const accountId = await deriveDeterministicAccountIdForMnemonic({ mnemonic });

      if (authState?.appLockType === 'pin') {
        await saveMnemonicForAccountUsingPIN({ mnemonic, pin: pinState, accountId });
      } else if (authState?.appLockType === 'biometrics') {
        await saveMnemonicForAccountUsingBiometrics({
          mnemonic,
          accountId,
          enforceShowBiometricsPrompt: false,
        });
      }

      // 1) Registers derived eth addresses to BE for default 10 wallet groups + any
      // add'l if creating 10+ wallet groups.
      await sendCreateWalletsPostRequest({
        accountId,
        indexes: Array.from(
          { length: Math.max(NUMBER_OF_ADDRESSES, numWalletGroupsToCreate) }, // Always register min 10 w/BE
          (_, i) => BigInt(i),
        ),
      });

      // 2) Creates the account + first wallet group.
      await createAccountForMnemonic({ accountId });

      // 3) Creates the first WalletGroup for the account.
      await createActiveWalletGroupAtIndex({
        accountId,
        walletIndex: 0n,
      });

      // 4) Creates the first 10 wallets for every chain + network.
      await createWallets({ accountId });

      // 5) Create any add'l wallet groups past first index 0 (which was already created w/account)
      if (numWalletGroupsToCreate > 1) {
        const walletGroupsToCreate = [];

        for (let i = 1; i < numWalletGroupsToCreate; i++) {
          walletGroupsToCreate.push({ walletIndex: BigInt(i), accountId });
        }

        await createWalletGroups(walletGroupsToCreate);
      }

      // 5) Create any add'l wallets for each chain + network past default 10, if creating more than 10 wallet groups.
      if (numWalletGroupsToCreate > NUMBER_OF_ADDRESSES) {
        for (let i = NUMBER_OF_ADDRESSES; i < numWalletGroupsToCreate; i++) {
          // Must await in loop. Cannot create mass wallets to db all at once.
          // eslint-disable-next-line no-await-in-loop
          await createWalletsAtIndex({ index: BigInt(i), accountId });
        }
      }

      setSubmitProgress(
        (parseInt(numMnemonics) - numMnemonicsToCreate + 1) / parseInt(numMnemonics),
      );
      setNumMnemonicsToCreate((prev) => prev - 1);
    } catch (err) {
      toast.show(formatMessage(messages.dataSeedingCreateMnemonicsSubmitError));
      setIsSubmitting(false);
      setSubmitProgress(0);
    }
  }, [
    numWalletGroups,
    authState?.appLockType,
    sendCreateWalletsPostRequest,
    createAccountForMnemonic,
    createActiveWalletGroupAtIndex,
    createWallets,
    numMnemonics,
    numMnemonicsToCreate,
    pinState,
    createWalletGroups,
    createWalletsAtIndex,
    toast,
    formatMessage,
  ]);

  useEffect(
    function createMnemonics() {
      if (prevNumMnemonicsToCreate === 1 && numMnemonicsToCreate === 0) {
        setIsSubmitting(false);
        toast.show(
          formatMessage(messages.dataSeedingCreateMnemonicsSubmitSuccess, {
            numMnemonics: parseInt(numMnemonics),
          }),
        );
        goBack();
        return;
      }

      if (numMnemonicsToCreate === 0 || prevNumMnemonicsToCreate === numMnemonicsToCreate) return;

      createSingleMnemonic();
    },
    [
      createSingleMnemonic,
      formatMessage,
      numMnemonicsToCreate,
      prevNumMnemonicsToCreate,
      toast,
      numMnemonics,
      goBack,
    ],
  );

  const getPinIfNeeded = useCallback(async (): Promise<string> => {
    return new Promise((resolve) => {
      if (authState?.appLockType === 'pin') {
        triggerAuth({
          accountId: activeAccountId,
          successCallback: (_, pin) => {
            if (pin) {
              resolve(pin);
            }
          },
          cancelledCallback: () => {
            setIsSubmitting(false);
          },
          mnemonicAccessContext: MnemonicAccessContext.DebugMenu,
        });
      } else {
        resolve('');
      }
    });
  }, [activeAccountId, authState?.appLockType, triggerAuth]);

  const handleSubmit = useCallback(
    async function handleSubmit() {
      setIsSubmitting(true);
      setSubmitProgress(0);
      setPinState(await getPinIfNeeded());
      setNumMnemonicsToCreate(parseInt(numMnemonics));
    },
    [getPinIfNeeded, numMnemonics],
  );

  return (
    <Screen navBar={navBar} scrollable>
      <VStack spacingHorizontal={3} gap={2}>
        <TextBody
          spacingTop={3}
          testID="recovery-phrase-description"
          color="foregroundMuted"
          spacingBottom={2}
        >
          {formatMessage(messages.dataSeedingCreateMnemonicsDescription)}
        </TextBody>
        <TextInput
          label={formatMessage(messages.dataSeedingNumMnemonicsInputLabel)}
          onChangeText={setNumMnemonics}
          value={numMnemonics}
          keyboardType="number-pad"
        />
        <TextInput
          label={formatMessage(messages.dataSeedingNumWalletGroupsInputForCreateMnemonicsLabel)}
          onChangeText={setNumWalletGroups}
          value={numWalletGroups}
          keyboardType="number-pad"
        />
        <Button
          block
          compact
          onPress={handleSubmit}
          loading={isSubmitting}
          disabled={!parseInt(numMnemonics) || !parseInt(numWalletGroups)}
        >
          {formatMessage(messages.dataSeedingCreateMnemonicsTitle)}
        </Button>
        {isSubmitting && <ProgressBar progress={submitProgress} />}
      </VStack>
    </Screen>
  );
}

import { useCallback, useMemo, useState } from 'react';
import { useIntl } from 'react-intl';
import { ETHEREUM_SYMBOL } from 'cb-wallet-data/chains/AccountBased/Ethereum/constants';
import { useCheckIfAccountExists } from 'cb-wallet-data/stores/Accounts/hooks/useCheckIfAccountExists';
import { useSaveAndSetAccount } from 'cb-wallet-data/stores/Accounts/hooks/useSaveAndSetAccount';
import { Account } from 'cb-wallet-data/stores/Accounts/models/Account';
import { AccountType } from 'cb-wallet-data/stores/Accounts/models/AccountTypes';
import { ExistingAccountError } from 'cb-wallet-data/stores/Accounts/utils/existingAccountError';
import { useCreateActiveWalletGroupAtIndex } from 'cb-wallet-data/stores/WalletGroups/hooks/useCreateActiveWalletGroupAtIndex';
import { importAddressesByBlockchain } from 'cb-wallet-data/stores/Wallets/utils/importAddressesByBlockchain';
import { TextInput } from '@cbhq/cds-mobile/controls/TextInput';
import { VStack } from '@cbhq/cds-mobile/layout';
import { TextBody } from '@cbhq/cds-mobile/typography';

import { Button } from ':rn/cds-wallet/components/interactables/Button';
