import { NavBarConfig } from ':rn/cds-wallet/components/NavBar/NavBar';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { messages } from './util/messages';

export function DataSeedingCreateSCWAccount() {
  const { formatMessage } = useIntl();
  const toast = useRateLimitedToast({});
  const { goBack } = useStackNavigation();

  const [addressForAccount, setAddressForAccount] = useState('');
  const [status, setStatus] = useState('ready'); // ready, pending

  const saveAndSetAccount = useSaveAndSetAccount();
  const checkIfAccountExists = useCheckIfAccountExists();
  const createActiveWalletGroupAtIndex = useCreateActiveWalletGroupAtIndex();

  const navBar = useMemo<NavBarConfig>(
    () => ({ title: formatMessage(messages.dataSeedingSCWAccountTitle), left: 'back' }),
    [formatMessage],
  );

  /**
   * WIP function to experiment with what's needed to create a SCW account.
   */
  const createSCWAccount = useCallback(
    async function createSCWAccount() {
      // TODO [jason] Figure out steps 1-5 in rn
      // 1) Get a nonce & generate passkey registration options
      // 2) Ask authenticator to register a new passkey
      // 3) Build factory call data and get counterfactual address
      // 4) Create session and user on backend
      // 5) Save session to local storage

      // 6) Create the account record and save to client db.
      // TODO [jason]: Will likely become a hook like useCreateAccountForSCW.
      const account = new Account({
        type: AccountType.SCW,
        primaryAddressChain: ETHEREUM_SYMBOL,
        primaryAddress: addressForAccount,
        hasCompletedBackupFlow: true,
      });

      if (checkIfAccountExists(account.id)) {
        throw new ExistingAccountError(account.id);
      }

      await saveAndSetAccount(account);

      // 7) Create single associated wallet group (scw has no multi-wallet support)
      await createActiveWalletGroupAtIndex({
        accountId: account.id,
        walletIndex: 0n,
      });

      // 8) Creates required wallet + address records
      // TODO [jason]: How can we more efficiently create wallet + address records and balance refresh for only supported chains?
      const importableAddresses = {
        [ETHEREUM_SYMBOL]: [
          {
            index: 0n,
            address: addressForAccount,
            derivationPath: addressForAccount,
            accountId: account.id,
          },
        ],
      };

      await importAddressesByBlockchain(importableAddresses);
    },
    [addressForAccount, saveAndSetAccount, checkIfAccountExists, createActiveWalletGroupAtIndex],
  );

  const handleSubmit = useCallback(
    async function handleSubmit() {
      setStatus('pending');

      try {
        await createSCWAccount();
      } catch (err) {
        toast.show(formatMessage(messages.dataSeedingSCWAccountSubmitError));
        setStatus('ready');
      }
      toast.show(
        formatMessage(messages.dataSeedingSCWAccountSubmitSuccess, {
          address: addressForAccount,
        }),
      );
      goBack();
    },
    [createSCWAccount, toast, formatMessage, goBack, addressForAccount],
  );

  return (
    <Screen navBar={navBar} scrollable>
      <VStack spacingHorizontal={3} gap={2}>
        <TextBody spacingTop={3} color="foregroundMuted" spacingBottom={2}>
          {formatMessage(messages.dataSeedingSCWAccountDesc)}
        </TextBody>
        <TextInput
          label={formatMessage(messages.dataSeedingSCWAddressInputLabel)}
          onChangeText={setAddressForAccount}
          value={addressForAccount}
        />
        <Button
          block
          compact
          onPress={handleSubmit}
          loading={status === 'pending'}
          disabled={!addressForAccount}
        >
          {formatMessage(messages.dataSeedingCreateAccount)}
        </Button>
      </VStack>
    </Screen>
  );
}

import { useCallback, useMemo, useState } from 'react';
import { useIntl } from 'react-intl';
import { MnemonicAccessContext } from 'cb-wallet-analytics/auth';
import { useCreateAccountForMnemonic } from 'cb-wallet-data/stores/Accounts/hooks/useCreateAccountForMnemonic';
import { deriveDeterministicAccountIdForMnemonic } from 'cb-wallet-data/stores/Accounts/utils/deriveDeterministicAccountIdForMnemonic';
import { useCreateActiveWalletGroupAtIndex } from 'cb-wallet-data/stores/WalletGroups/hooks/useCreateActiveWalletGroupAtIndex';
import { useCreateWallets } from 'cb-wallet-data/stores/Wallets/hooks/useCreateWallets';
import { useRecoilValue } from 'recoil';
import { TextInput } from '@cbhq/cds-mobile/controls/TextInput';
