import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import {
  saveMnemonicForAccountUsingBiometrics,
  saveMnemonicForAccountUsingPIN,
} from ':rn/shared/auth/Auth';
import { authStateAtom } from ':rn/shared/auth/stores/authState';
import { useMnemonic } from ':rn/shared/hooks/useMnemonic';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { messages } from './util/messages';

/**
 * Displays a screen for development build only, which allows
 * the user to create an account from an inputted mnemonic.
 */
export function DataSeedingImportMnemonicAccount() {
  const { formatMessage } = useIntl();
  const toast = useRateLimitedToast({});
  const { goBack } = useStackNavigation();

  const authState = useRecoilValue(authStateAtom);
  const { triggerAuth } = useMnemonic({ requireAuthentication: true });

  const createAccount = useCreateAccountForMnemonic();
  const createActiveWalletGroupAtIndex = useCreateActiveWalletGroupAtIndex();
  const createWallets = useCreateWallets();

  const [mnemonicValue, setMnemonicValue] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  /**
   * Used by the <Screen> component to display the title and navigation
   * at the top of the screen.
   */
  const navBar = useMemo<NavBarConfig>(
    () => ({ title: formatMessage(messages.dataSeedingImportMnemonicAccountTitle), left: 'back' }),
    [formatMessage],
  );

  /**
   * Handles submission of form to create the account with inputted
   * mnemonic seed phrase.
   */
  const handleSubmit = useCallback(
    async function handleSubmit() {
      setIsSubmitting(true);

      try {
        // 1) Derive accountId
        const accountId = await deriveDeterministicAccountIdForMnemonic({
          mnemonic: mnemonicValue,
        });
        // 2) Create the client-side account, and get a account ID.
        await createAccount({ mnemonic: mnemonicValue });

        // 3) Save the mnemonic in the device storage with created account ID.
        if (authState?.appLockType === 'pin') {
          triggerAuth({
            accountId,
            successCallback: (_, pin) => {
              if (pin) {
                saveMnemonicForAccountUsingPIN({ mnemonic: mnemonicValue, accountId, pin });
              }
            },
            mnemonicAccessContext: MnemonicAccessContext.DebugMenu,
          });
        } else {
          await saveMnemonicForAccountUsingBiometrics({
            mnemonic: mnemonicValue,
            accountId,
            enforceShowBiometricsPrompt: false,
          });
        }

        // 4) Creates the first WalletGroup for the account.
        await createActiveWalletGroupAtIndex({
          accountId,
          walletIndex: 0n,
        });

        // 5) Create the client-side wallets with created account ID.
        await createWallets({ accountId });

        toast.show(formatMessage(messages.dataSeedingMnemonicAccountSubmitSuccess));
        goBack(); // navigate back to main data seeding screen
      } catch (err) {
        toast.show(formatMessage(messages.dataSeedingMnemonicAccountSubmitError));
        setIsSubmitting(false);
      }
    },
    [
      createAccount,
      mnemonicValue,
      authState?.appLockType,
      createActiveWalletGroupAtIndex,
      createWallets,
      toast,
      formatMessage,
      goBack,
      triggerAuth,
    ],
  );

  return (
    <ScreenBoundary>
      <Screen navBar={navBar} scrollable>
        <VStack spacingHorizontal={3} gap={2}>
          <TextInput
            label={formatMessage(messages.dataSeedingImportMnemonicInputLabel)}
            onChangeText={setMnemonicValue}
            value={mnemonicValue}
            multiline
            numberOfLines={3}
            start={<Box spacingEnd={1} height={110} />}
          />
          <Button
            block
            compact
            onPress={handleSubmit}
            loading={isSubmitting}
            disabled={!mnemonicValue}
          >
            {formatMessage(messages.dataSeedingImportMnemonicAccountTitle)}
          </Button>
        </VStack>
      </Screen>
    </ScreenBoundary>
  );
}

import { useCallback, useMemo, useRef, useState } from 'react';
import { useIntl } from 'react-intl';
import { MnemonicAccessContext } from 'cb-wallet-analytics/auth';
import { useAccountsWithWalletGroups } from 'cb-wallet-data/stores/Accounts/hooks/useAccountsWithWalletGroups';
import { useActiveAccountId } from 'cb-wallet-data/stores/Accounts/hooks/useActiveAccountId';
import { useDefaultAccountName } from 'cb-wallet-data/stores/Accounts/hooks/useDefaultAccountName';
import { Account } from 'cb-wallet-data/stores/Accounts/models/Account';
import { DecryptedMnemonicsHandle } from 'cb-wallet-data/stores/Accounts/models/DecryptedMnemonicsHandle';
import { isMnemonicResult } from 'cb-wallet-data/stores/Accounts/models/NonMnemonicUnlockResult';
import { useCreateWalletGroups } from 'cb-wallet-data/stores/WalletGroups/hooks/useCreateWalletGroups';
import { useWalletGroups } from 'cb-wallet-data/stores/WalletGroups/hooks/useWalletGroups';
import {
  WalletGroup,
  WalletGroupConstructorOptions,
} from 'cb-wallet-data/stores/WalletGroups/models/WalletGroup';
import { useCreateWalletsAtIndex } from 'cb-wallet-data/stores/Wallets/hooks/useCreateWalletsAtIndex';
import { walletsAtom } from 'cb-wallet-data/stores/Wallets/state';
import { useRecoilValue } from 'recoil';
import { Radio } from '@cbhq/cds-mobile/controls';
import { TextInput } from '@cbhq/cds-mobile/controls/TextInput';
import { VStack } from '@cbhq/cds-mobile/layout';
import { TextLabel1, TextLabel2 } from '@cbhq/cds-mobile/typography';
import { ProgressBar } from '@cbhq/cds-mobile/visualizations/ProgressBar';

import { ScreenBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ScreenBoundary';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Screen } from ':rn/cds-wallet/components/layout/Screen';
import { NavBarConfig } from ':rn/cds-wallet/components/NavBar/NavBar';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';
import { useMnemonic } from ':rn/shared/hooks/useMnemonic';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { messages } from './util/messages';

const DEFAULT_NUM_WALLETS = 15;
const MAX_NUM_WALLETS = 100;

/**
 * Given the existing wallet groups and the number of wallet groups
 * that need to be created, determine all the indexes to be created.
 */
function computeIndexesToCreate(currentWalletGroups: WalletGroup[], numWalletGroups: number) {
  const usedIndexes = currentWalletGroups.map((group) => Number(group.walletIndex)).sort();
  const indexesToCreate = [];

  for (let i = 0; i < Number(numWalletGroups); i++) {
    let nextAvailableIdx = 0;

    while (usedIndexes.includes(nextAvailableIdx)) {
      nextAvailableIdx++;
    }

    indexesToCreate.push(nextAvailableIdx);
    usedIndexes.push(nextAvailableIdx);
  }

  return indexesToCreate;
}

/**
 * Displays a screen for development build only, which allows
 * the user to create wallet groups in bulk.
 */
export function DataSeedingWallets() {
  const { formatMessage } = useIntl();
  const toast = useRateLimitedToast({});
  const { goBack } = useStackNavigation();
  const { triggerAuth } = useMnemonic({ requireAuthentication: false, fetchAllMnemonics: false }); // TODO: fetchAllMnemonics=true
  const mnemonicsRef = useRef<DecryptedMnemonicsHandle>({}); // Hack to get around not being able to call triggerAuth multiple times between renders.

  const allWallets = useRecoilValue(walletsAtom);
  const allWalletGroups = useWalletGroups();
  const activeAccountId = useActiveAccountId();
  const accounts = useAccountsWithWalletGroups();
  const getAccountDisplayName = useDefaultAccountName();
  const createWalletGroups = useCreateWalletGroups();
  const createWalletsAtIndex = useCreateWalletsAtIndex();

  const [selectedAccountId, setSelectedAccountId] = useState(activeAccountId);
  const [numWalletGroups, setNumWalletGroups] = useState(String(DEFAULT_NUM_WALLETS));
  const [submitProgress, setSubmitProgress] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);

  /**
   * Used by the <Screen> component to display the title and navigation
   * at the top of the screen.
   */
  const navBar = useMemo<NavBarConfig>(
    () => ({ title: formatMessage(messages.dataSeedingWalletsTitle), left: 'back' }),
    [formatMessage],
  );

  /**
   * Used to display a total number of wallets for each account.
   */
  const walletCountByAccount = useMemo(() => {
    return Object.values(allWallets).reduce((acc, { accountId }) => {
      acc[accountId] = acc[accountId] ?? 0;
      acc[accountId]++;
      return acc;
    }, {} as Record<Account['id'], number>);
  }, [allWallets]);

  /**
   * Array of account options to map over and display with CDS Radios,
   * so the user can select which account to add wallet groups to.
   */
  const accountOptions = useMemo(() => {
    return accounts
      .filter(({ isMnemonicAccount }) => isMnemonicAccount)
      .sort((a, b) => a.createdAt.getTime() - b.createdAt.getTime())
      .map((account) => ({
        value: account.id,
        label: getAccountDisplayName(account),
        info: formatMessage(messages.dataSeedingDefaultAccountInfo, {
          numWallets: walletCountByAccount[account.id],
          numWalletGroups: account.walletGroups.length,
        }),
      }));
  }, [accounts, formatMessage, walletCountByAccount, getAccountDisplayName]);

  /**
   * Error message to display below text input, when user enters a number
   * greater than the max.
   */
  const maxWalletsErrorMessage = useMemo(() => {
    if (Number(numWalletGroups) > MAX_NUM_WALLETS) {
      return formatMessage(messages.dataSeedingNumWalletsInputMaxError, {
        max: MAX_NUM_WALLETS,
      });
    }
    return '';
  }, [numWalletGroups, formatMessage]);

  /**
   * Used to determine whether the submit button is disabled.
   * User must enter a number of wallet groups to create, which is below the max.
   */
  const canSubmit = useMemo(() => {
    return !maxWalletsErrorMessage && Boolean(numWalletGroups);
  }, [maxWalletsErrorMessage, numWalletGroups]);

  /**
   * Handles making radio group account selection to add wallet groups to
   * Handler is required because of how CDS RadioGroup onChange is typed.
   */
  const handleSelectAccountId = useCallback(
    (value?: string) => setSelectedAccountId(value ?? ''),
    [setSelectedAccountId],
  );

  /**
   * Function to unlock the mnemonic and possibly present unlock screen.
   * Required during wallet creation, when createWalletsAtIndex is called.
   */
  const unlockMnemonic = useCallback(
    async function unlockMnemonic(): Promise<boolean> {
      const prevFetchedMnemonics = mnemonicsRef.current;

      // Because the caller of this function (useCreateWalletsAtIndex) will execute this
      // multiple times before a re-render, we are storing mnemonic result in a ref so that
      // you're not prompted for the pin code multiple times in creating a batch of wallets.
      if (prevFetchedMnemonics[selectedAccountId]) {
        return new Promise((res) => {
          res(prevFetchedMnemonics[selectedAccountId]);
        });
      }

      return new Promise((res) => {
        triggerAuth({
          accountId: selectedAccountId,
          successCallback: (universalUnlockResult) => {
            if (isMnemonicResult(universalUnlockResult)) {
              const mnemonicsHandle = universalUnlockResult;
              mnemonicsRef.current = { ...mnemonicsHandle };
              res(mnemonicsHandle[selectedAccountId]);
            }
          },
          mnemonicAccessContext: MnemonicAccessContext.DebugMenu,
        });
      });
    },
    [selectedAccountId, triggerAuth],
  );

  /**
   * Handles submission of form to create wallet groups + wallets for a
   * selected account.
   */
  const handleSubmit = useCallback(
    async function handleSubmit() {
      await unlockMnemonic();
      setIsSubmitting(true);

      try {
        const walletGroupsOfAccount = allWalletGroups.filter(
          (group) => group.accountId === selectedAccountId,
        );

        const indexesToCreate = computeIndexesToCreate(
          walletGroupsOfAccount,
          Number(numWalletGroups),
        );

        let numWalletGroupsCreated = 0;

        for (const idx of indexesToCreate) {
          const createWalletsPromise = createWalletsAtIndex({
            index: BigInt(idx),
            accountId: selectedAccountId,
          });

          const walletGroupOptions: WalletGroupConstructorOptions = {
            walletIndex: BigInt(idx),
            accountId: selectedAccountId,
          };
          const createWalletGroupsPromise = createWalletGroups([walletGroupOptions]);

          // Note: This is obviously a bit slower than async, but results to the database seem
          // to be more consistent executing synchronously, and progress feedback can be provided
          // to the user so it's more clear what's happening during this long submit.
          // eslint-disable-next-line no-await-in-loop
          await Promise.all([createWalletsPromise, createWalletGroupsPromise]);

          numWalletGroupsCreated++;
          setSubmitProgress(numWalletGroupsCreated / indexesToCreate.length);
        }

        toast.show(
          formatMessage(messages.dataSeedingWalletsSubmitSuccess, {
            numWalletGroups: numWalletGroupsCreated,
          }),
        );
        goBack(); // navigate back to main data seeding screen
      } catch (err) {
        toast.show(formatMessage(messages.dataSeedingWalletsSubmitError));
        setIsSubmitting(false);
        setSubmitProgress(0);
      }
    },
    [
      unlockMnemonic,
      allWalletGroups,
      numWalletGroups,
      toast,
      formatMessage,
      goBack,
      selectedAccountId,
      createWalletsAtIndex,
      createWalletGroups,
    ],
  );

  return (
    <ScreenBoundary>
      <Screen navBar={navBar} scrollable>
        <VStack spacingHorizontal={3} gap={2}>
          {accountOptions.map(({ value, label, info }) => (
            <>
              <Radio
                key={value}
                value={value}
                checked={selectedAccountId === value}
                onChange={handleSelectAccountId}
              >
                <VStack>
                  <TextLabel1>{label}</TextLabel1>
                  <TextLabel2>{info}</TextLabel2>
                </VStack>
              </Radio>
            </>
          ))}
          <TextInput
            label={formatMessage(messages.dataSeedingNumWalletsInputLabel)}
            onChangeText={setNumWalletGroups}
            value={numWalletGroups}
            keyboardType="numeric"
            helperText={maxWalletsErrorMessage}
            variant={maxWalletsErrorMessage ? 'negative' : undefined}
          />
          <Button block compact onPress={handleSubmit} loading={isSubmitting} disabled={!canSubmit}>
            {formatMessage(messages.dataSeedingWalletsTitle)}
          </Button>
          {isSubmitting && <ProgressBar progress={submitProgress} />}
        </VStack>
      </Screen>
    </ScreenBoundary>
  );
}

