type DisplayTextAlertCellProps = {
  url?: string;
};

function DisplayTextAlertCell({ url }: DisplayTextAlertCellProps) {
  const displayDebugNotification = useCallback(
    async function displayDebugNotification(): Promise<void> {
      const channelId = await notifee.createChannel({
        id: 'debug',
        name: 'Debug Android Channel',
      });

      const payload: Notification = {
        title: url ? 'Deeplinking Notification' : 'Notification Title',
        body: url || 'Main body content of the notification',
        android: ((): NotificationAndroid | undefined => {
          if (!device.isAndroid) {
            return;
          }

          return {
            channelId,
            smallIcon: GROWTH_NOTIFICATION_ICON,
            pressAction: {
              id: 'default',
            },
          };
        })(),
        data: ((): Record<string, string> => {
          if (!url) {
            return {};
          }

          return {
            url,
          };
        })(),
      };

      notifee.displayNotification(payload).catch((error) =>
        cbReportError({
          error,
          context: 'notifications-error',
          severity: 'error',
          isHandled: false,
        }),
      );
    },
    [url],
  );

  const displayTextAlert = useCallback(async () => {
    displayDebugNotification();
  }, [displayDebugNotification]);

  return <SettingsCell title="Display Push Notifications" onPress={displayTextAlert} />;
}

