export const DebugQrGenerator = memo(function DebugQrGenerator() {
  const [value, setValue] = useState('');
  const [logo, setLogo] = useState('');
  const [description, setDescription] = useState('');
  const [isPoapTab, setIsPoapTab] = useState(true);

  const activeWalletGroupId = useActiveWalletGroupId();
  const wallets = useWalletsForWalletGroupId(activeWalletGroupId);
  // TODO this probably isn't the right function for this
  const wallet = getWalletByLegacyTokenApprovalChainIdentifier({
    wallets,
    legacyTokenApprovalChainIdentifier: 'BLOCKCHAIN_ETHEREUM',
  });

  const viewShotRef = useRef<ViewShot>(null);

  const logoUrl = useMemo(() => {
    if (!logo) {
      return undefined;
    }
    return { uri: logo };
  }, [logo]);

  useEffect(() => {
    setValue('');
  }, [isPoapTab]);

  const handleValueChange = useCallback(
    (text: string) => {
      const calculateValue = async () => {
        const trimmedText = text.trim();
        if (!trimmedText) {
          setValue('');
          return;
        }
        if (isPoapTab) {
          setValue(`https://go.cb-w.com/dapp?cb_url=${encodeURIComponent(trimmedText)}`);
          return;
        }
        if (!isValidAddress(trimmedText) && !isEns(trimmedText)) {
          return;
        }
        const destination = await safeResolveDestination(trimmedText, wallet!);
        const address = destination?.address;
        setValue(getDeeplinkIntoMessaging({ address }));
        setDescription(text);
      };
      calculateValue();
    },
    [isPoapTab, wallet],
  );

  const handleLogoChange = useCallback((text: string) => {
    setLogo(text);
  }, []);

  const handleDescriptionChange = useCallback((text: string) => {
    setDescription(text);
  }, []);

  const handlePress = useCallback(async () => {
    if (Platform.OS === 'android') {
      const granted = await PermissionsAndroid.request(
        PermissionsAndroid.PERMISSIONS.WRITE_EXTERNAL_STORAGE,
        {
          title: 'Storage Permission',
          message: 'App needs access to your storage to download Photos.',
          buttonPositive: 'Ok',
        },
      );

      if (granted !== PermissionsAndroid.RESULTS.GRANTED) {
        alert('You need to give permission to save the image');
        return;
      }
    }

    viewShotRef.current
      ?.capture?.()
      .then((uri) => {
        Share.share({
          title: 'QR Code',
          message: 'Here is the QR code you requested.',
          url: uri,
        });
      })
      .catch(() => {
        alert('Failed to save image');
      });
  }, []);

  const handleTabPress = useCallback((val: boolean) => {
    return () => {
      setIsPoapTab(val);
    };
  }, []);

  return (
    <Screen navBar={navBar} scrollable>
      <HStack gap={1}>
        <TabButton onPress={handleTabPress(true)} text="POAP" isActive={isPoapTab} />
        <TabButton onPress={handleTabPress(false)} text="Messaging" isActive={!isPoapTab} />
      </HStack>
      <VStack justifyContent="center" alignItems="center" spacingTop={2}>
        {isPoapTab && (
          <VStack width="100%" gap={2}>
            <TextInput
              placeholder="Link for QR code"
              onChangeText={handleValueChange}
              autoCapitalize="none"
            />
            <TextInput
              placeholder="Image Url"
              onChangeText={handleLogoChange}
              autoCapitalize="none"
            />
            <TextInput
              placeholder="QR Description"
              onChangeText={handleDescriptionChange}
              autoCapitalize="none"
            />
          </VStack>
        )}
        {!isPoapTab && (
          <TextInput
            placeholder="ENS Name, or Address"
            onChangeText={handleValueChange}
            autoCapitalize="none"
          />
        )}
        <ViewShot key="debug-menu-view-shot" ref={viewShotRef} options={options}>
          <VStack
            spacingVertical={4}
            gap={1}
            justifyContent="center"
            alignItems="center"
            width="100%"
          >
            {value && (
              <QRCodeSVG
                isAsyncDataFetched
                value={value}
                size={QR_CODE_SIZE}
                logo={logoUrl}
                logoBorderRadius={QR_LOGO_RADIUS}
                logoSize={QR_LOGO_SIZE}
              />
            )}
            {description && value && <TextTitle1>{description}</TextTitle1>}
          </VStack>
        </ViewShot>
        {value && (
          <Button block spacing={2} onPress={handlePress}>
            Share QR
          </Button>
        )}
      </VStack>
    </Screen>
  );
});

