type SendTransactionComposerProps = {
  wallet?: Wallet;
  value?: bigint;
  onEdit?: () => void;
};

function SendTransactionComposer({ wallet, value, onEdit }: SendTransactionComposerProps) {
  const { formatToFiat, formatToCrypto } = useCurrencyFormatter();
  const fiatValue = useMemo(
    () =>
      wallet
        ? formatToFiat(
            wallet.currencyCode,
            wallet.decimals,
            value,
            false,
            wallet.contractAddress,
            wallet.network,
            wallet.blockchain,
          )
        : undefined,
    [formatToFiat, value, wallet],
  );

  const cryptoValue = useMemo(
    () =>
      wallet
        ? formatToCrypto({
            currencyCode: wallet.currencyCode,
            decimals: wallet.decimals,
            value,
            overridePrivacy: true,
          })
        : undefined,
    [formatToCrypto, value, wallet],
  );
  return (
    <HStack
      width="100%"
      spacing={3}
      borderRadius="rounded"
      bordered
      borderColor="secondary"
      alignItems="center"
      justifyContent="space-between"
    >
      {wallet && value ? (
        <VStack>
          <HStack alignItems="center" gap={2} spacingBottom={2}>
            <AssetIcon
              currencyCode={wallet.currencyCode.rawValue}
              network={wallet.network}
              showNetworkIcon
              iconUrl={wallet.imageURL}
            />
            <TextHeadline>{wallet.displayName}</TextHeadline>
          </HStack>

          <HStack>
            <TextHeadline>{fiatValue ?? ''}</TextHeadline>
          </HStack>
          <HStack>
            <TextBody color="foregroundMuted">{cryptoValue ?? ''}</TextBody>
          </HStack>
        </VStack>
      ) : (
        <TextBody>No wallet selected</TextBody>
      )}

      <IconButton name="pencil" onPress={onEdit} />
    </HStack>
  );
}

function DebugSignSendTransactionTrayContent() {
  const navBar = useMemo<NavBarConfig>(
    () => ({ title: 'Send Transaction Tray', left: 'back' }),
    [],
  );
  const { formatMessage } = useIntl();

  const activeWalletGroupId = useActiveWalletGroupId();
  const activeWallets = useWalletsForWalletGroupId(activeWalletGroupId);

  const [valueState, setValueState] = useState<AmountPickerState>({
    wallet: activeWallets[0],
    amount: 0n,
  });

  const isSponsoredTx = Boolean(useGetSponsoredSendInfo(valueState.wallet ?? activeWallets[0]));

  const [destinationAddress, setDestinationAddress] = useState('');

  const [errorMessageSync, setErrorMessageSync] = useState('');

  const [blockchainRawValue, setBlockchainRawValue] = useState('');
  const [contractAddress, setContractAddress] = useState('');
  const [chainId, setChainId] = useState('');
  const [txValue, setTxValue] = useState('0');
  const [toAddress, setToAddress] = useState('');

  const [errorMessageAsync, setErrorMessageAsync] = useState('');
  const [isLoading, setLoading] = useState(false);

  const { show } = useRateLimitedToast({});

  const { openModal, closeModal } = useModal();

  const handleAssetPickerChange = useCallback(
    (newState: AmountPickerState) => {
      setValueState(newState);
      setErrorMessageSync('');
      closeModal();
    },
    [closeModal],
  );

  const { openSignSendTransactionTray } = useSignSendTransactionTray({
    source: 'debug-menu',
  });

  const handleSuccess = useCallback(() => {
    show(formatMessage(messages.successMessage));
  }, [formatMessage, show]);

  const signSendTransactionAsync = useSignSendTransactionTrayAsync({ source: 'debug-menu' });

  const handleSubmitSync = useCallback(async () => {
    try {
      if (!valueState?.wallet || !valueState?.amount || !destinationAddress) {
        throw new Error('missing params');
      }

      const { wallet, amount } = valueState;

      const unsignedTx = await generateUnsignedTx({
        wallet,
        amount: {
          kind: amount === wallet.balance ? TransactionKind.ENTIRE_BALANCE : TransactionKind.AMOUNT,
          value: amount,
        },
        is1559Transaction: isNetwork1559Enabled(wallet.network),
        address: destinationAddress,
        metadata: new Map(),
      });

      if (!unsignedTx.transaction) throw new Error('failed to generate transaction');

      openSignSendTransactionTray({
        onSignSuccess: handleSuccess,
        transaction: unsignedTx.transaction,
        wallet,
        destination: { type: 'address', label: destinationAddress, address: destinationAddress },
        isTxSponsored: isSponsoredTx,
      });
    } catch (err) {
      setErrorMessageSync((err as Error).message);
    }
  }, [destinationAddress, handleSuccess, isSponsoredTx, openSignSendTransactionTray, valueState]);

  const handleSubmitAsync = useCallback(async () => {
    setLoading(true);
    try {
      const { result } = await signSendTransactionAsync({
        walletInfo: {
          blockchainRawValue,
          chainId: chainId.length > 0 ? chainId : undefined,
          contractAddress: contractAddress.length > 0 ? contractAddress : undefined,
        },
        amount: txValue.length > 0 ? { value: txValue } : undefined,
        toAddress,
      });
      setErrorMessageAsync('');
      if (result) {
        handleSuccess();
      }
    } catch (err) {
      setErrorMessageAsync((err as Error).message);
    } finally {
      setLoading(false);
    }
  }, [
    blockchainRawValue,
    chainId,
    contractAddress,
    handleSuccess,
    signSendTransactionAsync,
    toAddress,
    txValue,
  ]);

  const handleEditPress = useCallback(() => {
    openModal(
      <Modal
        testID="debug-sign-send-transaction-tray-modal"
        visible
        onRequestClose={closeModal}
        hideDividers
      >
        <ModalHeader />
        <AmountPicker
          value={valueState}
          onSubmit={handleAssetPickerChange}
          showMaxButton
          showAvailableBalance
          walletList={activeWallets}
        />
      </Modal>,
    );
  }, [activeWallets, closeModal, handleAssetPickerChange, openModal, valueState]);

  return (
    <Screen navBar={navBar} scrollable>
      <VStack spacing={3} flexGrow={1}>
        <ScrollView>
          <TextTitle2 spacingBottom={2}>{formatMessage(messages.syncApproachTitle)}</TextTitle2>
          <SendTransactionComposer
            onEdit={handleEditPress}
            wallet={valueState.wallet}
            value={valueState.amount}
          />
          <VStack spacingBottom={3} spacingTop={2}>
            <TextLabel2 spacingBottom={0.5}>To address:</TextLabel2>
            <TextInput onChangeText={setDestinationAddress} />
            <TextLabel2 color="negative" spacingTop={0.5}>
              {errorMessageSync}
            </TextLabel2>
          </VStack>
          <Box spacingBottom={2}>
            <Button variant="primary" onPress={handleSubmitSync}>
              {formatMessage(messages.ctaButtonLabel)}
            </Button>
          </Box>
          <Divider spacingVertical={2} />

          <TextTitle2 spacingBottom={2}>{formatMessage(messages.asyncApproachTitle)}</TextTitle2>
          <VStack spacingBottom={3} spacingTop={2}>
            <Box spacingBottom={2}>
              <TextLabel2 spacingBottom={0.5}>To address:</TextLabel2>
              <TextInput onChangeText={setToAddress} />
            </Box>
            <Box spacingBottom={2}>
              <TextLabel2 spacingBottom={0.5}>Blockchain:</TextLabel2>
              <TextInput onChangeText={setBlockchainRawValue} />
            </Box>
            <Box spacingBottom={2}>
              <TextLabel2 spacingBottom={0.5}>Contract Address (optional):</TextLabel2>
              <TextInput onChangeText={setContractAddress} />
            </Box>
            <Box spacingBottom={2}>
              <TextLabel2 spacingBottom={0.5}>Chain ID (optional):</TextLabel2>
              <TextInput onChangeText={setChainId} />
            </Box>
            <Box spacingBottom={2}>
              <TextLabel2 spacingBottom={0.5}>Transfer value (in crypto):</TextLabel2>
              <TextInput onChangeText={setTxValue} />
            </Box>
            <TextLabel2 color="negative" spacingTop={0.5}>
              {errorMessageAsync}
            </TextLabel2>
            <Box spacingVertical={2}>
              <Button
                variant="primary"
                onPress={handleSubmitAsync}
                loading={isLoading}
                disabled={isLoading}
              >
                {formatMessage(messages.ctaButtonLabel)}
              </Button>
            </Box>
          </VStack>
        </ScrollView>
      </VStack>
    </Screen>
  );
}

