function DebugSocialDefiContent() {
  const [apiKey, setApiKey] = useState(Store.get<string>(debugSocialDefiAPIKey) ?? '');
  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: 'back',
      title: 'Social Defi',
    }),
    [],
  );
  const { navigate } = useStackNavigation();
  const { formatMessage } = useIntl();
  const fetchCast = useGetCastCallback();
  const { newCastHash } = useParams<DebugParamList, 'DebugSocialDefi'>();
  const [newCast, setNewCast] = useState<V1Cast | undefined>(undefined);
  const userFid = useGetUserFid();
  const fetchUsers = useGetUsersCallback();
  const [user, setUser] = useState<V1User | undefined>({});
  const [visible, { toggleOn, toggleOff }] = useToggler(false);

  const tabMap: Record<string, ReactNode> = {
    trending: <SocialFeed type={FeedType.TRENDING} newCast={newCast} toggleOn={toggleOn} />,
    frames: <SocialFeed type={FeedType.FRAMES} newCast={newCast} toggleOn={toggleOn} />,
    debug: <DebugSocialDefiApiKey />,
  };

  useEffect(
    function setUserInfo() {
      async function fetchUserInfo() {
        if (userFid) {
          const userData = await fetchUsers({ fids: [userFid] });
          if (!(userData instanceof Error)) {
            setUser(userData?.users?.[0]);
          }
        }
      }
      fetchUserInfo();
    },
    [fetchUsers, userFid],
  );

  const [currentTab, setTab] = useState(tabs[0].id);

  const onSetTab = useCallback(function onSetTab(tab: TabState) {
    logFeedTabSwitch(tab);
    setTab(tab);
  }, []);

  const navigateToChannelsList = useCallback(() => {
    navigate('DebugSocialDefiChannels');
  }, [navigate]);

  /*  TODO: Will reinstate this code as Farcaster connect and create is enabled [WALL-37497] */
  // const navigateToCreateCast = useCallback(() => {
  //   navigate('SocialDefiCreateCast', { user });
  // }, [navigate, user]);

  const navigateToOwnProfile = useCallback(() => {
    navigate('DebugSocialDefiProfile', { profile: user });
  }, [navigate, user]);

  const fetchNewCast = useCallback(
    function fetchNewCast() {
      async function fetchNewCastData() {
        const castData = await fetchCast({
          identifier: newCastHash,
          identifierType: 'IDENTIFIER_TYPE_HASH',
        });
        if (!(castData instanceof Error)) setNewCast(castData.cast);
      }
      fetchNewCastData();
    },
    [fetchCast, newCastHash],
  );

  useEffect(
    function fetchNewCastEffect() {
      if (newCastHash) fetchNewCast();
    },
    [fetchNewCast, newCastHash],
  );

  if (!apiKey) {
    return (
      <Screen navBar={navBar}>
        <DebugSocialDefiApiKey onSetApiKey={setApiKey} />
      </Screen>
    );
  }

  return (
    <Screen navBar={navBar} hideNavBar>
      <ErrorBoundary errorFallback={<DebugSocialDefiError />}>
        <TextTitle1 spacingHorizontal={2}>{formatMessage(messages.communityTitle)}</TextTitle1>
        <HStack spacingHorizontal={2} spacingBottom={1} spacingTop={2}>
          <Button
            startIcon="lightningBolt"
            compact
            variant="secondary"
            onPress={navigateToChannelsList}
          >
            {formatMessage(messages.channelsLabel)}
          </Button>
        </HStack>
        {user && (
          <HStack alignItems="center" gap={1} spacing={1}>
            <Box
              bordered={false}
              borderRadius="roundedFull"
              background="backgroundAlternate"
              flexGrow={1}
              spacingStart={1}
              spacingHorizontal={3}
            >
              <HStack alignItems="center" alignContent="center">
                <Pressable background="transparent" onPress={toggleOn} noScaleOnPress>
                  <HStack alignContent="center" alignItems="center" gap={1}>
                    <Pressable
                      onPress={navigateToOwnProfile}
                      background="transparent"
                      noScaleOnPress
                    >
                      <Avatar alt="Sneezy" size="l" src={user.pfpUrl} />
                    </Pressable>
                    <TextHeadline spacingStart={1} color="foregroundMuted">
                      {formatMessage(messages.postingPlaceholder)}
                    </TextHeadline>
                  </HStack>
                </Pressable>
                <HStack justifyContent="flex-end" offsetEnd={1} flexGrow={3}>
                  <IconButton name="pFPS" variant="foregroundMuted" transparent />
                </HStack>
              </HStack>
            </Box>
          </HStack>
        )}
        <TabNavigation
          spacingHorizontal={2}
          value={currentTab}
          tabs={tabs}
          // @ts-expect-error since we don't use setState directly
          onChange={onSetTab}
        />
        <Suspense fallback={<SocialDefiFeedLoader />}>{tabMap[currentTab]}</Suspense>
        {visible && <FarcasterRequiredTray onCloseComplete={toggleOff} />}
      </ErrorBoundary>
    </Screen>
  );
}

type DebugSocialDefiApiKeyProps = { fullHeight?: boolean; onSetApiKey?: (key: string) => void };

function DebugSocialDefiApiKey({ fullHeight = true, onSetApiKey }: DebugSocialDefiApiKeyProps) {
  const [apiKey, setApiKey] = useState(Store.get<string>(debugSocialDefiAPIKey) ?? '');
  const [signer, setSigner] = useState(Store.get<string>(debugSocialDefiSigner) ?? '');
  const onSetKeyEnhanced = useCallback(() => {
    onSetApiKey?.(apiKey);
    Store.set(debugSocialDefiAPIKey, apiKey);
    Store.set(debugSocialDefiSigner, signer);
  }, [apiKey, onSetApiKey, signer]);

  return (
    <ScrollView>
      <VStack height={fullHeight ? '100%' : 'auto'} spacingBottom={6}>
        <HStack gap={2} alignItems="center" justifyContent="center">
          <Box flexGrow={1}>
            <VStack gap={2}>
              <TextInput
                label="Neynar API Key"
                placeholder="Enter an API Key"
                value={apiKey}
                onChangeText={setApiKey}
              />
              <TextInput
                label="Neynar Signer"
                placeholder="Enter an Signer"
                value={signer}
                onChangeText={setSigner}
              />
            </VStack>
          </Box>
          <Button onPress={onSetKeyEnhanced} spacingTop={6}>
            Save
          </Button>
        </HStack>
        {signer && (
          <Suspense
            fallback={
              <VStack gap={2} justifyContent="center" spacingTop={3} alignContent="center">
                <Loader />
                <TextBody align="center"> Fetching signer info </TextBody>
              </VStack>
            }
          >
            <ErrorBoundary errorFallback={null}>
              <AdditionalInfo signer={signer} />
            </ErrorBoundary>
          </Suspense>
        )}
        <SocialDefiCreateSigner />
      </VStack>
    </ScrollView>
  );
}

type AdditionalInfoProps = { signer: string };

export function AdditionalInfo({ signer }: AdditionalInfoProps) {
  const { data } = useFetchNeynar<SignerResponse>('signer', true, { signer });

  return (
    <>
      <TextLabel1 spacingTop={3}>Additional Info</TextLabel1>
      <HStack alignContent="space-between">
        <TextBody>Signer status: </TextBody>
        <TextBody>{data?.status}</TextBody>
      </HStack>
    </>
  );
}

type DebugSocialDefiErrorProps = { error?: string };

export function DebugSocialDefiError({ error }: DebugSocialDefiErrorProps) {
  const { formatMessage } = useIntl();
  const onSetApiKey = useCallback(() => {
    RNRestart.Restart();
  }, []);
  return (
    <>
      <VStack alignItems="center" justifyContent="center" flexGrow={1}>
        <Pictogram name="shield" dimension="64x64" />
        <TextBody spacingTop={2} align="center">
          {error ? JSON.stringify(error) : formatMessage(messages.fetchingError)}
        </TextBody>
      </VStack>
      <Box>
        <DebugSocialDefiApiKey fullHeight={false} onSetApiKey={onSetApiKey} />
      </Box>
    </>
  );
}

