type TimeWindow = Parameters<typeof useGetTrendingChannels>[0]['timeWindow'];
const DEFAULT_TIME_WINDOW: TimeWindow = 'CHANNEL_TIME_WINDOW_DAY';

type ChannelsListProps = { timeWindow?: TimeWindow; searchQuery?: string };

type ChannelListItemProps = { item: V1TrendingChannel };

function ChannelListItem({ item }: ChannelListItemProps) {
  const channelUrlSlug = getFarcasterChannelSlugFromURL(item.channel?.url || '');
  const timeAgoOrDate = useCastTimeAgoOrDate(parseInt(item.channel?.createdAt || '') * 1000);
  const { navigate } = useStackNavigation();

  const navigateToChannel = useCallback(() => {
    navigate('DebugSocialDefiChannel', { channel: item.channel });
  }, [navigate, item]);

  const channelAccessibilityLabel = `Navigate to ${item.channel?.name} channel`;
  const channelDescriptionLabel = `Channel ${item.channel?.name} created ${timeAgoOrDate}`;

  return (
    <VStack spacingHorizontal={3} spacingVertical={3}>
      <Pressable accessibilityLabel={channelAccessibilityLabel} onPress={navigateToChannel}>
        <HStack alignItems="center" gap={1}>
          <Avatar alt="Sneezy" name={item.channel?.name} size="xl" src={item.channel?.imageUrl} />

          <VStack>
            <TextHeadline>{item.channel?.name}</TextHeadline>
            <TextLegal accessibilityLabel={channelDescriptionLabel} color="foregroundMuted">
              /{channelUrlSlug}
              <Icon
                spacingTop={0.5}
                color="foregroundMuted"
                spacingHorizontal={1}
                name="blog"
                size="s"
              />
              {timeAgoOrDate}
            </TextLegal>
          </VStack>
        </HStack>
      </Pressable>
    </VStack>
  );
}

function ChannelsList({ timeWindow = DEFAULT_TIME_WINDOW, searchQuery = '' }: ChannelsListProps) {
  const { channels } = useGetTrendingChannels({ timeWindow });

  const renderItem = useCallback(({ item }: { item: V1TrendingChannel }) => {
    return <ChannelListItem item={item} />;
  }, []);

  const keyExtractor = useCallback((item: V1TrendingChannel) => item.channel!.id!, []);

  const channelsByQuery = useMemo(
    () =>
      channels?.filter((channel) =>
        searchQuery
          ? channel.channel?.name?.toLowerCase().includes(searchQuery.toLowerCase())
          : channels,
      ),
    [channels, searchQuery],
  );

  if (!channels) return null;

  return <FlatList data={channelsByQuery} renderItem={renderItem} keyExtractor={keyExtractor} />;
}

