  const [mainnets] = useDefaultNetworks();

  const networks = useMemo(
    () =>
      mainnets.map((networkItem) =>
        NetworkWithBalance.fromNetworkRawValue(networkItem.network.rawValue, new Decimal(0)),
      ),
