type Params = { item: string };

export function MessagingToggle({ item }: Params) {
  const [hasItem, setHasItem] = useState(localStorage.getItem(item) === 'true');

  const handleChange = useCallback(() => {
    if (hasItem) {
      localStorage.removeItem(item);
      setHasItem(false);
    } else {
      localStorage.setItem(item, 'true');
      setHasItem(true);
    }

    // finish toggle before restarting
    setTimeout(() => {
      RNRestart.Restart();
    }, 500);
  }, [item, hasItem]);

  return <Switch onChange={handleChange} checked={hasItem} />;
}

