import { TextHeadline } from '@cbhq/cds-mobile/typography';

import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { parseWalletLinkQRCodeText } from ':rn/screens/Scan/hooks/utils/parseWalletLinkQRCodeText';
import { QRCodeType } from ':rn/screens/Scan/types';
import { useSaveSession } from ':rn/shared/walletlink/hooks/useSaveSession';
import { Session } from ':rn/shared/walletlink/models/Session';

const messages = defineMessages({
  parseWalletLink: {
    defaultMessage: 'Parse walletlink url',
    description: 'Enter walletlink url to parse it and initiate a connection',
  },
  parseWalletLinkDescription: {
    defaultMessage: 'Copy paste a walletlink url here (instead of scanning via QR code)',
    description: 'Allows you to past a walletlink url instead of scanning it via QR code.',
  },
  parseWalletLinkButton: {
    defaultMessage: 'Parse',
    description: 'Parse walletlink url',
  },
});

export function ParseWalletLink() {
  const { formatMessage } = useIntl();
  const saveSession = useSaveSession();
  const [walletLinkURL, setWalletLinkURL] = useState('');

  const parseWalletLink = useCallback(
    function parseWalletLink() {
      const response = parseWalletLinkQRCodeText(walletLinkURL);

      if (!response || response.type !== QRCodeType.WALLET_LINK) {
        return;
      }

      const session: Session = {
        id: response.data.sessionId,
        secret: response.data.secret,
        url: response.data.url,
        isParent: response.data.isParent,
        version: response.data.version,
        chainId: response.data.chainId ?? 1,
      };

      saveSession(session);
    },
    [walletLinkURL, saveSession],
  );

  return (
    <VStack flexGrow={1} justifyContent="center" alignItems="flex-start" spacing={3}>
      <TextHeadline>{formatMessage(messages.parseWalletLink)}</TextHeadline>
      <TextInput
        label={formatMessage(messages.parseWalletLinkDescription)}
        onChangeText={setWalletLinkURL}
      />
      <Box spacingVertical={2}>
        <Button block compact onPress={parseWalletLink}>
          {formatMessage(messages.parseWalletLinkButton)}
        </Button>
      </Box>
    </VStack>
  );
}

