import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
// eslint-disable-next-line no-restricted-imports
import { Dimensions, Image, Modal, StyleSheet, TouchableOpacity } from 'react-native';
import {
  PanGestureHandler,
  PinchGestureHandler,
  TapGestureHandler,
} from 'react-native-gesture-handler';
import Animated, {
  useAnimatedGestureHandler,
  useAnimatedStyle,
  useSharedValue,
  withSpring,
} from 'react-native-reanimated';
import { useToggler } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Box } from '@cbhq/cds-mobile/layout';
import { RemoteImage, RemoteImageProps } from '@cbhq/cds-mobile/media';

const { width: screenWidth } = Dimensions.get('window'); // Get the screen width

type LightboxProps = {
  source: string;
  modalImageWidth: number;
  modalImageHeight?: number;
  imageAspectRatio?: [number, number];
  imageProps?: RemoteImageProps;
};

const defaultImageAspectRatio = [1, 1] as [number, number];

export function ImageLightBox({
  source,
  imageAspectRatio = defaultImageAspectRatio,
  modalImageWidth = screenWidth,
  modalImageHeight,
  imageProps,
}: LightboxProps) {
  const [modalVisible, { toggleOn, toggleOff }] = useToggler(false);
  const scale = useSharedValue(1);
  const offsetX = useSharedValue(0);
  const offsetY = useSharedValue(0);
  const doubleTapRef = useRef();
  const [imageSize, setImageSize] = useState({
    width: modalImageWidth,
    height: modalImageHeight || screenWidth,
  });

  useEffect(
    function setImageDimensions() {
      if (!modalImageHeight) {
        Image.getSize(source, (width, height) => {
          const aspectRatio = height / width;
          setImageSize({ width: modalImageWidth, height: modalImageWidth * aspectRatio });
        });
      }
    },
    [source, modalImageWidth, modalImageHeight],
  );

  // TODO: consider using a more dynamic height
  // Calculate dynamic height if not provided, maintaining image aspect ratio
  // Assuming a placeholder aspect ratio of 1:1 for simplicity
  // Adjust accordingly based on your image source or provide the height as a prop
  //   const aspectRatio = modalImageHeight ? modalImageHeight / modalImageWidth : 1;
  //   const imageHeight = modalImageWidth * aspectRatio;

  const pinchHandler = useAnimatedGestureHandler({
    onActive: (event) => {
      // @ts-expect-error
      scale.value = event.scale;
    },
    onEnd: () => {
      scale.value = withSpring(1); // Reset scale to original after pinch ends
    },
  });

  const panHandler = useAnimatedGestureHandler({
    onActive: (event) => {
      if (scale.value > 1) {
        // Allow panning only when zoomed in
        offsetX.value = event.translationX;
        offsetY.value = event.translationY;
      }
    },
    onEnd: () => {
      offsetX.value = withSpring(0); // Reset position after release
      offsetY.value = withSpring(0); // Reset position after release
    },
  });

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [
        { translateX: offsetX.value },
        { translateY: offsetY.value },
        { scale: scale.value },
      ],
    };
  });

  const onDoubleTap = useCallback(() => {
    if (scale.value === 1) {
      scale.value = withSpring(2);
    } else {
      scale.value = withSpring(1);
    }
  }, [scale]);

  const animatedImageSource = useMemo(() => {
    return { uri: source };
  }, [source]);

  return (
    <Box>
      <TouchableOpacity testID="image-touchable-opacity" onPress={toggleOn}>
        <RemoteImage
          height="auto"
          width="100%"
          resizeMode="cover"
          aspectRatio={imageAspectRatio}
          source={source}
          {...imageProps}
        />
      </TouchableOpacity>

      {/* eslint-disable react/forbid-component-props */}
      <Modal visible={modalVisible} transparent onRequestClose={toggleOff}>
        <Box justifyContent="center" alignItems="center" flexGrow={1} style={styles.modalView}>
          <Box style={styles.closeButtonContainer}>
            <IconButton onPress={toggleOff} name="close" testID="close-button" />
          </Box>
          <TapGestureHandler
            onActivated={onDoubleTap}
            numberOfTaps={2}
            ref={doubleTapRef}
            key="image-lightbox-gesture-handler"
          >
            <Animated.View style={styles.centerAlignedAnimatedView}>
              {/* @ts-expect-error issues with PinchGestureHandler typing and useAnimatedGestureHandler */}
              <PinchGestureHandler onGestureEvent={pinchHandler}>
                {}
                <Animated.View style={styles.centerAlignedAnimatedView}>
                  <PanGestureHandler onGestureEvent={panHandler}>
                    {}
                    <Animated.View style={styles.centerAlignedAnimatedView}>
                      <Animated.Image
                        source={animatedImageSource}
                        resizeMode="contain"
                        width={imageSize.width}
                        height={imageSize.height}
                        style={animatedStyle}
                      />
                    </Animated.View>
                  </PanGestureHandler>
                </Animated.View>
              </PinchGestureHandler>
            </Animated.View>
          </TapGestureHandler>
        </Box>
      </Modal>
      {/* eslint-enable react/forbid-component-props */}
    </Box>
  );
}

const styles = StyleSheet.create({
  modalView: {
    flex: 1,
    backgroundColor: 'rgba(0, 0, 0, 0.85)',
  },
  closeButtonContainer: {
    position: 'absolute',
    top: 40,
    right: 15,
    zIndex: 10000000,
  },
  centerAlignedAnimatedView: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});

