const messages = defineMessages({
  confirmRecastText: {
    defaultMessage: 'Recast this post?',
    description: 'Description to confirm recasting of cast',
  },
  confirmRemoveRecastText: {
    defaultMessage: 'Are you sure you want to remove this recast?',
    description: 'Description to confirm removal of recast',
  },
  deleteCastConfirmText: {
    defaultMessage: 'Are you sure you want to delete this cast?',
    description: 'Description to confirm deletion of cast',
  },
  deleteCastConfirmYes: {
    defaultMessage: 'Confirm',
    description: 'Confirm deletion of cast',
