    description: 'Cancel deletion of cast',
  },
});

type CastProps = {
  item: V1Cast;
  toggleOn?: () => void;
  liked?: boolean;
  recasted?: boolean;
  onRemoveCast?: () => void;
};

export const Cast = memo(({ item, toggleOn, liked, recasted, onRemoveCast }: CastProps) => {
  const text = useMemo(() => replaceFrameLinks(item.text || ''), [item.text]);
  const { navigate } = useStackNavigation();

  // Gets the date of the cast and returns the time ago or the date, parsing the timestamp that comes from Neynar
  // e.g.: "2024-09-29 16:00:00 +0000 UTC" parsed using the below format -> 2024-09-29T16:00:00.000Z
  const timestampInMs = useMemo(
    () => parse(item.timestamp ?? '', "yyyy-MM-dd HH:mm:ss XX 'UTC'", new Date()).getTime(),
    [item.timestamp],
  );
  const timeAgoOrDate = useCastTimeAgoOrDate(timestampInMs, {
    formatRelativeTimeOptions: { style: 'narrow' },
  });

  const navigateToProfile = useCallback(() => {
    navigate('DebugSocialDefiProfile', { profile: item.author });
  }, [item.author, navigate]);

  const frames = item.frames;
  const frame = frames && frames.length > 0 ? frames[0] : null;
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const { hyperlinks: _hyperlinks, ...embeds } = getEmbeddableContent(item.embeds || []);
  const totalEmbeds = useMemo(
    () => Object.values(embeds).reduce((sum, currentArray) => sum + currentArray.length, 0),
    [embeds],
  );

  // TODO: https://jira.coinbase-corp.com/browse/WALL-37562
  const contentWidth = Dimensions.get('window').width - 80;

  return (
    <HStack spacing={2} gap={2} borderColor="line" borderedBottom>
      <Box flexGrow={0}>
        <Pressable background="transparent" onPress={navigateToProfile}>
          <Avatar
            alt="Sneezy"
            size="l"
            src={item.author?.pfpUrl?.length ? item.author?.pfpUrl : undefined}
          />
        </Pressable>
      </Box>
      <VStack gap={2} width={contentWidth}>
        <HStack alignItems="center" gap={0.5} spacingTop={0.5}>
          <HStack maxWidth="80%" alignItems="center" gap={1}>
            <Pressable background="transparent" onPress={navigateToProfile}>
              <TextLabel1 ellipsizeMode="tail" numberOfLines={1}>
                {item.author?.displayName}
              </TextLabel1>
            </Pressable>
            <Box flexShrink={1}>
              <TextLegal color="foregroundMuted" ellipsizeMode="tail" numberOfLines={1}>
                @{item.author?.username}
              </TextLegal>
            </Box>
          </HStack>
          <Box flexGrow={0} width="max-content">
            <TextLegal color="foregroundMuted" ellipsizeMode="tail" numberOfLines={1}>
              {timeAgoOrDate}
            </TextLegal>
          </Box>
        </HStack>

        <TextLabel2>
          <TextIncludeLinks text={text} />
        </TextLabel2>

        {!!totalEmbeds && <CastEmbeds embeds={embeds} />}
        {frame && (
          <>
            <Spacer vertical={2} />
            <Frame frame={frame} />
          </>
        )}
        <CastSocial
          item={item}
          toggleOn={toggleOn}
          liked={liked ?? false}
          recasted={recasted ?? false}
          onRemoveCast={onRemoveCast}
        />
      </VStack>
    </HStack>
  );
});

type CastSocialProps = {
  item: V1Cast;
  liked: boolean;
  recasted: boolean;
  toggleOn?: () => void;
  onRemoveCast?: () => void;
};

function useLikeLottieAnimation(): { progress: LottieProgress; Lottie: () => JSX.Element } {
  const { progress, Lottie } = useLottie(heartBurstAnimation);
  const { primaryForeground } = usePalette();

  const lottieStyle = useMemo<StyleProp<Record<string, unknown>>>(
    () => ({
      position: 'absolute',
      alignSelf: 'center',
      justifyContent: 'center',
      backgroundColor: primaryForeground,
      height: '105%',
    }),
    [primaryForeground],
  );

  useBackground(progress.reset);

  return useMemo(
    () => ({
      progress,
      Lottie: () => (
        <Lottie
          testID="like-animation"
          // eslint-disable-next-line react/forbid-component-props
          style={lottieStyle}
        />
      ),
    }),
    [Lottie, lottieStyle, progress],
  );
}

function CastSocial({ item, toggleOn, liked, recasted, onRemoveCast }: CastSocialProps) {
  const { navigate } = useStackNavigation();
  const fid = useGetUserFid();
  const [castData, setCastData] = useState({ ...item });
  const { onRemove } = useRemoveCast(castHashToUint8Array(String(item.hash)));
  const { formatMessage } = useIntl();
  const onRemoveEnhanced = useCallback(async () => {
    Alert.alert('', formatMessage(messages.deleteCastConfirmText), [
      { text: formatMessage(messages.deleteCastConfirmNo), style: 'cancel' },
      {
        text: formatMessage(messages.deleteCastConfirmYes),
        onPress: async () => {
          await onRemove();
          if (onRemoveCast) onRemoveCast();
        },
      },
    ]);
  }, [formatMessage, onRemove, onRemoveCast]);

  const [isLiked, setIsLiked] = useState<boolean>(liked);
  const [isRecasted, setIsRecasted] = useState<boolean>(recasted);

  const { progress, Lottie } = useLikeLottieAnimation();

  const updateLikes = useCallback(() => {
    if (!fid) return;

    if (isLiked && castData?.reactions?.likeCount) {
      setCastData({
        ...castData,
        reactions: {
          ...castData.reactions,
          likeCount: (Number(castData?.reactions?.likeCount) - 1).toString(),
        },
      });
    } else if (!isLiked && castData?.reactions?.likeCount) {
      setCastData({
        ...castData,
        reactions: {
          ...castData.reactions,
          likeCount: (Number(castData?.reactions?.likeCount) + 1).toString(),
        },
      });
    }
  }, [fid, isLiked, castData]);

  const updateRecasts = useCallback(() => {
    if (!fid) return;

    if (isRecasted && castData?.reactions?.recastCount) {
      setCastData({
        ...castData,
        reactions: {
          ...castData.reactions,
          recastCount: (Number(castData?.reactions?.recastCount) - 1).toString(),
        },
      });
    } else if (!isRecasted && castData?.reactions?.recastCount) {
      setCastData({
        ...castData,
        reactions: {
          ...castData.reactions,
          recastCount: (Number(castData?.reactions?.recastCount) + 1).toString(),
        },
      });
    }
  }, [fid, isRecasted, castData]);

  useEffect(
    function hydrateReactions() {
      setIsLiked(liked);
      if (liked) progress.play();
      setIsRecasted(recasted);
    },
    [liked, recasted, progress],
  );

  const castHash = castHashToUint8Array(String(item.hash));
  const { onReaction } = useAddReaction(castHash);
  const { onRemoveReaction } = useRemoveReaction(castHash);

  const toggleLike = useCallback(() => {
    if (isLiked) {
      progress.reset();
      onRemoveReaction(ReactionType.LIKE);
      logCastLikeRemoved({
        hash: String(item.hash),
      });
    } else {
      progress.play();
      onReaction(ReactionType.LIKE);
      setTimeout(() => {
        Haptics.lightImpact();
      }, 170);
      logCastLike({
        hash: String(item.hash),
      });
    }
    setIsLiked(!isLiked);
    updateLikes();
  }, [isLiked, onRemoveReaction, onReaction, progress, updateLikes, item.hash]);

  const toggleRecast = useCallback(() => {
    if (isRecasted) {
      onRemoveReaction(ReactionType.RECAST);
      logCastRecastRemoved({
        hash: String(item.hash),
      });
    } else {
      onReaction(ReactionType.RECAST);
      logCastRecast({
        hash: String(item.hash),
      });
    }
    setIsRecasted(!isRecasted);
    updateRecasts();
  }, [isRecasted, onRemoveReaction, onReaction, updateRecasts, item.hash]);

  const onRecastEnhanced = useCallback(async () => {
    Alert.alert(
      '',
      `${
        isRecasted
          ? formatMessage(messages.confirmRemoveRecastText)
          : formatMessage(messages.confirmRecastText)
      }`,
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Yes',
          onPress: async () => {
            toggleRecast();
          },
        },
      ],
    );
  }, [formatMessage, isRecasted, toggleRecast]);

  /*
   * We are using a string currently as our fid that is a mock value.
   * Once we enable Farcaster Connect and Create account flows, we'll
   * integrate the like, comment, and recast functionality appropriately
   * to check for the FID and have it derive appropriately as opposed
   * to the current implementation in the Debug menu.
   * */

  const likeItem = useCallback(() => {
    if (toggleOn) {
      toggleOn();
      return;
    }
    if (!fid) return;
    startTransition(() => {
      toggleLike();
    });
  }, [toggleOn, fid, toggleLike]);

  const commentItem = useCallback(() => {
    if (toggleOn) {
      toggleOn();
      return;
    }
    if (!fid) return;
    navigate('SocialDefiCastDetails', { cast: item });
    logCastClicked({ hash: String(item.hash) });
  }, [toggleOn, fid, item, navigate]);

  const recastItem = useCallback(() => {
    if (toggleOn) {
      toggleOn();
      return;
    }
    if (!fid) return;
    startTransition(() => {
      onRecastEnhanced();
      Haptics.lightImpact();
    });
  }, [toggleOn, fid, onRecastEnhanced]);

  return (
    <HStack alignItems="center" gap={2} justifyContent="space-between">
      <Pressable onPress={commentItem} background="transparent">
        <HStack alignItems="center" gap={1}>
          <Icon
            name="comment"
            size="s"
            color="foreground"
            accessibilityLabel={`Comment on a post by ${castData?.author?.displayName}`}
          />
          <TextBody>{castData?.replies?.count}</TextBody>
        </HStack>
      </Pressable>
      <Pressable onPress={recastItem} background="transparent" testID="SocialCast-Recast">
        <HStack alignItems="center" gap={1}>
          <Icon
            name="wireTransfer"
            size="s"
            color={isRecasted ? 'positive' : 'foreground'}
            accessibilityLabel={`Recast a post by ${castData.author?.displayName}`}
          />
          <TextBody>{castData.reactions?.recastCount}</TextBody>
        </HStack>
      </Pressable>
      <Pressable onPress={likeItem} background="transparent">
        <HStack alignItems="center" gap={1}>
          <Icon
            name={isLiked ? 'heartActive' : 'heartInactive'}
            size="s"
            color={isLiked ? 'negative' : 'foreground'}
            accessibilityLabel={`Like a post by ${castData.author?.displayName}`}
          />
          {/* eslint-disable-next-line @cbhq/react-no-nested-component */}
          <Lottie />
          <TextBody>{castData.reactions?.likeCount}</TextBody>
        </HStack>
      </Pressable>
      {castData.author?.fid === fid && (
        <Pressable onPress={onRemoveEnhanced} background="transparent">
          <HStack alignItems="center" gap={1}>
            <Icon name="trashCan" size="s" color="foreground" accessibilityLabel="Remove cast" />
            <TextBody>{castData.reactions?.recastCount}</TextBody>
          </HStack>
        </Pressable>
      )}
    </HStack>
  );
}

// TODO: update function to include other link types.
// Currently, there is no simplified way to do this
function replaceFrameLinks(input: string): string {
  const regex = /https:\/\/frames\.neynar\.com\/f\/[a-z0-9]+\/[a-z0-9]+/g;
  return input.replaceAll(regex, '');
}

