export function SocialDefiCastDetails() {
  const { cast } = useParams<DebugParamList, 'SocialDefiCastDetails'>();

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: 'back',
      title: `Reply to ${cast.author?.username}`,
    }),
    [cast.author?.username],
  );

  return (
