type SocialDefiCastCommentsProps = { topCast: V1Cast };

export function SocialDefiCastComments({ topCast }: SocialDefiCastCommentsProps) {
  const [casts, setCasts] = useState<CastsForThreadHashResult['casts']>([]);
  const { pop } = useStackNavigation();
  const [postingComment, setPostingComment] = useState(false);
  const fetchCasts = useGetCastsForThreadHashCallback();
  const onRemoveCast = useCallback(() => {
    // No replies, they're deleting the only cast, pop back in stack
    if (!topCast.replies?.count) pop();
  }, [pop, topCast.replies?.count]);
  const renderItem = useCallback(
    ({ item }: { item: V1Cast }) => <Cast item={item} onRemoveCast={onRemoveCast} />,
    [onRemoveCast],
  );
  const keyExtractor = useCallback((item: V1Cast) => item.hash!, []);

  const { formatMessage } = useIntl();
  const spectrum = useSpectrum();
  const palette = usePalette();

  useEffect(
    function fetchThread() {
      async function fetchCastsData() {
        const { casts: castsFetched } = (await fetchCasts({
          threadHash: topCast.hash,
        })) as CastsForThreadHashResult;
        if (castsFetched) setCasts(castsFetched);
      }
      fetchCastsData();
    },
    // disable, since adding fetchCasts causes additional calls
    // eslint-disable-next-line wallet/exhaustive-deps
    [topCast.hash],
  );

  const mergedCasts = useMemo(() => {
    // since we already have the parent cast, show it immediately, while the thread loads
    if (!casts?.length) {
      return [topCast];
    }

    return casts;
  }, [casts, topCast]);

  const {
    castText: comment,
    onComment,
    onChangeCastText: onChangeComment,
  } = usePostCast(String(topCast.threadHash), Number(topCast.author?.fid));

  const onCommentEnhanced = useCallback(
    async function onCommentEnhanced() {
      setPostingComment(true);
      await onComment();
      // account for latency in the comment getting indexed
      // TODO: Utilize optimistic UI to show the comment immediately
      // https://jira.coinbase-corp.com/browse/WALL-33200
      await new Promise((resolve) => {
        setTimeout(resolve, 500);
      });
      const { casts: castsFetched } = (await fetchCasts({
        threadHash: topCast.hash,
      })) as CastsForThreadHashResult;
      if (castsFetched) setCasts(castsFetched);
      onChangeComment('');
      setPostingComment(false);
    },
    // disable, since adding fetchCasts causes additional calls
    // eslint-disable-next-line wallet/exhaustive-deps
    [onComment],
  );

  const [inputHeight, setInputHeight] = useState(0);

  const initialInputHeight = useRef();
  const isMultilineInput = initialInputHeight.current && inputHeight > initialInputHeight.current;
  const textInputStyle = useMemo(
    () => ({
      maxHeight:
        isMultilineInput && initialInputHeight.current
          ? initialInputHeight.current * 2.75
          : undefined,
      paddingStart: 10,
      paddingEnd: 10,
      paddingTop: 15,
      paddingBottom: 10,
      color: palette.foreground,
      fontFamily: 'CoinbaseSans-Regular',
      fontSize: 16,
    }),
    [isMultilineInput, palette.foreground],
  );
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleHeightChange = useCallback(function handleHeightChange({ nativeEvent }: any) {
    if (!initialInputHeight.current) {
      initialInputHeight.current = nativeEvent.layout.height;
    }

    setInputHeight(nativeEvent.layout.height);
  }, []);

  return (
    <>
      <FlatList data={mergedCasts} renderItem={renderItem} keyExtractor={keyExtractor} />
      <HStack alignItems="flex-end" gap={1} spacing={2} spacingBottom={3}>
        <Box borderRadius="roundedFull" flexGrow={1} flexShrink={1} spacingStart={1}>
          <TextInput
            blurOnSubmit={false}
            keyboardAppearance={spectrum}
            keyboardType="default"
            multiline
            onChangeText={onChangeComment}
            onLayout={handleHeightChange}
            placeholder={formatMessage(messages.commentPlaceholder, {
              username: topCast.author?.username,
            })}
            placeholderTextColor={palette.foregroundMuted}
            // eslint-disable-next-line react/forbid-component-props
            style={textInputStyle}
            testID="social-defi-cast-details-comment-input"
            value={comment}
            scrollEnabled={false}
            disabled={postingComment}
          />
        </Box>
        {!!comment && (
          <Box spacingBottom={0.5}>
            {postingComment ? (
              <Loader size="small" />
            ) : (
              <IconButton
                accessibilityLabel={formatMessage(messages.accessibilityLabel)}
                name="paperAirplane"
                onPress={onCommentEnhanced}
                testID="message-composer-button"
                variant="primary"
              />
            )}
          </Box>
        )}
      </HStack>
    </>
  );
}

