const messages = defineMessages({
  postingPlaceholder: {
    defaultMessage: `What's happening?`,
    description: 'placeholder for posting text input',
  },

  accessibilityLabel: {
    defaultMessage: 'comment on thread',
    description: 'accessibility label for a submit button',
  },
});

export function SocialDefiCreateCastInner() {
  const [isPosting, setIsPosting] = useState(false);
  const [successfullyPosted, setSuccessfullyPosted] = useState(false);
  const { castText, onComment: onPost, onChangeCastText } = usePostCast();
  const [castHash, setCastHash] = useState<string | undefined>(undefined);

  const { navigate } = useStackNavigation();

  const onPostEnhanced = useCallback(
    async function onPostEnhanced() {
      setIsPosting(true);
      const postResponse = await onPost();

      function isV1PostMessageResponse(obj: unknown): obj is V1PostMessageResponse {
        return (obj as V1PostMessageResponse).success !== undefined;
      }

      if (isV1PostMessageResponse(postResponse) && postResponse.success) {
        setSuccessfullyPosted(true);
        setCastHash(postResponse.hash);
      }

      onChangeCastText('');
      setIsPosting(false);
    },
    // eslint-disable-next-line wallet/exhaustive-deps
    [onPost],
  );

  useEffect(
    function navigateToDebugSocialDefi() {
      if (successfullyPosted && castHash) {
        navigate('DebugSocialDefi', { newCastHash: castHash });
      }
    },
    [navigate, castHash, successfullyPosted],
  );

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: 'back',
      right: (
        <Button
          compact
          variant="primary"
          disabled={isPosting || !castText}
          onPress={onPostEnhanced}
        >
          Post
        </Button>
      ),
    }),
    [castText, isPosting, onPostEnhanced],
  );

  return (
    <Screen navBar={navBar}>
      <ErrorBoundary errorFallback={<DebugSocialDefiError />}>
        <SocialDefiCreateCastContent
          castText={castText}
          onChangeCastText={onChangeCastText}
          isPosting={isPosting}
        />
      </ErrorBoundary>
    </Screen>
  );
}

type SocialDefiCreateCastProps = {
  castText: string;
  onChangeCastText: (text: string) => void;
  isPosting: boolean;
};

export function SocialDefiCreateCastContent({
  castText,
  onChangeCastText,
  isPosting,
}: SocialDefiCreateCastProps) {
  const { formatMessage } = useIntl();
  const spectrum = useSpectrum();
  const palette = usePalette();
  const { user } = useParams<DebugParamList, 'SocialDefiCreateCast'>();

  const textInputStyle = useMemo(
    () => ({
      paddingStart: 10,
      paddingEnd: 10,
      paddingTop: 15,
      paddingBottom: 10,
      color: palette.foreground,
      fontFamily: 'CoinbaseSans-Regular',
      fontSize: 16,
      borderWidth: 0,
    }),
    [palette.foreground],
  );

  return (
    <HStack gap={1} spacing={2}>
      <Avatar alt="Sneezy" size="l" src={user.pfpUrl} />
      <Box flexGrow={1} offsetTop={1} flexShrink={1}>
        <TextInput
