} from './farcasterSignerStorage';
import { useCreateSigner } from './useCreateSigner';

export function SocialDefiCreateSigner() {
  const { step, url, castText, onChangeCastText, onComment } = useCreateSigner();
  const [appPKLocal, setAppPKLocal] = useState('');
  const [userPKLocal, setUserPKLocal] = useState('');

  const onSetAppPK = useCallback(async () => {
    await setAppPK(appPKLocal as `0x${string}`);
  }, [appPKLocal]);

  const onSetUserPK = useCallback(async () => {
    if (!userPKLocal) await setUserSignerPK('');
    await setUserPK(userPKLocal as `0x${string}`);
  }, [userPKLocal]);

  useEffect(function initPKs() {
    //
    async function getAppPKs() {
      const appPKEncrypted = await getAppPK();
      if (appPKEncrypted) setAppPKLocal(appPKEncrypted);

      const userPKEncrypted = await getUserPK();
      if (userPKEncrypted) setUserPKLocal(userPKEncrypted);
    }
    getAppPKs();
  }, []);

  const palette = usePalette();
  const spectrum = useSpectrum();
  const textInputStyle = useMemo(
    () => ({
      paddingStart: 10,
      paddingEnd: 10,
      paddingTop: 15,
      paddingBottom: 10,
      color: palette.foreground,
      fontFamily: 'CoinbaseSans-Regular',
      fontSize: 16,
    }),
    [palette.foreground],
  );

  return (
    <VStack spacingTop={3}>
      <TextLabel1>Signer & Cast Debugging</TextLabel1>
      <Box>
        <TextBody>{step}</TextBody>
      </Box>

      <TextBody spacingTop={1}>App key</TextBody>
      <HStack alignItems="flex-end" gap={1} spacingEnd={1} spacingBottom={1}>
        <Box flexGrow={1} flexShrink={1}>
          <TextInput
            blurOnSubmit={false}
            keyboardAppearance={spectrum}
            keyboardType="default"
            multiline
            onChangeText={setAppPKLocal}
            placeholder="Set your APP Wallet's private key"
            placeholderTextColor={palette.foregroundMuted}
            // eslint-disable-next-line react/forbid-component-props
            style={textInputStyle}
            testID="social-defi-cast-details-comment-input"
            value={appPKLocal}
            scrollEnabled={false}
          />
        </Box>
        <Box spacingBottom={0.5}>
          <IconButton
            accessibilityLabel="Make a cast from App!"
            name="paperAirplane"
            onPress={onSetAppPK}
            testID="message-composer-button"
            variant="primary"
          />
        </Box>
      </HStack>
      <TextBody spacingTop={1}>User key</TextBody>
      <HStack alignItems="flex-end" gap={1} spacingEnd={1} spacingBottom={1}>
        <Box flexGrow={1} flexShrink={1}>
          <TextInput
            blurOnSubmit={false}
            keyboardAppearance={spectrum}
            keyboardType="default"
            multiline
            onChangeText={setUserPKLocal}
            placeholder="Set your User's private key"
            placeholderTextColor={palette.foregroundMuted}
            // eslint-disable-next-line react/forbid-component-props
            style={textInputStyle}
            testID="social-defi-cast-details-comment-input"
            value={userPKLocal}
            scrollEnabled={false}
          />
        </Box>
        <Box spacingBottom={0.5}>
          <IconButton
            accessibilityLabel="Make a cast from App!"
            name="paperAirplane"
            onPress={onSetUserPK}
            testID="message-composer-button"
            variant="primary"
          />
        </Box>
      </HStack>

      <TextBody spacingTop={1}>Test casts</TextBody>
      <HStack alignItems="flex-end" gap={1} spacingEnd={1} spacingBottom={1}>
        <Box flexGrow={1} flexShrink={1}>
          <TextInput
            blurOnSubmit={false}
            keyboardAppearance={spectrum}
            keyboardType="default"
            multiline
            onChangeText={onChangeCastText}
            placeholder="Make a cast from App!"
            placeholderTextColor={palette.foregroundMuted}
            // eslint-disable-next-line react/forbid-component-props
            style={textInputStyle}
            testID="social-defi-cast-details-comment-input"
            value={castText}
            scrollEnabled={false}
          />
        </Box>
        {!!castText && (
          <Box spacingBottom={0.5}>
            <IconButton
              accessibilityLabel="Make a cast from App!"
              name="paperAirplane"
              onPress={onComment}
              testID="message-composer-button"
              variant="primary"
            />
          </Box>
        )}
      </HStack>
      {!!url && (
        <TextBody>
          <Link to={url}>{url}</Link>
        </TextBody>
      )}
    </VStack>
  );
}

