import { memo, useCallback, useMemo } from 'react';
import { Linking } from 'react-native';
import { PROTOCOL_REPLACER, SOCIAL_REPLACER } from 'cb-wallet-data/stores/Profile/constants';
import type { IconName } from '@cbhq/cds-mobile';
import { Icon } from '@cbhq/cds-mobile/icons';
import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';

import { isSocialIcon, SocialIcon } from ':rn/screens/Profile/components/SocialLink/SocialIcon';

const nonSocialIcons: Record<string, IconName> = {
  url: 'globe',
  email: 'email',
};

export type ProfileRecordName = 'url' | 'email' | 'twitter' | 'reddit' | 'github';

export type ProfileRecordProps = {
  recordName: ProfileRecordName;
  value?: string;
};

export const DefiSocialProfileRecord = memo(function ProfileRecord({
  recordName,
  value,
}: ProfileRecordProps) {
  const description = useMemo(() => {
    if (!value) {
      return;
    }

    if (isSocialIcon(recordName)) {
      return value.replace(SOCIAL_REPLACER, '');
    }

    if (recordName === 'url') {
      return value.replace(PROTOCOL_REPLACER, '');
    }

    return value;
  }, [recordName, value]);

  const handleLinkPress = useCallback(
    function handleLinkPress() {
      if (!value) return;

      let formattedValue = value;

      if (recordName === 'email') {
        formattedValue = `mailto:${value}`;
      }

      if (recordName === 'url') {
        formattedValue = value.startsWith('http')
          ? value.replace(PROTOCOL_REPLACER, '')
          : `https://${value}`;
      }

      Linking.openURL(formattedValue);
    },
    [recordName, value],
  );

  return (
    <VStack spacingEnd={1}>
      <Pressable
        onPress={handleLinkPress}
        background="transparent"
        testID={`profile-record-${recordName}`}
      >
        <HStack>
          <VStack spacingTop={0.5} spacingEnd={0.5}>
            {isSocialIcon(recordName) ? (
              <SocialIcon name={recordName} testID={`social-icon-${recordName}`} />
            ) : (
              <Icon
                name={nonSocialIcons[recordName]}
                size="s"
                color="foregroundMuted"
                testID={`icon-${recordName}`}
              />
            )}
          </VStack>
          <TextBody color="foregroundMuted" numberOfLines={1} ellipsizeMode="tail">
            {description}
          </TextBody>
        </HStack>
      </Pressable>
    </VStack>
  );
});

import { useCallback, useMemo } from 'react';
import { TextInput } from '@cbhq/cds-mobile/controls';
import { Icon } from '@cbhq/cds-mobile/icons';
import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { RemoteImage } from '@cbhq/cds-mobile/media';
import { TextBody } from '@cbhq/cds-mobile/typography';
import { V1Frame, V1FrameButton } from '@cbhq/instant-api-hooks-social-service/types';

import { getErrorVitalsClient } from ':rn/app/init/errorVitals';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { useOpenWebBrowser } from ':rn/shared/hooks/useOpenBrowser';

const errorVitalsClient = getErrorVitalsClient();

type FrameProps = {
  frame: V1Frame;
};

export function Frame({ frame }: FrameProps) {
  const aspectRatio: [number, number] = useMemo(() => {
    // TODO: get updated types from Neynar
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    if ((frame as any).image_aspect_ratio === '1:1') {
      return [1, 1];
    }
    return [1.91, 1];
  }, [frame]);

  return (
    <VStack
      key={frame.framesUrl}
      gap={2}
      background="backgroundAlternate"
      borderRadius="roundedLarge"
    >
      <RemoteImage
        height="auto"
        width="100%"
        resizeMode="cover"
        aspectRatio={aspectRatio}
        source={frame.image}
        borderTopLeftRadius={20}
        borderTopRightRadius={20}
      />

      <VStack gap={1} spacingHorizontal={2}>
        {/* TODO: get updated types from Neynar */}
        {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
        {!!(frame as any).input.text && <TextInput placeholder={(frame as any).input.text} />}
        {frame.buttons?.map((button) => (
          <FrameButton button={button} key={`frame-${button.index}`} />
        ))}
      </VStack>
    </VStack>
  );
}

type FrameButtonProps = {
  button: V1FrameButton;
};

function FrameButton({ button }: FrameButtonProps) {
  const openWebBrowser = useOpenWebBrowser();
  const handlePress = useCallback(() => {
    if (button.actionType === 'link') {
      // TODO: Neynar V1 api does not include button target
      const url = '';
      try {
        openWebBrowser(url);
      } catch (e) {
        errorVitalsClient.logError(new Error(`URL: ${url} cannot be opened from Feed`), {
          severity: 'warning',
          context: 'social_defi_feed',
          isHandled: false,
        });
      }
    } else {
      // eslint-disable-next-line no-alert
      alert('Button action not yet supported');
    }
  }, [button, openWebBrowser]);
  return (
    <Button variant="secondary" testID="cta-frame-button" compact onPress={handlePress}>
      <HStack gap={1} alignItems="center">
        <TextBody>{button.title || ''}</TextBody>
        {button.actionType === 'link' && <Icon size="s" name="externalLink" />}
      </HStack>
    </Button>
  );
}

import { memo, useCallback, useMemo, useState } from 'react';
import { Animated } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import {
  logSubdomainProfilePictureModalClosed,
  logSubdomainProfilePictureModalOpened,
} from 'cb-wallet-analytics/subdomain';
import { logEvent } from 'cb-wallet-analytics/utils/log';
import { ETHEREUM_SYMBOL } from 'cb-wallet-data/chains/AccountBased/Ethereum/constants';
import { useIsMiamiViceFeatureEnabled } from 'cb-wallet-data/hooks/useIsMiamiViceFeatureEnabled/useIsMiamiViceFeatureEnabled';
import {
  CombinedThemeColorPreference,
  MIAMI_THEME_COLORS,
  miamiThemeColorConfigs,
  MiamiThemeColorPreference,
  THEME_COLORS,
  themeColorConfigs,
  ThemeColorPreference,
} from 'cb-wallet-data/stores/ThemeColors/themeColorConfigs';
import { useSetWalletGroupAvatar } from 'cb-wallet-data/stores/WalletGroups/hooks/useSetWalletGroupAvatar';
import { useGetWalletsForWalletGroupForChain } from 'cb-wallet-data/stores/Wallets/hooks/useGetWalletsForWalletGroupForChain';
import { PaletteValue, useSpectrum } from '@cbhq/cds-common';
import { paletteValueToRgbaString } from '@cbhq/cds-common/palette/paletteValueToRgbaString';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { useSpacingScale } from '@cbhq/cds-mobile/hooks/useSpacingScale';
import { Box, HStack, Spacer, VStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { ActionType, ComponentType } from '@cbhq/client-analytics';

import { useThemeColorPreference } from ':rn/app/hooks/useThemeColorPreference';
import { useThemeColorPreferenceUpdater } from ':rn/app/ThemeColorPreferenceProvider';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Screen } from ':rn/cds-wallet/components/layout/Screen';
import { NavBarConfig } from ':rn/cds-wallet/components/NavBar/NavBar';
import * as Avatars from ':rn/cds-wallet/images/ProfileAvatarSVGs/Avatars';
import { withScreenBoundary } from ':rn/cds-wallet/utils/withScreenBoundary';
import { useDimensions } from ':rn/shared/hooks/useDimensions';
import { useParams } from ':rn/shared/hooks/useParams';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';
import { SettingsRedesignParamList } from ':rn/shared/types/ParamLists';

import { ProfilePictureModal } from './components/ProfilePictureModal';

const messages = defineMessages({
  title: {
    defaultMessage: 'Customize',
    description: 'Customize avatar page title',
  },
  save: {
    defaultMessage: 'Save',
    description: 'Button text to save profile changes',
  },
  chooseYourOwn: {
    defaultMessage: 'Choose your own',
    description: 'Text for choose your own avatar button',
  },
});

function logAvatarChange(avatar: number, preference: CombinedThemeColorPreference) {
  return logEvent('settings.avatar.change', {
    action: ActionType.click,
    componentType: ComponentType.button,
    avatarIndex: avatar,
    avatarBackgroundColor: preference,
  });
}

const OUTER_SELECTOR_SIZE = 33;
const INNER_SELECTOR_SIZE = 22;

const CustomizeAvatar = memo(function CustomizeAvatar() {
  const isMiamiViceThemeColorEnabled = useIsMiamiViceFeatureEnabled(
    'wallet_redesign_miami_vice_theme_colors',
  );

  const { walletGroup } = useParams<SettingsRedesignParamList, 'CustomizeAvatarScreen'>();

  const { goBack } = useStackNavigation();
  const avatarArray = Array.from(Array(Object.keys(Avatars).length).keys());
  const [avatar, setAvatar] = useState<number>(0);

  const preference = useThemeColorPreference({
    walletGroupId: walletGroup.id,
  });

  const spectrum = useSpectrum();
  const { formatMessage } = useIntl();
  const { screenWidth } = useDimensions();
  const spacing = useSpacingScale();

  const [pfpModalVisible, setPfpModalVisible] = useState(false);
  const getWalletsForWalletGroupForChain = useGetWalletsForWalletGroupForChain();

  const ethAddress = useMemo(() => {
    return getWalletsForWalletGroupForChain({ walletGroup, chain: ETHEREUM_SYMBOL })[0]
      ?.primaryAddress;
  }, [getWalletsForWalletGroupForChain, walletGroup]);

  const togglePfpModalVisibility = useCallback(
    function togglePfpModalVisibility() {
      if (pfpModalVisible) {
        logSubdomainProfilePictureModalClosed();
      } else {
        logSubdomainProfilePictureModalOpened();
      }

      setPfpModalVisible((prevPfpModalVisible) => !prevPfpModalVisible);
    },
    [pfpModalVisible],
  );

  const preferenceBackground = useCallback(
    (config: CombinedThemeColorPreference) => {
      let value: PaletteValue;
      if (isMiamiViceThemeColorEnabled) {
        if (MIAMI_THEME_COLORS.includes(config as MiamiThemeColorPreference)) {
          value = miamiThemeColorConfigs[config as MiamiThemeColorPreference].primary;
        } else {
          value = miamiThemeColorConfigs.blue.primary;
        }
      } else if (THEME_COLORS.includes(config as ThemeColorPreference)) {
        value = themeColorConfigs[config as ThemeColorPreference].primary;
      } else {
        value = themeColorConfigs.blue.primary;
      }

      return paletteValueToRgbaString(value, spectrum);
    },
    [isMiamiViceThemeColorEnabled, spectrum],
  );

  const setWalletGroupAvatar = useSetWalletGroupAvatar();
  const handleSetPreference = useThemeColorPreferenceUpdater();

  const handleBack = useCallback(() => {
    handleSetPreference(walletGroup.id, walletGroup?.themeColor ?? 'blue');

    goBack();
  }, [goBack, handleSetPreference, walletGroup.id, walletGroup?.themeColor]);

  const handleColorChange = useCallback(
    (name: CombinedThemeColorPreference) => {
      return () => handleSetPreference(walletGroup.id, name);
    },
    [handleSetPreference, walletGroup.id],
  );

  const handleSave = useCallback(() => {
    setWalletGroupAvatar(walletGroup.id, avatar);
    logAvatarChange(avatar, preference);
    goBack();
  }, [avatar, goBack, preference, setWalletGroupAvatar, walletGroup.id]);

  const changeAvatar = useCallback((index: number) => {
    return () => setAvatar(index);
  }, []);

  const keyExtractor = useCallback(
    function keyExtractor(item: number) {
      return `avatar-${item}-${preference}`;
    },
    [preference],
  );

  const navBar: NavBarConfig = useMemo(
    () => ({
      left: 'back',
      title: formatMessage(messages.title),
      handleLeft: handleBack,
    }),
    [formatMessage, handleBack],
  );

  const renderItem = useCallback(
    function renderItem({ item }: { item: number }) {
      const Avatar = Avatars[`Avatar${item}` as keyof typeof Avatars];

      // calculate size by subtracting the spacing 3 on each side and spacing 1 in between avatars
      const dimension = (screenWidth - spacing[6] - spacing[4] - spacing[2] * 5) / 5;

      const spacingStart = item % 5 === 0 ? 0 : 0.5;
      const spacingEnd = item % 5 === 4 ? 0 : 0.5;

      const selected = avatar === item;

      return (
        <Pressable
          background="transparent"
          borderRadius="roundedFull"
          feedback="normal"
          onPress={changeAvatar(item)}
          transparentWhileInactive
        >
          <Box spacingStart={spacingStart} spacingEnd={spacingEnd} spacingVertical={0.5}>
            <Box
              borderRadius="roundedFull"
              spacing={0.5}
              dangerouslySetBackground={selected ? preferenceBackground(preference) : undefined}
            >
              <Box borderRadius="roundedFull" spacing={0.5} background="background">
                <Box
                  borderRadius="roundedFull"
                  background="secondary"
                  dangerouslySetBackground={selected ? preferenceBackground(preference) : undefined}
                >
                  <Avatar size={dimension} key={item} />
                </Box>
              </Box>
            </Box>
          </Box>
        </Pressable>
      );
    },
    [avatar, changeAvatar, preference, preferenceBackground, screenWidth, spacing],
  );

  const SelectedAvatar = Avatars[`Avatar${avatar}` as keyof typeof Avatars];

  const isSelectedColor = useCallback(
    (name: string) => {
      if (isMiamiViceThemeColorEnabled) {
        if (MIAMI_THEME_COLORS.includes(preference as MiamiThemeColorPreference)) {
          return preference === name;
        }
        return name === 'blue';
      }
      if (THEME_COLORS.includes(preference as ThemeColorPreference)) {
        return preference === name;
      }
      return name === 'blue';
    },
    [isMiamiViceThemeColorEnabled, preference],
  );

  return (
    <Screen navBar={navBar} full>
      <VStack flexShrink={1} spacingHorizontal={3} spacingTop={2}>
        <VStack alignItems="center">
          <Box
            borderRadius="roundedFull"
            dangerouslySetBackground={preferenceBackground(preference)}
          >
            <SelectedAvatar size={96} />
          </Box>
        </VStack>
        <Spacer vertical={3} />
        <Animated.FlatList
          data={avatarArray}
          // need the evm address as part of the key to prevent a rendering bug
          // where the previous wallet's NFTs would show when you switch wallets
          key="avatar-grid"
          numColumns={5}
          renderItem={renderItem}
          testID="grid-view-avatars"
          showsVerticalScrollIndicator={false}
          keyExtractor={keyExtractor}
        />
        <Box background="secondary" borderRadius="roundedFull">
          <HStack justifyContent="space-between" spacing={1}>
            {Object.entries(
              isMiamiViceThemeColorEnabled ? miamiThemeColorConfigs : themeColorConfigs,
            ).map(([name]) => {
              return (
                <Pressable
                  background="secondary"
                  borderRadius="roundedFull"
                  feedback="normal"
                  onPress={handleColorChange(name as CombinedThemeColorPreference)}
                  testID={`theme-color-preference-button-${name}`}
                  transparentWhileInactive
                >
                  <Box
                    alignItems="center"
                    borderRadius="roundedFull"
                    height={OUTER_SELECTOR_SIZE}
                    justifyContent="center"
                    width={OUTER_SELECTOR_SIZE}
                    background={isSelectedColor(name) ? 'background' : undefined}
                  >
                    <Box
                      width={INNER_SELECTOR_SIZE}
                      height={INNER_SELECTOR_SIZE}
                      borderRadius="roundedFull"
                      dangerouslySetBackground={preferenceBackground(
                        name as CombinedThemeColorPreference,
                      )}
                    />
                  </Box>
                </Pressable>
              );
            })}
          </HStack>
        </Box>
      </VStack>
      <ProfilePictureModal
        address={ethAddress}
        visible={pfpModalVisible}
        onClose={togglePfpModalVisibility}
      />
      <Spacer />
      <VStack spacingTop={2} spacingHorizontal={3}>
        <ButtonGroup direction="vertical">
          <Button onPress={handleSave} testID="submit-button">
            {formatMessage(messages.save)}
          </Button>
          <Button onPress={togglePfpModalVisibility} testID="choose-button" variant="secondary">
            {formatMessage(messages.chooseYourOwn)}
          </Button>
        </ButtonGroup>
      </VStack>
    </Screen>
  );
});

