import { memo, useCallback, useMemo } from 'react';
import { useIsNFTRoundCornersEnabled } from 'cb-wallet-data/stores/Collection/hooks/useIsNFTRoundCornersEnabled';
import { UserProfileNft } from 'cb-wallet-data/stores/DecentralizedID/hooks/useNFTsForProfilePhoto';
import { usePalette } from '@cbhq/cds-mobile/hooks/usePalette';
import { useSpacingScale } from '@cbhq/cds-mobile/hooks/useSpacingScale';
import { Box } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';

import { CollectibleAsset } from ':rn/cds-wallet/components/Collectibles/CollectibleAsset';
import { ROUNDED_NFT_RADIUS } from ':rn/screens/Collectibles/utils/constants';
import { useDimensions } from ':rn/shared/hooks/useDimensions';

type NFTGalleryListItemProps = {
  token: UserProfileNft;
  onPress: (token: UserProfileNft | null) => void;
  isSelected: boolean;
  testID?: string;
};

const DIMENSION_SCALE_DENOMINATOR = 2.4;

export const NFTGalleryListItem = memo(function NFTGalleryListItem({
  token,
  onPress,
  isSelected,
  testID,
}: NFTGalleryListItemProps) {
  const { screenWidth } = useDimensions();
  const spacing = useSpacingScale();
  const isNFTRoundCornersEnabled = useIsNFTRoundCornersEnabled();

  const colors = usePalette();

  const dimension = screenWidth / DIMENSION_SCALE_DENOMINATOR - spacing[2];

  const borderColor = useMemo(
    () => (isSelected ? colors.primary : colors.transparent),
    [isSelected, colors],
  );

  const dangerousStyle = useMemo(() => {
    if (isNFTRoundCornersEnabled) {
      return { borderRadius: ROUNDED_NFT_RADIUS, borderColor, borderWidth: 2 };
    }
  }, [borderColor, isNFTRoundCornersEnabled]);

  const dangerousRadius = useMemo(() => {
    if (isNFTRoundCornersEnabled) {
      return ROUNDED_NFT_RADIUS;
    }
  }, [isNFTRoundCornersEnabled]);

  const handlePress = useCallback(() => {
    onPress(isSelected ? null : token);
  }, [isSelected, onPress, token]);

  return (
    <Box spacingBottom={2} testID={testID}>
      <Pressable
        key={token.id}
        onPress={handlePress}
        testID={`collections-list-v2-collectible-${token.id}`}
        background="background"
      >
        <Box
          background="background"
          flexBasis="50%"
          minWidth={dimension}
          minHeight={dimension}
          style={dangerousStyle}
        >
          <CollectibleAsset
            hasBackground
            height={dimension}
            width={dimension}
            contractAddress={token.contractAddress}
            animationUrl={token.animationUrl}
            imageUrl={token.imageUrl}
            cachedAnimationUrl={token.cachedAnimationUrl}
            cachedImageUrl={token.cachedImageUrl}
            chainId={token.chainId}
            preview
            dangerouslySetRadius={dangerousRadius}
            testID={`collectible-asset-${token.contractAddress}-${token.tokenId}`}
            name={token.name}
          />
        </Box>
      </Pressable>
    </Box>
  );
});

