import { memo, useCallback, useMemo, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { SceneMap, TabView } from 'react-native-tab-view';
import { useIsNftPfpEnabled } from 'cb-wallet-data/stores/DecentralizedID/hooks/useIsNftPfpEnabled';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { VStack } from '@cbhq/cds-mobile/layout';
import { PortalProvider } from '@cbhq/cds-mobile/overlays/PortalProvider';
import { TabNavigation } from '@cbhq/cds-mobile/tabs/TabNavigation';

import { Modal } from ':rn/cds-wallet/components/Modal/Modal';

import { ProfilePictureModalHeader } from './ProfilePictureModalHeader';
import { SelectNFT } from './SelectNFT';
import { UploadImage } from './UploadImage';

const messages = defineMessages({
  uploadImage: {
    defaultMessage: 'Upload image',
    description: 'Tab title for uploading a profile image',
  },
  selectNFT: {
    defaultMessage: 'Select NFT',
    description: 'Tab title for selecting a profile nft',
  },
});

enum Tab {
  UPLOAD_IMAGE = 'UPLOAD_IMAGE',
  SELECT_NFT = 'SELECT_NFT',
}

export type ProfilePictureModalProps = {
  address: string;
  onClose: () => void;
  visible: boolean;
};

export const ProfilePictureModal = memo(function ProfilePictureModal({
  address,
  onClose,
  visible,
}: ProfilePictureModalProps) {
  const { formatMessage } = useIntl();
  const [tabIndex, setTabIndex] = useState(0);
  const isNftPfpEnabled = useIsNftPfpEnabled();
  const tabs = useMemo(() => {
    const visibleTabs = [{ id: Tab.UPLOAD_IMAGE, label: formatMessage(messages.uploadImage) }];
    if (isNftPfpEnabled) {
      visibleTabs.push({ id: Tab.SELECT_NFT, label: formatMessage(messages.selectNFT) });
    }
    return visibleTabs;
  }, [formatMessage, isNftPfpEnabled]);

  const active = useMemo(() => tabs[tabIndex].id, [tabIndex, tabs]);

  const navigationState = useMemo(
    () => ({ index: tabIndex, routes: tabs.map(({ id, label }) => ({ key: id, title: label })) }),
    [tabIndex, tabs],
  );

  const handleTabChange = useCallback(
    (tabId: string) => {
      setTabIndex(tabs.findIndex(({ id }) => tabId === id));
    },
    [tabs],
  );

  const renderScene = SceneMap({
    [Tab.UPLOAD_IMAGE]: useCallback(() => <UploadImage address={address} />, [address]),
    [Tab.SELECT_NFT]: useCallback(() => <SelectNFT onClose={onClose} />, [onClose]),
  });

  const renderTabBar = useCallback(() => {
    return (
      <TabNavigation
        variant="primary"
        tabs={tabs}
        onChange={handleTabChange}
        value={active}
        testID="profile-picture-tab-nav"
        spacingHorizontal={3}
      />
    );
  }, [active, handleTabChange, tabs]);
  return (
    <PortalProvider>
      <Modal testID="profile-picture-modal" visible={visible} hideDividers onRequestClose={onClose}>
        <VStack spacingTop={1} spacingHorizontal={1}>
          <IconButton onPress={onClose} name="close" transparent testID="close-modal" />
        </VStack>
        <VStack spacingHorizontal={3}>
          <ProfilePictureModalHeader />
        </VStack>
        <TabView
          navigationState={navigationState}
          renderScene={renderScene}
          onIndexChange={setTabIndex}
          renderTabBar={renderTabBar}
        />
      </Modal>
    </PortalProvider>
  );
});

import { memo, useCallback } from 'react';
import {
  triggerSignoutConfirmed,
  triggerSignoutPhraseAcknowledge,
  useSignoutConfirmationViewed,
} from 'cb-wallet-analytics/offboarding';
import { useUserFacingAccountsData } from 'cb-wallet-data/stores/Accounts/hooks/useUserFacingAccountsData';
import { isSigningOutAtom } from 'cb-wallet-data/stores/Global/state';
import { useRecoilValue } from 'recoil';
import { useToggler } from '@cbhq/cds-mobile';
import { Checkbox } from '@cbhq/cds-mobile/controls';
import { HStack, Spacer, VStack } from '@cbhq/cds-mobile/layout';
import { TextBody, TextHeadline, TextLabel2 } from '@cbhq/cds-mobile/typography';

import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { BigRedWarning } from ':rn/cds-wallet/images/BigRedWarning';
import { withScreenBoundary } from ':rn/cds-wallet/utils/withScreenBoundary';
import { SignoutAndCleanup } from ':rn/screens/Offboarding/SignoutAndCleanup';
import { useParams } from ':rn/shared/hooks/useParams';
import { useSignout } from ':rn/shared/hooks/useSignout';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';
import { SignoutParamList } from ':rn/shared/types/ParamLists';

import { useSignOutConfirmationCopy } from './useSignOutConfirmationCopy';

type SignoutConfirmContentProps = {
  onBack?: () => void;
  isMnemonicEscapeHatch: boolean;
  mnemonicsLength?: number;
};

export const SignoutConfirmContent = memo(function SignoutConfirmContent({
  onBack,
  isMnemonicEscapeHatch,
  mnemonicsLength,
}: SignoutConfirmContentProps) {
  const signout = useSignout();
  const isSigningOut = useRecoilValue(isSigningOutAtom);
  const [acknowledged, { toggle: toggleAcknowledged }] = useToggler(false);
  const { accountTotals } = useUserFacingAccountsData();
  const numAccounts = mnemonicsLength ?? accountTotals.mnemonic + accountTotals.mpc;

  const hasAccounts = numAccounts !== 0;
  const { signOutScreenContentCopy, checkboxCopy, title, signOutButtonCopy, goBackButtonCopy } =
    useSignOutConfirmationCopy({ numAccounts });

  useSignoutConfirmationViewed(isMnemonicEscapeHatch);

  const handleCheckboxChange = useCallback(
    function handleCheckboxChange() {
      toggleAcknowledged();
      if (!acknowledged) {
        triggerSignoutPhraseAcknowledge();
      }
    },
    [acknowledged, toggleAcknowledged],
  );

  const handleSignout = useCallback(
    function handleSignout() {
      const context = isMnemonicEscapeHatch ? 'escape-hatch' : 'signout-confirmation';
      triggerSignoutConfirmed();
      signout({ context });
    },
    [isMnemonicEscapeHatch, signout],
  );

  // RootStack cannot re-render when the escape hatch is open,
  // thus Signout and cleanup needs to be done here
  if (isMnemonicEscapeHatch && isSigningOut) {
    return <SignoutAndCleanup />;
  }

  return (
    <VStack
      flexGrow={1}
      height="100%"
      spacing={2}
      justifyContent="space-between"
      alignItems="center"
    >
      <VStack flexGrow={1} justifyContent="center" alignItems="center">
        <BigRedWarning />

        <TextHeadline align="start">{title}</TextHeadline>
        {hasAccounts && (
          <TextBody testID="content-copy" spacingTop={3} align="center" color="foregroundMuted">
            {signOutScreenContentCopy}
          </TextBody>
        )}
      </VStack>
      <VStack width="100%">
        {hasAccounts && (
          <HStack width="100%" alignItems="center" justifyContent="flex-start" spacingStart={1}>
            <Checkbox
              testID="sign-out-acknowledge-phrase"
              checked={acknowledged}
              onChange={handleCheckboxChange}
              accessibilityLabel={checkboxCopy}
            />
            <Spacer horizontal={1} />
            <TextLabel2 onPress={toggleAcknowledged}>{checkboxCopy}</TextLabel2>
          </HStack>
        )}

        <Spacer vertical={2} />
        {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
        {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
        <Button
          spacingBottom={2}
          testID="sign-out-final-confirmation-button"
          variant="primary"
          flexGrow={1}
          disabled={!acknowledged && hasAccounts}
          loading={isSigningOut}
          onPress={handleSignout}
        >
          {signOutButtonCopy}
        </Button>
        {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
        {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
        <Button
          spacingBottom={2}
          loading={isSigningOut}
          variant="secondary"
          transparent
          onPress={onBack}
        >
          {goBackButtonCopy}
        </Button>
      </VStack>
    </VStack>
  );
});

function SignoutConfirmationContent() {
  const { goBack } = useStackNavigation();
  // eslint-disable-next-line wallet/no-restricted-route-params
  const { isMnemonicEscapeHatch, mnemonicsLength } = useParams<
    SignoutParamList,
    'SignoutConfirmation'
  >();
  return (
    <SignoutConfirmContent
      mnemonicsLength={mnemonicsLength}
      onBack={goBack}
      isMnemonicEscapeHatch={isMnemonicEscapeHatch}
    />
  );
}

export const SignoutConfirmationScreen = withScreenBoundary(SignoutConfirmationContent);

