import { memo, useCallback, useMemo } from 'react';
import { StyleProp, ViewStyle } from 'react-native';
import { logSettingCategoryPressed } from 'cb-wallet-analytics/settings';
import { useAccountsWithWalletGroups } from 'cb-wallet-data/stores/Accounts/hooks/useAccountsWithWalletGroups';
import { SettingCategoryConfig } from 'cb-wallet-data/stores/SettingsRedesign/types';
import { useSpectrum } from '@cbhq/cds-common';
import { paletteValueToRgbaString } from '@cbhq/cds-common/palette/paletteValueToRgbaString';
import { Icon } from '@cbhq/cds-mobile/icons';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';

import { SettingCell } from ':rn/screens/SettingsRedesign/components/SettingCell';
import { WalletGroupAvatar } from ':rn/shared/components/MultiWallet/WalletGroupAvatar';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { useManageAllWalletsCategoryBaseConfig } from '../hooks/useManageAllWalletsCategoryBaseConfig';

const walletGroupAvatarSharedStyle: StyleProp<ViewStyle> = {
  position: 'absolute',
  borderWidth: 3,
  borderRadius: 100,
};

type ManageAllWalletsProps = {
  onPress?: () => void;
};

export const ManageAllWallets = memo(function ManageAllWallets({ onPress }: ManageAllWalletsProps) {
  const spectrum = useSpectrum();
  const { navigate } = useStackNavigation();
  const manageAllWalletsConfig = useManageAllWalletsCategoryBaseConfig();
  const accountsWithWalletGroups = useAccountsWithWalletGroups();

  const walletGroupsToDisplay = useMemo(() => {
    return accountsWithWalletGroups.flatMap((account) => account.walletGroups);
  }, [accountsWithWalletGroups]);

  const borderColor = useMemo(() => paletteValueToRgbaString(`gray5`, spectrum), [spectrum]);

  const iconContainerStyle = useMemo<StyleProp<ViewStyle>>(() => {
    return { ...walletGroupAvatarSharedStyle, borderColor };
  }, [borderColor]);

  const addIconColor = useMemo(() => paletteValueToRgbaString('gray0', spectrum), [spectrum]);

  const addIconBackGroundColor = useMemo(
    () => paletteValueToRgbaString(`gray60`, spectrum),
    [spectrum],
  );

  const addIconSingleWalletGroupContainerStyle = useMemo<StyleProp<ViewStyle>>(() => {
    return {
      ...walletGroupAvatarSharedStyle,
      position: 'relative',
      borderColor,
      backgroundColor: addIconBackGroundColor,
    };
  }, [addIconBackGroundColor, borderColor]);

  const addIconMultiWalletGroupsContainerStyle = useMemo<StyleProp<ViewStyle>>(() => {
    return {
      ...walletGroupAvatarSharedStyle,
      borderColor,
      backgroundColor: addIconBackGroundColor,
    };
  }, [addIconBackGroundColor, borderColor]);

  const AddIcon = useMemo(() => {
    return (
      <Icon
        name="add"
        size="s"
        spacing={0.5}
        dangerouslySetColor={addIconColor}
        testID="add-icon"
      />
    );
  }, [addIconColor]);

  const media = useMemo(() => {
    if (walletGroupsToDisplay.length <= 1) {
      return (
        <Box bordered style={addIconSingleWalletGroupContainerStyle}>
          {AddIcon}
        </Box>
      );
    }

    return (
      <HStack alignItems="center" position="relative" width={70} spacingVertical={2}>
        <Box borderColor="transparent" bordered style={iconContainerStyle}>
          <WalletGroupAvatar
            walletGroup={walletGroupsToDisplay[0]}
            size="m"
            testID="wallet-avatar"
          />
        </Box>
        <Box bordered left={20} style={iconContainerStyle}>
          <WalletGroupAvatar
            walletGroup={walletGroupsToDisplay[1]}
            size="m"
            testID="wallet-avatar"
          />
        </Box>
        <Box bordered left={40} style={addIconMultiWalletGroupsContainerStyle}>
          {AddIcon}
        </Box>
      </HStack>
    );
  }, [
    AddIcon,
    addIconSingleWalletGroupContainerStyle,
    addIconMultiWalletGroupsContainerStyle,
    iconContainerStyle,
    walletGroupsToDisplay,
  ]);

  const handlePress = useCallback(
    function handleManageAllWalletsPress() {
      logSettingCategoryPressed({ context: 'manage_all_wallets' });
      navigate('AddAndManageWallets');
      onPress?.();
    },
    [navigate, onPress],
  );

  const config = useMemo<SettingCategoryConfig>(
    () => ({
      ...manageAllWalletsConfig,
      title: <TextBody color="foregroundMuted">{manageAllWalletsConfig.title}</TextBody>,
      media,
    }),
    [manageAllWalletsConfig, media],
  );

  return (
    <Box spacingHorizontal={2} spacingBottom={2}>
      <Pressable
        background="backgroundAlternate"
        borderRadius="roundedLarge"
        onPress={handlePress}
        testID="manage-all-wallets-pressable"
      >
        <SettingCell config={config} />
      </Pressable>
    </Box>
  );
});

