import { memo, useCallback, useMemo } from 'react';
import { TouchableWithoutFeedback } from 'react-native-gesture-handler';
import { SettingCategoryConfig } from 'cb-wallet-data/stores/SettingsRedesign/types';
import { Cell, CellProps } from '@cbhq/cds-mobile/cells/Cell';
import { Divider, VStack } from '@cbhq/cds-mobile/layout';
import { TextBody, TextHeadline } from '@cbhq/cds-mobile/typography';

import { SettingCellAccessory } from './SettingCellAccessory';
import { SettingCellMedia } from './SettingCellMedia';

const cellPriority: CellProps['priority'] = ['middle', 'end'];

type SettingCellProps = {
  config: SettingCategoryConfig;
};

export const SettingCell = memo(function SettingCell({ config }: SettingCellProps) {
  const title = useMemo(() => {
    if (typeof config.title === 'string') {
      return (
        <TextHeadline numberOfLines={1} ellipsize="tail">
          {config.title}
        </TextHeadline>
      );
    }

    return config.title;
  }, [config]);

  const description = useMemo(() => {
    if (typeof config.description === 'string') {
      return <TextBody color="foregroundMuted">{config.description}</TextBody>;
    }

    return config.description;
  }, [config]);

  const detail = useMemo(() => {
    if (typeof config.detail === 'string') {
      return (
        <TextBody color="foregroundMuted" testID={`${config?.testID}-detail`}>
          {config.detail}
        </TextBody>
      );
    }

    return config.detail;
  }, [config]);

  const media = useMemo(() => {
    if (!config.media) return;

    if (typeof config.media === 'string') {
      return <SettingCellMedia type={config.media} />;
    }

    return config.media;
  }, [config.media]);

  // Avoid passing the gesture event to config.onPress
  const onPress = useCallback(() => config.onPress?.(), [config]);

  const cell = useMemo(() => {
    return (
      <>
        <Cell
          accessory={
            config.accessory ? <SettingCellAccessory type={config.accessory} /> : undefined
          }
          media={media}
          onPress={config.isTouchableWithoutFeedback || !config.onPress ? undefined : onPress}
          priority={config.priority ?? cellPriority}
          detail={detail}
          testID={config.testID}
          innerSpacing={config.innerSpacing}
          outerSpacing={config.outerSpacing}
          accessibilityLabel="settings-cell-list-item"
        >
          <VStack justifyContent="center">
            {title}
            {description}
          </VStack>
        </Cell>
        {config.showDivider && <Divider spacingVertical={1} />}
      </>
    );
  }, [
    config.accessory,
    config.innerSpacing,
    config.isTouchableWithoutFeedback,
    config.onPress,
    config.outerSpacing,
    config.priority,
    config.showDivider,
    config.testID,
    description,
    detail,
    media,
    onPress,
    title,
  ]);

  return config.isTouchableWithoutFeedback ? (
    <TouchableWithoutFeedback onPress={onPress}>{cell}</TouchableWithoutFeedback>
  ) : (
    cell
  );
});

