export const Appearance = memo(function Appearance() {
  const { formatMessage } = useIntl();
  const rootSpectrumPreference = useRootSpectrumPreference();
  const rootSpectrumPreferenceUpdater = useRootSpectrumPreferenceUpdater();

  const updatePreference = useCallback(
    function updatePreference(preference: RootSpectrumPreference) {
      Store.set(StoreKeys_rootSpectrumPreference, preference);
      rootSpectrumPreferenceUpdater(preference);
    },
    [rootSpectrumPreferenceUpdater],
  );

  const handleDeviceSettingsPress = useCallback(() => {
    updatePreference('system');
  }, [updatePreference]);

  const handleLightPress = useCallback(() => {
    updatePreference('light');
  }, [updatePreference]);

  const handleDarkPress = useCallback(() => {
    updatePreference('dark');
  }, [updatePreference]);

  const buildDetailComponent = useCallback(
    function buildDetailComponent(mode: RootSpectrumPreference, onPress: () => void) {
      const isChecked = rootSpectrumPreference === mode;
      const radioStateMessage = isChecked ? messages.selectedMode : messages.unselectedMode;

      return (
        <Radio
          checked={isChecked}
          accessibilityLabel={formatMessage(radioStateMessage)}
          onPress={onPress}
        />
      );
    },
    [formatMessage, rootSpectrumPreference],
  );

  const darkConfig = useMemo<SettingCategoryConfig>(() => {
    return {
      title: formatMessage(messages.darkTitle),
      description: formatMessage(messages.darkDescription),
      detail: buildDetailComponent('dark', handleDarkPress),
      onPress: handleDarkPress,
      testID: 'dark-mode',
    };
  }, [buildDetailComponent, formatMessage, handleDarkPress]);

  const lightConfig = useMemo<SettingCategoryConfig>(() => {
    return {
      title: formatMessage(messages.lightTitle),
      description: formatMessage(messages.lightDescription),
      detail: buildDetailComponent('light', handleLightPress),
      onPress: handleLightPress,
      testID: 'light-mode',
    };
  }, [buildDetailComponent, formatMessage, handleLightPress]);

  const systemConfig = useMemo<SettingCategoryConfig>(() => {
    return {
      title: formatMessage(messages.systemTitle),
      description: formatMessage(messages.systemDescription),
      detail: buildDetailComponent('system', handleDeviceSettingsPress),
      onPress: handleDeviceSettingsPress,
      testID: 'system-mode',
    };
  }, [buildDetailComponent, formatMessage, handleDeviceSettingsPress]);

  return (
    <Section title={formatMessage(messages.appearanceSectionTitle)} showDivider>
      <SettingCell config={darkConfig} />
      <SettingCell config={lightConfig} />
      <SettingCell config={systemConfig} />
    </Section>
  );
});

