import { useCallback } from 'react';
import {
  StoreKeys_chaosTestingProviderGroups,
  StoreKeys_chaosTestingServiceGroups,
} from 'cb-wallet-http/fetchJSON';
import { Store } from 'cb-wallet-store/Store';

import { SwitchSettingsCell } from ':rn/screens/Settings/components/SwitchSettingCell';

type ChaosTestingListItemProps = {
  group: { name: string; id: string; type: 'service' | 'provider' };
  currentGroups: string;
};

export function ChaosTestingListItem({ group, currentGroups }: ChaosTestingListItemProps) {
  const handleSwitch = useCallback(
    function toggleServiceGroup(id: string, type: string) {
      return (isToggled: boolean) => {
        if (isToggled) {
          if (!currentGroups.includes(id)) {
            const storeKey =
              type === 'service'
                ? StoreKeys_chaosTestingServiceGroups
                : StoreKeys_chaosTestingProviderGroups;
            Store.set(storeKey, `${currentGroups}${id},`);
          }
        } else {
          const storeKey =
            type === 'service'
              ? StoreKeys_chaosTestingServiceGroups
              : StoreKeys_chaosTestingProviderGroups;
          Store.set(storeKey, currentGroups.replace(`${id},`, ''));
        }
        return true;
      };
    },
    [currentGroups],
  );

  return (
    <SwitchSettingsCell
      handleSwitch={handleSwitch(group.id, group.type)}
      title={group.name}
      accessibilityLabel={group.name}
      isOn={currentGroups.includes(group.id)}
      key={group.id}
      testID={`chaos-testing-service-${group.id}`}
    />
  );
}

