const DebugDeepLinksScreenInner = memo(function DebugDeepLinksScreenInner() {
  const { navigateToUrl, state } = useDeepLinkProvider();
  const { listAllRoutes } = useDeepLinkListRoutesContext();
  const registeredRoutes = useMemo(() => {
    const allRoutes = listAllRoutes();
    const sections: SectionItem[] = [];

    if (!allRoutes.length) {
      return sections;
    }

    sections.push({
      title: 'Filter routes',
      owningTeamId: '',
      data: ['search-and-simulate'],
    });

    let currentSection: SectionItem = {
      title: allRoutes[0].groupTitle,
      owningTeamId: allRoutes[0].owningTeamId,
      data: [],
    };

    for (const route of allRoutes) {
      if (
        currentSection.title === route.groupTitle &&
        currentSection.owningTeamId === route.owningTeamId
      ) {
        currentSection.data.push(route);
      } else {
        sections.push(currentSection);
        currentSection = {
          title: route.groupTitle,
          owningTeamId: route.owningTeamId,
          data: [route],
        };
      }
    }

    sections.push(currentSection);

    return sections;
  }, [listAllRoutes]);

  const [query, setQuery] = useState('');
  const filteredRoutes = useMemo(() => {
    if (!query) {
      return registeredRoutes;
    }
    return registeredRoutes.filter((route) => {
      if (route.data[0] === 'search-and-simulate') {
        return true;
      }
      return (
        route.title.toLowerCase().includes(query.toLowerCase()) ||
        route.owningTeamId.toLowerCase().includes(query.toLowerCase()) ||
        route.data.some((r) =>
          typeof r === 'string'
            ? true
            : r.name.toLowerCase().includes(query.toLowerCase()) ||
              r.path.includes(query.toLowerCase()),
        )
      );
    });
  }, [query, registeredRoutes]);

  const renderRouteTitle = useCallback(
    ({
      section: { title, owningTeamId },
    }: {
      section: SectionListData<DeepLinkProps | string, SectionItem>;
    }) => {
      return (
        <HStack
          justifyContent="space-between"
          alignItems="center"
          spacingHorizontal={2}
          spacingVertical={0.5}
          borderedBottom
          borderColor="line"
          background="background"
        >
          <TextBody>{title}</TextBody>
          <TextLegal>{owningTeamId}</TextLegal>
        </HStack>
      );
    },
    [],
  );

  const renderRouteItem = useCallback(
    ({ item: route }: ListRenderItemInfo<DeepLinkProps | string>) => {
      if (typeof route === 'string')
        return (
          <SearchAndSimulateUI
            query={query}
            setQuery={setQuery}
            isNavigating={state === 'processing'}
            onSimulate={navigateToUrl}
          />
        );
      const schemeInfo = (
        typeof route.schemes === 'string' ? [route.schemes] : route.schemes ?? []
      ).join(', ');
      const hostInfo = (typeof route.hosts === 'string' ? [route.hosts] : route.hosts ?? []).join(
        ', ',
      );

      return (
        <VStack spacingHorizontal={2} spacingVertical={1} gap={0.5} borderedBottom>
          <TextBody>{route.name}</TextBody>
          <TextBody color="foregroundMuted">{route.description}</TextBody>
          <TextLegal color="foregroundMuted">
            <TextLegal color="foreground">Path: </TextLegal>
            <Text>{route.path}</Text>
          </TextLegal>
          {schemeInfo && (
            <TextLegal color="foregroundMuted">
              <TextLegal color="foreground">Schemes: </TextLegal>
              <Text>{schemeInfo}</Text>
            </TextLegal>
          )}
          {hostInfo && (
            <TextLegal color="foregroundMuted">
              <TextLegal color="foreground">Hosts: </TextLegal>
              <Text>{hostInfo}</Text>
            </TextLegal>
          )}
        </VStack>
      );
    },
    [navigateToUrl, query, state],
  );

  const keyExtractor = useCallback(
    (route: DeepLinkProps | string) => (typeof route === 'string' ? route : route.name),
    [],
  );

  return (
    <Screen navBar={navBar}>
      <SectionList
        stickySectionHeadersEnabled
        sections={filteredRoutes}
        renderItem={renderRouteItem}
        renderSectionHeader={renderRouteTitle}
        keyExtractor={keyExtractor}
      />
    </Screen>
  );
});

