import { useCallback, useMemo, useState } from 'react';
import { HCESession, NFCTagType4, NFCTagType4NDEFContentType } from 'react-native-hce';
import { logNfcTagError } from 'cb-wallet-analytics/nfc/nfc';
import { TextInput } from '@cbhq/cds-mobile/controls';
import { VStack } from '@cbhq/cds-mobile/layout';

import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { Screen } from ':rn/cds-wallet/components/layout/Screen';
import { NavBarConfig } from ':rn/cds-wallet/components/NavBar/NavBar';

export function NFC() {
  const [input, setInput] = useState<string>();
  const navBar = useMemo<NavBarConfig>(() => ({ title: 'NFC Tag', left: 'back' }), []);

  const handleNfcTag = useCallback(
    async function handleNfcTag() {
      try {
        const tag = new NFCTagType4({
          type: NFCTagType4NDEFContentType.Text,
          content:
            input ?? `send/prefilledSend/ETH/8453/0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913/1e6`,
          writable: false,
        });

        const session = await HCESession.getInstance();
        session.setApplication(tag);
        await session.setEnabled(true);

        session.on(HCESession.Events.HCE_STATE_READ, async () => {
          // Additional actions upon read
          await session.setEnabled(false);
        });
      } catch (e: ErrorOrAny) {
        // Handle error
        logNfcTagError(e);
      }
    },
    [input],
  );

  return (
    <Screen navBar={navBar} scrollable>
      <VStack gap={3} spacing={3}>
        <TextInput
          multiline
          label="Type NFC tag payload"
          placeholder="Enter a message"
          onChangeText={setInput}
          value={input}
        />
        <Button block onPress={handleNfcTag}>
          Set
        </Button>
      </VStack>
    </Screen>
  );
}

