  const [isActiveSearch, { toggleOn: toggleActiveSearchOn, toggleOff: toggleActiveSearchOff }] =
    useToggler(false);
  const [query, setQuery] = useState('');
  const [mainnets, testnets] = useDefaultNetworks();
  const customNetworks = useCustomNetworkArgs();

  const filterMainnets = useNetworkSearch({ networks: mainnets, query });
  const filterTestnets = useNetworkSearch({ networks: testnets, query });
  const filterCustomNetworks = useNetworkSearch({ networks: customNetworks, query });

  const networkSections = useMemo(() => {
    return [
      {
        title: formatMessage(messages.mainnetsTabLabel),
        data: filterMainnets,
      },
      {
        title: formatMessage(messages.testnetsTabLabel),
        data: filterTestnets,
      },
      {
        title: formatMessage(messages.customTabLabel),
        data: filterCustomNetworks,
      },
    ];
  }, [filterCustomNetworks, filterMainnets, filterTestnets, formatMessage]);

  const handleAddCustomNetworkPress = useCallback(
    function handleAddCustomNetworkPress() {
      triggerAddCustomNetworkClick('tabsView-list');
      navigate('CustomNetwork', { action: 'Add' });
    },
    [navigate],
  );

  const addCustomNetworkButton = useCallback(
    () => <IconButton onPress={handleAddCustomNetworkPress} transparent name="add" />,
    [handleAddCustomNetworkPress],
  );

  const { routes, navigationState, listContainerStyles, handleIndexChange } =
    useNetworksSettingTabContext();

