  );
  const customTabList = useCallback(
    () => <NetworkList items={customNetworks} testID="custom-networks-list" />,
    [customNetworks],
  );

  const scenes = useMemo(() => {
    return routes.reduce((accumulator, cur) => {
      let scene: React.ComponentType;

      switch (cur.key) {
        case NetworksSettingTabKey.MAINNETS:
          scene = mainnetsTabList;
          break;
        case NetworksSettingTabKey.TESTNETS:
          scene = testnetsTabList;
          break;
        case NetworksSettingTabKey.CUSTOM:
