      return accumulator;
    }, {} as Record<string, React.ComponentType>);
  }, [customTabList, mainnetsTabList, routes, testnetsTabList]);

  const renderScene = SceneMap(scenes);

  const handleSearch = useCallback(function handleNetworksSearch(queryText: string) {
    setQuery(queryText);
