import { memo, useCallback, useMemo } from 'react';
import { useIntl } from 'react-intl';
import {
  triggerNotificationSettingsToggled,
  useNotificationSettingsViewed,
} from 'cb-wallet-analytics/notifications/settingsEvents';
import { reportComponentError } from 'cb-wallet-data/errors/reportError';
import { useIsFeatureEnabled } from 'cb-wallet-data/FeatureManager/hooks/useIsFeatureEnabled';
import { useOverridableKillSwitch } from 'cb-wallet-data/hooks/KillSwitches/useOverridableKillSwitch';
import { getKillSwitchByPlatform } from 'cb-wallet-data/hooks/KillSwitches/utils/getKillSwitchByPlatform';
import { useIsMessagingEnabled } from 'cb-wallet-data/stores/Messaging/hooks/useIsMessagingEnabled';
import {
  PreferencesMap,
  PreferencesMapValueType,
  resolveDynamicDescriptor,
} from 'cb-wallet-data/stores/Notifications/channels/preferences';
import { useNotificationPreferences } from 'cb-wallet-data/stores/Notifications/hooks/useNotificationPreferences';
import {
  matchingKey,
  useUpdateNotificationPreference,
} from 'cb-wallet-data/stores/Notifications/hooks/useUpdateNotificationPreference';
import { SimplifiedNotificationPreference } from 'cb-wallet-data/stores/Notifications/types/NotificationPreference';
import { messages } from 'cb-wallet-data/stores/SettingsRedesign/messages/notifications';
import { ListCell } from '@cbhq/cds-mobile/cells';
import { Switch } from '@cbhq/cds-mobile/controls';
import { Box } from '@cbhq/cds-mobile/layout';

import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';

export type DesctructuredPreferenceMap = {
  preferences: SimplifiedNotificationPreference[];
  walletActivityAlertPreference?: SimplifiedNotificationPreference;
  walletMessagingAlertPreference?: SimplifiedNotificationPreference;
  gasFeesAlertPreference?: SimplifiedNotificationPreference;
};

export const NotificationPreferences = memo(function NotificationPreferences() {
  const { formatMessage } = useIntl();
  const toast = useRateLimitedToast({});
  const isMessagingEnabled = useIsMessagingEnabled();
  const isGasFeeNotifsEnabled = useIsFeatureEnabled('lower_gas_fee_notifs');

  const allPreferences = useNotificationPreferences({ suspense: true });
  // we show the NFT offer notification settings in a different screen
  const preferencesMap = useMemo(
    () =>
      allPreferences?.reduce<DesctructuredPreferenceMap>(
        (acc, pref) => {
          switch (pref.type) {
            case 'WALLET_ACTIVITY':
              acc.walletActivityAlertPreference = pref;
              return acc;
            case 'WALLET_MESSAGING':
              acc.walletMessagingAlertPreference = pref;
              return acc;
            case 'GAS_FEES':
              acc.gasFeesAlertPreference = pref;
              return acc;
            default:
              acc.preferences.push(pref);
              return acc;
          }
        },
        {
          preferences: [],
        },
      ),
    [allPreferences],
  );
  const preferences = preferencesMap?.preferences;
  const walletActivityAlertPreference = preferencesMap?.walletActivityAlertPreference;
  const walletMessagingAlertPreference = preferencesMap?.walletMessagingAlertPreference;
  const showWalletMessagingAlertPreference = isMessagingEnabled && !!walletMessagingAlertPreference;
  const gasFeesAlertPreference = preferencesMap?.gasFeesAlertPreference;
  const showGasFeesAlertPreference = isGasFeeNotifsEnabled && !!gasFeesAlertPreference;

  const { mutate: updateNotificationPreference } = useUpdateNotificationPreference({
    onError: () => toast.show(formatMessage(messages.notificationPreferencesErrorToast)),
  });

  useNotificationSettingsViewed();

  const togglePreference = useCallback(
    function togglePreference(preference: SimplifiedNotificationPreference) {
      triggerNotificationSettingsToggled(preference);

      updateNotificationPreference({
        ...preference,

        currentlyEnabled: preference.enabled,
        switchingTo: !preference.enabled,
        ...(preference.enum ? { currentEnum: preference.enum, newEnum: preference.enum } : {}),
      });
    },
    [updateNotificationPreference],
  );

  const renderPreferenceRow = useCallback(
    function renderPreferenceRow(preference: SimplifiedNotificationPreference) {
      const metadata = PreferencesMap[matchingKey(preference)];

      if (!metadata) {
        reportComponentError({
          error: new Error(
            'Notification preference not supported on wallet frontend, label and feature flag definition needed',
          ),
          metadata: {
            preferenceKey: preference.key,
            preferenceType: preference.type,
          },
          severity: 'error',
          isHandled: false,
        });
        return null;
      }

      return (
        <PreferenceRow
          key={`${preference.type}${preference.key}`}
          preference={preference}
          metadata={metadata}
          onToggle={togglePreference}
          enabled={preference.enabled}
        />
      );
    },
    [togglePreference],
  );

  const preferenceRows = useMemo(() => {
    if (!preferences) {
      return null;
    }

    return preferences.map(renderPreferenceRow);
  }, [preferences, renderPreferenceRow]);

  return (
    <Box spacingVertical={3} testID="notification-preferences">
      {preferenceRows}
      {walletActivityAlertPreference && renderPreferenceRow(walletActivityAlertPreference)}
      {showWalletMessagingAlertPreference && renderPreferenceRow(walletMessagingAlertPreference)}
      {showGasFeesAlertPreference && renderPreferenceRow(gasFeesAlertPreference)}
    </Box>
  );
});

type PreferenceRowProps = {
  preference: SimplifiedNotificationPreference;
  metadata: PreferencesMapValueType;
  onToggle: (preference: SimplifiedNotificationPreference) => void;
  enabled: boolean;
};

export const PreferenceRow = memo(function Preference({
  metadata,
  preference,
  onToggle,
  enabled,
}: PreferenceRowProps) {
  const { title, description, killSwitch } = metadata;
  const intlShape = useIntl();
  const isFeatureEnabled = !useOverridableKillSwitch(getKillSwitchByPlatform(killSwitch));

  const toggle = useCallback(() => {
    onToggle(preference);
  }, [onToggle, preference]);

  if (!isFeatureEnabled) {
    return null;
  }

  return (
    <ListCell
      testID="notification-preference-row"
      title={resolveDynamicDescriptor(intlShape, title)}
      description={description && resolveDynamicDescriptor(intlShape, description)}
      multiline
      action={
        <Switch
          accessibilityLabel="toggle"
          onChange={toggle}
          checked={enabled}
          testID={`${preference.type}-toggle`}
        />
      }
    />
  );
});

import { memo, useCallback, useState } from 'react';
import { useIntl } from 'react-intl';
import { MnemonicAccessContext } from 'cb-wallet-analytics/auth';
import { cbReportError, coerceError } from 'cb-wallet-data/errors/reportError';
import { useActiveAccountId } from 'cb-wallet-data/stores/Accounts/hooks/useActiveAccountId';
import { Account } from 'cb-wallet-data/stores/Accounts/models/Account';
import { isMnemonicResult } from 'cb-wallet-data/stores/Accounts/models/NonMnemonicUnlockResult';
import { messages } from 'cb-wallet-data/stores/SettingsRedesign/messages/security';
import { useRecoilState, useRecoilValue, useSetRecoilState } from 'recoil';
import { Box } from '@cbhq/cds-mobile/layout';
import { TextLegal } from '@cbhq/cds-mobile/typography';

import { useAreAccountBackupRemindersEnabled } from ':rn/screens/InstantOnboarding/hooks/useAreAccountBackupRemindersEnabled';
import { WalletListBackup } from ':rn/screens/Settings/screens/MnemonicBackup/WalletListBackup';
import { Section } from ':rn/screens/SettingsRedesign/components/Section';
import { SettingScreen } from ':rn/screens/SettingsRedesign/components/SettingScreen';
import { SwitchSettingCell } from ':rn/screens/SettingsRedesign/components/SwitchSettingCell';
import {
  messageDescriptorForBiometryType,
  saveUnlockedMnemonicsUsingBiometrics,
} from ':rn/shared/auth/Auth';
import { useRefreshAuthState } from ':rn/shared/auth/hooks/useRefreshAuthState';
import {
  isAuthRequiredForAppAccessAtom,
  isAuthRequiredForTxAtom,
} from ':rn/shared/auth/stores/appLockState';
import {
  authStateAtom,
  availableBiometricsAtom,
  hasAuthenticatedForAppAccessAtom,
} from ':rn/shared/auth/stores/authState';
import { useMnemonic } from ':rn/shared/hooks/useMnemonic';

import { AppLockMethodCell } from './AppLockMethodCell';

export const Security = memo(function Security() {
  const { formatMessage } = useIntl();

  const [highlightMinRequirementText, setHighlightMinRequirementText] = useState<boolean>(false);

  const [isAuthRequiredForAppAccess, setIsAuthRequiredForAppAccess] = useRecoilState(
    isAuthRequiredForAppAccessAtom,
  );
  const [isAuthRequiredForTx, setIsAuthRequiredForTx] = useRecoilState(isAuthRequiredForTxAtom);

  const setHasAuthenticatedForAppAccess = useSetRecoilState(hasAuthenticatedForAppAccessAtom);

  const authState = useRecoilValue(authStateAtom);
  const availableBiometry = useRecoilValue(availableBiometricsAtom);
  const messageDescriptorForBiometry = messageDescriptorForBiometryType(availableBiometry);
  const formattedAvailableBiometrics = formatMessage(messageDescriptorForBiometry);
  const areAccountBackupRemindersEnabled = useAreAccountBackupRemindersEnabled();
  const refreshAuthState = useRefreshAuthState();
  const { triggerAuth } = useMnemonic({ requireAuthentication: true, fetchAllMnemonics: true });
  const activeAccountId = useActiveAccountId();

  const handleHighlightMinRequirementText = useCallback(
    function handleHighlightMinRequirementText() {
      setHighlightMinRequirementText(true);

      setTimeout(() => {
        setHighlightMinRequirementText(false);
      }, 1000);
    },
    [setHighlightMinRequirementText],
  );

  const toggleAuthRequirementOnAppStartMnemonic = useCallback(
    function toggleAuthRequirementOnAppStartMnemonic(isToggled: boolean, toggle: () => void) {
      if (!isToggled) {
        triggerAuth({
          accountId: activeAccountId,
          successCallback: () => {
            setHasAuthenticatedForAppAccess(true);
            setIsAuthRequiredForAppAccess(isToggled);
            toggle();
            return true;
          },
          cancelledCallback: () => {
            return false;
          },
          mnemonicAccessContext: MnemonicAccessContext.ToggleAppAccess,
        });
        return false;
      }

      setHasAuthenticatedForAppAccess(true);
      setIsAuthRequiredForAppAccess(isToggled);
      return true;
    },
    [activeAccountId, setHasAuthenticatedForAppAccess, setIsAuthRequiredForAppAccess, triggerAuth],
  );

  const toggleAuthRequirementOnAppStart = useCallback(
    function toggleAuthRequirementOnAppStart(isToggled: boolean, toggle: () => void) {
      if (!isToggled && !isAuthRequiredForTx) {
        handleHighlightMinRequirementText();
        return false;
      }

      if (Account.isMnemonicAccount(activeAccountId)) {
        return toggleAuthRequirementOnAppStartMnemonic(isToggled, toggle);
      }

      // Toggling for non-mnemonic account does not support verification yet.
      setHasAuthenticatedForAppAccess(true);
      setIsAuthRequiredForAppAccess(isToggled);
      return true;
    },
    [
      isAuthRequiredForTx,
      activeAccountId,
      setHasAuthenticatedForAppAccess,
      setIsAuthRequiredForAppAccess,
      handleHighlightMinRequirementText,
      toggleAuthRequirementOnAppStartMnemonic,
    ],
  );

  const toggleAuthRequirementOnTxSigning = useCallback(
    function toggleAuthRequirementOnTxSigning(isToggled: boolean, toggle: () => void) {
      if (!isToggled && !isAuthRequiredForAppAccess) {
        handleHighlightMinRequirementText();
        return false;
      }

      if (!isToggled) {
        triggerAuth({
          accountId: activeAccountId,
          successCallback: () => {
            setIsAuthRequiredForTx(isToggled);
            toggle();
            return true;
          },
          cancelledCallback: () => {
            return false;
          },
          mnemonicAccessContext: MnemonicAccessContext.ToggleTxAuth,
        });
        return false;
      }

      setIsAuthRequiredForTx(isToggled);
      return true;
    },
    [
      isAuthRequiredForAppAccess,
      setIsAuthRequiredForTx,
      handleHighlightMinRequirementText,
      triggerAuth,
      activeAccountId,
    ],
  );

  const toggleAuthRequirementOnBiometricChange = useCallback(
    function toggleAuthRequirementOnBiometricChange(enabled: boolean, toggle: () => void) {
      triggerAuth({
        accountId: activeAccountId,
        successCallback: (mnemonicsHandle) => {
          const protectionType = enabled ? 'currentBiometrics' : 'anyBiometrics';
          if (isMnemonicResult(mnemonicsHandle)) {
            saveUnlockedMnemonicsUsingBiometrics({
              mnemonicsHandle,
              protection: protectionType,
              enforceShowBiometricsPrompt: false,
            })
              .then(() => {
                refreshAuthState();
                // if the save succeeded, flip the setting switch
                toggle();
                return true;
              })
              .catch((error) => {
                const err = coerceError(error, 'security');
                cbReportError({
                  error: err,
                  context: 'authentication-error',
                  severity: 'error',
                  isHandled: false,
                });
                // Don't refresh the auth state here
                return false;
              });
          }
        },
        mnemonicAccessContext: MnemonicAccessContext.ToggleBiometricProtection,
      });
      return false;
    },
    [activeAccountId, refreshAuthState, triggerAuth],
  );

  return (
    <SettingScreen screen="security" navBarTitle={formatMessage(messages.title)} scrollable>
      <Box spacingBottom={3}>
        {areAccountBackupRemindersEnabled && (
          <Section title={formatMessage(messages.backupSectionTitle)} showDivider>
            <WalletListBackup shouldTestForBackup />
          </Section>
        )}
        <Section title={formatMessage(messages.appLockTitle)} showDivider>
          <AppLockMethodCell />
        </Section>
        <Section title={formatMessage(messages.lockRequirementSectionTitle)} showDivider>
          <SwitchSettingCell
            title={formatMessage(messages.requireForAppAccessCellTitle)}
            isOn={isAuthRequiredForAppAccess}
            handleSwitch={toggleAuthRequirementOnAppStart}
            accessibilityLabel={formatMessage(messages.requireForAppAccessSwitchAccessibilityLabel)}
          />
          <SwitchSettingCell
            title={formatMessage(messages.requireForTxCellTitle)}
            isOn={isAuthRequiredForTx}
            handleSwitch={toggleAuthRequirementOnTxSigning}
            accessibilityLabel={formatMessage(messages.requireForTxSwitchAccessibilityLabel)}
          />
          <TextLegal
            color={highlightMinRequirementText ? 'negative' : 'foregroundMuted'}
            spacingHorizontal={3}
            spacingBottom={3}
          >
            {formatMessage(messages.appLockMinRequirementsDescription)}
          </TextLegal>
        </Section>
        {authState?.appLockType === 'biometrics' && (
          <Section title={formatMessage(messages.biometricsSecuritySectionTitle)}>
            <SwitchSettingCell
              title={formatMessage(messages.biometricChangeProtectionCellTitle)}
              isOn={authState?.biometricProtectionType === 'currentBiometrics'}
              handleSwitch={toggleAuthRequirementOnBiometricChange}
              accessibilityLabel={formatMessage(
                messages.biometricChangeProtectionSwitchAccessibilityLabel,
                {
                  biometry: formattedAvailableBiometrics,
                },
              )}
            />
            <TextLegal color="foregroundMuted" spacingHorizontal={3}>
              {formatMessage(messages.biometricProtectionExplanation, {
                biometry: formattedAvailableBiometrics,
              })}
            </TextLegal>
          </Section>
        )}
      </Box>
    </SettingScreen>
  );
});

