/**
 * HeaderDisplay
 *
 * This component handles the header displayName section, UI for whether or not
 * the displayName is editable and if the wallet group is hidden.
 */
const HeaderDisplay = memo(
  ({
    walletGroupDisplayName,
    navigateToEditNickname,
    isEditable,
    isHidden,
  }: {
    walletGroupDisplayName: string;
    navigateToEditNickname: () => void;
    isEditable: boolean;
    isHidden: boolean;
  }) => {
    const walletGroupDisplayNameNode = useMemo(() => {
      return (
        <TextTitle3 testID="wallet-name" color={isHidden ? `foregroundMuted` : `foreground`}>
          {walletGroupDisplayName}
        </TextTitle3>
      );
    }, [isHidden, walletGroupDisplayName]);

    if (isEditable) {
      return (
        <Pressable onPress={navigateToEditNickname} background="transparent">
          <HStack alignItems="center" gap={1}>
            <TextTitle3 testID="wallet-name" color={isHidden ? 'foregroundMuted' : 'foreground'}>
