            </TextTitle3>
            <Icon name="pencil" size="s" color="foreground" testID="wallet-name-edit" />
          </HStack>
        </Pressable>
      );
    }

    return (
      <HStack alignItems="center" gap={1}>
        {walletGroupDisplayNameNode}
      </HStack>
    );
  },
);

type ActiveWalletGroupProps = {
  walletGroup: WalletGroupToDisplay;
};

export const ActiveWalletGroup = memo(function ActiveWalletGroup({
  walletGroup,
}: ActiveWalletGroupProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const getWalletGroupDisplayName = useGetWalletGroupDisplayName();
  const hideProfileAssets = useIsFeatureEnabled('hide_profile_assets');

  const profileAddress = useProfileAddressForWalletGroupId(walletGroup.id);

  const primaryDomain = useAddressPrimaryDomain(profileAddress);
  const { profile } = useUserProfile(profileAddress);

  const isProfileEnabled = useIsProfileEnabled();
  const getShouldSuppressDIDFeature = useGetShouldSuppressDIDFeature();
  const hasActiveWalletGroup = !!walletGroup;
  const shouldSuppressDIDFeature = useMemo(
    () => hasActiveWalletGroup && getShouldSuppressDIDFeature({ walletGroup }),
    [hasActiveWalletGroup, getShouldSuppressDIDFeature, walletGroup],
  );

  const defaultSubdomainSuffix = 'cb.id';
  const [subdomainSuffix] = useSubdomainSuffixes();

  const isMiamiViceEnabled = useIsMiamiViceFeatureEnabled(
    'wallet_redesign_miami_vice_theme_colors',
  );

  const activeWalletGroupId = useActiveWalletGroupId();
  // flag from apps/rn/src/screens/ManageWallets/EditWallet.tsx
  // to control the visibility of "Claim a username"
  const canShowClaimSubdomain = useCanClaimSubdomainFromSettings(
    activeWalletGroupId,
    profileAddress,
    walletGroup,
  );

  const [startManageProfilePerfMark] = usePerfMark(
    PERF_MARKS.profile,
    PROFILE_MARKS.manage_profile_load,
    {
      logMetric: true,
    },
  );

  const hasDID = useMemo(
    () => isProfileEnabled && !!profile?.isSubdomain && !shouldSuppressDIDFeature,
    [isProfileEnabled, profile?.isSubdomain, shouldSuppressDIDFeature],
  );

  const isPaymentsModeEnabled = useIsPaymentsModeEnabled();

  // show the profile button when hasDID
  const isProfileButtonVisible = useMemo(
    () => !isPaymentsModeEnabled && (hasDID || canShowClaimSubdomain),
    [canShowClaimSubdomain, hasDID, isPaymentsModeEnabled],
  );

  const profileButtonText = useMemo(() => {
    const dIDTitle = isMiamiViceEnabled ? messages.editProfileTitle : messages.viewProfileTitle;
    return formatMessage(hasDID ? dIDTitle : messages.setUpProfileTitle);
  }, [formatMessage, hasDID, isMiamiViceEnabled]);

  const walletGroupDisplayName = useMemo(
    () => getWalletGroupDisplayName(walletGroup),
    [getWalletGroupDisplayName, walletGroup],
  );

  const navigateToEditNickname = useCallback(() => {
    navigate('EditNickname', { walletGroupId: walletGroup.id });
  }, [navigate, walletGroup.id]);

  const isOffchain = useMemo(() => {
    return primaryDomain?.endsWith(subdomainSuffix || defaultSubdomainSuffix);
  }, [primaryDomain, subdomainSuffix]);

  const handleProfileButtonClick = useCallback(() => {
    if (hasDID) {
      if (isMiamiViceEnabled) {
        logProfilePageButtonClick({ walletAddress: profileAddress }, 'edit_details');
        if (isOffchain) {
          return navigate('EditProfile', { address: profileAddress });
        }
        return navigate('BrowserTab', {
          deeplinkUrl: `https://app.ens.domains/name/${primaryDomain}/details`,
          activeTabId: undefined,
          action: 'browse',
        });
      }

      startManageProfilePerfMark();
      markJourney('navigate_to_profile_from_wallet_settings');
      logSettingWalletSubCategoryPressed({ context: 'view_profile' });
      return navigate(hideProfileAssets ? 'ManageProfile' : 'Profile', {
        address: profileAddress,
        domain: primaryDomain,
      });
    }

    if (canShowClaimSubdomain) {
      logSettingWalletSubCategoryPressed({ context: 'set_up_profile' });
      markJourney('navigate_to_subdomain_pick_username');
      return navigate('AuthenticatedClaimSubdomain', {
        screen: 'SubdomainSharedPickUsername',
        params: {
          launchedFrom: 'existing',
        },
      });
    }
  }, [
    hasDID,
    canShowClaimSubdomain,
    isMiamiViceEnabled,
    profileAddress,
    isOffchain,
    navigate,
    primaryDomain,
    startManageProfilePerfMark,
    hideProfileAssets,
  ]);

  const handleEditAvatar = useCallback(() => {
    navigate('CustomizeAvatarScreen', { walletGroup });
  }, [navigate, walletGroup]);

  return (
    <VStack>
      <HStack alignItems="center" gap={2} spacingBottom={isProfileButtonVisible ? 3 : 0}>
        {isMiamiViceEnabled ? (
          <PressableOpacity onPress={handleEditAvatar}>
            <WalletGroupAvatar
              walletGroup={walletGroup}
              size="xxl"
              testID="wallet-avatar-editable"
            />
            <Box
              position="absolute"
              height={24}
              width={24}
              right={-8}
              bottom={-1}
              borderRadius="roundedFull"
              bordered
              borderColor="primaryWash"
              background="primary"
              justifyContent="center"
              alignItems="center"
            >
              <Icon name="pencil" size="xs" color="primaryForeground" />
            </Box>
          </PressableOpacity>
        ) : (
          <WalletGroupAvatar walletGroup={walletGroup} size="xxl" testID="wallet-avatar" />
        )}
        <VStack gap={0.5}>
          <HStack alignItems="center" gap={1}>
            {walletGroup.isHidden && (
              <Icon
                testID="wallet-hidden-icon"
                name="visibleInactive"
                size="s"
                color="foregroundMuted"
              />
            )}
            <HeaderDisplay
              walletGroupDisplayName={walletGroupDisplayName}
              navigateToEditNickname={navigateToEditNickname}
              isHidden={walletGroup.isHidden}
              isEditable={!walletGroup.primaryDomainName}
            />
          </HStack>
          {walletGroup.isHidden && (
            <TextLegal testID="wallet-hidden-text">{formatMessage(messages.hiddenTag)}</TextLegal>
          )}
        </VStack>
      </HStack>
      {isProfileButtonVisible && (
        <Button
          variant="secondary"
          compact
          testID="profile-action-button"
          onPress={handleProfileButtonClick}
        >
          {profileButtonText}
        </Button>
      )}
    </VStack>
  );
});

