import { useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useToggler } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-mobile/buttons';

import { ScreenBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ScreenBoundary';
import { Screen } from ':rn/cds-wallet/components/layout/Screen';
import { NavBar } from ':rn/cds-wallet/components/NavBar/NavBar';
import { useNavHeaderScrolling } from ':rn/cds-wallet/components/NavBar/useNavHeaderScrolling';
import { QRCodeScannerModal } from ':rn/screens/Scan/QRCodeScannerModal';
import { QRCodeScannerResponse, QRCodeType } from ':rn/screens/Scan/types';
import { ConnectionsTabsContextProvider } from ':rn/screens/Settings/context/ConnectionsTabsContext';
import { useSaveSession } from ':rn/shared/walletlink/hooks/useSaveSession';

import { ConnectionNetworkSwitcherDialog } from './components/ConnectionNetworkSwitcherDialog';
import { ConnectionsTabs } from './components/ConnectionsTabs';
import { ConnectionNetworkSwitcherProvider } from './providers/ConnectionNetworkSwitcherProvider';

const messages = defineMessages({
  title: {
    defaultMessage: 'Connected dapps',
    description: 'Title describing the list of connected dapps',
  },
});

function Connections() {
  const { formatMessage } = useIntl();
  const [showQRCodeScanner, { toggleOn: openQRCodeScanner, toggleOff: closeQRCodeScanner }] =
    useToggler(false);
  const saveSession = useSaveSession();

  const { onScroll } = useNavHeaderScrolling();

  const handleOnScan = useCallback(
    function onScan(response: QRCodeScannerResponse) {
      closeQRCodeScanner();

      if (!response) return;

      switch (response.type) {
        case QRCodeType.WALLET_LINK:
          saveSession({
            id: response.data.sessionId,
            secret: response.data.secret,
            url: response.data.url,
            version: response.data.version,
            isParent: response.data.isParent,
            chainId: response.data.chainId ?? 1,
          });
          break;
        default:
          break;
      }
    },
    [closeQRCodeScanner, saveSession],
  );

  const QRButton = useCallback(
    () => <IconButton name="qrCode" onPress={openQRCodeScanner} transparent />,
    [openQRCodeScanner],
  );

  const navBar = useMemo(
    () => <NavBar title={formatMessage(messages.title)} left="back" right={QRButton} />,
    [formatMessage, QRButton],
  );

  return (
    <Screen navBar={navBar} onScroll={onScroll}>
      <ConnectionNetworkSwitcherProvider>
        <ConnectionsTabsContextProvider>
          <QRCodeScannerModal
            visible={showQRCodeScanner}
            onScan={handleOnScan}
            onClose={closeQRCodeScanner}
            connectToDapp
          />
          <ConnectionsTabs />
          <ConnectionNetworkSwitcherDialog />
        </ConnectionsTabsContextProvider>
      </ConnectionNetworkSwitcherProvider>
    </Screen>
  );
}

export function ConnectionsBoundary() {
  return (
    <ScreenBoundary>
      <Connections />
    </ScreenBoundary>
  );
}

export { ConnectionsBoundary as Connections };

