function isVersionNumberBigEnough(v1: string, v2: string) {
  const versionArr1 = v1.split('.');
  const versionArr2 = v2.split('.');
  for (let i = 0; i < versionArr1.length; i++) {
    if (versionArr1[i] !== versionArr2[i]) {
      return Number(versionArr1[i]) > Number(versionArr2[i]);
    }
  }
  return true;
}

export function WalletLinkConnectionListCell({
  session,
  onDelete,
  testID,
}: WalletLinkConnectionListCellProps) {
  const { formatMessage } = useIntl();
  const [isLoading, setIsLoading] = useState(false);
  const menuAnchorRef = useRef<View>(null);
  const menuRef = useRef<PopoverRef>(null);
  const { showNetworkSwitcher, selectSessionById } = useConnectionNetworkSwitcher();

  const onMenuPress = useCallback(() => {
    menuRef.current?.show({
      anchorRef: menuAnchorRef.current,
      stickToPosition: Position.BOTTOM_RIGHT,
      extraOffset: { left: -30, top: -20 },
    });
  }, []);

  const handlePopoverClose = useCallback((callback?: () => void) => {
    menuRef.current?.hide(callback);
  }, []);

  const handleSwitchNetwork = useCallback(() => {
    handlePopoverClose(() => {
      selectSessionById(session.id);
      showNetworkSwitcher();
    });
  }, [handlePopoverClose, selectSessionById, session.id, showNetworkSwitcher]);

  const handleDelete = useCallback(
    function handleDelete() {
      setIsLoading(true);
      onDelete(session);
      handlePopoverClose();
    },
    [onDelete, session, handlePopoverClose],
  );

  const dappOrigin = useMemo(() => {
    if (session.dappURL && !session.isParent) {
      return safeParseUrl(session.dappURL)?.host ?? session.dappURL;
    }
  }, [session.dappURL, session.isParent]);

  const walletlinkVersionCompatible = useMemo(
    () => isVersionNumberBigEnough(session.version ?? '0.0.0', '3.5.2'),
    [session.version],
  );

  if (session.isParent || !walletlinkVersionCompatible) {
    return (
      <ListCell
        title={session.dappName ?? formatMessage(messages.unlinkedDapp)}
        description={dappOrigin ? truncateMiddle(dappOrigin, 15, 15) : ''}
        testID={testID}
        media={
          <DappIcon
            dappIconUrl={session.dappImageURL}
            chainId={session.isParent ? undefined : session.chainId}
          />
        }
        action={
          <IconButton
            name="close"
            variant="secondary"
            transparent
            onPress={handleDelete}
            testID={`icon-delete-session-${session.id}`}
            loading={isLoading}
          />
        }
      />
    );
  }

  return (
    <Box ref={menuAnchorRef} collapsable={false} justifyContent="center" alignItems="center">
      <ListCell
        title={session.dappName ?? formatMessage(messages.unlinkedDapp)}
        description={dappOrigin ? truncateMiddle(dappOrigin, 15, 15) : ''}
        testID={testID}
        media={<DappIcon dappIconUrl={session.dappImageURL} chainId={session.chainId} />}
        action={
          <IconButton
            name="more"
            variant="secondary"
            transparent
            onPress={onMenuPress}
            loading={isLoading}
          />
        }
      />
      <PopoverMenu key="walletlink-connection-delete-session-menu" ref={menuRef}>
        <PopoverMenuItem
          disabled={!session.chainId}
          onPress={handleSwitchNetwork}
          minWidth="50%"
          customStyle={style}
        >
          {formatMessage(messages.switchNetwork)}
        </PopoverMenuItem>
        <PopoverMenuItem
          disabled={!session.chainId}
          onPress={handleDelete}
          minWidth="50%"
          customStyle={style}
          testID={`icon-delete-session-${session.id}`}
        >
          {formatMessage(messages.disconnect)}
        </PopoverMenuItem>
      </PopoverMenu>
    </Box>
  );
}

