const HideAssets = memo(function HideAssets() {
  const { formatMessage } = useIntl();
  const layout = useWindowDimensions();
  const { routes, tabs } = useLocalizedPortfolio(true);
  const params = useParams<SettingsRedesignParamList, 'HideAssets'>();
  const initialTabIndex = useMemo(() => {
    if (params.initialTab) {
      const index = routes.findIndex(({ key }) => params.initialTab === key);
      return Math.max(index, 0);
    }

    return 0;
  }, [params, routes]);
  const { index, setIndex } = useTabIndex(initialTabIndex);
  const { reset, getState, goBack } = useStackNavigation<SettingsRedesignParamList, 'HideAssets'>();
  const previousScreenName = useMemo(() => {
    return getPreviousScreenName(getState());
  }, [getState]);

  const handleBack = useCallback(() => {
    if (!previousScreenName) {
      reset({ index: 0, routes: [{ name: 'Settings' }] });
      return;
    }

    goBack();
  }, [previousScreenName, reset, goBack]);

  const active = useMemo(() => routes[index].key, [index, routes]);
  const initialLayout = useMemo(() => ({ width: layout.width }), [layout.width]);
  const navigationState = useMemo(() => ({ index, routes }), [index, routes]);

  const addCustomTokenButton = useCallback(() => <AddCustomTokenButton />, []);

  useAssetManagementScreenViewed();

  const navBar = useMemo<NavBarConfig>(
    () => ({
      title: formatMessage(messages.hideAssetsTitle),
      left: 'back',
      handleLeft: handleBack,
      right: addCustomTokenButton,
    }),
    [addCustomTokenButton, formatMessage, handleBack],
  );

  const handleTabChange = useCallback(
    function handleTabChange(tabId: string) {
      triggerTabChange({ nextStatus: tabId === AssetTabKey.WALLETS ? 'crypto' : 'nft' });
      setIndex(routes.findIndex(({ key }) => tabId === key));
    },
    [routes, setIndex],
  );

  const renderScene = SceneMap({
    [AssetTabKey.WALLETS]: useCallback(() => <SuspendedWalletList />, []),
    [AssetTabKey.COLLECTIONS]: useCallback(() => <SuspendedCollectibleSectionList />, []),
  });

  const renderTabBar = useCallback(() => {
    return (
      <Box spacingTop={2}>
        <TabNavigation
          spacingHorizontal={3}
          tabs={tabs}
          onChange={handleTabChange}
          value={active}
        />
      </Box>
    );
  }, [active, handleTabChange, tabs]);

  return (
    <Screen navBar={navBar}>
      <TabView
        navigationState={navigationState}
        renderScene={renderScene}
        onIndexChange={setIndex}
        renderTabBar={renderTabBar}
        initialLayout={initialLayout}
        sceneContainerStyle={sceneContainerStyle}
      />
    </Screen>
  );
});

