type UserWalletSettingsListProps = {
  wallets: Wallet[];
  lowBalanceWallets: Wallet[];
};

type PossibleCellType = 'wallet-setting' | 'low-balance' | 'spam-wallet-setting';

type WalletListCellType = {
  type: PossibleCellType;
  wallet: Wallet;
};

type UserWalletSettingsCellProps = {
  title?: string;
  action?: {
    label: string;
    onPress: () => void;
  };
  data: WalletListCellType[];
};

