};

export const UserWalletSettingsList = memo(function UserWalletSettingsList({
  wallets,
  lowBalanceWallets,
}: UserWalletSettingsListProps) {
  const { formatMessage } = useIntl();
  const listRef = useRef<SectionList<WalletListCellType, UserWalletSettingsCellProps> | null>(null);
  const [areLowBalanceWalletsHidden, setAreLowBalanceWalletsHidden] =
    useAreLowBalanceWalletsHidden();

  const userWalletSettings = useUserWalletSettings();
  const isCrossPlatformHiddenAssetsKilled = useIsCrossPlatformHiddenAssetsKilled();
  const shouldPushWalletToRegularSection = useIsRegularWalletSection();
  const shouldPushWalletToSpamSection = useIsSpamWalletSection();

  const { userWalletsInfo, spamWalletsInfo } = useMemo(() => {
    const walletSettingsFromUser: WalletListCellType[] = [];
    const spamWalletsSettings: WalletListCellType[] = [];

    wallets.forEach((wallet) => {
      const walletSettingId = generateUserWalletSettingId(wallet);
      const walletSetting = userWalletSettings[walletSettingId];

      if (
        shouldPushWalletToSpamSection({
          isCrossPlatformHiddenAssetsKilled,
          walletSetting,
          wallet,
        })
      ) {
        spamWalletsSettings.push({ type: 'spam-wallet-setting', wallet });
      }

      if (
        shouldPushWalletToRegularSection({
          isCrossPlatformHiddenAssetsKilled,
          walletSetting,
          wallet,
        })
      ) {
        walletSettingsFromUser.push({ type: 'wallet-setting', wallet });
      }
    });

    return { userWalletsInfo: walletSettingsFromUser, spamWalletsInfo: spamWalletsSettings };
  }, [
    isCrossPlatformHiddenAssetsKilled,
    shouldPushWalletToRegularSection,
    shouldPushWalletToSpamSection,
    userWalletSettings,
    wallets,
  ]);

  const toggleLowBalanceWalletsVisibility = useCallback(
    function toggleLowBalanceWalletsVisibility() {
      const isHiddenState = !areLowBalanceWalletsHidden;

      if (isHiddenState) {
        triggerLowBalanceWalletsHidden();
      } else {
        triggerLowBalanceWalletsUnhidden();
      }

      setAreLowBalanceWalletsHidden(isHiddenState);
    },
    [areLowBalanceWalletsHidden, setAreLowBalanceWalletsHidden],
  );

  const lowBalanceWalletsInfo = useMemo<WalletListCellType[]>(
    () => lowBalanceWallets.map((wallet) => ({ type: 'low-balance', wallet })),
    [lowBalanceWallets],
  );

  const userWalletsSection = useMemo<UserWalletSettingsCellProps>(
    () => ({
      data: userWalletsInfo,
    }),
    [userWalletsInfo],
  );

  const spamWalletsSection = useMemo<UserWalletSettingsCellProps>(
    () => ({
      title: formatMessage(messages.spamSectionTitle),
      data: spamWalletsInfo,
    }),
    [formatMessage, spamWalletsInfo],
  );

  const lowBalanceWalletsSection = useMemo<UserWalletSettingsCellProps>(
    () => ({
      title: formatMessage(messages.lowBalanceSectionTitle),
      action: {
        label: formatMessage(areLowBalanceWalletsHidden ? messages.showAll : messages.hideAll),
        onPress: toggleLowBalanceWalletsVisibility,
      },
      data: lowBalanceWalletsInfo,
    }),
    [
      formatMessage,
      areLowBalanceWalletsHidden,
      lowBalanceWalletsInfo,
      toggleLowBalanceWalletsVisibility,
    ],
  );

  const userWalletSettingsListData = useMemo(() => {
    return [userWalletsSection, spamWalletsSection, lowBalanceWalletsSection].filter(
      (section) => section.data.length > 0,
    );
  }, [userWalletsSection, spamWalletsSection, lowBalanceWalletsSection]);

  useEffect(
    function onDataLengthChange() {
      if (wallets.length) {
        listRef.current?.scrollToLocation({ sectionIndex: 0, itemIndex: 0, animated: false });
      }
    },
    [wallets.length],
  );

  const keyExtractor = useCallback(({ wallet }: WalletListCellType) => wallet.id, []);

  const renderItem = useCallback(
    ({ item }: SectionListRenderItemInfo<WalletListCellType, UserWalletSettingsCellProps>) =>
      item.type === 'wallet-setting' || item.type === 'spam-wallet-setting' ? (
        <UserWalletSettingsListCell wallet={item.wallet} />
      ) : (
        <LowBalanceWalletListCell wallet={item.wallet} />
      ),
    [],
  );

  const renderSectionHeader = useCallback(({ section: { title, action } }: SectionHeaderProps) => {
    return title ? (
      <HStack
        background="background"
        alignItems="center"
        justifyContent="space-between"
        spacingHorizontal={1}
        spacingEnd={3}
      >
        <TextCaption color="foregroundMuted" spacingVertical={1} spacingHorizontal={3}>
          {title}
        </TextCaption>
        {action && (
          <Pressable onPress={action.onPress} background="transparent">
            <TextLabel1 color="primary">{action.label}</TextLabel1>
          </Pressable>
        )}
      </HStack>
    ) : null;
  }, []);

  return (
    <SectionList
      ref={listRef}
      sections={userWalletSettingsListData}
      keyExtractor={keyExtractor}
      renderItem={renderItem}
      renderSectionHeader={renderSectionHeader}
      showsVerticalScrollIndicator={false}
    />
  );
});

