import { memo, useCallback, useMemo, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { SceneMap, TabView } from 'react-native-tab-view';
import { useIsNftPfpEnabled } from 'cb-wallet-data/stores/DecentralizedID/hooks/useIsNftPfpEnabled';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { VStack } from '@cbhq/cds-mobile/layout';
import { PortalProvider } from '@cbhq/cds-mobile/overlays/PortalProvider';
import { TabNavigation } from '@cbhq/cds-mobile/tabs/TabNavigation';

import { Modal } from ':rn/cds-wallet/components/Modal/Modal';
import { ProfilePictureModalHeader } from ':rn/screens/Settings/screens/ManageProfile/components/ProfilePictureModalHeader';
import { SelectNFT } from ':rn/screens/Settings/screens/ManageProfile/components/SelectNFT';
import { UploadImage } from ':rn/screens/Settings/screens/ManageProfile/components/UploadImage';

const messages = defineMessages({
  uploadImage: {
    defaultMessage: 'Upload image',
    description: 'Tab title for uploading a profile image',
  },
  selectNFT: {
    defaultMessage: 'Select NFT',
    description: 'Tab title for selecting a profile nft',
  },
});

enum Tab {
  UPLOAD_IMAGE = 'UPLOAD_IMAGE',
  SELECT_NFT = 'SELECT_NFT',
}

export type ProfilePictureModalProps = {
  address: string;
  onClose: () => void;
  visible: boolean;
};

export const ProfilePictureModal = memo(function ProfilePictureModal({
  address,
  onClose,
  visible,
}: ProfilePictureModalProps) {
  const { formatMessage } = useIntl();
  const [tabIndex, setTabIndex] = useState(0);
  const isNftPfpEnabled = useIsNftPfpEnabled();
  const tabs = useMemo(() => {
    const visibleTabs = [{ id: Tab.UPLOAD_IMAGE, label: formatMessage(messages.uploadImage) }];
    if (isNftPfpEnabled) {
      visibleTabs.push({ id: Tab.SELECT_NFT, label: formatMessage(messages.selectNFT) });
    }
    return visibleTabs;
  }, [formatMessage, isNftPfpEnabled]);

  const active = useMemo(() => tabs[tabIndex].id, [tabIndex, tabs]);

  const navigationState = useMemo(
    () => ({ index: tabIndex, routes: tabs.map(({ id, label }) => ({ key: id, title: label })) }),
    [tabIndex, tabs],
  );

  const handleTabChange = useCallback(
    (tabId: string) => {
      setTabIndex(tabs.findIndex(({ id }) => tabId === id));
    },
    [tabs],
  );

  const renderScene = SceneMap({
    [Tab.UPLOAD_IMAGE]: useCallback(() => <UploadImage address={address} />, [address]),
    [Tab.SELECT_NFT]: useCallback(() => <SelectNFT onClose={onClose} />, [onClose]),
  });

  const renderTabBar = useCallback(() => {
    return (
      <TabNavigation
        variant="primary"
        tabs={tabs}
        onChange={handleTabChange}
        value={active}
        testID="profile-picture-tab-nav"
        spacingHorizontal={3}
      />
    );
  }, [active, handleTabChange, tabs]);
  return (
    <PortalProvider>
      <Modal visible={visible} hideDividers onRequestClose={onClose} testID="profile-picture-modal">
        <VStack spacingTop={1} spacingHorizontal={1}>
          <IconButton onPress={onClose} name="close" transparent testID="close-modal" />
        </VStack>
        <VStack spacingHorizontal={3}>
          <ProfilePictureModalHeader />
        </VStack>
        <TabView
          navigationState={navigationState}
          renderScene={renderScene}
          onIndexChange={setTabIndex}
          renderTabBar={renderTabBar}
        />
      </Modal>
    </PortalProvider>
  );
});

import { memo, useCallback, useMemo } from 'react';
import { triggerThemeColorChange } from 'cb-wallet-analytics/settings';
import { useIsMiamiViceFeatureEnabled } from 'cb-wallet-data/hooks/useIsMiamiViceFeatureEnabled/useIsMiamiViceFeatureEnabled';
import {
  CombinedThemeColorPreference,
  miamiThemeColorConfigs,
  MiamiThemeColorPreference,
  themeColorConfigs,
  ThemeColorPreference,
} from 'cb-wallet-data/stores/ThemeColors/themeColorConfigs';
import { useSpectrum } from '@cbhq/cds-common';
import { useSpectrumConditional } from '@cbhq/cds-common/hooks/useSpectrumConditional';
import { paletteValueToRgbaString } from '@cbhq/cds-common/palette/paletteValueToRgbaString';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';

const OUTER_SELECTOR_SIZE = 40;
const INNER_SELECTOR_SIZE = 24;

function entries<T extends Record<keyof T, T[keyof T]>>(item: T) {
  return Object.entries(item) as [keyof T, T[keyof T]][];
}

export type ThemeColorSelectorProps = {
  preference: CombinedThemeColorPreference;
  walletGroupId: string;
  onSetPreference: (walletGroupId: string, preference: CombinedThemeColorPreference) => void;
};

export type ThemeColorSelectorItemProps = {
  name: CombinedThemeColorPreference;
  config:
    | (typeof themeColorConfigs)[ThemeColorPreference]
    | (typeof miamiThemeColorConfigs)[MiamiThemeColorPreference];
} & ThemeColorSelectorProps;

const ThemeColorSelectorItem = memo(function ThemeColorSelectorItem({
  preference,
  config,
  walletGroupId,
  name,
  onSetPreference,
}: ThemeColorSelectorItemProps) {
  const spectrum = useSpectrum();
  const active = preference === name;
  const outerBackgroundColor = useSpectrumConditional({
    light: active ? 'background' : 'transparent',
    dark: active ? 'secondary' : 'transparent',
  } as const);

  const handleOnPress = useCallback(
    function handleOnPress() {
      onSetPreference(walletGroupId, name);
      triggerThemeColorChange(preference, name);
    },
    [walletGroupId, name, onSetPreference, preference],
  );

  const preferenceBackground = useMemo(() => {
    // This is more performant than nesting ThemeProvider,
    // which generates deep merge of all parent ThemeProviders
    return paletteValueToRgbaString(config.primary, spectrum);
  }, [config.primary, spectrum]);

  return (
    <Pressable
      accessibilityLabel={`theme-color-preference-button-${name}`}
      background="secondary"
      borderRadius="roundedFull"
      feedback="normal"
      onPress={handleOnPress}
      testID={`theme-color-preference-button-${name}`}
      transparentWhileInactive
    >
      <Box
        alignItems="center"
        background={outerBackgroundColor}
        borderRadius="roundedFull"
        height={OUTER_SELECTOR_SIZE}
        justifyContent="center"
        width={OUTER_SELECTOR_SIZE}
      >
        <Box
          width={INNER_SELECTOR_SIZE}
          height={INNER_SELECTOR_SIZE}
          borderRadius="roundedFull"
          dangerouslySetBackground={preferenceBackground}
        />
      </Box>
    </Pressable>
  );
});

export const ThemeColorSelector = memo(function ColorSelectors({
  walletGroupId,
  preference,
  onSetPreference,
}: ThemeColorSelectorProps) {
  const isMiamiViceThemeEnabled = useIsMiamiViceFeatureEnabled(
    'wallet_redesign_miami_vice_theme_colors',
  );
  const themeConfig = isMiamiViceThemeEnabled ? miamiThemeColorConfigs : themeColorConfigs;
  return (
    <HStack
      spacing={1}
      gap={1}
      width="100%"
      alignItems="center"
      justifyContent="space-between"
      background="backgroundAlternate"
      borderRadius="roundedFull"
    >
      {entries(themeConfig).map(([name, config]) => {
        return (
          <ThemeColorSelectorItem
            walletGroupId={walletGroupId}
            key={name}
            preference={preference}
            config={config}
            name={name}
            onSetPreference={onSetPreference}
          />
        );
      })}
    </HStack>
  );
});

