import { useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { TransactionDetailRowItem } from 'cb-wallet-data/hooks/Swap/useTransactionDetailRowItems/useTransactionDetailRowItems';
import { Divider, HStack, VStack } from '@cbhq/cds-mobile/layout';
import { TextBody, TextLabel2, TextLegal } from '@cbhq/cds-mobile/typography';

import { Fallback } from ':rn/cds-wallet/components/Fallbacks/Fallback';
import { TooltipIcon } from ':rn/cds-wallet/components/icons/TootltipIcon';
import { RefreshCountdown } from ':rn/cds-wallet/components/TransactionDetails/RefreshCountdown';

const messages = defineMessages({
  networkFeeLabel: {
    defaultMessage: 'Network fee (est.)',
    description: 'Label for network fee row in tooltip',
  },
  extraFeeLabel: {
    defaultMessage: 'Account creation fee',
    description: 'Label for transaction detail row displaying the account creation fee',
  },
  gaslessSwitchDescription: {
    defaultMessage: 'Pay network fee in {currencyCode} No {gasToken} required.',
    description:
      'Description of gasless switch which users can opt-in to pay gas using source token instead of native gas token.',
  },
});

type NetworkFeeRowProps = Pick<
  TransactionDetailRowItem,
  | 'label'
  | 'detailText'
  | 'subDetailText'
  | 'tooltipText'
  | 'tooltipAccessibilityLabel'
  | 'testID'
  | 'keyLabel'
  | 'loadingLabelNode'
  | 'onClick'
  | 'isRowLoading'
  | 'isPageLoading'
  | 'lastUpdateTime'
  | 'tooltipObject'
  | 'testID'
  | 'gasPaymentMethodSelector'
>;

export function NetworkFeeRow({
  label,
  detailText,
  keyLabel,
  isRowLoading,
  isPageLoading,
  lastUpdateTime,
  tooltipObject,
  subDetailText,
  testID,
  loadingLabelNode,
  tooltipText,
  tooltipAccessibilityLabel,
  gasPaymentMethodSelector,
}: NetworkFeeRowProps) {
  const { formatMessage } = useIntl();

  const textDetail = useMemo(() => {
    return (
      <HStack alignItems="center" gap={1}>
        {isRowLoading ? (
          <Fallback width={40} height={25} testID={`${testID}-text-detail-loader`} />
        ) : (
          <TextBody testID={`${testID}-details`} align="end" color="foregroundMuted">
            {typeof detailText === 'string' ? detailText : detailText?.text}
          </TextBody>
        )}
      </HStack>
    );
  }, [detailText, isRowLoading, testID]);

  const tooltipContent = useMemo(() => {
    if (tooltipObject?.rowType === 'estimatedFees') {
      const { message, extraFee, networkFeeRange } = tooltipObject;
      return (
        <VStack>
          <TextLabel2>{message}</TextLabel2>
          <Divider color="lineHeavy" opacity={0.66} spacingVertical={1} />
          <VStack>
            {extraFee ? (
              <HStack justifyContent="space-between">
                <TextLabel2>{formatMessage(messages.extraFeeLabel)}</TextLabel2>
                <TextLabel2>{extraFee}</TextLabel2>
              </HStack>
            ) : null}
            <HStack justifyContent="space-between">
              <TextLabel2>{formatMessage(messages.networkFeeLabel)}</TextLabel2>
              <TextLabel2>{networkFeeRange}</TextLabel2>
            </HStack>
          </VStack>
        </VStack>
      );
    }
    if (tooltipObject?.message) {
      return <TextLegal>{tooltipObject?.message}</TextLegal>;
    }
  }, [formatMessage, tooltipObject]);

  const subDetail = useMemo(() => {
    if (gasPaymentMethodSelector) {
      return gasPaymentMethodSelector;
    }

    if (subDetailText) {
      return (
        <TextLegal testID={`${testID}-details`} align="end" color="foregroundMuted">
          {subDetailText}
        </TextLegal>
      );
    }
  }, [gasPaymentMethodSelector, subDetailText, testID]);

  return (
    <VStack key={keyLabel || label} spacingVertical={1} position="relative" width="100%">
      <HStack justifyContent="space-between" alignItems="center">
        <HStack justifyContent="flex-start" alignItems="center">
          {loadingLabelNode ? (
            <Fallback width={125} height={25} testID={`${testID}-label-loader`} />
          ) : (
            <TextBody testID={testID}>{label}</TextBody>
          )}
          {tooltipText ? (
            <TooltipIcon
              description={tooltipText}
              title={label}
              iconName="info"
              testID={`${testID}-tooltip-icon`}
              accessibilityLabel={tooltipAccessibilityLabel}
            />
          ) : null}
          {tooltipContent ? (
            <TooltipIcon
              content={tooltipContent}
              iconName="info"
              testID={`${testID}-tooltip-icon`}
            />
          ) : null}
        </HStack>
        <HStack justifyContent="flex-end" alignItems="center">
          {textDetail}
        </HStack>
      </HStack>
      <HStack justifyContent="space-between" alignItems="flex-end">
        <HStack justifyContent="flex-start" alignItems="baseline">
          <RefreshCountdown
            lastUpdateTime={lastUpdateTime}
            isPageLoading={Boolean(isPageLoading)}
          />
        </HStack>
        <HStack justifyContent="flex-end" alignItems="center">
          {subDetail}
        </HStack>
      </HStack>
    </VStack>
  );
}

import { useMemo } from 'react';
import { useIsAdjustableSlippageEligible } from 'cb-wallet-data/hooks/Slippage/useIsAdjustableSlippageEligible';
import { TransactionDetailRowItem } from 'cb-wallet-data/hooks/Swap/useTransactionDetailRowItems/useTransactionDetailRowItems';
