import { HStack, VStack } from '@cbhq/cds-mobile/layout';
import { PressableOpacity } from '@cbhq/cds-mobile/system';
import { TextBody } from '@cbhq/cds-mobile/typography';

import { Fallback } from ':rn/cds-wallet/components/Fallbacks/Fallback';
import { TooltipIcon } from ':rn/cds-wallet/components/icons/TootltipIcon';

type SlippageRowProps = Pick<
  TransactionDetailRowItem,
  | 'label'
  | 'detailText'
  | 'tooltipText'
  | 'tooltipAccessibilityLabel'
  | 'testID'
  | 'keyLabel'
  | 'loadingLabelNode'
  | 'onClick'
  | 'isRowLoading'
>;

export function SlippageRow({
  label,
  detailText,
  tooltipText,
  tooltipAccessibilityLabel,
  testID,
  keyLabel,
  loadingLabelNode,
  isRowLoading,
  onClick,
}: SlippageRowProps) {
  const isAdjustableSlippageEnabled = useIsAdjustableSlippageEligible();

  const textDetail = useMemo(() => {
    return (
      <HStack alignItems="center" gap={1}>
        {isRowLoading ? (
          <Fallback width={40} height={25} testID={`${testID}-text-detail-loader`} />
        ) : (
          <TextBody testID={`${testID}-details`} align="end" color="foregroundMuted">
            {typeof detailText === 'string' ? detailText : detailText?.text}
          </TextBody>
        )}
        {isAdjustableSlippageEnabled ? <Icon name="gear" size="s" color="foreground" /> : null}
      </HStack>
    );
  }, [isRowLoading, testID, detailText, isAdjustableSlippageEnabled]);

  const content = useMemo(() => {
    return isAdjustableSlippageEnabled ? (
      <PressableOpacity accessibilityLabel="AdjustSlippageToleranceButtonLabel" onPress={onClick}>
        {textDetail}
      </PressableOpacity>
    ) : (
      textDetail
    );
  }, [isAdjustableSlippageEnabled, onClick, textDetail]);

  if (!detailText) return null;

  return (
    <VStack key={keyLabel || label} spacingVertical={1} position="relative" width="100%">
      <HStack justifyContent="space-between" alignItems="center">
        <HStack justifyContent="flex-start" alignItems="center">
          {loadingLabelNode ? (
            <Fallback width={125} height={25} testID={`${testID}-label-loader`} />
          ) : (
            <TextBody testID={testID}>{label}</TextBody>
          )}
          <TooltipIcon
            description={tooltipText}
            title={label}
            iconName="info"
            accessibilityLabel={tooltipAccessibilityLabel}
          />
        </HStack>
        <HStack justifyContent="flex-end" alignItems="center">
          {content}
        </HStack>
      </HStack>
    </VStack>
  );
}

