const messages = defineMessages({
  title: {
    defaultMessage: 'Slippage tolerance',
    description: 'Title for slippage tolerance screen',
  },
  titleTooltipMessage: {
    defaultMessage: `Your swap will execute within the maximum amount of slippage you define for this swap. For example, 1% slippage means you're  willing to accept up to 1% less due to market conditions.`,
    description: 'Tooltip message describing how slippage works for swap',
