const defaultSlippageOptions = ['1', '2', '3'];

type AdjustableSlippageFormType = {
  slippage: string;
};

export const initialValues: AdjustableSlippageFormType = {
  slippage: '',
};

export function AdjustableSlippage() {
  const { formatMessage } = useIntl();
  const { goBack } = useStackNavigation();
  const { cryptoAmount, sourceWallet, targetAsset, mode, updateSwapInfoValue } =
    useContext(SwapContext);

  const swapSlippageValidationSchema = createValidationSchema(
    formatMessage(messages.slippageRegexMatch),
  );

  useOnMount(() => {
    logAdjustableSlippageViewed();
  });

  const validationSchema = useMemo(
    () => yupResolver(swapSlippageValidationSchema),
    [swapSlippageValidationSchema],
  );

  const methods = useForm<AdjustableSlippageFormType>({
    mode: 'onChange',
    reValidateMode: 'onChange',
    defaultValues: initialValues,
    resolver: validationSchema,
  });

  const {
    formState: { isValid, isDirty, isSubmitting },
    getValues,
  } = methods;

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: 'back',
      handleLeft: goBack,
    }),
    [goBack],
  );

  const sourceSwapAsset = useSwapAsset({
    contractAddress: sourceWallet?.contractAddress,
    chainId: sourceWallet?.network.asChain()?.chainId.toString(),
  });

  const { generateTransactions, isGenerateTransactionsLoading } = useSwapGenerateTransactions({
    cryptoAmount,
    sourceSwapAsset,
    targetSwapAsset: targetAsset,
    mode,
    handleSuccess: goBack,
    handleOnError: goBack,
  });

  const handleSlippageClick = useCallback(
    (slippageValue: string) => async () => {
      logAdjustableSlippageSaveClicked();

      const newSlippage = parseInt(slippageValue) * 10;
      const newSlippageValue = newSlippage.toString();

      updateSwapInfoValue({
        slippage: newSlippageValue,
      });

      generateTransactions({ isReloadCall: false, overrideSlippage: newSlippageValue });
    },
    [generateTransactions, updateSwapInfoValue],
  );

  const slippageOptions = useMemo(() => {
    return defaultSlippageOptions.map((slippageValue) => {
      return (
        <Button
          key={`slippage-${slippageValue}-option`}
          variant="secondary"
          onPress={handleSlippageClick(slippageValue)}
        >
          {slippageValue}%
        </Button>
      );
    });
  }, [handleSlippageClick]);

  const handleSubmit = useCallback(
    async function handleSubmit() {
      logAdjustableSlippageSaveClicked();

      try {
        const { slippage: slippageFormValue } = getValues();
        const newSlippage = parseFloat(slippageFormValue) * 10;
        const newSlippageValue = newSlippage.toFixed(0).toString();
        updateSwapInfoValue({
          slippage: newSlippageValue,
        });

        generateTransactions({ isReloadCall: false, overrideSlippage: newSlippageValue });
      } catch (err) {
        const error = coerceError(err, 'adjustable slippage');
        cbReportError({
          error,
          metadata: { method: 'AdjustableSlippage.handleSubmit' },
          context: 'swap_adjustable_slippage',
          severity: 'error',
          isHandled: false,
        });
        logAdjustableSlippageSaveError(err as Error);
      }
    },
    [generateTransactions, getValues, updateSwapInfoValue],
  );

  const isButtonLoading = useMemo(
    () => isSubmitting || isGenerateTransactionsLoading,
    [isGenerateTransactionsLoading, isSubmitting],
  );

  const isButtonDisabled = useMemo(
    () => !isValid || !isDirty || isButtonLoading,
    [isDirty, isValid, isButtonLoading],
  );

  return (
    <Screen full navBar={navBar}>
      <VStack spacingHorizontal={2} flexShrink={1} height="100%">
        <CDSInputKeyboardAwareScrollView testID="adjustable-slippage-scroll-view">
          <VStack>
            <HStack alignItems="center" gap={1}>
              <TextTitle3>{formatMessage(messages.title)}</TextTitle3>
              <TooltipIcon
                description={formatMessage(messages.titleTooltipMessage)}
                title={formatMessage(messages.title)}
                iconName="info"
                accessibilityLabel={formatMessage(messages.tooltipAccessibilityLabel)}
              />
            </HStack>
            <TextBody color="foregroundMuted" spacingTop={1} spacingBottom={3}>
              {formatMessage(messages.description)}
            </TextBody>
            <ButtonGroup testID="slippage-percentage-options" accessibilityLabel="Group" block>
              {slippageOptions}
            </ButtonGroup>
            <VStack justifyContent="center" alignItems="center" spacingVertical={3}>
              <TextBody color="foregroundMuted">{formatMessage(messages.dividerText)}</TextBody>
            </VStack>
          </VStack>
          <FormProvider {...methods}>
            <ControlledTextInput
              autoCapitalize="none"
              autoComplete="off"
              autoCorrect={false}
              testID="custom-slippage-input"
              label={formatMessage(messages.customAmountTitle)}
              name="slippage"
              suffix="%"
              helperText={formatMessage(messages.customAmountHelperText)}
            />
          </FormProvider>
        </CDSInputKeyboardAwareScrollView>
        <VStack>
          <Button
            testID="custom-slippage-save-btn"
            onPress={methods.handleSubmit(handleSubmit)}
            disabled={isButtonDisabled}
            loading={isButtonLoading}
            variant="primary"
          >
            {formatMessage(messages.primaryCTAButton)}
          </Button>
        </VStack>
      </VStack>
    </Screen>
  );
}

function createValidationSchema(validationMessage: string) {
  return object({
    slippage: string().test({
      name: 'slippage-valid-number',
      message: validationMessage,
      test: (value) => isValidSlippage(value),
    }),
  });
}

