function SwapDepositGasContent() {
  const { formatMessage } = useIntl();
  const { cryptoAmount, depositAmount, sourceWallet } = useContext(SwapContext);
  const { navigate } = useStackNavigation();

  const currencyFormatter = useCurrencyFormatter();
  const { isConnected } = useIsConnectedToCoinbase();
  const launchBuyFlow = useLaunchBuyFlow();
  const onrampEligibility = useOnrampEligibility();

  const chainDetails = useSwapAnalyticsDetails();
  useDepositGasStepViewed({ chainDetails });

  const { network } = useSwapFormNetworkChain();

  const { sourceSwapAsset, targetSwapAsset } = useSwapCurrencySelectorAssets();

  const { generateTransactions, isGenerateTransactionsLoading } = useSwapGenerateTransactions({
    cryptoAmount,
    sourceSwapAsset,
    targetSwapAsset,
  });

  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useGetFeeWallet(activeWalletGroupId, network);
  const isBNB = network.asChain()?.chainId === EVMChain.BSC;

  const refreshNetworkFeeCallback = useCallback(async () => {
    // if wallet has zero balance we don't have enough info
    // to generate transaction
    if (feeWallet?.balance !== undefined && feeWallet.balance > 0n) {
      await generateTransactions();
    }
  }, [generateTransactions, feeWallet]);

  useIntervalForPromises(refreshNetworkFeeCallback, { interval: 30000 });

  // if a user needs $13 more of ETH, we want to pre-fill the CB pay form with $25
  // if a user needs $42 more of ETH, we want to pre-fill with $50
  // (the next multiple of 25).
  const nextMultipleOf25 = useMemo(() => {
    if (!feeWallet?.currencyCode || !depositAmount) return 0;
    const decimalAmount = currencyFormatter.fiatValue(
      feeWallet?.currencyCode,
      feeWallet?.decimals,
      depositAmount,
      feeWallet?.contractAddress,
      feeWallet?.network,
      feeWallet?.blockchain,
    );
    const numberAmount = decimalAmount?.toNumber();
    if (!numberAmount) return 0;
    return numberAmount + ((25 - (numberAmount % 25)) % 25);
  }, [currencyFormatter, feeWallet, depositAmount]);

  const handleConnectCoinbaseClick = useCallback(
    function handleConnectCoinbaseClick() {
      logDepositGasStepCBPayButtonClicked({
        chainDetails,
        source: Source.MOBILE,
      });

      launchBuyFlow({
        wallet: feeWallet,
        presetFiatAmount: nextMultipleOf25,
      });
    },
    [chainDetails, feeWallet, launchBuyFlow, nextMultipleOf25],
  );

  const handleOtherClick = useCallback(
    function handleOtherClick() {
      logDepositGasStepTransferButtonClicked({
        chainDetails,
        source: Source.MOBILE,
      });
      navigate('Receive', {
        screen: 'ReceiveWalletAddressScreen',
        params: { walletId: feeWallet?.id ?? sourceWallet?.swapId },
      });
    },
    [chainDetails, feeWallet?.id, navigate, sourceWallet],
  );

  const depositAmountMessage = useMemo(() => {
    if (depositAmount) {
      const formattedCryptoAmountNeeded =
        feeWallet?.balance !== undefined && feeWallet?.currencyCode
          ? currencyFormatter.formatToCrypto({
              currencyCode: feeWallet.currencyCode,
              decimals: feeWallet.decimals,
              value: depositAmount,
              network: feeWallet.network,
              blockchain: feeWallet.blockchain,
            })
          : '';

      const formattedFiatAmountNeeded =
        feeWallet?.balance !== undefined && feeWallet?.currencyCode
          ? currencyFormatter.formatToFiat(
              feeWallet.currencyCode,
              feeWallet.decimals,
              depositAmount,
              false,
              feeWallet.contractAddress,
              feeWallet.network,
              feeWallet.blockchain,
              true,
              true, // format $0 balance
            )
          : '';

      return formatMessage(messages.notEnoughBalanceSubtitle, {
        cryptoAmountNeeded: formattedCryptoAmountNeeded,
        fiatAmountNeeded: formattedFiatAmountNeeded,
      });
    }

    if (feeWallet?.currencyCode.code && feeWallet?.displayName) {
      return formatMessage(messages.zeroBalanceSubtitle, {
        cryptoSymbol: feeWallet?.currencyCode.code,
        networkName: feeWallet?.network.asChain()?.displayName,
      });
    }
    return '';
  }, [depositAmount, feeWallet, currencyFormatter, formatMessage]);

  const cbPayButtonText = useMemo(() => {
    if (onrampEligibility?.isSupported) return formatMessage(messages.fundButtonCta);

    if (isConnected) {
      return formatMessage(messages.buttonCtaConnected, {
        cryptoSymbol: feeWallet?.currencyCode.code,
      });
    }
    return formatMessage(messages.buttonCta);
  }, [feeWallet?.currencyCode.code, formatMessage, isConnected, onrampEligibility?.isSupported]);

  return (
    <VStack flexGrow={1} justifyContent="space-between" spacingHorizontal={2}>
      <VStack alignItems="center" width="100%" spacingHorizontal={2}>
        <HStack alignItems="center" justifyContent="center" spacingTop={10} spacingBottom={2}>
          <MiamiIllustrationWrapper illustration="BorrowWalletMiami">
            <SpotRectangle name="borrowWallet" />
          </MiamiIllustrationWrapper>
        </HStack>
        <TextTitle3 spacingBottom={1} align="center">
          {formatMessage(messages.title, {
            cryptoSymbol: feeWallet?.currencyCode.code,
          })}
        </TextTitle3>

        <TextBody
          color="foregroundMuted"
          align="center"
          testID="deposit-gas-message"
          spacingBottom={2}
        >
          {depositAmountMessage}
        </TextBody>
      </VStack>
      <VStack alignItems="center" width="100%" spacingBottom={2}>
        <ButtonGroup
          accessibilityLabel={formatMessage(messages.accessibilityLabel)}
          direction="vertical"
        >
          {isBNB ? null : (
            <Button
              onPress={handleConnectCoinbaseClick}
              loading={isGenerateTransactionsLoading}
              testID="deposit-gas-cbpay-button"
            >
              {cbPayButtonText}
            </Button>
          )}
          <Button onPress={handleOtherClick} variant="secondary">
            {formatMessage(messages.otherButton)}
          </Button>
        </ButtonGroup>
        <TextLegal color="foregroundMuted" align="center" spacingTop={2}>
          {formatMessage(messages.finePrint, {
            userAgreement: (
              <Link variant="legal" color="primary" to={LINK_USER_AGREEMENT}>
                {formatMessage(messages.userAgreement)}
              </Link>
            ),
            privacyPolicy: (
              <Link variant="legal" color="primary" to={LINK_LEGAL_PRIVACY}>
                {formatMessage(messages.privacyPolicy)}
              </Link>
            ),
          })}
        </TextLegal>
      </VStack>
    </VStack>
  );
}

