type HRTxnDetailButtonsProps = {
  transaction: Transaction;
  transactionType: TransactionType;
  blockExplorerUrl: string | undefined;
  blockExplorerTitle: string;
  setIsSpeedUp: (arg: boolean) => void;
  showActionsTray: () => void;
};

export type TxnActionButtonProps = {
  icon: UiIconName;
  isButtonDisabled?: boolean;
  label: string;
  onPress: () => void;
};

function TxnActionButton({ icon, isButtonDisabled, label, onPress }: TxnActionButtonProps) {
  return (
    <VStack alignItems="center" gap={1} flexBasis={1} flexGrow={1}>
      <IconButton
        disabled={isButtonDisabled}
        variant="secondary"
        name={icon}
        onPress={onPress}
        testID={`${icon}-tx-action-button`}
      />
      <TextLabel2 color="foreground" align="center">
        {label}
      </TextLabel2>
    </VStack>
  );
}

export function HRTxnDetailButtons({
  transaction,
  transactionType,
  blockExplorerUrl,
  blockExplorerTitle,
  setIsSpeedUp,
  showActionsTray,
}: HRTxnDetailButtonsProps) {
  const { navigate, push } = useStackNavigation();
  const { launchSwapFlow, isSwapEnabled } = useLaunchSwapFlow();
  const { launchBridgeFlow, isBridgeEnabled } = useLaunchBridgeFlow();
  const { launchStakeFlow, isStakeEnabled } = useLaunchStakeFlow();
  const activeWalletGroupId = useActiveWalletGroupId();
  const walletById = useWalletById(activeWalletGroupId, transaction.walletId);
  const isBBML2App2AppEnabled = useIsBBML2AppToAppEnabled();
  const oAuthSDK = useOAuthSDK();
  const { launchIAB } = useAuthorizedIAB();
  const { copyToClipboard } = useClipboard();

  const { activeWalletGroupTronAddress } = useActiveWalletGroupTronAddress(activeWalletGroupId);

  const isNFT = transaction.isNFTTransaction();
  const isNFTMint = transactionType === 'MINT';
  const isNFTReceive = transactionType === 'RECEIVE' && isNFT;
  const isNFTPurchase = transactionType === 'SWAP' && isNFT && transaction.toTokenId;

  const openWebBrowser = useOpenWebBrowser();

  const { primaryActionButton, secondaryActionButton } = useDisplayTransactionDetails(transaction);

  const openUrl = useCallback(() => {
    if (blockExplorerUrl) {
      logBlockExplorerClicked(transaction.blockchain.rawValue, transaction.network.rawValue);
      openWebBrowser(blockExplorerUrl);
    }
  }, [
    blockExplorerUrl,
    openWebBrowser,
    transaction.blockchain.rawValue,
    transaction.network.rawValue,
  ]);

  const handleOpenCoinbase = useCallback(async () => {
    const isCoinbaseInstalled = isBBML2App2AppEnabled
      ? await oAuthSDK.isAppToAppAvailable()
      : false;

    if (isCoinbaseInstalled) {
      Linking.openURL(LINK_COINBASE_ASSETS);
      return;
    }

    if (await oAuthSDK.isAuthenticated()) {
      // This launches a authenticated in-app browser using WSST Token. This requires user to be already connected.
      launchIAB({
        context: 'cashout_transaction_details_from_wallet',
        url: `${LINK_COINBASE_ASSETS}`,
      });
    } else {
      // We will not hit this case with Cash out because we don't expect the
      // user get here without connecting to Coinbase
      openWebBrowser(LINK_COINBASE_ASSETS);
    }
  }, [isBBML2App2AppEnabled, launchIAB, oAuthSDK, openWebBrowser]);

  // If we return "undefined" here, it means that the "Copy Address" button will be hidden because we don't
  // have a valid "copy address" handler for the given transaction.
  //
  // With that, the "Copy Address" button will be rendered only if it's a TRON receive transaction and we
  // have a valid tron address to be copied
  const handleNetworkCopyAddress = useMemo(() => {
    if (transaction.isTronReceiveTx && activeWalletGroupTronAddress) {
      return function handleTronCopyAddress() {
        copyToClipboard(activeWalletGroupTronAddress);
      };
    }

    return undefined;
  }, [activeWalletGroupTronAddress, copyToClipboard, transaction.isTronReceiveTx]);

  const handleCancelPressed = useCallback(
    function handleCancelPressed() {
      logCancelClicked();
      setIsSpeedUp(false);
      showActionsTray();
    },
    [setIsSpeedUp, showActionsTray],
  );

  const handleSpeedUpPressed = useCallback(
    function handleSpeedUpPressed() {
      logSpeedUpClicked();
      setIsSpeedUp(true);
      showActionsTray();
    },
    [setIsSpeedUp, showActionsTray],
  );

  const handleSendAgain = useCallback(() => {
    logSendAgainClicked(transaction.walletId);
    navigate('Send', {
      screen: 'SendInput',
      params: { walletId: transaction.walletId, entryPoint: 'transactionDetail' },
    });
  }, [navigate, transaction.walletId]);

  const handleSwapAgain = useCallback(() => {
    logSwapAgainClicked({
      sourceSwapId: walletById?.swapId,
      chainId: transaction.network.asChain()?.chainId,
      contractAddress: transaction.toContractAddress,
    });
    launchSwapFlow({
      sourceWalletSwapId: walletById?.swapId,
      chainId: transaction.network.asChain()?.chainId,
      contractAddress: transaction.toContractAddress,
    });
  }, [launchSwapFlow, transaction.network, transaction.toContractAddress, walletById?.swapId]);

  const handleBridgeAgain = useCallback(() => {
    logBridgeAgainClicked({
      fromChainId: transaction.network.asChain()?.chainId,
      targetChainId: transaction.toNetwork?.asChain()?.chainId,
    });
    launchBridgeFlow({
      sourceChainId: transaction.network.asChain()?.chainId.toString(),
      targetChainId: transaction.toNetwork?.asChain()?.chainId.toString(),
    });
  }, [launchBridgeFlow, transaction.network, transaction.toNetwork]);

  const handleStakeAgain = useCallback(() => {
    logStakeAgainClicked(transaction.currencyCode.code ?? ETHEREUM_SYMBOL);
    launchStakeFlow({ currencyCode: transaction.currencyCode.code ?? ETHEREUM_SYMBOL });
  }, [launchStakeFlow, transaction.currencyCode.code]);

  const handleNavigateToAsset = useNavigateToAsset({ transaction });

  const handleNavigateToNft = useCallback(
    function handleNavigateToNft() {
      const nftContractAddress = isNFTPurchase
        ? transaction.toContractAddress
        : transaction.contractAddress;
      const nftTokenId =
        isNFTMint || isNFTPurchase || isNFTReceive
          ? transaction.toTokenId
          : transaction.fromTokenId;
      logViewNFTClicked({
        contractAddress: nftContractAddress,
        tokenId: nftTokenId,
        chainId: transaction.network.asChain()?.chainId,
      });
      push('CollectibleDetailCommerce', {
        contractAddress: nftContractAddress,
        tokenId: nftTokenId,
        chainId: transaction.network.asChain()?.chainId,
        tokenCount: '1',
      });
    },
    [
      isNFTMint,
      isNFTPurchase,
      isNFTReceive,
      push,
      transaction.contractAddress,
      transaction.fromTokenId,
      transaction.network,
      transaction.toContractAddress,
      transaction.toTokenId,
    ],
  );

  const getActionButton = useCallback(
    function getActionButton(actionButton: ActionButtonToDisplay | undefined) {
      const actionHandlers = {
        speedUp: handleSpeedUpPressed,
        cancel: handleCancelPressed,
        sendAgain: handleSendAgain,
        swapAgain: handleSwapAgain,
        stakeAgain: handleStakeAgain,
        bridgeAgain: isBridgeEnabled ? handleBridgeAgain : undefined,
        goToAssetDetail: handleNavigateToAsset,
        goToNFTDetail: handleNavigateToNft,
        openCoinbase: handleOpenCoinbase,
        copyAddress: handleNetworkCopyAddress,
      };

      if (!actionButton) return undefined;

      const handler = actionHandlers[actionButton.action];
      if (!handler) return undefined;

      return (
        <TxnActionButton
          isButtonDisabled={
            (actionButton.action === 'stakeAgain' && !isStakeEnabled) ||
            (actionButton.action === 'swapAgain' && !isSwapEnabled)
          }
          icon={actionButton.icon}
          label={actionButton.label}
          onPress={handler}
        />
      );
    },
    [
      handleBridgeAgain,
      handleCancelPressed,
      handleNavigateToAsset,
      handleNavigateToNft,
      handleNetworkCopyAddress,
      handleOpenCoinbase,
      handleSendAgain,
      handleSpeedUpPressed,
      handleStakeAgain,
      handleSwapAgain,
      isBridgeEnabled,
      isStakeEnabled,
      isSwapEnabled,
    ],
  );

  const primaryButton = useMemo(() => {
    return getActionButton(primaryActionButton);
  }, [primaryActionButton, getActionButton]);

  const secondaryButton = useMemo(() => {
    return getActionButton(secondaryActionButton);
  }, [secondaryActionButton, getActionButton]);

  if (!primaryButton && !secondaryActionButton) {
    return (
      <>
        {blockExplorerUrl && blockExplorerTitle && (
          <Button
            testID="explorer-large-button"
            variant="secondary"
            onPress={openUrl}
            spacingHorizontal={3}
            spacingBottom={3}
          >
            {blockExplorerTitle}
          </Button>
        )}
      </>
    );
  }

  return (
    <HStack
      justifyContent="space-around"
      alignContent="center"
      spacingBottom={3}
      spacingHorizontal={6}
      gap={3}
      testID="tx-detail-buttons"
    >
      {primaryButton}
      {secondaryButton}
      {blockExplorerUrl && blockExplorerTitle && (
        <TxnActionButton icon="externalLink" label={blockExplorerTitle} onPress={openUrl} />
      )}
    </HStack>
  );
}

import { useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { TouchableWithoutFeedback } from 'react-native-gesture-handler';
import { STAKE_TRANSACTION_TYPES } from 'cb-wallet-data/stores/Transactions/constants';
import { Card } from '@cbhq/cds-mobile/cards/Card';
import { ListCell } from '@cbhq/cds-mobile/cells/ListCell';
import { Icon } from '@cbhq/cds-mobile/icons';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { TextBody, TextHeadline, TextLabel2 } from '@cbhq/cds-mobile/typography';

import { spacingHorizontal } from ':rn/cds-wallet/components/cells/constants';

type HRTxnDetailCardProps = {
  transactionType: string;
  transactionState: string;
  topIcon: React.ReactElement;
  topDescription: string;
  topDetail: string | undefined;
  topSubdetail: string | undefined;
  bottomIcon: React.ReactElement;
  bottomDescription: string | undefined;
  bottomDetail: string | undefined;
  bottomSubdetail: string | undefined;
  handleToAddressPress?: (() => void) | undefined;
  handleFromAddressPress?: (() => void) | undefined;
};

const messages = defineMessages({
  fromTitle: {
    defaultMessage: 'From',
    description: 'Cell title for senders field',
  },
  toTitle: {
    defaultMessage: 'To',
    description: 'Cell title for recipients field',
  },
  swap: {
    defaultMessage: 'Swap',
    description: 'Cell title for a swap transaction',
  },
  bridge: {
    defaultMessage: 'Bridge',
    description: 'Cell title for a bridge transaction',
  },
  stake: {
    defaultMessage: 'Stake',
    description: 'Cell title for a stake transaction',
  },
  unstake: {
    defaultMessage: 'Unstake',
    description: 'Cell title for an unstake transaction',
  },
  mint: {
    defaultMessage: 'Mint',
    description: 'Cell title for a mint transaction',
  },
  smartContract: {
    defaultMessage: 'Smart contract',
    description: 'Cell title for a smart contract transaction',
  },
});

export function HRTxnDetailCard({
  transactionState,
  transactionType,
  topIcon,
  topDescription,
  topDetail,
  topSubdetail,
  bottomIcon,
  bottomDescription,
  bottomDetail,
  bottomSubdetail,
  handleToAddressPress,
  handleFromAddressPress,
}: HRTxnDetailCardProps) {
  const { formatMessage } = useIntl();

  const titleTop = useMemo(() => {
    switch (transactionType) {
      case 'SWAP':
        return formatMessage(messages.swap);
      case 'BRIDGE':
        return formatMessage(messages.bridge);
      case 'STAKE':
        return formatMessage(messages.stake);
      case 'UNSTAKE':
        return formatMessage(messages.unstake);
      case 'MINT':
        return formatMessage(messages.mint);
      case 'CONTRACT_EXECUTION':
        return formatMessage(messages.smartContract);
      default:
        return formatMessage(messages.fromTitle);
    }
  }, [formatMessage, transactionType]);

  const topDetailColor = useMemo(() => {
    switch (transactionState) {
      case 'pending':
        return 'foregroundMuted';
      case 'failed':
        return 'negative';
      default:
        return 'foreground';
    }
  }, [transactionState]);

  const bottomDetailColor = useMemo(() => {
    switch (transactionState) {
      case 'pending':
        return 'foregroundMuted';
      case 'failed':
        return 'foregroundMuted';
      default:
        return 'positive';
    }
  }, [transactionState]);

  const detailTop = useMemo(() => {
    if (!topDetail) {
      return undefined;
    }
    return (
      <TextHeadline align="end" color={topDetailColor}>
        {transactionState === 'failed' ? topDetail : `−${topDetail}`}
      </TextHeadline>
    );
  }, [topDetail, topDetailColor, transactionState]);

  const subdetailTop = useMemo(() => {
    if (!topSubdetail) {
      return undefined;
    }
    return (
      <TextLabel2 align="end" color="foregroundMuted">
        {topSubdetail}
      </TextLabel2>
    );
  }, [topSubdetail]);

  const detailBottom = useMemo(() => {
    if ((transactionType === 'SEND' && transactionState === 'failed') || !bottomDetail) {
      return undefined;
    }
    return (
      <TextBody align="end" color={bottomDetailColor}>
        +{bottomDetail}
      </TextBody>
    );
  }, [transactionType, transactionState, bottomDetail, bottomDetailColor]);

  const subdetailBottom = useMemo(() => {
    if ((transactionType === 'SEND' && transactionState === 'failed') || !bottomSubdetail) {
      return undefined;
    }
    return (
      <TextLabel2 align="end" color="foregroundMuted">
        {bottomSubdetail}
      </TextLabel2>
    );
  }, [bottomSubdetail, transactionType, transactionState]);

  // when listcell detail is not present, subdetail could be really
  // long (ex: 0.00000 THE PROOF OF ATTENDANCE) and make the entire
  // left hand side info disappear. Hence this check.
  // https://drive.google.com/file/d/1On6DdSe1kt7m7_titYl0aib4lCIS82gu/view?usp=sharing
  const priority = detailBottom ? 'end' : 'start';

  const showDetailBottom = useMemo(() => {
    if (STAKE_TRANSACTION_TYPES.includes(transactionType)) {
      return !!bottomDetail;
    }
    if (transactionType !== 'CONTRACT_EXECUTION') {
      return true;
    }
    return false;
  }, [bottomDetail, transactionType]);

  return (
    <Box spacingVertical={2} spacingHorizontal={2}>
      <Card bordered borderRadius="rounded">
        <TouchableWithoutFeedback
          onPress={handleFromAddressPress}
          testID="hr-transaction-detail-card-top-pressable"
        >
          <ListCell
            testID="hr-transaction-detail-card-top"
            detail={detailTop}
            title={titleTop}
            disableMultilineTitle
            description={topDescription}
            subdetail={subdetailTop}
            media={topIcon}
            priority={priority}
            innerSpacing={spacingHorizontal}
          />
        </TouchableWithoutFeedback>
        {showDetailBottom && (
          <>
            <HStack spacingHorizontal={3}>
              <Icon name="downArrow" size="s" spacingStart={0.5} color="foregroundMuted" />
            </HStack>
            <TouchableWithoutFeedback
              onPress={handleToAddressPress}
              testID="hr-transaction-detail-card-bottom-pressable"
            >
              <ListCell
                testID="hr-transaction-detail-card-bottom"
                detail={detailBottom}
                title={formatMessage(messages.toTitle)}
                disableMultilineTitle
                description={bottomDescription}
                subdetail={subdetailBottom}
                media={bottomIcon}
                priority={priority}
                innerSpacing={spacingHorizontal}
              />
            </TouchableWithoutFeedback>
          </>
        )}
      </Card>
    </Box>
  );
}

