const LINK_URL = 'https://www.coinbase.com/learn/tips-and-tutorials';

const messages = defineMessages({
  title: {
    defaultMessage: 'No transactions yet',
    description: 'Title for empty transactions list',
  },
  description: {
    defaultMessage:
      'Your crypto and NFT activity will appear here once you start using your wallet.',
    description: 'Description for empty transactions list',
  },
  cta: {
    defaultMessage: 'Add crypto to your wallet',
    description: 'Button title for adding crypto on empty transactions list',
  },
  link: {
    defaultMessage: 'Tips for getting started',
    description: 'Link title for help page with tips and tutorials for using the app',
