type TransactionsEmptyStateProps = {
  header?: React.ReactNode;
  subHeader?: string;
  showButtons?: boolean;
  customIllustration?: React.ReactNode;
  listContainerStyles?: StyleProp<ViewStyle>;
};

export const TransactionsEmptyState = memo(function TransactionsEmptyState({
  header,
  subHeader,
  showButtons = true,
  customIllustration,
  listContainerStyles,
}: TransactionsEmptyStateProps) {
  const { formatMessage } = useIntl();
  const openWebBrowser = useOpenWebBrowser();
  const launchBuyFlow = useLaunchBuyFlow();
  const platform = getPlatformName();

  const NuxIllustration = useMemo(
    () => (
      <MiamiIllustrationWrapper illustration="TradeImmediatelyMiami">
        <HeroSquare
          name="tradeImmediately"
          dimension="200x200"
          testID="transactions-empty-illustration"
        />
      </MiamiIllustrationWrapper>
    ),
    [],
  );

  const handleAddCryptoPress = useCallback(
    function handleAddCryptoPress() {
      logTransactionsEmptyAddCryptoClicked();
      launchBuyFlow();
    },
    [launchBuyFlow],
  );

  const isCbPayEnabled = useIsCbPayEnabled();

  const onLinkPress = useCallback(() => {
    openWebBrowser(LINK_URL);
  }, [openWebBrowser]);

  return (
    <Box
      testID="transactions-empty-state"
      flexGrow={1}
      // eslint-disable-next-line react/forbid-component-props
      style={listContainerStyles}
    >
      {header}
      {subHeader && (
        <TextTitle3 spacingHorizontal={3} spacingBottom={1} spacingTop={2}>
          {subHeader}
        </TextTitle3>
      )}
      <ScrollView>
        <VStack alignItems="center" gap={1} spacingHorizontal={3}>
          {customIllustration ?? NuxIllustration}
          <TextTitle3 align="center">{formatMessage(messages.title)}</TextTitle3>
          <TextBody align="center" color="foregroundMuted">
            {formatMessage(messages.description)}
          </TextBody>
        </VStack>
      </ScrollView>

      {showButtons && (
        <VStack
          spacingHorizontal={3}
          spacingTop={1}
          spacingBottom={3}
          background="background"
          pin="bottom"
        >
          <ButtonGroup accessibilityLabel="Empty transactions buttons" direction="vertical">
            {isCbPayEnabled && (
              <Button variant="primary" onPress={handleAddCryptoPress}>
                {formatMessage(messages.cta)}
              </Button>
            )}
            {platform !== PlatformName.ios && (
              <Button variant="secondary" onPress={onLinkPress}>
                {formatMessage(messages.link)}
              </Button>
            )}
          </ButtonGroup>
        </VStack>
      )}
    </Box>
  );
});

