  filterButton: {
    defaultMessage: 'Filter',
    description: 'Label for filter by button',
  },
  filterNetworkHeader: {
    defaultMessage: 'Network',
    description: 'Heading for the filter network tray',
  },
  resetButton: {
    defaultMessage: 'Clear',
    description: 'Label for reset filter button',
  },
  doneButton: {
    defaultMessage: 'Done',
    description: 'Label for done button',
  },
});

type BlockchainListItemProps = {
  selected: boolean;
  blockchain: Blockchain;
  currencyCode: CurrencyCode;
  fiatBalance: Decimal;
  imageUrl?: string;
  onPress: (blockchain: string) => void;
};

const BlockchainListItem = memo(function BlockchainListItem({
  onPress,
  selected,
  blockchain,
  currencyCode,
  imageUrl,
  fiatBalance,
}: BlockchainListItemProps) {
  const { formatters } = useIntl();
  const activeFiatCurrency = useActiveFiatCurrency();

  const handleSelectAsset = useCallback(() => {
    onPress(blockchain.rawValue);
  }, [onPress, blockchain.rawValue]);

  const formattedBalance = useMemo(() => {
    const currencyFormatter = formatters.getNumberFormat(undefined, {
      style: 'currency',
      currency: activeFiatCurrency.code.rawValue,
    });

    const decimalFormatter = formatters.getNumberFormat(undefined, {
      style: 'decimal',
      currency: activeFiatCurrency.code.rawValue,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

    return formatDecimal({
      integerFormatter: currencyFormatter,
      decimalFormatter,
      value: fiatBalance ?? new Decimal(0),
    });
  }, [formatters, activeFiatCurrency.code.rawValue, fiatBalance]);

  return (
    <AssetListCell
      currencyCode={currencyCode.rawValue}
      name={blockchain.fullName()}
      onSelectAsset={handleSelectAsset}
      imageUrl={imageUrl}
      fiatBalance={formattedBalance}
      type="other"
      selected={selected}
    />
  );
});

type Props = {
  handleClose: () => void;
  goBack: () => void;
};

export const TransactionsFilterTrayContent = memo(function TransactionsFilterTray({
  handleClose,
  goBack,
}: Props) {
  const { formatMessage } = useIntl();

  const scrollViewRef = useRef<ScrollView>(null);
  const [itemHeight, setItemHeight] = useState<number>();

  const { filterableNetworksOrBlockchains, filter, setFilter } = useTransactionFilter();

  const resetTransactionFilter = useResetTransactionFilter();

  const numFilterableItems = useMemo(() => {
    return filterableNetworksOrBlockchains.length;
  }, [filterableNetworksOrBlockchains.length]);

  const deleteFromFilter = useCallback(
    function deleteFromFilter(arg: string) {
      const filterCopy = new Set([...filter]);
      filterCopy.delete(arg);
      return filterCopy;
    },
    [filter],
  );

  const handleSelectAsset = useCallback(
    function handleSelectAsset(asset: string) {
      const updatedFilter = filter.has(asset)
        ? deleteFromFilter(asset)
        : new Set([...filter, asset]);

      setFilter(updatedFilter);
    },
    [deleteFromFilter, filter, setFilter],
  );

  const handleSelectNetwork = useCallback(
    (network: Network) => {
      handleSelectAsset(network.rawValue);
    },
    [handleSelectAsset],
  );

  const onLayout = useCallback((event: LayoutChangeEvent) => {
    setItemHeight(event.nativeEvent.layout.height);
  }, []);

  const scrollViewHeight = useMemo(() => {
    // We're setting a fixed height if it has less than 3 wallet to avoid showing a tiny tray
    if (!itemHeight || numFilterableItems <= 3) return MIN_TRAY_HEIGHT;

    const maxContentHeight = Dimensions.get('window').height * MAX_TRAY_PERCENTAGE_HEIGHT;
    const newHeight = itemHeight * numFilterableItems;

    return newHeight > maxContentHeight ? maxContentHeight : newHeight;
  }, [itemHeight, numFilterableItems]);

  return (
    <VStack>
      <HStack alignItems="center" justifyContent="space-between" spacingHorizontal={2} gap={2}>
        <HStack alignItems="center" gap={1}>
          <IconButton name="backArrow" transparent onPress={goBack} />
          <TextTitle4>{formatMessage(messages.filterNetworkHeader)}</TextTitle4>
        </HStack>
        {filter.size > 0 && (
          <Link variant="body" onPress={resetTransactionFilter}>
            {formatMessage(messages.resetButton)}
          </Link>
        )}
      </HStack>
      <Spacer vertical={2} />
      <Box height={scrollViewHeight} spacingBottom={1}>
        <ScrollView
          fadingEdgeLength={100}
          showsVerticalScrollIndicator={false}
          ref={scrollViewRef}
          testID="transactions-filter-scroll-view"
        >
          {filterableNetworksOrBlockchains.map((networkOrBlockchain, index) => {
            switch (networkOrBlockchain.type) {
              case 'network': {
                const { network, fiatBalance } = networkOrBlockchain;
                return (
                  <Box
                    key={network.rawValue}
                    testID="transactions-filter-list-item"
                    onLayout={index === 0 ? onLayout : undefined}
                  >
                    <NetworkListItem
                      network={network}
                      balance={fiatBalance}
                      onPress={handleSelectNetwork}
                      selected={filter.has(network.rawValue)}
                      showBalance
                      iconSize={40}
                      compact
                    />
                  </Box>
                );
              }
              case 'blockchain': {
                const { blockchain, currencyCode, imageUrl, fiatBalance } = networkOrBlockchain;
                return (
                  <Box key={blockchain.rawValue} testID="transactions-filter-list-item">
                    <BlockchainListItem
                      selected={filter.has(blockchain.rawValue)}
                      blockchain={blockchain}
                      currencyCode={currencyCode}
                      fiatBalance={fiatBalance}
                      imageUrl={imageUrl}
                      onPress={handleSelectAsset}
                    />
                  </Box>
                );
              }
              // no default
            }
            // Will never get here, just here to make lint happy.
            return <></>;
          })}
        </ScrollView>
      </Box>
      <VStack spacingHorizontal={2}>
        <Button variant="primary" onPress={handleClose} testID="close-filter-btn">
          {formatMessage(messages.doneButton)}
        </Button>
      </VStack>
    </VStack>
  );
});

