type TransactionSortListCellProps = {
  title: string;
  media: ReactElement;
  onPress: (arg: string) => void;
  selected: boolean;
};

const TransactionSortListCell = memo(function TransactionSortListCell({
  title,
  media,
  onPress,
  selected,
}: TransactionSortListCellProps) {
  const { formatMessage } = useIntl();
  const { orderDesc, setOrderDesc } = useTransactionSort();

  const sortArg = useMemo(() => title.toLowerCase(), [title]);

  const intermediaryLabel = useMemo(() => {
    if (sortArg === 'date') {
      return orderDesc ? formatMessage(messages.dateDesc) : formatMessage(messages.dateAsc);
    }

    return orderDesc ? formatMessage(messages.amountDesc) : formatMessage(messages.amountAsc);
  }, [formatMessage, orderDesc, sortArg]);

  const intermediary = useMemo(() => {
    return (
      <HStack alignItems="center" justifyContent="flex-end" gap={1}>
        <TextBody>{intermediaryLabel}</TextBody>
        <Icon name={orderDesc ? 'downArrow' : 'upArrow'} color="primary" size="s" />
      </HStack>
    );
  }, [intermediaryLabel, orderDesc]);

  const handleSelect = useCallback(
    function handleSelect() {
      setOrderDesc(!orderDesc);
      onPress(sortArg);
    },
    [setOrderDesc, orderDesc, onPress, sortArg],
  );

  return (
    <Cell
      testID="transactions-sort-list-item"
      compact
      media={media}
      selected={selected}
      onPress={handleSelect}
    >
      <HStack justifyContent="space-between" alignItems="center">
        <TextHeadline>{title}</TextHeadline>

        {selected && (
          <Box flexGrow={0} justifyContent="center">
            {intermediary}
          </Box>
        )}
      </HStack>
    </Cell>
  );
});

