function TransactionDetailContent({ transaction }: Props) {
  useJourneyMarkOnMount('loaded_transaction_detail');
  const { from } = useParams<SuperAppModeStackParamList, 'TransactionDetail'>();
  const { goBack } = useStackNavigation();
  const { formatMessage } = useIntl();
  const openWebBrowser = useOpenWebBrowser();

  const activeWalletGroupId = useActiveWalletGroupId();
  const {
    fiatValue,
    submittedDate,
    completedOnDate,
    networkFee,
    valueDisplay,
    totalFiat,
    totalCrypto,
    cryptoValueDisplay,
    fromDisplay,
    toDisplay,
    networkName,
    blockExplorerUrl,
    blockExplorerTitle,
    blockExplorerCompactTitle,
    showPendingActions,
    status,
  } = useFormattedTransaction(activeWalletGroupId, transaction);
  const dominantCurrencyIsFiat = Boolean(fiatValue);
  const isPrivacyModeEnabled = usePrivacyMode();

  const getIsClaimLinkSendTx = useGetIsClaimLinkSend();
  const getIsClaimLinkReceiveTx = useGetIsClaimLinkReceive();
  const { isSponsored: isSponsoredClaimLinkSend } = getIsClaimLinkSendTx(transaction);
  const { isSponsored: isSponsoredClaimLinkReceive } = getIsClaimLinkReceiveTx(transaction);
  const isSponsoredClaimLinkTx = isSponsoredClaimLinkSend || isSponsoredClaimLinkReceive;
  const isSponsoredTx = transaction.isSponsored() || isSponsoredClaimLinkTx;
  const isSwapTx = useIsSwapTransaction(transaction);
  const isSwapPending = isSwapTx && transaction.state === TxState.PENDING;

  // Speedup / cancel tray
  const [trayVisible, { toggleOn: showActionsTray, toggleOff: hideActionsTray }] =
    useToggler(false);
  const [isSpeedUp, setIsSpeedUp] = useState(false);
  const { height: bottomOffset } = useBottomNavDimensions();
  const toast = useRateLimitedToast({});
  const { copyToClipboard } = useClipboard();
  const { walletId } = useFormattedTransactionListItem(activeWalletGroupId, transaction);

  const wallet = useWalletById(activeWalletGroupId, walletId ?? ''); // wallet will not be found until it's been hydrated
  const perfMarkEndOptions = useMemo(() => ({ ...stableEndTypeOption, logMetric: true }), []);
  const isMaliciousZeroValueTransfer = useIsMaliciousZeroValueTransfer();
  const is1559Enabled = isNetwork1559Enabled(transaction.network);
  const getIsSpeedUpEnabled = useIsSpeedUpEnabled();
  const getIsCancelEnabled = useIsCancelEnabled();
  const { networkFeeTooltip } = useNetworkFeeTooltipMessages(
    transaction.network.asChain()?.chainId,
  );

  const totalRowValue = useMemo(() => {
    if (isPrivacyModeEnabled) return DEFAULT_PRIVACY_MODE_ELEMENT;

    if (isSwapTx) {
      return transaction.state === TxState.PENDING ? status : `${valueDisplay}`;
    }

    if (isSponsoredTx) {
      return `${valueDisplay}`;
    }

    if (totalFiat) {
      return totalCrypto ? `${totalFiat} • ${totalCrypto}` : `${totalFiat}`;
    }
    return cryptoValueDisplay;
  }, [
    cryptoValueDisplay,
    isPrivacyModeEnabled,
    isSponsoredTx,
    isSwapTx,
    status,
    totalCrypto,
    totalFiat,
    transaction.state,
    valueDisplay,
  ]);

  const [, endNavigationFromAssetDetailPerfMark] = usePerfMark(
    PERF_MARKS.assets,
    ASSETS_MARKS.navigate_to_transaction_detail_from_asset_detail,
    perfMarkEndOptions,
  );

  const [, endNavigationFromAssetTxDetailsPerfMark] = usePerfMark(
    PERF_MARKS.assets,
    ASSETS_MARKS.navigate_to_transaction_detail_from_asset_tx_details,
    perfMarkEndOptions,
  );

  const openUrl = useCallback(() => {
    if (blockExplorerUrl) {
      logBlockExplorerClicked(transaction.blockchain.rawValue, transaction.network.rawValue);
      openWebBrowser(blockExplorerUrl);
    }
  }, [
    blockExplorerUrl,
    openWebBrowser,
    transaction.blockchain.rawValue,
    transaction.network.rawValue,
  ]);

  const handleCancelPressed = useCallback(
    function handleCancelPressed() {
      setIsSpeedUp(false);
      showActionsTray();
    },
    [showActionsTray],
  );

  const handleSpeedUpPressed = useCallback(
    function handleSpeedUpPressed() {
      setIsSpeedUp(true);
      showActionsTray();
    },
    [showActionsTray],
  );

  // Once done for any reason, close the tray
  const onCloseComplete = useCallback(() => {
    hideActionsTray();
  }, [hideActionsTray]);

  const handleError = useCallback(
    function handleError(error: Error) {
      const message = `Error modifying transaction: ${error.message}`;
      toast.show(message, { bottomOffset });
      onCloseComplete();
    },
    [toast, bottomOffset, onCloseComplete],
  );

  const handleSuccess = useCallback(
    function handleSuccess() {
      onCloseComplete();
      goBack();
    },
    [onCloseComplete, goBack],
  );

  const handleFromAddressPress = useCallback(
    function handleFromAddressPress() {
      if (isMaliciousZeroValueTransfer(transaction)) {
        return;
      }

      copyToClipboard(transaction.fromAddress, true, formatMessage(messages.fromAddressCopied));
      logAddressCopied({
        network: transaction.network.rawValue,
        blockchain: transaction.blockchain.rawValue,
        addressType: 'from',
        source: transaction.source,
      });
    },
    [isMaliciousZeroValueTransfer, transaction, copyToClipboard, formatMessage],
  );

  const handleToAddressPress = useCallback(() => {
    copyToClipboard(transaction.toAddress, true, formatMessage(messages.toAddressCopied));
    logAddressCopied({
      network: transaction.network.rawValue,
      blockchain: transaction.blockchain.rawValue,
      addressType: 'to',
      source: transaction.source,
    });
  }, [
    copyToClipboard,
    formatMessage,
    transaction.blockchain.rawValue,
    transaction.network.rawValue,
    transaction.source,
    transaction.toAddress,
  ]);

  const handleTxHashPress = useCallback(() => {
    copyToClipboard(transaction.txHash, true, formatMessage(messages.txHashCopied));
  }, [copyToClipboard, formatMessage, transaction.txHash]);

  useEffect(
    function onMountPerfMarkEffect() {
      if (from === 'AssetDetail') {
        endNavigationFromAssetDetailPerfMark();
      }

      if (from === 'AssetTransactionDetails') {
        endNavigationFromAssetTxDetailsPerfMark();
      }
    },
    [endNavigationFromAssetDetailPerfMark, endNavigationFromAssetTxDetailsPerfMark, from],
  );

  const buttons = useMemo(() => {
    const isSpeedUpEnabled = getIsSpeedUpEnabled({ transaction, is1559Enabled });
    const isCancelEnabled = getIsCancelEnabled({ transaction, is1559Enabled });

    return showPendingActions && (isSpeedUpEnabled || isCancelEnabled) ? (
      <HStack
        justifyContent="space-around"
        alignContent="center"
        spacingBottom={2}
        spacingHorizontal={8}
      >
        <>
          {isSpeedUpEnabled ? (
            <VStack alignItems="center" gap={1} flexBasis={1} flexGrow={1}>
              <IconButton variant="secondary" name="lightningBolt" onPress={handleSpeedUpPressed} />
              <TextLabel2 color="foregroundMuted" align="center">
                {formatMessage(messages.speedUpButtonLabel)}
              </TextLabel2>
            </VStack>
          ) : null}

          {isCancelEnabled ? (
            <VStack alignItems="center" gap={1} flexBasis={1} flexGrow={1}>
              <IconButton variant="secondary" name="close" onPress={handleCancelPressed} />
              <TextLabel2 color="foregroundMuted" align="center">
                {formatMessage(messages.cancelButtonLabel)}
              </TextLabel2>
            </VStack>
          ) : null}
        </>
        {blockExplorerUrl && blockExplorerCompactTitle && (
          <VStack alignItems="center" gap={1} flexBasis={1} flexGrow={1}>
            <IconButton variant="secondary" name="externalLink" onPress={openUrl} />
            <TextLabel2 color="foregroundMuted" align="center">
              {blockExplorerCompactTitle}
            </TextLabel2>
          </VStack>
        )}
      </HStack>
    ) : (
      <>
        {blockExplorerUrl && blockExplorerTitle && (
          <Button variant="secondary" onPress={openUrl} spacingHorizontal={3} spacingBottom={3}>
            {blockExplorerTitle}
          </Button>
        )}
      </>
    );
  }, [
    getIsSpeedUpEnabled,
    transaction,
    is1559Enabled,
    getIsCancelEnabled,
    showPendingActions,
    handleSpeedUpPressed,
    formatMessage,
    handleCancelPressed,
    blockExplorerUrl,
    blockExplorerCompactTitle,
    openUrl,
    blockExplorerTitle,
  ]);

  const formattedTxHash = useMemo(() => {
    if (transaction.txHash) {
      return getTruncatedAddress(transaction.txHash);
    }
    return '';
  }, [transaction.txHash]);

  const header = useMemo(() => {
    if (isSwapPending) {
      return <Header title={status} centered />;
    }
    return dominantCurrencyIsFiat ? (
      <TransactionDetailHeader
        title={fiatValue ?? ''}
        label={cryptoValueDisplay}
        transaction={transaction}
        centered
      />
    ) : (
      <TransactionDetailHeader
        title={cryptoValueDisplay ?? ''}
        transaction={transaction}
        centered
      />
    );
  }, [cryptoValueDisplay, dominantCurrencyIsFiat, fiatValue, isSwapPending, status, transaction]);

  const isSponsoredAsset = !!useGetSponsoredSendInfo(wallet);
  const isSuperapp = useIsSuperAppModeEnabled();
  const shouldShowAdvancedTxInfo = !isSponsoredAsset || isSuperapp;

  return (
    <>
      <Box testID="transaction-detail" height="100%" spacingBottom={3}>
        <ScrollView>
          <VStack spacingBottom={2}>
            <VStack borderedBottom spacingVertical={5}>
              {header}
            </VStack>
            {transaction.isTronReceiveTx ? (
              <TronReceiveTxDetailRow transaction={transaction} />
            ) : (
              <VStack spacingHorizontal={3} spacingTop={2}>
                {isSwapTx ? (
                  <TxDetailRow
                    label={formatMessage(messages.receivedLabel)}
                    detailText={isSwapPending ? status : valueDisplay}
                  />
                ) : null}
                <TxDetailRow
                  label={formatMessage(messages.fromLabel)}
                  detailText={fromDisplay}
                  testID="txdetail-from-row"
                  onDetailTextPress={handleFromAddressPress}
                />
                <TxDetailRow
                  label={formatMessage(messages.toLabel)}
                  detailText={toDisplay}
                  onDetailTextPress={handleToAddressPress}
                />
                {!!networkName && (
                  <TxDetailRow
                    label={formatMessage(messages.networkDisplayName)}
                    detailText={networkName}
                    actionIcon={<NetworkIcon network={transaction.network} />}
                  />
                )}
                {shouldShowAdvancedTxInfo && !!transaction.txHash && (
                  <TxDetailRow
                    label={formatMessage(messages.txHashLabel)}
                    onDetailTextPress={handleTxHashPress}
                    detailText={formattedTxHash}
                    testID="txhash"
                  />
                )}
                {shouldShowAdvancedTxInfo && (
                  <TxDetailRow
                    label={formatMessage(messages.submittedLabel)}
                    detailText={submittedDate}
                    testID="submitted"
                  />
                )}
                {completedOnDate && (
                  <TxDetailRow
                    label={formatMessage(messages.completedOnLabel)}
                    detailText={completedOnDate}
                    testID="completedon"
                  />
                )}
                {!!valueDisplay && !transaction.isNFTTransfer() && !isSwapTx ? (
                  <TxDetailRow
                    label={formatMessage(messages.amountLabel)}
                    detailText={isSwapPending ? status : valueDisplay}
                  />
                ) : null}
                {isSwapTx ? (
                  <TxDetailRow
                    label={formatMessage(messages.coinbaseFeeLabel)}
                    detailText={formatMessage(messages.freeLabel)}
                    tooltipText={formatMessage(messages.coinbaseFeeFreeTooltip)}
                  />
                ) : null}
                {!!networkFee && (
                  <TxDetailRow
                    testID="networkfee"
                    label={formatMessage(messages.networkFeeLabel)}
                    detailTextPreFormatted={
                      isSponsoredTx && !isSwapTx ? (
                        <VStack alignItems="flex-end">
                          <StrikeThroughDetailText>{networkFee}</StrikeThroughDetailText>
                          <TextLabel2 color="positive">
                            {formatMessage(messages.sponsoredTx)}
                          </TextLabel2>
                        </VStack>
                      ) : undefined
                    }
                    detailText={!isSponsoredTx && !isSwapPending ? networkFee : status}
                    tooltipText={formatMessage(
                      isSponsoredTx ? messages.sponsoredTooltip : networkFeeTooltip,
                    )}
                    tooltipAccessibilityLabel={formatMessage(
                      messages.networkFeeTooltipAccessibilityLabel,
                    )}
                  />
                )}

                {!!totalRowValue && !transaction.isNFTTransfer() && !isSwapTx ? (
                  <TxDetailRow
                    label={
                      transaction.isSent
                        ? formatMessage(messages.totalLabel)
                        : formatMessage(messages.totalReceivedLabel)
                    }
                    detailText={totalRowValue}
                    testID="total"
                  />
                ) : null}
                <Spacer />
              </VStack>
            )}
          </VStack>
        </ScrollView>
        <VStack
          gap={1}
          borderedTop
          background="background"
          spacingTop={transaction.isTronReceiveTx ? 3 : 0}
        >
          {!transaction.isTronReceiveTx ? (
            <TransactionDetailStatusRow transaction={transaction} />
          ) : null}
          {buttons}
        </VStack>
      </Box>
      {trayVisible && wallet && (
        <TransactionsActionsTray
          onCloseComplete={onCloseComplete}
          isSpeedUp={isSpeedUp}
          transaction={transaction}
          wallet={wallet}
          handleSuccess={handleSuccess}
          handleError={handleError}
        />
      )}
    </>
  );
}

