import { memo, useState } from 'react';
import { logUserInterestsQuizViewed } from 'cb-wallet-analytics/userInterestsQuiz';
import {
  Interest,
  useFetchUserInterests,
} from 'cb-wallet-data/hooks/useFetchUserInterests/useFetchUserInterests';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { useSetUserInterestsQuizSeen } from 'cb-wallet-data/stores/UserInterestsQuiz/hooks/useUserInterestsQuizSeen';
import { Box } from '@cbhq/cds-mobile/layout';
import { Spinner } from '@cbhq/cds-mobile/loaders';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextBody, TextDisplay2 } from '@cbhq/cds-mobile/typography';

import { Screen } from ':rn/cds-wallet/components/layout/Screen';
import { withScreenBoundary } from ':rn/cds-wallet/utils/withScreenBoundary';

import { unescapeUnicode } from './helpers';
import { UserInterestsFooter } from './UserInterestsFooter';

const UserInterestsQuizContent = memo(function UserInterestsQuizContent() {
  const [selectedInterests, setSelectedInterests] = useState<Interest[]>([]);
  const { data, isError } = useFetchUserInterests();
  const setUserInterestsQuizSeen = useSetUserInterestsQuizSeen();

  useOnMount(logUserInterestsQuizViewed);

  const handleInterestPressed = (interest: Interest) => () => {
    if (selectedInterests.includes(interest)) {
      setSelectedInterests((prev) => prev.filter((val) => val !== interest));
    } else {
      setSelectedInterests((prev) => [...prev, interest]);
    }
  };

  if (isError) {
    setUserInterestsQuizSeen(true);
  }

  if (!data) {
    return (
      <Screen footer={<UserInterestsFooter userInterests={selectedInterests} />}>
        <Box alignItems="center" justifyContent="center" flexGrow={1}>
          <Spinner size="large" />
        </Box>
      </Screen>
    );
  }

  return (
    <Screen
      footer={<UserInterestsFooter userInterests={selectedInterests} />}
      scrollable
      hideNavBar
    >
      <Box spacingHorizontal={2} spacingTop={5}>
        <TextDisplay2>{data.title}</TextDisplay2>
        <TextBody spacingBottom={3} spacingTop={1}>
          {data.subtitle}
        </TextBody>
        <TextBody color="foregroundMuted" spacingBottom={1}>
          {data.interestHeader}
        </TextBody>
        <Box flexWrap="wrap" flexDirection="row">
          {data.interests.map((interest) => (
            <Box spacing={0.5} key={interest.text} spacingHorizontal={1} spacingVertical={1}>
              <Pressable
                testID={interest.text}
                onPress={handleInterestPressed(interest)}
                background={selectedInterests.includes(interest) ? 'primary' : 'secondary'}
                borderRadius={100}
              >
                <TextBody spacingVertical={1} spacingHorizontal={2}>
                  {`${unescapeUnicode(interest.icon)} ${interest.text}`}
                </TextBody>
              </Pressable>
            </Box>
          ))}
        </Box>
      </Box>
    </Screen>
  );
});

export const UserInterestsQuizScreen = withScreenBoundary(UserInterestsQuizContent);

import { memo, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Pressable, ScrollView } from 'react-native';
import { useTriggerWalletlinkRequestViewed } from 'cb-wallet-analytics/walletlink';
import { useIsTxPreviewEnabled } from 'cb-wallet-data/stores/TxScanner/hooks/useIsTxPreviewEnabled';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { useActiveWalletIndex } from 'cb-wallet-data/stores/Wallets/hooks/useActiveWalletIndex';
import { useEthereumWalletPrimaryAddress } from 'cb-wallet-data/stores/Wallets/hooks/useEthereumWalletPrimaryAddress';
import { safeParseUrl } from 'cb-wallet-data/utils/urlUtils';
import { stringify } from 'cb-wallet-store/utils/serialization';
import noop from 'lodash/noop';
import { DrawerRefBaseProps, useToggler } from '@cbhq/cds-mobile';
import { Box } from '@cbhq/cds-mobile/layout';
import { PortalProvider } from '@cbhq/cds-mobile/overlays/PortalProvider';
import { markJourney, useJourneyMarkOnMount } from '@cbhq/core-vitals-mobile';

import { ErrorBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ErrorBoundary';
import { Modal } from ':rn/cds-wallet/components/Modal/Modal';
import { ModalSafeAreaView } from ':rn/cds-wallet/components/ModalSafeAreaView/ModalSafeAreaView';
import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { withScreenBoundary } from ':rn/cds-wallet/utils/withScreenBoundary';
import { AddChain } from ':rn/shared/components/Web3/AddChain';
import { SignMessage } from ':rn/shared/components/Web3/SignMessage/SignMessage';
import { SignTransaction } from ':rn/shared/components/Web3/SignTransaction/SignTransaction';
import { SwitchChain } from ':rn/shared/components/Web3/SwitchChain';
import { WatchAsset } from ':rn/shared/components/Web3/WatchAsset';
import { Web3DialogErrorFallback } from ':rn/shared/components/Web3/Web3DialogErrorFallback';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';
import { navigateBackToPreviousApp } from ':rn/shared/minimizer/navigateBackToPreviousApp';
import {
  AddEthereumChainMessage,
  DAppMetadata,
  SignEthereumMessageMessage,
  SignEthereumTransactionMessage,
  SwitchEthereumChainMessage,
  WatchAssetMessage,
  Web3Call,
  Web3CallResponse,
} from ':rn/shared/types/web3Types';
import {
  PendingWalletlinkRequest,
  usePendingRequests,
} from ':rn/shared/walletlink/hooks/usePendingRequests';
import { usePendingResponses } from ':rn/shared/walletlink/hooks/usePendingResponses';
import { useUpdatePendingResponses } from ':rn/shared/walletlink/hooks/useUpdatePendingResponses';
import { useUpdateSession } from ':rn/shared/walletlink/hooks/useUpdateSession';
import { requestHasErrorUi } from ':rn/shared/walletlink/models/HostRequest';
import { RequestMethod } from ':rn/shared/walletlink/models/RequestMethod';
import { WalletLinkAuthorizationModal } from ':rn/shared/walletlink/screens/WalletLinkAuthorizationModal';
import { WalletLinkConnectAndSignInTray } from ':rn/shared/walletlink/screens/WalletLinkConnectAndSignInTray';
import { WalletLinkErrorState } from ':rn/shared/walletlink/screens/WalletLinkErrorState';

const WalletLink = memo(function WalletLink() {
  const { goBack } = useStackNavigation();
  const pendingRequests = usePendingRequests();
  const pendingResponses = usePendingResponses();
  const activeWalletIndex = useActiveWalletIndex('ETH');
  const updatePendingResponses = useUpdatePendingResponses();
  const updateSession = useUpdateSession();
  const isTxPreviewEnabled = useIsTxPreviewEnabled();
  const redirectAfterCompletion = useRef(false);

  const [isTrayVisible, { toggleOn: toggleTrayOn, toggleOff: toggleTrayOff }] = useToggler(false);
  const trayRef = useRef<DrawerRefBaseProps>(null);

  // keep track of requests we've already handled so we do not
  // re-render a tray after it was closed / cancelled / confirmed
  const [handledRequestIds, setHandledRequestIds] = useState<string[]>([]);

  const activeWalletGroupId = useActiveWalletGroupId();
  const ethereumWalletPrimaryAddress = useEthereumWalletPrimaryAddress(activeWalletGroupId);

  const currentRequest = useMemo(
    () => {
      const current = pendingRequests.filter((request) => !request.hasSeen)[0];
      if (current) {
        markJourney('start_load_walletlink_request_tray');
        return current;
      }
      return undefined;
    },
    // stringifying the request array prevents us from re-rendering and firing the CUJ mark more than we should
    // eslint-disable-next-line wallet/exhaustive-deps
    [stringify(pendingRequests)],
  );

  useEffect(
    function toggleTrayForCurrentRequest() {
      if (currentRequest && !handledRequestIds.includes(currentRequest.serverEventId)) {
        // animate the Tray component in
        toggleTrayOn();
      }
    },
    [currentRequest, toggleTrayOn, handledRequestIds],
  );

  const responseWithError = useMemo(() => {
    if (!currentRequest) return;

    // Currently we only show the WalletLink Error state for initial connection issues.
    // More methods can be added by updating the Error state component and adding the relevant
    // methods to requestHasErrorUi
    return pendingResponses.find((response) => {
      return (
        response.request.serverEventId === currentRequest.serverEventId &&
        response.errorPublishing &&
        requestHasErrorUi(response.request)
      );
    });
  }, [pendingResponses, currentRequest]);

  useEffect(
    function goBackWhenDone() {
      if (!currentRequest) {
        goBack();
        if (redirectAfterCompletion.current) {
          redirectAfterCompletion.current = false;
          navigateBackToPreviousApp();
        }
      } else {
        redirectAfterCompletion.current = Boolean(currentRequest.session.redirectUrl);
      }
    },
    [currentRequest, goBack],
  );

  const closeTray = useCallback(
    function closeTray() {
      // animate the Tray component out
      trayRef?.current?.handleClose();
    },
    [trayRef],
  );

  const {
    metadata: metadataNullish,
    data: dataNullish,
    onConfirm: onConfirmNullish,
    onDismiss: onDismissNullish,
    onCancel: onCancelNullish,
    fullscreen,
  } = useMemo(
    function getDataAndMetadata(): {
      metadata?: DAppMetadata;
      data?: Web3Call;
      onConfirm?: (response: Web3CallResponse | undefined) => void;
      onDismiss?: () => void;
      onCancel?: () => void;
      fullscreen?: boolean;
    } {
      if (!currentRequest) {
        return {};
      }

      const dappUrl = currentRequest.session.isParent ? currentRequest.url : currentRequest.dappURL;

      const metadataRet = {
        dappUrl,
        dappName: currentRequest.dappName!,
        dappHostname: safeParseUrl(dappUrl).hostname,
        dappLogoUrl: currentRequest.session.dappImageURL,
      };

      const onCancelFunc = () => {
        setHandledRequestIds((prev) => [...prev, currentRequest.serverEventId]);

        closeTray();

        updatePendingResponses({
          type: 'reject',
          request: currentRequest,
          errorMessage: 'User rejected signature request',
          sent: false,
        });
      };

      const onConfirmFunc = (response: Web3CallResponse | undefined) => {
        if (!response) {
          return;
        }
        setHandledRequestIds((prev) => [...prev, currentRequest.serverEventId]);

        closeTray();

        if (response.errorMessage) {
          updatePendingResponses({
            type: 'reject',
            request: currentRequest,
            errorMessage: String(response.errorMessage),
            sent: false,
          });
          return;
        }

        const responseData = response.result
          ? Buffer.from(response.result as string, 'utf-8')
          : Buffer.from([]);

        updatePendingResponses({
          type: 'approve',
          data: responseData,
          request: currentRequest,
          metadata: {},
          sent: false,
        });
      };

      switch (currentRequest.method) {
        case RequestMethod.signEthereumTransaction: {
          const data: SignEthereumTransactionMessage = {
            id: 1,
            request: currentRequest.web3Request,
          };
          return {
            data,
            metadata: metadataRet,
            onConfirm: onConfirmFunc,
            onDismiss: onCancelFunc,
            onCancel: onCancelFunc,
            fullscreen: !isTxPreviewEnabled,
          };
        }
        case RequestMethod.signEthereumMessage: {
          const data: SignEthereumMessageMessage = {
            id: 1,
            request: currentRequest.web3Request,
          };

          return {
            data,
            metadata: metadataRet,
            onConfirm: onConfirmFunc,
            onDismiss: onCancelFunc,
            onCancel: onCancelFunc,
          };
        }
        case RequestMethod.switchEthereumChain:
          return {
            data: {
              id: 1,
              request: {
                method: 'switchEthereumChain',
                params: {
                  chainId: currentRequest.web3Request.params.chainId,
                },
              },
            },
            metadata: metadataRet,
            onConfirm: (response) => {
              if (!response) {
                return;
              }

              updatePendingResponses({
                type: 'approve',
                data: Buffer.from([]),
                request: currentRequest,
                metadata: { chainId: currentRequest.web3Request.params.chainId },
                sent: false,
              });

              updateSession({
                ...currentRequest.session,
                chainId: Number(currentRequest.web3Request.params.chainId),
              });
            },
            onDismiss: onCancelFunc,
            onCancel: onCancelFunc,
          };
        case RequestMethod.addEthereumChain: {
          const data: AddEthereumChainMessage = {
            id: 1,
            request: currentRequest.web3Request,
          };
          return {
            data,
            metadata: metadataRet,
            onConfirm: (response) => {
              if (!response) {
                return;
              }

              updatePendingResponses({
                type: 'approve',
                data: Buffer.from([]),
                request: currentRequest,
                metadata: { chainId: currentRequest.web3Request.params.chainId },
                sent: false,
              });

              updateSession({
                ...currentRequest.session,
                chainId: Number(currentRequest.web3Request.params.chainId),
              });
            },
            onDismiss: onCancelFunc,
            onCancel: onCancelFunc,
          };
        }
        case RequestMethod.watchAsset:
          return {
            data: {
              id: 1,
              request: currentRequest.web3Request,
            },
            metadata: metadataRet,
            onConfirm: (response) => {
              if (response?.result === true) {
                updatePendingResponses({
                  type: 'approve',
                  data: Buffer.from([]),
                  request: currentRequest,
                  metadata: {},
                  sent: false,
                });
              } else {
                // Watch asset is weird, it'll emit an onConfirm event with result === false
                // in the case the user rejected the request
                onCancelFunc();
              }
            },
            onDismiss: onCancelFunc,
            onCancel: onCancelFunc,
          };
        case RequestMethod.childRequestEthereumAccounts:
          throw new Error('Should never get here, these requests are auto-approved');
        case RequestMethod.generic:
          throw new Error('Generic request not yet implemented');
        case RequestMethod.requestEthereumAccounts:
        case RequestMethod.connectAndSignIn:
          return {};
        default:
          throw new Error(`Unexpected request ${currentRequest.method}`);
      }
    },
    [currentRequest, closeTray, updatePendingResponses, isTxPreviewEnabled, updateSession],
  );

  const closeConfirmationDialog = useCallback(
    function closeConfirmationDialog() {
      // hide the Tray component so it can be rendered for subsequent requests
      toggleTrayOff();
      // cancel the pending request
      onCancelNullish?.();
    },
    [onCancelNullish, toggleTrayOff],
  );

  /**
   * The order of these returns matter
   *
   * First:
   * We want to return if there is no current request or primary wallet address
   *
   * Second:
   * We want to display the WalletLinkErrorState if there is a currentRequest with
   * a pending response that could not be published
   *
   * Third:
   * Display the connection request authorization modal (full screen)
   *
   * Fourth:
   * Display any trays or modals for pending requests
   */

  if (!currentRequest || !ethereumWalletPrimaryAddress) {
    return <></>;
  }

  if (responseWithError) {
    return <WalletLinkErrorState request={currentRequest} response={responseWithError} />;
  }

  if (currentRequest.method === RequestMethod.requestEthereumAccounts) {
    return (
      <WalletLinkAuthorizationModal
        request={currentRequest}
        ethereumWalletPrimaryAddress={ethereumWalletPrimaryAddress}
      />
    );
  }

  if (currentRequest.method === RequestMethod.connectAndSignIn) {
    return (
      <WalletLinkConnectAndSignInTray
        request={currentRequest}
        ethereumWalletPrimaryAddress={ethereumWalletPrimaryAddress}
        activeWalletIndex={activeWalletIndex}
      />
    );
  }

  // At this point we're sure we have data, metadata etc.
  const data = dataNullish!;
  const metadata = metadataNullish!;
  const onConfirm = onConfirmNullish!;
  const onDismiss = onDismissNullish!;
  const onSuccess = noop;

  return (
    <>
      {currentRequest &&
        (fullscreen ? (
          <Modal
            testID="wallet-link-modal"
            hideDividers
            visible
            onRequestClose={closeConfirmationDialog}
          >
            <ModalSafeAreaView>
              <PortalProvider>
                <Box flexGrow={1} spacingTop={1} justifyContent="space-between">
                  <ErrorBoundary
                    context="walletlink"
                    errorFallback={
                      <Web3DialogErrorFallback
                        buttonVariant="close"
                        onPressTryAgain={onDismiss}
                        fullscreen
                      />
                    }
                  >
                    <WalletLinkRequest
                      request={currentRequest}
                      activeWalletIndex={activeWalletIndex}
                      ethereumWalletPrimaryAddress={ethereumWalletPrimaryAddress}
                      onSuccess={onSuccess}
                      onDismiss={onDismiss}
                      onConfirm={onConfirm}
                      data={data}
                      metadata={metadata}
                    />
                  </ErrorBoundary>
                </Box>
              </PortalProvider>
            </ModalSafeAreaView>
          </Modal>
        ) : (
          isTrayVisible && (
            <Tray
              onCloseComplete={closeConfirmationDialog}
              disableCapturePanGestureToDismiss
              verticalDrawerPercentageOfView={0.9}
              ref={trayRef}
              testID="wallet-link-request-tray"
            >
              <PortalProvider>
                <ScrollView>
                  <Pressable>
                    <ErrorBoundary
                      context="walletlink"
                      errorFallback={
                        <Web3DialogErrorFallback
                          buttonVariant="close"
                          onPressTryAgain={onDismiss}
                          fullscreen
                        />
                      }
                    >
                      <WalletLinkRequest
                        request={currentRequest}
                        activeWalletIndex={activeWalletIndex}
                        ethereumWalletPrimaryAddress={ethereumWalletPrimaryAddress}
                        onSuccess={onSuccess}
                        onDismiss={onDismiss}
                        onConfirm={onConfirm}
                        data={data}
                        metadata={metadata}
                      />
                    </ErrorBoundary>
                  </Pressable>
                </ScrollView>
              </PortalProvider>
            </Tray>
          )
        ))}
    </>
  );
});

type WalletLinkRequestProps = {
  request: PendingWalletlinkRequest;
  activeWalletIndex: bigint | undefined;
  ethereumWalletPrimaryAddress: string;
  onSuccess: () => void;
  onDismiss: () => void;
  onConfirm: (response: Web3CallResponse | undefined) => void;
  data: Web3Call | undefined;
  metadata: DAppMetadata;
};

const WalletLinkRequest = memo(function WalletLinkRequest({
  request,
  activeWalletIndex,
  ethereumWalletPrimaryAddress,
  onSuccess,
  onDismiss,
  onConfirm,
  data,
  metadata,
}: WalletLinkRequestProps) {
  useTriggerWalletlinkRequestViewed({
    method: request.method,
    sessionId: request.session.id,
    serverEventId: request.serverEventId,
    eventId: request.id,
    url: request.dappURL,
    requestSource: request.source,
  });
  useJourneyMarkOnMount('loaded_walletlink_request_tray');

  switch (request.method) {
    case RequestMethod.signEthereumTransaction:
      return (
        <SignTransaction
          data={data as SignEthereumTransactionMessage}
          metadata={metadata}
          onConfirm={onConfirm}
          onDismiss={onDismiss}
          txSource="walletlink"
        />
      );
    case RequestMethod.signEthereumMessage:
      return (
        <SignMessage
          data={data as SignEthereumMessageMessage}
          metadata={metadata}
          onConfirm={onConfirm}
          onDismiss={onDismiss}
          evmWalletIndex={activeWalletIndex}
          evmAddress={ethereumWalletPrimaryAddress}
        />
      );
    case RequestMethod.switchEthereumChain:
      return (
        <SwitchChain
          data={data as SwitchEthereumChainMessage}
          metadata={metadata}
          onConfirm={onConfirm}
          onDismiss={onDismiss}
          onSuccess={onSuccess}
        />
      );
    case RequestMethod.addEthereumChain:
      return (
        <AddChain
          data={data as AddEthereumChainMessage}
          metadata={metadata}
          onConfirm={onConfirm}
          onDismiss={onDismiss}
          onSuccess={onSuccess}
        />
      );
    case RequestMethod.watchAsset:
      return (
        <WatchAsset
          data={data as WatchAssetMessage}
          metadata={metadata}
          onConfirm={onConfirm}
          onDismiss={onDismiss}
        />
      );
    default:
      // Should never get here
      return <></>;
  }
});

