const outerSpacing: CellSpacing = { spacingEnd: 2, spacingStart: 1 };

type WatchlistDiscoveryCellProps = {
  address: string;
  index: number;
  item: ExploreAssetResponse;
};

type HandleSuccessParams = { isWatchingUpdate: boolean };

type WatchlistDiscoveryCellContentProps = WatchlistDiscoveryCellProps & {
  isWatching: boolean;
  optimisticUpdate: () => void;
  resetUpdate: () => void;
};

const WatchlistDiscoveryCellContent = memo(function WatchlistDiscoveryCellContent({
  address,
  index,
  item,
  isWatching,
  optimisticUpdate,
  resetUpdate,
}: WatchlistDiscoveryCellContentProps) {
  const { navigate } = useStackNavigation();

  const watchedAsset = useWatchlistItem({
    address: item.address,
    blockchain: item.blockchain,
    networkId: item.networkId,
    chainId: item.chainId,
    decimals: item.decimals,
    name: item.name,
    symbol: item.currencyCode,
    uuid: item.uuid,
  });

  const activeWalletGroupId = useActiveWalletGroupId();
  const getExploreAssetWallet = useGetExploreAssetWallet(activeWalletGroupId);
  const assetWallet = getExploreAssetWallet(watchedAsset.id);
  const { variant, label } = useFormatPercentChange({ percentChange: watchedAsset?.priceChange });

  const formattedAmount = useWatchedAssetPrice(watchedAsset);

  const { openNotificationOptInTrayIfEligible } = useNotificationOptInTray({ source: 'watchlist' });

  const eventData = useMemo(
    () => ({
      chainName: item.blockchain,
      entityName: item.name,
      entityType: EntityTypeEnum.ASSET,
      rankIndex: index,
    }),
    [index, item.blockchain, item.name],
  );

  const cellClickEvent = useClickWatchlistDiscoveryCardEvent(eventData);
  useFocusEffect(useViewWatchlistDiscoveryCardEvent(eventData));

  const watchEvent = useWatchlistButtonEvent({
    entityName: item.name,
    chainName: item.blockchain,
  });

  const handleNavigation = useCallback(
    function handleNavigation() {
      cellClickEvent();
      // Use walletId if wallet exists to get balance, transactions etc
      navigate('AssetDetail', {
        walletId: assetWallet?.id ?? watchedAsset.id,
        source: AssetDetailSource.Explore,
      });
    },
    [cellClickEvent, navigate, assetWallet?.id, watchedAsset.id],
  );

  const handleError = useCallback(
    function handleError(error: ErrorOrAny) {
      resetUpdate();

      reportComponentError({
        error: new Error(`WatchlistDiscoveryCell: ${error}`),
        severity: 'error',
        isHandled: true,
      });
    },
    [resetUpdate],
  );

  const handleSuccess = useCallback(
    function handleSuccess({ isWatchingUpdate }: HandleSuccessParams) {
      watchEvent({ componentName: isWatchingUpdate ? 'add' : 'remove' });
    },
    [watchEvent],
  );

  const { addToWatchlist, isAdding } = useAddToWatchlist({
    blockchain: item.blockchain,
    chainId: item.chainId,
    networkId: item.networkId,
    contractAddress: item.address,
    handleError,
    handleSuccess,
    symbol: item.currencyCode,
    type: 'OBJECT_TYPE_ASSET',
    uuid: item.uuid,
    walletAddress: address,
  });

  const { removeFromWatchlist, isRemoving } = useRemoveFromWatchlist({
    chainId: item.chainId,
    networkId: item.networkId,
    contractAddress: item.address,
    handleError,
    handleSuccess,
    symbol: item.currencyCode,
    type: 'OBJECT_TYPE_ASSET',
    walletAddress: address,
  });

  const handleWatchlistUpdate = useCallback(
    function handleWatchlistUpdate() {
      optimisticUpdate();

      if (isWatching) {
        removeFromWatchlist();
        return;
      }

      addToWatchlist();

      openNotificationOptInTrayIfEligible({ context: 'watchlist' });
    },
    [
      addToWatchlist,
      isWatching,
      openNotificationOptInTrayIfEligible,
      optimisticUpdate,
      removeFromWatchlist,
    ],
  );

  return (
    <Box spacingBottom={1} borderRadius="roundedLarge" spacingHorizontal={3}>
      <Pressable
        background="backgroundAlternate"
        noScaleOnPress
        borderRadius="roundedLarge"
        onPress={handleNavigation}
        testID="watchlist-discovery-cell"
      >
        <HStack alignItems="center" spacingHorizontal={1}>
          <Box width="85%">
            <ListCell
              media={
                <AssetIcon
                  currencyCode={watchedAsset.symbol}
                  network={watchedAsset.network}
                  showNetworkIcon
                  iconUrl={watchedAsset.imageUrl}
                  width={32}
                  height={32}
                />
              }
              title={item.name}
              description={item.currencyCode}
              detail={formattedAmount}
              subdetail={<TextBody color={variant}>{label}</TextBody>}
              outerSpacing={outerSpacing}
            />
          </Box>
          <Box>
            <AutoHitSlopWrapper>
              <IconButton
                name={isWatching ? 'starActive' : 'starInactive'}
                transparent
                onPress={handleWatchlistUpdate}
                disabled={isAdding || isRemoving}
                variant={isWatching ? 'primary' : 'secondary'}
                testID="watchlist-discovery-toggle"
              />
            </AutoHitSlopWrapper>
          </Box>
        </HStack>
      </Pressable>
    </Box>
  );
});

const WatchlistDiscoveryCell = memo(function WatchlistDiscoveryCell({
  address,
  index,
  item,
}: WatchlistDiscoveryCellProps) {
  const { isWatchable, isWatching, optimisticUpdate, resetUpdate } = useAssetWatchlistState({
    contractAddress: item.address,
    networkId: item.networkId,
    chainId: item.chainId,
    symbol: item.currencyCode,
    uuid: item.uuid,
    walletAddress: address,
  });

  const unwatchableAssetEvent = useUnwatchableAssetEvent({
    chainName: item.blockchain,
    contractAddress: item.address ?? '',
    entityName: item.name,
    componentName: 'watchlist_discovery',
  });

  useEffect(
    function reportUnwatchableAsset() {
      if (!isWatchable) {
        unwatchableAssetEvent();
      }
    },
    [unwatchableAssetEvent, isWatchable],
  );

  if (!isWatchable) {
    return null;
  }

  return (
    <WatchlistDiscoveryCellContent
      address={address}
      index={index}
      item={item}
      isWatching={isWatching}
      optimisticUpdate={optimisticUpdate}
      resetUpdate={resetUpdate}
    />
  );
});

const WatchlistDiscoveryCellWithBoundary = memo(function WatchlistDiscoveryCellWithBoundary({
  address,
  index,
  item,
}: WatchlistDiscoveryCellProps) {
  return (
    <NetworkBoundary fallback={null} errorFallback={null}>
      <WatchlistDiscoveryCell address={address} index={index} item={item} />
    </NetworkBoundary>
  );
});

