type BrowseCollectionCardProps = {
  collection: BuyAndMintCollection;
  collapsed: boolean;
  hideInfo?: boolean;
};

export type BrowseCollectionCardGroupProps = {
  collections: BuyAndMintCollection[];
  header: React.ReactNode;
  logo?: ListCellProps['media'];
  provider: (typeof ALL_PROVIDERS)[number];
  testID?: string;
  isLoading?: boolean;
};

export const TOTAL_WRAPPERS_PADDING = 40;
export const IMAGE_PADDING = 2;
const listCellSpacing = { spacingHorizontal: 2 } as SpacingProps;

export function BrowseCollectionCard({
  collection,
  collapsed,
  hideInfo = false,
}: BrowseCollectionCardProps) {
  const {
    context,
    setBuyAndMintCollectible,
    setSelectedCollection,
    setUnsignedTx,
    setIsOCSInactiveCollectibleTrayVisible,
  } = useBuyAndMintContext();
  const { formatToCrypto } = useCurrencyFormatter();
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const { screenWidth } = useDimensions();
  const spaces = useSpacingScale();
  const { source } = useParams<SuperAppModeStackParamList, 'BuyAndMint'>();

  const enableScroll = collection.buyAndMintCollectibles.length > 3;

  const subtitle = useMemo(() => {
    if (collection.isMintingServiceCollection) {
      return formatMessage(messages.subTitlePick);
    }

    return formatMessage(messages.subTitlePreview);
  }, [collection.isMintingServiceCollection, formatMessage]);

  const width = useMemo(() => {
    return (
      (screenWidth - 2 * (TOTAL_WRAPPERS_PADDING + spaces[IMAGE_PADDING])) /
      (enableScroll ? 3.5 : 3)
    );
  }, [enableScroll, screenWidth, spaces]);

  const networkFeeInFiat = useCovertCryptoToFiatByChainId({
    chainId: collection.chainId,
    cryptoAmount: collection.networkFee,
  });

  const hasEnoughFeeToBuyNFT = useHasEnoughFeeToBuyNFT({
    chainId: collection.chainId,
    cryptoAmount: collection.networkFee,
  });

  const activeWalletGroupId = useActiveWalletGroupId();
  const wallet = useBaseAssetByChainID(activeWalletGroupId, collection.chainId);

  const collectionFloorPriceInCrypto = useMemo(() => {
    if (!collection.collectionFloorPrice || !wallet) return;

    return formatToCrypto({
      currencyCode: wallet.currencyCode,
      decimals: wallet.decimals,
      value: BigInt(collection.collectionFloorPrice),
      includeCode: true,
      overridePrivacy: true,
      shouldDisplayDustAmount: false,
    });
  }, [collection.collectionFloorPrice, formatToCrypto, wallet]);

  const generateUnsignedCollectibleTx = useGenerateUnSignedCollectibleTx();

  const handleCollectionTitlePress = useCallback(
    function handleCollectionTitlePress() {
      setSelectedCollection(collection);
      logCollectionNameClicked({ collectionName: collection.collectionName, context });
      navigate('CollectionDetails');
    },
    [setSelectedCollection, collection, context, navigate],
  );

  const handleCollectibleImagePress = useCallback(
    (item: BuyAndMintCollectible) => {
      return () => {
        if (item.inactive) {
          return setIsOCSInactiveCollectibleTrayVisible(true);
        }
        setBuyAndMintCollectible(item);
        setSelectedCollection(collection);
        logCollectionItemSelected({
          itemName: item.name,
          collectionProvider: collection.provider,
          contractAddress: collection.contractAddress,
          context,
        });

        if (hideInfo) {
          return navigate('BuyAndMint', {
            screen: collection.isCBNFTCollection
              ? 'CBNFTCollectibleDetails'
              : 'BuyAndMintCollectibleDetails',
            context: BuyAndMintFlowContext.EXPLORE,
            params: { buyAndMintCollectible: item, selectedCollection: collection },
          });
        }

        navigate(
          collection.isCBNFTCollection ? 'CBNFTCollectibleDetails' : 'BuyAndMintCollectibleDetails',
        );
      };
    },
    [
      setBuyAndMintCollectible,
      setSelectedCollection,
      collection,
      context,
      hideInfo,
      navigate,
      setIsOCSInactiveCollectibleTrayVisible,
    ],
  );

  const handleMintPress = useCallback(
    async function handleMintPress() {
      const unsignedTx = await generateUnsignedCollectibleTx(collection);

      setUnsignedTx(unsignedTx);
      setSelectedCollection(collection);
      logMintButtonClicked({ collectionProvider: collection.provider, source, context });

      if (hasEnoughFeeToBuyNFT) return navigate('BuyAndMint', { screen: 'ConfirmMint' });

      if (source === 'instagram') {
        return navigate('BuyAndMint', {
          screen: 'BuyNFTFundYourWallet',
          networkFee: networkFeeInFiat,
          currencyCode: collection.network.asChain()?.baseAssetCurrencyCode,
        });
      }

      navigate('BuyAndMint', { screen: 'TwoStepsToBuyNFT' });
    },
    [
      collection,
      context,
      generateUnsignedCollectibleTx,
      hasEnoughFeeToBuyNFT,
      navigate,
      networkFeeInFiat,
      setSelectedCollection,
      setUnsignedTx,
      source,
    ],
  );

  const renderItem = useCallback<ListRenderItem<BuyAndMintCollectible>>(
