import { memo, useCallback, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  logGetFirstNFTBannerClicked,
  logGetFirstNFTBannerClosed,
  useGetFirstNFTBannerViewed,
} from 'cb-wallet-analytics/web3Activation';
import { buyAndMintPersistedDataAtom } from 'cb-wallet-data/stores/Web3Activation/states/buyAndMintPersistedDataAtom';
import { getFirstNFTBannerAtom } from 'cb-wallet-data/stores/Web3Activation/states/getFirstNFTBannerAtom';
import { BuyAndMintFlowContext } from 'cb-wallet-data/stores/Web3Activation/types/BuyAndMintCollections';
import { useRecoilState, useRecoilValue, useSetRecoilState } from 'recoil';
import { Banner } from '@cbhq/cds-mobile/banner/Banner';
import { Box } from '@cbhq/cds-mobile/layout/Box';
import { Pressable } from '@cbhq/cds-mobile/system/Pressable';

import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

const messages = defineMessages({
  title: {
    defaultMessage: 'Get your NFT!',
    description: 'Banner title prompting user to initiate buy NFT',
  },
  body: {
    defaultMessage: 'You received your funds, its time to get your first NFT.',
    description: 'Banner body prompting user to continue to buy NFT',
  },
});

type GetFirstNFTBannerContentProps = { onClose: () => void };

function GetFirstNFTBannerContent({ onClose }: GetFirstNFTBannerContentProps) {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const [buyAndMintPersistedData, setBuyAndMintPersistedData] = useRecoilState(
    buyAndMintPersistedDataAtom,
  );

  const setGetFirstNFTBanner = useSetRecoilState(getFirstNFTBannerAtom);

  const handleRedirectToBuyNFTCompleted = useCallback(
    function handleRedirectToBuyNFTCompleted() {
      if (!buyAndMintPersistedData) return;
      logGetFirstNFTBannerClicked({
        context: buyAndMintPersistedData?.context as BuyAndMintFlowContext,
      });
      setGetFirstNFTBanner({ bannerCloseCount: 0, showGetFirstNFTBanner: false });
      navigate('BuyAndMint', {
        screen: 'TwoStepsToBuyNFTBuyCompleted',
        params: buyAndMintPersistedData,
      });
    },
    [buyAndMintPersistedData, navigate, setGetFirstNFTBanner],
  );

  // clear context & exit flow if user dismisses banner
  const handleBannerClose = useCallback(
    function handleBannerClose() {
      logGetFirstNFTBannerClosed({
        context: buyAndMintPersistedData?.context as BuyAndMintFlowContext,
      });
      setBuyAndMintPersistedData(undefined);
      setGetFirstNFTBanner((state) => ({
        showGetFirstNFTBanner: state.bannerCloseCount < 2, // update it to false the third time users close it
        bannerCloseCount: state.bannerCloseCount + 1,
      }));
      onClose();
    },
    [buyAndMintPersistedData?.context, setBuyAndMintPersistedData, setGetFirstNFTBanner, onClose],
  );

  useGetFirstNFTBannerViewed({
    context: buyAndMintPersistedData?.context as BuyAndMintFlowContext,
  });

  return (
    <Box pin="bottom" spacing={3} width="100%" testID="get-first-nft-banner">
      <Pressable
        background="transparent"
        onPress={handleRedirectToBuyNFTCompleted}
        testID="get-first-nft-banner-pressable"
      >
        <Banner
          title={formatMessage(messages.title)}
          variant="informational"
          startIcon="info"
          showDismiss
          onClose={handleBannerClose}
        >
          {formatMessage(messages.body)}
        </Banner>
      </Pressable>
    </Box>
  );
}

export const GetFirstNFTBanner = memo(function GetFirstNFTBanner() {
  const { showGetFirstNFTBanner, bannerCloseCount } = useRecoilValue(getFirstNFTBannerAtom);
  const [isVisibleForCurrentAppSession, setCurrentAppSessionVisibility] = useState(true);

  const onBannerClose = useCallback(() => {
    setCurrentAppSessionVisibility(false);
  }, []);

  return isVisibleForCurrentAppSession && showGetFirstNFTBanner && bannerCloseCount < 3 ? (
    <GetFirstNFTBannerContent onClose={onBannerClose} />
  ) : null;
});

