import { updateRemoteUserAssetSettings } from 'cb-wallet-data/stores/AssetManagement/api';
import { AssetManagementStatus } from 'cb-wallet-data/stores/AssetManagement/models/AssetManagementStatus';
import { UserCollectibleSetting } from 'cb-wallet-data/stores/AssetManagement/models/UserCollectibleSetting';
import { Network } from 'cb-wallet-data/stores/Networks/models/Network';
import { BuyAndMintFlowContext } from 'cb-wallet-data/stores/Web3Activation/types/BuyAndMintCollections';
import noop from 'lodash/noop';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Box } from '@cbhq/cds-mobile/layout';
import { TextLabel2 } from '@cbhq/cds-mobile/typography';

import {
  PopoverMenu,
  PopoverRef,
  Position,
} from ':rn/cds-wallet/components/PopoverMenu/PopoverMenu';
import { PopoverMenuItem } from ':rn/cds-wallet/components/PopoverMenu/PopoverMenuItem';
import { useRateLimitedToast } from ':rn/cds-wallet/hooks/useRateLimitedToast';

export const messages = defineMessages({
  report: {
    defaultMessage: 'Report NFT',
    description: 'Label for report button',
  },
  reported: {
    defaultMessage: 'NFT Reported',
    description: 'Label for report toast',
  },
});

export type ReportCollectibleOptionsProps = {
  primaryAddress: string;
  network: Network;
  contractAddress: string;
  tokenId: string;
  context: BuyAndMintFlowContext;
};

export function ReportCollectibleOptions({
  primaryAddress,
  network,
  contractAddress,
  tokenId,
  context,
}: ReportCollectibleOptionsProps) {
  const { formatMessage } = useIntl();
  const toast = useRateLimitedToast({});
  const anchorRef = useRef<View | null>(null);
  const popOverRef = useRef<PopoverRef>(null);

  const onOpenMenu = useCallback(() => {
    popOverRef.current?.show({
      anchorRef: anchorRef.current,
      stickToPosition: Position.BOTTOM_RIGHT,
    });
  }, []);

  const onSelectReportOption = useCallback(async () => {
    try {
      const userSettings = new UserCollectibleSetting(
        EthereumBlockchain,
        network,
        AssetManagementStatus.spam,
        contractAddress,
        primaryAddress ?? '',
        tokenId,
      );
      await updateRemoteUserAssetSettings(primaryAddress, { collectibles: [userSettings] }, noop);

      logReportNFT({ contractAddress, tokenId, context });
      toast.show(formatMessage(messages.reported));
    } catch (e: ErrorOrAny) {
      logReportNFTError({ errorMessage: e?.message, context });
    } finally {
      popOverRef.current?.hide();
    }
  }, [context, contractAddress, formatMessage, network, primaryAddress, toast, tokenId]);

  return (
    <Box background="background" ref={anchorRef}>
      <IconButton
        transparent
        name="more"
        variant="secondary"
        testID="toggle-report-options-button"
        onPress={onOpenMenu}
      />
      <PopoverMenu key="report-collectible-menu" ref={popOverRef}>
        <PopoverMenuItem onPress={onSelectReportOption}>
          <TextLabel2 color="negative">{formatMessage(messages.report)}</TextLabel2>
        </PopoverMenuItem>
      </PopoverMenu>
    </Box>
  );
}

