  const { navigate, goBack } = useStackNavigation();
  const setPersistedBuyAndMintState = useSetRecoilState(buyAndMintPersistedDataAtom);
  const {
    buyAndMintCollectible,
    selectedCollection: {
      chainId,
      network,
      networkFee,
      collectionSlug,
      collectionName,
      collectionImageUrl,
      collectionDescription,
      ethVolumeWeek,
      totalTokens,
      gasBaseFee,
      gasPriorityFee,
      gasLimit,
      provider,
      buyAndMintCollectibles,
      contractAddress,
      tx,
    },
  } = useBuyAndMintContext();

  const { isLoading, totalFeeInFiat, totalFeeInCrypto, totalNumberFeeInFiat } =
    useBuyNFTFeesByChainId({
      chainId,
      buyNFTCryptoAmount: networkFee,
    });

  const assetCode = useMemo(
    () => (network.asChain() as BaseChain).baseAssetCurrencyCode as string,
    [network],
  );
  const { web3ActivationBuyNFTNetworkFeeDescription } = useNetworkFeeTooltipMessages(chainId);

  const launchBuyFlow = useLaunchBuyFlow();

  const handleSetPersistedContext = useCallback(() => {
    // Set persisted collection data for buy and mint flow after users fund their wallets
    setPersistedBuyAndMintState({
      chainId,
      collectionName,
      collectionSlug,
      collectionImageUrl,
      collectionDescription,
      ethVolumeWeek,
      totalTokens,
      gasBaseFee: Number(gasBaseFee),
      gasPriorityFee: Number(gasPriorityFee),
      gasLimit: Number(gasLimit),
      provider,
      buyAndMintCollectibles,
      contractAddress,
      tx,
      buyAndMintCollectible,
    });
  }, [
    setPersistedBuyAndMintState,
    chainId,
    collectionName,
    collectionSlug,
    collectionImageUrl,
    collectionDescription,
    ethVolumeWeek,
    totalTokens,
    gasBaseFee,
    gasPriorityFee,
    gasLimit,
    provider,
    buyAndMintCollectibles,
    contractAddress,
    tx,
    buyAndMintCollectible,
  ]);

  const handleNavigateToCBPayBuy = useCallback(
    function handleNavigateToCBPayBuy(presetFiatAmount?: number) {
      logBuyNFTFundYourWalletOpenCBPay(assetCode, presetFiatAmount);
      launchBuyFlow({
        chainId,
        asset: assetCode,
        presetFiatAmount,
      });
    },
    [assetCode, launchBuyFlow, chainId],
  );

  const handleBuySuggestedAmountPress = useCallback(
    function handleBuySuggestedAmountPress() {
      logBuyNFTFundYourWalletSuggestedAmountPress(totalNumberFeeInFiat);
      handleSetPersistedContext();
      handleNavigateToCBPayBuy(totalNumberFeeInFiat || 0);
