    [goBack],
  );

  const leftIcon = useCallback(() => {
    return <IconButton name="backArrow" onPress={handleGoBack} transparent />;
  }, [handleGoBack]);

  const navBar = useMemo<NavBarConfig>(
    () => ({
      left: leftIcon,
    }),
    [leftIcon],
  );

  useLogBuyNFTFundYourWalletViewed();

  return (
    <Screen testID="buy-nft-fund-your-wallet" full navBar={navBar}>
