function ConfirmMint() {
  const { formatMessage } = useIntl();
  const currencyFormatter = useCurrencyFormatter();
  const isSmallScreen = useIsSmallScreen();
  const [isMinting, setIsMinting] = useState<boolean>(false);
  const {
    context,
    unsignedTx,
    buyAndMintCollectible,
    selectedCollection,
    setMintDotFunRedirectUrl,
  } = useBuyAndMintContext();
  const {
    network,
    networkFee,
    chainId,
    collectionSlug,
    provider,
    contractAddress,
    isMintDotFunCollection,
    isMintingServiceCollection,
  } = selectedCollection;

  const { goBack, navigate, replace } = useStackNavigation();
  const mintMintingServiceNFT = useMintMintingServiceNFT();
  const setPendingCollectionData = useSetRecoilState(pendingCollectionAtom);
  const setFreeMintsMintedItems = useSetRecoilState(freeMintsMintedItemsAtom);
  const { screenWidth } = useDimensions();
  const width = screenWidth / 2;
  const networkFeeInFiat = useCovertCryptoToFiatByChainId({
    chainId,
    cryptoAmount: networkFee,
  });
  const activeWalletGroupId = useActiveWalletGroupId();
  const ethereumWalletPrimaryAddress = useEthereumWalletPrimaryAddress(activeWalletGroupId);
  const activeAccount = useActiveAccount();

  const completeChecklistAction = useCompleteChecklistAction();
  const isWeb3StarterKitEnabled = useIsWeb3StarterKitEnabled();

  const blockExplorerUrl = useMemo(() => {
    if (!contractAddress || !unsignedTx?.network.asChain()?.blockExplorerUrl) return '';

    return `${unsignedTx.network.asChain()?.blockExplorerUrl}/address/${contractAddress}`;
  }, [contractAddress, unsignedTx]);

  // use valid image data from collection to display in the confirm mint screen
  // if no valid image data is found in buyAndMintCollectible
  const collectibleWithValidImageData = useMemo(
    () => selectCollectibleWithValidImageData(selectedCollection, buyAndMintCollectible),
    [buyAndMintCollectible, selectedCollection],
  );

  const handleCancel = useCallback(
    function handleCancel() {
      logConfirmMintCancelled({ context });
      goBack();
    },
    [context, goBack],
  );

  const handleMintSuccess = useCallback(
    function handleMintSuccess() {
      setPendingCollectionData({ showPendingCollection: true });

      logConfirmMintConfirmed({ collectionProvider: provider, contractAddress, context });

      if (isWeb3StarterKitEnabled) completeChecklistAction({ name: ChecklistActionName.MINT });
      navigate('MintInProgress');
    },
    [
      completeChecklistAction,
      context,
      contractAddress,
      isWeb3StarterKitEnabled,
      navigate,
      provider,
      setPendingCollectionData,
    ],
  );

  const signError = useCallback(
    function signError(signingError: Error) {
      logSignTXError({
        errorMessage: signingError.message,
        contractAddress,
        context,
        accountType: activeAccount.type,
      });
      reportComponentError({ error: signingError, severity: 'error', isHandled: false });
      replace('BuyAndMintError', { errorMessage: formatMessage(messages.signTxError) });
    },
    [activeAccount.type, context, contractAddress, formatMessage, replace],
  );

  const signSuccess = useCallback(
    function signSuccess({ txHash }: SignedTx) {
      logSignTXSuccess({ context, accountType: activeAccount.type });

      if (!contractAddress) return;

      // this response doesn't matter as we redirect users to mint.fun below
      // we're just fetching the submit_tx endpoint here for measurements
      getMintDotFunRedirectUrl({
        hash: txHash,
        collection: contractAddress,
        connectedWallet: ethereumWalletPrimaryAddress,
      });

      const redirectUrl = `https://mint.fun/?collection=${contractAddress}&tx=${txHash}&utm_source=coinbase`;
      setMintDotFunRedirectUrl(redirectUrl);

      handleMintSuccess();
    },
    [
      activeAccount.type,
      context,
      contractAddress,
      ethereumWalletPrimaryAddress,
      handleMintSuccess,
      setMintDotFunRedirectUrl,
    ],
  );

  const {
    signAndSubmit,
    isLoading,
    enableFraudWarningConfirmationTray,
    fraudWarningConfirmationTray,
    showFraudWarningConfirmationTray,
  } = useMintPublicNFT({
    unsignedTx: unsignedTx as UnsignedTx,
    chainId,
    signSuccess,
    signError,
    enableTxScanner: isMintDotFunCollection,
  });

  const handleConfirm = useCallback(async () => {
    try {
      if (!ALL_PROVIDERS.includes(provider)) {
        throw new Error(formatMessage(messages.unknownProviderErrorMessage, { provider }));
      }

      if (isMintingServiceCollection) {
        setIsMinting(true);

        await mintMintingServiceNFT({
          chainId,
          collectionSlug,
          itemSlug: buyAndMintCollectible.slug,
        });

        setIsMinting(false);

        setFreeMintsMintedItems((prevItems) => [
          ...prevItems,
          {
            address: contractAddress ?? '',
            chainId,
            collectionSlug,
            itemSlug: buyAndMintCollectible.slug,
            mintStatus: '',
          },
        ]);

        handleMintSuccess();
      }

      if (isMintDotFunCollection) {
        if (enableFraudWarningConfirmationTray) return showFraudWarningConfirmationTray();

        signAndSubmit();
      }
    } catch (e: ErrorOrAny) {
      let errorTitle;
      let errorMessage;

      if (e instanceof HTTPError) {
        // status: 403 - rate limit reached, there is a rate limit of 200 mints/hr
        if (e.status === 403) {
          // TODO: add error title and message
          errorTitle = formatMessage(messages.mintLimitErrorTitle);
          errorMessage = formatMessage(messages.mintLimitErrorMessage);
        }
      }

      logMintItemError({
        errorMessage: e?.message ?? '',
        chainId,
        collectionSlug,
        itemSlug: buyAndMintCollectible.slug,
        collectionProvider: provider,
        context,
      });
      setIsMinting(false);
      replace('BuyAndMintError', { errorTitle, errorMessage });
    }
  }, [
    provider,
    isMintingServiceCollection,
    isMintDotFunCollection,
    formatMessage,
    mintMintingServiceNFT,
    chainId,
    collectionSlug,
    buyAndMintCollectible.slug,
    setFreeMintsMintedItems,
    handleMintSuccess,
    contractAddress,
    enableFraudWarningConfirmationTray,
    showFraudWarningConfirmationTray,
    signAndSubmit,
    context,
    replace,
  ]);

  // No cost for minting service nfts
  const costOfNFT = currencyFormatter.fiatValueString(new Decimal(0), true);

  const poweredViaText = useMemo(() => {
    if (isMintingServiceCollection) {
      return formatMessage(messages.poweredViaCBNFT);
    }

    if (isMintDotFunCollection) {
      return formatMessage(messages.poweredViaMintDotFun);
    }

    return '';
  }, [formatMessage, isMintDotFunCollection, isMintingServiceCollection]);

  useConfirmMintViewed({ collectionProvider: provider, context });

  return (
    <Web3ActivationStep
      navBarTitle={formatMessage(messages.navBarTitle)}
      scrollableWithFlexGrow
      scrollable
    >
      <VStack flexGrow={1}>
        <VStack spacingHorizontal={3} flexGrow={1}>
          <VStack
            justifyContent="center"
            alignItems="center"
            background="backgroundAlternate"
            borderRadius="roundedSmall"
            spacing={isSmallScreen ? 2 : 4}
          >
            <BuyAndMintCollectibleImage
              width={width}
              collectible={collectibleWithValidImageData}
              contractAddress={contractAddress}
              chainId={chainId}
            />

            <Spacer vertical={2} />
            <TextTitle3>{buyAndMintCollectible.name}</TextTitle3>
            <Spacer vertical={1} />
            <TextLegal color="foregroundMuted">{poweredViaText}</TextLegal>
          </VStack>

          <Spacer vertical={isSmallScreen ? 2 : 3} />

          <Web3ActivationListCell
            title={formatMessage(messages.costOfNFT)}
            detail={
              <TextBody color="foregroundMuted" testID="confirm-nft-cost-of-nft">
                {costOfNFT}
              </TextBody>
            }
          />

          <Web3ActivationListCell
            title={formatMessage(messages.networkFee)}
            detail={networkFeeInFiat}
            testID="confirm-nft-network-fee"
          />

          <Web3ActivationListCell
            title={formatMessage(messages.network)}
            detail={network.asChain()?.displayName}
            testID="confirm-nft-network"
          />

          {contractAddress ? (
            <Web3ActivationListCell
              title={formatMessage(messages.contractAddress)}
              detail={
                <HStack alignItems="center">
                  <TextBody color="foregroundMuted" testID="confirm-nft-contract-address">
                    {getTruncatedAddress(contractAddress)}
                  </TextBody>
                  {blockExplorerUrl ? (
                    <Link to={blockExplorerUrl}>
                      <Icon name="externalLink" color="foreground" size="s" spacingStart={1} />
                    </Link>
                  ) : null}
                </HStack>
              }
            />
          ) : null}
        </VStack>

        <VStack spacingHorizontal={2} spacingVertical={2}>
          <ButtonGroup accessibilityLabel="Group" block>
            <Button variant="secondary" onPress={handleCancel} testID="cancel-mint-nft">
              {formatMessage(messages.cancelCta)}
            </Button>
            <Button
              onPress={handleConfirm}
              testID="confirm-mint-nft"
              disabled={isLoading || isMinting}
              loading={isLoading || isMinting}
            >
              {formatMessage(messages.confirmCta)}
            </Button>
          </ButtonGroup>
        </VStack>

        {fraudWarningConfirmationTray}
      </VStack>
    </Web3ActivationStep>
  );
}

