type Action = { icon: UiIconName; text: string; url: string; params?: Record<string, string> };

// TODO(WALL-26934): Remove this once we get this from the backend
const ACTION_BUTTONS: Action[] = [
  { icon: 'add', text: 'Buy crypto', url: 'Buy', params: { screen: 'BuyEntry' } },
  { icon: 'nft', text: 'Mint NFTs', url: 'BuyAndMint' },
  { icon: 'wireTransfer', text: 'Make a swap', url: 'Swap' },
  {
    icon: 'stake',
    text: 'Stake crypto',
    url: 'Stake',
    params: {
      screen: 'StakeNux',
      currencyCode: 'ETH',
      targetCurrencyCode: 'CBETH',
      chainId: '1',
      stakeType: 'stake',
    },
  },
  { icon: 'bridging', text: 'Bridge crypto', url: 'Bridge', params: { screen: 'BridgeNux' } },
  { icon: 'arrowUp', text: 'Send crypto', url: 'Send', params: { screen: 'SendNux' } },
  { icon: 'planetActive', text: 'Use a dapp', url: 'BrowserTab' },
];

type StreaksV2HeaderProps = {
  mintStreak: MintStreak;
};

type RenderItemProps = { item: Action; index: number };

type StreakActionProps = {
  action: Action;
};

function StreakAction({ action }: StreakActionProps) {
  const { icon, text, url, params } = action;

  const { navigate } = useStackNavigation();

  const handleActionPress = useCallback(() => {
    if (!url) return;

    navigate(url, params);
  }, [navigate, params, url]);

  return (
    <Pressable onPress={handleActionPress} background="transparent">
      <HStack
        gap={1}
        alignItems="center"
        borderRadius="roundedLarge"
        spacing={1}
        background="secondary"
        spacingHorizontal={2}
      >
        <Icon name={icon} size="s" color="foreground" />
        <TextLegal color="foreground">{text}</TextLegal>
      </HStack>
    </Pressable>
  );
}

export function StreaksHeader({ mintStreak }: StreaksV2HeaderProps) {
  const spacing = useSpacingScale();

  const contentContainerStyle = useMemo(
    () => ({ paddingLeft: 20, paddingRight: 1, columnGap: spacing[1] }),
    [spacing],
  );

  const renderItem = useCallback(function renderItem({ item: action }: RenderItemProps) {
    return <StreakAction action={action} />;
  }, []);

  const keyExtractor = useCallback((action: Action) => action.text, []);

  return (
    <VStack gap={3}>
      <HStack spacingHorizontal={3} gap={1} alignItems="center" testID="streaks-v2-header">
        <StreakGradientCircle count={mintStreak.count} strokeWidth={6} />
        <VStack gap={0.5}>
          <TextTitle3>{mintStreak.title}</TextTitle3>
          <TextLegal color="foregroundMuted" numberOfLines={2}>
            {mintStreak.description}
          </TextLegal>
        </VStack>
      </HStack>

      <FlatList
        data={ACTION_BUTTONS}
        renderItem={renderItem}
        contentContainerStyle={contentContainerStyle}
        showsHorizontalScrollIndicator={false}
        keyExtractor={keyExtractor}
        keyboardShouldPersistTaps="always"
        horizontal
      />
    </VStack>
  );
}

