    defaultMessage: `Here's how to mint your first NFT`,
    description: 'Title for two steps to buy nft in the buy and mint flow',
  },
  description: {
    defaultMessage: 'Minting an NFT still requires you to pay a network fee. {learnMore}',
    description: 'Description for two steps to buy nft in the buy and mint flow',
  },
  learnMore: {
    defaultMessage: 'Learn more',
