    defaultMessage: 'Transfer Funds',
    description: 'Button group accessibility label',
  },
});

function TwoStepsToBuyNFT() {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const launchBuyFlow = useLaunchBuyFlow();
  const [isModalVisible, { toggleOn, toggleOff }] = useToggler(false);
  const { context, buyAndMintCollectible, selectedCollection } = useBuyAndMintContext();

  const {
    chainId,
    network,
    networkFee,
    collectionSlug,
    collectionName,
    collectionImageUrl,
    collectionDescription,
    ethVolumeWeek,
    totalTokens,
    gasBaseFee,
    gasPriorityFee,
    gasLimit,
    provider,
    buyAndMintCollectibles,
    contractAddress,
    tx,
  } = selectedCollection;
  const { isLoading, buyCryptoFeeInFiat, buyNFTFeeInFiat, totalFeeInFiat } = useBuyNFTFeesByChainId(
    {
      chainId,
      buyNFTCryptoAmount: networkFee,
    },
  );

  const { totalFeeInFiat: totalFeeInFiatAbbreviated } = useBuyNFTFeesByChainId({
    chainId,
    buyNFTCryptoAmount: networkFee,
    isAbbreviated: true,
  });

  const setPersistedBuyAndMintData = useSetRecoilState(buyAndMintPersistedDataAtom);

  const assetCode = (network.asChain() as BaseChain).baseAssetCurrencyCode as string;

  const destinationWallet = useDestinationWallet(assetCode);

  const handleConnectCoinbaseClick = useCallback(
    async function handleConnectCoinbaseClick() {
      logBuyAndMintConnectCoinbaseClicked({ context });
      launchBuyFlow({
        wallet: destinationWallet,
        chainId: destinationWallet?.network.asChain()?.chainId,
        asset: assetCode,
        presetFiatAmount: Number(totalFeeInFiatAbbreviated) || 0,
      });
    },
    [context, launchBuyFlow, destinationWallet, assetCode, totalFeeInFiatAbbreviated],
  );

  const handleTransferFromOtherClick = useCallback(
    function handleTransferFromOtherClick() {
      logBuyAndMintTransferOtherClicked({ context });
      navigate('Receive');
    },
    [context, navigate],
  );

  const handleLearnMoreClick = useCallback(
    function handleLearnMoreClick() {
      logBuyAndMintLearnMoreClicked({ context });
      toggleOn();
    },
    [context, toggleOn],
  );

  useTwoStepsToBuyNFTViewed({ context });

  // Set persisted collection data for buy and mint flow after users fund their wallets
  useOnMount(function setPersistedData() {
    setPersistedBuyAndMintData({
      chainId,
      collectionName,
      collectionSlug,
      collectionImageUrl,
      collectionDescription,
      ethVolumeWeek,
      totalTokens,
      gasBaseFee: Number(gasBaseFee),
      gasPriorityFee: Number(gasPriorityFee),
      gasLimit: Number(gasLimit),
      provider,
      buyAndMintCollectibles,
      contractAddress,
      tx,
      buyAndMintCollectible: selectCollectibleWithValidImageData(
        selectedCollection,
        buyAndMintCollectible,
      ),
      context,
    });
  });

  return (
    <Web3ActivationStep
      titleText={formatMessage(messages.title)}
      bodyText={formatMessage(messages.description, {
        learnMore: (
          <Link
            testID="learn-more-link"
            variant="body"
            color="primary"
            onPress={handleLearnMoreClick}
          >
            {formatMessage(messages.learnMore)}
          </Link>
        ),
      })}
    >
      <TwoStepsToBuyNFTComponent
        sourceAssetCode={network.asChain()?.baseAssetCurrencyCode}
        isNetworkFeeLoading={isLoading}
        buyCryptoFeeInFiat={buyCryptoFeeInFiat}
        buyNFTFeeInFiat={buyNFTFeeInFiat}
        totalFeeInFiat={totalFeeInFiat}
        buttonComponent={
          <VStack>
            <ButtonGroup
              accessibilityLabel={formatMessage(messages.buttonGroupAccessibilityLabel)}
              direction="vertical"
            >
              <Button onPress={handleConnectCoinbaseClick} testID="cbpay-button">
                {formatMessage(messages.buyWithCoinbasePay)}
              </Button>
              <Button
                onPress={handleTransferFromOtherClick}
                variant="secondary"
                testID="receive-button"
              >
                {formatMessage(messages.transferFromOther)}
              </Button>
            </ButtonGroup>
          </VStack>
        }
      />
      <CoinbaseConnectDisclaimer spacingHorizontal={3} />
      <HowTheyAreDifferentModal onRequestClose={toggleOff} visible={isModalVisible} />
      <Spacer vertical={3} />
    </Web3ActivationStep>
  );
}

