const messages = defineMessages({
  title: {
    defaultMessage: "Let's fund your Wallet with {currencyCode}",
    description: 'Title for select funding method description',
  },
  description: {
    defaultMessage:
      'You can buy {currencyCode} with Coinbase Onramp or transfer it from another wallet.',
    description: 'Description for select funding method',
  },
  buyWithCoinbasePay: {
    defaultMessage: 'Buy with Coinbase Onramp',
    description: 'Label for button to trigger cb pay onramp sdk',
  },
  transferFromOther: {
    defaultMessage: 'Transfer from another wallet',
    description: 'Label for button to transfer from another wallet',
  },
  buttonGroupAccessibilityLabel: {
    defaultMessage: 'Transfer Funds',
    description: 'Button group accessibility label',
  },
});

function SelectFundingMethod() {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const persistedContext = usePersistBuyAndSwapContext();
  const { targetAsset, sourceAsset } = useBuyAndSwapFormData();
  const isBuyableWithCBPay = targetAsset.isBuyableWithCBPay;
  const assetCode = isBuyableWithCBPay
    ? targetAsset.currencyCode.rawValue
    : sourceAsset.currencyCode.rawValue;

  const launchBuyFlow = useLaunchBuyFlow();

  useSelectFundingMethodViewed();

  const handleSetPersistedContext = useCallback(
    function handleSetPersistedContext(buyFromCBPay: boolean) {
      if (isBuyableWithCBPay) return;
      persistedContext.set({
        targetAsset: {
          id: targetAsset?.swapId,
          name: targetAsset.name,
          imageURL: targetAsset.imageURL,
          currencyCode: targetAsset.currencyCode.rawValue,
          chainId: targetAsset.network.asChain()?.chainId,
        },
        sourceAsset: {
          id: sourceAsset?.swapId,
          name: sourceAsset.name,
          imageURL: sourceAsset.imageURL,
          currencyCode: sourceAsset.currencyCode.rawValue,
          chainId: sourceAsset.network.asChain()?.chainId,
        },
        buyFromCBPay,
      });
    },
    [
      isBuyableWithCBPay,
      persistedContext,
      targetAsset?.swapId,
      targetAsset.name,
      targetAsset.imageURL,
      targetAsset.currencyCode.rawValue,
      targetAsset.network,
      sourceAsset?.swapId,
      sourceAsset.name,
      sourceAsset.imageURL,
      sourceAsset.currencyCode.rawValue,
      sourceAsset.network,
    ],
  );

  const handleConnectCoinbaseClick = useCallback(
    async function handleConnectCoinbaseClick() {
      logBuyWithCBPayClicked();
      handleSetPersistedContext(false);
      launchBuyFlow({
        chainId: sourceAsset.network.asChain()?.chainId,
        asset: assetCode,
      });
    },
    [assetCode, handleSetPersistedContext, launchBuyFlow, sourceAsset.network],
  );

  const handleTransferFromOtherClick = useCallback(
    function handleTransferFromOtherClick() {
      logTransferFromOtherClicked();
      handleSetPersistedContext(false);
      navigate('Receive');
    },
    [handleSetPersistedContext, navigate],
  );

  return (
    <Web3ActivationStep
      titleText={formatMessage(messages.title, {
        currencyCode: assetCode,
        assetName: isBuyableWithCBPay ? targetAsset.name : sourceAsset.name,
      })}
      bodyText={formatMessage(messages.description, {
        currencyCode: assetCode,
      })}
    >
      <VStack spacingStart={2}>
        <VStack spacing={4} alignItems="center">
          <MiamiIllustrationWrapper illustration="TransferCoinsMiami">
            <SpotRectangle name="primeEarn" testID="swap-illustration" />
          </MiamiIllustrationWrapper>
        </VStack>

        <VStack spacingHorizontal={2} spacingTop={3}>
          <ButtonGroup
            accessibilityLabel={formatMessage(messages.buttonGroupAccessibilityLabel)}
            direction="vertical"
          >
            <Button onPress={handleConnectCoinbaseClick} testID="cbpay-button">
              {formatMessage(messages.buyWithCoinbasePay)}
            </Button>
            <Button
              onPress={handleTransferFromOtherClick}
              variant="secondary"
              testID="receive-button"
            >
              {formatMessage(messages.transferFromOther)}
            </Button>
          </ButtonGroup>
        </VStack>
        <CoinbaseConnectDisclaimer />
      </VStack>
    </Web3ActivationStep>
  );
}

