// fiat amount added in addition to network fee
// so that users can have enough funds to swap
const CB_PAY_BUY_AMOUNT = 10;

function SelectFundingMethodV2() {
  const { formatMessage } = useIntl();
  const { navigate } = useStackNavigation();
  const setBuyAndSwapPersistedData = useSetRecoilState(buyAndSwapPersistedDataAtom);
  const { targetAsset, sourceAsset } = useBuyAndSwapContext();
  const launchBuyFlow = useLaunchBuyFlow();

  if (!sourceAsset || !targetAsset) throw new Error('Source asset or target asset is undefined');

  const activeWalletGroupId = useActiveWalletGroupId();
  const { networkFee } = useNetworkFeeOfAssetPair(
    activeWalletGroupId,
    { targetAsset, sourceAsset },
    { isAbbreviated: true },
  );
  const assetCode = sourceAsset.currencyCode.rawValue;

  // add $10 to network fee to ensure user has enough funds to swap
  const fiatAmount = useMemo(() => {
    const totalNetworkFee = Number(networkFee.total);
    return CB_PAY_BUY_AMOUNT + (isNaN(totalNetworkFee) ? 0 : Math.ceil(totalNetworkFee));
  }, [networkFee.total]);

  const handleSetPersistedContext = useCallback(
    function handleSetPersistedContext() {
      setBuyAndSwapPersistedData({
        targetAsset: {
          id: targetAsset?.swapId,
          name: targetAsset.name,
          imageURL: targetAsset.imageURL,
          currencyCode: targetAsset.currencyCode.rawValue,
        },
        sourceAsset: {
          id: sourceAsset?.swapId,
          name: sourceAsset.name,
          imageURL: sourceAsset.imageURL,
          currencyCode: sourceAsset.currencyCode.rawValue,
        },
        contractAddress: targetAsset.address?.rawValue,
        chainId: sourceAsset.network.asChain()?.chainId,
      });
    },
    [
      setBuyAndSwapPersistedData,
      targetAsset?.swapId,
      targetAsset.name,
      targetAsset.imageURL,
      targetAsset.currencyCode.rawValue,
      targetAsset.address?.rawValue,
      sourceAsset?.swapId,
      sourceAsset.name,
      sourceAsset.imageURL,
      sourceAsset.currencyCode.rawValue,
      sourceAsset.network,
    ],
  );

  const handleConnectCoinbaseClick = useCallback(
    async function handleConnectCoinbaseClick() {
      logFundAndSwapNextStepClicked({ navigateTo: 'cb_pay' });
      launchBuyFlow({
        asset: assetCode,
        chainId: sourceAsset.network.asChain()?.chainId,
        presetFiatAmount: fiatAmount,
      });
    },
    [launchBuyFlow, assetCode, sourceAsset.network, fiatAmount],
  );

  const handleTransferFromOtherClick = useCallback(
    function handleTransferFromOtherClick() {
      logFundAndSwapNextStepClicked({ navigateTo: 'receive' });
      navigate('Receive');
    },
    [navigate],
  );

  useFundAndSwapViewed({ screen: 'select_funding_method' });

  useJourneyMarkOnMount('loaded_select_funding_methods');

  useOnMount(handleSetPersistedContext);

  return (
    <Web3ActivationStep
      titleText={formatMessage(messages.title, {
        currencyCode: assetCode,
        assetName: sourceAsset.name,
      })}
      bodyText={formatMessage(messages.description, {
        currencyCode: assetCode,
      })}
    >
      <VStack spacing={3} flexGrow={1} gap={2}>
        <VStack spacing={4} alignItems="center" justifyContent="center" flexGrow={1}>
          <MiamiIllustrationWrapper illustration="TransferCoinsMiami" scaleMultiplier={1.2}>
            <SpotRectangle name="primeEarn" testID="swap-illustration" />
          </MiamiIllustrationWrapper>
        </VStack>
        <ButtonGroup
          accessibilityLabel={formatMessage(messages.buttonGroupAccessibilityLabel)}
          direction="vertical"
        >
          <Button onPress={handleConnectCoinbaseClick} testID="cbpay-button">
            {formatMessage(messages.buyWithCoinbasePay)}
          </Button>
          <Button
            onPress={handleTransferFromOtherClick}
            variant="secondary"
            testID="receive-button"
          >
            {formatMessage(messages.transferFromOther)}
          </Button>
        </ButtonGroup>

        <CoinbaseConnectDisclaimer />
      </VStack>
    </Web3ActivationStep>
  );
}

