const defaultSelectedAsset: BuyAndSwapListAsset = Object.assign(mockETHCBSwapAsset, {
  supportedNetworks: [mockETHCBSwapAsset],
});

function run(mockSelectedAsset: BuyAndSwapListAsset = defaultSelectedAsset, baseAsset?: SwapAsset) {
  mockBuyAndSwapListAssetById.mockReturnValue(mockSelectedAsset);

  const networkFeeIncrement = 10;
  const networkFeesMap = new Map(
    mockSelectedAsset.supportedNetworks.map((asset, i) => [
      getNetworkFeeMapKey(asset, asset.isBuyableWithCBPay ? undefined : baseAsset),
      { totalRange: `$${(i + 1) * networkFeeIncrement} - $${(i + 2) * networkFeeIncrement}` },
    ]),
  );
  mockUseNetworkFeesMap.mockReturnValue({ isLoading: false, networkFeesMap });
  return renderWithAllProviders(<SelectNetworkScreen />);
}

