type CheckListTileProps = {
  checklistAction: ChecklistAction;
};

export const CheckListTile = memo(function ChecklistTile({ checklistAction }: CheckListTileProps) {
  const { navigate } = useStackNavigation();
  const { name, title, description, isComplete, cta, meta, icon } = checklistAction;
  const { url } = cta;
  const launchBuyFlow = useLaunchBuyFlow();

  const handleOnPress = useCallback(() => {
    logWeb3ActionTileClicked(name);
    if (url === 'Fund') {
      launchBuyFlow();
    } else {
      navigate(url, meta?.urlParams);
    }
  }, [meta?.urlParams, name, navigate, url, launchBuyFlow]);

  return (
    <Pressable background="transparent" onPress={handleOnPress} testID={`${name}-pressable`}>
      <VStack
        borderRadius="roundedLarge"
        background={isComplete ? 'positive' : 'backgroundAlternate'}
        gap={1}
        spacing={2}
        minHeight={150}
      >
        <Icon
          color={isComplete ? 'positiveForeground' : 'primary'}
          name={icon as UiIconName}
          size="l"
          testID={`${name}-icon`}
          bordered
        />
        <TextLegal
          color={isComplete ? 'positiveForeground' : 'foregroundMuted'}
          numberOfLines={1}
          ellipsizeMode="tail"
        >
          {description}
        </TextLegal>
        <TextHeadline
          color={isComplete ? 'positiveForeground' : 'secondaryForeground'}
          numberOfLines={2}
          ellipsizeMode="tail"
        >
          {title}
        </TextHeadline>
      </VStack>
    </Pressable>
  );
});

