}));

function mockProgressCard({ handleOnPress, title }: { handleOnPress: () => void; title: string }) {
  return <Button testID="progress-card" onPress={handleOnPress} title={title} />;
}
jest.mock('./ProgressCard', () => ({
  ProgressCard: mockProgressCard,
}));

jest.mock('cb-wallet-analytics/web3-starter-kit');

describe('Web3EntryCard', () => {
  it('renders', () => {
    (useGetChecklist as jest.Mock).mockReturnValue({
      data: mockGetChecklistResponse,
      refetch: mockRefetch,
    });
    (usePerfMarks as jest.Mock).mockReturnValue({
      startPerfMark: mockStartPerfMark,
      endPerfMark: mockEndPerfMark,
    });

    renderWithAllProviders(<Web3EntryCard />);

    expect(mockRefetch).toHaveBeenCalled();
    expect(mockStartPerfMark).toHaveBeenCalledOnce();
    expect(mockEndPerfMark).toHaveBeenCalledOnce();

    const progressCard = screen.getByTestId('progress-card');
    expect(progressCard).toBeTruthy();

    fireEvent.press(progressCard);
    expect(mockPush).toHaveBeenCalledWith('Checklist', {});
    expect(logWeb3EntryCardViewed).toHaveBeenCalledOnceWith({ context: undefined });
    expect(logWeb3EntryCardClicked).toHaveBeenCalledOnceWith({ context: undefined });
  });

  it('trigger analytics event with correct property', () => {
    (useGetChecklist as jest.Mock).mockReturnValue({
      data: mockGetChecklistResponse,
      refetch: mockRefetch,
    });

    renderWithAllProviders(<Web3EntryCard context="assets_tab" />);

    fireEvent.press(screen.getByTestId('progress-card'));

    expect(logWeb3EntryCardViewed).toHaveBeenCalledOnceWith({ context: 'assets_tab' });
    expect(logWeb3EntryCardClicked).toHaveBeenCalledOnceWith({ context: 'assets_tab' });
  });

  it('does not render when checklist is null', () => {
    (useGetChecklist as jest.Mock).mockReturnValue({ data: null, refetch: mockRefetch });
    renderWithAllProviders(<Web3EntryCard onEmpty={mockOnEmpty} />);
    expect(mockOnEmpty).toHaveBeenCalledOnceWith(true);
    expect(screen.queryByTestId('progress-card')).toBeFalsy();
  });

