      refetch: mockRefetch,
    });
    renderWithAllProviders(<Web3EntryCard hideIfCompleted />);

    expect(screen.queryByTestId('progress-card')).toBeFalsy();
  });

  it('does not refetch data on focus effect if it is suppressed', () => {
    (useGetChecklist as jest.Mock).mockReturnValue({
      data: mockGetChecklistResponse,
      refetch: mockRefetch,
    });
    renderWithAllProviders(<Web3EntryCard suppressRefetchFocusEffect />);

    expect(mockRefetch).not.toHaveBeenCalled();
  });
});

