import { memo, useCallback } from 'react';
import {
  useUTXOPendingTxButtonClicked,
  useUTXOPendingTxTrayViewed,
} from 'cb-wallet-analytics/send/Send';
import { useOnMount } from 'cb-wallet-data/hooks/useOnMount';
import { Blockchain } from 'cb-wallet-data/models/Blockchain';
import { usePendingUTXOCopy } from 'cb-wallet-data/stores/Copy/usePendingUTXOCopy';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';
import { HeroSquare } from '@cbhq/cds-mobile/illustrations';
import { Box, VStack } from '@cbhq/cds-mobile/layout';
import { TextBody, TextTitle3 } from '@cbhq/cds-mobile/typography';

import { ScreenBoundary } from ':rn/cds-wallet/components/ErrorBoundary/ScreenBoundary';
import { Button } from ':rn/cds-wallet/components/interactables/Button';
import { VirtualTrayComponent } from ':rn/cds-wallet/components/VirtualTrayComponent/VirtualTrayComponent';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

export type UTXOPendingTxTrayProps = {
  /**
   * a UTXO blockchain
   */
  blockchain: Blockchain;

  /**
   * Optional callback function for when the tray is completely closed
   */
  onClose?: () => void;
};

function UTXOPendingTxTrayContent({ blockchain, onClose }: UTXOPendingTxTrayProps) {
  const cryptoFullName = blockchain.fullName();
  const confirmationTime = blockchain.avgConfirmationTime();
  if (!blockchain || !cryptoFullName || !confirmationTime)
    throw Error('Invalid blockchainUTXOPendingTxTray');

  const canSpeedUp = blockchain.rawValue === 'BTC';
  const { trayTitle, trayText, pendingUTXOTxButtonText, dismissButtonText } = usePendingUTXOCopy(
    cryptoFullName,
    canSpeedUp,
    confirmationTime,
  );
  const { navigate } = useStackNavigation();

  const closeTray = useCallback(() => {
    onClose?.();
  }, [onClose]);

  const trayViewed = useUTXOPendingTxTrayViewed(blockchain.rawValue);

  const utxoPendingTxButtonClicked = useUTXOPendingTxButtonClicked(blockchain.rawValue);

  const navigateToPendingTxs = useCallback(
    function navigateToPending() {
      utxoPendingTxButtonClicked();

      navigate('TransactionsTab');

      closeTray();
    },
    [utxoPendingTxButtonClicked, navigate, closeTray],
  );

  useOnMount(trayViewed);

  return (
    <VirtualTrayComponent onCloseComplete={closeTray}>
      {({ handleClose }) => (
        <VStack spacingHorizontal={3}>
          <Box alignItems="center">
            <HeroSquare
              name="transactionLimit"
              scaleMultiplier={0.6}
              testID="transactionLimit-hero-icon"
            />
            <TextTitle3 spacingVertical={1}>{trayTitle}</TextTitle3>
          </Box>
          <TextBody color="foregroundMuted" spacingBottom={2}>
            {trayText}
          </TextBody>
          <Box spacingTop={2}>
            <ButtonGroup block accessibilityLabel="go-to-pending-txs-group">
              <Button onPress={navigateToPendingTxs} testID="go-to-pending-txs">
                {pendingUTXOTxButtonText}
              </Button>
            </ButtonGroup>
          </Box>
          <Box spacingTop={2}>
            <ButtonGroup block accessibilityLabel="dismiss-button-group">
              <Button variant="secondary" onPress={handleClose} testID="dismiss-button">
                {dismissButtonText}
              </Button>
            </ButtonGroup>
          </Box>
        </VStack>
      )}
    </VirtualTrayComponent>
  );
}

/**
 * This is a global tray, it should never be called in any place but GlobalTrayManager.
 * If you need to use it, use useUTXOPendingTxTray hook.
 */
const UTXOPendingTxTrayWithErrorBoundary = memo(function UTXOPendingTxTrayWithErrorBoundary(
  props: UTXOPendingTxTrayProps,
) {
  return (
    <ScreenBoundary errorFallback={null}>
      <UTXOPendingTxTrayContent {...props} />
    </ScreenBoundary>
  );
});

export { UTXOPendingTxTrayWithErrorBoundary as UTXOPendingTxTray };

import { useCallback, useRef } from 'react';
import { View } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
import { triggerHideAssetOptionsViewed } from 'cb-wallet-analytics/asset-management/events';
import { useIsCrossPlatformHiddenAssetsKilled } from 'cb-wallet-data/stores/AssetManagement/hooks/useIsCrossPlatformHiddenAssetsKilled';
import { abridgeName } from 'cb-wallet-data/utils/String+Core';
import { IconButton } from '@cbhq/cds-mobile/buttons';
import { Box } from '@cbhq/cds-mobile/layout';
import { TextLabel2 } from '@cbhq/cds-mobile/typography';

import {
  PopoverMenu,
  PopoverRef,
  Position,
} from ':rn/cds-wallet/components/PopoverMenu/PopoverMenu';
import { PopoverMenuItem } from ':rn/cds-wallet/components/PopoverMenu/PopoverMenuItem';

import { useHideAssetActions } from './hooks/useHideAssetActions';

export const messages = defineMessages({
  hide: {
    defaultMessage: 'Hide {assetName}',
    description: 'Label for hide button',
  },
  report: {
    defaultMessage: 'Hide & report',
    description: 'Label for report button',
  },
});

export type HideAssetOptionsProps = {
  onHide: () => void;
  onReport: () => void;
  onUndo?: () => void;
  hideReport?: boolean;
  assetName: string;
  // skips the AssetHidden screen if we are about to navigate to it
  skipAssetHiddenScreen?: boolean;
};

export function HideAssetOptions({
  onHide,
  onUndo,
  onReport,
  hideReport = false,
  assetName,
  skipAssetHiddenScreen = false,
}: HideAssetOptionsProps) {
  const { formatMessage } = useIntl();

  const { hideAssetAndNavigateAway, reportAssetAndNavigateAway } = useHideAssetActions({
    onHide,
    onUndo,
    onReport,
    assetName,
    skipAssetHiddenScreen,
  });

  const anchorRef = useRef<View | null>(null);
  const popOverRef = useRef<PopoverRef>(null);

  const isCrossPlatformHiddenAssetsKilled = useIsCrossPlatformHiddenAssetsKilled();

  const onOpenMenu = useCallback(function onOpenMenu() {
    triggerHideAssetOptionsViewed();
    popOverRef.current?.show({
      anchorRef: anchorRef.current,
      stickToPosition: Position.BOTTOM_RIGHT,
    });
  }, []);

  const onSelectHideOption = useCallback(async () => {
    popOverRef.current?.hide(hideAssetAndNavigateAway);
  }, [hideAssetAndNavigateAway]);

  const onSelectReportOption = useCallback(async () => {
    popOverRef.current?.hide(reportAssetAndNavigateAway);
  }, [reportAssetAndNavigateAway]);

  return (
    <Box background="background" ref={anchorRef}>
      <IconButton
        transparent
        name="more"
        variant="secondary"
        testID="toggle-hide-options-button"
        onPress={onOpenMenu}
      />
      <PopoverMenu key="hide-asset-options-menu" ref={popOverRef}>
        <PopoverMenuItem onPress={onSelectHideOption} icon="visibleInactive">
          <TextLabel2>
            {formatMessage(messages.hide, { assetName: abridgeName(assetName, 12) })}
          </TextLabel2>
        </PopoverMenuItem>
        {!isCrossPlatformHiddenAssetsKilled && !hideReport && (
          <PopoverMenuItem onPress={onSelectReportOption} icon="reportInactive" color="negative">
            <TextLabel2 color="negative">
              {formatMessage(messages.report, { assetName: abridgeName(assetName, 12) })}
            </TextLabel2>
          </PopoverMenuItem>
        )}
      </PopoverMenu>
    </Box>
  );
}

import { memo, useCallback, useMemo, useRef, useState } from 'react';
import { LayoutChangeEvent } from 'react-native';
import { ScrollView } from 'react-native-gesture-handler';
import {
  triggerWalletSwitcherClosed,
  useTriggerWalletSwitcherViewed,
} from 'cb-wallet-analytics/accounts';
import { useIsFeatureEnabled } from 'cb-wallet-data/FeatureManager/hooks/useIsFeatureEnabled';
import { useAccountsWithWalletGroups } from 'cb-wallet-data/stores/Accounts/hooks/useAccountsWithWalletGroups';
import { useIsMultiAccountPhase2Enabled } from 'cb-wallet-data/stores/Accounts/hooks/useIsMultiAccountPhase2Enabled';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { useWalletSwitcherCopy } from 'cb-wallet-data/stores/WalletGroups/hooks/useWalletSwitcherCopy';
import noop from 'lodash/noop';
import { Menu } from '@cbhq/cds-mobile/controls';
import { Icon } from '@cbhq/cds-mobile/icons';
import { Box, HStack } from '@cbhq/cds-mobile/layout';
import { Pressable } from '@cbhq/cds-mobile/system';
import { TextHeadline } from '@cbhq/cds-mobile/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';

import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { useDimensions } from ':rn/shared/hooks/useDimensions';
import { useStackNavigation } from ':rn/shared/hooks/useStackNavigation';

import { AccountListItem } from './AccountListItem';
import { WalletSwitcherHeader } from './WalletSwitcherHeader';

type WalletSwitcherProps = {
  toggleOff: () => void;
  isMinimal?: boolean;
};

export const WalletSwitcher = memo(function WalletSwitcher({
  toggleOff,
  isMinimal = false,
}: WalletSwitcherProps) {
  const onCloseComplete = useRef(noop);
  const isWalletGroupBalancesEnabled = useIsFeatureEnabled('wallet_group_balances');
  const { walletSwitcherTitle } = useWalletSwitcherCopy();

  useTriggerWalletSwitcherViewed({ componentType: ComponentType.tray });

  const handleCloseComplete = useCallback(
    function handleCloseComplete() {
      toggleOff();

      // This callback is expected to perform navigation.
      onCloseComplete.current();
      onCloseComplete.current = noop;

      triggerWalletSwitcherClosed({
        action: ActionType.click,
        componentType: ComponentType.tray,
      });
    },
    [toggleOff],
  );

  return (
    <Tray
      disableCapturePanGestureToDismiss
      onCloseComplete={handleCloseComplete}
      title={isWalletGroupBalancesEnabled ? undefined : walletSwitcherTitle}
      testID="multi-wallet-switcher"
    >
      {({ handleClose }) => {
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        const close = (callback: (() => void) | undefined) => {
          // We need to schedule navigation initiated within WalletMenu to occur after the Tray has closed.
          onCloseComplete.current = callback ?? noop;
          handleClose();
        };

        return (
          <WalletMenu onPressSideEffect={close} handleClose={handleClose} isMinimal={isMinimal} />
        );
      }}
    </Tray>
  );
});

type WalletMenuProps = {
  handleClose: () => void;
  onPressSideEffect?: (callback?: () => void) => void;
  isMinimal?: boolean;
};

const WalletMenu = memo(function WalletMenu({
  handleClose,
  onPressSideEffect,
  isMinimal,
}: WalletMenuProps) {
  const [itemHeight, setItemHeight] = useState<number>();
  const isMultiAccountPhase2Enabled = useIsMultiAccountPhase2Enabled();
  const accountsWithWalletGroups = useAccountsWithWalletGroups({
    onlyIncludeAccountsWithNonZeroWalletGroups: true,
  });
  const { navigate } = useStackNavigation();
  const activeWalletGroupId = useActiveWalletGroupId();
  const { manageWalletsText } = useWalletSwitcherCopy();
  const { screenHeight } = useDimensions();
  const isWalletGroupBalancesEnabled = useIsFeatureEnabled('wallet_group_balances');

  const navigateToManageWallets = useCallback(() => {
    onPressSideEffect?.(() => navigate('AddAndManageWallets'));
  }, [navigate, onPressSideEffect]);

  const handleLayout = useCallback((event: LayoutChangeEvent) => {
    setItemHeight(event.nativeEvent.layout.height);
  }, []);

  // To prevent the scrollview from taking up too much space, we need
  // to provide a max height. This should be based on the screen height
  // to ensure that the scrollview is not too tall on smaller devices.
  const scrollViewMaxHeight = useMemo(() => {
    const scrollViewHeight = screenHeight / 2;
    // Add half of the item height to indicate the content is scrollable
    const partialItemHeight = itemHeight ? itemHeight / 2 : 0;

    return scrollViewHeight + partialItemHeight;
  }, [itemHeight, screenHeight]);

  return (
    <Menu value={activeWalletGroupId}>
      {isWalletGroupBalancesEnabled && <WalletSwitcherHeader />}
      <Box maxHeight={scrollViewMaxHeight} spacingBottom={1}>
        <ScrollView
          fadingEdgeLength={100}
          showsVerticalScrollIndicator={false}
          testID="wallet-switcher-scroll-view"
        >
          {accountsWithWalletGroups.map((account, index) => (
            <AccountListItem
              key={account.id}
              isMinimal={isMinimal}
              account={account}
              handleClose={handleClose}
              onPressSideEffect={onPressSideEffect}
              onLayout={index === 0 ? handleLayout : undefined}
              showAccountDisplayName={isMultiAccountPhase2Enabled}
            />
          ))}
        </ScrollView>
        {!isMinimal && (
          <Box spacingHorizontal={3} spacingTop={2}>
            <Pressable
              background="secondary"
              onPress={navigateToManageWallets}
              borderRadius="roundedFull"
              feedback="light"
              testID="add-and-manage-wallets-cta"
            >
              <HStack
                justifyContent="space-between"
                alignItems="center"
                spacingHorizontal={3}
                spacingVertical={2}
              >
                <TextHeadline>{manageWalletsText}</TextHeadline>
                <Icon size="s" name="gear" color="foreground" />
              </HStack>
            </Pressable>
          </Box>
        )}
      </Box>
    </Menu>
  );
});

