                  {stepsTags.map((step, stepIndex) => (
                    <HStack
                      width="85%"
                      gap={3}
                      key={`step-${stepIndex + 1}`}
                      alignItems="flex-start"
                    >
                      <Box spacingTop={0.5}>
                        <Icon name={STEP_MAP[stepIndex + 1]} size="m" color="foreground" />
                      </Box>
                      <TextBody>
                        {step.map((tag, tagIndex) =>
                          getComponentForTag(tag, `step-${stepIndex + 1}-${tagIndex + 1}`),
                        )}
                      </TextBody>
                    </HStack>
                  ))}
                </VStack>
              </VStack>
            </PortalProvider>
          </Pressable>
        </ScrollView>
      </Box>
      <Divider direction="horizontal" />
      <Box width="90%" spacingTop={2} alignSelf="center">
        <Button testID="quest-help-ok" variant="primary" onPress={hideTray}>
          {formatMessage(messages.gotIt)}
        </Button>
      </Box>
    </Tray>
  );
}

