  useSendRealTimeGasFeesRefreshFailed,
  useSendRealTimeGasFeesRefreshSucceed,
} from 'cb-wallet-analytics/send/Send';
import { useTransactionRequestStepViewed } from 'cb-wallet-analytics/sign-transaction';
import { isNetwork1559Enabled } from 'cb-wallet-data/chains/AccountBased/Ethereum/config';
import { SOLANA_SYMBOL } from 'cb-wallet-data/chains/AccountBased/Solana/constants';
import { SolanaUnsignedTransaction } from 'cb-wallet-data/chains/AccountBased/Solana/models/SolanaUnsignedTransaction';
import { useIntervalForPromises } from 'cb-wallet-data/hooks/useIntervalForPromises';
import { useIsRealTimeGasFeesEnabled } from 'cb-wallet-data/hooks/useIsRealTimeGasFeesEnabled/useIsRealTimeGasFeesEnabled';
import { useTxScannerContent } from 'cb-wallet-data/hooks/useTxScannerContent/useTxScannerContent';
