/**
 * This is a general purpose component for presenting an approval modal to the user for signing a transaction.
 * It is used by walletlink and dapp browser for requesting tx approval from the user.
 * Note that dex + bridge do not use this component.
 *
 * CODE QUALITY ALERT: this component is difficult to use because it has flow-specific business logic inside. we should
 * limit usage of this component to dapp browser and walletlink until it is cleaned up.
 */
export const SignTransactionBody = memo(function SignTransactionBody(props: SignTransactionProps) {
  const {
    collectible,
    wallet,
    transaction,
    transactions,
    onDismiss,
    isModal = false,
    onPressAdjustGas,
    showAddressField,
    dappMetadata,
    destination,
    approveOperation,
    txScannerNotices,
    parsedOperations,
    isTxScannerLoading,
    analyticsData,
    dismissTrayAnalyticsEvent,
    submitPreSubmitAnalyticsEvent,
    flow,
    isRevokeOperation,
    showBalanceAmount = true,
    onRefreshGasFee,
    error,
    isTxSponsored,
  } = props;

  const { formatMessage } = useIntl();

  const is1559Enabled = useMemo(() => isNetwork1559Enabled(wallet.network), [wallet.network]);
  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useTxFeeWallet(activeWalletGroupId, transaction);
  const isRealTimeGasFeesEnabled = useIsRealTimeGasFeesEnabled(wallet);
  const shouldShowRealTimeGasFeeCountdown = useMemo(
    () => isRealTimeGasFeesEnabled && !!onRefreshGasFee,
    [isRealTimeGasFeesEnabled, onRefreshGasFee],
  );

  const [lastUpdateTime, setLastUpdateTime] = useState<Date>(new Date());
  const [isRefreshingUnsignedTx, setIsRefreshingUnsignedTx] = useState(false);
  const isSolanaSigningRequest = useMemo(
    () => wallet.blockchain.rawValue === SOLANA_SYMBOL,
    [wallet.blockchain],
  );

  const isTxPreviewWeb3Enabled = useIsTxPreviewEnabled();
  const realTimeGasFeesParams = useMemo(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      isBaseAsset: wallet.isBaseAsset,
      is1559NetworkEnabled: isNetwork1559Enabled(wallet.network),
    }),
    [wallet.blockchain.rawValue, wallet.isBaseAsset, wallet.network],
  );

  const sendGasFeeRefreshed = useSendRealTimeGasFeesRefreshSucceed(realTimeGasFeesParams);
  const sendGasFeeFailed = useSendRealTimeGasFeesRefreshFailed(realTimeGasFeesParams);

  const isTxPreviewEnabled = useMemo(
    () => (dappMetadata ? isTxPreviewWeb3Enabled : false),
    [isTxPreviewWeb3Enabled, dappMetadata],
  );
  useTransactionRequestStepViewed({ ...analyticsData, isTxPreviewEnabled });

  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx: transaction,
    feeWallet,
    flow,
    error,
    isTxSponsored,
  });

  useTransactionCostAnalytics({ wallet, transaction, is1559Enabled, transactionDetailsErrors });
  const txScannerContent = useTxScannerContent(
    parsedOperations?.preAuthorizeOperations,
    txScannerNotices,
  );

  const isUpdatedApprovalUI = useMemo(() => {
    return approveOperation && dappMetadata;
  }, [approveOperation, dappMetadata]);

  const [
    isConfirmTxVisible,
    { toggleOn: showFraudWarningConfirmationTray, toggleOff: closeFraudWarningConfirmationTray },
  ] = useToggler(false);

  const enrichedParsedOperations = useEnrichParsedOperations({
    wallet,
    transaction,
    isTxPreviewEnabled,
    isTxScannerLoading,
    parsedOperations,
    hasDappInfo: !!dappMetadata,
    collectible,
  });

  const isRevokeOperationComputed = useIsRevokeOperation(enrichedParsedOperations);
  const isRevoke = isRevokeOperation || isRevokeOperationComputed;

  const shouldShowFraudWarningConfirmationScreen = useMemo(() => {
    return Boolean(txScannerContent?.fraudWarningConfirmationText) && !isRevoke;
  }, [isRevoke, txScannerContent?.fraudWarningConfirmationText]);

  const handlePreSignAndSubmit = useCallback(
    function handlePreSignAndSubmit() {
      submitPreSubmitAnalyticsEvent?.();
      showFraudWarningConfirmationTray();
    },
    [showFraudWarningConfirmationTray, submitPreSubmitAnalyticsEvent],
  );

  const AdjustGasPresetAction = useMemo(
    () =>
      is1559Enabled && onPressAdjustGas ? (
        <Pressable
          onPress={onPressAdjustGas}
          background="transparent"
          testID="show-adjustable-gas-button"
        >
          <Icon name="gear" size="s" color="foreground" spacingStart={1} />
        </Pressable>
      ) : null,
    [is1559Enabled, onPressAdjustGas],
  );

  const refreshNetworkFeeCallback = useCallback(async () => {
    if (shouldShowRealTimeGasFeeCountdown) {
      setIsRefreshingUnsignedTx(true);
      onRefreshGasFee?.()
        .then(() => sendGasFeeRefreshed())
        .catch((err) => sendGasFeeFailed({ errorMessage: err?.message }))
        .finally(() => {
          setLastUpdateTime(new Date());
          setIsRefreshingUnsignedTx(false);
        });
    }
  }, [onRefreshGasFee, sendGasFeeFailed, sendGasFeeRefreshed, shouldShowRealTimeGasFeeCountdown]);

  useIntervalForPromises(refreshNetworkFeeCallback, { interval: 31000 });

  const hideTotalCost = useHideTotalCost({
    wallet,
    isTxScannerLoading,
    isTxPreviewEnabled,
    parsedOperations,
  });

  const { confirmAndSubmit, isSubmissionLoading } = useConfirmSignAndSubmit({
    ...props,
    shouldShowFraudWarningConfirmationScreen,
    txScannerContent,
    closeFraudWarningConfirmationTray,
    shouldSubmit: props.shouldSubmit,
    isTxSponsored,
    wallet,
  });

  const isSubmitLoading = useMemo(() => {
    return isSubmissionLoading || isRefreshingUnsignedTx;
  }, [isSubmissionLoading, isRefreshingUnsignedTx]);

  const transactionCost = useTransactionCost({
    wallet,
    transaction,
    transactions,
    hideTotalCost,
  });

  const signTransactionRowDetails: SignTransactionRowDetails = useMemo(() => {
    const toAddressItem = {
      type: destination?.type,
      value: destination?.type === 'address' ? transaction.recipientAddress : destination?.label,
      address: transaction.recipientAddress,
    };
    return {
      transactionCost,
      wallet,
      AdjustGasPresetAction,
      showAddressField: showAddressField || isTxPreviewEnabled,
      unsignedTx: transaction,
      isTxScannerLoading,
      isTxSponsored,
      parsedOperations: enrichedParsedOperations,
      txScannerContent,
      toAddressItem: isTxPreviewEnabled ? toAddressItem : undefined,
      lastUpdateTime: shouldShowRealTimeGasFeeCountdown ? lastUpdateTime : undefined,
      isPageLoading: isRefreshingUnsignedTx,
      transactionError: transactionDetailsErrors,
    };
  }, [
    destination?.type,
    destination?.label,
    transaction,
    transactionCost,
    wallet,
    AdjustGasPresetAction,
    showAddressField,
    isTxPreviewEnabled,
    isTxScannerLoading,
    enrichedParsedOperations,
    txScannerContent,
    shouldShowRealTimeGasFeeCountdown,
    lastUpdateTime,
    isRefreshingUnsignedTx,
    transactionDetailsErrors,
    isTxSponsored,
  ]);

  const detailRows = useTransactionDetailRowItems(signTransactionRowDetails);

  const transactionInstructions = useMemo(() => {
    if (!isSolanaSigningRequest) return undefined;

    return ((transactions ?? [transaction]) as SolanaUnsignedTransaction[]).flatMap((tx) => {
      return tx.dappInstructionMetaData ?? [];
    });
  }, [transactions, transaction, isSolanaSigningRequest]);

  const onDismissView = useCallback(() => {
    if (onDismiss) {
      // TODO: Why do we have two callbacks here? one should suffice
      dismissTrayAnalyticsEvent?.();
      onDismiss();
    }
  }, [dismissTrayAnalyticsEvent, onDismiss]);

  return (
    <>
      {(!isConfirmTxVisible || isModal) && (
        <Box flexGrow={1} flexShrink={1}>
          {isModal && !isSolanaSigningRequest && (
            <ModalHeader
              title={
                !isTxPreviewEnabled || !dappMetadata ? formatMessage(messages.confirmRequest) : ''
              }
            />
          )}

          <ScrollView>
            <VStack key="tx-request-header">
              {!!isTxPreviewEnabled && !!dappMetadata && (
                <DappTransactionRequestHeader
                  dappMetadata={dappMetadata}
                  network={wallet.network}
                  isRevokeOperation={isRevoke}
                />
              )}

              <SignTransactionTopSection
                {...props}
                isTxPreviewEnabled={isTxPreviewEnabled}
                isRevoke={isRevoke}
                isUpdatedApprovalUI={isUpdatedApprovalUI}
                enrichedParsedOperations={enrichedParsedOperations}
                showBalanceAmount={showBalanceAmount}
              />
            </VStack>
            <VStack spacingHorizontal={3} spacingTop={1} key="tx-details">
              <TransactionDetails transactionDetailRowItems={detailRows} />
              <SolanaAdvancedTransactionDetails instructions={transactionInstructions} />
              <Spacer />
            </VStack>
          </ScrollView>

          <VStack
            flexShrink={0}
            borderedTop
            spacingTop={1}
            spacingHorizontal={2}
            background="background"
          >
            {transactionDetailsErrors && (
              <HStack spacingVertical={1} spacingBottom={2}>
                <VStack justifyContent="center">
                  <Icon name="warning" size="s" color="negative" />
                </VStack>
                <VStack justifyContent="center">
                  <TextLegal spacingStart={1}>{transactionDetailsErrors.message}</TextLegal>
                </VStack>
              </HStack>
            )}
            <ButtonGroup accessibilityLabel={formatMessage(messages.ctaGroup)} block>
              {onDismiss && (
                <Button
                  variant="secondary"
                  disabled={isSubmitLoading}
                  onPress={onDismissView}
                  testID="sign-transaction-cancel-button"
                >
                  {formatMessage(messages.cancel)}
                </Button>
              )}
              <Button
                loading={isSubmitLoading}
                disabled={transactionDetailsErrors?.isDisabled}
                onPress={
                  shouldShowFraudWarningConfirmationScreen
                    ? handlePreSignAndSubmit
                    : confirmAndSubmit
                }
                testID="sign-transaction-confirm-button"
              >
                {formatMessage(messages.confirmSendButton)}
              </Button>
            </ButtonGroup>
          </VStack>
        </Box>
      )}

      {shouldShowFraudWarningConfirmationScreen && (
        <FraudWarningConfirmationTray
          analyticsData={analyticsData}
          fraudWarningConfirmationText={txScannerContent!.fraudWarningConfirmationText!}
          isConfirmTxVisible={isConfirmTxVisible}
          toggleOff={closeFraudWarningConfirmationTray}
          onDismiss={onDismiss}
          dismissTrayAnalyticsEvent={dismissTrayAnalyticsEvent}
          handleSignAndSubmitStandalone={confirmAndSubmit}
          loading={isSubmitLoading}
          transaction={transaction}
        />
      )}
    </>
  );
});

import { useCallback, useMemo } from 'react';
