  },
  onrampButtonText: {
    defaultMessage: 'Buy {cryptoSymbol}',
    description: 'Button text for tray when user do not have enough native asset',
  },
});

export type TopUpDialogProps = {
  /**
   * BigInt number representing fiat amount required to proceed with the transaction.
   * This param is also used to prefill CBPay amount input
   */
  amountNeeded?: bigint;

  /**
   * Optional wallet to override the network base wallet
   */
  wallet: Wallet;

  /**
   * Optional callback function for when the user choose to buy the given token
   */
  onPressBuyButton?: () => void;

  /**
   * Optional tray text to override the network fee tray text
   */
  trayTextOverride?: string;

  /**
   * Flow that is invoking this component, for analytics purposes
   */
  flow?: string;
};

const LEARN_MORE_LINK_HIT_SLOP = 20;
const DRAWER_OUT_DURATION_OFFSET = 100;
const DRAWER_OUT_ANIMATION_DURATION =
  durations[drawerAnimationDefaultDuration] + DRAWER_OUT_DURATION_OFFSET;

const OUTER_SPACING = { spacingHorizontal: 0 } as CellSpacing;

export function TopUpDialog({
  amountNeeded,
  wallet,
  trayTextOverride,
  onPressBuyButton,
  flow,
}: TopUpDialogProps) {
  const { formatMessage } = useIntl();
  const network = wallet.network;
  const onrampEligibility = useOnrampEligibility();

  const currencyFormatter = useCurrencyFormatter();

  const fiatAmount = currencyFormatter
    .fiatValue(
      wallet?.currencyCode,
      wallet?.decimals,
      amountNeeded ?? 0n,
      wallet?.contractAddress,
      wallet?.network,
      wallet?.blockchain,
    )
    ?.toNumber();

  const fiatAmountNeededNumber = useMemo(() => Number(fiatAmount?.toFixed(2) ?? 0), [fiatAmount]);

  const fiatAmountNeededString = currencyFormatter.formatToFiat(
    wallet.currencyCode,
    wallet.decimals,
    amountNeeded,
    false,
    wallet.contractAddress,
    wallet.network,
    wallet.blockchain,
    true,
    false,
    true,
  );

  const isTopUpV2Enabled = useIsFeatureEnabled('top_up_v2');
  const shouldShowRemainingAmount = !!fiatAmountNeededString && isTopUpV2Enabled;

  const cryptoSymbol = wallet.currencyCode.code;
  const displayName = wallet.displayName;

  const displayedWallet = wallet;

  if (!network || !displayName || !displayedWallet)
    throw Error('Invalid network or base asset wallet provided to TopUpDialog');

  const launchBuyFlow = useLaunchBuyFlow();

  const isBuyableWithCBPay = useMemo(() => {
    const networkIdentifier = getCBPayIdentifierForNetwork(network, wallet?.currencyCode.code);
    if (!networkIdentifier) return false;

    return SUPPORTED_BLOCKCHAINS.map((chain) => chain.currencyCode.toString()).includes(
      networkIdentifier,
    );
  }, [network, wallet?.currencyCode.code]);

  const eventParams = useMemo(
    () => ({
      asset: displayName,
      isBuyableWithCBPay,
      network: wallet.network.asChain()?.displayName ?? wallet.currencyCode.rawValue,
      flow,
    }),
    [displayName, flow, isBuyableWithCBPay, wallet.currencyCode.rawValue, wallet.network],
  );

  const trayViewed = useSendTopUpBaseAssetTrayViewed(eventParams);

  const sendTopUpBaseAssetButtonClicked = useSendTopUpBaseAssetButtonClicked(eventParams);

  const topUpAmount = useMemo(() => {
    if (!fiatAmountNeededNumber) return 0;

    if (wallet.isBaseAsset) {
      let amount = 10 * Math.ceil(fiatAmountNeededNumber / 10);

      if (fiatAmountNeededNumber >= 1) {
        amount *= 1.1;
      }

      return amount;
    }
    return fiatAmountNeededNumber;
  }, [fiatAmountNeededNumber, wallet]);

  const navigateToBuy = useCallback(
    function navigateToBuy() {
      sendTopUpBaseAssetButtonClicked();

      launchBuyFlow({
        wallet: displayedWallet,
        presetFiatAmount: topUpAmount,
      });
    },
    [sendTopUpBaseAssetButtonClicked, launchBuyFlow, displayedWallet, topUpAmount],
  );

  const onBuyPress = useCallback(() => {
    if (onPressBuyButton) {
      onPressBuyButton();
      setTimeout(navigateToBuy, DRAWER_OUT_ANIMATION_DURATION);
      return;
    }

    navigateToBuy();
  }, [navigateToBuy, onPressBuyButton]);

  useOnMount(trayViewed);

  const handleLearnMorePress = useCallback(() => {
    Linking.openURL(GAS_FEE_LEARN_MORE_LINK);
  }, []);

  const topUpDialogV1 = useMemo(() => {
    return (
      <VStack spacingHorizontal={3} testID="top-up-dialog-v1">
        <TextTitle3 spacingVertical={1}>{formatMessage(messages.trayTitle)}</TextTitle3>
        <TextBody color="foregroundMuted" spacingBottom={2}>
          {trayTextOverride ?? formatMessage(messages.trayText1)}
        </TextBody>
        <Box
          alignItems="center"
          flexDirection="row"
          borderRadius="rounded"
          background="backgroundAlternate"
        >
          <TextBody spacingStart={3}>{formatMessage(messages.youNeed)}</TextBody>
          <Box maxWidth="80%">
            <ListCell
              testID={`base-asset-wallet-${displayedWallet.currencyCode.rawValue}-${
                displayedWallet.network.asChain()?.chainId
              }`}
              disabled
              title={<TextHeadline>{displayedWallet.displayName}</TextHeadline>}
              disableMultilineTitle
              description={
                displayedWallet.network.asChain()?.displayName
                  ? `${displayedWallet.network.asChain()?.displayName} network`
                  : ''
              }
              media={
                <AssetIcon
                  network={network}
                  iconUrl={displayedWallet.imageURL}
                  currencyCode={displayedWallet.currencyCode.code}
                  showNetworkIcon
                />
              }
              priority="end"
              multiline={false}
              compact
              innerSpacing={spacingHorizontal}
            />
          </Box>
        </Box>
        <HStack width="100%" flexWrap="wrap">
          <TextBody color="foregroundMuted" spacingTop={2}>
            {formatMessage(messages.trayText2)}{' '}
          </TextBody>
          <Pressable
            testID="learn-more-link"
            onPress={handleLearnMorePress}
            background="transparent"
            hitSlop={LEARN_MORE_LINK_HIT_SLOP}
          >
            <TextBody color="primary">{formatMessage(messages.learnMore)}</TextBody>
          </Pressable>
        </HStack>

        {onrampEligibility?.isSupported && isBuyableWithCBPay && (
          <Box spacingTop={2}>
            <ButtonGroup block accessibilityLabel="onramp-button-group">
              <Button onPress={onBuyPress} testID="onramp-button">
                {formatMessage(messages.onrampButtonText, { cryptoSymbol })}
              </Button>
            </ButtonGroup>
          </Box>
        )}
      </VStack>
    );
  }, [
    cryptoSymbol,
    displayedWallet.currencyCode.code,
    displayedWallet.currencyCode.rawValue,
    displayedWallet.displayName,
    displayedWallet.imageURL,
    displayedWallet.network,
    formatMessage,
    handleLearnMorePress,
    isBuyableWithCBPay,
    network,
    onBuyPress,
    onrampEligibility?.isSupported,
    trayTextOverride,
  ]);

  const topUpDialogV2 = useMemo(() => {
    return (
      <VStack spacingHorizontal={3} testID="top-up-dialog-v2">
        <TextTitle3 spacingTop={1}>{formatMessage(messages.trayTitle)}</TextTitle3>
        <Spacer vertical={2} />
        <TextBody color="foregroundMuted" testID="top-up-dialog-v2-description">
          {formatMessage(messages.trayDescription, {
            fiatAmount: <TextBody color="foreground">{fiatAmountNeededString}</TextBody>,
            cryptoSymbol: wallet.currencyCode.code,
            networkName: network.asChain()?.displayName ?? wallet.displayName,
            appendedMessage: wallet.isBaseAsset
              ? formatMessage(messages.feeIncluded)
              : formatMessage(messages.feeNotIncluded),
          })}
        </TextBody>
        <ListCell
          testID="top-up-dialog-asset-cell"
          disabled
          detail={<TextHeadline>{fiatAmountNeededString}</TextHeadline>}
          title={wallet.displayName}
          media={
            <AssetIcon
              network={network}
              iconUrl={wallet.imageURL}
              currencyCode={wallet.currencyCode.code}
              showNetworkIcon
            />
          }
          outerSpacing={OUTER_SPACING}
        />
        {onrampEligibility?.isSupported && isBuyableWithCBPay ? (
          <Box spacingTop={1}>
            <ButtonGroup block accessibilityLabel="onramp-button-group">
              <Button onPress={onBuyPress} testID="onramp-button">
                {formatMessage(messages.onrampButtonText, { cryptoSymbol })}
              </Button>
            </ButtonGroup>
          </Box>
        ) : null}
      </VStack>
    );
  }, [
    cryptoSymbol,
    fiatAmountNeededString,
    formatMessage,
    isBuyableWithCBPay,
    network,
    onBuyPress,
    onrampEligibility?.isSupported,
    wallet.currencyCode.code,
    wallet.displayName,
    wallet.imageURL,
    wallet.isBaseAsset,
  ]);

  return shouldShowRemainingAmount ? topUpDialogV2 : topUpDialogV1;
}

