export type AddChainProps = ConfirmationDialogProps<
  AddEthereumChainMessage,
  { onSuccess: (chainId: string) => void }
>;

export const AddChain = memo(function AddChain({
  data,
  onDismiss,
  onConfirm,
  metadata,
  onSuccess,
}: AddChainProps) {
  const { lineHeight: descriptionHeight } = useTypographyStyles('body', false);
  const { screenHeight } = useDimensions();
  const saveCustomNetwork = useSaveCustomNetwork(true);
  const toast = useRateLimitedToast({});

  const [isSubmitting, setIsSubmitting] = useState(false);
  const { formatMessage } = useIntl();
  const { chainId, chainName, nativeCurrency, rpcUrls, blockExplorerUrls, iconUrls } =
    data.request.params;
  const { dappUrl } = metadata;

  const isApprovable: boolean = nativeCurrency?.symbol !== undefined;

  const addChain = useCallback(
    async function addChain() {
      setIsSubmitting(true);
      try {
        await saveCustomNetwork({
          id: chainId,
          chainName: chainName ?? chainId,
          rpcUrls,
          chainId,
          nativeCurrency: {
            name: nativeCurrency?.name ?? '',
            symbol: nativeCurrency?.symbol ?? '',
            decimals: nativeCurrency?.decimals ?? 18,
          },
          blockExplorerUrls: blockExplorerUrls ?? [''],
          iconUrls: iconUrls ?? [''],
        });
        onConfirm({
          id: data.id,
          result: {
            isApproved: true,
            rpcUrl: rpcUrls[0],
          },
        });
        onSuccess(chainId);
      } catch (err: ErrorOrAny) {
        const errorMessage = err?.message;
        toast.show(formatMessage(messages.failure), { bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET });
        triggerBrowserAddEthereumChainFailed({ chainId, errorMessage });
        setIsSubmitting(false);
      }
    },
    [
      saveCustomNetwork,
      chainId,
      chainName,
      rpcUrls,
      nativeCurrency?.name,
      nativeCurrency?.symbol,
      nativeCurrency?.decimals,
      blockExplorerUrls,
      iconUrls,
      onConfirm,
      data.id,
      onSuccess,
      toast,
      formatMessage,
    ],
  );

  return (
    <VStack spacingHorizontal={2} spacingBottom={3} gap={3}>
      <TextHeadline align="center">
        {formatMessage(messages.switchNetwork, {
          network: chainName ?? 'Unknown',
        })}
      </TextHeadline>
      <ListCell
        title={chainName}
        description={
          <HStack height={descriptionHeight}>
            <Box flexShrink={1}>
              <TextBody color="foregroundMuted" numberOfLines={1} ellipsize="tail">
                {rpcUrls[0]}
              </TextBody>
            </Box>
          </HStack>
        }
        media={
          <RemoteFaviconImage
            iconUrl={iconUrls?.[0]}
            fallbackText={nativeCurrency?.symbol}
            url={blockExplorerUrls?.[0]}
            size={40}
          />
        }
        compact
        innerSpacing={chainHeaderInnerCellSpacing}
        outerSpacing={chainHeaderOuterCellSpacing}
      />
      <Disclaimer message={formatMessage(messages.beCarefulPrompt)} />
      <Box height={screenHeight / 4} spacingHorizontal={1}>
        <ScrollView fadingEdgeLength={200} persistentScrollbar showsVerticalScrollIndicator>
          <PressableOpacity noScaleOnPress>
            <VStack offsetTop={1} background="background">
              <ListCell
                title={formatMessage(messages.networkNameTitle)}
                description={chainName ?? formatMessage(messages.notAvailable)}
                testID="network-name"
                compact
                outerSpacing={chainDetailCellSpacing}
              />
              <ListCell
                title={formatMessage(messages.networkURLTitle)}
                description={rpcUrls[0]}
                testID="network-url"
                compact
                outerSpacing={chainDetailCellSpacing}
              />
              <ListCell
                title={formatMessage(messages.requestedByTitle)}
                description={dappUrl}
                compact
                outerSpacing={chainDetailCellSpacing}
              />
              <ListCell
                title={formatMessage(messages.chainIdTitle)}
                description={chainId}
                testID="chain-id"
                compact
                outerSpacing={chainDetailCellSpacing}
              />
              <ListCell
                title={formatMessage(messages.nativeCurrencyTitle)}
                description={
                  nativeCurrency?.symbol ?? (
                    <HStack alignItems="center">
                      <TextBody>{formatMessage(messages.notAvailable)}</TextBody>
                      <Icon name="error" size="s" spacingStart={0.5} color="negative" />
                    </HStack>
                  )
                }
                compact
                outerSpacing={chainDetailCellSpacing}
              />
              <ListCell
                title={formatMessage(messages.blockExplorerTitle)}
                description={blockExplorerUrls?.[0] ?? formatMessage(messages.notAvailable)}
                compact
                outerSpacing={chainDetailCellSpacing}
              />
            </VStack>
          </PressableOpacity>
        </ScrollView>
      </Box>
      <ButtonGroup block accessibilityLabel={formatMessage(messages.authorizationButtonGroup)}>
        <Button
          variant="secondary"
          onPress={onDismiss}
          disabled={isSubmitting}
          testID="add-chain-deny-button"
        >
          {formatMessage(messages.denyActionButton)}
        </Button>
        <Button
          variant="primary"
          onPress={addChain}
          loading={isSubmitting}
          disabled={!isApprovable}
          testID="add-chain-confirm-button"
        >
          {formatMessage(messages.switchNetworkButton)}
        </Button>
      </ButtonGroup>
    </VStack>
  );
});

