export type SignMessageProps = ConfirmationDialogProps<
  SignEthereumMessageMessage | SignSolanaMessageMessage,
  {
    titleText?: string;
    confirmButtonText?: string;
    evmWalletIndex: bigint | undefined;
    solWalletIndex?: bigint | undefined;
    evmAddress: string | undefined;
    solAddress?: string | undefined;
    chainId?: number;
  }
>;

export const SignMessage = memo(function SignMessage({
  data,
  onDismiss,
  onConfirm,
  metadata,
  titleText,
  confirmButtonText,
  evmWalletIndex: activeEvmWalletIndex,
  solWalletIndex: activeSolWalletIndex,
  evmAddress: activeEvmAddress,
  solAddress: activeSolAddress,
  chainId,
}: SignMessageProps) {
  const originalRequest = data.request;
  const isEVMSigningRequest = isEthereumWeb3Request(originalRequest);
  const isMessageScannerEnabled = useIsFeatureEnabled('message_scanner');
  const accountId = useAccountIdFromWeb3Request(originalRequest);
  const activeBlockchain = isEVMSigningRequest ? ETHEREUM_SYMBOL : SOLANA_SYMBOL;
  const { screenHeight } = useDimensions();
  const handleUnlock = useHandleUnlock();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { formatMessage } = useIntl();

  const { profile } = useUserProfile(isEVMSigningRequest ? activeEvmAddress : undefined);
  const nftAvatarMetadata = useNftAvatarMetadata(getPrimaryDomainAvatar(profile));
  const defaultAvatarIdx = useDefaultAvatarIdxByAddress(
    isEVMSigningRequest ? activeEvmAddress : undefined,
  );
  const { messagePreviewDisclaimer } = useTxPreviewMessages(ScannerService.MESSAGE_SCANNER);

  // dappHostname is safely extracted from the full URL in Web3Provider
  const { dappHostname } = metadata;

  const activeAddress = useMemo(
    () => (isEVMSigningRequest ? activeEvmAddress : activeSolAddress),
    [isEVMSigningRequest, activeEvmAddress, activeSolAddress],
  );

  const activeWalletIndex = useMemo(
    () => (isEVMSigningRequest ? activeEvmWalletIndex : activeSolWalletIndex),
    [isEVMSigningRequest, activeEvmWalletIndex, activeSolWalletIndex],
  );

  const network = useMemo(() => {
    return Network.fromChainId({
      chainPrefix: isEVMSigningRequest ? ETHEREUM_PREFIX : SOLANA_PREFIX,
      chainId: BigInt(chainId ?? 1),
    });
  }, [chainId, isEVMSigningRequest]);

  const sanitizedRequest = useSanitizeMessageSigningRequest(originalRequest, dappHostname);

  const { sanitizedTypedDataJson, readableMessage, isSpecialMessage, addPrefix } = useMemo(() => {
    const message = sanitizedRequest.params.message;
    const { addPrefix: addPrefixParam, typedDataJson } = (
      sanitizedRequest as Web3Request<'signEthereumMessage'>
    ).params;

    return {
      addPrefix: addPrefixParam,
      sanitizedTypedDataJson: isEVMSigningRequest ? typedDataJson : null,
      readableMessage: addPrefixParam ? hexToUtf8(message) : message,
      isSpecialMessage: !addPrefixParam && !typedDataJson && isEVMSigningRequest,
    };
  }, [sanitizedRequest, isEVMSigningRequest]);

  const analyticsData = useMemo(() => {
    const parsedJsonData = sanitizedTypedDataJson ? JSON.parse(sanitizedTypedDataJson) : null;
    return {
      dappURL: dappHostname,
      request: originalRequest.method,
      blockchain: activeBlockchain,
      isMessageScannerEnabled,
      eip712DomainName: parsedJsonData?.domain?.name ?? '',
      eip712DomainVersion: parsedJsonData?.domain?.version ?? '',
      contractAddress: parsedJsonData?.domain?.verifyingContract ?? '',
      chainId: parsedJsonData?.domain?.chainId ?? '',
      eip712OfferType: parsedJsonData ? getOfferType(parsedJsonData) : '',
    };
  }, [
    sanitizedTypedDataJson,
    dappHostname,
    originalRequest.method,
    activeBlockchain,
    isMessageScannerEnabled,
  ]);

  useTriggerWeb3SignMessageRequestViewed(analyticsData);

  const activeAddressTruncated = getTruncatedAddress(activeAddress ?? '');
  const activeAddressDomain = useFetchDomain(activeAddress ?? '');

  const activeAddressLabel = useMemo(
    () => <TextLabel2>{activeAddressDomain || activeAddressTruncated}</TextLabel2>,
    [activeAddressDomain, activeAddressTruncated],
  );

  const signMessageStandalone = useBuildDappMessageSignature({
    request: sanitizedRequest,
    activeAddress,
    activeWalletIndex,
    accountId,
  });

  const onSignMessage = useCallback(
    async function onSignMessage() {
      setIsSubmitting(true);
      triggerWeb3SignMessageClicked(analyticsData);

      const signMessage = signMessageStandalone; // TODO: accountType === AccountType.SCW ? signMessageSCW : signMessageStandalone

      const signMessageWithErrorHandling = async () => {
        return signMessage()
          .then((signature: Buffer) => {
            if (isEVMSigningRequest) {
              const result = ensureHexString(hexFromBuffer(signature), true);
              onConfirm({ id: data.id, result });
            } else {
              onConfirm({
                id: data.id,
                result: {
                  action: SolanaWeb3Response.signMessageSuccess,
                  signature: [...new Uint8Array(signature)],
                },
              });
            }
          })
          .catch((signError: Error) => {
            cbReportError({
              context: 'transactions',
              error: signError,
              severity: 'error',
              isHandled: true,
            });
            triggerWeb3SignMessageError({
              ...analyticsData,
              errorName: signError.name,
              errorMessage: signError.message,
            });
            onDismiss();
          });
      };

      await handleUnlock({
        accountId,
        unlockSuccess: signMessageWithErrorHandling,
        unlockError: (error) => {
          if (error) {
            throw new Error('Missing recovery phrase');
          }
          onDismiss();
        },
      });
    },
    [
      analyticsData,
      accountId,
      signMessageStandalone,
      handleUnlock,
      isEVMSigningRequest,
      onConfirm,
      data.id,
      onDismiss,
    ],
  );

  const onCancel = useCallback(
    function onCancel() {
      triggerWeb3CancelMessageClicked(analyticsData);
      onDismiss();
    },
    [analyticsData, onDismiss],
  );

  const wrapInnerWarningText = useCallback((variableAmount: string) => {
    return <TextLabel2 color="primary">{variableAmount}</TextLabel2>;
  }, []);

  const {
    messageScannerLoadStartTime,
    resetLoadTimer,
    messageScannerData,
    warningMessage,
    isMessageScannerLoading,
    isMessageScannerError,
  } = useMessageScanner({
    signerAddress: activeAddress,
    request: originalRequest,
    dappHostname,
    typedDataJson: sanitizedTypedDataJson,
    addPrefix,
    analyticsData,
    wrapInnerWarningText,
    chainId,
  });

  const hasParsedOperations =
    !!messageScannerData &&
    (messageScannerData.preAuthorizeOperations.length > 0 ||
      messageScannerData.assetChangeOperations.length > 0);

  const signatureRequestedTitle = isSpecialMessage
    ? formatMessage(messages.specialSignatureRequest)
    : formatMessage(messages.signatureRequested);

  const showMessageScannerPreview =
    isMessageScannerEnabled &&
    !isMessageScannerLoading &&
    hasParsedOperations &&
    !isMessageScannerError;

  const showMessageScannerError = isMessageScannerEnabled && isMessageScannerError;
  const showMessageScannerFallback = isMessageScannerEnabled && isMessageScannerLoading;

  const showFullMessageContent =
    !isMessageScannerEnabled ||
    (!isMessageScannerLoading && (!hasParsedOperations || isMessageScannerError));

  const messageContent = useMemo(() => {
    return (
      <Box maxHeight={screenHeight / 4}>
        <ScrollView
          showsHorizontalScrollIndicator={false}
          persistentScrollbar
          showsVerticalScrollIndicator
          nestedScrollEnabled
        >
          <PressableOpacity noScaleOnPress>
            <Box flexGrow={1} background="secondary">
              <TextLabel2 spacingVertical={2} spacingHorizontal={2} color="foregroundMuted">
                {sanitizedTypedDataJson || readableMessage}
              </TextLabel2>
            </Box>
          </PressableOpacity>
        </ScrollView>
      </Box>
    );
  }, [readableMessage, sanitizedTypedDataJson, screenHeight]);

  const walletGroup = useWalletGroupForEthAddress({ ethAddress: activeAddress ?? '' });

  return (
    <VStack spacingHorizontal={0} spacingBottom={0} gap={0}>
      <VStack gap={1}>
        <HStack gap={1} spacingHorizontal={1} spacingBottom={1}>
          <DynamicPfp
            alt="Signing avatar"
            nftAvatarMetadata={nftAvatarMetadata}
            src={profile?.avatar}
            idx={defaultAvatarIdx}
            size="m"
            walletGroup={walletGroup}
          />
          <TextLabel2 color="foregroundMuted" testID="signing-with-label">
            {formatMessage(messages.signingWith, { address: activeAddressLabel })}
          </TextLabel2>
        </HStack>
