export type FraudWarningConfirmationTrayProps = {
  fraudWarningConfirmationText: string;
  isConfirmTxVisible: boolean;
  toggleOff: () => void;
  onDismiss?: () => void;
  dismissTrayAnalyticsEvent?: () => void;
  handleSignAndSubmitStandalone: () => void;
  loading: boolean;
  transaction: UnsignedTx;
  dappURL?: string;
  analyticsData: Web3EventProps;
};

const messages = defineMessages({
  title: {
    defaultMessage: 'Fraud warning',
    description: 'Title for the sign out confirmation page',
  },
  dynamicContent: {
    defaultMessage: 'dynamic content.',
    description: 'dynamicContent',
  },
  allowAndContinue: {
    defaultMessage: 'Allow and continue',
    description: 'Allow and continue.',
  },
  cancel: {
    defaultMessage: 'Cancel',
    description: 'Cancel button.',
  },
});

/**
 * A tray component that is shown when the user is about to engage with a transaction
 * that is likely fraudulent.
 *
 * @param handlePrimaryButtonPress when user clicks confirm
 * @param handleCancelButtonPress when user clicks cancel
 * @param isLoading whether the confirm button should show as loading or not
 * @param handleBackButton when user navigates back from this confirmation tray
 * @param warningContent the warning message to display
 * @param analyticsData the analytics context for this event
 */
export const FraudWarningConfirmationTray = memo(function FraudWarningConfirmationTray({
  fraudWarningConfirmationText,
  isConfirmTxVisible,
  toggleOff,
  handleSignAndSubmitStandalone,
  loading,
  onDismiss,
  dismissTrayAnalyticsEvent,
  analyticsData,
}: FraudWarningConfirmationTrayProps) {
  const { formatMessage } = useIntl();

  useFraudWarningConfirmationPopUpViewed(analyticsData);

  const onDismissFraudWarningConfirmationTray = useCallback(
    function onDismissFraudWarningConfirmationTray() {
      if (onDismiss) {
        dismissTrayAnalyticsEvent?.();
        onDismiss();
      } else {
        toggleOff();
      }
    },
    [toggleOff, dismissTrayAnalyticsEvent, onDismiss],
  );

  return (
    <>
      {Boolean(isConfirmTxVisible) && (
        <Tray
          onCloseComplete={toggleOff}
          disableCapturePanGestureToDismiss
          testID="confirm-sign-transaction-tray"
        >
          <ScrollView>
            <Pressable>
              <PortalProvider>
                <VStack flexGrow={1} spacingTop={2} spacingBottom={1} spacingHorizontal={4}>
                  <VStack alignItems="center" spacingBottom={6}>
                    <BigYellowWarning />
                    <TextTitle3 testID="cloud-backup-tray-title" spacingBottom={2}>
                      {formatMessage(messages.title)}
                    </TextTitle3>
                    <TextBody
                      testID="cloud-backup-tray-body"
                      color="foregroundMuted"
                      align="center"
                    >
                      {fraudWarningConfirmationText}
                    </TextBody>
                  </VStack>
                  <VStack gap={2}>
                    {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
                    {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
                    <Button
                      testID="double-confirmation-sign-transaction-cancel-button"
                      onPress={onDismissFraudWarningConfirmationTray}
                      variant="primary"
                      disabled={loading}
                    >
                      {formatMessage(messages.cancel)}
                    </Button>
                    {/* FIXME: Adjacent buttons must be rendered inside of a ButtonGroup component */}
                    {/* eslint-disable-next-line wallet/no-buttons-without-button-groups */}
                    <Button
                      testID="double-confirmation-sign-transaction-confirm-tray-button"
                      onPress={handleSignAndSubmitStandalone}
                      variant="negative"
                      loading={loading}
                    >
                      {formatMessage(messages.allowAndContinue)}
                    </Button>
                  </VStack>
                </VStack>
              </PortalProvider>
            </Pressable>
          </ScrollView>
        </Tray>
      )}
    </>
  );
});

