export const WatchAsset = memo(function WatchAsset({
  data,
  onDismiss,
  onConfirm,
}: AuthorizationRequestProps) {
  const toast = useRateLimitedToast({});
  const [authorizing, setAuthorizing] = useState(false);
  const { formatMessage } = useIntl();
  const activeWalletGroupId = useActiveWalletGroupId();
  const addCustomEthToken = useAddCustomEthToken(activeWalletGroupId);
  const customNetworks = useCustomNetworkArgs();

  const { options, chainId } = data.request.params;
  const { address, symbol, decimals, image } = options;
  const source = useMemo(() => ({ uri: image }), [image]);

  if (!chainId) {
    throw new Error('Received a watch asset request without chainId, should never happen');
  }

  const customNetwork = useMemo(
    () =>
      customNetworks.find(
        ({ network }) => network && network.asChain()?.chainId === parseInt(chainId.toString(), 10),
      ),
    [customNetworks, chainId],
  );

  const ethereumChain = useMemo(() => {
    return !customNetwork && Network.fromChainId({ chainId: BigInt(chainId) });
  }, [customNetwork, chainId]);

  const allowAuthorize = useCallback(
    async function allowAuthorize() {
      setAuthorizing(true);
      try {
        const currencyCode = new CurrencyCode(symbol ?? '');
        if (customNetwork) {
          await addCustomEthToken(currencyCode, address, customNetwork, BigInt(decimals ?? 18));
        }
        onConfirm({
          id: data.id,
          result: true,
        });
      } catch (err: ErrorOrAny) {
        toast.show(formatMessage(messages.customTokenFailed), {
          bottomOffset: DEFAULT_TOAST_BOTTOM_OFFSET,
        });
      }
    },
    [
      addCustomEthToken,
      address,
      customNetwork,
      data.id,
      decimals,
      formatMessage,
      onConfirm,
      symbol,
      toast,
    ],
  );

  const denyAuthorize = useCallback(() => {
    onConfirm({
      id: data.id,
      result: false,
    });
  }, [data.id, onConfirm]);

  if (ethereumChain) {
    return (
      <AllowlistedNetworkView
        onDismiss={onDismiss}
        symbol={options.symbol}
        chainName={ethereumChain.asChain()?.displayName}
      />
    );
  }

  return (
    <VStack spacing={3}>
      {options.image && (
        <HStack justifyContent="center" alignItems="center" spacingBottom={2}>
          <RemoteImage
            resizeMode="cover"
            accessibilityLabel={formatMessage(messages.dappLogoAlt)}
            width={80}
            height={80}
            source={source}
          />
        </HStack>
      )}
      <VStack gap={2} spacingBottom={3}>
