type Handler = (ev: { url: string; isRetriggered?: boolean }) => void;
type MockLinkingType = React.ComponentProps<typeof DeepLinkProvider>['Linking'] & {
  emit: (eventType: 'url', ev: Parameters<Handler>[0]) => void;
};

const listeners: { url: Handler[] } = {
  url: [],
};

const MockLinking: MockLinkingType = {
  addEventListener: (type, handler) => {
    listeners.url.push(handler);
    return {
      remove: () => {
        const index = listeners.url.indexOf(handler);
        if (index !== -1) {
          listeners.url.splice(index, 1);
        }
      },
    };
  },
  getInitialURL: async () => null,
  emit: (eventType: 'url', ev: Parameters<Handler>[0]) => {
    listeners[eventType].forEach((listener) => listener(ev));
  },
};

