type EthereumActionRequestComponentProps = {
  action: EthereumRequestAction;
  message: RequestMessage;
  session: Session;
  onNextAction: NoopFn;
};

type OnApproveRequestParams = {
  request: RequestAction;
  result: { value: string };
  closeTray?: NoopFn;
};

type OnRejectRequestParams = {
  request: RequestAction;
  error: {
    code: number;
    message: string;
  };
  closeTray?: NoopFn;
};

type GetActionComponentParams = {
  onApprove: (params: OnApproveRequestParams) => void;
  onReject: (params: OnRejectRequestParams) => void;
  handleClose: NoopFn;
};

function noop() {}

function MWPEthereumActionRequestTrayContent({
  message,
  action,
  session,
  onNextAction,
}: EthereumActionRequestComponentProps) {
  const availableNetworks = useAvailableNetworks();
  const evmWalletIndex = useActiveWalletIndex('ETH');
  const activeWalletGroupId = useActiveWalletGroupId();
  const evmPrimaryAddress = useEthereumWalletPrimaryAddress(activeWalletGroupId);
  const { approveAction, rejectAction } = useMobileWalletProtocolHost();

  const proceedToNextAction = useRef(false); // whether next tray should be shown after approve/reject
  const trayDismissedFromButton = useRef(false); // whether tray was dismissed via Confirm or Cancel buttons
  const [showTray, setTrayVisibility] = useState(false);

  const metadata: DAppMetadata = useMemo(() => {
    const dappURL = safeParseUrl(session.dappURL);
    const dappHost = session.dappURL.startsWith('https://') ? dappURL.host : dappURL.protocol;

    const dappBase64Image = session.dappBase64Image
      ? `data:image/png;base64,${session.dappBase64Image}`
      : undefined;

    return {
      dappUrl: session.dappURL,
      dappName: session.dappName,
      dappHostname: dappHost ?? session.dappURL,
      dappLogoUrl: session.dappImageURL ?? dappBase64Image,
    };
  }, [session.dappBase64Image, session.dappImageURL, session.dappName, session.dappURL]);

  const chainIsAlreadySupported = useCallback(
    (chainIdInQuestion: string) =>
      !!availableNetworks.find(
        ({ network }) => network.asChain()?.chainId.toString() === chainIdInQuestion,
      ),
    [availableNetworks],
  );

  const onApproveRequest = useCallback(
    async function onApproveRequest({ request, result, closeTray }: OnApproveRequestParams) {
      const proceed = await approveAction(request, result);
      proceedToNextAction.current = proceed;
      trayDismissedFromButton.current = true;
      closeTray?.();
    },
    [approveAction],
  );

  const onRejectRequest = useCallback(
    async function onRejectRequest({ request, error, closeTray }: OnRejectRequestParams) {
      const proceed = await rejectAction(request, error);
      proceedToNextAction.current = proceed;
      trayDismissedFromButton.current = true;
      closeTray?.();
    },
    [rejectAction],
  );

  // Shows the new tray whenever the action changes
  useEffect(
    function handleTrayVisibility() {
      if (action.method === 'eth_requestAccounts') {
        triggerNativeSdkEthereumAccountsRequest({ session, message });

        // Auto-approve eth_requestAccounts requests; don't show tray
        approveAction(action, {
          value: JSON.stringify({
            chain: 'eth',
            networkId: 1,
            address: evmPrimaryAddress,
          }),
        }).then((proceed) => {
          triggerNativeSdkEthereumAccountsConfirmResponse({ session, message });
          if (proceed) {
            onNextAction();
          }
        });
      } else {
        setTrayVisibility(true);
      }
    },
    [action, approveAction, evmPrimaryAddress, message, onNextAction, session],
  );

  const onTrayCloseComplete = useCallback(
    async function onTrayCloseComplete() {
      setTrayVisibility(false);

      if (!trayDismissedFromButton.current) {
        // Tray was dismissed via gesture or back button
        const proceed = await rejectAction(action, MWPHostErrors.rejectRequest);
        proceedToNextAction.current = proceed;
      } else {
        // Reset state to default
        trayDismissedFromButton.current = false;
      }

      if (proceedToNextAction.current) {
        onNextAction();
        proceedToNextAction.current = false;
      }
    },
    [action, onNextAction, rejectAction],
  );

  const data = useMemo(
    () => getWeb3Call({ action, availableNetworks, address: evmPrimaryAddress }),
    [action, availableNetworks, evmPrimaryAddress],
  );

  const getActionComponent = useCallback(
    function getActionComponent({ handleClose, onApprove, onReject }: GetActionComponentParams) {
      const onCancelFunc = () => {
        // Analytics
        switch (data?.request.method) {
          case 'signEthereumMessage':
            triggerNativeSdkSignEthereumMessageDenyResponse({ session, message });
            break;
          case 'signEthereumTransaction':
            triggerNativeSdkSignEthereumTransactionDenyResponse({ session, message });
            break;
          case 'switchEthereumChain':
            triggerNativeSdkSwitchEthereumChainDenyResponse({
              session,
              message,
              chainId: data.request.params.chainId as string,
            });
            break;
          case 'addEthereumChain':
            triggerNativeSdkAddEthereumChainDenyResponse({
              session,
              message,
              chainId: data.request.params.chainId as string,
            });
            break;
          case 'watchAsset':
            triggerNativeSdkWatchAssetDenyResponse({ session, message });
            break;
          default:
        }

        onReject({
          request: action,
          error: MWPHostErrors.rejectRequest,
          closeTray: handleClose,
        });
      };

      const onConfirmFunc = (response?: Web3CallResponse) => {
        // Analytics
        switch (data?.request.method) {
          case 'signEthereumMessage':
            triggerNativeSdkSignEthereumMessageConfirmResponse({ session, message });
            break;
          case 'signEthereumTransaction':
            triggerNativeSdkSignEthereumTransactionConfirmResponse({ session, message });
            break;
          case 'switchEthereumChain':
            triggerNativeSdkSwitchEthereumChainConfirmResponse({
              session,
              message,
              chainId: data.request.params.chainId as string,
            });
            break;
          case 'addEthereumChain':
            triggerNativeSdkAddEthereumChainConfirmResponse({
              session,
              message,
              chainId: data.request.params.chainId as string,
            });
            break;
          case 'watchAsset':
            triggerNativeSdkWatchAssetConfirmResponse({ session, message });
            break;
          default:
        }

        // Handle error
        if (response?.errorMessage && response?.errorCode) {
          onReject({
            request: action,
            error: {
              code: response.errorCode as number,
              message: response.errorMessage as string,
            },
            closeTray: handleClose,
          });
          return;
        }

        // Handle success
        if (response?.result) {
          let result: unknown | null;
          switch (action.method) {
            case 'wallet_addEthereumChain':
            case 'wallet_switchEthereumChain':
              // return null to client instead of RPC URL
              result = null;
              break;
            default:
              result = response.result;
          }

          onApprove({
            request: action,
            result: { value: JSON.stringify(result) },
            closeTray: handleClose,
          });
          return;
        }

        onReject({
          request: action,
          error: MWPHostErrors.failure,
          closeTray: handleClose,
        });
      };

      switch (data?.request.method) {
        case 'signEthereumMessage': {
          return (
            <SignMessage
              data={data as SignEthereumMessageMessage}
              metadata={metadata}
              onConfirm={onConfirmFunc}
              onDismiss={onCancelFunc}
              evmWalletIndex={evmWalletIndex}
              evmAddress={evmPrimaryAddress}
            />
          );
        }
        case 'signEthereumTransaction': {
          if (action.method === 'eth_sendTransaction') {
            return (
              <MWPSendTransaction
                session={session}
                action={action}
                data={data as SignEthereumTransactionMessage}
                metadata={metadata}
                onConfirm={onConfirmFunc}
                onDismiss={onCancelFunc}
              />
            );
          }

          return (
            <SignTransaction
              data={data as SignEthereumTransactionMessage}
              metadata={metadata}
              onConfirm={onConfirmFunc}
              onDismiss={onCancelFunc}
            />
          );
        }
        case 'switchEthereumChain': {
          const callData = data as SwitchEthereumChainMessage;
          const requestedChainId = callData.request.params.chainId;

          // Reject the action if chain is not supported
          if (!chainIsAlreadySupported(requestedChainId)) {
            triggerNativeSdkSwitchEthereumChainRequestError({
              method: action.method,
              chainId: requestedChainId,
              session,
              message,
            });

            onReject({
              request: action,
              error: MWPHostErrors.unsupportedChainId(requestedChainId),
              closeTray: handleClose,
            });

            return <></>;
          }

          return (
            <SwitchChain
              data={callData}
              metadata={metadata}
              onConfirm={onConfirmFunc}
              onDismiss={onCancelFunc}
              onSuccess={noop}
            />
          );
        }
        case 'addEthereumChain': {
          const callData = data as AddEthereumChainMessage;
          return (
            <AddChain
              data={callData}
              metadata={metadata}
              onConfirm={onConfirmFunc}
              onDismiss={onCancelFunc}
              onSuccess={noop}
            />
          );
        }
        case 'watchAsset': {
          return (
            <WatchAsset
              data={data as WatchAssetMessage}
              metadata={metadata}
              onConfirm={onConfirmFunc}
              onDismiss={onCancelFunc}
            />
          );
        }
        default: {
          onReject({
            request: action,
            error: MWPHostErrors.unsupportedMethod(action.method),
            closeTray: handleClose,
          });
          return <></>;
        }
      }
    },
    [
      action,
      chainIsAlreadySupported,
      data,
      evmPrimaryAddress,
      evmWalletIndex,
      message,
      metadata,
      session,
    ],
  );

  useEffect(
    function actionAnalytics() {
      switch (data?.request.method) {
        case 'signEthereumMessage':
          triggerNativeSdkSignEthereumMessageRequest({ session, message });
          break;
        case 'signEthereumTransaction':
          triggerNativeSdkSignEthereumTransactionRequest({ session, message });
          break;
        case 'switchEthereumChain':
          triggerNativeSdkSwitchEthereumChainRequest({
            method: action.method,
            chainId: data.request.params.chainId as string,
            session,
            message,
          });
          break;
        case 'addEthereumChain':
          triggerNativeSdkAddEthereumChainRequest({
            method: action.method,
            chainId: data.request.params.chainId as string,
            session,
            message,
          });
          break;
        case 'watchAsset':
          triggerNativeSdkWatchAssetRequest({ session, message });
          break;
        default:
          triggerNativeSdkUnknownRequest({ session, message, method: action.method });
      }
    },
    [action.method, data, message, session],
  );

  return (
    <>
      {showTray && (
        <Tray
          onCloseComplete={onTrayCloseComplete}
          // commented this out due to a CDS issue, https://github.cbhq.net/frontend/cds/pull/2346/files, can uncomment this when
          // RN upgrades to cds-mobile > 5.16.1
          // preventDismissGestures
          disableCapturePanGestureToDismiss
          verticalDrawerPercentageOfView={0.9}
          testID="MWP-ethereum-action-request-tray"
        >
          {({ handleClose }) => {
            return (
              <PortalProvider>
                <ScrollView>
                  <Pressable>
                    {getActionComponent({
                      handleClose,
                      onApprove: onApproveRequest,
                      onReject: onRejectRequest,
                    })}
                  </Pressable>
                </ScrollView>
              </PortalProvider>
            );
          }}
        </Tray>
      )}
    </>
  );
}

export const MWPEthereumActionRequestTray = memo(MWPEthereumActionRequestTrayContent);

