import { memo, useCallback, useMemo, useState } from 'react';
import { Button, StyleProp, View, ViewStyle } from 'react-native';
import { setAppLoadStartTimestamp } from 'cb-wallet-data/performance/debug';

import { App } from ':rn/app/App';

/**
 * A component that allows us to mount the App manually, instead of the component
 * being mounted automatically as soon as you open the app. This is useful for taking
 * react profiles of app start. See index.js for more details.
 */
export const MountableApp = memo(function MountableApp() {
  const [isMounted, setMounted] = useState(false);
  const rootStyle = useMemo(
    () => ({
      flex: 1,
    }),
    [],
  );

  const buttonContainerStyle: StyleProp<ViewStyle> = useMemo(
    () => ({
      backgroundColor: '',
      flex: 1,
      justifyContent: 'center',
      alignItems: 'center',
    }),
    [],
  );

  const handlePress = useCallback(() => {
    setAppLoadStartTimestamp();
    setMounted(true);
  }, []);

  return (
    <View style={rootStyle}>
      {isMounted ? (
        <App />
      ) : (
        <View style={buttonContainerStyle}>
          <Button title="Mount" onPress={handlePress} />
        </View>
      )}
    </View>
  );
});

