import { shouldProfileOnInitAtom } from '../profileOnInit';

function ProfileOnInitToggle() {
  const [shouldProfileOnInit, setShouldProfileOnInit] = useRecoilState(shouldProfileOnInitAtom);

  const handleChange = useCallback(() => {
    setShouldProfileOnInit((shouldProfile) => !shouldProfile);
  }, [setShouldProfileOnInit]);

  return (
    <Switch
      testID="profile-on-init-switch"
      accessibilityLabel="Profile on init"
      onChange={handleChange}
      checked={shouldProfileOnInit}
    />
  );
}

const innerSpacing: CellSpacing = { spacing: 0 };
