export function ProfileOnInitToggleRow() {
  return (
    <Cell detail={<ProfileOnInitToggle />} innerSpacing={innerSpacing} outerSpacing={outerSpacing}>
      <VStack justifyContent="center">
        <TextLabel1 numberOfLines={1} ellipsize="tail">
          Profile on app start
        </TextLabel1>
      </VStack>
    </Cell>
  );
}

import { Alert, Button } from 'react-native';
import { fireEvent, render, screen, waitFor } from '@testing-library/react-native';
import { triggerRecoveryModeButtonPressed } from 'cb-wallet-analytics/app-load/app-load-rn';
import { useIsRecoveryModeKilled } from 'cb-wallet-data/hooks/KillSwitches/useIsRecoveryModeKilled';
import { MutableSnapshot, useRecoilValue } from 'recoil';

import { AuthState } from ':rn/shared/auth/Auth';
import { authStateAtom } from ':rn/shared/auth/stores/authState';
import { isRecoveryModeEnabledAtom } from ':rn/shared/recovery-mode/stores';
import { MockedComponent } from ':rn/shared/test/MockedComponent';
import { MockedProviders } from ':rn/shared/test/MockedProviders';

import { useToggleRecoveryMode } from './useToggleRecoveryMode';

jest.mock('cb-wallet-data/hooks/KillSwitches/useIsRecoveryModeKilled');
jest.mock('cb-wallet-analytics/app-load/app-load-rn');

const mockRefreshAuthState = jest.fn();
jest.mock(':rn/shared/auth/hooks/useRefreshAuthState', () => ({
  useRefreshAuthState: () => mockRefreshAuthState,
}));

const spyAlert = jest.spyOn(Alert, 'alert');

const mockAuthState: AuthState = {
  hasMnemonic: true,
  hasSecrets: true,
  appLockType: 'biometrics',
  biometricProtectionType: 'legacy',
  areBiometricsInvalidated: false,
  isAuthRequiredForAppAccess: false,
  isAuthRequiredForTx: false,
  availableBiometry: undefined,
  hasSalt: true,
  hasEncryptedMnemonic: true,
  hasPinSalt: false,
  hasBiometricsSalt: true,
  hasEncryptedMnemonicForPin: false,
  hasEncryptedMnemonicForBiometrics: true,
};

function MockDeeplinkingProviderConsumer() {
  const isRecoveryModeEnabled = useRecoilValue(isRecoveryModeEnabledAtom);
  const handleToggleRecoveryMode = useToggleRecoveryMode();

  return (
    <>
      <Button
        title="Toggle Recovery Mode"
        onPress={handleToggleRecoveryMode}
        testID="toggle-recovery-mode"
      />
      <MockedComponent testID="mock-recovery-mode" text={String(isRecoveryModeEnabled)} />
    </>
  );
}

function run() {
  const initializeState = ({ set }: MutableSnapshot) => {
    set(authStateAtom, mockAuthState);
  };

  return render(
    <MockedProviders initializeState={initializeState}>
      <MockDeeplinkingProviderConsumer />
    </MockedProviders>,
  );
}

describe('useToggleRecoveryMode', () => {
  it('should enable recovery mode when not killed and signed in', async () => {
    (useIsRecoveryModeKilled as jest.Mock).mockReturnValue(false);
    mockRefreshAuthState.mockResolvedValueOnce(mockAuthState);

    run();
    expect(screen.getByTestId('mock-recovery-mode')).toHaveTextContent('false');

    fireEvent.press(screen.getByTestId('toggle-recovery-mode'));

    await waitFor(async () => {
      expect(triggerRecoveryModeButtonPressed).toHaveBeenCalledOnceWith({
        isRecoveryModeKilled: false,
      });
    });
    expect(mockRefreshAuthState).toHaveBeenCalledOnce();
    expect(screen.getByTestId('mock-recovery-mode')).toHaveTextContent('true');
  });

  it('should show an alert when not killed and signed out', async () => {
    (useIsRecoveryModeKilled as jest.Mock).mockReturnValue(false);
    mockRefreshAuthState.mockResolvedValueOnce({ ...mockAuthState, hasMnemonic: false });

    run();

    fireEvent.press(screen.getByTestId('toggle-recovery-mode'));

    await waitFor(async () => {
      expect(triggerRecoveryModeButtonPressed).toHaveBeenCalledOnceWith({
        isRecoveryModeKilled: false,
      });
    });
    expect(mockRefreshAuthState).toHaveBeenCalledOnce();
    expect(screen.getByTestId('mock-recovery-mode')).toHaveTextContent('false');
    expect(spyAlert).toHaveBeenCalledOnce();
    expect(spyAlert).toHaveBeenCalledWith(
      'Recover your wallet',
      "You're signed out of Coinbase Wallet. To view your recovery phrase, sign in.",
      [{ style: 'default', text: 'Okay' }],
    );
  });

  it('should not enable recovery mode when killed', async () => {
    (useIsRecoveryModeKilled as jest.Mock).mockReturnValue(true);
    mockRefreshAuthState.mockResolvedValueOnce(mockAuthState);

    run();

    fireEvent.press(screen.getByTestId('toggle-recovery-mode'));

    await waitFor(async () => {
      expect(triggerRecoveryModeButtonPressed).toHaveBeenCalledOnceWith({
        isRecoveryModeKilled: true,
      });
    });
    expect(mockRefreshAuthState).not.toHaveBeenCalledOnce();
    expect(screen.getByTestId('mock-recovery-mode')).toHaveTextContent('false');
  });
});

import { NavigationProp } from '@react-navigation/native';
import { ButtonGroup } from '@cbhq/cds-mobile/buttons';

import { Button } from ':rn/cds-wallet/components/interactables/Button';

import { MockedComponent } from './MockedComponent';

type MockedScreenProps<T> = {
  testID?: string;
  navigation: T;
  text: string;
};

/**
 *
 * @param testID pass through testID from actual callsite of component
 * @param children a string to represent the component
 * @param navigation a navigation object passed to all children screens by the stack navigator in test
 * @returns MockedComponent with navigation links to other children in a stack
 * @example
 * jest.mock(':rn/screens/Browser/screens/BrowserWebViews/BrowserWebViews', () => ({
 *   BrowserWebViews: ({ navigation }: { navigation: NavigationProp<any> }) => (
 *    <MockedScreen navigation={navigation}>BrowserWebViewsTab</MockedScreen>
 *   ),
 * }));
 */
export function MockedScreen<T extends NavigationProp<any> = NavigationProp<any>>({
  testID,
  navigation,
  text,
}: MockedScreenProps<T>) {
  return (
    <>
      <MockedComponent testID={testID} text={text} />
      <ButtonGroup accessibilityLabel="navigationLinks">
        {navigation.getState().routeNames.map((routeName) => (
          <Button
            key={routeName}
            onPress={() => navigation.navigate(routeName)}
          >{`navigate to ${routeName}`}</Button>
        ))}
      </ButtonGroup>
    </>
  );
}

import { useCallback, useMemo } from 'react';
import { Pressable, ScrollView } from 'react-native';
import { defineMessages, useIntl } from 'react-intl';
// eslint-disable-next-line no-restricted-imports
import {
  ensureAddressString,
  ensureHexString,
  hexStringFromBuffer,
} from '@coinbase/wallet-sdk/dist/core/util';
import { EIP4361Message } from 'cb-wallet-data/chains/AccountBased/Ethereum/models/EIP4361Message';
import { safeParseUrl } from 'cb-wallet-data/utils/urlUtils';
import * as yup from 'yup';
import { PortalProvider } from '@cbhq/cds-mobile/overlays/PortalProvider';

import { Tray } from ':rn/cds-wallet/components/Tray/Tray';
import { SignMessage } from ':rn/shared/components/Web3/SignMessage/SignMessage';
import { SignEthereumMessageMessage, Web3CallResponse } from ':rn/shared/types/web3Types';

import { useUpdatePendingResponses } from '../hooks/useUpdatePendingResponses';
import { ConnectAndSignIn } from '../models/HostRequest';

const messages = defineMessages({
  signIn: {
    defaultMessage: 'Sign in',
    description: 'Sign in button text',
  },
});

type ConnectAndSignInTrayProps = {
  request: ConnectAndSignIn;
  data: SignEthereumMessageMessage;
  evmAddress: string;
  evmWalletIndex?: bigint;
};

function ConnectAndSignInTray({
  request,
  data,
  evmWalletIndex: activeWalletIndex,
  evmAddress: activeAddress,
}: ConnectAndSignInTrayProps) {
  const updatePendingResponses = useUpdatePendingResponses();
  const { formatMessage } = useIntl();

  const onConfirm = useCallback(
    function onConfirm(response?: Web3CallResponse) {
      if (!response || response.errorMessage) {
        updatePendingResponses({
          type: 'reject',
          request,
          errorMessage: (response?.errorMessage as string) ?? 'User rejected signature request',
          sent: false,
        });
        return;
      }

      updatePendingResponses({
        type: 'approve',
        request,
        data: Buffer.from([]),
        metadata: {
          address: activeAddress,
          signature: ensureHexString(response.result, true),
          message: data.request.params.message,
        },
        sent: false,
      });
    },
    [activeAddress, data.request.params.message, request, updatePendingResponses],
  );

  const onCancel = useCallback(() => {
    updatePendingResponses({
      type: 'reject',
      request,
      errorMessage: 'User rejected signature request',
      sent: false,
    });
  }, [updatePendingResponses, request]);

  const metadata = useMemo(
    () => ({
      dappHostname: safeParseUrl(request.dappURL).hostname,
      dappName: request.dappName ?? '',
      dappUrl: request.dappURL,
      dappLogoUrl: request.dappImageURL,
    }),
    [request.dappImageURL, request.dappName, request.dappURL],
  );

  return (
    <Tray
      onCloseComplete={onCancel}
      disableCapturePanGestureToDismiss
      verticalDrawerPercentageOfView={0.9}
      testID="wallet-link-connect-and-sign-tray"
    >
      {({ handleClose }) => {
        return (
          <PortalProvider>
            <ScrollView>
              <Pressable>
                <SignMessage
                  titleText={metadata.dappName}
                  confirmButtonText={formatMessage(messages.signIn)}
                  evmAddress={activeAddress}
                  evmWalletIndex={activeWalletIndex}
                  data={data}
                  metadata={metadata}
                  onDismiss={handleClose}
                  onConfirm={onConfirm}
                />
              </Pressable>
            </ScrollView>
          </PortalProvider>
        );
      }}
    </Tray>
  );
}

type WalletLinkConnectAndSignInTrayProps = {
  request: ConnectAndSignIn;
  ethereumWalletPrimaryAddress: string;
  activeWalletIndex?: bigint;
};

export function WalletLinkConnectAndSignInTray({
  request,
  ethereumWalletPrimaryAddress,
  activeWalletIndex,
}: WalletLinkConnectAndSignInTrayProps) {
  const requestSchema = useMemo(() => {
    return yup.object({
      aud: yup.string().url().required(),
      chainId: yup.string().required(),
      domain: yup.string().required(),
      iat: yup.string().required(),
      nonce: yup.string().required(),
      resources: yup.array(yup.string().required()).optional(),
      statement: yup.string().optional(),
      version: yup.string().required(),
    });
  }, []);

  const { data, error } = useMemo(() => {
    try {
      const web3request = requestSchema.validateSync(request.web3Request);

      const {
        aud,
        chainId: eip155ChainId,
        domain,
        iat,
        nonce,
        version,
        resources,
        statement,
      } = web3request;
      const chainId = eip155ChainId.split(':')[1];

      const message = new EIP4361Message({
        domain,
        address: ethereumWalletPrimaryAddress,
        statement: statement ?? null,
        uri: aud,
        version,
        chainId: chainId ? parseInt(chainId) : parseInt(eip155ChainId),
        nonce,
        issuedAt: iat,
        expirationTime: null,
        notBefore: null,
        requestId: null,
        resources: resources ?? null,
      });

      const { isValid, errorMessage } = message.validateMessage();

      if (isValid) {
        const messageString = message.toMessage();
        const messageBuffer = Buffer.from(messageString, 'utf8');

        const signMessageData: SignEthereumMessageMessage = {
          id: 1,
          request: {
            method: 'signEthereumMessage',
            params: {
              message: hexStringFromBuffer(messageBuffer, true),
              address: ensureAddressString(ethereumWalletPrimaryAddress),
              addPrefix: true,
              typedDataJson: null,
            },
          },
        };

        return {
          data: signMessageData,
        };
      }

      return {
        error: errorMessage ?? 'Invalid message',
      };
    } catch (e: ErrorOrAny) {
      return {
        error: e.message ?? 'Invalid message',
      };
    }
  }, [ethereumWalletPrimaryAddress, request.web3Request, requestSchema]);

  const updatePendingResponses = useUpdatePendingResponses();

  if (error || !data) {
    updatePendingResponses({
      type: 'reject',
      request,
      errorMessage: error ?? 'Invalid message',
      sent: false,
    });

    return null;
  }

  return (
    <ConnectAndSignInTray
      request={request}
      data={data}
      evmAddress={ethereumWalletPrimaryAddress}
      evmWalletIndex={activeWalletIndex}
    />
  );
}
